// AUTO-GERADO. Quiz alternatives V9.2.1 (4341).
import type { SQLiteDatabase } from 'expo-sqlite';

export function applySeedQuiz(db: SQLiteDatabase): void {
  db.execSync("BEGIN;");
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT01-L01-Q01','Primeiro livro do Pentateuco e da Bíblia','Segundo livro do Pentateuco e da Bíblia','Quinto livro do Pentateuco e da Bíblia','Último livro do Pentateuco e da Bíblia'),('AT01-L01-Q02','Origem, começo. Do grego genesis, principio da Bíblia','Formação do universo. Nome hebraico Torah, lei divina','Criação completa. Significa ''o livro sagrado'' em aramaico','Primeiro livro. Do latim genus, espécie e classificação'),('AT01-L01-Q05','A Moisés','A Abraão','Ao Espírito Santo','Ao rei Davi'),('AT01-L01-Q03','História Primordial e História Patriarcal','Lei e Profetas e Escritos','Primeira e Segunda Alianças','História Pré-faraônica e História Egípcia'),('AT01-L01-Q04','As fórmulas separam secções narrativas e genealogias, estruturando o livro.','As fórmulas indicam datas exatas da criação para todos os eventos bíblicos.','As fórmulas definem apenas os livros considerados canônicos na Bíblia.','As fórmulas conectam todos os livros bíblicos em uma única linha temporal.'),('AT01-L01-Q06','Hipótese documental J E D P e historicidade dos patriarcas','Autoria exclusiva de Moisés confirmada por manuscritos antigos','Composição por um único autor no período helenístico','Base exclusiva nos textos cuneiformes encontrados em Nínive'),('AT01-L01-Q07','Revelar a criação, a queda e o início da aliança divina com os homens','Ensinam os mandamentos e leis para a vida religiosa de Israel','Narrar exclusivamente a vida e os milagres de Moisés','Profetizar os eventos do fim dos tempos e o apocalipse'),('AT01-L02-Q01','Deus, Adão, Eva e a criação do mundo em seis dias, com o descanso no sétimo.','Adão, Caim, Abel e o Dilúvio como parte dos sete dias da criação.','Deus, os anjos caídos, Adão e Eva, e a construção da Arca de Noé.','Moisés, o mar Vermelho, os profetas Elias e Eliseu na criação original.'),('AT01-L02-Q03','A queda do homem e a promessa messiânica','O dilúvio universal como julgamento divino','A construção da arca de Noé para salvação','A confusão das línguas na torre de Babel'),('AT01-L02-Q02','Gênesis 1 e 2','Gênesis 3 e 4','Êxodo 20:11','Salmo 139'),('AT01-L02-Q04','A queda do homem, a maldição sobre a criação, a entrada da morte e dor no mundo.','O estabelecimento do sacerdócio levítico e das ofertas rituais no Tabernáculo.','A criação dos anjos caídos e a guerra celestial no céu.','A construção do templo de Salomão e as leis cerimoniais de Israel.'),('AT01-L03-Q02','Gênesis 1:26-27','Gênesis 2:7','Gênesis 3:22','Gênesis 18:1'),('AT01-L02-Q06','Estabelecem a relação entre Deus e a humanidade, preparando a esperança da restauração futura.','São relatos independentes que não se conectam com a narrativa de redenção bíblica.','Demonstram que a humanidade pode salvar-se por seus próprios esforços morais.','Servem apenas como cenário histórico sem implicações para a aliança.'),('AT01-L03-Q04','A imagem de Deus revela que o ser humano foi criado para refletir a natureza e os atributos divinos.','A imagem de Deus indica que Deus é um ser visível e corpóreo semelhante ao ser humano.','A imagem de Deus revela que a humanidade possui a mesma essência divina e é igual a Deus.','A imagem de Deus mostra que apenas os líderes religiosos foram criados à semelhança divina.'),('AT01-L03-Q06','Reducao a apenas atributos fisicos ou aparencia exterior','Que a imagem foi totalmente eliminada pelo pecado original','Que apenas pessoas religiosas possuem a imagem de Deus','Que Deus possui forma humana semelhante a nossa'),('AT01-L02-Q05','NAO SEI','A criacao revela que Deus e um artesao mortal que esculpiu o mundo da materia','Os relatos mostram que os humanos foram criados como seres autonomos sem necessidade de Deus','A criacao demonstra que Deus e malevolo e criou os humanos para sofrerem'),('AT01-L03-Q03','A criação do homem à imagem e semelhança de Deus (Gn 1.26-27)','A Trindade como elemento principal para compreender a imagem de Deus','Os Dez Mandamentos como fundamento da imagem divina no ser humano','A criação dos animais antes do homem como elemento comparativo essencial'),('AT01-L03-Q01','Ser criado com atributos que refletem a natureza divina, como racionalidade e moralidade.','Ser fisicamente semelhante a Deus, como um retrato ou fotografia perfeita do Criador.','Ter a mesma forma física de Deus, com corpo, braços, rosto e olhos semelhantes aos humanos.','Ser literalmente uma parte de Deus, um fragmento da essência divina incarnado no homem.'),('AT01-L04-Q02','Gênesis 1:28','Gênesis 2:15','Gênesis 3:17-19','Gênesis 9:1'),('AT01-L04-Q01','Mandato de cultivar e subjugar a terra','Proibição de comer do fruto da árvore','Ordem de abandonar o jardim do Éden','Mandato de destruir toda a vida selvagem'),('AT01-L04-Q03','Encher a terra, subjulgai-a e dominai sobre as obras das mãos de Deus.','Proclamai o evangelho a todas as nações e fazei discípulos em meu nome.','Observai todos os meus estatutos e guardai os meus juízos.','Amai os vossos inimigos e orai pelos que vos perseguem.'),('AT01-L03-Q05','Evolui na Escritura mostrando Cristo como imagem perfeita e a santificação do fiel.','Permanece estática, mantendo sempre o mesmo sentido original de Genêsis.','Refere-se apenas à aparência física de Deus descrita nas visões proféticas.','Passa a significar exclusivamente o poder político dos reis ungidos por Deus.'),('AT01-L04-Q05','Através da relação do ser humano com a criação em toda a Escritura','Somente através da lei cerimonial no Pentateuco','Nos Sacrifícios e rituais do templo','Através das guerras santas de Israel'),('AT01-L05-Q02','Refere-se a refletir a natureza, os atributos e a semelhança moral de Deus.','Significa que Deus possui forma física semelhante à natureza humana.','Indica que todos os seres vivos foram criados à imagem de Deus.','Quer dizer que o homem recebeu poderes divinos iguais a Deus.'),('AT01-L04-Q06','Dominar a natureza e separar do evangelho','Descartar a natureza e viver apenas do espiritual','Copiar literalmente toda a cultura biblica','Deixar o Estado executar todo o mandato'),('AT01-L05-Q03','Ambos criados à imagem de Deus, iguais, mas distintos como macho e fêmea.','Diferentes em essência: a mulher foi criada inferior ao homem por Deus.','O homem e a mulher foram criados idênticos em todos os aspectos e funções.','A relação foi revelada apenas no Novo Testamento, sem base no Gênesis.'),('AT01-L04-Q04','Revela que Deus convida a humanidade a participar de Sua obra criadora.','Revela que a humanidade deve dominar a criação sem nenhuma responsabilidade.','Indica que a criação existe independentemente da soberania divina.','Sugere que o homem foi criado para competir com os anjos por poder.'),('AT01-L05-Q01','Deus formou o homem do pó e da costela de Adão fez a mulher.','Deus criou homem e mulher ao mesmo tempo do mesmo pó da terra.','Os anjos formaram o homem e a mulher do pó da terra.','Deus criou a mulher da terra depois de formar o homem.'),('AT01-L05-Q06','Citações diretas de Gênesis nos Evangelhos e Epístolas, confirmando a criação.','Rejeitam o relato mosaico e criam uma versão própria da criação.','Baseiam-se exclusivamente em tradições filosóficas gregas sobre a origem.','Modificam o texto de Gênesis para adequá-lo à cultura helenística.'),('AT01-L05-Q05','Eva foi tirada do lado de Adão, para ser sua companheira ehelper,fundamentando igual dignidadena.uniao','Eva foi creada antes de Adão, para que ele pudesse escolher sua companheira segundo sua vontade.','A mulher foi tirada dos pés de Adão, simbolizando que deve ser pisoteada pelo marido.','Eva foi creada独立的mente de Adão, sem nenhuma relação de origem ou complementaridade.'),('AT01-L05-Q04','Habitar o jardim, cultivar a terra e obedecer ao mandamento divin','Cultivar a solidão, pregar a Palavra e sacrificar-se pelo próximo','Expulsar o inimigo, construir altares e realizar rituais sagrados','Conquistar territórios, acumular riquezas e dominar as nações'),('AT01-L06-Q01','Instituição divina onde homem e mulher se tornam uma só carne','Contrato civil exclusivo entre duas pessoas do mesmo gênero','União meramente temporária baseada em interesses econômicos','Aliança espiritual sem qualquer compromisso físico entre伴侣'),('AT01-L06-Q02','Gênesis 2:18-25','Gênesis 1:27-28','Gênesis 3:16','Gênesis 4:1'),('AT01-L06-Q04','Reflete a união de Cristo com a igreja','Prova que Deus depende da humanidade','Mostra que a mulher foi criada primeiro','Revela que o casamento é mera tradição'),('AT01-L07-Q01','Desobediência de Adão e Eva ao comer do fruto proibido em Génesis 3.','A destruição das cidades de Sodoma e Gomorra por fogo do céu.','A morte de Cristo na cruz para remissão dos pecados da humanidade.','A dispersão dos povos após a construção da Torre de Babel.'),('AT01-L06-Q03','Génesis 2:24, Efésios 5:22-33, aliança, mutualidade e propósito divino','Poligamia, concubinato e divórcio irrestrito como modelo divino original','Apenas o contrato civil, tradição cultural e aspecto legal humano','Sacrifício unilateral da esposa sem amor sacrificial do marido'),('AT01-L06-Q06','Tratar casamento como contrato em vez de aliança sagrada entre homem e Deus','Considerar que Deus aprova unioes sem compromisso com os principios biblicos','Entender que casamento e mera tradicao cultural sem valor espiritual','Acreditar que a Escritura condena qualquer relacao conjugal entre pessoas'),('AT01-L07-Q02','Gênesis 3','Gênesis 1','Gênesis 2','Gênesis 4'),('AT01-L06-Q05','Cresce como alianca de amor entre Cristo e a Igreja','Passa a ser proibido e substituido pelo celibato universal','Permanece apenas como contrato civil sem dimensao espiritual','Torna-se optional para todos os crentes em qualquer circunstancia'),('AT01-L07-Q03','Adão, Eva, serpente, árvore do conhecimento do bem e do mal, desobediência','Moisés, tabernáculo, maná, mandamentos, Faraó','Noé, arca, dilúvio,彩虹,aliança','Cruz, sangue, sacrifício, redenção, graça'),('AT01-L07-Q05','A queda de Adão traz o pecado ao mundo e necessidade de redenção.','A queda é descrita como um evento isolado no Gênesis, sem consequências.','A queda refere-se apenas à destruição de Sodoma e Gomorra.','A queda não é mencionada em outras partes da Bíblia, apenas em Gênesis.'),('AT01-L07-Q04','A queda revela a soberania de Deus e a necessidade de redenção do homem','A queda demonstra que Deus abandonou completamente a criação ao pecado','A queda prova que o homem nasceu essencialmente mau e sem livre-arbítrio','A queda revela que Deus criou o mundo como um experimento falho'),('AT01-L08-Q02','Gênesis 3:15','Gênesis 1:27-28','Gênesis 12:1-3','Gênesis 28:10-15'),('AT01-L09-Q02','Gênesis capítulo 4','Êxodo capítulo 12','Gênesis capítulo 3','Números capítulo 15'),('AT01-L08-Q04','Revela o plano gracioso e redentor de Deus para restaurar a humanidade caída.','Revela que Deus abandonou a humanidade ao pecado sem oferecer salvação.','Revela que a humanidade deveria salvar-se por seus próprios esforços.','Revela que apenas os sacrifícios de animais seriam suficientes para redimir o pecado.'),('AT01-L08-Q01','Deus prometeu a Abraão que sua semente abençoaria todas as nações da terra.','Deus prometeu que os descendentes de Abraão seriam destruídos como castigo às nações.','A promessa de prosperidade material ilimitada aos filhos de Abraão apenas.','A promessa de que Abraão seria o único povo abençoado por Deus.'),('AT01-L08-Q03','A aliança abraâmica, a linhagem messiânica e a fé do patriarca são essenciais.','Apenas o texto de Gênesis 3 e o sacrifício de Cristo na cruz.','A destruição de Sodoma e a chuva de fogo sobre as cidades.','Os dez mandamentos no Sinai e a observância da lei mosaica.'),('AT01-L08-Q05','Desenvolve-se como promessa messiânica que se cumpre em Jesus Cristo, o descendente abençoado.','Desenvolve-se como promessa de prosperidade material e terrestre para o povo de Israel.','Cumpre-se inteiramente na figura de Abraão como pai de todas as nações.','Refere-se únicamente à обещание de uma dinastia terrena de reis em Judá.'),('AT01-L07-Q06','Tratar Gênesis 3 como simbolismo puro, ignorando o pecado original e a queda real da humanidade.','Achar que a queda nao trouxe consequências reais para a natureza humana decaída.','Culpar exclusivamente Satanás pela queda, eximindo a responsabilidade do homem.','Interpretar a queda como um avanço evolutivo positivo para a humanidade.'),('AT01-L09-Q03','O assassinato de Abel por Caim, movido pela inveja da oferta aceita.','A disputa entre os irmaos por heranca do territorio de Canaa.','A destruicao de Sodoma e Gomorra pelos anjos do Senhor.','A oferta de sacrifício que Deus aceitou de Abraão.'),('AT01-L09-Q01','Caim e Abel, filhos de Adão e Eva. Ofereceram sacrifícios a Deus. A oferta de Abel foi aceita, a de Caim rejeitada. Caim matou Abel e foi amaldiçoado.','Caim e Abel, filhos de Adão e Eva, se reconciliaram após o conflito e fundaram uma cidade juntos.','Caim e Abel, filhos de Adão e Eva, ofereceram sacrifícios a Deus, mas ambos foram rejeitados.','Abel aceito por Deus, Caim rejeitado, Caim mudou de vida, Abel pediu perdão e foi absolto.'),('AT01-L09-Q05','Deus é santo e justo, e o ser humano é incline ao pecado e à desobediência.','Deus favorece os mais jovens e rejeita os mais velhos em suas ofertas.','A condição humana é inerentemente boa e Deus aceita toda oferta sincera.','Deus é indiferente às escolhas humanas e aceita todas as ofertas igualmente.'),('AT01-L08-Q06','Reduzir apenas à descendência física e ignorar a promessa messiânica.','Desconsiderar o contexto histórico-cultural em que foi registrada.','Aplicar as normas jurídicas do texto diretamente aos dias atuais.','Negar completamente a relevância espiritual do texto bíblico.'),('AT01-L10-Q03','Preservam a linhagem eleita e mostram a continuidade da promessa divina.','Demonstram que a Terra foi criada em seis dias literais conforme Genesis.','Estabelecem regras detalhadas para sacrifícios e celebrações religiosas.','Prova historica de que todos os povos descendem de uma só familia.'),('AT01-L10-Q01','Registrar a linhagem e mostrar a historia da salvacao','Compor a estrutura poetica e narrativa do livro','Determinar as leis civis e os direitos de heranca','Servir de ornamentacao para preencher espacos vazios'),('AT01-L09-Q04','Maldição de Caim, marca protetora, exílio e construção da primeira cidade.','Abel foi ressuscitado por Deus e se tornou sumo sacerdote da humanidade.','Todos os descendentes de Caim foram destruídos por um incêndio divino.','A terra foi dividida entre os descendentes de Caim e Abel por Deus.'),('AT01-L09-Q06','Mostraram a seriedade do pecado e a necessidade de um Salvador, prefigurando Cristo.','Estabeleceram os primeiros sacrifícios rituais que todas as gerações deveriam observar.','Provaram que apenas os sacrifícios de animais podem purificar os pecados da humanidade.','Demonstraram que Deus aceita apenas ofertas materiais e rejeita a fé sem obras.'),('AT01-L10-Q02','Mostram a continuidade das promessas ao longo das gerações','São apenas listas de nomes sem importância teológica','Provam que a narrativa bíblica é completamente linear','Demonstram que Deus abandonou seu plano original'),('AT01-L11-Q01','Noé, sua família e os animais na arca; o dilúvio que destruiu a terra.','Abraão, Sara e os três anjos que visitaram as tendas em Berseba.','Moisés, os patriarcas e a travessia do Mar Vermelho sobre secos.','Davi, o gigante Golias e a arca da aliança transportada a Jerusalém.'),('AT01-L11-Q02','Gênesis capítulos 6 a 9','Gênesis capítulos 11 a 14','No livro de Êxodo','Gênesis capítulos 2 e 3'),('AT01-L10-Q04','Porque visavam objetivos teologicos e nao apenas biologicos, sendo frequentemente seletivas.','Porque os escribas medievais copiavam os nomes de forma imprecisa e desordenada.','Porque os povos antigos nao possuiam metodos adequados de registro genealogico.','Porque as genealogias biblicas tinham finalidade exclusivamente estatistica e demografica.'),('AT01-L11-Q04','Deus fez aliança com Noé e colocou o arco-íris como sinal','A terra foi completamente destruída e nunca mais teve vida','Os anjos foram enviados para habitar entre os homens','Os homens passaram a viver eternamente após o dilúvio'),('AT01-L11-Q05','Revela a santidade de Deus, sua justiça contra o pecado e o desejo de restaurar a criação.','Demonstra que Deus é indiferente ao sofrimento humano e incapaz de perdoar.','Prova que a humanidade é fundamentalmente boa e que o mal vem apenas de fora.','Indica que Deus se arrepende de ter criado o ser humano e deseja destruí-lo.'),('AT01-L12-Q02','Gênesis 9:8-17','Gênesis 6:5-8','Gênesis 7:1-24','Gênesis 8:20-22'),('AT01-L12-Q01','Promessa divina de não destruir a terra por águas, selada pelo arco-íris.','Pacto de obediência perpétua entre Deus e os descendentes de Sem.','Aliança que exigia ofertas diárias de animais como sinal de fidelidade.','Compromisso humano de nunca consumir carne de qualquer animal.'),('AT01-L12-Q04','A fidelidade e a misericordia de Deus para com toda a criação, mesmo após o pecado.','A destruição total da humanidade como consequência eterna do pecado original.','O direito dos animais sobre a terra em igualdade com os seres humanos.','A promessa de que nunca mais haverá sofrimento ou morte no mundo.'),('AT01-L11-Q06','Revela o julgamento divino contra o pecado e estabelece a aliança com Noé, prenunciando a redenção.','Representa um fenômeno meteorológico que ilustra apenas o poder criativo de Deus sobre a natureza.','Foi uma medida desesperada de Deus que fracassou em seus planos originais para a humanidade.','Serve como advertência sobre as consequências da desobediência às leis civis e morais.'),('AT01-L12-Q03','Promessa de não destruir a terra por águas, o arco-íris como sinal.','A obediência de Noé como condição principal da aliança.','O shabath como sinal perpétuo da aliança com Noé.','A promessa limitada apenas aos descendentes de Sem.'),('AT01-L11-Q03','Promessa divina de nunca mais destruir a terra por meio de dilúvio','Ordem para Noé construir a arca e reunir animais para repovoar a terra','Bênção de Deus aos filhos de Noé para que dominassem toda a terra','Mandamento de oferecer sacrifícios rituais sempre que o arco-íris aparecer'),('AT01-L13-Q02','Gênesis 11','Gênesis 10','Êxodo 1','Gênesis 3'),('AT01-L12-Q05','Prometeu nunca mais destruir a terra por água; sinal: o arco-íris','Estabeleceu leis cerimoniais específicas para os descendentes','Foi renovada e ampliada por Abraão e confirmada por Moisés','Prometeu bênçãos especiais e terras aos descendentes de Noé'),('AT01-L12-Q06','Que a aliança permite explorar os animais sem responsabilidade moral perante Deus.','Que a aliança isenta a humanidade de qualquer responsabilidade perante Deus.','Que o arco-íris é um sinal meramente meteorológico sem significado espiritual.','Que a aliança garante que não haverá mais nenhuma destruição na terra.'),('AT01-L13-Q05','NAO SEI','Revela que Deus precisa intervir para impedir o progresso da humanidade.','Mostra que Deus aprova a ambição humana de construir grandes obras.','Indica que Deus deseja que os homens vivam espalhados pela terra.'),('AT01-L14-Q02','Gênesis 12:1-3','Gênesis 11:26-32','Gênesis 15:1-6','Gênesis 22:1-19'),('AT01-L13-Q03','Confusão das línguas','Dilúvio que dispersou a humanidade','Construção da arca de Noé','Pacto da circuncisão'),('AT01-L14-Q01','Deus chama Abraão, que parte com Sara e Ló para Canaã, onde recebe promessas.','Deus chama Abraão, que foge do Egito com Sara e Ló, levando todos os tesouros do faraó.','Deus chama Abraão para construir a arca e pregar ao mundo inteiro sobre o dilúvio iminente.','Deus chama Abraão, que é enviado pelo pai TARÃ para pregar a palavra divina em Canaã.'),('AT01-L14-Q03','Deus prometeu a Abraão terra, descendência e bênção para todas as nações.','Deus ordenou que Abraão sacrificasse seu filho primogênito como prova de fé.','Abraão pecou ao duvidar da promessa e foi amaldiçoado por Deus.','Deus enviou uma praga sobre o Egito para forçar a saída de Abraão.'),('AT01-L13-Q06','Mostra a rebeldia humana e prepara o caminho para a aliança com Abraão.','Prova que Deus aprova a construção de torres e cidades pelos seres humanos.','Estabeleceu uma aliança eterna entre Deus e todas as nações da terra.','Criou as línguas para que os povos pudessem se unir e glorificar a Deus.'),('AT01-L14-Q06','A obediência de Abraão à vocação estabelece a aliança e prepara a redenção.','A vocação de Abraão anula a necessidade de sacrifício na história da redenção.','Abraão foi chamado apenas para fundar uma nação, sem relação direta com a redenção.','O chamado de Abraão substitui a necessidade de Cristo na história da salvação.'),('AT01-L14-Q04','Abraão recebeu promessas de descendência numerosa, terra e bênção para todas as famílias da terra.','Abraão foi ordenado a construir o Templo e guardar o sábado como aliança permanente.','Deus entregou a Abraão os Dez Mandamentos e o constituiu sumo sacerdote.','Abraão foi chamado para conquistar militarmente Canaã e estabelecer um reino terreno.'),('AT01-L15-Q01','Pacto divino unilateral com Abraão, prometendo terra, descendentes e bênção.','Pacto bilateral que exigia sacrifícios contínuos e ofertas diárias de Abraão.','Aliança condicional baseada exclusivamente na obediência total de Abraão.','Pacto firmado entre Abraão e os reis vizinhos de Canaã para divisão de terras.'),('AT01-L14-Q05','Deus chama pela fé; o ser humano responde com obediência confiante.','Deus exige perfeição moral do ser humano antes de chamá-lo.','Deus escolhe aleatoriamente pessoas sem relação com a fé.','Abraão já era perfeito quando Deus o chamou para segui-lo.'),('AT01-L15-Q03','Promessa de terra, descendência numerosa, circuncisão e bênção universal.','Sacrifícios de animais, observação do sábado e código de leis morais.','Dez mandamentos, arca da aliança e tabernáculo no deserto.','Promessa de um reino terreno, templo de Salomão e sacrifícios perpétuos.'),('AT01-L15-Q02','Gênesis 15:18','Gênesis 12:1-3','Gênesis 17:1-14','Gênesis 22:1-19'),('AT01-L15-Q05','Desenvolve-se na promessa de terra, descendencia e bênção cumprida em Cristo.','Desenvolve-se na revogação completa da promessa por meio da Lei.','Desenvolve-se como promessa exclusivamente politica e territorial.','Desenvolve-se apenas na tradição oral sem relação com o Novo Testamento.'),('AT01-L16-Q02','Gênesis 16 e 21','Gênesis 12 e 13','Livro de Êxodo, capítulos 1 e 2','Gênesis 17 apenas'),('AT01-L15-Q04','Revela o plano de Deus para abençoar toda a humanidade','Revela que Deus exige obras perfeitas do ser humano','Revela que Deus estabeleceu aliança baseado em merecimento','Revela que a salvação depende da capacidade humana'),('AT01-L16-Q03','Deus promete um filho a Abraão e Sara','Deus exige que Abraão sacrifique Isaque','Sara pede divórcio e retorna ao Egito','Deus condena Agar por adorar ídolos'),('AT01-L15-Q06','Achar que a aliança é apenas para descendentes físicos','Negar que os árabes descendem de Abraão','Acreditar que foi revogada no Sinai','Considerar que exige obras para sua validade'),('AT01-L16-Q01','Sara e Agar protagonizam o conflito pela maternidade, com Agar fugindo ao anjo ordena-la retornar, e Isaac e Ismael sendo fruto dessas relações.','Jacó e Raquel foram o casal que lutou pela bênção e pela primogenitura entre as duas esposas e suas servas.','Moisés e Zípora tiveram conflitos semelhante, onde Zípora fugiu e foi encontrada pelo anjo no deserto.','Saul e Davi discutiram a sucessão do trono, com Mical como serva enviada para conceber um herdeiro.'),('AT01-L17-Q02','Gênesis capítulos 21 a 35','Gênesis capítulos 1 a 10','Êxodo e Números','Levítico e Deuteronômio'),('AT01-L16-Q06','Sara foi mãe de Isaque, filho da promessa; Agar gerou Ismael, mas fora da aliança.','Agar foi a matriarca do povo escolhido através de quem veio a linhagem messiânica.','Sara e Agar tiveram papéis igualmente importantes na promessa de Deus a Abraão.','Ambas foram esposas legítimas de Abraão e mães dos filhos da promessa.'),('AT01-L16-Q05','Revelam que Deus e fiel e age com misericordia, e que o ser humano e marcado pela incredulidade e conflitos.','Mostram que Deus so abençoa os poderosos e ignora completamente os mais humildes.','Demonstram que a polyca sexual e sanctioned diretamente por Deus sem nenhuma ressalva.','Revelam que a condicao humana e essencialmente perfeita e sem tendencia ao egoismo.'),('AT01-L16-Q04','O nascimento de Ismael e a expulsão de Agar e seu filho para o deserto.','A promessa divina de que Agar seria a mãe do herdeiro de Abraão.','Agar e Sara se reconciliaram e viveram juntas até a morte de Sara.','Abraão construiu um altar em homenagem a Agar e seu filho.'),('AT01-L17-Q05','A provisão e fidelidade de Deus, e a fragilidade da fé humana diante das provas.','A onipotência divina e a capacidade humana de controlar todos os desígnios de Deus.','A rejeição total de Deus ao sacrifício humano e a invalidação das promessas antigas.','A necessidade de sacrifícios humanos contínuos e a impossibilidade do perdão divino.'),('AT01-L17-Q01','Nascimento de Isaque, casamento com Rebeca, pais de Jaco e Esaú','Peregrinação ao Egito, construção do tabernáculo, encontro com Faraó','Conversão no caminho de Damasco, fundação de Antioquia, Martírio de Estêvão','Reconciliação com Esaú, construção de Betel, fuga para Harã'),('AT01-L18-Q03','Jacó rouba a bênção prometida por Isaac a Esaú','Davi e Golias lutam em campo de batalha por terras','Moisés recebe os dez mandamentos no monte Horebe','Abraão nearly sacrifica Isaque no monte Moriá'),('AT01-L18-Q02','Gênesis 25 a 33','Êxodo 1 a 10','Deuteronômio 6 a 12','1 Reis 1 a 5'),('AT01-L17-Q06','Isaque foi o filho da promessa que continuou a aliança de Deus com Abraão.','Isaque foi o primeiro a estabelecer a circuncisão como sinal da aliança com Deus.','Isaque redimiu os israelitas da escravidão no Egito através de sua intercessão.','Isaque escreveu os livros da Lei que foram transmitidos a Moisés no Sinai.'),('AT01-L18-Q05','Deus escolhe segundo seu propósito, não segundo a carne, revelando soberania sobre a queda humana.','Deus privilegia os mais fortes e poderosos para executar seus planos na terra.','A vontade humana é superior aos propósitos divinos, e o homem controla seu destino.','Esaú foi totalmente rejeitado por Deus, sem qualquer bênção ou chance de redenção.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT01-L18-Q04','Jacob obtém a bênção e a primogenitura, mas precisa fugir de Esaú.','Esaú aceita perder a bênção e se torna amigo de Jacob imediatamente.','Isaque também perde a bênção e os dois precisam deixar a terra.','Ambos os irmãos são mortos e suas tribos desaparecem da história.'),('AT01-L19-Q02','Gênesis 35','Êxodo 1','Gênesis 46','Números 1'),('AT01-L18-Q01','Venda do direito de primogenitura, roubo da benção, sonho da escada em Betel, luta em Penuel e reconciliação.','Bênção de Isaque a Esaú, construção da arca, fuga para o Egito e praga das rãs.','Nascimento dos gêmeos, jejum de quarenta dias, construção do templo e cativeiro na Babilônia.','Isaías profetizando, destruição de Jericó, sonho do boi gordo, matrimônio com Lia e reconciliou se com Esaú.'),('AT01-L18-Q06','Jacó foi escolhido para a linhagem da aliança, recebendo o nome Israel e gerando os doze tribos.','Esaú recebeu a bênção profética que selou a aliança eterna com o Deus Todo-Poderoso.','Ambos fundaram templos em Hebrom para adorar ao Senhor conjuntamente como aliança.','Esaú foi o patriarca principal da linhagem messiânica segundo a Escritura Sagrada.'),('AT01-L19-Q01','Ruben, Simeão, Levi, Judá, Dã, Naftali, Gade, Aser, Issacar, Zabulão, José e Benjamim.','Ruben, Simeão, Levi, Judá, Issacar, José, Benjamim, Manassés, Efraim, Gade, Aser e Dã.','Jacó teve doze filhos com suas quatro esposas, que originaram as doze tribos de Israel.','Ruben, Simeão, Aarão, Levi, Judá, José, Benjamim, Nadabe, Abiu, Gideão, Sansão e Dã.'),('AT01-L10-Q05','Registram linhagem e cumprimento das promessas divinas ao longo das gerações.','Detêm apenas dados históricos sem significado teológico para a narrativa bíblica.','Mostram exclusivamente origens étnicas sem связь com bênçãos divinas.','Servem apenas como recurso literário para datar eventos cronológicos.'),('AT01-L13-Q04','Confusão das línguas e dispersão dos povos pela terra.','Fome e praga dizimaram os construtores da torre.','Os construtores foram transformados em estátuas de pedra.','A torre foi concluída e glorificada pelo Altíssimo.'),('AT01-L13-Q01','Nimrod, a construcao da torre e a confusao das linguas','A arca de Noe e os animais entrando dois a dois','A fuga do povo de Israel do Egito com Moises','A destruicao de Sodoma e Gomorra por fogo'),('AT01-L17-Q03','A prova de Isaque no monte Moriá, com intervenção divina ao prover um替代.','A seca em Gerar, onde Isaque foi rejeitado por Abimeleque.','A bênção de Isaque a Esaú pelo direito de primogenitura.','A fuga de Isaque para o Egito durante a fome.'),('AT01-L10-Q06','Cristo é presentado como descendente de Abraão e filho de Davi.','As genealogias provam que Cristo é Deus eterno sem início.','Todas as genealogias de Gênesis são repetidas integralmente em Apocalipse.','Paulo cita Gênesis para demostrar que Cristo existia antes de Adão.'),('AT01-L19-Q03','Os irmãos venderam José por inveja','Os doze filhos litigaram por herança em Hebrom','Jacó abençoou cada filho individualmente em Gileade','Todos os irmãos fugiram do Egito por fome e seca'),('AT01-L17-Q04','Fortalecimento da aliança e preservacao da linhagem prometida a Abraao.','Dissolucao da promessa divina e interrupcao da linhagem escolhida.','Transferencia definitiva da heranca para Esaú e seus descendentes.','Abandono completo da familia e destruicao de todas as nacoes vizinhas.'),('AT01-L19-Q05','Revela soberania divina, condição humana marcada por pecado e redenção.','Mostra que Deus escolhe apenas pessoas moralmente perfeitas para Seus planos.','Indica que os irmãos agiam sempre guiados por orientação divina direta.','Revela que o favoritismo parental não causa conflitos entre siblings.'),('AT01-L19-Q04','O estabelecimento das doze tribos de Israel como nação','A divisão do reino após a morte de Saul por causa das discórdias','O cativeiro babilônico por 70 anos como julgamento divino','A construção do templo de Jerusalém sob o reignio de Davi'),('AT01-L19-Q06','Os doze filhos de Jacó foram os patriarcas das doze tribos, povo da aliança e canal da redenção.','Os doze filhos de Jacó foram os primeiros seguidores de Jesus Cristo na história da redenção.','Os doze filhos de Jacó eram todos nascidos no Egito, durante o cativeiro egípcio.','Os doze filhos de Jacó foram sumos sacerdotes que ministravam no templo de Jerusalém.'),('AT01-L20-Q02','Gênesis caps. 37 a 50','Gênesis caps. 1 a 11','Gênesis caps. 12 a 25','Gênesis caps. 26 a 36'),('AT01-L20-Q04','José se tornou segundo no Egito e Israel habitou em Gósen.','José foi crucificado no Egito e seus ossos foram levados por Gideão.','Os egípcios perseguiram os hebreus imediatamente após a famine.','José fundou a primeira religião monoteísta no Egito antigo.'),('AT01-L20-Q05','A soberania e providência divina sobre a condição humana','A incapacidade humana de modificar os planos divinos','A rejeição total de Deus aos pecadores','O isolamento total de José em sua jornada de fé'),('AT01-L21-Q02','Gênesis 22:14 - Jeová-Jiré, o Senhor proverá.','Gênesis 1:1 - No princípio criou Deus os céus e a terra.','Gênesis 3:21 - Deus fez ao homem e à mulher túnicas de pele.','Gênesis 50:20 - Vos bin intentastes contra mim mal, porém Deus o tornou em bem.'),('AT01-L20-Q06','Preservou a família de Israel da fome, permitindo que a promessa a Abraão se cumprisse.','Transformou o Egito em uma potência mundial através de sua sabedoria e liderança.','Fundou a tribo de Efraim e tornou-se ancestor direto do Messias.','Escreveu os primeiros livros da Lei que seriam seguidos por todo Israel.'),('AT01-L21-Q04','Revela o cuidado amoroso e soberano de Deus sobre toda a criação','Revela que Deus abandonou a criação ao acaso e à própria sorte','Revela apenas a onisciência divina, sem relação com Sua bondade','Revela que a humanidade alcança a salvação por seus próprios esforços'),('AT01-L21-Q01','Deus guia soberanamente a criação cumprindo Seus propósitos de redenção.','A intervenção milagrosa de Deus que elimina completamente o livre-arbítrio humano.','O destino fixo e inevitável que determina toda ação humana sem exceção.','A proteção especial de Deus direcionada exclusivamente aos patriarcas.'),('AT01-L21-Q05','Desenvolve-se pelo cuidado contínuo de Deus com a criação e seu plano redentor em Cristo.','Limitou-se apenas ao Antigo Testamento como proteção exclusiva do povo de Israel.','Foi abandonada após a queda do homem no Éden e nunca mais mencionada.','Restringiu-se aos milagres pontuais realizados por profetas chosen.'),('AT01-L21-Q03','Soberania de Deus, plano divino e cuidado providente.','Livre-arbítrio humano isolado, sem relação com Deus','Ceticismo e dúvida sobre a intervenção divina','Determinismo absoluto sem espaço para a fé'),('AT01-L21-Q06','Fatalismo, deísmo e openismo, que negam a soberania ou a liberdade humana.','Teísmo clássico, deísmo e panteísmo, que confundem a natureza de Deus.','Materialismo, estoicismo e epicurismo, que negam a existência do Criador.','Ceticismo, dualismo e fatalismo, que rejeitam toda possibilidade de plano divino.'),('AT01-L22-Q01','Promessa da semente da mulher que esmagaria a cabeça da serpente em Gn 3.15','A destruicao total de Sodoma e Gomorra como profecia do julgamento messianico','A arca de Noe como simbolo central do Messias Salvador da humanidade','As ofertas de Caim e Abel como tipo perfeito da vinda do Salvador'),('AT01-L22-Q02','Gênesis 3:15 - O protoevangelho, promessa do descendente que esmagaria a serpente.','Gênesis 12:1-3 - A promessa do beneficio às nações através de Abraão.','Gênesis 49:8-12 - A profecia da vara real e do nascente de Judá.','Gênesis 1:1-2:25 - A narrativa da criação do homem à imagem de Deus.'),('AT01-L22-Q03','Promessas a Abraão, Judá, José e Protoevangelho','Narrativas do dilúvio, arco-íris e Noé','Leis do Sinai, tabernáculo e sacerdócio','Genealogias, cidades primitivas e línguas'),('AT01-L22-Q04','Revela o plano redentor de Deus para a humanidade desde o inicio da criação.','Revela que Deus abandonou a humanidade apos a queda no Éden.','Indica que os temas messiânicos foram adicionados posteriormente à Torá.','Mostra que a redenção humana foi uma ideia tardia na tradição bíblica.'),('AT01-L22-Q05','Promessas a Abraão, Daví e interpretações proféticas concretizam-se em Cristo','Promessas messiânicas de Gênesis anulam-se na legislação deuteronomica','Profetas menores substituem as promessas patriarcais por um messias terreno','Promessas messiânicas de Gênesis limitam-se ao livro de Êxodo apenas'),('AT02-L01-Q01','José, Jacó, Faraó, a fome, a escravidão e o êxodo dos israelitas.','Abraão, Sara, a aliança, Melquisedeque e a promessa divina.','Moisés, os Dez Mandamentos, a arca e a construção do templo.','Davi, Golias, Saul, o reino unido e as guerras cananeias.'),('AT02-L01-Q02','No inicio do livro de Exodo','No meio do livro, quando Deus chama Moises','No final, antes da travessia do Mar Vermelho','No livro de Numeros, apos a saida do Egito'),('AT01-L22-Q06','Desconsiderar o contexto histórico e literário original de Génesis ao buscar Cristo.','Tratar toda referência patriarcal como profecia explícita sobre a volta de Cristo.','Ler Génesis apenas como narrativa literal sem reconhecer tipos messiânicos.','Aplicar métodos cabalísticos para interpretar os textos messiânicos do Génesis.'),('AT02-L01-Q03','A resistencia de Farao','A alianca entre Israel e Egito','O casamento de Moises com egipcia','A praga da frogidão nos egipcios'),('AT02-L01-Q04','Através das pragas do Egito e da libertação do povo.','Por meio de pragas que afligiram apenas os israelitas.','Pela derrota dos israelitas diante do faraó.','Mediante a adoração de ídolos egípcios pelo povo.'),('AT02-L01-Q05','A libertação de Israel da escravidão e a destruição do exército egípcio no mar Vermelho.','A conversão de todo o Egito ao Deus de Israel e a paz eterna entre os povos.','O estabelecimento imediato do reino de Israel na terra de Canaã após o êxodo.','A aliança permanente entre faraó e o povo de Israel baseada na libertação.'),('AT02-L02-Q01','Amram, Jochebed, Miriam, Arão e a filha de Faraó','Abraão, Sara, Anão e a esposa de Faraó','José, Maria, Josué e o rei de Egito','Davi, Jessé, Natã e a filha do rei Saul'),('AT02-L02-Q03','O faraó ordenou que todo menino hebreu fosse morto','Deus ordenou a Abraão sacrificar seu filho Isaque','O anjo Gabriel apareceu a Maria anunciando o plano','O sumo sacerdote ordenou a construção do tabernáculo'),('AT02-L01-Q06','Na escravidão egípcia, Israel cresceu como povo e foi redimido por Deus.','Os egípcios ensinaram Israel toda a sua cultura e identidade nacional.','Israel só se formou como nação depois de abandonar completamente o Egíto.','A redenção bíblica não está relacionada com a experiência de Israel no Egíto.'),('AT02-L02-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT02-L02-Q04','Pela preservacao do bebe, pela fidelidadede Deus ao povo hebreu','Pela destruicao dos soldados egipcios no rio Nilo','Pela manifestacao de fogo e trovões sobre o palácio de Faraó','Pela revelacao direta de Deus a Moisés em forma de sarça ardente'),('AT02-L02-Q02','No inicio de Êxodo, quando o Faraó ordena que todos os meninos hebreus sejam mortos.','Após a travessia do Mar Vermelho, quando Deus salva o povo.','Quando Deus se revela a Moisés na sarça ardente no deserto.','No livro de Números, apos a saida do Sinai para Canaã.'),('AT02-L02-Q05','Moisés foi salvo das águas e criado no palácio do Faraó.','Moisés foi rejeitado pelo Faraó e serviu como escravo no Egito.','O Faraó ordenou a libertação imediata de todos os hebreus.','Moisés nasceu durante uma grande fome que durou sete anos.'),('AT02-L03-Q02','No arbusto ardente, em Êxodo 3','Quando婴幼儿 é posto no cesto do Nilo','Diante do Faraó ao exigir liberdade','No monte Sinai ao receber os dez mandamentos'),('AT02-L03-Q05','Libertação dos israelitas do cativeiro egípcio','A construção do primeiro templo em Jerusalém','A destruição total de Israel como nação','O exílio dos israelitas na Babilônia'),('AT02-L03-Q03','Ordem divina para confrontar Faraó e libertar Israel','Fuga secreta do Egito durante a noite','Construção do templo em Jerusalém','Conversão dos egípcios ao Deus de Israel'),('AT02-L03-Q06','Moisés foi chamado para libertar Israel do Egito e medi-la aliança, prefigurando a redenção.','Moisésfoi chamado para estabelecer a monarquia em Israel e consolidar seu reino terreno.','O chamado de Moisés visava apenas registrar a lei sem relação com a redenção.','Moisés foi escolhido como príncipe do Egito para unir Israel politicamente.'),('AT02-L04-Q01','EU SOU','Jeová','Elohim','Aleluia'),('AT02-L03-Q01','Deus na sarça ardente, Moisés, Arão e os sinais ao Faraó.','Josué, Calebe, a arca da aliança e a travessia do Jordão.','Faraó, as pragas do Egito, a travessia do Mar Vermelho e o maná.','Abraão, Isaac, Jacó, os Dez Mandamentos e a construção do tabernáculo.'),('AT02-L04-Q06','SENHOR em maiúsculas','Deus Todo-Poderoso','Jeová em versaletes','Elohim em português'),('AT02-L04-Q03','O tetragrama YHWH é o nome sagrado de Deus na Bíblia, revelado a Moisés','O tetragrama YHWH é um ritual de oração dos sumos sacerdotes.','O tetragrama YHWH é a abreviação hebraica para os Dez Mandamentos.','O tetragrama YHWH é o nome do anjo mensageiro que apareceu a Abraão.'),('AT02-L04-Q02','A autoexistência e imutabilidade do Deus eterno.','A promessa de que Deus abençoaria o Egito com fartura.','A revelação das três pessoas da Trindade em um só Deus.','A identidade de Deus como o deus dos antepassados de Moisés.'),('AT02-L04-Q05','Porque nos manuscritos hebraicos as vogais foram omitidas e o nome era considerado sagrado demais para pronunciar.','Porque os originais hebraicos da Bíblia foram todos perdidos ao longo dos séculos.','Porque a pronúncia mudou significativamente entre os diferentes idiomas semíticos.','Porque os primeiros tradutores gregos alteraram completamente a pronúncia original.'),('AT02-L04-Q04','YHWH revela o Deus eterno e fiel que cumpre suas alianças.','YHWH significa apenas criador e não tem relação direta com a aliança.','O nome YHWH foi revelado apenas no Novo Testamento aos apóstolos.','YHWH representa um deus menor do pacto deuteronômico.'),('AT02-L03-Q04','Pela sarça ardendo, pelo nome ''Eu Sou'' e pela promessa de libertar Israel.','Pela construção do tabernáculo e pelo sacrifício dos primogênitos.','Pela chuva de maná no deserto e pela divisão das águas.','Pela destruição de Sodoma e pela voz dos profetas.'),('AT02-L05-Q03','Deus ordenou a Moisés que exigisse de Faraó a libertação de Israel','Deus ordenou que Moisés construísse um templo para adoração no Egito','Faraó ordenou a Moisés que conduzisse o povo para adorar no deserto','Deus ordenou que os israelitas ficassem escravizados no Egito para sempre'),('AT02-L05-Q04','Por meio das dez pragas do Egito e da abertura do mar Vermelho.','Pela fome e pela sede que assolaram o Egito inteiro por sete anos.','Através de guerras e batalhas entre Israel e os soldados egípcios.','Pela formação de trevas sobre todo o Egito por quarenta dias.'),('AT02-L05-Q05','Morte dos primogênitos, libertação de Israel e afogamento do exército de Faraó.','Firma de alianças comerciais entre Egito e Israel, fortalecendo ambas as nações.','Israel se estabeleceu como nação próspera no Egito por muitos anos.','Faraó converteu-se ao Deus de Israel e abençoou o seu povo.'),('AT02-L05-Q02','No encontro com faraó no capítulo 5 de Êxodo','Na zarça ardente do capítulo 3 de Êxodo','Nas dez pragas do Egito, no capítulo 7','No monte Sinai durante a entrega da Lei'),('AT02-L05-Q01','Moisés e Arão confrontam o faraó com as dez pragas do Egito','Os doze apóstolos e a última ceia de Jesus com os discípulos','Josué, os muros de Jericó e a arca da aliança','Abraão, o sacrifício de Isaque e o anjo do Senhor'),('AT02-L05-Q06','O Êxodo formou Israel como nação e revelou Deus como redentor do seu povo','Determinou que Israel se estabelecesse permanentemente na terra do Egito','Demonstrou que a redenção depende exclusivamente da obediência ritual','Estabeleceu o Egito como modelo da salvação bíblica futura'),('AT02-L06-Q01','Água em sangue, rãs, piolhos, moscas, peste nos animais, úlceras, granizo, gafanhotos, trevas e morte dos primogênitos.','Rãs, piolhos, água em sangue, moscas, peste nos animais, úlceras, gafanhotos, granizo, trevas e morte dos primogênitos.','Água em sangue, rãs, piolhos, granizo, peste nos animais, úlceras, moscas, gafanhotos, trevas e morte dos primogênitos.','Água em sangue, rãs, piolhos, moscas, peste nos animais, gafanhotos, feridas, granizo, trevas e destruição do Faraó.'),('AT02-L06-Q06','NAO SEI','As pragas mostram que Deus desconhece as estrategias dos inimigos','As pragas revelam a impaciencia de Deus diante dos homens','As pragas demonstram o poder limitado do Deus de Israel'),('AT02-L06-Q04','Os israelitas foram poupados na terra de Gósen enquanto o Egito sofria as pragas.','Os israelitas foram ordenados a marcar suas portas com sangue de cordeiro pascal.','Os egípcios foram compelidos a entregar todo o seu gado aos israelitas.','Os israelitas receberam poder divino para realizar sinais contra os egípcios.'),('AT02-L06-Q02','Para que Faraó soubesse que eu sou o SENHOR e os egípcios me conhecessem','Para punir os egípcios por oprimirem os filhos de Israel por quatrocentos anos','Para enriquecer os israelitas com os despojos dos egípcios antes da partida','Para converter Faraó e toda a casa dele ao monoteísmo Yahvista'),('AT02-L06-Q03','Teimosamente endureceu o coração, resistindo a cada praga','Humildemente se rendeu a Deus apos a primeira praga','Purificou o coracao e adorou ao Senhor dos exercitos','Culhou os magos egipcios pela origem das dez pragas'),('AT02-L07-Q01','Jesus Cristo, sua crucificação e ressurreição','Adão, Eva, a serpente e o pecado original','O dilúvio, a arca de Noé e as alianças','A entrega dos Dez Mandamentos no Sinai'),('AT02-L07-Q02','Êxodo 12, na noite da instituição da páscoa','Êxodo 14, quando o povo atravessou o mar Vermelho','Êxodo 7, durante a primeira praga do Egito','Êxodo 20, quando Deus entregou os dez mandamentos'),('AT02-L06-Q05','A páscoa commemorou a salvação dos primogênitos pelo sangue do cordeiro.','A páscoa commemorou a libertação dos escravos através da divisão das águas.','A páscoa commemorou a aliança selada entre Deus e o patriarca Abraão.','A páscoa commemorou a chuva de maná no deserto durante quarenta anos.'),('AT02-L07-Q04','Pela ressurreição de Cristo, que demonstra Seu poder, santidade e fidelidade','Pela destruição de Sodoma e Gomorra, demonstrando Seu poder sobre os pecadores','Pelo dilúvio universal, revelando Sua santidade e juízo sobre a terra','Pela construção do tabernáculo, manifestando Sua presença entre Seu povo'),('AT02-L07-Q05','Perdão dos pecados, reconciliação com Deus e vida eterna','Destruição do templo de Jerusalém e fim definitivo da Lei','Instituição de um reino político terreno para Israel','Exclusão eterna da humanidade do plano de salvação'),('AT02-L07-Q03','A ordem divina de celebrar a páscoa como memorial','A ordem de jejuar durante sete dias consecutivos','O confronto entre Jesus e os anjos no deserto','A ordem divina de construir o templo em três dias'),('AT02-L08-Q02','Êxodo 12','Êxodo 14','Êxodo 7','Êxodo 20'),('AT02-L08-Q01','Moisés, Arão, as dez pragas, a Páscoa e a travessia do Mar Vermelho','Moisés, Abraão, Josué, as dez pragas e a entrada em Canaã','Moisés, Gideão, o maná no deserto e a construção da arca','José do Egito, Jacó, as sete pragas e a travessia do Jordão'),('AT02-L07-Q06','A Páscoa celebra a libertação de Israel da escravidão do Egito, marco da redenção.','A Páscoa é a celebração do nascimento de Abraão em Canaã, berço de Israel.','A Páscoa marca a coroação de Davi como rei de Israel,团契 da redenção.','A Páscoa celebra a destruição do primeiro templo em Jerusalém, symbol da redenção.'),('AT02-L08-Q03','O coração de Faraó foi endurecido','A construção da arca da aliança','A promulgação dos dez mandamentos','A travessia do rio Jordão'),('AT02-L09-Q02','Capitulo 14 de Exodo','Capitulo 13 de Exodo','Capitulo 10 de Exodo','Capitulo 16 de Exodo'),('AT02-L08-Q04','Através das pragas do Egito, da travessia do Mar Vermelho e da aliança no Sinai.','Por meio da construção do templo de Salomão em Jerusalém.','Mediante a destruição das muralhas de Jericó.','Através da vocação de Abraão e da aliança em Génesis.'),('AT02-L08-Q05','A instituição da Páscoa e a travessia do Mar Vermelho','A construção do Templo de Jerusalém e a coroação de Salomão','O cativeiro em Babilônia e a destruição de Jerusalém','A divisão do reino e a adoração do bezerro de ouro'),('AT02-L09-Q01','Moisés, israelitas, mar Vermelho se abre, egipcios se afogam, faraó','Noé, arca, diluvio universal, animais, águas cobriram a terra','Jesus, discipulos, tempestade no mar da Galileia, Jesus dormia na barca','Elias, rio Jordão se abriu, Eliseu, carros de fogo, faraó do Egito'),('AT02-L08-Q06','Formou Israel como nação e demonstrou a redenção de Deus ao seu povo','Estabeleceu Israel como uma teocracia militar para conquistar Canaã','Criou alianças comerciais que enriqueceram as tribos israelitas','Resultou no cativeiro assírio das dez tribos do norte'),('AT02-L09-Q04','Partiu o mar em dois e afogou os egípcios','Fez cair maná do céu e água da rocha','Destruiu Sodoma com fogo e brasas','Fez o sol parar sobre Gibeom'),('AT02-L09-Q03','O mar se abriu por ordem divina e Faraó foi derrotado','As pragas do Egito continuaram durante toda a travessia','Moisés construiu uma arca para atravessar o mar','Os israelitas foram capturados por inimigos na travessia'),('AT02-L09-Q05','Egípcios foram afogados e israelitas creram no Senhor','Aliança de paz entre egípcios e israelitas foi firmada','Moisés tornou-se governante de todo o Egito','As dez pragas continuaram afetando o Egito'),('AT02-L10-Q01','Moisés, israelitas, Deus, travessia do mar vermelho e derrota de Faraó.','Moisés, Josué, Deus, entrada na terra prometida e queda de Jericó.','Moisés, Arão, os levitas, Deus, construção da arca e tabernáculo.','Elias, Eliseu, os profetas, Deus, fogo do Carmelo e derrota de Acabe.'),('AT02-L09-Q06','Revela o poder de Deus na formação de Israel como povo redimido e separado.','Mostra Israel conquistando Canaã imediatamente após a libertação.','Estabelece a aliança do Sinai antes da travessia do mar Vermelho.','Prova que o faraó reconheceu o Deus de Israel como o verdadeiro Deus.'),('AT02-L10-Q04','Na destruição dos inimigos no mar e na promessa de habitar no seu santuário','No recebimento dos dez mandamentos no monte Sinai','Na queda do maná para alimentar o povo no deserto','Na construção da arca da aliança por Bezalel'),('AT02-L10-Q03','Destruição do exército egípcio no Mar Vermelho','Batalha contra os cananeus nas terras altas de Judá','Rebelião do povo contra a ordem de Deus no deserto','Ordem de atravessar o Jordão para conquistar Jericó'),('AT02-L10-Q05','Profecia sobre a destruição dos inimigos de Israel e promessa de salvação eterna.','Libertação imediata de todos os hebreus escravizados no Egito após décadas de opressão.','Instituição da festa da Páscoa como memorial da passagem do anjo destruidor sobre os primogênitos egípcios.','Entrega dos Dez Mandamentos no Sinai como aliança eterna entre Deus e seu povo.'),('AT02-L10-Q02','Êxodo 15, após a travessia do Mar Vermelho','Êxodo 3, quando Moisés vê a zarça ardente','Êxodo 20, quando Deus entrega os Dez Mandamentos','Samuel 2, após a vitória sobre os filisteus'),('AT02-L10-Q06','Celebra a libertação do Egito, estabelecendo Israel como povo redimido por Deus.','Celebra a construção do templo de Jerusalém como centro da adoração.','Documenta as leis mosaicas sobre sacrifícios e rituais de purificação.','Relata a conquista de Canaã sob a liderança de Josué.'),('AT02-L11-Q02','Êxodo 16 e 17','Êxodo 14 e 15','Êxodo 20 e 21','Êxodo 40'),('AT02-L11-Q01','Moisés pediu água a Deus; maná e água da rocha no deserto para os israelitas','Jesus multiplicou pães e peixes no deserto para milhares de pessoas','Elias foi alimentado por corvos durante sua fuga no deserto','Paulo converteu-se ao ouvir a voz de Jesus no caminho de Damasco'),('AT02-L12-Q02','Deus entregou os Dez Mandamentos e fez aliança com Israel','Jesus pregou o Sermão da Montanha aos apóstolos','Moisés recebeu os livros proféticos de Jeremias','Paulo fundou a primeira igreja cristã ali'),('AT02-L11-Q03','Murmurar contra Deus e tentar ao Senhor','Duvidar da identidade de Deus com Moises','Reclamar da falta de alimento e agua','Abandonar a jornada pela terra prometida'),('AT02-L12-Q01','O monte onde Deus entregou os Dez Mandamentos a Moisés','O local sagrado onde Jesus foi crucificado','A montanha da transfiguração de Jesus','O monte onde Noé construiu a arca'),('AT02-L11-Q05','Prova da obediência e vínculo da aliança entre Deus e Israel.','Fim da escravidão egípcia e libertação imediata do povo.','Abundância material e prosperidade permanente de Israel.','Castigo divino pelo murmúrio do povo contra Deus.'),('AT02-L12-Q03','No Sinai, Deus estabeleceu Sua alianca com Israel, entregando a Lei.','O Sinai foi apenas um ponto de passagem na jornada de Israel pelo deserto.','A alianca do Sinai foi feita entre Deus e os povos cananeus.','O Sinai se refere ao monte onde Jesus pregou o Sermon da Montanha.'),('AT02-L12-Q05','Guardar a aliança e os mandamentos de Deus no Sinai','Conquistar militarmente o Monte Sinai para Israel','Construir um templo permanente no topo do Sinai','Abandonar completamente o Sinai após a aliança'),('AT02-L11-Q04','Providenciando maná e água diariamente, mostrando cuidado e fidelidade ao seu povo.','Enviando anjos para entregar maná aos patriarcas no deserto.','Exigindo jejum prolongado como prova de obediência ao Senhor.','Tornando a água amarga em doce para batismo dos levitas.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT02-L11-Q06','Provas da fidelidade de Deus que sustentaram Israel e simbolizaram a redenção futura por meio de Cristo.','Rituais de adoração que Israel devia cumprir para satisfazer a Lei de Moisés no deserto.','Castigos divinos que demostraram a ira de Deus contra a desobediência do povo de Israel.','Sinais de que os ídolos cananeus tinham poder para sustentar Israel no deserto.'),('AT02-L12-Q06','Cumprido em Cristo e na Nova Alianca por Hebreus 12:18-24 e Galatas 4:24-26.','Cumprido atraves dos Sacrificios do Templo de Jerusalém no livro de Hebreus.','Cumprido pelo cumprimento da Lei Cerimonial em Mateus 5:17-18.','Retomado na Multiplicacao dos Pães e Peixes segundo Joao 6:30-35.'),('AT02-L12-Q04','Monte Sinai manifesta a santidade de Deus e Sua presença entre o povo','Monte Sinai mostra que Deus apenas se manifesta em momentos especiais','Monte Sinai ensina que a santidade depende solely da obediencia humana','Monte Sinai indica que Deus nunca habitou no meio do Seu povo'),('AT01-L20-Q01','José vendido, sonhos do Faraó, revelou-se aos irmãos, Jacó desceu ao Egito','As dez pragas, passagem do Mar Vermelho, construção da arca da aliança','Moisés interpretado sonhos do imperador, fugiu para o deserto, regressou ao Egito','A esposa de Faraó, os midianitas, a construção das pirâmides de Gizé'),('AT01-L20-Q03','A intervencao divina em favor de Jose','A promessa de Deus a Abraão sobre a terra de Canaã','O conflito entre Jose e seus irmaos na adolescencia','A ordem divina para que Jose出去 da prisão'),('AT02-L13-Q01','Fora entregue por Deus a Moisés no monte Sinai, no deserto, depois do êxodo do Egito.','Fora entregue por Deus a Adão e Eva no jardim do Éden, quando Deus os criou.','Fora entregue por Deus a Abraão quando este acampou e ofereceu sacrifício em Morija.','Fora entregue por Deus a Josué quando este atravessou o rio Jordão para entrar em Canaã.'),('AT02-L13-Q03','Exigem amor exclusivo, adoração só a Deus e reverência ao seu nome.','Permitem adorar outros deuses além do Deus verdadeiro.','Focam apenas em regras morais e relação entre pessoas.','Instruem a fazer imagens para representar a presença divina.'),('AT02-L13-Q02','Dez preceitos divinos entregues por Deus a Moisés no Sinai.','Sete leis fundamentais reveladas por Deus a Abraão em Judá.','Doze mandamentos escritos por Jesus nos Evangelhos segundo Marcos.','Nove preceitos divinos transmitidos pelo anjo Gabriel a Daniel.'),('AT02-L13-Q04','Os mandamentos do segundo túmulo orientam o amor ao próximo e a vida em sociedade','Os mandamentos regulam exclusivamente as relações entre governantes e súditos','As relações humanas são dirigidas apenas pelos livros proféticos, não pelos mandamentos','Os mandamentos determinam únicamente regras para atividades econômicas e comerciais'),('AT02-L13-Q05','Os Dez Mandamentos são a base da aliança selada no monte Sinai com Israel.','Os Dez Mandamentos foram revelados originalmente na aliança com Abraão, antes do Sinai.','Os Dez Mandamentos se aplicavam exclusivamente aos sacerdotes e líderes religiosos.','Os Dez Mandamentos perderam validade com a construção do primeiro templo.'),('AT02-L13-Q06','Amarás o Senhor, teu Deus, de todo o coração, e ao teu próximo como a ti mesmo.','Guarda fielmente os Dez Mandamentos e observarás toda a Lei.','Não farás para outrem o que não queres para ti.','Faze aos outros o que queres que vos façam.'),('AT02-L14-Q01','As leis divinas de Êxodo 20.22 a 23.33','Os dez mandamentos gravados nas duas tábuas','O livro de Levítico com suas ordenanças','As promessas de Deus a Abraão em Gênesis'),('AT02-L14-Q03','NAO SEI','As leis dividiam Israel em doze tribos independentes sem conexão entre si','Os princípios da aliança eram aplicados apenas aos sacerdotes e não ao povo','As leis ignoravam completamente os princípios da aliança e eram baseadas apenas em costumes egípcios'),('AT02-L13-Q07','Tradições católicas separam ‘não terás outros deuses’ e ‘não farás imagens’, enquanto protestantes as combinam, resultando em numerações diferentes.','A diferença está apenas na ordem dos mandamentos, pois o conteúdo permanece idêntico em todas as tradições cristãs.','Igreja Ortodoxa e Protestantismo usam a mesma numeração, differing apenas de católicos na interpretação dos textos.','A numeração dos Dez Mandamentos é igual em todas as tradições, pois foi definida pelo Concílio de Nicéia.'),('AT02-L14-Q05','Êx 21-23 foi lido ao povo e ratificado com aspersão de sangue na cerimônia de Êx 24.','Êx 21-23 foram leis distintas que substituiram os rituais de sangue de Êx 24.','O Livro da Aliança foi acrescentado posteriormente à cerimônia original de Êx 24.','Êx 24 narra a fundação do santuário, enquanto o Livro da Aliança originou-se independentemente.'),('AT02-L15-Q02','No capitulo 32 de Exodo, apos os 40 dias no monte Sinai','No capitulo 20 de Exodo, ao lado dos Dez Mandamentos','No inicio de Exodo, quando o povo deixa a terra do Egito','No livro de Levitico, durante a dedicacao do tabernaculo'),('AT02-L14-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT02-L14-Q06','Porque foram destinadas ao povo de Israel no contexto da antiga aliança mosaica.','Porque devem ser interpretadas literalmente como mandamentos universais para todos os Cristãos.','Porque foram escritas em hebraico arcaico que exige interpretação rabínica exclusiva.','Porque o Novo Testamento anulou completamente todas as leis do Antigo Testamento.'),('AT02-L15-Q01','Aaron fez o bezerro de ouro e o povo o adorou.','Samuel ungiu Saul diante do bezerro de ouro em Betel.','O bezerro de ouro foi derretido por Gideão na batalha.','Elias desafiou os profetas do bezerro de ouro no Carmelo.'),('AT02-L15-Q03','Desobediência à ordem divina contra idolatria','Reclamação do povo por falta de água no deserto','Ordem divina para construir a arca da aliança','Confronto entre Moísés e o faraó do Egito'),('AT02-L15-Q04','Deus revela sua santidade destruindo o bezerro e punindo a idolatria do povo.','Deus revela seu poder ao aceitar o bezerro como forma legítima de adoração temporária.','Deus revela sua fidelidade ao transformar o bezerro em símbolo sagrado da aliança.','Deus revela sua santidade ao comandar Aarão para construir o bezerro de ouro.'),('AT02-L16-Q01','Jesus Cristo, a Santa Ceia, crucificação, ressurreição e dom do Espírito Santo','Moisés, os Dez Mandamentos e a arca da aliança no Sinai','O dilúvio, a arca de Noé e as tábuas da lei','Abraão, Isaque, Jacó e a promessa da terra de Canaã'),('AT02-L15-Q05','Quebra das tábuas, morte de cerca de três mil homens e praga de Deus sobre o povo.','Moisés rompeu os céus e ascendeu ao céu em corpo e alma, abandonando o povo.','As tábuas da Lei foram guardadas intactas na Arca da Aliança sem nenhum dano.','O povo foi liberado imediatamente de toda punição e perdoado instantaneamente.'),('AT02-L16-Q02','Quando Moises recebe as segundas tabuas no Sinai apos o bezerro de ouro','Quando Deus fala a Moises da sarca ardente no deserto','Quando o povo constrói o bezerro de ouro no deserto','Quando Deus passa adiante e proclama seu nome ao povo'),('AT02-L16-Q04','Pela morada do Espirito Santo que regenera, santifica e confirma a aliança eterna.','Pela observancia rigorosa da Lei de Moises guardada no coracao do povo escolhido.','Pela destruicao dos inimigos de Israel e restricao territorial de Canaan.','Pela revelacao de angulos secretos sobre o trono de Deus aos profetas.'),('AT02-L16-Q05','Perdao dos pecados, Espírito Santo e vida eterna.','Destruição do templo de Jerusalém e fim do judaísmo.','Obrigatoriedade da circuncisão e guardas das leis mosaicas.','Separação definitiva entre Israel e as demais nações.'),('AT02-L15-Q06','O bezerro de ouro expôs a infidelidade de Israel, e Deus, por Moisés, demonstrou Sua redenção.','O bezerro de ouro foi um método aprovado por Deus para a adoração inicial de Israel.','O bezerro de ouro uniu as tribos de Israel como símbolo nacional de identidade política.','O bezerro de ouro foi um sacrifício aceito que acelerou a formação da aliança mosaica.'),('AT02-L17-Q01','Santuário móvel construido por Moisés no deserto, onde Deus habitava.','A arca da aliança que guardava as tábuas da lei com os dez mandamentos.','Tenda de oração construida pelo rei Salomão no monte Sião em Jerusalém.','Cidade sagrada onde os patriarcas reuniam o povo para celebrar pactos.'),('AT02-L16-Q03','A Lei escrita nos corações e o perdão dos pecados','A destruição do templo e a perda da arca da aliança','A obrigação de celebrar todas as festas judaicas','O retorno ao culto no templo de Jerusalém'),('AT02-L17-Q02','Servia de habitação de Deus entre o povo, centro do culto e dos sacrifícios.','Era um marco geográfico para orientacao das doze tribos no deserto.','Funcionava como quartel militar e arsenal de guerra contra inimigos.','Servia de moradia temporaria para os anciãos e líderes religiosos.'),('AT02-L17-Q03','Pátio, Santuário e Lugar Santíssimo','Pátio Externo, Tenda Interior e Sala do Conselho','Área Sagrada, Altar Central e Câmara dos Levitas','Portão Principal, Átrio dos Sacerdotes e Santo dos Santos'),('AT02-L16-Q06','Aliança renovadaforma Israel espiritualmente e consuma redenção por Cristo.','Aliança renovada estabelece Israel como reino militar mediante conquistas.','Aliança renovada substitui redenção pela observância estrita da lei mosaica.','Aliança renovadaforma igreja separada de Israel sem relação com sua história.'),('AT02-L17-Q04','Bezalel e seus帮手fabricaram a Arca, o Altar, o Candelábro e a Mesa.','Os Levitas transportavam apenas as Trombetas de Prata e as Bolsinhas.','Somente o Sumo Sacerdote podia tocar os móveis sagrados do Tabernáculo.','Os objetos sagrados eram todos feitos de ferro e bronze purificados.'),('AT02-L17-Q07','Cristo, como Sumo Sacerdote, entrou no verdadeiro tabernáculo celestial','O tabernáculo mosaico foi reconstruído no templo de Herodes','Cristo estabeleceu um novo tabernáculo físico em Jerusalém','O tabernáculo do Antigo Testamento perdeu todo valor espiritual'),('AT02-L17-Q06','A glória de Deus habitava no Santo dos Santos entre o povo.','Os sacrifícios de animais indicavam a presença de Deus no tabernáculo.','As cortinas coloridas mostravam a santidade de Deus ao povo.','O incenso queimado diariamente revelava a presença divina no altar.'),('AT02-L18-Q02','A urna do maná, a vara de Arão e as tábuas da Lei, sob o propiciatório.','As tábuas da Lei, o incenso sagrado e a coroa de espinhos.','O livro de Moisés, a espada de Josué e o turbante do sumo sacerdote.','A urna do maná, os ossos de José e o shamir de Salomão.'),('AT02-L18-Q01','Arca sagrada construída por Moisés para guardar as tábuas da Lei e outros objetos sagrados.','Altar de ouro construído por Davi no tabernáculo para offering sacrifícios.','Templo sagrado erguido por Salomão para guardar relíquias dos patriarcas.','Caixa de madeira utilizada para transportar o maná durante o êxodo do Egito.'),('AT02-L18-Q04','No Lugar Santíssimo','No átrio do tabernáculo','No compartimento dos pães','Perto da porta de entrada'),('AT02-L18-Q03','Era a tampa de ouro puro da Arca da Aliança, onde Deus habitava entre os querubins.','Era o altar de incenso que ficava no Lugar Santo do Tabernáculo.','Era o véu que separava o Lugar Santo do Santo dos Santos.','Era o altar onde se ofereciam os sacrifícios de animais.'),('AT02-L18-Q05','A arca era o propiciatório onde Deus prometia estar presente entre seu povo.','A arca continha relíquias sagradas que representavam a autoridade real divina.','O propiciatório era o altar sacrificial onde os sacerdotes ofereciam sacrifícios.','A nuvem de glória descia sobre a arca para abençoar os sacrifícios oferecidos.'),('AT02-L18-Q06','A arca representava a presença de Deus, não um artefato de poder automático.','A arca perdeu poder sagrado ao ser construída por mãos humanas imperfeitas.','Os profetas ensinaram que seu poder dependia exclusivamente de materiais raros.','Os sumérios já possuíam arcas similares com poderes sobrenaturais idênticos.'),('AT02-L19-Q01','O sacerdócio em Êxodo é o ministério de Aãrum e seus filhos no tabernáculo.','O sacerdócio em Êxodo se baseia na linhagem dos primogênitos de cada família israelita.','O sacerdócio em Êxodo é um sistema de adoração liderado por judges e anciãos.','O sacerdócio em Êxodo se refere aos profetas que intermediam a aliança com Deus.'),('AT02-L19-Q02','Sacrifícios, ofertas, intercessão, santificação e culto no tabernáculo e no templo.','Governo civil, julgamento de causas e liderança militar nas batalhas de Israel.','Predição do futuro, exorcismo de demônios e realização de milagres pelos sacerdotes.','Cobrança de impostos, administração de terras e comando do exército de Israel.'),('AT02-L19-Q04','O sacerdócio ensina que Deus é santo e que só se aproxima dele quem é santificado.','O sacerdócio ensina que os sacerdotes controlam livremente o acesso de qualquer pessoa a Deus.','O sacerdócio revela que a presença de Deus pode ser invocada por qualquer ritual humano.','O sacerdócio mostra que a santidade de Deus depende das boas obras dos líderes religiosos.'),('AT02-L19-Q06','Cristo é o sumo sacerdote eterno que cumpre e supera o sacerdício levítico','O sacerdício é exercido exclusivamente pelos descendentes de Arão no NT','Os apóstolos criaram uma nova hierarquia sacerdotal terrena','O sacerdício mosaico foi abolido sem continuidade alguma no NT'),('AT02-L19-Q05','Sustentar o sacerdício levítico e servir como reino de sacerdotes','Designar os sumos sacerdotes entre todas as doze tribos','Realizar pessoalmente todos os sacrifícios do templo','Estabelecer regras para a seleção de profetas nacionais'),('AT02-L19-Q03','O sacerdócio levítico foi instituído no Sinai para manter a aliança mediante sacrifícios e intercessão.','O sacerdócio de Melquisedeque foi o modelo direto para o sistema do Sinai.','A aliança do Sinai aboliu completamente qualquer forma anterior de sacerdócio.','O sacerdócio não possuía função mediadora, servindo apenas para fins administrativos.'),('AT02-L20-Q03','Moisés pediu para ver a glória de Deus em Êxodo 33','O anjo do Senhor ordenou que Jacó fugisse em Gênesis 32','Deus confrontou Abraão pedindo o sacrifício de Isaque','A arca da aliança ordenou que Davi dançasse diante dela'),('AT02-L20-Q01','Jesus Cristo, Moisés, a shekiná, o Sinai e a ressurreição','Adão e Eva, o pecado original, a expulsão do Éden','Caim e Abel, o sacrifício, a maldição de Caim','Davi e Golias, a coroação, o reino de Judá'),('AT02-L20-Q02','Quando a glória do Senhor encheu o tabernáculo','Quando Deus falou com Moisés na sarça ardente','Quando o maná caiu no deserto para Israel','Quando a nuvem desceu sobre o mar Vermelho'),('AT02-L20-Q04','Pela Criação, pelas Escrituras e pela redenção em Cristo','Pela prática de boas obras e caridade aos pobres','Através de rituais e tradições religiosas humanas','Por acumulo de riquezas e prosperidade material'),('AT02-L21-Q02','Pois Cristo, nosso cordeiro pascal, foi imolado.','Porque a Páscoa celebra o nascimento de Cristo como Salvador.','Porque os apóstolos instituíram a festa para lembrar a crucificação.','Porque a Páscoa é a festa que commemorate a ressurreição de Lazaro.'),('AT02-L20-Q05','Os presentes reconhecem sua impureza e se prostram em reverência ao Senhor.','Os fiéis recebem dons espirituais extraordinários e profetizam com poder.','O мест围攻 сьогодніня敌дим и несмыслено возлюби余长безогову.','Os inimigos de Deus são destruídos e o templo é completamente consumed pelo fogo.'),('AT02-L20-Q06','Glória de Deus lidera Israel e realiza a redenção','Glória de Deus é recompensa pela obediência de Israel','Glória de Deus foi herdada por Abraão como promessa','Glória de Deus se manifesta apenas no templo de Jerusalém'),('AT02-L21-Q03','Cristo e chamado de nosso cordeiro pascoal em 1 Corintios 5:7','O evangelho de Lucas identifica Cristo como o cordeiro pascal no capitulo 15','Jesus e comparado ao cordeiro pascal atraves de uma metafora em Hebreus 11:17','O Apocalipse menciona Cristo como cordeiro pascal em seu primeiro capitulo'),('AT02-L21-Q04','Figuras de Cristo e do Espírito, citados por Paulo e João','Proibições superadas pela Graça, conforme o Evangelho de Mateus','Símbolos do paganismo derrotada, referenciados no livro de Atos','Precedentes da circuncisão espiritual, segundo a Epístola aos Gálatas'),('AT03-L01-Q01','Levítico estabelece leis sobre santidade e culto a Deus.','Levítico narra a fuga do Egito e travessia do deserto.','Levítico contém profecias sobre o Messias e os últimos dias.','Levítico ensina princípios de economia e商贸易.'),('AT03-L01-Q02','Deus fala do tabernáculo recém-inaugurado','Os sacrifícios detalhados de Levítico continuam a história','Os Dez Mandamentos se repetem no Sinai','A arca da aliança é descrita em detalhes'),('AT02-L21-Q05','Pela sua morte na cruz e ressurreição, Cristo redimiu a humanidade do pecado e da morte.','Por meio de seus milagres e curas, Jesus demonstrou poder sobre enfermidades e pragas.','Estabelecendo um reino político celeste onde não haveria mais opressão romana.','Enviando o Espírito Santo para eliminar instantaneamente toda tentação humana.'),('AT02-L21-Q07','Cristo e o novo Moises que liberta seu povo da escravidao do pecado, inaugurando a nova criacao.','O cativeiro babilonico foi a conclusao definitiva da libertacao do Exodo.','A construcao do Primeiro Templo representou a culminancia das promessas divinas do Exodo.','A divisao dos reinos de Israel e Juda simbolizou a concretizacao das promessas do Exodo.'),('AT02-L21-Q06','A Ceia do Senhor é o memorial do Cordeiro Pascal que selou a Nova Aliança pelo seu sangue.','A Ceia do Senhor substitui completamente a Páscoa e rompe com a Nova Aliança instituída.','A Nova Aliança foi selada pelo sangue animal oferecido no Templo durante a Páscoa.','A Ceia do Senhor é apenas um simbolismo da Páscoa judaica sem relação com a Nova Aliança.'),('AT03-L01-Q03','Deus é santo e ordena que Israel seja santo (Lv 19:2) - a presença divina exige purificação.','Porque Deus tem medo de ser contaminado pelos pecados do seu povo','Porque a santidade era apenas um requisito administrativo do templo','Porque os sacerdotes criaram regras para manter o poder sobre Israel'),('AT03-L01-Q04','Santidade, sacrifícios, sacerdócio, leis de purezas e festas sagradas','Profetas, promessas, aliança, história da salvação e esperança messiânica','Realeza, guerras santas, conquista da terra, tribos e governo','Sabedoria, hymnos, poesia, provérbios e cânticos de louvor'),('AT03-L02-Q02','A santidade de Deus exige separação e obediência para que Israel se aproxime do Senhor.','As leis de Levítico foram organizadas segundo a sabedoria dos sacerdotes para facilitar a adoração.','Os rituais de Levítico seguem principalmente a tradição oral dos anciãos de Israel.','A estrutura de Levítico baseia-se na aliança mosaica sem relação direta com a santidade divina.'),('AT03-L01-Q06','O sistema sacrificial de Levítico prefigura Cristo como sacrifício perfeito.','Os rituais de Levítico sao apenas tradições historicas sem vinculo com Cristo.','A lei cerimonial de Levítico mostra que a salvacao vem pelas obras da lei.','Os sacrifícios de Levítico tornaram desnecessaria a morte redentora de Cristo.'),('AT03-L02-Q01','Afirmar que Deus é santo significa reconhecer Sua pureza absoluta e separação do mal.','Afirmar que Deus é santo significa reconhecer Seu poder supremo sobre toda a criação.','Afirmar que Deus é santo significa reconhecer Seu amor infinito e incondicional.','Afirmar que Deus é santo significa reconhecer Sua ira perfeita contra todo pecado.'),('AT03-L02-Q03','Para ser testemunho do Deus santo às nações e refletir o caráter divino.','Porque eram moralmente superiores a todas as outras nações da época.','Porque solicitaram a Deus para ser um povo separado e dedicado.','Para obter poder político e econômico sobre os povos vizinhos.'),('AT03-L02-Q06','Pela fé em Cristo, a obra do Espírito Santo e a obediência às Escrituras.','Pela observação rigorosa da Lei mosaica e seus rituais outermost.','Através de boas obras e doações à igreja sem necessidade de arrependimento.','Pela pertença formal à instituição eclesiástica sem transformação interior.'),('AT03-L03-Q01','Holocausto, Manjares, Sacrifício Pacífico, Expiação e Culpa.','Holocausto, Purificação, Aliança, Benção e Redenção.','Sangue, Incenso, Flor, Fruto e Cereal.','Holocausto, Manutenção, Comunhão, Perdão e Renovação.'),('AT03-L02-Q05','A santidade de Deus separa o seu povo para o culto puro, a conduta ética e a comunhão fraternal.','A santidade divina permite que o homem viva sem padrões morais, pois a graça cancela a ética.','A santidade de Deus é apenas um atributo teológico sem efeito prático no cotidiano do fiel.','A santidade divina exige que os crentes se isolem do mundo, abandonando toda vida comunitária.'),('AT03-L02-Q04','Santidade é ser separado; separação é o ato de viver para Deus; dedicação é a entrega total.','Santidade, separação e dedicação são conceitos sem relação bíblica entre si.','Santidade significa ser perfeito; separação é viver isolado; dedicação é ir à igreja.','Santidade depende do esforço humano; separação é dom de Deus; dedicação é automática.'),('AT03-L03-Q02','Voluntárias: Holocausto Oferta de Manjares e Oferta de Paz Culpa e Pecado: Oferta de Culpa e Oferta pelo Pecado','Voluntárias: Oferta pelo Pecado e Oferta de Culpa Holocausto e Oferta de Manjares: de culpa','Todas as ofertas eram voluntárias segundo Levítico Somente o Holocausto era obligatorio','Oferta de Paz e Holocausto eram de culpa Oferta de Manjares e Oferta pelo Pecado eram voluntárias'),('AT03-L03-Q03','Fazer expiação pelos pecados, conforme Levítico 17:11','Purificar os sacerdotes antes do culto no tabernáculo','Alimentar os anjos ou seres celestiais que habitavam o tabernáculo','Marcar os animais limpos para separação do rebanho'),('AT03-L03-Q04','Porque o sacrifício representava Cristo, o Cordeiro sem defeito, oferta perfeita pelos pecados.','Porque os animais com defeito eram impuros e não podiam tocar o altar sagrado do templo.','Porque Deus preferia animais sadios para consumir como alimento durante as festividades.','Porque os sacerdotes precisavam vender apenas animais perfeitos para obter maior lucro no templo.'),('AT03-L03-Q06','Porque o sangue dos animais não podia tirar o pecado de forma permanente.','Porque os animais oferecidos eram insuficientes em quantidade para satisfazer a Deus.','Porque Deus exigia diversidade nos tipos de oferendas presentadas ao santuário.','Porque os sacerdotes precisavam de prática constante nos rituais de sacrifício.'),('AT03-L04-Q01','Oferta queimada inteiramente ao Senhor no altar','Sacrifício onde apenas a gordura era oferecida a Deus','Ritual de purificação realizado com água benta','Celebração comunitária de agradecimento ao Senhor'),('AT03-L04-Q02','O holocausto envolvia animais limpos, altar, fogo sagrado e servico sacerdotal.','O holocausto era um metodo romano de execucao em Kreuzigung em cruz de madeira.','O holocausto era um sacrificio de sangue humano ofrecido sobre altares de pedra.','O holocausto era realizado por anjos no tempio celestial de forma automatic.'),('AT03-L03-Q05','Os sacrifícios mostravam que o pecado exige pagamento e apontam para Cristo.','Os sacrifícios ensinavam que a obediência moral bastava para a salvação.','Os sacrifícios ofereciam perdão eterno sem necessidade de repetição.','Os sacrifícios funcionavam como ritual mágico de purificação automática.'),('AT03-L03-Q07','Os sacrifícios levíticos eram repetidos anualmente e nunca tiravam pecados; o sacrifício de Cristo foi único e alcançou perfeição eterna.','Os sacrifícios levíticos e o de Cristo eram igualmente eficazes para a salvação.','Os sacrifícios levíticos eram superiores por serem ordenados diretamente por Deus.','Os sacrifícios levíticos foram criados depois do sacrifício de Cristo na narrativa bíblica.'),('AT03-L04-Q03','Oferta queimada inteiramente a Deus para propiciação dos pecados do povo.','Ritual onde os fiéis consumiam a carne da oferta em comunidade sagrada.','Sacrifício realizado para aplacar a fome dos deuses idólatras.','Cerimônia de purificação através da fumaça que abençoava os campos.'),('AT03-L04-Q05','Sem defeito, sangue aspergido e inteiramente queimado no altar','Podia ser oferecida em qualquer lugar fora do Tabernáculo','Sangue guardado para consumo dos sacerdotes após o sacrifício','Oferta exclusiva para sacerdotes, leigos não participavam'),('AT03-L05-Q02','Ofertante, flor de farinha, azeite, sal, incenso e mão do sacerdote.','Somente o sangue do animal e a fumaça do altar.','O sumo deromãs, o incenso e a agua viva.','Os levitas, o pão da proposicao e o vinho da libacao.'),('AT03-L04-Q06','O holocausto prefigura o sacrifício expiatório de Cristo na cruz.','O holocausto representa apenas um ritual de purificação física.','O holocausto demonstra que a vida santa se obtém por méritos próprios.','O holocausto anula a necessidade de qualquer sacrifício posterior.'),('AT03-L05-Q01','Era uma oferta de farinha e cereal, sem sangue, queimada sobre o altar.','Era uma taxa imposta aos estrangeiros para entrada no tabernáculo.','Era o dízimo dos primogênitos doados ao sacerdócio.','Era um sacrifício de animais menores como pombas.'),('AT03-L05-Q03','Agradecer a Deus por suas provisões e fazer memória perante ele','Alimentar exclusivamente os sacerdotes e suas famílias','Celebrar os festivais de colheita com toda a comunidade','Substituir os sacrifícios de sangue nos dias de jejum'),('AT03-L06-Q01','Sacrifício de comunhão com Deus, oferecido em sinal de paz e gratidão.','Oferta queimada inteiramente no altar, sem participação do offerente.','Sacrifício realizado exclusivamente pelos sacerdotes antes de seus serviços.','Ritual de purificação feito apenas no Dia da Expiação.'),('AT03-L05-Q06','A oferta de cereal representa a devoção perfeita e a vida dedicada a Deus.','A oferta de cereal é um sacrificio pelo pecado que substitui a morte de animais.','O cerealoffering deve ser feito com fermento para simbolizar a presença do Espirito.','A oferta de cereal representa apenas bens materiais sem significado espiritual.'),('AT03-L06-Q02','O offerente, o sacerdote, o altar e o animal sem defeito.','Apenas os levitas, o incenso e a tenda da congregacao.','O sumo sacerdote, o pao da proposicao e o candelabro.','O animal, o sangue no propiciatorio e os anjos do Senhor.'),('AT03-L06-Q03','A paz com Deus e o próximo, expressando comunhão e gratidão.','A purificação dos pecados do povo antes da entrada no santuário.','O sustento exclusivo dos sacerdotes e das suas famílias.','A obtenção de prosperidade material e riqueza através de bênçãos divinas.'),('AT03-L06-Q04','Representava comunhao e louvor a Deus, sendo distinta das ofertas de expiacao.','Era a principal oferta de expiacao e perdao dos pecados segundo a Lei.','Tinha poder de purificacao ritual que removia toda impureza do offerente.','Era obrigatoria e exigia sangue derramado para obtainer o perdão dos pecados.'),('AT03-L07-Q01','Sacrifício para expiação de pecados não intencionais','Sacrifício queimado inteiramente sobre o altar','Oferta de gratidão por bênçãos recebidas','Sacrifício para confirmar pacto com Deus'),('AT03-L06-Q05','Tres tipos: acoes de gracias, pagar voto ou oferta voluntaria','Podia ser oferecida apenas por padres e levitas','A carne deveria ser queimada no altar por completo','So podia ser oferecida durante a festa da páscoa'),('AT03-L07-Q02','cabrito macho, cordeiro, cabra, rolas, pombinhos, farinha e sangue','ouro, prata,青铜 e pedras preciosas','cavalos, bois, jumentos e ovelhas','vinho, incenso, mirra e bálsamo'),('AT03-L07-Q03','Fazer expiação pelos pecados e purificação das pessoas e do santuário.','Proteger o povo de inimigos naturais e pragas divinas enviadas.','Celebrar vitórias militares alcançadas pelo povo de Israel.','Determinar dias oficiais de jejum e orações coletivas.'),('AT03-L07-Q06','A oferta pelo pecado demonstra a necessidade de expiação, apontando para Cristo como sacrifício perfeito.','A oferta pelo pecado elimina a necessidade de santificação e santificação na vida do crente.','A oferta pelo pecado foi totalmente abolida, não tendo mais relevância para o crente moderno.','A oferta pelo pecado ensina que o crente pode pecar impunemente pela fé em Cristo.'),('AT03-L07-Q05','O sacerdote, a assembleia, o príncipe e o comum: regras distintas conforme o grau','O sangue era oferecido no altar principal e a carne no lugar santo interior','A vítima deveria ser sama e sem mácula, e todo o povo participava do ritual','As oferendas variavam conforme a fase da lua e o ciclo agrícola do ano'),('AT03-L08-Q01','Sacrifício por pecados contra coisas sagradas ou próximo, com restituição.','Sacrifício para pedir bênçãos materiais ao Senhor, sem necessidade de restituição.','Oferta queimada inteiramente no altar sem participação do sacerdote nem doofferente.','Sacrifício somente para pecados intenccionais contra os mandamentos divinos.'),('AT02-L14-Q02','Leis civis, cerimoniais e morais.','Apenas leis cerimoniais e rituais.','Somente mandamentos morais.','Leis apenas sobre o tabernáculo.'),('AT02-L17-Q05','Porque o santuário era a morada de Deus e exigia obediência precisa','Porque os israelitas não sabiam construir sem instruções detalhadas','Porque o tabernáculo era apenas um símbolo político de poder','Porque Deus queria ocupar o tempo livre do povo no deserto'),('AT02-L21-Q01','Modelo de libertação: opressão, clamor, intervenção divina e redenção do povo.','Simples registro histórico de migração de hebreus do Egito para Canaã.','Narrativa que ensina apenas sobre a construção da Arca da Aliança.','História de guerra entre Egito e Hebreus por territórios na Palestina.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT03-L01-Q05','O sacerdócio mediava, os sacrifícios expiavam, a pureza aproximava','Esses elementos eram apenas simbolos sem efeito espiritual real','A comunhao dependia somente da obediencia estrita a Lei','Sacrifícios serviam apenas para sustentar financeiramente os sacerdotes'),('AT03-L04-Q04','O holocausto era sacrifício de expiação para obter perdão dos pecados.','O holocausto era ritual de ação de graças para a comunidade.','O holocausto era oferta material para acumular riquezas.','O holocausto aplicava-se a todo tipo de sacrifício.'),('AT03-L05-Q04','Representava oferta de ação de graças, simbolizando pureza e comunhão com Deus.','Era oferta que diretamente expiava os pecados do povo, purificando a alma.','Constituía o sacrifício mais importante do sistema levítico, superior aos demais.','Continha mel e fermento, simbolizando a imperfeição humana diante de Deus.'),('AT03-L05-Q05','Não podia conter fermento nem mel, e levava sal.','Devia ser accompanies only incense as offering.','Era obrigatória only na Festa dos Tabernáculos.','Somente os anciãos da cidade podían ofrecer.'),('AT03-L06-Q06','A oferta pacífica simboliza a reconciliação e comunhão com Deus obtidas por meio da morte expiatória de Cristo, demonstrando a vida santa em paz e fellowship.','A oferta pacífica realizava expiação pelos pecados do povo, garantindo a salvação eterna de forma automática e completa.','A oferta pacífica consistia num sacrifício obrigatório para a justificação do pecador diante da lei cerimonial mosaica.','A oferta pacífica representava a guerra santa contra os inimigos de Israel, ordenando a destruição completa dos adversários.'),('AT03-L08-Q03','A oferta pela culpa expiava pecados específicos e restaurava a comunhao com Deus.','A oferta pela culpa era para celebrar vitorias militares e dar gracias a Deus.','A oferta pela culpa servia exclusivamente para sustentar os sacerdotes e suas familias.','A oferta pela culpa era oferecida apenas pelos lideres religiosos da epoca.'),('AT03-L08-Q02','Carneiro sem defeito, sacerdote e ofertas de manejo.','Pao sem fermento, vinho e incenso aromatico.','Bode expiatorio e sangue de touro imaculado.','Primicias da terra e dizimos materiais.'),('AT03-L07-Q04','A oferta pelo pecado purificava da culpa e restabelecia a comunhao do ofertante com Deus.','A oferta pelo pecado era um ritual exclusivamente social sem qualquer efeito espiritual.','A oferta pelo pecado purificava apenas o santuario, nao o proprio ofertante.','A oferta pelo pecado simbolizava a vida mundana e nao tinha relacao com a santidade.'),('AT03-L08-Q04','Proporcionava expiação, purificação e restauração da comunhão com Deus','Exigia apenas confissão verbal sem necessidade de qualquer sacrifício','Era oferecida exclusivamente pelo sumo sacerdote no Dia da Expiação','Anulava automaticamente toda impureza sem necessidade de arrependimento'),('AT03-L09-Q02','Sumo sacerdote, ofertas, sacrifícios, santuário e rituais de purificação.','Anjos e demônios participavam diretamente dos rituais de adoração.','Os profetas assumiam as funções sagradas no lugar dos sacerdotes.','Torres de vigilância e espadas constituíam os principais objetos litúrgicos.'),('AT03-L09-Q01','Os sacerdotes eram descendentes de Arão, designados para realizar os serviços religiosos no santuário.','Os sacerdotes eram os governantes da tribo de Judá que serviam no santuário.','Os sacerdotes eram comerciantes de animais usados nos sacrifícios do Tabernáculo.','Os sacerdotes eram todos os membros da tribo de Levi sem distinção hierárquica.'),('AT03-L08-Q06','A oferta pela culpa antecipa a expiação de Cristo pelo pecado.','A oferta pela culpa elimina a necessidade de arrependimento pessoal.','A oferta pela culpa foi totalmente abandonada no Novo Testamento.','A oferta pela culpa demonstra que Cristo não precisava morrer na cruz.'),('AT03-L09-Q03','Mediar entre Deus e o povo, realizando sacrifícios e intercedendo.','Conduzir guerras santas e liderar exércitos em nome de Deus.','Administrar os templos e coletar dízimos para sustento próprio.','Escrever e copiar textos sagrados para distribuição nas sinagogas.'),('AT03-L09-Q04','Através de sacrifícios expiatórios, purificavam o povo e mantinham a santidade do santuário.','Os sacerdotes vendiam indulgências para garantir a salvação dos pecadores.','Eram responsáveis por realizar liturgias diárias nas sinagogas de todo o mundo.','Por meio de jejuns e orações pessoais sem envolvimento de rituais.'),('AT03-L08-Q05','A carne tinha de ser comida no mesmo dia ou no dia seguinte, com pao sem fermento.','A carne tinha de ser queimada completamente no altar como sacrificio.','O animaloffering devia ser um boi sem defeito, nao um carneiro.','Apenas os sacerdote podiam comer da carne do sacrificio todo.'),('AT03-L09-Q06','Pregando a Palavra e administrando sacramentos para compreender a Cristo e viver em santidade.','Realizando milagres e prodigios para provar o poder de Deus ao povo.','Interpretando sonhos e visoes profeticas para revelar a vontade divina.','Controlando fenomenos naturais como tempestades e pragas conforme a vontade celestial.'),('AT03-L09-Q05','Não ter defeitos físicos, não se contaminar com mortos, não beber vinho ao servir.','Deviam usar vestes completamente vermelhas e usar coroas de ouro todos os dias.','Precisavam jejuar semanalmente e viver isolados do restante do povo.','Deviam renunciar a todos os bens e viver como mendigos nos templos.'),('AT03-L10-Q01','Eram os dois filhos mais velhos de Arão, consumidos por fogo do Senhor em Levítico.','Eram servos do tabernáculo que desobedeceram às regras de pureza ritual em Levítico.','Eram levitas designados para tocar as trombetas nas cerimônias de Levítico.','Eram sacerdotes que foram censurados por Deus, mas não morreram em Levítico.'),('AT03-L10-Q04','Morreram por oferecer fogo estranho e foram substituídos na função sagrada','Foram os primeiros sumos sacerdotes e simbolizavam a expiação perfeita','Serviam como auxiliares na limpeza do Tabernáculo e expiavam pecados','Foram nomeados guardiões da arca e participavam dos sacrifícios diarios'),('AT03-L11-Q01','Animais que podiam ou não ser usados em sacrifícios e consumo, conforme suas características.','Animais que viviam no templo e fora dele, conforme a lei de Deus.','Criaturas divididas entre servos e libres, conforme sua posição social.','Animais que podiam ou não entrar nas casas, conforme a região.'),('AT03-L10-Q03','Filhos de Arão que ofrecen fogo estranho ao Senhor e foram consumidos pelo fogo.','Eram profetas que previam a destruicao de Sodoma e foram atingidos pelo fogo celestial.','Ofereciam sacrifícios aos idolos cananeus e foram eliminados pelo exercito de Josue.','Eram reis de Israel que abandonaram a lei mosaica e foram enforcados pelo povo.'),('AT03-L10-Q06','Sua morte por fogo estranho ilustra a santidade de Deus e a necessidade de obediência aos Seus mandamentos.','Seu sacrifício antecipou a obra redentora de Cristo no Calvário.','Foram os primeiros salmistas a louvar a Deus com música sagrada.','Sua obediência perfeita serviu de modelo para os apóstolos.'),('AT03-L10-Q02','Nadab e Abiú, censer de incenso, fogo estranho ao Senhor','Os filhos de Arão, o altar de ouro, incenso aromatico','Arão, sangue de bode, propiciacao pelo pecado','Abel e Caim, oferta de primicias, maná do céu'),('AT03-L11-Q02','Deus, Moisés e os levitas ensinaram as leis de animais puros e impuros.','Somente os sacerdotes podiam determinar quais animais eram puros ou impuros.','Os animais eram classificados como puros ou impuros pelos profetas de Israel.','As leis de animais puros e impuros foram inventadas pelos rabinos fariseus.'),('AT03-L11-Q03','Separar Israel como nação santa e distinguir o puro do impuro para adoração.','Determinar quais animais podiam ser consumidos para uma alimentação mais saudável.','Classificar os animais conforme seu grau de santidade inerente e poder espiritual.','Estabelecer hierarquias de prestígio social entre as tribos de Israel.'),('AT03-L11-Q04','Animais puros podiam servir de oferta pelo pecado e expiação','Animais impuros eram os únicos aceitos em sacrifícios','A pureza dos animais determinava a santidade do templo','Todos os animais podiam ser usados indistintamente nos altares'),('AT03-L10-Q05','Eram filhos de Arão e deviam observar rigorosamente os mandamentos divinos','Eram levitas e podiam entrar no Lugar Santissimo a qualquer hora','Deviam oferecer incenso com fogo sagrado somente nos sábados','Eram cohenim que podiam adorar a Deus conforme melhor lhes parecesse'),('AT03-L11-Q05','Animais ruminantes com unhas fendido sao puros; aquaticos precisam de barbatanas e escamas.','Animais de cor clara sao puros e os escuros impuros, conforme Levitico 11.','Somente animais de grande porte sao puros; os pequenos eram considerados todos impuros.','Animais que morrem naturalmente sao puros, e os sacrificados no templo sao impuros.'),('AT03-L11-Q06','A distinção ensina santidade e a obra purificadora de Cristo.','Prova que os animais têm alma igual aos humanos','Demonstra que a alimentação afeta a alma humana','Estabelece regras permanentes de alimentação para todos'),('AT03-L12-Q02','Sacerdotes, agua, sangue, cinzas e banhos rituais','Apenas os profetas e os reis de Israel','Orações e jejum exclusivamente','Somente objetos do templo'),('AT03-L12-Q01','Estado de limpeza sagrada necessario para participar do culto e se aproximar de Deus.','Pureza ritual era um tipo de jejum alimentar praticado pelos sacerdotes.','Pureza ritual era a obrigação de construir altares em todos os lares.','Pureza ritual era um testamento espiritual sobre a vida apos a morte.'),('AT03-L12-Q03','Separar o sagrado do profano e permitir a aproximacao a Deus','Garantir a saude fisica e previnir doencas entre o povo','Demonstrar poder economico e status social na comunidade','Regulamentar o uso da terra e dos recursos naturais'),('AT03-L13-Q01','Tsaraat, afecções de pele reguladas nos capítulos 13 e 14 de Levítico.','Pragas incuráveis enviadas por Deus como punição direta aos pecadores.','Doenças contagiosas que afectavam exclusivamente os sacerdotes.','Feridas abertas que causavam morte imediata do infectado em sete dias.'),('AT03-L12-Q04','Rituais de pureza preparavam o povo para a santidade através da expiação.','A pureza ritual substituiu a necessidade de sacrifícios e expiação.','Rituais de pureza eram apenas tradições culturais sem significado espiritual.','A pureza ritual garantia salvação eterna pelas obras da lei.'),('AT03-L12-Q06','As leis de pureza ritual apontavam para Cristo, que purifica do pecado.','As leis de pureza ritual criavam barreiras para separar pecadores dos justos.','As leis de pureza ritual eram obrigatorias para todos os crentes em todas as eras.','As leis de pureza ritual determinavam quem podia participar da vida social da igreja.'),('AT03-L13-Q02','Naaman, Miriam, ritos de purificacao com cedar, hissopo e lã escarlate','Abraão, sua tenda e os unguentos sagrados que curavam os enfermos de pele','O templo de Salomão e os óleosantos que o sumo sacerdote aplicava nos leprosos','Daniel, Sadraque, Misael e Azarias e os jejuns que eliminavam doenças de pele'),('AT03-L12-Q05','Distinção entre limpo e impuro com ofertas, banhos e períodos de separação','Classificação dos animais conforme a cor e tamanho para determinaçao de pureza','Separação baseada exclusivamente na linhagem e genealogia dos participantes','Regras aplicáveis apenas aos sacerdotes e nao ao povo de Israel'),('AT03-L13-Q03','Manifestar o juizo divino e separar o impuro do acampamento.','Eliminar permanentemente os doentes da comunidade.','Testar a resistencia fisica e espiritual do povo.','Servir como sinal magico contra inimigos de Israel.'),('AT03-L13-Q05','Levítico 13 e 14 estabeleciam regras sobre diagnóstico pelo sacerdote, isolamento e purificação.','O enfermo deveria jejuar por quarenta dias antes de ser examinado pelo sacerdote.','Somente o médico do templo podia diagnosticar e determinar o tempo de isolamento.','O leproso deveria ser expulso do acampamento imediatamente sem chance de purificação.'),('AT03-L13-Q06','Simbolizam pecado e impureza; Cristo purifica leprosos, mostrando poder sobre o mal','Prova que Jesus era medico e ensinava que a fe ensinava que a fe heal diseases','Doencas de pele eram premios divinos para os justos e seus escolhidos','Serviam como teste de fe onde apenas os fortes espiritualmente sobreviviam'),('AT03-L13-Q04','DFDF tornavam o homem impuro, exigindo separação e sacrifício para purificação.','DFDF eram castigo divino direto, sem possibilidade de purificação pelo sistema sacrificial.','DFDF indicavam possessão demoníaca, e cura vinha apenas por exorcismo.','DFDF eram sinal de santidade especial, isolando o doente para comunhão com Deus.'),('AT03-L14-Q02','Águas, cinzas da vacca vermelha, sangue e sacerdócio.','Fogo, enxofre, ventos e trovão do Sinai.','Orações, jejum, peregrinações e esmolas aos pobres.','Sangue de bode, pão ázimo, vinho e unção com azeite.'),('AT03-L14-Q01','Ritual de limpeza que tornava o impuro apto a cultuar a Deus.','Banho em águas paradas realizado ao amanhecer para purificação física do corpo.','Confissão verbal de pecados ao sacerdote sem necessidade de oferta ou sacrifício.','Cerimônia de aspersão com água benta para expulsar demônios do corpo.'),('AT03-L14-Q05','Aspersão com água lustral, prazo de sete dias e oferta pelo pecado.','Jejum exclusivo de quarenta dias sem alimento algum.','Unção com azeite sobre a testa apenas.','Circuncisão imediata no oitavo dia.'),('AT03-L15-Q01','Levítico 16','Levítico 23','Levítico 17','Levítico 15'),('AT03-L14-Q03','Remover a impureza sagrada e restaurar a comunhão do povo com Deus','Celebrar datas festivas e marcar eventos importantes do calendário religioso','Estabelecer hierarquias sociais entre os membros da comunidade','Realizar casamentos sagrados entre membros das tribos de Israel'),('AT03-L14-Q04','Purificação removia a impureza e restaurava a comunhão com Deus, apontando para a expiação de Cristo.','Purificação era apenas um ritual físico que não tinha relação com o pecado ou a santidade.','Purificação era um requisito exclusivamente cerimonial que foi abolido completamente na Lei.','Purificação era automática e não exigia arrependimento ou fé do individuo.'),('AT03-L15-Q04','Um era oferecido em sacrifício e o outro enviado ao deserto','Ambos eram queimados inteiros sobre o altar do templo','Serviam para identificar os pecadores entre o povo','Um era consumido pelos sacerdotes e o outro solto no templo'),('AT03-L15-Q05','Remoção dos pecados, carregando-os para longe','Sacrifício para satisfazer a Deus','Símbolo da punição dos pecadores','Oferta de agradecimento ao Senhor'),('AT03-L15-Q03','Porque era o dia da expiação, para expiar os pecados do povo, conforme a Lei.','Porque só nesse dia a arca da aliança estava presente no Santo dos Santos.','Porque os demais sacerdotes haviam sido contaminados pelos pecados do povo.','Porque Deus ordenou que a entrada fosse limitada a esse dia específico.'),('AT03-L16-Q01','Conjunto de leis em Levítico 17-26 que ordena santidade ao povo de Deus','Lista de ofertas e sacrifícios do tabernáculo nos livros de Números e Êxodo','Código moral de Levítico 1-7 sobre limpeza e impureza ritual do santuário','Profecias de Ezequiel sobre a reconstrução do templo e seus rituais'),('AT03-L15-Q07','NAO SEI','Baptismo e uma repeticao do sacrificio de Cristo','Ceia representa a ultima ceia como memorial humano','Uncao点滴 substitute a obra Finished na cruz'),('AT03-L15-Q06','Com sangue no Santo dos Santos, expiavam-se sacerdote, povo e santuário.','Por jejum e confissão pública, os pecados eram perdoados ao sacerdote e ao povo.','O fogo do altar consumia os sacrifícios para purificar o santuário anualmente.','Sangue era aspergido no altar para o povo, no véu para o sacerdote e nas tábuas para o santuário.'),('AT03-L16-Q02','Sacerdotes, levitas, santuário, altar, sacrifícios, festividades, ano sabático','Profetas e visionários com santuários e altares pagãos','Reis e guerreiros em palácios e carros de guerra','Mulheres, crianças, escravos e terras estrangeiras'),('AT03-L16-Q05','Distinções entre limpo e impuro, regras de santidade e justiça social','Apenas regras dietéticas sobre animais limpos e impuros','Somente vestimentas e ornamentos sagrados dos sacerdotes','Unicamente leis sobre a construção do tabernáculo'),('AT03-L16-Q03','Separar Israel das nações, promovendo santidade e comunhao com Deus.','Estabelecer um codigo penal detalhado para punir crimes civis e militares.','Regulamentar exclusivamente rituais agricolas relacionados as estacoes do ano.','Determinar a estrutura politica e hierarquica do governo teocratico.'),('AT03-L16-Q06','Estabelece que a santidade reflete o caráter de Deus, Cristo é o exemplo supremo.','Substitui completamente a Lei antiga pela graça, eliminando a necessidade de santidade.','Determina regras rígidas que Cristo revogou integralmente, sem relação com seu ensino.','Autoriza a santificação humana independente da ação do Espírito Santo.'),('AT03-L17-Q02','Sacerdotes, tabernaculo, rituais de purificacao e processos legais com testemunhas.','Anjos mensageiros, pactos celestiais e aliancas eternas entre Deus e os homens.','Profetas, sacrifícios diarios e grandes festivais de louvor no templo.','Reis guerreiros, altares pagãos e rituais de fertilidade cananeus.'),('AT03-L17-Q01','Regulamentações de pureza sexual encontradas no código de santidade do Levítico.','Procedimentos para ofrecimentos e sacrificios no altar do tabernáculo.','Preceitos dietéticos que proibiam o consumo de animais impuros.','Normas sobre a observância do sábado e descanso semanal.'),('AT03-L17-Q03','Manter a santidade do povo de Deus e proteger a família.','Evitar qualquer contato físico entre homens e mulheres.','Separar economicamente casais de diferentes classes sociais.','Permitir a livre expressão sexual fora do casamento.'),('AT03-L17-Q04','Elas separavam Israel como povo santo, exigindo pureza para a adoração e a expiação.','As leis sexuais eram apenas regras sociais sem conexão com a santidade ou adoração.','A expiação nunca se aplicava às impurezassexuais conforme as leis do Antigo Testamento.','As leis sexuais foram criadas principalmente para separar economicamente homens e mulheres.'),('AT03-L17-Q05','Distinções entre limpo e impuro e entre relações permitidas e proibidas','Liberdade total para relações sexuais sem restrições','Proibição de toda forma de contato físico entre cônjuges','Unicamente regras sobre a frequência dos encontros conjugais'),('AT03-L18-Q03','Comemorar os grandes atos de Deus e fortalecer a aliança com o povo','Celebrar conquistas militares e fortalecer o poderio bélico de Israel','Providenciar diversão e entretenimento para o povo durante o ano','Reunir estrangeiros e nações vizinhas em show de força nacional'),('AT03-L18-Q01','Solenes donde Deus reunia seu povo em assembleia santa ao longo do ano.','Reuniões populares onde os israelitas decidiam asuntos de governança e leis civis.','Celebrações agricolas instituídas por Moíses para marcar as colheitas e estações.','Cerimônias penitenciais realizadas exclusivamente pelos sacerdotes no tabernáculo.'),('AT03-L17-Q06','Elas revelam a santidade de Deus e a necessidade de redenção por Cristo','Elas foram todas abolidas no Novo Testamento sem nenhuma relação com Cristo','Elas garantem automaticamente a salvação ao serem cumpridas pelo homem','Elas serviam apenas para condenar e não apontam para a graça divina'),('AT03-L18-Q02','Cordeiros, pães asmos, trombetas e ofertas de sangue.','Búfalos, arroz, sinos e oferendas de leite.','Cabras, hidromel, flautas e presentes de madeira.','Touros, vinho,harpas e orações em latim.'),('AT03-L18-Q04','As festas celebravam a santidade de Deus e ofereciam meios de purificacao e expiacao para o povo.','As festas eram apenas celebrações agricolas sem relação com santidade ou expiacao.','As festas serviam principalmente para separar Israel das demais nacoes por motivos culturais.','As festas foram estabelecidas depois do cativeiro babilonico para substituir os sacrifícios.'),('AT03-L18-Q06','As festas de Israel point para Cristo e Sua obra redentora.','As festas de Israel sao apenas costumes antigos sem relevancia.','As festas de Israel foram abolidas completamente apos Cristo.','As festas de Israel serviam apenas para celebrar colheitas.'),('AT03-L18-Q05','Cada festa tinha ofertas, dias de descanso e proibições específicas conforme a Lei.','As regras variavam conforme a região e o clima de Israel.','Somente os sacerdotes podiam participar das festas.','As festas não tinham regras fixas, eram decididas pelos anciãos.'),('AT03-L19-Q02','Terra em pousio, libertação de escravos e remissão de dividas','Dizimo obligatorio e ofertas ao templo de Jerusalem','Sacrificios de animais e rituais de purificação','Jejum e orações prolongadas no santuario'),('AT03-L19-Q01','Ano de descanso da terra a cada sete anos, conforme Levítico 25.','Celebração anual da libertação dos servos hebreus no Egito.','Sete semanas de jejum e oração para purificação do povo.','Descanso semanal do sábado prolongado para sete dias seguidos.'),('AT03-L19-Q05','Descanso da terra, remissão de dividas e libertação de escravos.','Jejum absoluto e fechamento de todas as casas de oração por um ano.','Duplicação dos sacrifícios e ampliação do trabalho no Templo.','Proibição total de contato entre israelitas e estrangeiros.'),('AT03-L20-Q01','De cinquenta em cinquenta anos, apos sete semanas de anos.','De sete em sete anos, ao final de cada ciclo de anos sabaticos.','De doze em doze anos, correspondendo as doze tribos de Israel.','De vinte e um em vinte e um anos, a cada geracao.'),('AT03-L19-Q03','Permitir o descanso da terra e remissão das dividas ao povo.','Celebrar a páscoa com sacrifícios de animais no templo.','Realizar peregrinações obrigatórias anuais a Jerusalém.','Proibir completamente o trabalho manual por sete dias.'),('AT03-L19-Q06','O ano sabático aponta para o descanso em Cristo e a libertação dos pecados.','Prova que a observância literal da Lei é suficiente para a salvação.','Determina que os fiéis devem descansar um ano a cada sete para serem Santos.','Estabelece um calendário fixo para as festas do Senhor sem relação com a redenção.'),('AT03-L19-Q04','O ano sabático santificava o tempo e a terra, separando-os para Deus.','O ano sabático oferecia expiação pelos pecados capitais do povo.','O ano sabático purificava o santuário através de ofertas de animais.','O ano sabático apagava toda iniqnidade do povo.'),('AT03-L20-Q02','O jubileu era anunciado apos sete ciclos de anos sabáticos, no quinquagesimo ano.','O jubileu era celebrado a cada sete anos, coincidindo com o próprio ano sabático.','O jubileu não tinha qualquer conexão com o ciclo dos anos sabáticos na lei mosaica.','O jubileu era proclamado antes de se cumprir o ciclo completo dos anos sabáticos.'),('AT03-L20-Q03','Eram restauradas ao dono original, dividas canceladas e servos libertados.','Eram vendidas ao templo para pagamento de dividas ao Senhor.','As propriedades eram redistribuidas entre os pobres da tribo.','Dividas eram renegociadas em novos prazos de pagamento.'),('AT03-L20-Q04','No Jubileu as terras vendidas eram devolvidas às famílias originais.','As terras eram redistribuídas igualmente entre todas as doze tribos.','O governo ficava com as terras e as arrendava novamente.','Novas terras eram conquistadas e distribuídas às famílias.'),('AT03-L20-Q05','Libertação de servos, restituição de bens e perdão de dívidas, promovendo justiça.','Conquista militar de territórios inimigos e distribuição de despojos entre o povo.','Proibição completa de toda atividade comercial e laboral durante o período.','Sacrifício de animais para expiação collective e purificação dos pecados.'),('AT03-L21-Q03','Estabelecer ordem moral, reaffirmar a aliança e distinguir o povo de Deus.','Proteger contra doenças físicas e espirituais apenas.','Celebrar datas festivas e marcar eventos familiares.','Substituir leis escritas e regulamentos civis.'),('AT03-L20-Q06','O jubileu projeta a libertação em Cristo, que proclama redenção ao povo.','O jubileu era apenas um ano de descanso agrícola, sem relação com libertação.','Cristo rejeitou o conceito de jubileu em seu ministério de redenção.','A libertação bíblica era exclusivamente política, sem fundamento teológico.'),('AT03-L21-Q01','Consequências do pacto mosaico: bênçãos por obediência e maldições por desobediência aos mandamentos.','Rituais de purificação para pecadores arrependidos no tabernáculo.','Práticas de magia e feitiçaria proibidas pela lei cerimonial.','Ofertas diárias para agradar aos deuses pagãos da região.'),('AT03-L21-Q04','Bênçãos seguiam a santidade e pureza; maldições, a impureza. A expiação restabelecia.','Bênçãos e maldições eram arbitrárias, sem relação com santidade ou pureza.','A santidade anulava completamente os efeitos de bênçãos e maldições.','Expiação era desnecessária para restaurar a comunhão após maldições.'),('AT03-L21-Q02','Deus, sacerdotes, profetas, imposição de mãos, unção e mandamentos.','Anjos e demônios como agentes principais de bênçãos e maldições.','Templos pagãos, ídolos e rituais de adivinhação.','Sacrifícios humanos e pactos com espíritos familiares.'),('AT03-L21-Q05','Exigiam testemunhas, pronunciamento por sacerdotes e vinculação à aliança','Podiam ser pronunciadas livremente por qualquer pessoa, sem restrições','Não se relacionavam com obediência ou desobediência à lei divina','Não havia regras específicas sobre quando e como deveriam ser pronunciadas'),('AT03-L22-Q01','Cristo é o sacrifício perfeito que cumpre e encerra toda a oferta pelo pecado.','Os sacrifícios levíticos foram revogados sem qualquer relação com Cristo.','Cristo reiterou a necessidade dos sacrifícios animais após sua morte.','Os sacrifícios do AT serviam apenas como rituais culturais sem propósito espiritual.'),('AT03-L21-Q06','Cristo suportou a maldição para que fossemos abençoados por Deus','As bênçãos são conquistadas pelos méritos pessoais do fiel','Maldiçōes simbolizam apenas o fracasso humano sem relação com Cristo','A vida santa depende da obediência perfeita à Lei de Moisés'),('AT03-L22-Q03','O sangue de Cristo expia, purifica a consciência e garante o perdão dos pecados.','O sangue de Cristo apenas simboliza amor, sem efeito real na expiação.','A purificação pelo sangue depende de obras humanas para ser completa.','O perdão vem apenas pela fé, sem necessidade do sangue de Cristo.'),('AT03-L22-Q06','A morte de Cristo no Calvário substituiu todos os sacrifícios de animais.','Deus permitiu que os sacrifícios fossem abolidos por serem muito dispendiosos.','Os sacrifícios foram proibidos após a destruição do Templo de Jerusalém.','A Lei Mosaica deixou de ser obrigatória quando os apóstolos morreram.'),('AT03-L22-Q05','Cristo é o Sumo Sacerdote que se ofereceu uma única vez como sacrifício perfeito.','Cristo oferece-se repetidamente no céu como os sacerdotes terrenos faziam.','Cristo é apenas sacerdote, sendo o Espírito Santo a verdadeira oferta.','Cristo continua offering animais no templo celestial como no AT.'),('AT03-L22-Q02','Jesus é o Cordeiro de Deus, sem defeito, que se offerceu para tirar o pecado do mundo.','Porque os sacerdocios humanos tambem podiam offerecer sacrificios perfeitos, como os levitas.','Porque a obediencia de Maria e Jose o tornaram santo e sem pecado desde o nascimento.','Porque Deus o isentou de toda lei, permitindo que elle offerecesse qualquer sacrificio.'),('AT03-L22-Q07','Os sacrifícios de Levítico prefiguram a obra redentora de Cristo na cruz.','Levítico anula a necessidade da cruz ao cumprir todas as leis temporais.','A cruz torna Levítico obsoleto e sem relevância teológica atual.','Cristo rejeitou integralmente o sistema sacrificial levítico.'),('AT04-L01-Q02','No Sinai','Na travessia do mar Vermelho','Na entrada de Canaã','No deserto de Sim'),('AT04-L01-Q01','O recenseamento das doze tribos e a disposição dos acampamentos ao redor do Tabernáculo.','O recenseamento dos levitas aos vinte e cinco anos e sua dedicação ao serviço do santuário.','A nomeação dos setenta anciãos para governar o povo e auxiliar nas tarefas administrativas.','O censo dos homens de guerra de cada tribo para a conquista da Terra Prometida.'),('AT04-L01-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L01-Q03','As doze tribos de Israel organizadas conforme Num 2','As doze tribos de Israel e os levitas','As dez tribos do norte mais Judá e Benjamim','As doze tribos mais as duas metades de José'),('AT04-L01-Q06','Deus organizou as tribos para cumprir Seus propósitos, mostrando fidelidade e ordem.','As tribos se organizaram por conta própria, mostrando a iniciativa humana.','A organização das tribos ensina que a fé depende de líderes políticos.','As tribos foram organizadas conforme a capacidade militar de cada uma.'),('AT04-L02-Q02','Sinaí','Deserto de Parã','Jericó','Mar Vermelho'),('AT04-L01-Q05','Organização militar e territorial para entrada na Terra Prometida.','Dissolução da aliança divina com o povo de Israel.','Destruição completa dos povos cananeus sem resistência.','Fim da liderança de Moisés e dos ancianos sobre o povo.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT04-L02-Q01','Censo militar das tribos (Nm 1) e recenseamento para distribuição da terra (Nm 26).','Contagem dos levitas para coleta do dízimo e manutenção do tabernáculo.','Recenseamento ordenado pelo imperador romano para taxação dos judeus.','Censo exclusivo dos levitas realizado por Arão para designar sacerdotes.'),('AT03-L15-Q02','Realizava os sacrifícios pelo pecado do povo e entrava no Santo dos Santos.','Pregava ao povo sobre arrependimento e expunha os pecadospublicamente.','Cessava todas as funções sacerdotais e jejuava sozinho no templo.','Distribuía a carne dos sacrifícios expiatórios a todos os israelitas.'),('AT03-L14-Q06','Purificação revela a limpeza do pecado pela obra redentora de Cristo','Purificação se alcança exclusivamente pela obediência estrita à Lei','Purificação é desnecessária, pois Cristo já garantiu a santidade plena','Purificação compete exclusivamente à força de vontade humana sem graça divina'),('AT03-L16-Q04','Ligava a santidade à obediência aos estatutos e aos rituais de expiação.','Eram leis apenas para os sacerdotes, não para todo o povo.','Substituía os sacrifícios por obras de caridade e jejum.','Negava qualquer relação entre pureza ritual e santidade moral.'),('AT03-L22-Q04','Cristo se sacrificou uma vez; sacrifícios de animais precisavam ser repetidos.','Sacrifícios de animais eram mais eficazes por possuírem valor próprio.','Cristo e os animais se sacrificaram a cada ano com a mesma finalidade.','Os sacrifícios de animais nunca foram aceitos por Deus.'),('AT04-L02-Q03','As doze tribos de Israel, exceto Levi, que foi contada à parte','Somente as tribos de Judá e Benjamim, por serem tribos reais','As doze tribos incluindo Levi, que participava do culto','Apenas as tribos do norte, que formavam o reino de Israel'),('AT04-L02-Q04','O pecado do censo de Davi','O mandamento divino de numerar Israel','A promessa de descendência numerosa','A praga como intervenção divina pelo census'),('AT04-L02-Q06','O censo mostra a fidelidade de Deus ao multiplicar Israel conforme a promessa.','O censo prova que Deus cobrava impostos do Seu povo fiel.','O censo revela a desobediência de Israel ao recusar a liderança.','O censo demonstra a rejeição do povo ao liderazgo de Moisés.'),('AT04-L03-Q01','Os israelitas acamparam ao redor do Tabernáculo, organizados segundo as doze tribos (Nm 2).','Os levitas desmontavam e armavam o Tabernáculo quando o povo partia de cada acampamento no Sinai.','As doze tribos se organizaram em torno do Templo de Salomão construído no deserto da Arábia.','Moab e Amom forneceram tendas e suprimentos para o acampamento israelita no deserto de Parã.'),('AT04-L02-Q05','A praga enviou por Deus matou setenta mil homens em Israel','O povo foi prohibido de entrar na Terra Prometida por quarenta anos','Guerra civil estourou entre as doze tribos de Israel','A prosperidade economica de Israel foi dividida igualmente entre o povo'),('AT04-L03-Q03','As doze tribos de Israel acamparam ao redor do tabernáculo no deserto do Sinai.','Os profetas de Israel e os sacerdotes levitas formavam o acampamento principal no deserto.','Os gentios, os romanos e os gregos participavam do acampamento no deserto bíblico.','Os reis de Judá e Israel montaram suas tendas separadamente no deserto de Parã.'),('AT04-L03-Q02','No deserto de Sinai, após a saída do Egito','Na travessia do Rio Jordão para Canaã','No momento da fuga do Egito sob a liderança de Faraó','No retorno do cativeiro babilônico a Jerusalém'),('AT04-L04-Q01','Censo, subdivisão em famílias e serviço no tabernáculo','Guerras de conquista e distribuição de territórios','Administração de dízimos e ofertas ao templo','Sacrifícios de animais e celebrações litúrgicas'),('AT04-L04-Q02','No deserto, durante o cuidado do tabernaculo','Na saida do Egito, no exodo de Israel','Na travessia do Mar Vermelho','Na entrada em Canaa, na conquista'),('AT04-L04-Q03','A tribo de Levi, separata para o serviço sagrado.','As doze tribos de Israel indistintamente.','Somente os filhos primogênitos de cada família.','A tribo de Judá e seus descendentes.'),('AT04-L03-Q04','O bezerro de ouro','O maná do céu','A arca da aliança','A serpente de bronze'),('AT04-L03-Q06','NAO SEI','Ensinou que Deus abandona seu povo no deserto','Prova que a disciplina de Deus sempre traz fracasso','Demonstra que a liderança moisesica foi rejeitada por Deus'),('AT04-L03-Q05','Ser tentado e provado por Deus no deserto.','Receber visões profeticas e revelacoes divinas.','Realizar sacrifícios e ofertas perante o Senhor.','Ter visoes da Gloria de Deus face a face.'),('AT04-L05-Q01','O voto de nazireado em Numeros 6, com regras sobre vinho, cabelos e corpos','A construção do tabernáculo e as ofertas de sacrifícios diarios','O leviatã e as pragas do deserto durante a jornada de Israel','A divisão das terras de Canaã entre as doze tribos de Israel'),('AT04-L04-Q04','A proibicao de dormir com outro homem como com mulher','A prohibicao de trabalhar no septimo dia como dia de descanso','O mandamento de amar o proximo como a si mesmo','A destruicao das cidades de Sodoma e Gomorra por fogo divine'),('AT04-L05-Q03','O nazireado era voto individual de israelitas, como Sansão e Samuel.','O nazireado era privilégio exclusivo da tribo de Levi no santuário.','Somente as tribos do norte de Israel praticavam o nazireado.','Os nazireus formavam uma das doze tribos de Israel.'),('AT04-L04-Q06','Os levitas ensinam que servir a Deus com fidelidade e obediência traz bênçãos','Os levitas eram os guerreiros que lideraram as conquistas de Canaã sob Josué','Os levitas fundaram as escolas proféticas e escreveram os livros históricos','Os levitas governaram Israel como juízes e reyes durante o período monarchico'),('AT04-L05-Q02','Durante a jornada no deserto, apos a saida do Sinai','No momento da travessia do Mar Vermelho','Ao chegar a Terra Prometida de Canaa','Durante a permanencia no Monte Sinai'),('AT04-L04-Q05','A tristeza segue o riso, e o fim da alegria é tristeza.','A prosperidade segue a alegria e o vinho copioso.','A sabedoria eterna segue a levidade e o prazer.','A vida abundante segue todo divertimento humano.'),('AT04-L05-Q04','Abster-se de vinho e bebidas fermentadas','Procurar visoes e revelacoes divinas','Jejuar por quarenta dias e quarenta noites','Oferecer sacrificio pelo pecado ignorado'),('AT04-L06-Q01','Bênção Aarônica em Números 6:22-27','Sacrifícios no tabernáculo em Números 1-10','Purificação dos levitas em Números 8:5-22','Inauguração do templo em 2 Crônicas 5:6-14'),('AT04-L06-Q02','No deserto, no monte Sinai','Na travessia do Mar Vermelho','Nas planícies de Moabe','No Egito, antes do êxodo'),('AT04-L06-Q04','Promessa de Deus de abençoar o seu povo','Mandamento de orar tres vezes ao dia','Pecado da infidelidade a Deus','Intervencao divina na partilha do mar Vermelho'),('AT04-L06-Q03','Aaron e seus filhos abençoavam as doze tribos de Israel','As doze tribos abençoavam os sacerdotes de Levi','Apenas a tribo de Judá realizava a bênção sacerdotal','Os reis de Israel abençoavam os sacerdotes'),('AT04-L05-Q06','Demonstra dedicação total a Deus por meio de disciplina e separação voluntária','Ensina que a salvação depende de observar rigorosamente regras alimentares','Prova que Deus abandona quem não consegue cumprir votos por toda a vida','Indica que líderes devem rejeitar todo contato com a comunidade'),('AT04-L05-Q05','Abster-se de vinho, não cortar os cabelos e não tocar em mortos.','Abster-se de toda carne e de leite.','Tornar-se sacerdote do Santuário.','Jejuar por quarenta dias e noites.'),('AT04-L06-Q05','Proteção, favor, presença e paz divinos','Riqueza material, prosperidade financeira e abundância','Poderes sobrenaturais, curas e exorcismos','Justiça divina, punição dos ímpios e guerra santa'),('AT04-L07-Q03','Moisés, Arão e as doze tribos de Israel','Os profetas Elias, Eliseu e Samuel','As tribos de Judá, Benjamim e Efraim','Moisés, Josué e os sumos sacerdotes'),('AT04-L07-Q01','A arca da alianca, a nuvem de gloria e as trombetas de prata.','As doze pedras do altar e os sacrifícios perpetuos no Lugar Santo.','O mana cotidiano e a jarra do oleo da uncao.','Os setenta anciãos e a tenda da congregacao.'),('AT04-L07-Q02','Na saída do Sinai após a Lei','Na travessia do Mar Vermelho','No êxodo final de Israel','Na entrada na Terra Prometida'),('AT04-L07-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L06-Q06','Ensina que Deus é fiel em abençoar, proteger e dar paz ao seu povo.','Ensina que a bênção depende únicamente da obediência perfeita do sacerdote.','Ensina que os descendentes de Arão podiam determinar o destino das pessoas.','Ensina que a disciplina de Deus impede bênçãos e paz ao seu povo.'),('AT04-L07-Q05','Rebelaram-se e Deus os condenou a 40 anos de peregrinacao no deserto.','Receberam a promessa da terra e entraram imediatamente em Canaa.','Fortaleceram-se e conquistaram todas as cidades pagãs voisinhas.','Tiveram paz total e nenhuma praga os atingiu durante a jornada.'),('AT04-L08-Q02','No deserto, durante a caminhada pelo Sinai','Durante as pragas no Egito, antes da saida','Ao atravessar o Mar Vermelho em seguranca','Na entrada de Canaa apos a conquista de Jerico'),('AT04-L08-Q04','NAO SEI','O mandamento de observar o sábado como dia de descanso sagrado','A promessa divina de enviar um Messias Salvador','A intervenção do anjo do Senhor com espada flamejante'),('AT04-L07-Q06','A fidelidade de Deus ao guiar seu povo para a promessa','Que a obediência completa garantiza entrada imediata na terra','Que a disciplina humana substitui a ação do Espirito Santo','Que Deus abandona aqueles que hesitam em seguir'),('AT04-L08-Q03','A congregacao de Israel e os filhos de Corá','As doze tribos de Israel unanimousente','Os profetas de Baal no monte Carmelo','Os medos e os persas no cativeiro'),('AT04-L08-Q01','Murmúração no deserto, codornizes, dez espias, rebelião de Corá, água da rocha.','Visita dos três varões a Abraão, dilúvio, escada de Jacó.','Plagas do Egito, travessia do mar Vermelho, entrega dos dez mandamentos.','Construção do templo de Salomão, cativeiro babilônico, exílio na Assíria.'),('AT04-L09-Q03','As mulheres de Israel, lideradas por Miriã e Arão','As doze tribos de Israel com seus príncipes','Os anciãos e líderes de Judá e Simeão','Os levitas e os primogênitos de cada família'),('AT04-L08-Q05','Pestilência, morte e exclusão da Terra Prometida','Abundância, vitória militar e prosperidade contínua','Perdão automático e restauração espiritual completa','Migração para novas terras e expansão territorial'),('AT04-L08-Q06','As murmurações mostram incredulidade e testam a fidelidade de Deus','Que Deus abandona Seu povo quando este Lhe faz reclamações','Que a liderança humana é mais confiável que a divina','Que a disciplina divina sempre indica ira sem propósito redentor'),('AT04-L09-Q01','Rebelaram-se contra Moisés e Miriam foi atingida pela lepra','Acompanharam o povo na construção do tabernáculo de encontro','Dirigiram a festa dos pães asmos no primeiro mês do ano','Pregaram a Palavra no deserto e converteram milhares'),('AT04-L09-Q05','Miriã foi atingida com lepra e ficou isolada por sete dias.','Arão foi atingido com lepra e morreu fora da terra prometida.','Ambos foram consumidos por fogo que desceu do céu.','O povo foi castigado com pragas e fome no deserto.'),('AT04-L09-Q06','Que Deus usa líderes imperfeitos e permanece fiel mesmo na desobediência.','Que só os perfeitos são escolhidos por Deus para liderar Seu povo.','Que a desobediência nunca traz consequências para os líderes de Israel.','Que Deus abandona Seu povo quando há falhas entre os líderes.'),('AT04-L10-Q01','Para espiar a terra que Deus prometera a Israel e avaliar seus habitantes.','Para conquistar imediatamente a terra de Canaã com força militar.','Porque Deus precisasse de informações sobre a terra prometida.','Para selecionar os doze líderes das futuras tribos de Israel.'),('AT04-L09-Q04','A travessia do Mar Vermelho, quando Miryam liderou as mulheres em louvor (Êxodo 15)','O maná que desceu do céu para alimentar o povo no deserto','O bezerro de ouro que Arão fez para o povo adorar','A abertura da terra que tragou Corá e seus seguidores'),('AT04-L10-Q03','Josué e Calebe disseram que a terra era boa e que o Senhor a daria','Josué e Calebe disseram que a terra era impossível de conquistar','Josué e Calebe concordaram com os outros espias em tudo','Josué e Calebe disseram que a terra era péssima e habitada por gigantes'),('AT04-L10-Q07','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L10-Q04','O povo chorou, murmurou e quis apedrejar Josué e Calebe.','O povo aceitou a vontade de Deus e entrou na terra.','O povo pediu que os espias voltassem para confirmar o relatório.','O povo jejuou e orou em arrependimento pelos pecados.'),('AT04-L10-Q02','Corre leite e mel, terra muito boa e frutos abundantes.','Terra seca e estéril, sem água nem vegetação.','Possui grandes montanhas e muitos rios.','É terra plana e quente, boa para plantar trigo.'),('AT04-L10-Q06','Porque confiaram no poder de Deus para conquistar a terra prometida.','Porque eram os mais velhos entre os espias e mereciam honras especiais.','Porquearam os unicos que sabiam construir as trombetas de prata.','Porque Deus os abençoou com vida longa por adorarem o bezerro de ouro.'),('AT04-L11-Q01','Corá, Datã, Abirã e duzentos e cinquenta homens notáveis de Israel.','Miriã, Numbe e todos os primogênitos de Israel.','Os doze príncipes das tribos de Israel.','Os levitas do santuário e os anciãos de Judá.'),('AT04-L10-Q05','Eles morreriam no deserto sem entrar na Terra Prometida.','Seriam dispersos entre todas as nações da terra.','Sofreriam sete pragas e fome por quarenta anos.','Seriam entregados nas mãos dos seus inimigos para sempre.'),('AT04-L11-Q04','Fogo, abertura da terra e praga','Trovão, relâmpago e fogo','Tempestade, pragas e fome','Sorteio, lapidação e praga'),('AT04-L11-Q03','Fez brotar as varas de cada tribo, confirmando a primazia de Arão','Fez o mar se abrir em dois, confirmando a autoridade de Moisés','Envio anjos para confirmar a escolha dos doze apóstolos','Mandou fogo do céu sobre o altar, confirmando a liderança de Elias'),('AT04-L11-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L11-Q02','A autoridade como mensageiros enviados por Deus Jeová','A autoridade do sacerdócio levítico sobre os israelitas','A autoridade política e militar de governar Israel','A autoridade sobre as terras e tesouros do Egito'),('AT04-L12-Q02','No deserto, quando as varas das tribos foram postas diante da Arca','Na travessia do Mar Vermelho, como sinal de poder divino','Quando Israel acamhou ao pé do monte Sinai','Nas margens do Jordao, antes da entrada em Canaa'),('AT04-L12-Q03','A tribo de Levi, representada por Arão, foi a vara que floresceu.','As doze tribos de Israel colocaram suas varas e todas floresceram.','As tribos de Judá e Efraim foram escolhidas por Deus para o sacerdócio.','Os sumos sacerdotes do Egito e seus servos participam da vara de Arão.'),('AT04-L12-Q01','O brotar da vara de Arão para confirmar o sacerdócio levítico em Números 17','O bezerro de ouro fabricado por Arão enquanto Mosés estava no Sinai','A água da rocha que Mosés fez brotar no deserto de Cades','As tábuas da lei que Arão guardava na arca da aliança'),('AT04-L11-Q06','NAO SEI','Que a rebeldia fortalece a fé e aprova a ousadia','Que a ambição guia o culto e conquista a glória','Que a santidade se alcança pela revolta contra Deus'),('AT04-L12-Q04','A vara de Arão brotou e deu amêndoas, confirmando-o como sacerdote.','A vara de Arão foi usada para abrir o Mar Vermelho diante de Farao.','A vara de Arão se converteu em serpente para realizar a primeira praga.','A vara de Arão feriu a rocha e dela saiu agua para o povo no deserto.'),('AT04-L13-Q02','Fala à rocha para que dê a sua água','Ferir a rocha com a vara para que saísse água','Lavar a rocha com água antes de falar sobre ela','Bater na rocha com duas pedras até sair água'),('AT04-L13-Q01','Porque não tinham água para beber','Porque estavam cansados da longa viagem pelo deserto','Porque o maná tinha acabado de cair do céu','Porque queriam voltar para o Egito logo'),('AT04-L12-Q05','Prova de que Deus escolheu Arão para o sacerdócio, e fim da reclamação do povo contra ele','As pragas que assolaram o Egito por causa da desobediência de Faraó','A chuva de maná que alimentou os israelitas no deserto durante quarenta anos','O silêncio dos profetas de Baal quando Arão desafiou-os no monte Carmelo'),('AT04-L13-Q04','Por ter golpeado a rocha em vez de falar-lhe, desobedecendo a Deus em Zin.','Porque duvidaram do poder de Deus quando o povo necessitava de água no deserto.','Porque o povo rejeitou a liderança deles antes de entrarem na terra prometida.','Porque hicieron aliança com os cananeus contra a vontade do Senhor.'),('AT04-L12-Q06','A vara de Arão florescida prova que Deus confirma os Seus escolhidos','A vara de Arão era símbolo da lei e demonstrava a obediência completa aos mandamentos','A vara de Arão estava no Egito e representava as pragas que Deus enviou sobre os egipcios','A vara de Arão ensina que a fidelidade de Deus depende da fé do povo hebreu'),('AT04-L13-Q06','Cristo é a rocha que fornece água viva, como em 1 Coríntios 10:4','Paulo identifica a rocha como o Espírito Santo em Romanos 8','Lucas diz que a água da rocha virou vinho nas Bodas de Caná','Pedro é chamado de rocha na carta aos Efésios'),('AT04-L13-Q05','O caso de Nadabe e Abiú, mortos por oferecerem fogo estranho ao Senhor','O caso de Uzá, atingido por Deus ao tocar na arca transportada em carro','A revolta de Corá contra a autoridade de Moisés e Arão no deserto','A queixa de Miriã contra o casamento de Moisés com uma mulher cusita'),('AT04-L14-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L14-Q01','Castigo do SENHOR pela murmuração do povo contra Ele e Moisés','Prova de Deus para os israelitas demonstrarem sua fé','Enviadas pelos povos cananeus para atacar Israel','Castigo pelos pecados dos pais contra os filhos'),('AT04-L14-Q03','Olhar para a serpente de bronze erguida por Moisés','Aplicar unguento sagrado sobre a ferida da mordida','Rezar fielmente ao Senhor durante sete dias','Oferecer um sacrifício de sangue ao altar'),('AT04-L14-Q02','Fazer uma serpente de bronze sobre uma estandarte para que os mordidos olhassem para ela','Untar os feridos com óleo e lavar com água чиста seven times','Orar três vezes ao dia com as mãos estendidas para o céu','Mandar os feridos ao tabernaculo para serem examinados pelos sacerdotes'),('AT04-L13-Q03','Moisés feriu a rocha com a vara, sendo que Deus lhe ordenara que falasse à rocha.','Moisés feriu a rocha apenas uma vez com a vara, quando devia ter ferido duas vezes.','Moisés falou à rocha sem antes apresentar a vara diante dela como Deus ordenara.','Moisés destruiu a rocha com um machado, em vez de usar a vara que Deus lhe dera.'),('AT04-L14-Q05','Como Moisés levantou a serpente, assim o Filho do homem será levantado.','Jesus disse que seria crucificado como castigo pelo pecado original.','Ele comparou a serpente ao diabo que seria destruído na cruz.','Jesus afirmou que a serpente representava o Espírito Santo que desceria.'),('AT04-L15-Q01','Profeta de Deus e rei de Moabe, respectivamente','Dois reis de Israel que lutaram contra os midianitas','Anjos mensageiros enviados por Deus a Abraão','Sacerdotes egípcios que auxiliaram José no Egito'),('AT04-L15-Q02','Porque temia que Israel o derrotasse e queria que Deus o abandonasse.','Porque Balaão era inimigo de Deus e desejava destruí-lo pessoalmente.','Porque Deus ordenou a Balaão que amaldiçoasse o povo rebelde de Moab.','Porque queria testar os poderes proféticos de Balaão antes de contratá-lo.'),('AT04-L14-Q06','Porque era símbolo do poder de Deus, não um objeto de adoração.','Porque o metal bronze era considerado impuro pelos israelitas.','Porque Deus proibiu qualquer objeto em forma de serpente.','Porque a serpente já era ídolo dos povos vizinhos.'),('AT04-L15-Q03','Deus colocou um anjo com espada no caminho, e o jumento viu e desviou.','Deus fechou a boca de Balaão com fogo celestial, impedindo-o de falar.','Deus fez a língua de Balaão ficar paralisada por três dias inteiros.','Deus enviou raios e trovões para silenciar Balaão no monte.'),('AT04-L15-Q07','NAO SEI','O episodio ensina que Deus controla todas as circunstancias da vida','O episodio demonstra que oracao anula a soberania divina','O episodio sugere que bênçao e maldicao dependem exclusivamente do homem'),('AT04-L15-Q04','A jumenta desviou Balaão quando viu o anjo do Senhor bloqueando o caminho (Nm 22)','A jumenta foi o presente oferecido por Balaão ao rei moabita Balaque (Nm 22)','A jumenta permitiu que Balaão pudesse enxergar o anjo do Senhor (Nm 22)','A jumenta levou as oferendas de Balaão até o altar em Gileade (Nm 22)'),('AT04-L15-Q05','Bênçãos de poder, vitória, estrela e cetro para Israel','Maldições sobre o povo por terem deixado o Egito','Profecias de derrota e escravidão pelos povos vizinhos','Abençoou a Moab e disse que Israel seria destruído'),('AT04-L16-Q01','A apostasia de Baal-Peor, imoralidade e idolatria com moabitas','A queixa do povo contra Deus por causa das codornizes no deserto','A praga de lepra enviada sobre Miriam por murmurar contra Moisés','A queima de incenso proibida pelos filhos de Corá contra Deus'),('AT04-L15-Q06','Balaão é citado como exemplo de falsos mestres e avidez por ganho.','Balaão profetizou sobre Cristo e sua mensagem foi confirmada pelos apóstolos.','Balaão foi modelo de obediência e perseverança na caminhada cristã.','Balaão morreu como mártir e seu nome foi honrado por todas as igrejas.'),('AT04-L16-Q04','NAO SEI','A apostasia em peor e o abandono voluntario da fe','Pecado de apostasia e a renúncia ao Espirito Santo','Apostasia em peor refere-se a blasfemia contra Deus'),('AT04-L16-Q03','Os israelitas em Números 25 com Baal-Peor, Phinees agiu contra os pecados.','Os midianitas liderados por seu rei foram os principais participantes da apostasia.','As tribos de Judá e Efraim incitaram os demais à adoração de Baal-Peor.','Os amorreus foram os responsáveis por introduzir o culto a Baal-Peor.'),('AT04-L16-Q02','Na terra de Moabe, antes de atravessar o Jordão','No Sinai, quando Israel recebeu a Lei','Durante a travessia do Mar Vermelho','Ao acampar em Cades-Barnéa'),('AT04-L16-Q05','Não há mais sacrifício pelos pecados e aguarda juízo severo de Deus','Receber bênçãos materiais imediatas e prosperidade garantida nesta vida','Ser perdoado automaticamente mediante simples confissão oral posterior','Perder apenas privilégios sociais mas manter a salvação assured'),('AT04-L16-Q06','O episódio de Baal-Peor revela a fidelidade de Deus ao disciplinar a infidelidade do Seu povo.','Baal-Peor demonstra que Deus abençoa a idolatria quando o povo permanece dedicado aos seus ídolos.','Em Péor, Deus prova que a infidelidade do Seu povo não anula a aliança divina estabelecida.','O caso de Péor ensina que a disciplina de Deus é simbolica e Seus olhos se fecham para o pecado.'),('AT04-L17-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L17-Q03','As doze tribos de Israel em Numeros 26','Os levitas e os sumos sacerdotes em Numeros 3','Os reis de Israel e Judea em 2 Samuel 24','Os doze apostolos no livro de Atos dos Apostolos'),('AT04-L17-Q05','Setenta mil homens morreram pela praga enviada por Deus','Fogo do céu consumiu os offerentes do sacrificio','O povo foi escravo dos povos vizinhos por quarenta anos','Fome de três anos atingiu toda a terra de Israel'),('AT04-L18-Q01','Maala, Noa, Hogla, Milca e Tirza','Bara, Zila, Ada e Naama','Tamar, Rute, Ester e Maria','Abigail, Débora, Raabe e Ana'),('AT04-L17-Q01','Preparação militar para conquista de Canaã e divisão das heranças.','Organização das tribos para a travessia do mar Vermelho.','Instituição dos turnos de serviço levítico no santuário.','Celebração da páscoa e ofertas determinadas pelo Senhor.'),('AT04-L17-Q06','O censo ensina que Deus disciplina a desobediência, mas age com misericórdia e fidelidade ao Seu povo.','O censo prova que Deus protege os guerreiros fortes e abandona os fracos em batalha.','O censo mostra que a contagem humana é inútil, pois Deus já conhece todos os Seus filhos.','O censo ensina que a liderança bíblica exige sacrifícios humanos para garantir vitória.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT04-L18-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L18-Q03','Que o irmão case com a viúva e levante descendência para o irmão falecido.','Que a propriedade fosse dividida entre os parentes do homem falecido.','Que a viúva voltasse para a casa de seu pai sem herdar nada.','Que os bens fossem doados ao templo pelo homem falecido.'),('AT04-L18-Q04','NAO SEI','A decisão dividiu opiniões sobre mudanças nas leis de herança','A decisão fortaleceu o sistema patriarcal de herança','A decisão estabeleceu novos prazos para partilha de bens'),('AT04-L19-Q01','Josué foi escolhido por Deus para suceder Moisés, conforme Números 27:15-23.','Josué foi nomeado líder pelos ancianos de Israel antes da entrada em Canaã.','Josué liderou a travessia do Mar Vermelho conforme registrado em Números.','Josué foi considerado sucessor de Arão como sumo sacerdote em Números.'),('AT04-L09-Q02','Em Cades Barnéia','No Monte Sinai','Nas planícies de Moabe','Nas margens do Jordão'),('AT04-L17-Q02','Nas planícies de Moabe','No deserto do Sinai','Nas proximidades de Jericó','No monte Sinai'),('AT04-L18-Q02','Zelophehad nao tinha filhos homens, apenas filhas, e queriam herdar terra','Seus maridos estavam em guerra e queriam protecao para os filhos','O pai era leproso e elas queriam sua curacao por Moises','Questionavam se as mulheres podiam ser sacerdotes em Israel'),('AT04-L19-Q02','Na entrada em Canaã, após a morte de Moisés.','Na travessia do mar Vermelho, como guerreiro de Deus.','No cativeiro da Babilônia, como líder restaurador.','Na saída do Egito, como conselheiro de Arão.'),('AT04-L19-Q03','Josué filho de Num foi o sucessor de Moisés','Arão foi o sucessor de Moisés no sacerdócio','Os levitas foram os sucessores de Moisés','Moisés não teve sucessor registrado na Bíblia'),('AT04-L19-Q04','A queda dos muros de Jericó','A multiplicação do maná no deserto','A divisão das águas do mar Vermelho','A voz de Deus no monte Sinai'),('AT04-L19-Q05','Josué conquistou Jericó e распределиу as terras entre as doze tribos de Israel.','Josué estabeleceu a monarquia unificada e fundou a dinastia real de Israel.','Josué registrou todos os milagres no livro de Números durante seu governo.','Josué construiu o Primeiro Templo em Jerusalém após entrar em Canaã.'),('AT04-L20-Q01','O recenseamento das tribos e a organização do acampamento.','A construção do bezerro de ouro e a confecção das tábuas da lei.','A divisão do mar Vermelho e a travessia do deserto de Sinai.','A instituição da páscoa e a consagração dos primogênitos.'),('AT04-L20-Q02','Em Moabe, antes de atravessar o Jordao','No Sinai, apos a alianca com Deus','Durante o exodo, enquanto fugiam do Egito','Nas planicies de Jerico, apos a travessia'),('AT04-L19-Q06','Deus é fiel em cumprir Suas promessas aos Seus servos','A ajuda de Deus depende da perfeição humana','A obediência a Deus não é necessária para a vitória','Deus abandonou o Seu povo na terra prometida'),('AT04-L20-Q03','As doze tribos de Israel, lideradas por Josue','Os midianitas e moabitas que vieram auxiliar Israel','As sete nações de Cananeus que resistiram','Os levitas e cohanim que organizavam o tabernaculo'),('AT04-L20-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT04-L20-Q05','Em resultado, Israel vagou quarenta anos no deserto e a geração incrédula morreu.','Os cananeus se renderam voluntariamente e Israel entrou sem guerra na terra.','Todos os israelitas morreram no deserto e a terra ficou despovoada.','A terra de Canaã foi consumida por fogo do céu antes da entrada.'),('AT04-L20-Q04','A promessa a Abraão','A construção da arca de Noé','A queda de Sodoma e Gomorra','A destruição da torre de Babel'),('AT04-L21-Q02','NAO SEI','No Sinai, quando Deus revela a Lei','Na travessia do Mar Vermelho','Na entrada na Terra Prometida'),('AT04-L21-Q03','Os tres jovens hebreus, Daniel, Josias e os levitas','Os filisteus, os amorreus e os moabitas','Os cananeus, os edomitas e os amonitas','Os samaritanos, os fariseus e os publicanos'),('AT04-L21-Q05','Disciplina de Deus produz frutos de justiça e paz','Disciplina de Deus remove todos os problemas da vida','Disciplina de Deus garante prosperidade material imediata','Disciplina de Deus resulta em afastamento permanente dele'),('AT05-L01-Q01','Segunda lei; livro dos discursos de despedida de Moisés ao povo de Israel','Terceira lei; livro que contém as leis adicionais ditadas por Josué','Primeira lei; livro onde Deus revela os Dez Mandamentos a Moisés','Lei antiga; livro dos relatos da criação do mundo segundo Moisés'),('AT04-L21-Q06','Deus é fiel e disciplina para nos conduzir à santidade e firmeza na fé','Deus exige obediência cega sem demonstrar amor ou compaixão','A disciplina divina cancela a necessidade de fé e obediência','Fidelidade divina significa que Deus sempre age conforme esperamos'),('AT04-L21-Q04','Obediencia aos mandamentos de Deus','Amor propio e autopreservacao','Rebeliao contra a lei divina','Idolatria e veneracao de images'),('AT05-L01-Q02','Segunda Lei, recapitulação dos mandamentos, promessas da terra e bênçãos pela obediência','Profetas menores e historias de reis que guardaram a aliança divina com o povo','Salmos e hinos sagrados compostos durante a travessia do Mar Vermelho','Genealogias das doze tribos e a linha successória do rei Salomão'),('AT05-L01-Q03','Segunda lei que reafirmou a aliança de Deus com Israel no Sinai.','Deuteronômio significa aliança no Sinai separada da primeira aliança patriarcal.','O termo indica que Deus rejeitou a primeira aliança e estabeleceu nova aliança.','Deuteronômio refere-se à aliança eterna feita no deserto após a travessia do Jordão.'),('AT05-L01-Q04','Amar a Deus de todo o coração e alma','Amar as riquezas e os bens terrenos','Seguir as tradições dos falsos profetas','Abandonar os mandamentos do Senhor'),('AT05-L02-Q01','Discursos de Moisés são suas pregações ao povo de Israel no Pentateuco.','Discursos de Moisés referem-se às cartas escritas por Paulo.','Discursos de Moisés são os sermões do profeta Elias.','Discursos de Moisés referem-se aos milagres realizados por ele.'),('AT05-L01-Q06','Significa segunda lei, referindo-se à repetição da lei mosaica para a nova geração.','Significa livro das alianças, referindo-se aos pactos entre Deus e Israel nas terras de Canaã.','Significa lei dos sacrifícios, detalhando os rituais do tabernáculo e as ofertas sagradas.','Significa livro dos reis, preparando espiritualmente Israel para sua monarquia futura.'),('AT05-L01-Q05','Bênçãos de prosperidade e segurança, maldições de pragas e dispersão.','Apenas bênçãos espirituais sem consequências materiais ou temporais.','Bênçãos eternas no céu, sem relação com eventos terrenos.','Consequências apenas após a morte, sem bênçãos terrenas.'),('AT05-L02-Q02','Os Dez Mandamentos, o Shema e a promessa da terra de Canaã','Os doze preceitos do Sermão da Montanha','O mandamento de adorar o bezerro de ouro','A promessa de setenta e duas nações no deserto'),('AT05-L02-Q04','Amor a Deus de todo o coração, alma e forças','Obedecer a todos os Dez Mandamentos','Ter fé apenas nos profetas','Oferecer sacrifícios diários no templo'),('AT05-L02-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT05-L02-Q03','Moisés exortava Israel a cumprir os termos da aliança do Sinai','Moisés pregava que Israel deveria adorar os ídolos cananeus','Os discursos de Moisés anulavam a aliança feita por Deus','Moisés ensinava Israel sobre uma aliança com o Egito'),('AT05-L03-Q01','Recapitulação da jornada de Israel no deserto, em Deuteronômio.','Nome dado à última oração de Josué ao povo de Israel.','Expressão usada por Gideão para descrever sua vida antes do chamado.','Relato do êxodo dos hebreus da escravidão do Egito.'),('AT05-L02-Q05','Bênçãos por obediência e maldições por desobediência à lei de Deus (Dt 28)','Perdão automático e completo de todos os pecados ao ouvir suas palavras','Proteção divina permanente contra todos os inimigos externos de Israel','Garantia de prosperidade material imediata e saúde perfeita a todos'),('AT05-L03-Q03','Revisão da caminhada é o memorial das obras de Deus na aliança com Israel','Revisão da caminhada é um ritual de adoração aos ídolos cananeus','Revisão da caminhada era apenas um registro genealógico de Israel','Revisão da caminhada foi uma tradição criada após o exílio na Babilônia'),('AT05-L03-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT05-L04-Q01','Ratificação da aliança para a nova geração antes de Canaã','Promulgação de novas leis diferentes das anteriores','Anulação dos mandamentos dados no Sinai','Mudança completa dos Dez Mandamentos originais'),('AT05-L03-Q04','Temer ao Senhor e andar nos seus caminhos','Praticar a justiça e atender aos necessitados','Observar todos os sacrifícios e ofertas','Guardar os mandamentos e celebrar festas'),('AT05-L03-Q02','O Dia da Expiação: Levítico 23:26-32, jejum e autoexame.','A Ceia do Senhor: 1 Corntios 11:23-26, memórial de Cristo.','O batismo: Romanos 6:3-5, revisão da nova vida em Cristo.','A páscoa: Êxodo 12:14, memórial da libertação do Egito.'),('AT05-L04-Q04','Amar a Deus de todo o coração, de toda a alma e de toda a tua força','Obedecer aos Dez Mandamentos sem exceção alguma','Fazer penitências e sacrifícios todos os dias','Crer em Jesus Cristo como único Salvador'),('AT05-L04-Q02','Lembrar a escravidão no Egito, guardar os mandamentos e ensiná-los aos filhos','Lembrar o dilúvio e oferecer sacrifícios de animais como recordação','Celebrar a páscoa e jejuar durante a semana da festa dos pães ázimos','Lembrar a travessia do Mar Vermelho e construir um altar no lugar onde Deus secou as águas'),('AT05-L04-Q03','A repetição da lei em Deuteronômio renova a aliança de Deus com Israel.','A repetição da lei substitui a aliança do Sinai por uma nova aliança.','A repetição da lei cumpre a profecia de uma nova aliança com os gentios.','A repetição da lei confirma que a aliança foi totalmente cancelada por Deus.'),('AT05-L04-Q05','Bênçãos de prosperidade e cur','Perdão automático de todos os pe','Promessa de vida eterna e salv','Visão profética e dons miraculo'),('AT05-L03-Q06','Pelo ensino de Jesus sobre contar o custo e se autocolocar em prova.','Pela ênfase de Jesus em celebrar only o sucesso espiritual sem revisar falhas.','Pela promessa de Jesus de que ninguém precisa jamais se arrepender.','Pelo ensino de que a caminhada espiritual não requer reflexão alguma.'),('AT05-L04-Q06','Jesus declarou que veio para cumprir a lei, nao para revoga-la.','Jesus aboliu completamente a lei antiga em seu primeiro sermao.','Paulo ensinou que a lei deve ser esquecida pelos fieis.','Os apostles decidiram ignorar toda a lei do Antigo Testamento.'),('AT05-L05-Q03','Os dez mandamentos sao os termos da alianca de Deus com Israel no Sinai.','Os dez mandamentos foram dados antes do concerto da alianca no Sinai.','Os dez mandamentos foram dirigidos exclusivamente aos sacerdotes e levitas.','Os dez mandamentos foram integralmente substituidos pela nova alianca em Cristo.'),('AT05-L05-Q06','Jesus resumiu a Lei nos dois maiores mandamentos: amar a Deus e ao próximo','Jesus aboliu os dez mandamentos e criou sete novas leis para seus seguidores','Paulo ensinou que os dez mandamentos não se aplicam mais aos cristãos','Os dez mandamentos foram completamente ignorados por todos os escritores do Novo Testamento'),('AT05-L05-Q01','Os dez mandamentos sao a lei fundamental entregue por Deus a Moises no Sinai.','As leis cerimoniais que regulavam os sacrifícios no tabernaculo de Moises.','As regras morais ensinadas pelos profetas ao povo de Israel apos a conquista de Canaa.','Os preceitos sagrados transmitidos pelos sacerdotes aaronitas apos a construcao do templo.'),('AT05-L05-Q05','Obediência traz bênçãos; desobediência traz maldições.','Apenas bênçãos espirituais sem consequências terrenas.','Cada mandamento tinha uma bênção específica e diferente.','As consequências eram apenas materiais e financeiras.'),('AT05-L06-Q02','Ouvir','Paz','Amor','Fé'),('AT05-L05-Q04','Temê-lo, andar nos seus caminhos, amá-lo, servi-lo de todo o coração e guardar os seus mandamentos','Reconhecê-lo como único Deus e oferecer-lhe sacrifícios diários de animais','Frequentar o templo, pagar o dízimo e jejuar duas vezes por semana','Profetizar em seu nome, realizar milagres e pregar o evangelho'),('AT05-L06-Q01','Ouve, Israel: O Senhor nosso Deus é o único Senhor. Deuteronômio 6:4','Eu sou o Senhor teu Deus, que te tirei da terra do Egito. Êxodo 20:2','Amarás o Senhor teu Deus de todo o teu coração. Deuteronômio 6:5','No princípio criou Deus os céus e a terra. Gênesis 1:1'),('AT05-L05-Q02','O Shema de Dt 6.4-5 relacionado ao amor a Deus e o sábado como sinal da aliança','As ofertas e sacrifícios substituem completamente a necessidade de obediência','A prosperidade material é promessa automática para todos os observers do sábado','As bênçãos de Deuteronômio 28 se aplicam apenas ao primeiro mandamento'),('AT05-L06-Q03','Que o Senhor é o único Deus, o Deus único e verdadeiro','Que Deus é formado por três pessoas distintas e separadas','Que os deuses dos povos podem ser adorados juntos com o Senhor','Que a unidade divina exige que se abandone toda oração'),('AT05-L07-Q01','Amar a Deus com todo o coração, alma e forças, obedecendo aos seus mandamentos.','Amar a Deus consiste em oferecer sacrifícios regulares no altar e guardar as festas anuais.','Amar a Deus significa acumular riquezas materiais e prosperidade para si e sua família.','Amar a Deus se resume a conhecer profundamente e debater os textos das leis antigas.'),('AT05-L06-Q05','Falando delas todos os dias, em toda circunstancia, segundo Deuteronomio 6:7','Apenas por escrito, em pergaminhos afixados nas paredes, conforme Deuteronomio 6:9','Somente no templo, pelos sacerdotes, durante as tres oracoes diarias','Por meio de simbolos visuais e imagens pintadas nos marcos de portas'),('AT05-L06-Q06','Jesus citou o Shemá e agregou Amarás o próximo como a ti mesmo','Jesus rejeitou o Shemá e declarou um mandamento totalmente novo sobre a pobreza','Jesus substituiu o Shemá pelo mandamento de honrar o imperador romano','Jesus ordenou que os discípulos abandonassem o Shemá e seguissem apenas seus ensinamentos'),('AT05-L07-Q04','Amar a Deus de todo o coração, alma e forças','Temer apenas os mortos e consultar adivinhos','Oferecer sacrifícios diarios no altar','Jejuar e fazer votos solenes ao不出去'),('AT05-L07-Q02','Amar a Deus de todo o coração e guardar Seus mandamentos','Amar o proximo como a si mesmo e fazer penitencia diaria','Observar os sacrifícios e ofertas segundo a lei de Moises','Jejuar tres vezes por semana e dar esmolas aos pobres'),('AT05-L08-Q01','Ensinar os mandamentos divinos aos filhos','Transmitir conhecimentos agrícolas e ofícios','Preparar os filhos para servir no templo','Ensinar as leis e costumes egípcios'),('AT05-L07-Q05','Amor a Deus traz vida eterna e bênçãos de Deus Pai.','Amor a Deus garante prosperidade material sem necessidade de fé.','Amor a Deus remove automaticamente todo sofrimento da vida.','Amor a Deus anula a necessidade de guardar os mandamentos.'),('AT05-L07-Q03','Amor a Deus fundamenta a aliança, e a resposta fiel de Israel aos mandamentos a confirma.','Amor a Deus na aliança se manifesta exclusivamente por meio de sacrificios automaticos sem necessidade de obediencia.','A aliança com Israel foi baseada inteiramente em meras obras humanas sem nenhuma iniciativa do amor divino.','O amor a Deus na aliança biblica e facultativo e independe completamente da obediencia aos mandamentos.'),('AT05-L07-Q06','Jesus disse que o maior mandamento é amar a Deus de todo o coração','Paulo ensinou que amar a Deus era menos importante que os dons espirituais','O amor a Deus foi substituido pelo amor ao próximo apenas','Os apóstolos abandonaram o conceito de amar a Deus após Pentecostes'),('AT05-L08-Q03','Deus ordenou ensinar os filhos sobre a aliança para preserva-la','A educacao dos filhos e um requisito previo ao estabelecimento da aliança','Os filhos de Israel decidiam individualmente se queriam participar da alianca','A alianca foi feita diretamente com cada filho de Israel separadamente'),('AT05-L08-Q02','Deuteronômio 6:6-7: ensinar os mandamentos aos filhos','Êxodo 20:12: honrar pai e mãe para ter longa vida','Provérbios 13:24: quem disciplina seu filho o ama','Colossenses 3:20: filhos obedeçam aos pais em tudo'),('AT05-L08-Q04','NAO SEI','Amar o proximo como a si mesmo e guardar todos os seus mandamentos','Crer nos seus profetas e oferecer sacrificios todos os dias','Guardar os seus mandamentos e andar nos seus caminhos'),('AT05-L08-Q05','Bênção de sabedoria e vida; consequência de correção e disciplina','Bênção de riqueza e prosperidade; consequência de trabalho e sofrimento','Bênção de obediência e paz; consequência de maldição e ruína','Bênção de conhecimento; consequência de disciplina severa sem amor'),('AT05-L09-Q03','Deuteronômio 12 ordena adorar no lugarchosen, cumprindo a aliança.','Êxodo 20 proíbe outros deuses, não trata da centralização do culto.','O tabernáculo no deserto já resolvia a questão da centralização.','Samuel estableció a centralização em Siló como padrão permanente.'),('AT05-L09-Q04','Amar a Deus de todo o coração, alma e forças','Praticar rituais e sacrifícios diariamente','Cumprir apenas os dez mandamentos','Observar dias de jejum e orações constantes'),('AT05-L09-Q02','O lugarchosenpeloSenhorparanome,ealémdaaliançacomIsraelpromessasdesubstênciaepresença','Osdezmandamentos,oshonoramaoeopaiemaeecomsubstânciaparaabendiredescansosábado','AliançaHorebe,ofertasdepreciosos祭oescolhafamíliaAaronsacerdotes','Profetasdiscípulos,instruçãosabática,pazeguerraeldouradojerusalémterreno'),('AT05-L09-Q01','Adorar no lugar chosen por Deus, rejeitando altares fora dele','Realizar sacrifícios em qualquer local conforme a vontade individual','Permitir a adoração em múltiplos altares simultâneos sem distinção','Cultuar livremente em qualquer santuário local estabelecido pelo povo'),('AT05-L08-Q06','Deuteronômio 6 ordena pais ensinarem filhos na lei, e Efésios 6 ordena criá-los na disciplina do Senhor.','Jesus nunca falou diretamente sobre a educação das crianças.','A educação dos filhos era privativa dos sacerdotes no templo.','A Bíblia não menciona em nenhum lugar a educação dos filhos.'),('AT05-L09-Q05','Bênçãos: protecao divina e prosperidade. Consequências: unidade e fim da idolatria.','Maldiçoes: fome, seca e guerra pelo rompimento da aliança.','Promessa eterna de terra para os descendentes de Abraão.','Dissolução completa das doze tribos de Israel.'),('AT05-L09-Q06','Jesus ensinou que se adorará em espírito e verdade, não mais em lugar determinado.','Jesus criticou todos os rituais do templo de Jerusalém e os aboliu completamente.','O culto centralizado deixou de existir após a morte e ressurreição de Jesus.','Jesus ordenou que cada pessoa adorasse exclusivamente em sua própria casa.'),('AT05-L10-Q01','Leis que regulavam as relações interpessoais da comunidade israelita, protegendo vulneráveis.','Leis políticas que determinavam a estrutura de governo e liderança de Israel.','Leis que estabeleciam rituais de adoração e festividades sagradas do povo.','Leis militares que governavam estratégias de conquista e defesa territorial.'),('AT05-L10-Q02','O Sábado libera escravos, o Ano Sabático perdoa dívidas, o Jubileu devolve propriedades','O Shema guarda a tradição, os Salmos celebram a criação, as Crônicas registram genealogias','A Páscoa lembra a libertação do Egito, o Pentecostes celebra a colheita, a Expiação purifica o templo','O Dezmo sustenta o sacerdócio, as Primícias honram a terra, as Votas cumprimentam guerreiros'),('AT05-L10-Q04','Amar a Deus de todo o coração, de toda a alma e de toda a força','Oferecer sacrifícios diários de animais no tabernáculo','Guardar rigorosamente apenas os sábados e festas anuais','Abster-se de todo trabalho e jejuar permanentemente'),('AT05-L10-Q03','Expressavam obediência aos mandamentos da aliança com o Senhor.','Eram normas separadas da aliança, apenas para organização social.','Foram criadas pelo povo de Israel sem interferência divina.','Eram aplicadas exclusivamente aos sacerdotes e levitas.'),('AT05-L11-Q04','Temer a Deus,e guardar os seus mandamentos','Procurar apenas a prosperidade material e a riqueza','Oferecer sacrifícios diariamente no templo','Cumprir rigorosamente todas as leis de Israel'),('AT05-L10-Q05','Bênçãos pela obediência e maldições pela desobediência, conforme Deuteronômio 28.','Riqueza para os obedientes e prosperidade garantida para todos os seguidores.','Perdão automático ao pecador sem necessidade de arrependimento algum.','Proteção divina exclusiva contra inimigos e enfermidades para obedientes.'),('AT05-L11-Q01','Leis divinas que regiam a conduta militar de Israel nas conquistas da Terra Prometida','Mandamentos sobre a coleta de dízimos e ofertas para sustentação dos levitas','Instruções para a construção e funcionamento do tabernáculo no deserto','Regras sobre divisão de terras e heranças entre as tribos de Israel'),('AT05-L10-Q06','No amor ao próximo e cuidado com os necessitados','Na guarda integral de toda a Lei cerimonial','No perdão dos pecados sem necessidade de obras','Na separação entre puros e impuros pela Lei'),('AT05-L11-Q02','A destruicao herem de povos e cidades dedicados ao Senhor nas guerras de Israel','A observancia do sabado para que os soldados descansassem antes das batalhas','A oferta do primeiro anniversario de toda guerra ao templo de Jerusalém','O mandamento de nunca cobicar os bens dos povos inimigos vencidos'),('AT05-L12-Q01','Deuteronomio 18:15-18','Deuteronomio 34:10','Deuteronomio 5:1','Deuteronomio 31:1-6'),('AT05-L11-Q05','Bênçãos: vitória e proteção divina. Consequências: derrota e destruição.','Bênçãos: prosperidade financeira garantida. Consequências: exílio voluntário.','Bênçãos: immortality espiritual. Consequências: maldição permanente sobre a terra.','Bênçãos: expansão territorial ilimitada. Consequências: conversão forçada dos inimigos.'),('AT05-L11-Q06','Jesus pregou amor aos inimigos e não retaliação','Jesus confirmou todas as leis de guerra do AT','Jesus estabeleceu novas leis de guerra para seus seguidores','Jesus ordenou que seus discípulos participassem de guerras santas'),('AT05-L11-Q03','As leis de guerra faziam parte da aliança mosaica entre Deus e Israel.','As leis de guerra foram criadas pelos reis militares de Israel para proteger o reino.','As leis de guerra de Israel foram importadas dos povos cananeus vizinhos.','As leis de guerra foram reveladas diretamente a Abraão na aliança patriarcal.'),('AT05-L12-Q02','Para conhecer a vontade de Deus e ser guiado por Seus caminhos.','Porque os profetas eram os governantes políticos de Israel e decidiam guerras santas.','Para realizar milagres visíveis e demonstrar o poder de Deus às nações.','Porque sem um profeta o templo não podia realizar os sacrifícios corretamente.'),('AT05-L12-Q03','Ser chamado e santificado antes de nascer e constituído profeta para as nações','Realizar milagres e dividir as águas do mar Vermelho como Josué','Receber a lei no monte Sinai e escrever os dez mandamentos','Conduzir o povo pelo deserto e construir o tabernáculo'),('AT05-L12-Q06','É Filho sobre a casa, não apenas servo como Moisés','Realizou mais milagres do que Moisés durante seu ministério','Viveu mais anos na terra do que Moisés viveu','Teve mais discípulos seguidores do que Moisés teve'),('AT05-L13-Q01','Consequências da obediência ou desobediência à aliança do SENHOR com Israel.','Rituais mágicos para atrair prosperidade ou afastar demônios e espíritos.','Promessas exclusivamente materiais de riqueza e possessões terrenas.','Decisões humanas baseadas apenas no merecimento pessoal e boas obras.'),('AT05-L12-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT05-L13-Q02','O Sábado, sinal sagrado ligado à bênção e à maldição divina.','A circuncisão, sinal da aliança com bênção e maldição.','A páscoa, memória da libertação com promessas de bênção.','O dízimo, oferta ligada à promessa de bênçãos.'),('AT05-L13-Q05','Bênçãos: prosperidade, saúde, terra e descendência. Maldições: enfermidade, pobreza e destruição.','Bênçãos garantiam salvação eterna imediata, e maldições causavam possessão demoníaca instantânea.','Bênçãos e maldições eram determinísticas e automáticas, sem relação com obediência do povo.','Maldições afetavam apenas o corpo, nunca a alma ou os descendentes do culpado.'),('AT05-L12-Q04','Deus ordenou que Israel aceitasse profetas que prophetejavam em seu nome e rejeitasse os que prophetejavam em nome de outros deuses','Deus ordenou que Israel eliminasse todo propheta que tivesse sonhos ou visões de qualquer especie','Deus ordenou que Israel aceitasse qualquer propheta que prophetejasse em nome do Senhor, sem verificar se suas palavras se cumpriam','Deus ordenou que Israel seguisse o propheta mais antigo e respeitado da congregacao para julgar os demais'),('AT05-L13-Q04',' temer ao Senhor, andar nos seus caminhos, amá-lo e servir-lhe de todo o coração e toda a alma ',' apresentar sacrifícios e ofertas no templo conforme a lei de Moisés ',' observar rigorosamente o sábado e guardar todas as festividades anuais ',' seguir fielmente apenas os dez mandamentos entregados a Moisés '),('AT05-L13-Q06','As bem-aventuranças de Jesus reinterpretam bênçãos e maldições na Nova Aliança','Jesus substituiu todas as maldições por bênçãos exclusivamente materiais e físicas','As bênçãos e maldições do AT foram completamente anuladas pelo Novo Testamento','Jesus nunca falou sobre maldições ou juízo em nenhum de seus ensinamentos'),('AT05-L14-Q01','Reafirmação dos termos do pacto entre Deus e Israel, com chamado à obediência.','Criação de uma nova aliança com regras diferentes das anteriores estabelecidas.','Celebração anual do êxodo com danças e cantos rituais em memória de Deus.','Renúncia aos compromissos anteriores e início de uma nova relação com Deus.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT05-L14-Q05','Bênçãos: prosperidade, chuvas, vitórias. Maldições: pragas, derrota, dispersão.','Vida eterna garantida a todos os participantes da aliança sem condições.','Destruição imediata de todos os inimigos externos sem esforço militar.','Perdão automático de pecados passados, presentes e futuros sem arrependimento.'),('AT04-L18-Q05','A lei do levirato para preservar o nome do falecido','Deixar as bordas e cantos do campo para os pobres','A Lei do Jubileu que restituia as propriedades','A proibicao de remover as marcas divisórias'),('AT04-L21-Q01','O censos, a serpente de bronze e a disciplina de Deus','O bezerro de ouro e a fidelidade de Deus ao seu pacto','A separacao dos levitas e a disciplina do povo','O mar Vermelho e a fidelidade de Deus ao seu povo'),('AT05-L06-Q04','Amar a Deus de todo o coração, de toda a alma e de toda a força','Observar os sábados e oferecer sacrifícios no templo de Jerusalém','Cumprir rigorosamente todos os mandamentos sem exceptions','Servir aos deuses das nações vizinhas para manter a paz'),('AT05-L13-Q03','Bênçãos e maldições eram condicionadas ao cumprimento da aliança mosaica.','Eram recompensas imediatas aplicadas após a morte de cada israelita.','Applicavam-se exclusivamente aos sacerdotes e levitas da tribo de Levi.','Baseavam-se na posição social e econômica do individuo.'),('AT05-L14-Q02','Lembrar os mandamentos, ensinar aos filhos e escrever nas portas','Lembrar o nome de Deus, jejuar por tres dias e ofrecer primicias','Lembrar os pecados passados, fazer penitencia e lavar as maos','Lembrar o sabado, acender velas e recitar a bencao sacerdotal'),('AT05-L14-Q04','Arrependimento','Desobediência','Idolatria','Rebelião'),('AT05-L14-Q03','Reafirma o compromisso de Israel com a lei mosaica e a fidelidade de Deus.','Substitui a aliança mosaica pela aliança abraamica','Simplesmente ratifica um acordo j existente sem significado espiritual','Finaliza e encerra permanentemente a aliança com Israel'),('AT05-L15-Q02','Amar a Deus e guardar Seus mandamentos, que conduzem a vida eterna','Obedecer a Deus e guardar Seus preceitos, que conduzem a vida eterna','Amar a Deus e viver segundo a carne, que conduz a vida eterna','Conhecer a Deus e crer em Seus profetas, que conduzem a vida eterna'),('AT05-L14-Q06','A Nova Aliança é selada pelo sangue de Cristo na Santa Ceia (Lucas 22:20)','A renovação da aliança é alcançada exclusivamente pelos atos rituais do templo','A aliança foi renovada apenas como formalidade institucional na Igreja','A Nova Aliança não estabelece relação direta com a aliança abraâmica'),('AT05-L15-Q03','Por desobedecer aos mandamentos, o povo seria amaldiçoado e levado ao cativeiro.','A desobediência traria prosperidade imediata e domínio sobre as outras nações.','Obedecer aos ídolos seria o único caminho para evitar a destruição do povo.','A transgressão causaria bênçãos materiais sem afetar o relacionamento com Deus.'),('AT05-L15-Q04','Para que o povo possa conhecer, guardar e viver a vontade divina.','Para que os líderes religiosos controlassem as decisões do povo.','Porque Deus dependia do povo para Se fazer conhecido.','Para demonstrar que toda lei surgiu da própria vontade do povo.'),('AT05-L16-Q01','Cântico de louvor pela deliverance do Egito e profecia sobre a aliança.','Cântico fúnebre composto por ocasião da morte de alguém da família de Moisés.','Código de leis divinas que regulava a vida social e religiosa do povo.','Cântico de casamento sagrado que celebrava a união entre Deus e Israel.'),('AT05-L16-Q02','A lembranca da libertacao do Egito e a promessa de heranca na terra prometida','O descanso sabatico e a prohibicao de trabalhar aos sabados','A observancia dos dez mandamentos e a celebracao da páscoa','O dizimo das primicias e a oferta dos sacrifícios no templo'),('AT05-L16-Q03','Recorda a aliança e adverte sobre a infidelidade de Israel','Celebra exclusivamente a victoria militar de Israel em Canaã','Profetiza a ruptura total e definitiva da aliança mosaica','Anula o pacto e estabelece uma nova aliança com os gentios'),('AT05-L15-Q05','A escolha é a resposta voluntária do povo ao convite divino de renovação','A escolha elimina completamente a necessidade de fé pessoal em Deus','A escolha anula a soberania de Deus na determinação dos termos da aliança','A escolha substitui a graça divina por um sistema de méritos humanos'),('AT05-L15-Q06','Paulo usa a linguagem de Dt 30 para ensinar que a justiça pela fé está próxima.','Paulo rejeita completamente a lei mosaica em Romanos 10.','Paulo afirma que a fé anula todos os mandamentos.','Paulo modifica Dt 30 para agradar aos gentios.'),('AT05-L16-Q04','Que temessem ao SENHOR, o amassem e o servissem de todo o coração e alma','Que guardasse todos os mandamentos e statutes do SENHOR fielmente','Que amasse ao próximo como a si mesmo e observasse os costumes','Que oferecesse sacrifícios e holocaustos segundo a lei de Moisés'),('AT05-L16-Q05','Bênçãos pela obediência e maldições pela desobediência à aliança','Riqueza material garantida a todos que cantarem o cântico','Perdão automático de todos os pecados sem necessidade de arrependimento','Proteção sobrenatural contra qualquer inimigo durante sete gerações'),('AT05-L16-Q06','Apocalipse menciona o cântico de Moisés cantado junto ao do Cordeiro em heaven.','Jesus nunca mencionou o cântico de Moisés em seus ensinamentos registrados.','Paulo citas diretas do cântico de Moisés em todas as suas epístolas.','O cântico de Moisés foi incluído no Saltério para uso na liturgia judaica.'),('AT05-L17-Q01','Votos proféticos de bênção de Moisés às doze tribos de Israel, em Deuteronômio 33.','Sacrifícios tribeiros oferecidos no tabernáculo segundo as instruções de Moisés.','As maldições pronunciadas por Deus contra as tribos que praticavam a idolatria.','Profecias sobre a futura divisão do reino após a morte de Salomão.'),('AT05-L17-Q03','As bênçãos tribais materializam as promessas da aliança abraâmica a Israel.','As guerras entre tribos confirmavam a aliança pela conquista de terras.','Celebram rituais cananeus incorporados à adoração de Israel.','Repudiam a aliança mosaica estabelecendo um novo concerto.'),('AT05-L17-Q04','Que o amassem e o servissem de todo o coração e de toda a alma','Que oferecessem sacrifícios diários no altar do templo','Que guardassem estritamente a lei de Moisés sem exceções','Que seguissem os mandamentos dos profetas e sumos sacerdotes'),('AT05-L18-Q01','Moisés morreu em Moabe, Deus o sepultou e ninguém conheceu o seu sepulcro.','Moisés morreu na Terra Prometida, na fronteira de Canaã.','Moisés ascendeu aos céus em um carro de fogo como Enoque.','O corpo de Moisés foi mumificado e guardado no Egito.'),('AT05-L17-Q02','A lei que Moisés nos ordenou','As doze estrelas da coroa de José','O sangue da aliança com Abraão','Os nomes das doze tribos escritas nas pedras do éfode'),('AT05-L17-Q05','Cada tribo recebeu bênçãos específicas e consequências conforme seu caráter.','As doze tribos foram igualmente abençoadas sem distinção de consequências.','Todas as tribos receberam apenas bênçãos materiais e prosperidade terrestre.','Somente Judá e José foram abençoados e as demais foram descartadas.'),('AT05-L18-Q03','Deus renovou a alianca com Josue como sucessor de Moises.','A morte de Moises encerrou permanentemente a alianca entre Deus e Israel.','Josue foi rejeitado por Deus como sucessor de Moises em Israel.','A alianca foi transferida para os povos vizinhos apos a morte de Moises.'),('AT05-L18-Q02','Promessa do Profeta semelhante a moisés em Deuteronômio 18:15','Celebração da páscoa como memorial da saída do egito','O jejum anual no dia da morte de moisés em israel','O cântico de moisés como lembrança para as gerações'),('AT05-L18-Q04','Amar a Deus de todo o coração e toda a alma','Guardar todos os mandamentos da Lei de Moisés','Oferecer sacrifícios daily no templo','Cumprir rigorosamente o sábado e circuncidar-se'),('AT05-L18-Q05','O povo chorou por trinta dias. Josué recebeu o espírito de sabedoria.','Moisés ressuscitou e continuou guiando o povo por mais quarenta anos.','O povo entrou imediatamente na terra prometida sem necessitar de Josué como líder.','Moisés foi sepultado pelos líderes israelitas no deserto de Sinai.'),('AT05-L19-Q01','Deuteronômio 8:3, 6:13 e 6:16','Êxodo 16:3, 20:3 e 20:13','Deuteronômio 10:20, 11:28 e 15:5','Números 14:22, 21:4 e 32:10'),('AT05-L19-Q03','Jesus cita Deuteronômio 6:5 como o maior mandamento.','Jesus substitui o ensino de Deuteronômio pelo amor ao próximo.','O ensino de Jesus contradiz completamente Deuteronômio.','Jesus modifica Deuteronômio para incluir novos rituais.'),('AT05-L19-Q02','Jesus citouv o Shema ao afirmar que amar a Deus de todo o coração e mente e o maior mandamento','Jesus criticou o Shema como um mandamento ultrapassado e irrelevante para os tempos modernos','Jesus declarou que o Shema deveria ser recitado exclusivamente pelos sacerdotes do templo','Jesus substituiu o Shema pelo amor ao próximo como o mandamento supremo da lei'),('AT06-L01-Q02','Josué 1:1-2','Êxodo 33:9-11','Números 27:15-23','Deuteronômio 34:9'),('AT05-L19-Q06','Jesus usou Deuteronômio como Autoridade Divina, confirmando toda a Escritura Hebraica.','Jesus reinterpretou Deuteronômio conforme o Espírito Santo inspirou os apóstolos.','Jesus anulou Deuteronômio ao proclamar a Nova Aliança, tornando-o obsoleto.','Jesus consultou Deuteronômio apenas como tradição cultural do povo judaico.'),('AT05-L19-Q04','Jesús citava Deuteronômio para ensinar fidelidade e obediência a Deus.','Deuteronômio foi o livro que Jesús reescreveu durante seu ministério.','Jesús usou Deuteronômio para provar que os profetas estavam errados.','Deuteronômio continha as leis secretas que Jesús revelou aos apóstolos.'),('AT05-L19-Q05','Jesus cumpre a profecia de Deuteronômio 18:15, revelando o Pai e cumprindo a Lei.','A profecia indica que Jesus seria igual a Moisés como mero professor da Lei.','Jesus nunca se declarou Deus, apenas cumpriu o que Moisés profetizou.','A profecia se cumpriu em Jeremias, que pregou antes do nascimento de Jesus.'),('AT06-L01-Q05','Josué conduziu Israel à Terra Prometida e estabeleceu as doze tribos em Canaã.','Josué instituiu o sistema de sacrifícios perpétuos no templo de Silo.','Josué fundou a monarquia unificada e coroou Saul como rei.','Josué conduziu Israel de volta ao cativeiro egípcio por desobedecer a Deus.'),('AT06-L01-Q04','Deus fortalece Josué e cumpre Seus juízos em Canaã','Deus abandona Josué por não ser tăo fiel quanto Moisés','Deus permite que Josué governe sem nenhuma intervencao divina','Josué age por conta propria e Deus apenas observa os eventos'),('AT06-L01-Q06','A obediência fiel à aliança e a coragem divinamente fortalecem a liderança.','A sucessão depende de mérito próprio e habilidade política do líder.','O declínio espiritual é inevitável após a morte do líder anterior.','Alianças humanas e políticas são mais importantes que a fé.'),('AT06-L01-Q03','O pecado de Acã, que desviou o que era dedicado ao Senhor em Jericó, trazendo derrota em Ai.','A divisão das doze tribos de Israel na Terra Prometida, garantindo a cada uma sua herança.','O cumprimento da promessa divina a Abraão de dar a terra de Canaã aos seus descendentes.','A travessia do rio Jordão com as águas se abrindo diante do povo de Israel.'),('AT06-L02-Q02','No livro de Josu233, capitulos 3 e 4, ao atravessar o rio Jordao','No livro dos Juizes, capitulo 2, quando o povo se estabelece na terra','No livro de Exodo, capitulo 14, quando atravessam o mar Vermelho','No livro de Josue, capitulo 6, quando as muralhas de Jerico caem'),('AT06-L02-Q01','Josué, Raabe, a queda de Jericó e a travessia do Rio Jordão.','Moisés, as pragas do Egito e a travessia do Mar Vermelho.','Abraão, o chamado de Deus e a aliança da circuncisão.','Davi, Golias e a conquista de Jerusalém.'),('AT06-L02-Q04','Deus julgou as nações cananeias e as expulsou perante Israel.','Deus abandonou Israel durante a entrada em Canaã para que conquistasse sozinho.','As nações de Canaã julgaram Deus e por isso foram destruídas.','Deus enviou pragas contra Israel ao entrar em Canaã como castigo.'),('AT06-L03-Q02','Nos capítulos 3 e 4 do Livro de Josué','Nos capítulos 7 e 8 do Livro de Juízes','No capítulo 2 do Livro de Josué, após a queda de Jericó','Nos capítulos 5 e 6 do Livro de Josué, antes da entrada em Canaã'),('AT06-L02-Q06','A circuncisão em Gilgal simboliza renovação da aliança antes da conquista.','A queda de Jericó ensina que a fé move montanhas sem esforço humano.','O tabernáculo foi erguido em Jericó como centro da adoração cananeia.','Josué liderou sozinho sem depender de orientação divina directa.'),('AT06-L02-Q05','Guerra contra os povos cananeus, conquista e distribuição da terra entre as tribos.','Fim imediato de todas as guerras e paz eterna entre Israel e todas as nações.','Exílio automático de Israel de volta ao Egito como punição divina.','Transformação de Israel na maior potência militar do mundo antigo.'),('AT06-L02-Q03','O pecado de Acan, que desviou do anátema.','A promessa da terra a Abraão em Gênesis.','A queda dos muros de Jericó por trombetas.','A travessia do Mar Vermelho por Israel.'),('AT06-L03-Q03','A ordem para os sacerdotes entrarem no Jordao com a Arca','A promessa de abundantes territorios ao norte do Jordao','O pecado de duvidar da promessa diva ao atravessar as aguas','O conflito com os reis dos amorreus ao atravessar o rio'),('AT06-L03-Q01','Josué, arca da aliança, sacerdotes, rio Jordão que parou, doze pedras em Gilgal.','Moisés, maná, serpente de bronze, tábuas da lei.','Elias, Eliseu, rio Jordão, odre de óleo.','A arca, o bezerro de ouro, tábuas da lei, candelabro.'),('AT06-L04-Q01','Marchar 7 vezes ao redor no sétimo dia, tocar shofares e gritar','Atacar imediatamente ao amanhecer com toda a força militar','Cercar a cidade e esperar até que se rendessem por fome',' cavalos de Troia dentro da cidade durante a noite'),('AT06-L04-Q02','Sete dias, girando ao redor da cidade uma vez por dia','Treze dias, girando ao redor da cidade uma vez por dia','Quarenta dias, girando ao redor da cidade duas vezes por dia','Sete semanas, girando ao redor da cidade uma vez por semana'),('AT06-L03-Q04','Deus parou as águas do Jordão em montão para que o povo passasse em seco.','Deus enviou fogo do céu para secar o rio antes da travessia do povo.','Deus abriu a terra formando um caminho seco no meio das águas.','Deus enviou anjos para carregar a arca da aliança através do rio.'),('AT06-L03-Q05','Ingresso na Terra Prometida, circuncisão e fim do maná','Águas se tornaram amargas como em玛拉','Quedas de codornizes cessaram','Tablets de pedra foram recibidos'),('AT06-L04-Q07','Fé, obediência e a soberania de Deus em cumprir suas promessas.','Que a força militar humana é suficiente para conquistar qualquer cidadela.','Que a fé exige confrontar diretamente os inimigos sem hesitação.','Que as bênçãos divinas dependem de condições favoráveis ao homem.'),('AT06-L04-Q06','Os bens da cidade foram dedicados ao Senhor, não podíanser tomados.','Os bens da cidade deviam ser distribuidos entre os soldados.','Os bens da cidade deviam ser queimados completamente.','Os bens da cidade pertenciam ao rei local e seriam seus.'),('AT06-L04-Q03','Os sacerdotes levavam a Arca e tocavam trombetas para derrubar os muros de Jericó.','Os sacerdotes ofereciam sacrifícios sobre o altar para apaziguar a Deus.','As trombetas reuniam o povo para adoração no tabernáculo.','A Arca guardava as tábuas da Lei e o maná como的记忆.'),('AT06-L04-Q05','Por sua fé em Deus e por ter acolhido os espiões','Porque foi a unica que creu na promessa de Deus','Por ser a mulher mais rica e influente de Jericó','Porque escondeu os espiões por medo das autoridades'),('AT06-L04-Q04','As muralhas de Jericó ruíram','Deus enviou fogo do céu sobre o acampamento','O mar Vermelho se abriu diante deles','Sete pragas foram enviadas sobre o Egito'),('AT06-L05-Q03','NAO SEI','Por meio de julgamento divino com fogo do céu','Pela confissão voluntária diante do sumo sacerdote','Através de um sonho revelado pelo anjo do Senhor'),('AT06-L05-Q02','O pecado de Acan fez Deus desviar-se de Israel, causando a derrota contra Ai.','Os amigos de Acan impediram Josue de liderar, causando a derrota em Ai.','O pecado de todos os israelitas em Jerico fez o povo perder a batalha contra Ai.','A chuva forte fez os israelitas tropecar durante o ataque surpresa a Ai.'),('AT06-L05-Q01','Não tomar para si o spoil dedicado ao Senhor em Jericó','Não adulterar com as mulheres de Jericó','Não profanar o sábado após a conquista','Não construir altares a deuses estranhos'),('AT06-L05-Q04','Um manto de Sinar, duzentos siclos de prata e uma barra de ouro de cinqüenta siclos.','Gados, ovelhas e bois do rebanho de Jericó.','O arco de Ebenezer e as trombetas de prata.','Pedras preciosas, especiarias e unguentos aromáticos.'),('AT06-L05-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT06-L06-Q01','Josué na conquista de Canaã, Davi nas guerras, Gideão contra Midiã','Abraão e a construção da arca, Noé no dilúvio, Sansão contra os filisteus','Moisés e o êxodo do Egito, Elias contra os profetas de Baal, Davi e o templo','Isaías nas profecias, Jeremias na queda de Judá, Daniel no sonho de Nabucodonosor'),('AT06-L06-Q02','Nos livros de Josué e Juízes','Livros de Samuel e Reis','Livros de Crônicas e Esdras','Nos livros de Êxodo e Números'),('AT06-L06-Q04','Deus usa nações como instrumentos de juizo divino sobre povos rebeldes','Deus sempre protege militarmente seu povo escolhido na guerra','Deus abandona nações que usam a força militar para conquistar','Jesus ordenou guerras de conquista aos seus apostolos'),('AT06-L05-Q05','Porque o pecado de Acã tornou toda a congregação culpada diante de Deus.','Porque Deus puniu a todos por falhas individuais de cada membro.','Porque o pecado de um líder religioso afeta toda a liderança da igreja.','Porque pragas e defeats eram coincidências sem relação com o pecado.'),('AT06-L06-Q05','As campanhas trouxeram cativeiro, destruicao do templo e perda da independencia.','As campanhas resultaram em paz perpetua e destruicao dos inimigos.','As campanhas trouxeram prosperidade continua e aliancas militares permanentes.','As campanhas causaram a construcao do terceiro templo e conversao universal.'),('AT06-L06-Q03','A promessa da terra prometida','A ordem de atravessar o mar Vermelho','O pecado da construção da arca','O conflito entre Caim e Abel'),('AT06-L06-Q06','A desobediência a Deus anula o sucesso militar e espiritual, como ocorreu com o rei Saul.','O sucesso militar absoluto garantiza a aprovação divina e a permanence na liderança do povo.','A fé em Deus é desnecessária quando se tem superioridade numérica e estratégica no campo de batalha.','As campanhas militares bem-sucedidas sempre indicam bênção divina e fidelidade à aliança.'),('AT06-L07-Q05','Gerou disputas territoriais entre as tribos e consolidou a confederação israelita.','Causou o exílio imediato das doze tribos para o Egito e Babilônia.','Resultou na destruição total e no desaparecimento dos povos cananeus.','Estabeleceu um reino unificado sob um único rei desde o início.'),('AT06-L07-Q01','Josué e Calebe na exploração de Canaã, e a divisão da terra entre as doze tribos.','Abraão recebeu a terra prometida e dividiu entre seus filhos Isaque e Ismael.','Sansão e Gideão lideraram a conquista e distribuição de Canaã aos israelitas.','O dilúvio foi o primeiro evento relacionado à distribuição de terras no mundo.'),('AT06-L07-Q03','Os levitas não receberam terra, mas cidades','Cada um dos doze filhos de Jacó recebeu porção igual de terra','A distribuição foi feita por Deus diretamente a cada família','Os cananeus aceitaram sair da terra sem nenhuma resistência'),('AT06-L07-Q04','Deus julgou e distribuiu a terra por sorte entre as tribos de Israel.','Deus entregou a terra aos mais fortes conforme o direito de conquista.','Deus permitiu que a terra fosse dividida conforme a sabedoria dos líderes.','Deus exigia pagamento pela terra para determinar a herança de cada um.'),('AT06-L08-Q02','Josué 20 – Josué designa as seis cidades de refúgio','Juízes 5 – nas cidades onde as mulheres se reuniam','Josué 15 – nas cidades situadas na fronteira de Judá','Juízes 1 – quando Judá expulsou os cananeus'),('AT06-L07-Q06','Fé e obediência: Deus cumpre Suas promessas quando Seu povo confia e obedece','A terra foi dividida conforme a capacidade militar e merecimento de cada tribo','Todos os israelitas receberam porção igual e permanente na terra prometida','A distribuição aconteceu por conquista humana independente da vontade divina'),('AT06-L07-Q02','Josué 13-21, na divisão da terra prometida','Juízes 17-21, quando cada tribo escolheu terra','Josué 1-12, na conquista das cidades cananeias','Josué e Juízes, no período patriarcal de Abraão'),('AT06-L08-Q01','Homicida involuntario, vingador do sangue, sumo sacerdote, seis cidades.','Sodoma, Gomorra, Ninive, Babel, Tiro e Damasco.','Rei Davi, Salomon, Jeremias, Ezequiel e Daniel.','Jesus, Paulo, Pedro, Joao e Tiago construiram as cidades.'),('AT06-L08-Q03','O sumo sacerdote falecido','O caminho preparado para o refúgio','A oferta pelo pecado do inocente','O altar de bronze no centro da cidade'),('AT06-L08-Q04','Deus estabeleceu cidades para proteger inocentes e garantir justiça correta.','Deus destruiu as cidades de refúgio por causa da impunidade dos pecadores.','Os refugiados eram obrigados a adorar ídolos para serem aceitos nas cidades.','Deus usava as cidades para punir crimes intencionais com maior rigor.'),('AT06-L08-Q05','Proteger homicidas involuntarios da vinganca ate o julgamento.','Funcionar como centros comerciais e estrategicos para o reino.','Servir de abitacao exclusiva para os levitas e seus descendentes.','Isolar doentes e leprosos da populacao para evitar contágio.'),('AT06-L09-Q01','Josué e o povo de Israel renovaram a aliança em Siquém ao entrarem na Terra Prometida.','Abraão recebeu a promessa da aliança com Deus em Ur dos caldeus.','Moisés subiu ao monte Sinai para selar a primeira aliança com o povo.','Davi ungido por Samuel estabeleceu nova aliança em Hebrom.'),('AT06-L08-Q06','Deus provedencia protecao e justica para o matarife inadvertido.','As cidades de refgio foram estabelecidas para adoracao de deuses cananeus.','Os homicidas intencionais tambem recebiam protecao nes sas cidades.','Foram abandonadas apos o reinado de Davi e nunca mais usadas.'),('AT06-L09-Q02','Josué 24','Josué 8','Josué 3','Josué 23'),('AT06-L09-Q05','Bênçãos pela obediência e maldições pela desobediência, incluindo a dispersão entre as nações.','Prosperidade econômica imediata e paz perpetua com todos os povos vizinhos.','Perdão automático de todos os pecados passados, presentes e futuros sem necessidade de arrependimento.','Transformação imediata de Israel na maior superpotência militar do mundo antigo.'),('AT06-L09-Q03','A promessa de Deus em abençoar o seu povo','A ordem de adorar outros deuses neben os demais','O conflito armado entre israel e as demais nações','O pecado da mentira praticado pelo povo elegido'),('AT06-L09-Q04','Deus renova a alianca com fidelidade, perdoando e transformando o seu povo','Deus destroi completamente a sua alianca com Israel e abandona o seu povo para sempre','Deus exige obediencia perfeita sem oferecer graça ou misericordia ao pecador','Deus reconhece o merito humano como base suficiente para a salvacao eterna'),('AT06-L10-Q01','Josué reúne todos em Siquém, renova a aliança, recorda a história de Israel e morre aos 110 anos.','Josué nomeia novos profetas para liderarem Israel após sua morte e organiza um grande sacrifício em Gilgal.','Os líderes de Judá assumem o comando político e Josué é sepultado na região do Sinai.','Josué entrega o governo aos anciãos de cada tribo e institui uma monarquia temporária em Betel.'),('AT06-L09-Q06','Renovar aliança exige escolher a Deus e romper com ídolos','Basta renovar a aliança externamente para garantir a proteção divina','A renovação da aliança，只需 realizar rituais formais sem mudança de coração','A aliança renovada não exige compromisso pessoal do líder'),('AT06-L10-Q02','Josué 24, em Siquém','Juízes 2, em Betel','Josué 23, em Jericó','Juízes 21, em Siquém'),('AT06-L10-Q04','Deus renova a alianca e adverte sobre as consecuencias da desobediencia.','Deus condena Josue por nao ter conduzido Israel adequadamente.','Deus abandona Israel imediatamente apos a morte de Josue.','Deus envia pragas sobre o povo pela desobediencia a Josue.'),('AT06-L10-Q03','A advertência contra casamentos mistos e adoração de deuses estranhos','A ordenação da construção do templo em Jerusalém pelos levitas','A promessa de um rei que governaria sobre todo o Israel','O relato do cativeiro do povo na terra do Egito'),('AT06-L11-Q01','A conquista cumpriu a promessa a Abraão de dar Canaã aos seus descendentes.','A promessa a Abraão foi sobre a linhagem messiânica, não sobre a terra.','A conquista foi ordenada por Gideão, cumprindo a promessa a Sansão.','A promessa de Canaã foi feita diretamente a Josué, não a Abraão.'),('AT06-L10-Q05','Abandonaram a Deus e serviram ídolos, e os cananeus permaneceram no meio deles.','As doze tribos se dividiram em reinos rivais e entraram em guerra civil.','Israel viveu em paz e prosperidade perfeita por todo o período do juízes.','O povo foi imediatamente levado em cativeiro para a Babilônia.'),('AT06-L10-Q06','Manter-se fiel à aliança apesar das pressões e escolhas de cada geração.','A liderança deve ser passada por herança direta de sangue entre os líderes.','A decadência espiritual é inevitável e não pode ser prevenida por ensino.','Alianças com nações pagãs fortalecem a fé e a aliança do povo.'),('AT06-L11-Q03','A terra era dada conforme a obediência à aliança mosaica, pela fidelidade a Deus','A terra foi prometida por direito divino absoluto, sem relação com a conduta','A santidade de Israel era apenas espiritual, sem vínculo com a possessão','A fidelidade mosaica era apenas cerimonial, sem consequência territorial'),('AT06-L11-Q02','Como juizo divino contra a impiedade das nacoes cananeias','Como resultado de disputas territoriais entre povos antigos','Como prova de fe e obediência do povo de Israel','Como conquista militar motivada por interesses economicos'),('AT06-L11-Q04','Porque Deus é o Criador e Dono de toda a terra','Porque os israelitas eram demasiado fracos militarmente','Porque os anjos criaram a terra antes de Deus','Porque a terra estava vazia quando chegaram'),('AT06-L11-Q05','A desobediência impediu que expulsassem todos os povos cananeus, deixando terra por conquistar.','A falta de recursos militares impediu que derrotassem os cananeus nas batalhas restantes.','A obediência perfeita de Israel limitou a conquista ao tempo designado por Deus.','Os cananeus tinham carros de ferro superiores que tornaram a vitória impossível.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT05-L15-Q01','Moisés exortou Israel antes de morrer, mostrando bênçãos e maldições.','Moisés fez isso durante o êxodo do Egito.','Contexto da construção do tabernáculo no deserto.','Quando Israel pediu um rei para governar.'),('AT05-L17-Q06','É retomado na promessa messiânica, cumprida em Jesus Cristo.','É completamente abandonado no Novo Testamento após a lei.','É restabelecido integralmente nos mandamentos cerimoniais.','É aplicado aos anjos no livro de Apocalipse como bênção final.'),('AT05-L18-Q06','Moisés morreu em Nebo, Judá o enterrou. Jesus citava Mois','Moisés não morreu, foi arrebatado em um carro de fogo como Enoque.','Jesús ressuscitou a Moses durante seu ministério na Galileia.','Moisés morreu em frente ao Mar Vermelho, e Deus o sepultou nas aguas.'),('AT06-L01-Q01','Josue sucessor de Moises na conducao de Israel na conquista de Canaa','Josue sucessor de Samuel como ultimo politico e juiz de Israel','Josue liderou a fuga do povo hebreu e a travessia do Mar Vermelho','Josue acompanhou Elias na viagem de carruagem de fogo ao ceu'),('AT06-L03-Q06','Fé e obediência a Josué garantiram a travessia miraculosa do Jordão','A travessia simbolizou a independência dos israelitas sem intervenção divina','O evento demonstrou que a fé sozinha, sem obediência, bastava a Deus','A travessia probou que Deus havia abandonado seu pacto com Israel'),('AT06-L12-Q01','A impiedade das nações, cujas abominações estavam completas','A recusa em adorar o Deus de Israel e sua resistência armada','A proximidade geográfica com Israel e a disputa por territórios','A decisão política dos líderes hebreus de expandir suas fronteiras'),('AT06-L11-Q06','Por ser juízo particular da aliança com Israel, não modelo universal.','Porque Canaã foi totalmente destruída no passado.','Porque Deus agora prega paz universal a todos.','Porque Jesus Cristo anulou toda a Lei.'),('AT06-L12-Q04','Como parte da convenção literária retórica de guerra do ANE','Como descrições literais de genocídio ordenado por Deus aos israelitas','Como termos exclusivos hebraicos sem paralelo cultural mesopotâmico','Como registros arqueológicos precisos de campanhas de extermínio'),('AT06-L12-Q05','A fé e as obras de Rahab e dos gibeonitas importaram mais que sua origem étnica.','Porque os gibeonitas e Raabe descendiam dos mesmos patriarcas que Israel.','Sua aceitação dependeu de que abandonassem completamente sua cultura nativa.','Os cananeus preservados haviam sido todos circuncidados antes da conquista.'),('AT06-L12-Q07','Unidas no caso de Raabe, que pela fé foi poupada da destruição de Jericó.','Separadas nos livros históricos, aparecendo apenas nos profetas maiores.','Combinadas nas ofertas levíticas como requisitos para a entrada em Canaã.','Apresentadas apenas nos Salmos como tipos messiânicos da vida de Cristo.'),('AT06-L13-Q02','Juízes 1:1','Josué 24:1','Josué 1:1','1 Samuel 1:1'),('AT06-L14-Q01','Pecado, opressão, clamor, libertação, restauração','Sacrifício, jejum, oferta, testemunho, adoração','Profetismo, revelação, julgamento, sentença, execução','Batalha, vitória, aliança, celebrações, conquistas'),('AT06-L13-Q06','A infidelidade à aliança resulta em declínio espiritual por desobedecer a Deus.','A fidelidade à aliança garante prosperidade material e vitória militar imediata.','O período dos juízes demonstra que a liderança forte e humana é suficiente para a vitória.','A aliança com Deus pode ser mantida mesmo quando se adora outros deuses.'),('AT06-L13-Q05','Opressão por povos vizinhos e cada um fazendo o que parecia reto aos seus olhos','Unificação completa sob um único rei e paz duradoura em toda a terra','Fim de toda adoração idólatra e纯全敬拜Jeová em Israel','Prosperidade econômica generalizada e ausência completa de conflitos'),('AT06-L14-Q02','Pela violação da aliança, Deus os entregava aos inimigos como juízo.','Por meio de pacto com demônios que invocavam a dominação estrangeira sobre eles.','Porque a adoração de falsos deuses enfraquecia o exército na guerra santa.','Devido à cobiça que os povos vizinhos sentiam pelas terras prometidas.'),('AT06-L14-Q05','Porque voltavam a pecar e a servir outros deuses','Porque os inimigos voltavam com mais forca','Porque os juizes nao eram suficientemente fortes','Porque Deus nao queria libertacao definitiva'),('AT06-L14-Q04','Por meio do Espírito Santo, que vinha sobre eles e os capacitava para liderar Israel.','Por meio de sonhos e visões receivedas em oração sincera','Por meio de eleição popular entre os anciãos das tribos','Por meio de sinais e prodígios realizados diante do povo'),('AT06-L14-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT06-L14-Q03','Era a comunicação do povo com Deus em momentos de sofrimento e angústia.','Era um ritual de celebração e alegria durante as festas religiosas.','Era um sinal de rebellião contra as autoridades estabelecidas.','Era uma forma de honrar os ídolos e templos pagãos da época.'),('AT06-L15-Q03','Otniel foi o primeiro juiz de Israel que derrotou Cúsã-Risataim.','Otniel foi um propheta que recebeu a Lei no monte Sinai.','Otniel construiu o primeiro altar em Jericó após a conquista.','Otniel foi sacerdote e liderou o povo no deserto por 40 anos.'),('AT06-L15-Q05','Libertou Israel da opressão de Cusã-Risataim, trazendo paz por quarenta anos.','Conduziu Israel à conquista de Jericó e estabeleceu a capital em Jerusalém.','Fundou a escola dos profetas em Betel para formar líderes religiosos.','Introduziu a monarquia em Israel como primeiro rei ungido.'),('AT06-L15-Q04','O Espírito do Senhor veio sobre ele e o Senhor entregou o inimigo nas suas mãos','Deus abandonou Otniel por falta de fé e permitiu que o inimigo o vencesse','O Senhor julgou Otniel com severidade por não destruir completamente os cananeus','Deus nada fez por Otniel, que sozinho derrotou o rei de Mesopotâmia'),('AT06-L15-Q01','Primeiro juiz de Israel, irmão de Caleb, derrotou Cuchã-Risataim e casou com Acsa.','Filho de Gideão e pai de Sansão, liderou a resistência contra os filisteus.','Sacerdote que construiu o primeiro templo e aconselhou o rei Davi.','Profeta que alertou o rei de Judá sobre a destruição de Nínive.'),('AT06-L15-Q02','Juízes 3.7-11, primeiro juiz de Israel','Josué 2, quando Josué enviou espias a Jericó','No livro de Gênesis, como filho de Quenaz','Em 1 Samuel, como predecessor do rei Saul'),('AT06-L15-Q06','Deus levanta libertadores quando Seu povo se arrepende e clama por ajuda','Otniel foi o primeiro rei ungido de Israel apos a morte de Josue','Otniel construiu o primeiro templo de Jerusalem nos dias de sua vida','Otniel liderou uma rebeliao militar contra os Filisteus em Hebron'),('AT06-L16-Q03','Eúde libertou Israel do rei Eglom de Moab','Eúde recebeu a promessa de ser juiz de Israel','Eúde ordenou a construção do templo de Silo','Eúde cometeu idolatria e afastou Israel de Deus'),('AT06-L16-Q02','Juízes 3:12-30, na história do juez Eúde','Josué 2, na queda dos muros de Jericó','Juízes 4, no tempo da profetisa Débora','Josué 10, na batalha contra os amorreus'),('AT06-L16-Q05','Libertou Israel da opressão de Eglon, rei de Moabe, e a terra teve descanso por oitenta anos.','Estabeleceu a capital em Samaria e proclamou o reino united de Israel sob sua liderança.','Conduziu Israel à guerra contra os filisteus, resultando em grande vitória militar.','Introduziu a adoração idólatra em Israel, causando grande apostasia no povo.'),('AT06-L16-Q06','Deus usa líderes improváveis para libertar seu povo','A passividade é virtude essencial para bons líderes','Alianças com inimigos garantem a vitória militar','A decadência espiritual garante a libertação de Israel'),('AT06-L16-Q01','Eúde, juiz canhoto de Benjamim, matou Eglom, rei de Moabe, libertando Israel.','Sansão, guerreiro canhoto de Judá, destruiu o templo de Dagom dos filisteus.','Gideão, juiz de Manassés, derrotou os midianitas com 300 tochas e barulho.','Débora, profetisa e juíza de Israel, comandou Baraque contra Sísera nas planícies.'),('AT06-L17-Q01','Profetisa e juíza de Israel que julgava o povo sob a tenda.','Rainha que governava Israel antes da monarquia.','Mãe do profeta Samuel que o entregou ao templo.','Esposa do juiz Gideão, conhecido como板材者.'),('AT06-L16-Q04','Deus levantou Eúde para libertar Israel da opressão moabita, usando-o como instrumento do Seu juíz','Deus enviou Eúde como profeta para condenar os ídolatras de Israel e restaurá-los à aliança','Eúde foi um sumo sacerdote que julgou as disputas religiosas do templo em Jerusalém','Deus condenou Eúde por usar violência e nunca mais permitiu que outro juez governasse Israel'),('AT06-L17-Q02','Fosse ao monte Tabor com dez mil homens','Fugisse para o Egito com seu povo','Construsse um altar para oferecer sacrifícios','Reunisse as doze tribos para jejuar e orar'),('AT06-L17-Q05','Ela matou o general cananeu Sisera com uma estaca de tenda.','Ela foi profetisa que liderou Israel como juiza apos Baraque.','Ela construiu o templo onde a arca da alianca foi guardada.','Ela foi esposa de Baraque e liderou a resistencia israelita.'),('AT06-L17-Q06','Louvor a Deus pela vitória e Libertação de Israel','O cântico fala da criação do mundo em sete dias','Aborda a divisão do reino após a morte de Salomão','Ensina sobre os sacrifícios do templo de Jerusalém'),('AT06-L18-Q01','Pelo anjo do Senhor, enquanto moía trigo no lagar','Por uma voz dos céus durante uma batalha contra os midianitas','Através de um sonho enviado por Deus enquanto dormia','Por uma estrela brilhante que apareceu à noite'),('AT06-L17-Q04','Por Baraque e Débora, e morto por Jael com uma estaca na têmpora.','Por Gideão, com a ajuda dos midianitas, no vale de Jezreel.','Por Sansão, que o derrotou na arena de Gaza.','Por Saul, que o capturou vivo e o levou a Judá.'),('AT06-L18-Q02','O velo de lã molhado de orvalho e depois a terra molhada com velo seco.','Fogo descendo do céu e água brotando da rocha.','O sol parando e a lua se detendo sobre Gibeão.','Três dias de jejum e chuva caindo sobre o monte Carmelo.'),('AT06-L18-Q03','Para que a vitória fosse de Deus, e não pela força do exército','Porque os homens não quiseram lutar contra os midianitas','Porque Deus ordenou que ficassem apenas trezentos','Porque os trezentos eram os mais fortes guerreiros de Israel'),('AT06-L18-Q04','Gideão venceu os midianitas com trezentos homens, usando tochas e trombetas.','Por meio de jejum e oração durante quarenta dias no deserto.','Usando carros de guerra e cavalos em batalha aberta durante o dia.','Comercando o rei dos midianitas no monte Sinai.'),('AT06-L18-Q05','Fez um éfode de ouro e teve filhos que se revoltaram contra sua casa.','Rejeitou a oferta de governar o povo e se isolou no deserto.','Destruiu todos os altares idólatras e por isso foi perseguido.','Construiu um templo com os despojos dos midianitas.'),('AT06-L19-Q02','Juízes, capítulo 9','Josué, capítulo 15','Juízes, capítulos 8 e 9','Juízes, capítulo 10'),('AT06-L19-Q01','Abraão, Sara, Isaque, Rebeca, Gideão e seus setenta irmãos.','Abraão, Sara, José, Faraó e os três anjos de Sodoma.','Davi, Betsabá, Nabal, Abigail e o profeta Natã.','Jacó, Ráquel, Lia, Esaú e o anjo que lutou com Jacó.'),('AT06-L18-Q06','O povo o adorou como ídolo, desviando Israel de Deus.','Gideao o usou em batalha, causando grandes perdas a Israel.','Os filisteus roubaram o efode e o usaram contra Israel.','Ele foi destruido pelos profetas, causando revolta popular.'),('AT06-L18-Q07','Deus usa os fracos para manifestar Seu poder, mostrando que a victoria vem do Senhor.','A victoria depende do tamanho do exercito e da forca fisica do lider, nao da dependencia de Deus.','O homem deve confiar apenas em sua propria forca e capacidades, sem buscar orientacao divina.','Deus so chama pessoas ja poderosas e bem estabelecidas para realizar Sua obra.'),('AT06-L20-Q02','Os amonitas','Os filisteus','Os moabitas','Os edomitas'),('AT06-L19-Q03','O pecado de Abrão ao dizer que Sara era sua irmã','A promessa de Deus de dar-lhe um filho','A ordem divina para construir um altar','O conflito de Jacó com o anjo em Penuel'),('AT06-L19-Q05','Guerra, destruição de Siquém e ruína sobre Israel por 3 anos.','Exílio em massa do povo de Israel para o Egito.','Fome e pragas que duraram 40 anos sobre a terra.','Construção de altares idólatras em todo o território.'),('AT06-L19-Q04','Deus advertiu Abimeleque em sonho, revelando que Sara era esposa de Abraão.','Deus destruiu o reino de Abimeleque por causa da iniq¨idade de seu povo.','Deus condenou Abimeleque à morte por ter desejado a esposa de Abraão.','Deus abençoou Abimeleque por ter tratado bem Sara durante sua estada.'),('AT06-L20-Q01','Era gibeonita rejeitado por seus irmãos que os anciãos de Gileade elegeram para liderar Israel contra os amonitas.','Era neto de Moísés que o sucedeu como juiz de Israel após sua morte.','Era cananeu convertido que Samuel ungiu como rei sobre as doze tribos de Israel.','Era levyta escolhido por Deus para guiar Israel na conquista de Jericó.'),('AT06-L19-Q06','Deus protege Sua aliança mesmo através de reis pagãos que O temem','Lições de liderança exigem que se elimine rivais para manter o poder','Abimeleque prova que a riqueza material indica bênção espiritual','O medo faz o homem abandonar a fé em Deus para buscar proteção humana'),('AT06-L20-Q04','O voto feito a Deus deve ser cumprido sem atraso','Votos sao apenas metas pessoais e nao exigem cumprimento','Deus libera do voto se a oracao nao for respondida','O voto so precisa ser cumprido se nao atrapalhar a vida'),('AT06-L20-Q05','O texto ensina que o voto pode se tornar um fardo','O texto ensina que todo crente deve fazer votos solenes','O texto considera o voto superior à oração simples','O texto proibe completamente qualquer tipo de voto'),('AT06-L21-Q03','Os filisteus','Os amorreus','Os egípcios','Os moabitas'),('AT06-L20-Q03','Oferecer a Deus quem saísse de sua casa ao seu encontro','Que Samson nascesse nazireu desde o nascimento','Jejuar e orar continuamente por quarenta dias','Abster-se de toda bebida fermentada para sempre'),('AT06-L20-Q06','Sem rei, cada um fazia o que parecia certo aos seus olhos','A queda do homem ocorreu por soberba e desobediência voluntária','Obediência leva à vida e desobediência à morte espiritual','A fé é dom de Deus e não resultado de esforço humano'),('AT06-L21-Q02','Sansão era nazireu desde o ventre de sua mãe.','Sansão liderava a ordem dos nazireus em Israel.','Ele escreveu as leis do nazireu em Números seis.','Sansão era sacerdote responsável pelo voto de nazireu.'),('AT06-L21-Q01','Um anjo do Senhor apareceu à esposa de Manoa prometendo um filho nazireu.','Uma estrela brilhante surgiu no céu anunciando o nascimento do guerreiro.','Deus falou diretamente a Sansão ainda no ventre de sua mãe.','Os profetas de Betel anunciaram sua chegada como juiz de Israel.'),('AT06-L21-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT06-L21-Q05','Sansão revelou que seu poder estava em seus cabelos, por ser nazireu.','Dalila descobriu a força ao ver Sansão carregar as portas de Gaza sozinho.','A força de Sansão vinha de um anel mágico que ele usava no braço.','Dalila encontrou um frasco sagrado com azeite na tenda de Sansão.'),('AT06-L22-Q02','Juízes 17:6 e 21:25','Josué 24:23 e Juízes 2:11','Juízes 3:7 e Josué 7:1','Josué 23:16 e Juízes 2:19'),('AT06-L21-Q06','Não. A força vinha do Espírito de Deus. O cabelo era sinal do voto de nazireu.','Sim, o cabelo era encantado por um espírito demoníaco que habitava em Sansão.','Sim, a força estava no cabelo porque Sansão era descendente de gigantes.','Sim, o cabelo continha um feitiço antigo que perdia efeito ao ser cortado.'),('AT06-L21-Q08','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT06-L21-Q07','Sansão derrubou o templo de Dagã sobre os filisteus, matando mais gente do que em toda a sua vida.','Sansão foi apedrejado até a morte pelos filisteus após ser traído por Dalila.','Sansão morreu de velhice em Gaza, tendo se arrependido de todos os seus pecados.','Sansão se lançou de um penhasco, sacrificando a si mesmo sozinho.'),('AT06-L22-Q03','A idolatria como pecado central','A quebra da aliança mosaica','O cativeiro babilonico como juizo','A violacao do sabado ritual'),('AT06-L22-Q04','Deus envia profetas para admoestar Israel e chama ao arrependimento.','Deus abandona Israel sem esperança de restauração futura.','Deus se mostra indiferente ao declínio moral de Israel.','O homem resolve o declínio pela própria sabedoria e força.'),('AT06-L22-Q01','Ciclo de Juízes, Salomão, Jeroboão, Acabe, culto a Baal','Abraão, Gideão, Davi, Sansão, Jeú, Josias','Noé, Ló, Ezequias, Josias, João Batista, Elias','Caim, Balaão, Coré, Roboão, Eliseu, Nabucodonosor'),('AT06-L22-Q05','Cativeiro, destruição do templo, pragas e dominação por povos inimigos','Prosperidade econômica e expansão territorial contínua sobre todas as nações','Aliança eterna e proteção divina permanente sem necessidade de arrependimento','Fortalecimento político e paz duradoura em todo o território israelita'),('AT06-L22-Q06','A infidelidade à aliança resulta em julgamento divino','A prosperidade material indica aprovação divina','O pecado individual não afeta a comunidade','Líderes ímpios não influenciam seu povo'),('AT06-L23-Q01','Samuel, Saul e Davi em 1 Samuel 8, quando Israel pediu um rei, culminando em Davi','Moisés, Josué e os juizes do periodo pré-monarquia, que governaram Israel com justiça','O dilúvio, a arca de Noé e a aliança com Abraão, que estabeleceram a liderança divina','O cativeiro babilônico e os profetas do exílio, que pediram libertação do imperador'),('AT06-L23-Q03','O pecado de rejeitar a Deus como rei','A promessa de um rei segundo o coração de Deus','A ordem de destruir os povos cananeus','O conflito entre Gideão e os midianitas'),('AT06-L23-Q04','Deus levanta e derruba reis conforme sua soberana vontade','Deus aprova todo rei que o povo democraticamente escolhe','Deus abandona os reis apos concede les a uncao real','Deus permite que os reis reigns sem qualquer julgamento'),('AT07-L01-Q01','Rute, Naomi, Boaz, e a historia da redencao em Belém de Judá','Rute, Esther, Neemias e o cativeiro babilonico em Judá','Rute, Lia, Raquel e os doze filhos de Israel no Egito','Rute, Débora, Baraque e a derrota de Sísera por Baraque'),('AT07-L01-Q02','Ponte entre juizes e monarquia, culminando na genealogia de Davi.','Ambientado exclusivamente no período da monarquia consolidada de Israel.','Narra a vida dos profetas durante o cativeiro babilonico.','Relata a conquista de Canaã sob a liderança de Josué.'),('AT07-L01-Q03','Fidelidade e bondade de Rute; decisão de não abandonar Noemi.','Rute foi punida por desobedecer à lei do levirato.','Noemi pecou ao ordenar que Rute se casasse com Boaz.','Rute cometeu adultério antes de conhecer Boaz.'),('AT06-L23-Q06','Sem rei justo, Israel vivia em decadência espiritual, cada um fazendo o que parecia reto aos seus olhos.','A necessidade de um rei justo prova que Deus favorece monarquias absolutistas sobre teocracias.','O texto ensina que a fé em Deus é desnecessária quando há um rei terreno para governar.','A lição é que líderes seculares são sempre mais justos que autoridades religiosas.'),('AT07-L02-Q01','Rute Noemi Boaz e o avô de Davi, Obede.','Abraão Sara Isaque e Jacó, patriarcas de Israel.','Moisés Arão Débora e Gideão, líderes do Êxodo.','Sansão Dalila Sansão Dalila e Dalila, protagonista do livro.'),('AT07-L01-Q04','Atraves da providencia soberana de Deus, usando circustancias e pessoas','Por intermedio dos anjos que controlavam diretamente todos os eventos','Atraves de milagres constantes e interrupcoes sobrenaturais','Pela forca da vontade humana sem nenhuma participacao divina'),('AT07-L01-Q05','Perda de provedores, viuvez, orfandade e escassez. A família de Naomi perde o marido e os dois filhos em Moabe.','Prosperidade imediata e abundância de recursos para toda a família em Moabe.','Casamentos exitosos com estrangeiros locais e integração total na cultura moabita.','Reconhecimento nacional imediato e posição de liderança na comunidade de Moabe.'),('AT07-L01-Q06','Rute, moabita redimida por Boaz, gera a linhagem davídica que leads ao Messias.','Rute foi rejeitada por sua fé e separada da linhagem davídica.','Rute casou-se com o rei Saul para unir as tribos de Israel.','A história de Rute demonstra que os gentios não participam da promessa messiânica.'),('AT07-L02-Q04','Atraves da Sua providencia soberana, guiando cada circunstancia para o bem dos Seus','Por meio de milagres directos e interrupcoes sobrenaturais na vida das personagens','Atraves da intervencao de anjos que comunicavam directamente a vontade de Deus','Mediante a oracao directa de Rute e Noemi, que determinavam os acontecimentos'),('AT07-L02-Q05','Perda do marido e dos filhos, mas redempcao por meio de rute e obede, integrando-a na linhagem de davi','Fuga para o deserto e maldicao sobre toda a descendencia de rute ate a geracao presente','Destruicao total da cidade de belem e morte de todos os seus habitantes por causa do pecado','Exilio imediato da familia de noemi para a assiria e perda total da identidade nacional'),('AT07-L02-Q03','LEALDADE, PERSEVERANÇA, BONDADE, HUMILDADE, DEVOÇÃO, SABEDORIA.','AVAREZA, MENTIRA, ORGULHO, INVEJA, TRAIÇÃO, COBIÇA.','REBELDIA, CRUELDADE, INGRATIDÃO, PREGUIÇA, SOFREGUIDÃO, GANÂNCIA.','DISSIMULAÇÃO, HIPOCRISIA, MALDADE, ARROGÂNCIA, DESLEALDADE, AMBIÇÃO.'),('AT07-L03-Q02','Era o parente remidor obligated a redimir familia, vingar sangue e recuperar herancas','O sacerdote principal que liderava os sacrifícios no Tabernaculo','O guerreiro designado para liderar exercitos contra os inimigos de Israel','O elder responsavel por julgar causas civis entre as tribos'),('AT07-L03-Q01','Boaz era um parente remidor da família de Noemi','Boaz era o sogro de Noemi, pai de seu falecido marido','Boaz era o pai biológico da Moabita Rute','Boaz era o irmão mais novo de Noemi'),('AT07-L03-Q06','Permitiu que Rute colhesse, protegeu-a e redimiu a herança de Naomi.','Negou alimento a Rute para que ela dependesse de sua própria força.','Vendeu suas terras antes que o parente redentor pudesse reclamá-las.','Recusou o papel de resgatador por não querer casar com uma estrangeira.'),('AT07-L03-Q04','Porque era parente mais chegado de Elimelech, com direito prioritário de redenção conforme a lei.','Porque Boaz não tinha recursos financeiros para comprar a herança de Elimelech.','Porque Rute já estava prometida em casamento a outro homem da cidade.','Porque Elimelech tinha vendido todas as terras a um clã estrangeiro primeiro.'),('AT07-L03-Q03','Fez-na colher nas suas terras e ordenou aos servos deixarem feixes para ela.','Pagou-lhe directamente o salario pelas espigas colhidas no campo.','Deu-lhe imediatamente uma casa para morar na cidade de Belém.','Casou-se com ela no mesmo dia em que a encontrou na eira.'),('AT07-L03-Q05','Boaz comprou o campo e desposou Rute, agindo como remidor.','Rute vendeu a heranca e voltou sozinha para sua terra.','O parente mais proximo cedeu a heranca e casou com Naomi.','Boaz negociou e devolveu todas as terras aos moabitas.'),('AT07-L04-Q01','Tamar, Onã, Rute e Boaz, conforme Gn 38 e Rt 4, sobre casamento levirato e redenção familiar.','Abraão, Isaque e Raquel, conforme Gn 22 e Gn 29, sobre casamento e redenção familiar.','Jacó, Esaú e Labão, conforme Gn 25 e Gn 31, sobre aliança e resgate de família.','Moisés, Zípora e Arão, conforme Êx 2 e Êx 4, sobre casamento levirato e redenção.'),('AT07-L03-Q07','Boaz, parente-redentor, prefigura Cristo que redime da condenação.','Ruth, como intercessora, foi o instrumento divino para a redenção de Boaz.','Boaz representava a riqueza material como figura da salvação completa.','O papel de Boaz simbolizava a necessidade de obras humanas para a redenção.'),('AT07-L04-Q02','Resgatava linhagem e terras, consolidando estruturas sociais na transição para Estado.','Eram ritos de guerra usados para legitimar conquistas territoriais.','Função exclusiva do sacerdócio levítico no serviço do santuário.','Instituição do império babilônico adaptada pelos hebreus no exílio.'),('AT07-L04-Q03','Fidelidade, dever familiar, obediência à lei, redenção da herança','Poligamia obrigatória e venda dos filhos para pagamento de dívidas','Sacrifício voluntário do primogênito para garantir a bênção','Abandono da viúva ao templo para purificação do nome'),('AT06-L12-Q03','Porque Israel era povo da aliança e respondeu ao juízo divino por quebrar a Lei.','Porque Deus odeia Israel mais que as outras nações e os castiga com mais severidade.','Porque os pecados de Israel eram piores que os das outras nações, pois conheciam a Lei.','Porque Deus transferiu a culpa dos pecados das outras nações para Israel como sacrifício.'),('AT06-L12-Q06','NAO SEI','O juizo historico precede a salvacao das nacoes pelo Espirito','A missao da Igreja anula os efeitos do juizo divino antigo','Ambos compartilham a mesma natureza de condenacao eterna'),('AT06-L12-Q02','Nos quarenta anos de peregrinação no deserto, aguardando a geração rebelde passar.','Na descida do maná durante quarenta anos para alimentar os israelitas no Sinai.','Nos sete anos de fome que Deus permitiu antes da libertação do Egito.','Nas doze pragas do Egito que demonstraram a paciência divina para com Faraó.'),('AT06-L13-Q03','O conflito contra os cananeus','A promessa da terra de Canaã aos patriarcas','A ordem de atravessar o Jordão','O pecado da adoração ao bezerro de ouro'),('AT06-L13-Q01','Josué e anciãos que lhe sobreviveram, geração que abandonou o Senhor,小宝转的','Profetas que profetizaram em Silo e Santuário de Betel,小宝转的,小宝转的','Arca da Aliança conduzida em procissão e小宝转的,小宝转的,小宝转的','Sumos sacerdotes que revelaram a vontade divina em小宝转的,小宝转的,小宝转的'),('AT06-L13-Q04','Deus os entregou nas mãos de opressores por fazerem o que era mau aos seus olhos.','Deus os enviou pragas e fome imediata sobre todo o Israel sem предупреждение.','Deus destruiu as cidades de Canaã com fogo do céu sem предупреждение aos justos.','Deus abandonou completamente Israel e nunca mais se comunicou com o seu povo.'),('AT06-L17-Q03','Para ter a certeza da promessa e presença de Deus na batalha.','Porque Débora era a única guerreira capacitada do exército de Israel.','Porque precisava que ela conduzisse os soldados à cidade de Quedes.','Porque temia enfrentar Sísera e queria a proteção de uma mulher.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT06-L23-Q02','Juízes 17-21: não havia rei em Israel','Josué 1:8: o livro da lei não departing de tua boca','Juízes 3:10: o Espírito do Senhor veio sobre Otniel','Josué 24:15: escolhei hoje quem servis'),('AT06-L23-Q05','Opressão e tomada dos bens e filhos do povo','Prosperidade e paz permanente para a nação','Aliança eterna com Deus renovada pelo rei','Libertação imediata da opressão inimiga'),('AT07-L02-Q02','Rute e Noemi vivem no tempo dos juizes e sao ancestrais de Davi, ligando as duas eras.','Rute e Noemi foram profetas que anunciaram a vinda do rei Davi ao povo de Israel.','Rute e Noemi foram judgeiras que governaram Israel apos o inicio da monarquia.','O livro de Rute foi escrito pelo proprio Samuel para registrar a transicao dos juizes.'),('AT07-L02-Q06','Rute gerou Obede, bisavó de Davi,链结 messiânica conforme Rute 4:17.','Noemi foi a mãe biológica do rei Davi segundo os textos deuterocanônicos.','Rute e Noemi fundaram a cidade de Belém onde o Messias nasceria.','As duas profetizaram diretamente sobre Jesus em suas conversaciones.'),('AT07-L04-Q04','Pela soberana providencia, ordenando circunstancias e caminhos para Seus propositos redentores.','Pela intervencao direta de anjos que selecionam os conjuges segundo a vontade angelical.','Pela aplicacao exclusiva de leis humanas sem qualquer participacao da vontade divina.','Atraves de sonhos profeticos que determinam mecanicamente todos os casamentos biblicos.'),('AT07-L04-Q06','Boaz agiu como goel e resgatou Rute, garantindo a linhagem que levou ao Messias.','O levirato foi abandonado apos a volta do exilio babilonico por ser considerado impuro.','Moises foi o principal exemplo de resgate familiar que definiu a linhagem messianica.','O levirato garantia apenas a sobrevivencia material, sem relevancia espiritual para a fe.'),('AT07-L04-Q05','Preservação do nome, herança mantida na família e bênção ou maldição conforme o cumprimento.','Dissolução completa da família e perda total de todos os bens para sempre.','Enriquecimento imediato de toda a comunidade vizinha sem nenhuma condição.','Prisão perpétua dos membros da família e confisco de todos os bens.'),('AT07-L05-Q02','Conecta juizes monarquia via Boaz, Rute e a profecia messiânica em Natã','Prova que Davi descende exclusivamente da linhagem profética de Samuel','Registra apenas os nomes dos reis que antecederam Davi em Judá','Demonstra a superiority da linhagem davídica sobre todos os juizes'),('AT07-L05-Q04','Deus elegeu a linhagem de Davi segundo sua soberana vontade','Por meio de guerras e conquistas entre as tribos de Israel','Através do acaso e da escolha humana sem intervenção divina','Mediante alliances matrimoniais com reinos pagãos vizinhos'),('AT07-L05-Q01','Jesse, Obede, Boaz, Rute, Naassão e a unção por Samuel','Saul, Golias, Abigail e a coroação em Hebrom','Salomão, Roboão, Jeroboão e a divisão do reino','Abraão, Isaque, Jacó e os patriarcas de Israel'),('AT07-L05-Q06','Estabelece Jesus como descendente de Davi, cumprindo a promessa messiânica.','Prova que Deus rejeitou a casa de Davi após o cativeiro babilônico.','Mostra que a linhagem messiânica vinha dos filhos de Esaú, não de Jacó.','Indica que o Messias seria descendente de Saul, e não de Davi.'),('AT07-L05-Q03','Tamar, Raabe, Rute, e reyes como Manasses, Ezequias e Josias.','Apenas figuras menores sem relevancia moral ou espiritual registrada.','Somente Saul e seus descendentes com seus atos de guerras.','Unicamente Jesus Cristo sem qualquer mencao a pecados ancestrais.'),('AT07-L05-Q05','Da linhagem de Davi veio Jesus Cristo, o Salvador e Messias prometido, trazendo consequências eternas.','A genealogia de Davi resultou em maldições permanentes sobre toda a sua descendência até hoje.','Os registros genealógicos de Davi causaram rivalidades tribais que dividiram permanentemente Israel.','A linhagem davídica foi completamente abandonada por Deus após os pecados de Roboão.'),('AT07-L06-Q01','Ana estéril, promessa ao Senhor, concepção, nascimento e dedicação de Samuel a Eli','Abraão, Sara, Isaac, anjo do Senhor e pacto da circuncisão','Moisés, Jocabede, caixa de juncos, filha de Faraó e libertação','Isaque, Rebeca, Esaú, Jacó, direito de primogenitura e bênçãos'),('AT07-L06-Q04','Respondendo à oração de Ana, sua mãe, que o dedicou ao Senhor desde o ventre.','Por meio de anjos que anunciaram a Ana a futura maternidade.','Através de sinais miraculosos que apareceram no templo de Siló.','Determinando que Ana ficasse estéril por sete anos antes de conceder o filho.'),('AT07-L06-Q02','Samuel encerra o período dos juízes e abre a era dos profetas e reis.','Samuel nasce para confirmar o pacto mosaico entre Deus e Israel.','O nascimento de Samuel inicia o cativeiro babilônico de Israel.','Samuel nasce como sumo sacerdote取代 os de Siló.'),('AT07-L06-Q03','Fé e devoção de Ana em sua súplica ao Senhor, e zombaria de Penina','Cobiça e inveja de Abraão ao desejar os bens de Ló','Orgulho e rebelião de Caim contra a oferta de Abel','Inveja e mentiras de Rebeca para favorecer Jacó sobre Esaú'),('AT07-L06-Q05','Fim da esterilidade de Ana, Samuel tornou-se profeta e ungiu reis de Israel.','Samuel liderou o êxodo do Egito e fundou as tribos de Israel.','A família de Ana recebeu terras em Hebrom como herança perpétua.','Samuel destruiu os ídolos de Dagão no templo de Silo.'),('AT07-L06-Q06','Samuel ungiu Davi, estabelecendo a linhagem real messiânica.','Samuel era descendente direto do Messias por ser de Judá.','Samuel fundou a linhagem messiânica através de seus filhos.','Samuel nasceu como o próprio libertador profetizado por Moisés.'),('AT07-L07-Q01','Ana, Elcana, Penina, Eli e Samuel; sua oração no tabernáculo e o nascimento de Samuel.','Moisés, Arão e os Dez Mandamentos no Monte Sinai.','Débora, Baraque e a vitória sobre o general Sísera.','Rute, Noemi e Boaz; a coleta de espigas e o casamento.'),('AT07-L07-Q03','Fé perseverante em oração, humildade e promessa de dedicação do filho a Deus','Rebeldia contra a autoridade do sacerdote Eli','Avaricia pelos bens materiais e fertilidade','Desobediência voluntária às leis de Israel'),('AT07-L07-Q05','Deus lhe concedeu um filho, Samuel, e mais потомос.','O sacerdote Eli a repreendeu e a enviou para casa sem bênção.','Ela recebeu uma grande soma de dinheiro como recompensa.','Ana foi proibida de retornar ao tabernáculo por sua oração.'),('AT07-L07-Q06','Ana reconheceu Jesus como o Messias e testificou sobre ele a todos que esperavam a redenção de Israel.','Ana foi mãe de João Batista e o apresentou ao mundo como o predecessor do Messias.','Ana profetizou que Jesus seria crucificado e ressurgiria ao terceiro dia.','Ana era da linhagem real de Judá e confirmou a到来的 do ungido do Senhor.'),('AT07-L07-Q02','Seus louvores preveem a monarquia davídica e o profetismo','Sua súplica pessoal ocorre após o estabelecimento da monarquia','Faz parte da linhagem levítica que governava em Silo','Sua oração celebra o fim dos profetas e dos juízes'),('AT07-L07-Q04','Deus atendeu sua súplica e lhe concedeu Samuel, respondendo sua oração.','Deus enviou o profeta Natã para abençoá-la com um filho.','Elcana intercedeu junto a Deus para que ela concebesse.','Deus a curou primeiramente para que pudesse conceber.'),('AT07-L08-Q01','Eli e seus filhos Hophni e Finéias, Samuel e a arca da aliança','Abraão, Isaque, Jacó e a aliança do Sinai','Samuel, Saul, Davi e a unção como rei','Aarão, Miriã, Josué e a terra prometida'),('AT07-L08-Q03','Impiedade, cubiça e fornicação dos filhos, e omissão de Eli','Orgulho, vaidade e ambição desmedida da família','Embriaguez, preguiça e blasfêmia contra o nome de Deus','Inveja, traição e谋杀 dos inimigos de Israel'),('AT07-L08-Q04','Através da sua soberana vontade e palavra','Pela intervencao direta e exclusiva dos anjos','Por meio da vontade humana exclusivamente','Através de sonhos e visoes profeticas apenas'),('AT07-L08-Q05','Os filhos foram mortos, Eli morreu, e a arca foi capturada pelos filisteus.','Eli foi promovido a juiz de Israel e seus filhos tornaram-se sumos sacerdotes.','A família de Eli recebeu bênçãos e prosperidade eterna.','Os filisteus foram derrotados e entregaram territórios a Eli.'),('AT07-L09-Q01','Samuel, Eli e Deus. Samuel ouviu a voz, não reconheceu, Eli o orientou a responder.','Samuel, rei Saul e Deus. Samuel foi ao deserto e recebeu a mensagem para ungir um rei.','Samuel, Ana e o sumo sacerdote. Ana orou no templo e Deus respondeu sua súplica.','Samuel, os profetas de Betel e Deus. Todos profetizaram juntos no santo lugar.'),('AT07-L08-Q02','Eli foi o ultimo juiz antes de Samuel, transitionando da era dos juzes para a profecia e monarquia.','Eli foi o primeiro sacerdote a servir no templo de Jerusalem durante a monarquia unificada de Davi.','Os filhos de Eli fundaram a escola dos prophetas em Ramot, preparando o caminho para a monarquia.','Eli e seus filhos foram os primeiros reis de Israel apos o periodo dos juzes, estabelecendo a sucesso real.'),('AT07-L08-Q06','Eli guiou Samuel, que ungiu reis e manteve viva a esperança messiânica.','Seus filhos foram ancestrais diretos de Jesus conforme as genealogias bíblicas.','Eli fundou a dinastia real que levou ao Messias através de seus descendentes.','Pregaram pessoalmente a vinda do Salvador e deixaram registros proféticos.'),('AT07-L09-Q05','Samuel tornou-se profeta e juiz de Israel, e a casa de Eli foi julgada por Deus.','Samuel abandonou o serviço sagrado e retornou à vida familiar como pastor.','A família de Samuel recebeu terras abundantes como recompensa divina.','Samuel foi elevado a rei, iniciando uma dinastia davídica antecipada.'),('AT07-L09-Q03','Obediencia, servico fiel, e os pecados dos filhos de Eli','Rebelião, orgulho e avareza de Samuel','Fé, esperança e caridade de Samuel','Paciência, mansidão e os pecados de Raquel'),('AT07-L09-Q06','Samuel ungiu Davi, iniciando a linhagem messiânica e a esperança do reino eterno.','Samuel iniciou a monarquia em Israel, mas rejeitou a ideia de um rei messiânico.','Samuel profetizou que o Messias viria da tribo de Efraim, não de Judá.','O chamado de Samuel foi apenas para julgar Israel, sem relação com a esperança messiânica.'),('AT07-L09-Q04','Deus o chamou diretamente, revelando-lhe a sua vontade progressivamente.','Por meio de sonhos e visões que Samuel recebia durante a noite.','Através da intercessão de anjos mensageiros que lhe apareciam.','Pela escritura de palavras sagradas num pergaminho sagrado.'),('AT07-L09-Q02','Samuel encarna a transição: último juiz, primeiro profeta ungidor de reis.','Samuel iniciou sua vocação como sacerdote no templo de Silo antes de ser juiz.','A vocação de Samuel ocorreu após a instituição da monarquia em Israel.','Samuel foi chamado durante o período dos patriarcas, antes dos juizes.'),('AT07-L10-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT07-L10-Q04','Deus manifestou seu poder sobre os filisteus, afligindo-os com tumors e destruindo o idolo Dagom.','Deus enviou anjos para recuperar a arca diretamente das maos dos filisteus durante a noite.','Deus ordenou que os profetas negociassem a devolucao pacifica da arca aos israelitas.','Deus permitiu que os filisteus ficassem com a arca como sinal de sua preferencia por eles.'),('AT07-L10-Q01','Os filisteus capturaram a arca, o ídolo Dagom caiu, e a arca retornou após pragas.','Moisés construiu a arca no Sinai e a entregou aos sacerdotes para guardá-la.','Davi王爷capturou a arca dos filisteus e a levou em procissão para Jerusalém.','Josué colocou a arca no templo após conquistar a cidade de Jericó.'),('AT07-L10-Q05','Pragas, tumores e mortandade sobre os filisteus que capturaram a Arca.','Abundancia e prosperidade para os filisteus que a possuiram.','Os filisteus se converteram e adoraram ao Deus de Israel.','A Arca trouxe paz e fartura as cidades dos filisteus.'),('AT07-L10-Q06','A arca simboliza a fidelidade de Deus ao concerto davídico e a esperança messiânica.','A captura da arca encerrou definitivamente a aliança divina com Israel.','O rei messiânico nasceria diretamente da arca capturada pelos filisteus.','A arca capturada anulou todas as promessas proféticas sobre o Ungido.'),('AT07-L11-Q02','Tiravam proveito, pervertiam a justiça e não andavam nos caminhos do Senhor.','Eram idólatras e adoravam os deuses das nações vizinhas.','Rejeitaram publicamente a autoridade de Samuel como profeta.','Fugiram para terras distantes e abandonaram o povo de Israel.'),('AT07-L10-Q02','Em 1 Samuel 4, a arca foi capturada pelos filisteus no final dos juizes.','A arca foi capturada por Salomão ao construir o templo em Jerusalem.','A captura da arca aconteceu durante o cativeiro babilonico de Israel.','A arca foi capturada pelos egipcios durante o exodo no deserto.'),('AT07-L11-Q04','Tomará vossos filhos para guerras e vossas filhas para unguentos e cozinhas','Abençoará vossas terras e multiplicará vossos rebanhos e celeiros','Dar-vos-á plena liberdade para fazerdes o que quiserdes','Protegerá vossas famílias e nunca tocará em vossas posses'),('AT07-L11-Q05','Deus permitiu para cumprir Seus propósitos apesar da motivação errada.','Deus enviou profetas para impedir a monarquia imediatamente.','A monarquia foi rejeitada completamente por Deus desde o início.','Deus puniu o povo sem permitir que a monarquia existisse.'),('AT07-L11-Q03','Porque Deus era o Rei de Israel e o pedido significava rejeitar a soberania divina.','Porque Deus é o verdadeiro Rei de Israel e o pedido demonstrava ingratidão aos Seus cuidados.','Porque a monarquia contrariava a promessa messiânica já estabelecida por Deus.','Porque Samuel não tinha autoridade divina para ungir nenhum rei em Israel.'),('AT07-L12-Q01','Samuel ungiu Saul como rei de Israel sob direcao do Senhor','Elias ungiu Saul no templo de Jerusalem apos grandes guerras','Samuel coroou Saul apos o povo pedir um rei como as nacoes','O sacerdote Eli ungiu Saul com o oleo da Arca da Alianca'),('AT07-L11-Q06','O rei devia seguir a Lei de Deus e ler todos os dias','O rei deveria governar independente da Lei, apenas consultando profetas','A monarquia deveria controlar a interpretação da Lei conforme sua vontade','O rei deveria aplicar a Lei apenas aos súditos, isentando-se dela'),('AT07-L12-Q03','Humildade de Saul e obediência de Samuel à vontade de Deus.','Orgulho de Saul ao se declarar superior ao povo de Deus.','Inveja de Davi contra Saul por não ter sido ungido primeiro.','Ambição de Samuel ao escolher Saul como rei por interesse pessoal.'),('AT07-L12-Q04','Deus agia pelo Espirito Santo sobre Saul, guiando-o para reinar.','Deus utilizava anjos para diretamente controlar as decisões de Saul','Saul era escolhido por sorteio entre todos os homens de Israel','Deus influenciava por sonhos e visões que Saul recebia diretamente'),('AT07-L12-Q02','Samuel, último juiz e profeta, ungiu Saul como primeiro rei.','Os juízes escolheram Saul para sucedê-los na liderança de Israel.','A unção foi feita pelo povo através de votação popular em assembleia.','Saul recebeu a unção profética antes mesmo do período dos juízes.'),('AT07-L12-Q06','Estabeleceu o modelo profetico e a esperança de um rei ungido por Deus segundo a Escritura.','Garantiu a sucessão direta do trono israelita para a descendência de Saul até a vinda do Messias.','Transferiu automaticamente a aliança real para a casa de Saul quando Davi falhou.','Deu a Saul o Espírito Santo em plenitude para governar eternamente sobre Israel.'),('AT07-L12-Q05','Perda do reino, espírito maligno, morte de Saul e sua casa, rejeição da linhagem real.','Abundância material, paz permanente e bênçãos eternas para todo o Israel.','Saul viveu em paz com todos os povos vizinhos e prosperou grandemente.','Sua família recebeu primazia sobre a linhagem davídica para sempre.'),('AT07-L13-Q03','Poupou o rei Agague e os melhores animais, destruindo apenas o vil.','Destruiu todas as propriedades e não deixou sobreviventes.','Recusou-se a liderar o exército contra os amalequitas.','Vendeu todos os despojos em vez de destruí-los.'),('AT07-L13-Q04','A obediencia a Deus e mais valiosa que qualquer ritual ou oferta formal.','Os sacrifícios só têm valor quando oferecidos com arrependimento verdadeiro.','Deus prefere ofertas materiais à obediência dos mandamentos.','Sacrificar animais é proibido pela Lei de Moisés desde então.'),('AT07-L13-Q05','Disse que os animais eram para sacrificar ao Senhor','Afirmou que Deus mudou de ideia sobre a ordem','Culparam os sacerdotes pela desobediência','Afirmou que os inimigos o forçaram a agir assim'),('AT07-L13-Q02','Samuel repreendeu a Saul por ter agido tolamente, e disse que o seu reino não seria permanente.','O Senhor aceitou o sacrifício e abençoou Saul com vitória imediata sobre os filisteus.','Samuel elogiou a iniciativa piedosa de Saul e confirmou que seu reino seria estabelecido.','O sacrifício foi rejeitado e Saul foi removido imediatamente do seu cargo de rei.'),('AT07-L14-Q01','Davi, Golias, os filisteus, a fundinha e a pedra no vale de Ela.','Saul, Golias, os amalequitas e a batalha no deserto.','Davi, Sansão, os filisteus e a mandíbula de jumento.','Samuel, o gigante, a espada e a arca no monte.'),('AT07-L13-Q06','A perda do trono para a casa de Davi, fim de sua linhagem real e guerra civil.','O estabelecimento de um reino eterno sob seu comando e prosperidade.','A transferencia do covenant para osenieis e bênçãos permanentes.','A conversao de todo o povo e a fundacao de uma nova alianca sagrada.'),('AT07-L14-Q02','Marca a transição dos juízes para a monarquia no tempo de Samuel.','Ocorreu durante o exílio babilônico, após o período dos profetas.','Davi foi o último juiz antes do estabelecimento da monarquia.','Golias era um propheta que desafiou Saul para testar sua fé.'),('AT07-L14-Q04','Pela Sua soberana providencia, fortalecendo Davi pela fe.','Por intervencao angelical direta, com um anjo empurrando a pedra contra Golias.','Pela forca fisica de Davi, que era um guerreiro poderoso e experiente.','Por um milagre que tornou Davi invisivel aos olhos de todos os exrcitos.'),('AT07-L14-Q03','Fé, coragem, humildade, confiança em Jeová e zelo pela honra de Deus.','Orgulho, vaidade, arrogância e presunção na força própria.','Paciência, mansidão, resignação e medo de enfrentar o gigante.','Inveja, cobiça, rancor e desejo de poder sobre o trono de Saul.'),('AT07-L14-Q05','Vitoria para Israel, gloria para Davi e derrota dos filisteus.','Davi foi condenado a morte por Saul por agir sem ordens.','Israel perdeu a guerra e Golias se tornou rei de Judá.','A familia de Davi foi amaldiçoada por tres gerações.'),('AT07-L15-Q01','Saul, Jonathan, Nabal, Abigail, Samuel e a fuga de Davi para En-Gedi','Faraó, José, Moisés, os dez flagelos e a travessia do Mar Vermelho','Abraão, Ló, Sodoma, Gomorra, o anjo do Senhor e a sarça ardente','Elias, Eliseu, Acabe, Jezabel, o monte Carmelo e a chuva de fogo'),('AT07-L14-Q06','Davi derrotou Golias e foi ungido rei, tornando-se ancestral do Messias prometido.','Golias era descendente do gigante Enaque, inimigo ancestral dos israelitas.','Davi pediu a Saul que guardasse a cabeça de Golias como troféu.','A vitória de Davi sobre Golias antecipou o fim da esperança messiânica.'),('AT07-L15-Q02','Transicao do carisma profetico para a monarquia daviica','Davi foi o ultimo juiz antes da monarquia em Israel','A persecucao de Davi marca o fim da era dos profetas','Saul foi ungido rei pelos proprios labios de Deus'),('AT07-L15-Q03','NAO SEI','Fé, humildade e fidelidade a Deus durante a fuga de Saul','Adultério com Bate-Seba e homicídio de Urias o heteu','Orgulho pelo censo e incredulidade no momento da fuga'),('AT07-L15-Q06','A perseguição levou à unção e ao trono de Davi, de cuja linhagem nasceria o Messias.','A perseguição levou ao exílio permanente de Davi, impedindo-o de reinar.','A perseguição demonstrou que Deus rejeitou a casa de Davi para sempre.','A perseguição fez com que a linhagem messiânica viesse de Saul.'),('AT07-L15-Q05','David tornou-se fugitivo, perdeu sua família e gerou divisão no reino de Israel','David morreu jovem e seu reino foi destruído imediatamente após a perseguição','A perseguição não trouxe consequências significativas a Davi durante sua vida','Davi retornou ao palácio de Saul imediatamente após o inicio da perseguição'),('AT07-L15-Q04','Pela providencia divina, o Espirito Santo e a direcao soberana de Deus.','Por intermedio de anjos que diretamente protegiam Davi de todos os perigos.','Pela sagacidade e estrategia militar que Davi desenvolveu durante a fuga.','Atraves de sonhos profeticos que revelavam cada movimento de Saul.'),('AT07-L16-Q01','Jônatas fez aliança com Davi e entregou-lhe suas vestes e armaduras.','Jônatas era irmão de Davi, filho de Saul, e foram criados juntos.','Jônatas combateu o gigante Golias ao lado de Davi, demonstrando sua coragem.','Jônatas e Davi selaram um pacto e compartilhavam o trono de Israel.'),('AT07-L16-Q03','Lealdade, amor fraterno, fidelidade e aliança entre amigos.','Orgulho, inveja, traição e ressentimento entre os amigos.','Amor próprio, independência, neutralidade e distância.','Rivalidade, cobiça, ciúme e desconfiança mútua.'),('AT07-L16-Q04','Pela providencia soberana de Deus, que une os corações','Por intervencao direta de anjos que aproximavam os dois','Atraves de milagres sobrenaturais que separavam Saul de Davi','Por escolhas puramente humanas, sem participacao divina'),('AT07-L16-Q02','Simboliza lealdade que transcende a rivalidade política entre Saul e Davi.','Ilustra uma aliança militar entre as tribos do norte e do sul.','Prova que a monarquia foi rejeitada por Deus desde o início.','Sinaliza que os juizes deveriam ter permanecido no poder.'),('AT07-L16-Q05','Amizadedeeeperssoalnocompartilhamentodealma,aliancadequedavi sobreviveuaosal','Inimizadedesaulcontraovidacriandoumconflitonacionalentreascasas','Uniaodostriboscontraodedaviematravesdaprotecaodejônatas','Abencaoadoternaquejônatasrecebeupordeixarumamizocomdavi'),('AT07-L16-Q06','A amizade protegeu a vida de Davi para que cumprisse a linhagem messiânica','Jonathan foi o ancestral direto do rei messiânico ao casar-se com a filha de Davi','A amizade enfraqueceu a linhagem davídica ao dividir o reino entre os dois','Jonathan intercedeu junto a Deus para que a promessa messiânica passasse a ele'),('AT07-L17-Q02','A morte de Saul encerra sua dinastia fracassada e abre espaco para o reino de Davi, consumando a transicao dos juizes para a monarquia.','A morte de Saul marca o inicio dos juizes, pois Deus escolheu um governante teocratico para liderar Israel apos os profetas.','O falecimento de Saul confirma a vigencia da monarquia teocratica dos jueces, ja que todos os reis de Israel descendiam dele.','A morte de Saul representa o fim dos profetas veterotestamentarios, transferindo toda a revelacao divina para a monarquia davidica.'),('AT07-L17-Q01','Saul, Samuel, Jonathan, os filisteus e a feiticeira de En-Dor.','Moisés, Josué, os egípcios e o mar Vermelho.','Davi, Absalão, os filisteus e a arca da aliança.','Elias, Eliseu, os profetas de Baal e Jezabel.'),('AT07-L17-Q04','Pela soberania divina, cumprindo seus propositos','Por intervencao dos profetas de Baal','Atraves de coincidencias e destino','Por meio de oraculos pagãos'),('AT07-L17-Q03','Suicidio por medo dos inimigos, desobediencia anterior consultando a nigromante','Morte heroica em combate contra os filisteus','Perdao divino antes de sua morte','Morreu pacificamente em sua cama aos dias de velhice'),('AT07-L17-Q05','Guerra civil, perda do reino pela sua casa e elevação de Davi ao trono','Fim da monarquia em Israel e invasão assíria imediata','Prosperidade e paz duradoura para todo o povo de Israel','Conversão dos filisteus ao Deus de Israel e aliança eterna'),('AT07-L17-Q06','Remove Saul e estabelece Davi, pela linhagem do qual virá o Messias.','Anula as alianças divinas com Israel e encerra a esperança messiânica.','Prova que Saul era o ungido de Deus e o verdadeiro Messias.','Indica que o Messias não virá pela linhagem davídica, mas de Saul.'),('AT07-L18-Q01','Davi: ungido por Samuel, enfrentou Golias, rei em Hebrom e Sião','Davi: ungido por Elias, enfrentou o faraó, reinou em Betel e Jericó','Davi: batizado por João, pregou no templo, fundou a sinagoga','Davi: venceu Nabucodonosor, construiu o tabernáculo, reinou em Damasco'),('AT07-L18-Q03','Virtudes: fé, arrependimento. Pecados: adultério, homicídio de Urias.','Virtudes: jejum, peregrinação a Canaã. Pecados: idolátria, blasfêmia.','Decisões: construção do templo, travessia do mar Vermelho.','Virtudes: humildade, dom de profecia. Pecados: roubar, mentir abertamente.'),('AT07-L19-Q01','2 Samuel, capítulo 7','2 Samuel, capítulo 11','2 Samuel, capítulo 23','2 Samuel, capítulo 5'),('AT07-L18-Q02','Davi consolidou a monarquia e conectou juizes, profetas e reis na historia de Israel','Davi foi o primeiro rei de Israel, iniciando a monarquia no lugar dos juizes','Davi foi o maior dos profetas e seus Salmos marcaram o fim da profecia biblica','Como judge, Davi governou Israel antes de se tornar rei dos judaus'),('AT07-L18-Q04','Pela uncao que Samuel fez por ordem de Deus','Por meio de guerras e batalhas que venceu sozinho','Atraves de sonhos e visoes que recebeu diariamente','Mediante a forca de seu exercito e Estrategias politicas'),('AT07-L19-Q02','Desejou a mulher de Urias, Bate-Seba','Desejou construir uma casa para Deus','Desejou matar o filho de Bersabé','Desejou realizar grandes guerras'),('AT07-L19-Q05','Porque a promessa do trono eterno a Davi apontava para o Messias, o Rei eterno.','Porque Salomão reinou por mais tempo que qualquer outro rei de Israel.','Porque o templo de Salomão representava a presença eterna de Deus.','Porque os profetas nomearam outro rei humano após a morte de Davi.'),('AT07-L19-Q03','Fazer seu nome grande, estabelecer sua casa e seu trono eternamente','Conceder-lhe toda a terra de Canaã e vastas propriedades','Livrá-lo de todos os inimigos e dar-lhe vitórias militares','Abençoar toda a sua posteridade com saúde e longa vida'),('AT07-L19-Q04','Deus prometeu a Davi que seu filho Salomão construiria o templo.','Deus prometeu a Abraão que por meio de Salomão todas as nações seriam abençoadas.','Salomão recebeu a promessa de construir o templo sem relação com Davi.','A promessa inicial a Salomão foi de prosperidade sem mencionar o templo.'),('AT07-L19-Q07','Jesus e apresentado como descendente de Davi por genealogia e por ser chamado filho de Davi.','Jesus e chamado filho de Abraao para enfatizar sua origem patriarcal hebraica.','O Novo Testamento nega a linhagem davidica de Jesus para universalizar sua mensagem.','Jesus e apresentado como filho de Davi apenas nas epístolas de Paulo, não nos evangelhos.'),('AT07-L20-Q01','Adultério, homicídio e roubo da esposa de Urias','Adultério e ingratidão pelo bem que Deus lhe concedera','Simples adultério, pois Urias morreu legitimamente em guerra','Adultério e blasfêmia contra o nome do Senhor'),('AT07-L19-Q06','Pela promessa do concerto davídico e profecias de um rei eterno de Davi.','Pela incorporação de elementos messiânicos das culturas egípcias e mesopotâmicas.','Através de uma mudança gradual da esperança de um rei político para um líder espiritual.','Pela rejeição da monarquia e adoção de modelos de liderança comunitária por anciãos.'),('AT07-L20-Q05','NAO SEI','Falta contexto biblico especifico para a pergunta.','Indique capitulo e livro biblico para a resposta.','A pergunta requer referencia textual mais precisa.'),('AT07-L20-Q04','Reconheceu seu pecado e disse: Pequei contra o Senhor.','Ficou irado e mandou matar o profeta Natã.','Negou o pecado e expulsou o profeta de Judá.','Fugiu para as montanhas e escondeu-se de Natã.'),('AT07-L20-Q07','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT07-L20-Q03','A parábola da ovelhinha','A parábola de Uriá e Betsabá','A parábola do altar no terraço','A parábola da arca roubada'),('AT07-L20-Q02','Davi enviou Urias à guerra hoping que ele fosse morto.','Davi destruiu todas as cartas e provas do caso com Bate-Seba.','Davi confessou publicamente seu pecado diante de todo o Israel.','Davi fugiu de Jerusalém e se escondeu no deserto.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT07-L11-Q01','Para serem como as demais nacoes, desejando um rei que os julgasse e os liderasse em guerra.','Porque Samuel ja nao tinha mais autoridade para julgar o povo de Israel.','Porque Deus instruiu os ancianos a escolherem um rei para governar Israel.','Porque os profetas de Israel haviam previsto que um rei deveria surgir.'),('AT07-L13-Q01','Sacrificar apenas parte dos amalequitas, desobedecendo a Deus','Consultar a medianeira de En-Dor e abandonar a lei mosaica','Oferecer sacrifício sem a-mediação do sacerdote em Silo','Rejeitar o reino de Judá e separar-se de Davi prematuramente'),('AT07-L18-Q06','Deus prometeu a Davi um trono eterno, fundando a esperança messiânica.','Davi estabeleceu a esperança messiânica por meio de suas vitórias militares contra os inimigos de Israel.','Davi criou a esperança messiânica ao compor os Salmos que prediziam a vinda do Salvador.','Davi garante a esperança messiânica ao construir o Templo onde o Cristo habitaria entre o povo.'),('AT07-L18-Q05','Guerra, rebelião de Absalão e pragas sobre Israel','Paz eterna, prosperidade e unidade total das tribos','Perda completa do reino e exílio imediato da família','Riqueza infinita sem guerras ou conflitos familiares'),('AT07-L20-Q06','O episodio distingue perdao (culpa removida) de consequencias (sofrimento continuo), como em 2Samuel12 onde Deus perdoa David mas a criança morre e o sword nao parte de sua casa','O episodio ensina que perdao divino automatico remove todas as consequencias temporais, pois a graa de Deus basta para livrar de todo sofrimento futuro','O episodio mostra que perdão e consequencias sao identicas, ou seja, quem pecou e perdoado nao enfrenta nenhum tipo de chastimento ou disciplina','O episodio presenta que as consequencias temporais sao apenas ilusoes, pois Deus em sua onipotencia anula completamente qualquer efeito do pecado na vida'),('AT07-L21-Q01','Intercedia pelo povo junto ao rei, à porta da cidade, dizendo que este não ouvia suas causas.','Prometia isentar os impostos e dar terras a quem o seguisse.','Usava de magia e feitiços para persuadir as multidões.','Realizava milagres e curava enfermos para conquistar adeptos.'),('AT07-L21-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT07-L21-Q05','Foi atravessado por tres flexas no coracao enquanto pendia pelos cabelos num carvalho.','Morreu de causas naturais durante uma longa doenca que o consumiu.','Foi apedrejado pelo povo de Israel em Hebrom a pedradas.','Fugiu para o Egito e la morreu em paz na velhice.'),('AT07-L21-Q04','Aitofel aconselhou perseguir Davi imediatamente; Husai recomendou reunir todo Israel primeiro.','Aitofel sugeriu negociar a paz; Husai indicou fugir para outro país.','Ambos aconselharam esperar; Husai discordou sobre o local da batalha.','Aitofel ordenou atacar de noite; Husai defendeu ataque ao amanhecer.'),('AT07-L21-Q03','Absalomo se rebelou e Davi fugiu para salvar a vida.','Uma praga divina atingiu a cidade e Davi fugiu.','Houve uma grande fome em Jerusalém e Davi saiu.','Saul perseguia Davi e ele precisou fugir de novo.'),('AT07-L21-Q06','Davi levantou-se, purificou-se, adorou a Deus e comeu normalmente.','Davi se prostrou em pranto e jejuar por sete dias no templo','Davi ordenou que Bate-Seba fosse apedrejada pelo seu adultério','Davi enlouqueceu de dor e destruiu o altar do sacrificio'),('AT07-L21-Q07','Revela que o pecado abriu brecha para a rebeliao e a destruicao do reino','Mostra que Deus protege sempre os seus servos fielmente ate o fim','Demonstra que o reino de Davi era invencivel e eternal por causa da alianca','Prova que a obediencia de Davi foi recompensada com forca e vitoria total'),('AT07-L22-Q05','Peste que matou setenta mil pessoas em Israel','Guerra civil entre Judá e as demais tribos','Exílio do rei e destruição do templo','Fome por três anos consecutivos na terra'),('AT07-L22-Q01','Rebeliao de Absalao,Adonias e coroacao de Salomao','Guerra contra os filisteus e captura da arca','Salomao constroi o templo em Jerusalem','Elias e Eliseu confrontam os prophets de Baal'),('AT07-L22-Q03','O levantamento do census de Israel como pecado','A construcao do templo em Jerusalem por si mesmo','O recebimento de Joab como propheta de Deus','A ordenacao divina para fazer o recenseamento'),('AT07-L22-Q04','Pela sua soberania, movendo os corações e dispondo os fatos conforme seu plano.','Através de anjos mensageiros que supervisionavam todos os negócios de Davi.','Pela prophetia direta de Natã em cada decisão importante de Davi.','Por meio de sonhos e visões noturnas que Deus enviava continuamente a Davi.'),('AT08-L01-Q02','Reino de Israel, período da Monarquia Unida, por volta de 970-931 a.C.','Reino de Judá, período do Exílio Babilônico, por volta de 586-538 a.C.','Reino de Israel, período dos Juízes, por volta de 1079-1048 a.C.','Reino da Judeia, período helenístico, por volta de 332-63 a.C.'),('AT08-L01-Q01','Davi, seu pai que o ungiu como rei','Faraó do Egito que liberou os israelitas','Elias e Eliseu, grandes profetas de Israel','Ciro da Pérsia, que permitiu a reconstrução'),('AT08-L02-Q02','Reino de Israel, período da Monarquia Unida, século X a.C.','Reino de Judá, período do exílio babilônico, século VI a.C.','Império Romano, período helenístico, século II a.C.','Reino de Israel, período da Monarquia Dividida, século IX a.C.'),('AT08-L01-Q04','Salomão começou fiel, mas seu coração se dividiu ao seguir mulheres estrangeiras.','Todos os envolvidos foram abençoados por Salomão pedir sabedoria a Deus.','Davi foi condenado por não ter preparado adequadamente o filho para reinar.','As esposas estrangeiras foram aceitas como profetas do Senhor em Israel.'),('AT08-L01-Q03','Salomão edificou o templo do Senhor, recebeu sabedoria por aliança e caiu em idolatria.','Salomão dedicou toda sua vida à destruição de ídolos e rejeitou qualquer aliança com Deus.','A profecia foi o único papel de Salomão, pois ele nunca construiu o templo nem recebeu aliança.','Salomão recebeu sua sabedoria por meios ocultos e construiu um templo dedicado a ídolos.'),('AT08-L01-Q05','Construção do Templo em Jerusalém, centralização do culto e divisão do reino após sua morte.','Fim da monarquia israelita e exílio imediato do povo para o Egito.','Conversão de todas as nações vizinhas ao culto javista e уничтожение da idolatria.','Destruição do Tabernáculo e proibição total de qualquer forma de adoração.'),('AT08-L02-Q04','Deus aprova os que buscam a sabedoria com coração reto e temor do Senhor','O texto condena todos que buscam sabedoria humana sem discernimento','A sabedoria de Salomão é rejeitada por priorizar o conhecimento sobre a fé','Somente os escribas e levitas eram dignos de receber tal sabedoria'),('AT08-L01-Q06','Seus pecados justificaram o exílio, mas sua sabedoria e o templo prometeram restauração.','Salomão impediu o exílio ao construir o templo e organizar adoração perfeita.','Salomão causou o exílio por ter destruído o templo que seu pai Davi ergueu.','Salomão foi exilado por escolher a riqueza em vez da sabedoria de Deus.'),('AT08-L02-Q01','A Rainha de Sabá testou a sabedoria de Salomão','Rei Davi consultou Salomão sobre questões de guerra','O profeta Elias desafiou a sabedoria do rei Salomão','Sansão tentou superar Salomão em provérbios e riddles'),('AT08-L02-Q03','Critica a idolatria e celebra a sabedoria como presente divino em Israel','Estabelece novas alianca entre Deus e o povo de Israel','Descreve a construcao do templo e seus rituais detalhados','Revela profecias messianicas sobre o Salvador que viria'),('AT08-L02-Q06','A sabedoria justifica o exílio como castigo pelo pecado e ensina que a restauração depende da obediência a Deus.','A sabedoria salomônica foi a causa direta do exílio por suas práticas idolátricas nos últimos anos.','Salomão explicou que o exílio era um fenômeno meramente político, sem relação com a vontade divina.','A esperança de restauração na sabedoria de Salomão dependia exclusivamente do poder militar de Israel.'),('AT08-L03-Q03','NAO SEI','Pedra talhada e servos israelitas do Egito','Madeira de cedro e artesãos fenicios especializados','Ouro purissimo e levitas ordenada por Deus'),('AT08-L03-Q04','Santo, Santo dos Santos e Pórtico.','Câmara externa, câmara interna e átrio.','Santuário, altar maior e corredor sagrado.','Cela menor, cela maior e casa de Deus.'),('AT08-L03-Q02','Porque era homem de guerra e derramou sangue, e Deus escolheu Salomão.','Porque não tinha recursos financeiros suficientes para a obra.','Porque Deus preferia que outro rei construísse para testar a fé de Davi.','Porque Salomão era mais velho e experiente que Davi na construção.'),('AT08-L02-Q05','Construção do templo em Jerusalém, unificação do reino e prosperidade de Israel','Fim do cativeiro egípcio e libertação imediata de todo o povo','Conversão universal de todas as nações ao Deus de Israel','Restauração do reino dividido sob o comando de um só rei'),('AT08-L03-Q01','Salomão, filho de Davi.','Davi, por vontade divina.','O sumo sacerdote Zadoque.','Os profetas Elias e Eliseu.'),('AT08-L04-Q03','A glória desceu dos céus e encheu o templo, impedindo os sacerdotes de entrar','A glória subiu do altar em forma de luz brilhante que envolveu o templo inteiro','Nuvens de gloria entraram pelos quatro cantos do templo ate enche-lo por completo','A glória manifestationou-se como pilares de fogo ao redor do altar sagrado'),('AT08-L03-Q06','O templo foi construído por Salomão como cumprimento das promessas da aliança davídica.','O templo anulou a aliança davídica, estabelecendo um novo pacto eterno.','A construção do templo antecedeu a aliança davídica em duas gerações.','O templo não tinha relação alguma com as promessas feitas a Davi e sua linhagem.'),('AT08-L03-Q07','Porque Deus é onipresente e transcende qualquer espaço físico','Porque o templo era o único lugar onde Deus consentia em habitar','Porque os profetas ensinaram que Deus ficava preso ao templo','Porque a presença divina no templo era temporária e revocável'),('AT08-L04-Q01','Trasladação da arca, glória do Senhor e fogo do céu','A consagração dos dois pilares Jachin e Boaz','A unção do sumo sacerdote Zadoque com óleo','A instalação das duas colunas de bronze no pórtico'),('AT08-L04-Q02','Símbolo da presença divina e morada de Deus entre os israelitas.','Guardava as túnericas sagradas usadas pelo sumo sacerdote.','Era sacrificada anualmente como parte do ritual de expiação.','Transportava o incenso aromatico nas procissões do templo.'),('AT08-L04-Q05','Confissão e arrependimento restauram a comunhão mediante a fé','O perdão é concedido automaticamente sem necessidade de confissão','As obras humanas são suficientes para restaurar a comunhão com Deus','Rituais externos substituem a necessidade de arrependimento sincero'),('AT08-L03-Q05','A Arca da Alianca, o candelabro, a mesa e o altar de incenso.','Os querubins de ouro e as colunas Jachin e Boaz do santuario.','O molho de mana e a vara de Aarao conservados no templo.','O veludo sagrado e as cortinas exteriores do tabernaculo.'),('AT08-L04-Q04','Fidelidade divina, perdão de pecados e a casa de oração','Construção do templo e ostentação da riqueza de Salomão','Guerras de conquista e expansão do reino de Israel','Instituição de novos sacrifícios e rituais levíticos'),('AT08-L04-Q07','Caminhar em obediência, ou o templo seria destruído e Israel disperso','Que o templo seria transferido para outro lugar sagrado','Que os sacerdotes deveriam jejuar continuamente no templo','Que os sacrifícios deveriam aumentar em quantidade anualmente'),('AT08-L04-Q06','Voltam-se para o templo e são atendidos por Deus','São excluídos da presença divina no templo','Recebem a aliança completa de Deus com Israel','Têm os mesmos direitos que o povo de Israel no templo'),('AT08-L05-Q01','As esposas estrangeiras, a rainha de Sheba e Hiram de Tiro','Moisés, o faraó do Egito e as pragas do deserto','Davi, Absalão e o levita que serviu em Silo','Elias, Acabe e Jezabel no monte Carmelo'),('AT08-L05-Q02','Reino de Israel Unificado, século X a.C.','Reino do Norte (Israel), séculos IX-VIII a.C.','Reino de Judá durante o cativeiro babilônico','Reino de Judá no período da monarquia divididos'),('AT08-L05-Q04','O texto avalia que Salomão fez o mal perante o Senhor, e seus parceiros na apostasia foram igualmente condenados por sua idolatria.','O texto abençoa todos os envolvidos com prosperidade material como recompensa por suas alianças políticas.','O texto condena apenas as esposas estrangeiras, absolvendo Salomão de toda culpa espiritual.','A riqueza acumulada foi interpretada como sinal de aprovação divina, mesmo durante a apostasia.'),('AT08-L05-Q06','A apostasia de salomão motivou o juicio divino que levou ao exílio, mas a aliança davídica preservou a esperança de restauração.','A riqueza de salomão permitiu que israel vivesse em paz perpetua sem precisar do exílio como castigo divino.','O exílio foi causado exclusivamente pelas guerras externas e não teve relação com a apostasia de salomão.','Salomão construiu o templo em jerusalém e isso automaticamente evitou que qualquer exílio ocorresse.'),('AT08-L06-Q02','Aliviar a dura servidão imposta por Salomão','Reduzir os impostos para construção do templo','Permitir que adorassem outros deuses','Nomear novos sacerdotes do templo'),('AT08-L06-Q03','Porque seguiu o conselho dos jovens que cresceram com ele, que lhe disseram para responder ao povo com palavras mais severas','Porque os anciãos haviam se aliado com Jeroboão e ele desconfiava das suas intenções','Porque ele queria estabelecer um novo sistema religioso no reino de Judá','Porque Deus lhe revelou em sonho que o povo merecia ser punido com rigor'),('AT08-L05-Q05','Deus rasgou o reino e o entregou a Jeroboão; surgiram adversários contra Israel.','Salomão tornou-se rei absoluto e fundou a nova aliança com Deus.','Israel alcançou paz eterna e prosperidade espiritual duradoura.','A prosperidade econômica trouxe bênçãos militares permanentes a Israel.'),('AT08-L05-Q03','Aaliança matrimonial c/ Egito Levou-o à idolatria, profecia de Aías denunciou sua apostasia, e o templo foi profanado por seus ídolos.','A aliança com Tiro construiu o templo, garantindo-lhe prosperidade e impedindo toda apostasia espiritual.','A profecia de Natã confirmou a riqueza de Salomão, e a idolatria foi apenas um símbolo de sua sabedoria.','O templo centralizou toda adoração, eliminando automaticamente qualquer risco de apostasia ou infidelidade.'),('AT08-L06-Q04','Jeroboão','Davi','Salomão','Abraão'),('AT08-L06-Q05','Judá e Benjamim','As dez tribos do norte','Judá, Benjamim e Efraim','As doze tribos de Israel'),('AT08-L06-Q01','A recusa de Roboão em reduzir os pesados impostos e o afastamento de Deus causaram a divisão.','A guerra entre Judá e as dez tribos do norte dividiu o reino permanentemente.','A invasão dos assírios forçou as tribos a se separarem para sobreviver.','A seca prolongada em Israel fez as tribos se dispersarem em busca de água.'),('AT08-L06-Q06','Quando Roboão rejeitou o pedido do povo e Jeroboão tornou-se rei das dez tribos','Quando uma invasão estrangeira conquistou metade do território de Salomão','No momento da morte de Salomão, o reino automaticamente se dividiu em dois','Quando os profetas anunciaram que o reino seria dividido por causa da luxúria de Roboão'),('AT08-L07-Q01','Reino dividido, bezerros de ouro, profeta Acaías, fim da dinastia por Baasa','Cativeiro babilônico, livros de Esdras e Neemias, reconstrução do templo','Reino unido restaurado, profetas Isaías e Jeremias, exílio no Egito','Guerras contra a Assíria, aliança com a Babilônia, queda de Nínive'),('AT08-L07-Q02','Reino de Israel, no período da monarquia dividida, após 931 a.C.','Reino de Judá, no período do exílio na Babilônia, após 586 a.C.','Egito, no período da dominação egípcia sobre Canaã, por volta de 1550 a.C.','Reino de Israel, no período pré-monárquico, por volta de 1050 a.C.'),('AT08-L07-Q06','Jeroboão estabeleceu bezerros de ouro, causando apostasia que levou ao exílio do reino do norte.','Jeroboão construiu o templo de Jerusalém e preservou a verdadeira adoração no norte.','O exílio do norte ocorreu por invasões estrangeiras sem relação com a infidelidade religiosa.','Jeroboão profetizou a restauração messiânica e unitária de todas as tribos de Israel.'),('AT08-L08-Q02','Reino de Judá, século X antes de Cristo','Reino de Israel, século VIII antes de Cristo','Reino de Judá, século VI antes de Cristo','Reino de Israel, século X antes de Cristo'),('AT08-L07-Q05','Divisão do reino e idolatria com bezerros em Dã e Betel, condenada pelos profetas','Aliança permanente com Judá que trouxe prosperidade comercial ao reino do norte','Construção do Templo de Dã como centro religioso legítimo de adoração','Conversão de todo o povo ao monoteísmo estrito após a divisão política'),('AT08-L08-Q01','Jeroboão, Sisaque e a divisão do reino','Acabe, Jezabel e o culto a Baal','Omri, Acabe e a dinastia de Samaria','Elias, Eliseu e o reino do norte'),('AT08-L07-Q04','O texto os condena por fazerem o que era mau diante do Senhor','O texto os aprova por manterem a verdadeira adoracao ao Senhor em Betel e Da','O texto os elogia como reis fielmente escolhidos por Deus para governar Israel','O texto os considera modelos de fidelidade por resistirem ao reino de Juda'),('AT08-L08-Q04','Feito o mau perante o Senhor; abominações no reino','Mantiveram a aliança e serviram ao Senhor com fidelidade','O reino do sul foi abençoado por sua obediência total','Juízo favorável aos que buscaram ao Senhor em Judá'),('AT08-L09-Q02','Reino de Israel e Judá, período monárquico.','Império Babilônico, período neobabilônico.','Reino egípcio, período das dinastias faraônicas.','Império Assírio, período imperial mesopotâmico.'),('AT08-L08-Q05','Divisão do reino em Judá e Israel com rompimento religioso entre ambos.','Roboão unificou todas as tribos sob seu comando e estabeleceu um único reino.','O reino do sul tornou-se automaticamente um império religioso mundial.','Roboão reinstaurou a adoração idólatra em Judá e eliminou os profetas.'),('AT08-L09-Q01','Saul,Davi,Salomao,Jeroboao,Elias,Acabe,Josias','Abraao,Isaque,Jaco,Moises,Aarao,Davi,Salomao','Sansao,Dalila,Golia,Saul,Davi,Salomao,Elias','Nabucodonosor,Ciro,Dario,Artajerjes,Neemias,Esdras'),('AT08-L08-Q06','Judá conservou a linhagem davídica e as promessas de restauração após o exílio babilônico.','Judá foi destruído sem esperança de restauração messiânica.','Roboão fundou a assembléia que preparou o retorno do exílio.','O reino do sul pereceu sem preservar as promessas davídicas.'),('AT08-L09-Q04','Pela fidelidade à aliança e obediência aos mandamentos','Pelo tamanho do reino e pela prosperidade econômica','Pela duração do governo e victories militares obtidas','Pelo número de descendentes e alliances firmadas'),('AT08-L08-Q03','Profetas como semaías orientaram roboão a aceitar a divisão do reino','A idolatria foi completamente eliminada por roboão ao assumir o trono','O templo de siló tornou-se o centro religioso do reino do sul','A aliança mosaica foi substituída pela nova aliança em judá'),('AT08-L09-Q03','Fundaram, sustentaram ou ameaçaram a legitimidade religiosa e política dos reis.','Eram fatores exclusivamente militares que decidiam as conquistas territoriais.','Funcionavam de forma separada e não interferiam nas decisões dinásticas.','Representavam apenas costumes culturais locais sem importância espiritual.'),('AT08-L10-Q01','Acabe e Acazias','Davi e Salomão','Jeroboão e Roboão','Ezequias e Manassés'),('AT08-L09-Q05','Monarquia estabelecida, divisão do reino, centralização do culto em Jerusalém e profetismo.','Dissolução total de Israel sem sucessão dinástica, resultando em teocracia pura.','Adoção do politeísmo como consequência direta das dinastias reais de Israel.','Transferência do centro religioso para Samaria após o estabelecimento das dinastias.'),('AT08-L10-Q02','Como juizo de Deus contra a idolatria de Israel','Para testar a obediencia do rei Acabe','Porque os impostos de Acabe eram excessivos','Por causa de uma profecia de Samuel'),('AT08-L10-Q03','Por corvos e pela farinha e azeite multiplicados.','Deus fez chover maná do céu durante toda a seca.','Um anjo trazia pão e água diretamente do céu.','A rocha fez brotar água e pão todos os dias.'),('AT08-L10-Q05','Fugiu para o deserto e pediu a Deus que tirasse a sua vida','Enfrentou Jezabel com coragem e a desafiou publicamente','Orou pedindo forças para combatê-la no Carmelo','Mandou descer fogo do céu sobre o palácio real'),('AT08-L10-Q04','Elias desafiou os profetas de Baal, e Deus enviou fogo do céu consumindo o sacrifício.','Os profetas de Baal se converteram e passaram a adorar o Senhor junto ao povo.','Moisés apareceu no monte Carmelo para mediar o conflito entre Elias e Acabe.','O monte Carmelo foi destruído por fogo divino e nunca mais pode ser habitado.'),('AT08-L10-Q06','Voz de um sussurro suave','Voz de um grande trovão','Fogo que desceu do céu','Chama que consumiu o altar'),('AT08-L10-Q07','Elias disse: Tu mataste e também tomaste a herança','Elias abençoou Acabe e confirmou a propriedade da vinha','Elias orou para que fogo do céu consumisse a vinha','Elias profetizou que a vinha seria dividida entre os filhos'),('AT08-L10-Q08','Foi arrebatado num carro de fogo ao céu','Morreu de causas naturais em samaria','Foi martirizado pelo rei acabe','foi sepultado na caverna do carmel'),('AT08-L11-Q04','Multiplicou azeite para viúva, curou Naamã sírio e orientou comunidades proféticas.','Multiplicou água em azeite para viúva, fechou céus com oração e multiplicou pães aos famintos.','Curou a sogra de Pedro, converteu o centurião romano e batizou converts em nome de Jesus.','Partiu as águas do Jordão, levantó filho da sunamita e feedou a mumia que tocou seus ossos.'),('AT08-L11-Q05','Naamã se lavou sete vezes no rio Jordão e foi curado da lepra','Foi ungido com óleo sagrado pelo profeta Eliseu','Tocou nos ossos do profeta Eliseu e foi sanado','Jejuou e orou durante quarenta dias no templo'),('AT08-L11-Q01','Elias foi arrebatado num carro de fogo, e Eliseu arava com doze juntas de bois quando foi chamado.','Deus falou diretamente a Eliseu numa visão noturna ordenando sua missão profética.','Elias tocou Eliseu com sua capa enquanto profetizava no monte Carmelo.','O rei Acabe ordenou que Eliseu fosse sagrado profeta no templo de Jerusalém.'),('AT08-L11-Q06','Eliseu profetizou a reis de Israel, ungindo Jeú e confrontando a casa de Acabe.','Eliseu foi rei de Israel e estabeleceu uma dinastia profética no trono.','Eliseu viveu no tempo de Salomão e serviu como conselheiro da corte.','Eliseu confrontou apenas os reis de Judá e nunca os de Israel.'),('AT08-L12-Q02','Reino do Norte de Israel, seculo IX a.C.','Reino de Judá, durante o seculo VIII a.C.','Império Assírio, no seculo VII a.C.','Reino de Babilônia, durante o cativeiro.'),('AT08-L11-Q07','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT08-L12-Q04','Ambos condenados por sua maldade e idolatria contra Deus','Ambos foram abençoados por sua fé e devoção ao Senhor','Ambos foram usados por Deus para pregar a verdade','Ambos foram aceitos como justos perante o Senhor'),('AT08-L12-Q06','Sua apostasia explica o exílio e a esperança de restauração mediante o testemunho profético preservado','Sua fidelidade ao Senhor serviu de modelo para as gerações futuras da história de Israel','Sua conversão sincera evitou o juízo divino sobre o reino do norte de Israel','Seus tratados de paz com as nações vizinhas garantiram a prosperidade económica de Judá'),('AT08-L12-Q03','Ahab e Jezabel promoveram a idolatria baálica, quebrando a aliança com Javé.','Ahab e Jezabel mantiveram a aliança com Javé, construindo o templo de Jerusalém.','Ahab e Jezabel foram profetas que предупредили Israel contra a idolatria.','Jezabel respeitou o templo de Javé e rejeitou completamente o culto baálico.'),('AT08-L12-Q01','Elias, o tisbita, que confrontou ambos','Jeú, que reinou sobre Judá após Acazias','Roboão, filho de Salomão e pai de Abias','Jeroboão, primeiro rei das dez tribos'),('AT08-L12-Q05','A idolatria se espalhou e a casa de Acabe foi destruida por Jeú','Israém atingiu seu apogeu politico e religioso sob o governo de Acabe','O povo de Israel aceitou Jezabel como profetisa do Senhor','A aliança com Jezabel trouxe bênçãos permanentes ao reino'),('AT08-L13-Q03','Reformaram o culto, removeram ídolos, restauraram o templo e ouviram a profecia','Ignoraram a profecia e confiaram apenas na força militar para proteger Judá','Mantiveram altares pagãos junto ao templo para garantir alianças políticas','Destruíram o templo e adotaram práticas religiosas estrangeiras em Judá'),('AT08-L13-Q04','Sao abençoados e aprovados por Deus','Recebem castigo divino por participar','Sao mencionados sem qualquer comentario','Perdem sua herança espiritual em Israel'),('AT08-L13-Q01','Davi, Josias, Ezequias, Asa e Josafate, fieis a Deus, com suas reformas e aliancas','Jeroboao, Acabe e os reis idolatras do reino do norte de Israel','O farao do Egypto, Nabucodonosor e Ciro, imperadores estrangeiros','Jefté, Gideão e os juizes fieis antes do estabelecimento dos reis'),('AT08-L13-Q05','Revival espiritual, prosperidade e victorias militares para Juda.','Destruicao do templo e abandono total das leis mosaicas por toda a nacao.','Exilio imediato do povo e dissolucao completa do reino de Juda.','Fortalecimento dos cultos pagãos e alianças militares com nacoes idolatras.'),('AT08-L13-Q06','Eles mostravam que a obediência trazia bênção e mantinham viva a esperança de restauração.','Eles conseguiram evitar completamente o exílio babilônico por meio de suas reformas.','Os reis fieis profetizavam diretamente o fim do exílio e a data da volta.','Eles transferiram a culpa do pecado para os reis pecadores do Israel do norte.'),('AT08-L14-Q02','Reino de Judá, após o cisma, séculos X a VI a.C.','Reino de Israel, durante o período da monarquia unificada, séculos XI a X a.C.','Reino do norte, após a divisão do reino em 722 a.C.','No Reino de Judá, período do cativeiro babilônico, séculos VI a V a.C.'),('AT08-L14-Q01','Reis de Judá que abandonaram os mandamentos de Deus','Reis de Judá que guardaram fielmente a Lei do Senhor','Profetas que exortavam o povo à adoração de ídolos','Sacerdotes que queimavam incenso nos altos de Judá'),('AT08-L13-Q02','Reino de Judá, período da monarquia dividida','Reino de Israel, durante a monarquia unida','Reino de Judá, no período do cativeiro egípcio','Reino do norte, sob domínio assírio'),('AT07-L22-Q02','Os últimos anos de Davi consolidam a monarquia sob orientação profética de Natã.','Davi encerra o período dos juízes e introduz uma nova era de profetas como guias.','Os últimos anos de Davi representam o fim da monarquia e retorno aos juízes.','Davi foi simultaneamente o último juiz e o primeiro rei segundo a Escritura.'),('AT07-L22-Q06','Davi confirmou a aliança messiânica, garantindo um successors eterno do seu trono.','Davi construiu o Templo em seus últimos anos, assegurando a presença messiânica.','Davi dividiu o reino em seus últimos anos, enfraquecendo a linhagem messiânica.','Nos últimos anos, Davi abandonou a aliança, reduzindo a esperança messiânica.'),('AT08-L06-Q07','NAO SEI','Expansao das praticas de cultos pagos','Fim da pratica religiosa em todo o territorio','Convertimento universal a idolatria')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT08-L07-Q03','Jeroboão fez dois bezerros de ouro em Betel e Dã, estabelecendo culto idólatra.','Jeroboão construiu o primeiro templo de Jerusalém para consolidar o culto ao Senhor.','Jeroboão foi fiel à aliança e manteve o culto no templo de Jerusalém.','A profecia confirmou a aliança de Jeroboão com o Egito contra Judá.'),('AT08-L09-Q06','A queda dinástica cumpriu ameaças proféticas e manteve esperança messiânica.','As dinastias foram eliminadas permanentemente para que Israel se tornasse uma teocracia sem reis.','O exílio foi um simples deslocamento geopolítico sem qualquer significado espiritual.','A esperança surgiu apenas pós-exílio, sem vínculo com promessas anteriores aos patriarcas.'),('AT08-L11-Q02','Pediu que o seu espírito ficasse em si em porção dobrada','Pediu que Elias ficasse com ele até ao fim','Pediu para ser feito profeta em seu lugar','Pediu que Deus o protegesse dos seus inimigos'),('AT08-L11-Q03','Multiplicação do azeite, ressurreição do filho da sunamita e cura da lepra de Naamã','Multiplicação dos pães e peixes, caminhar sobre as águas e transfiguração no monte','Abertura do mar Vermelho, transformação da vara em serpente e conversão da água em vinho','Ressurreição de Lázaro, cura do cego de nascença e perdão dos pecados pelo batismo'),('AT08-L14-Q06','A infidelidade dos reis levou ao exílio como juízo divino, mas prophets prometeram restauração futura.','Os reis infiéis foram poupados do exílio por sua sabedoria diplomática.','O exílio foi causado exclusivamente por invasões estrangeiras, não pelos reis.','A esperança de restauração surgiu apenas da obediência dos últimos reis de Judá.'),('AT08-L14-Q03','Infidelidade à aliança, abandono do templo, idolatria e rejeição à profecia.','Obediência à aliança, culto no templo, adoração exclusiva e aceitação da profecia.','A aliança confirmada, o templo engrandecido, idolatria extinta e profecia seguida.','Manutenção da aliança, zelo pelo templo, ausência de idolatria e escuta dos profetas.'),('AT08-L14-Q04','São condenados por fazerem o que era mal perante o Senhor','São absolvidos por buscarem sabedoria nos reinos vecinos','São considerados justos por manterem os rituais externos apenas','São louvados por promoverem a tolerância religiosa entre povos'),('AT08-L14-Q05','Cativeiro em Babilônia, destruição de Jerusalém e do templo.','Prosperidade imediata e expansão territorial do reino.','Aliança permanente com o Egito e expansão comercial.','Construção de novos templos e autonomia religiosa total.'),('AT08-L15-Q01','O Império Assírio conquistou Samaria em 722 a.C.','O Império Babilônico destruiu Samaria e o Reino do Norte.','O Império Egípcio derrotou Samaria e o Reino do Norte.','O Império Persa conquistou Samaria e o Reino do Norte.'),('AT08-L15-Q05','NAO SEI','Os povos foram estabelecidos por meio de alianca com os lideres tribais da regiao','Outros povos se estabeleceram atraves de casamentos mixtos com os israelitas','Os povos foram estabelecidos na regiao por meio de conquistas militares de Moises'),('AT08-L15-Q03','Idolatria, infidelidade à aliança e os pecados de Jeroboam','Adultério, homicídio e roubo como pecados capitais','Soberba, inveja e preguiça como vícios principais','Injustiça social, opressão aos pobres e corrupçao'),('AT08-L15-Q02','Conquista assíria do Reino de Israel, em 722 a.C., sob Salmanasar V.','Guerra civil entre Israel e Judá após a morte do rei Salomão, no século X a.C.','Cerco babilônico de Jerusalém que resultou no exílio dos judeus para a Babilônia.','Invasão dos persas que destruiu a cidade após o retorno do exílio babilônico.'),('AT08-L16-Q01','Ezequias, levitas, sumos sacerdotes, Isaías, a páscoa.','Dario, ESDRAS, neemias, a páscoa.','Acabe, Jezabel, Elias, o maná.','Manassés, Amom, Josias, o mar vermelho.'),('AT08-L16-Q02','Reino de Judá, século VII a.C.','Reino de Israel, século VIII a.C.','Egito, período dos patriarcas','Babilônia, período exílico'),('AT08-L15-Q04','Foi levada cativa pela Assíria no século VIII a.C.','Foi destruída por Josué na conquista de Jericó.','Morreu na praga do primogênito no Egito.','Fugiu para o Egito durante a fome de José.'),('AT08-L15-Q07','Que Judá se arrependesse da idolatria para não sofrer o mesmo juízo divino','Que Judá se aliasse aos assírios para garantir sua sobrevivência política','Que Judá adotasse o sistema de culto idolátrico do Reino do Norte','Que Judá se separasse completamente de qualquer prática religiosa antiga'),('AT08-L15-Q06','Os israelitas abandonaram o Senhor e serviram os Baalins e Astarotes','Os profetas ordenaram que se misturassem os cultos para agradar Deus','A lei mosaica incentivava a adoção de práticas religiosas estrangeiras','A revelacao divina ordenou que se mesclassem os sacrifícios'),('AT08-L17-Q01','Senaqueribe foi rei da Assíria que invadiu Judá no tempo de Ezequias.','Senaqueribe foi rei da Babilônia que invadiu Judá durante o cativeiro.','Senaqueribe foi faraó egípcio que conquistou Judá no século VIII a.C.','Senaqueribe foi general da Pérsia que destruiu Jerusalém nos dias de Davi.'),('AT08-L16-Q05','Restauracao da adoracao pura, prosperidade politica e vitoria contra a Assíria.','Guerra civil em Judá e cisma permanente com o Reino do Norte.','Alianca militar com a Assíria e adocao dos deuses pagãos assírios.','Destruicao do templo de Jerusalém e exílio do povo para a Babilônia.'),('AT08-L16-Q03','Ezequias purificou o templo, destruiu ídolos, renovou a aliança e ouviu Isaías.','Ezequias construiu um novo templo em Samaria e firmou aliança com a Assíria.','A profecia foi usada por Ezequias para justificar guerras de conquista territorial.','Ezequias manteve os santuários nas alturas e integrou a idolatria à adoração.'),('AT08-L16-Q06','Ezequias restaurou o culto puro a Deus em Judá, mas a apostasia anterior manteve o exílio inevitável.','Ezequias negociou directamente com o rei da Assíria para evitar todo o cativeiro babilónico.','Os sacrifícios oferecidos por Ezequias anularam por completo a sentença divina contra Judá.','Ezequias ordenou a construção de um novo templo em Samaria antes do exílio.'),('AT08-L16-Q04','Elogia a fidelidade e zelo dos participantes da reforma','Critica a vaidade e orgulho dos reformadores','Condena a violência usada na remoção de ídolos','Rejeita a participação do povo nas decisões'),('AT08-L17-Q02','NAO SEI','Hezekias','Zedequias','Manasses'),('AT08-L17-Q04','Orau a Deus e enviou representantes ao profeta Isaías em busca de orientação divina.','Fechou aliança militar com o Egito para confrontar diretamente os assírios em batalha.','Entregou a cidade aos assírios, rendendo-se completamente e pagando pesados tributos.','Desceu pessoalmente ao campo inimigo para confrontar Rabsaqué com ameaças de guerra.'),('AT08-L17-Q03','Ele disse para não confiarem em Hezekias nem no Senhor, pois nenhuma divindade salvou nações do rei assírio.','Ele enviou uma carta ameaçando incinerar toda a cidade de Jerusalém com fogo do céu.','Ele ordenou que o povo saísse em paz para Babilônia, onde seriam bem tratados pelo rei assírio.','Ele ofereceu alianza de casamento com a filha do rei da Assíria em troca da rendição.'),('AT08-L17-Q05','Pregou o arrependimento a Judá e anunciou a vinda do Messias','Profetizou a destruição total do reino do Norte de Israel','Escreveu os Salmos e Os Provérbios para o templo','Fundou as escolas dos profetas nas terras de Samaria'),('AT08-L18-Q01','Oito anos','Vinte e oito anos','Doze anos','Dezesseis anos'),('AT08-L17-Q06','Pelo decreto de Ciro, rei da Pérsia, permitindo o retorno.','Por Tito e Vespasiano, que a libertaram dos romanos.','Por Alexandre Magno, que a conquistou dos persas.','Por Jesus, que a libertou com um grande milagre.'),('AT08-L18-Q02','O livro da aliança','O livro dos salmos','O livro das crónicas','O livro dos profetas'),('AT08-L18-Q03','Rasgou as suas vestes e chorou amargamente','Aceitou as palavras com alegria e as praticou de imediato','Mandou queimar o livro por considera-lo herege','Prostrou-se em adoracao e offerceu sacrifícios ao Senhor'),('AT08-L18-Q04','Que a destruição viria sobre Judá, mas Josias seria poupado.','Que o templo deveria ser reedificado e dedicado ao Senhor.','Que o Messias nasceria da linhagem real de Judá.','Que Josias deveria casar-se com uma virgem piedosa.'),('AT08-L18-Q05','Idolatrias, adivinhação, sortilégios e objetos de culto estranho','Apenas os bezerros de ouro de Betel e Dã','Somente os templos dos prophetas de Baal e Asera','Unicamente as imagens de madeira e pedra dos santuarios'),('AT08-L17-Q07','Prisma de Senaqueribe e Anais Assírios de Nínive','Crônicas de Nabopolassar e tabletes cuneiformes de Ur','Estelas de Salmaneser III e relevos de Balawat','Tabletes de Ebla e textos de Ras Shamra'),('AT08-L19-Q01','O império babilônico','O império assírio','O império romano','O império medo-persa'),('AT08-L18-Q06','Josias restaurou a celebração da Páscoa em Jerusalem com grande solemnidade','Ezequias celebrou a Páscoa por sete dias com grande festividade em Jerusalem','Esdras restaurou a Páscoa quando retornou do cativeiro na Babilônia','Salomão celebrou a Páscoa durante a dedicação solene do templo'),('AT08-L19-Q03','Primeira em 605, segunda em 597','Tres deportacoes apos a queda de Jerusalem','Deportacoes de Israel ao Imperio Assirio','Apenas uma deportacao, sem etapas'),('AT08-L19-Q02','Zedequias, ultimo rei de Judá durante o cerco babilônico','Joaquim, rei que foi deportado para a Babilônia antes do cerco','Jeoaquaz, rei que subiu ao trono apos Josias e foi depososto','Joás, rei que reinou em Judá durante o ataque siro-israelita'),('AT08-L18-Q07','O julgamento ja estava decretado e a corrupcao era profunda demais','A reforma de Josias foi superficial e nao atingiu o povo','Deus mudou de ideia sobre o castigo planejado','Os profetas falsearam as previsoes de juizo'),('AT08-L19-Q06','Os mais pobres da terra, os vinhateiros e os lavradores','Os sacerdotes e os levitas que ficaram guardando o templo','Os príncipes e os oficiais do rei Zedequias','Os profetas e os escribas que restaram em Judá'),('AT08-L19-Q05','Rejeição dos profetas e idolatria (Jr 25,1-7)','Infidelidade conjugal e injustiça social (Os 4,1-2)','Orgulho e confiaca em alianças humanas (Ez 16,49)','Abandono da lei e profanação do sábado (Ne 13,17-18)'),('AT08-L20-Q04','Deus avalia reis conforme fidelidade ao Criador.','Ricos sao abençoados por proposito de reis.','Reis tem poder absoluto sobre nacoes.','Sabedoria humana garante sucesso a reis.'),('AT08-L20-Q02','No reinado dos reis da terra, nos últimos dias.','No Egito, sob o domínio dos faraós.','No período dos juízes e profetas de Israel.','Na Roma antiga, sob o domínio imperial.'),('AT08-L19-Q04','Foram destruidos e levados cativos por Nabucodonosor.','Foram restaurados miraculosamente por um anjo do Senhor.','Sobreviveram intocados ate a primeira vinda de Cristo.','Foram demolidos pelos romanos durante a primeira cruzada.'),('AT08-L20-Q06','Deus usa reis para cumprir Seus propósitos soberanos de juízo e restauração','Réis determinam livremente o destino da nação conforme sua vontade pessoal','O exílio aconteceu porque os reis abandonaram os rituais mágicos sagrados','A esperança de restauração dependia exclusivamente da força militar dos reis'),('AT08-L19-Q07','Queda de Jerusalem levou ao cativeiro babilonico e esperança de restauração.','A queda fortaleceu Judá contra invasões de povos vizinhos posteriores.','O cativeiro converteu imediatamente todos os judeus à verdadeira fé.','Jerusalém foi destruída pelos assírios, não pelos babilônios.'),('AT08-L20-Q01','Saul, Davi, Salomão, e o Profeta Natã.','Abraão, Isaque, Jacó e José, patriarcas.','Moisés, Arão, Josué e os juizes de Israel.','Elias, Eliseu, Jeremias e Ezequiel profetas.'),('AT08-L20-Q05','Submissão às autoridades e julgamento divino aos que resistem','Revolta contra toda ordem política e libertação imediata','Autonomia absoluta dos reis sem qualquer responsabilidade','Abandono total de toda estrutura religiosa e civil'),('AT08-L21-Q02','Reino de Judá, período pós-exílio babilônico.','Reino de Israel, período da monarquia dividida.','Período do êxodo e conquista de Canaã.','Reino de Judá, durante o reino de Davi e Salomão.'),('AT08-L21-Q04','NAO SEI','E avaliar se hanno ánimo sincero e non finto nel servizio a Deus','Seus nomes serão escritos no libro da vida por sua fidelidade','São aprovados por suas obras conforme a lei de Cristo'),('AT08-L21-Q05','Restauracao da identidade religiosa e legitimacao do culto no templo de Jerusalem','Transferencia da capital para Samaria e destruicao dos santuarios profeticos','Estabelecimento do paganismo cananeu e abandono total da lei mosaica','Abolicao do sacerdocio aaronico e implementacao do culto imperial assirio'),('AT08-L21-Q03','Enfatizar a fidelidade de Deus à aliança davídica e a importância do templo no culto.','Registrar genealogias e listas de famílias como propósito central da narrativa.','Documentar a conquista de Canaã e a divisão da terra entre as tribos.','Demonstrar que o templo era apenas símbolo simbólico sem relevância espiritual.'),('AT08-L22-Q02','Reino de Judá, período monárquico e pós-exílico','Reino de Israel, período da monarquia unificada','Império babilônico, período do cativeiro','Egito, período do êxodo e conquista de Canaã'),('AT08-L21-Q06','Explicar o exílio como castigo divino e a esperança de restauração na fidelidade à aliança davídica.','Substituir a Lei de Moisés por novas regulamentações pós-exílicas adaptadas ao contexto.','Comprovar que o exílio foi um erro político e não uma consequência da desobediência.','Registrar eventos cronológicos sem nenhuma intenção teológica ou esperança escatológica.'),('AT08-L22-Q01','Davi, reis de Judá, Abraão, Jacó, Judá, Levi e os sacerdotes.','Eliseu, Jonas, Amós, os profetas do Reino do Norte.','Ciro, Dario, Artaxerxes, os reis persas do livro de Esdras.','Sansão, Gideão, Débora, os juízes do livro de Juízes.'),('AT08-L23-Q02','Reino de Judá, período monárquico','Reino de Israel, período profético','Reino da Pérsia, período pós-exílico','Reino dividido, período dos Judges'),('AT08-L23-Q01','Davi, Salomão, Josias, Ezequias e os levitas.','Sansão, Gideão e os juízes de Israel.','Abraão, Isaque, Jacó e José.','Nabucodonosor, Dario e Ciro.'),('AT08-L22-Q06','As genealogias ligam o retorno do exílio às promessas divinas a Davi.','As genealogias servem principalmente para provar que o exílio acabou com todas as linhagens reais.','As genealogias demonstram que apenas a tribo de Judá tinha direito de retornar da Babilônia.','As genealogias foram incluídas para demonstrar a superioridade dos sumos sacerdotes sobre os reis.'),('AT08-L22-Q04','NAO SEI','SAO AVALIADOS COMO SANTOS E SEPARADOS PARA DEUS','SAO CONSIDERADOS IMPIOS E REPROVADOS PELO ESPIRITO','SAO LOUVADOS POR SUA BELEZA E RIQUEZA TERRENA'),('AT08-L23-Q05','Centralização do culto em Jerusalém e legitimidade da dinastia davídica','Fim da monarquia unificada e exílio imediato do povo','Unificação permanente das doze tribos sob o templo','Submissão total de Judá aos reinos pagãos vizinhos'),('AT08-L23-Q03','A fidelidade ao templo e seu culto evita o julgamento divino.','A profecia estabelece o templo como centro de revelacao profetica.','A alianca davidica e confirmada pela construcao do templo.','A idolatria legitima o culto praticado no templo.'),('AT08-L24-Q01',' Reis: da morte de Davi ate a queda de Judá. Crônicas: de Adao ate o decreto de Ciro.',' Reis abrange toda a historia de Israel desde Abraão ate o exílio babilônico.',' Reis cobre a vida de Jesus e a igreja primitiva. Crônicas cobre o periodo apostólico.',' Reis abrange apenas o periodo monarquico. Crônicas cobre toda a historia biblica.'),('AT08-L24-Q02','Porque foi escrito para os judios repatriados do exílio, salientando a linea davídica e o templo.','Porque Crônicas era um manual militar para os reis de Judá.','Porque o autor preferia a história política à religiosa.','Porque Davi foi o único rei justo de todo o Israel.'),('AT08-L23-Q04','Os levitas dedicados ao serviço do santuário foram considerados retos e abençoados','Todos os participantes do templo foram igualmente condenados por infidelidade','A avaliação espiritual baseava-se na riqueza material dos participantes','Somente os sacerdotes eram avaliados, os levitas não eram considerados'),('AT08-L24-Q03','Os públicos e contextos de composição explicam as diferenças de ênfase porque os autores adaptaram suas mensagens às necessidades específicas de cada audiência.','As diferenças de ênfase são causadas exclusivamente pela inspiração divina sem relação com os públicos.','Os públicos e contextos não influenciam as ênfases, que são idênticas em toda a Bíblia.','As diferenças de ênfase resultam apenas das preferências pessoais dos autores biblicos.'),('AT08-L24-Q04','NAO SEI','Porque os autores tinham fontes diferentes e independentes entre si.','Porque Deus quis que cada livro contivesse exatamente os mesmos relatos.','Porque os escribas removeram aleatoriamente trechos dos manuscritos originais.'),('AT08-L24-Q05','A infidelidade e idolatria do povo e dos reis contra a aliança com Deus.','As rivalidades politicas entre os reinos do norte e do sul.','As pragas e a fome que assolaram a terra prometida por Deus.','A invasão de povos estrangeiros movidos por ambição territorial.'),('AT08-L24-Q07','Porque Deus inspirou autores com propósitos, audiencias e perspectivas distintas.','Porque Deus ditou a Biblia palavra por palavra, exigindo narrativa identica.','Porque diferenças entre relatos prov am que as Escrituras perderam sua confiabilidade.','Porque toda interpretacao biblica deve ign orar o contexto historico e cultural.'),('AT08-L24-Q06','Ressalta a fidelidade de Deus e a reconstrução do templo em Jerusalém','Enfatiza que o exílio foi punição eterna e sem esperança de restauração','Destaca a necessidade de abandonar completamente a adoração no templo','Promete que Judá seria destruído novamente se não abandonasse a terra'),('AT09-L01-Q02','Autorizou o regresso a Jerusalém para reconstruir o templo.','Autorizou a construção de um novo templo em Babilônia.','Autorizou a libertação de todos os prisioneiros do império.','Autorizou os judeus a fundarem uma colônia na Média.'),('AT09-L01-Q01','Ciro foi o rei da Pérsia, fundador do Império Aquemênida, mencionado na Bíblia.','Ciro foi um rei da Média que conquistou a Assíria e fundou o Império Assírio.','Ciro foi o imperador da Babilônia que destruiu Jerusalém e levou os judeus ao cativeiro.','Ciro foi o fundador do Império Grego após as conquistas de Alexandre Magno.'),('AT09-L01-Q04','Os utensílios do templo de ouro e prata','As tábuas da lei e a arca da aliança','Os dois pilares de bronze e o mar de bronze','Os candelabros e a mesa dos pães propostos'),('AT09-L02-Q02','Sob Zorobabel','Sob Esdras','Sob Neemias','Sob Ciro'),('AT09-L01-Q03','Deus decretou a restauração e a cumpriu conforme suas profecias','Deus enviou profetas para anular seu decreto original de destruição','Os líderes religiosos decidiram quando e como o decreto seria cumprido','O decreto de restauração foi uma resposta aos clamor do povo babilônico'),('AT09-L01-Q05','NAO SEI','Porque Judá ainda estava sob dominio romano e tributario','Porque o decreto foi revogado pelo senado romano posteriormente','Porque os.judeus themselves rejeitaram a independencia oferecida'),('AT09-L01-Q06','Deus dá o reino a quem quer, como em Daniel 4:17','Deus apenas observa passivamente as decisões dos reis','Reyes estrangeiros têm autoridade independente de Deus','A providência divina se limita apenas ao povo de Israel'),('AT09-L02-Q01','Zorobabel, Jesua, Ageu e Zacarias no retorno do cativeiro da Babilônia','Esdras, Neemias e Ageu no retorno do cativeiro da Assíria','Daniel, Zorobabel e Mardoqueu no retorno do cativeiro da Pérsia','Ciro, Dario e Zorobabel no primeiro retorno de Judá'),('AT09-L02-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT09-L02-Q04','Reconstrução do templo sob Zorobabel e retorno da comunidade.','Reconstrução dos muros de Jerusalém sob Zorobabel.','Rejeição da Lei e adoção de práticas babilônicas.','Retorno sob liderança exclusiva de Neemias.'),('AT09-L02-Q06','Deus cumpre Suas promessas e restaura Israel reaffirmando identidade do Seu povo.','O povo deve confiar em seus próprios esforcos para garantir a restauração nacional.','A fidelidadede Deus depende das obras do povo para ser demonstrada.','O retorno exila a identidade religiosa e nacional de Israel para sempre.'),('AT09-L03-Q02','Primeiro retorno dos exilados da Babilônia','Terceiro retorno sob o governo de Neemias','Segunda fase da restauração liderada por Esdras','Exílio na Babilônia sem participação na volta'),('AT09-L03-Q01','Jesua, Ageu, Zacarias, reedificacao do templo, retorno do cativeiro','Moisés, Arão, Josué, travessia do mar Vermelho, recebimento da lei','Daniel, Ezequiel, Jeremias, queda de Jerusalém, cativeiro egípcio','Esdras, Neemias, Samuel, construção do tabernáculo, batalha de Jericó'),('AT09-L03-Q05','Deus moveu Ciro a devolver os utensílios sagrados e prover recursos para o templo.','Deus ordenou guerras Santas contra a Babilônia para recuperar os tesouros do templo.','Deus enviou maná sobrenatural para sustentar os trabalhadores da reconstrução.','Deus fez Zorobabel vender terras em Judá para financiar a obra do templo.'),('AT09-L02-Q05','Deus levantou profetas e governadores para liderar seu povo de volta.','Deus enviou anjos para materializar recursos diretamente do céu.','O povo decidiu por si mesmo quem lideraria sem intervenção divina.','Deus deixou o povo sem direção até que buscassem ajuda estrangeira.'),('AT09-L03-Q04','Zorobabel liderou a reconstrução do templo e a restauração da comunidade após o exílio.','Zorobabel construiu os muros de jerusalém sob a proteção do rei dário.','Zorobabel recebeu e promulgou a lei no monte sinai durante o êxodo.','Zorobabel enviou a comunidade ao cativeiro na babilônia como castigo divino.'),('AT09-L03-Q03','Oposição dos povos vizinhos contra a reconstrução do templo','Autorização de Ciro para reconstruir o templo em Jerusalém','Desafio do profeta Ageu para edificar a casa de Deus','Oposição de Nabucodonosor à reconstrução da cidade'),('AT09-L03-Q06','Zorobabel mostra que Deus restaura, preserva a fidelidade e a identidade do Seu povo.','Zorobabel ensina que a prosperidade material é a principal recompensa da fidelidade a Deus.','A lição de Zorobabel é que o templo físico é mais importante que a fé do povo.','Zorobabel demonstra que a sabedoria humana basta para restaurar a identidade nacional.'),('AT09-L04-Q02','Primeira fase, sob Zorobabel','Segunda fase, sob Esdras','Terceira fase, sob Neemias','Quarta fase da restauração'),('AT09-L04-Q06','A reconstrução do altar simboliza a restauração da adoração e da identidade do povo como adoradores.','A reconstrução do altar simboliza a punição divina e o castigo pelo pecado do povo.','A reconstrução do altar demonstra a necessidade de construir um templo maior e mais glorioso.','A reconstrução do altar ensina que a fé individual é mais importante que a adoração comunitária.'),('AT09-L04-Q01','Zerubbabel e Jeshua reconstruíram o altar no governo de Dario (Esdras 3:2).','Abraão e Isaque reconstruíram o altar que seus pais haviam erguido em Canaã.','Elias e Acabe reconstruíram o altar no Monte Carmelo para adorar Baal.','Josué e Calebe reconstruíram o altar quando entraram na Terra Prometida.'),('AT09-L04-Q03','Autorização de Josué para edificar o altar no monte Ebal','Desafio dos jebuseus na construção do altar em Jericó','Oposição de Faraó à reconstrução do altar no deserto','Ordem do rei Acabe para edificar altar a Baal no Carmelo'),('AT09-L05-Q01','Zorobabel','Esdras','Neemias','Ciro'),('AT09-L04-Q04','Obedeceram à lei de Moisés, os sacerdotes oficiaram e os levitas foram incumbidos de vigiar a obra.','Os profetas determinaram o local exato, os escribas supervisionaram a construção e os levitas foram dispensados.','Seguiram as tradições orais, os sumos sacerdotes presidiram e os guerreiros garantiram a segurança.','Consultaram os augúrios, os ancianos elegeram o lugar e os nazarenos guardaram o templo.'),('AT09-L05-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT09-L05-Q02','Retorno do exílio,fundação,e dedicação do templo','Construção do tabernáculo,arco,e altar','Profetas,muros,torres,e sacrifícios','Cativeiro,rebelião,cortes,e exílio'),('AT09-L05-Q06','No reign de Dario I da Pérsia','No reign de Ciro da Pérsia','No reign de Artaxerxes I','No reign de Nabucodonosor'),('AT09-L04-Q05','Deus moveu Ciro a permitir a reconstrução','Anjos desceram para reconstruir o altar','Comerciantes financiaram toda a obra','Deus enviou maná aos obreiros do altar'),('AT09-L05-Q05','Chorei em alta voz ao ver o fundamento','Fugiram para as montanhas com medo','Prostraram-se em silêncio em adoração','Rejeitaram completamente a construção'),('AT09-L05-Q04','Por meio de profecias, apelando ao povo para reconstruir a casa do Senhor.','Por meio de milagres e sinais visiveis que obrigaram o povo a obedecer.','Exigindo grandes sacrifícios financeiros antes de permitir a continuacao.','Proclamando que Deus destruiria Jerusalem se nao reconstruissem o templo.'),('AT09-L05-Q07','Restaurou o culto a Deus em Jerusalem apos o cativeiro babilonico','Permitiu que Israel adorasse a Deus no templo edificado por Salomão','Estabeleceu a adoracao ao Senhor no monte Moriá, em Samaria','Simbolizou a aliança eterna de Deus com o povo de Judá'),('AT08-L20-Q03','Regular a relação entre o rei e Deus, definindo deveres e consequências','Determinar o poder absoluto do rei sobre o povo, sem intermediação divina','Substituir a lei de Deus por tradições humanas no governo','Eliminar a necessidade de santuário e intercessores no reino')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT08-L21-Q01','Davi, Salomão, Ezequias e Josias; ênfase no templo e nos reinados de Judá.','Moisés, Arão e os profetas do norte; foco na wanderings no deserto.','Sansão, Gideão e os juízes; ênfase nas batalhas contra os filisteus.','Abraão, Isaque e Jacó; foco nas narrativas patriarcais e na terra prometida.'),('AT08-L22-Q03','Definem participação no templo e demonstram fidelidade à aliança davídica.','Determinam as datas exactas da construção do templo de Salomão.','Proibem a adoração em qualquer lugar sagrado que não seja Judá.','Regulam todas as práticas de idolatria permitidas em Israel.'),('AT08-L22-Q05','Legitimidade dinástica davídica e identidade religiosa pós-exílica','Destruição total da linhagem sacerdotal e levítica','Fragmentação territorial e perda de identidade tribal','Rejeição das promessas divinas feitas aos patriarcas'),('AT08-L23-Q06','Crônicas explica o exílio pela infidelidade e oferece esperança pela restauração do culto no templo.','Crônicas atribui o exílio a pragas e desastres naturais enviados por Deus como castigo.','Crônicas ensina que o exílio ocorreu por adorarem em altos lugares em vez do templo.','Crônicas fundamenta a esperança de restauração nos relatos das vitórias militares de Israel.'),('AT09-L06-Q01','Sanbalat, Tobias e Geshem se opuseram à reconstrução dos muros de Jerusalém.','Os profetas Ageu e Zacarias se opuseram ativamente à reconstrução do templo.','O rei Dario ordenou a interrupção completa da reconstrução do templo.','Os romanos destruíram completamente Jerusalém durante o período de Esdras.'),('AT06-L11-Q07','Da Criação ao Éden, Terra Prometida, exílio e nova criação.','Da Criação ao Sinai, da Lei à Graça e à vida eterna.','Da Criação, Dilúvio, Arca, Monte Sinai e redenção.','Do Éden ao reino messiânico e à vida eterna.'),('AT09-L06-Q03','Sanbalat, Tobias e Gesém se opuseram à reconstrução dos muros','O rei da Pérsia enviou uma ordem para paralisar a reconstrução','Os profetas Ageu e Zacarias incentivaram a停止 da obra','O sumo sacerdote interditou o templo durante a reconstrução'),('AT09-L06-Q02','Na reconstrução do templo sob Zerubbabel, quando foram lançados os fundamentos, surgiu oposição dos inimigos.','Na primeira fase sob Zorobabel os inimigos se uniram para ajudar a reconstruir o templo com alegria.','Na última fase sob Esdras, quando o povo já era numeroso, surgiu a oposição mais intensa.','Na fase de Ageu e Zacarias, quando o templo já estava quase concluido, os inimigos se levantaram.'),('AT09-L06-Q05','Deus levantou Neemias para liderar a reconstrução de Jerusalém.','Deus enviou anjos para reconstruir os muros miraculosamente.','Deus condenou a reconstrução e destruiu o que foi feito.','Moisés liderou a reconstrução do templo em Canaã.'),('AT09-L06-Q06','Deus restaura Seu povo fielmente, preservando identidade e aliança na adversidade.','A oposição demonstra que Deus definitivamente rejeitou Seu povo para sempre.','A reconstrução accomplisha-se unicamente pelo esforço humano, sem intervenção divina.','O povo perdeu completamente sua identidade e jamais conseguiu recuperá-la.'),('AT09-L06-Q04','Os povos circum-adjacentes contrataram conselheiros para frustrar o seu purpose','Os profetas ordenaram que a reconstrução cessasse ate que a lei fosse restaurada primeiro','O templo enviou guardas para impedir os operarios de trabalhar nos muros','A comunidade se dividiu em facções que lutavam entre si pelo controle da reconstrução'),('AT09-L07-Q02','No primeiro retorno, sob Zorobabel','No segundo retorno, sob Esdras','No terceiro retorno, sob Neemias','Durante o cativeiro babilônico'),('AT09-L07-Q01','Zerubbabel, Jesua e a reconstrução do Segundo Templo','Samuel, Saul e a unção do primeiro rei de Israel','Elias, Eliseu e os milagres no Reino do Norte','Jeremias e a destruição do Primeiro Templo'),('AT09-L07-Q04','incentivaram a reconstrução do templo de Jerusalém','pregavam a destruição total de Jerusalém','rejeitavam o regresso dos exilados','advogavam a reconstrução do templo de Babilônia'),('AT09-L07-Q05','Deus suscitou Haggai e Zacarias para liderar e prover recursos para o templo.','Deus enviou anjos militar para reconstruir o templo de Judá.','Os profetas venderam seus bens para financiar a reconstrução.','Deus abandonou Judá após o retorno do cativeiro babilônico.'),('AT09-L07-Q06','Deus restaura e renova Seu povo quando este se volta para a adoração e obedece à Sua Palavra.','A restauração depende solely da capacidade humana e dos recursos materiais do povo.','Os profetas ensinaram que a identidade do povo estava baseada em conquistas militares.','A fidelidade divina exige que o povo primeiro prove seu merecimento por obras.'),('AT09-L08-Q02','Um escriba com profundo conhecimento da Lei de Moisés, responsavel por ensiná-la e interpretá-la.','Um funcionario publico designado por Herodes para coletar impostos.','Um escriba responsavel apenas por copiar manualmente os rolos sagrados.','Um sacerdote incumbido de realizar os sacrifícios no Templo.'),('AT09-L08-Q01','Era scribe e sacerdote da linhagem de Seraiah, sumo sacerdote.','Era profeta da linhagem de Arão, o primeiro sumo sacerdote.','Era rei de Judá descendente da linhagem real de Davi.','Era comerciante da tribo de Judá sem ligação sacerdotal.'),('AT09-L07-Q03','Autorização divina para reconstruir o templo','Profecia contra os povos vizinhos da Judeia','Mandato para fundar uma nova religião nacional','Ordem para abandonar completamente Judá e partir'),('AT09-L08-Q03','Revelar o pecado, conduzir a Cristo e guiar a vida','Condenar o pecador, punir o ímpio e separar os povos','Abrogar os mandamentos, substituir a lei e criar novos ritos','Eliminar a culpa, perdoar os pecados e regenerar o fiel'),('AT09-L08-Q04','Autoridade para reedificar os muros de Jerusalém','Autoridade para reconstruir o templo de Jerusalém','Autoridade para pregar o evangelho na Pérsia','Autoridade para escolher um novo rei'),('AT09-L08-Q05','Esdras ensinou a Lei de Deus ao povo e restaurou a adoração em Jerusalm.','Esdras construiu o templo de Jerusalm com suas prprias mos.','Esdras escreveu a maior parte do livro dos Salmos.','Esdras foi o primeiro rei de Jud apos o cativeiro.'),('AT09-L09-Q02','No segundo retorno, sob a lideranca de Esdras','No primeiro retorno, sob a lideranca de Zorobabel','No terceiro retorno, sob a lideranca de Neemias','No retorno messiânico, quando Jesus vier'),('AT09-L09-Q01','Jesus Cristo, o Anticristo, a grande tribulação e o juízo final','O Dilúvio, o Êxodo, a queda de Jericó e o cativeiro','A Santa Ceia, a Crucificação, a Ascensão e Pentecostes','O chamamento de Abraão, a aliança no Sinai e o reino de Davi'),('AT09-L09-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT09-L08-Q06','Porque era Deus feito homem, revelando a verdade em palavra e obra','Porque aprendeu com os mestres da lei desde criança','Porque Deus o escolheu como único mediador entre céu e terra','Porque era o primeiro dos profetas do Antigo Testamento'),('AT09-L09-Q05','NAO SEI','Pelo poder do Espirito Santo que guia a Igreja','Atraves da profecia e visoes sagradas','Pela autoridade dos apostolos ungidos'),('AT09-L09-Q04','Restauracao da Lei, reedificacao do templo, muros e comunidade.','Guerra contra os povos vizinhos para expandir o territorio de Israel.','Construcao de uma nova cidade fora dos muros antigos de Jerico.','Exilio forçado dos judios que rejeitaram os profetas.'),('AT09-L10-Q02','No retorno de Esdras','No retorno de Zorobabel','Na construção dos muros','No primeiro retorno'),('AT09-L09-Q06','Deus cumpre suas promessas e restaura o seu povo quando este volta para Ele','A identidade nacional depende exclusivamente da reconstrução física do templo','A fidelidade divina é condicionada ao mérito do povo','A restauração ocorre pelo poder militar dos líderes humanos'),('AT09-L10-Q01','Moisés, a promulgação da Lei no monte Sinai, os escribas e Esdras.','Abraão, a aliança com Deus e a circuncisão como inicio do ensino da lei.','Jesus Cristo, a abolição da Lei e a nova aliança no monte Calvário.','O cativeiro babilônico, a reconstrução do templo e os profetas menores.'),('AT09-L11-Q01','Infidelidade contra Deus ao casar com mulheres estrangeiras','Violacao das leis sabaticas com casamentos no domingo','Roubo de ofertas e dizimos destinados ao templo','Recusa da comunidade em participar das festividades sacredas'),('AT09-L10-Q05','Deus constituiu os levitas e escribas para ensinarem a lei.','Deus entregou a lei aos anjos para que a ensinassem diretamente.','Cada família deveria interpretar a lei sem nenhuma orientação.','Deus proibiu qualquer forma organizada de ensino da lei.'),('AT09-L10-Q04','Ezra leu e explicou a Lei ao povo junto à porta da cidade','O sumo sacerdote recitava a Lei durante os sacrifícios no altar','Os muros do templo guardavam as tábuas da Lei em segredo','As mulheres ensinavam a Lei nos portões da cidade todos os dias'),('AT09-L11-Q04','NAO SEI','UM TRIBUNAL RELIGIOSO FOI ESTABELECIDO','A LEI DE MOISES FOI APLICADA','UMA COMISSAO DE SACERDOTES FOI FORMADA'),('AT09-L11-Q03','Bendisse ao Senhor e deu graças pela boa notícia','Ficou irado e rasgou as vestes em sinal de indignação','Chorou copiosamente e jejuou por muitos dias','Pregou um sermão ao povo sobre desobediência'),('AT09-L10-Q03','Cristo afirmou cumprir a lei','Paulo declarou abolir a lei mosaica','Os profetas confirmaram a lei sem mudanças','O Espirito Santo revogou todos os mandamentos'),('AT09-L11-Q02','Porque o povo de Deus era definido pela aliança com ele, não pela etnia.','Porque a etnia era o único critério de identidade do povo escolhido de Deus.','Porque os líderes queriam preservar a pureza genealógica acima de tudo.','Porque a origem étnica determinava a salvação segundo a lei mosaica.'),('AT09-L11-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT09-L10-Q06','Que a fidelidade de Deus restaura a identidade do Seu povo mediante a observância da lei','Que o povo deve abandonar a lei para ser restaurado e encontrar sua identidade','Que a restauração depende do esforço humano e não da fidelidade divina','Que a identidade do povo não está ligada à observância da lei de Deus'),('AT09-L12-Q03','Neemias recebeu do rei Artaxerxes autorização para reconstruir os muros de Jerusalém.','Esdras recebeu do rei Artaxerxes autorização para reconstruir o templo de Jerusalém.','Neemias foi autorizado a reconstruir o palácio real em Susã.','O sumo sacerdote proibiu Neemias de entrar em Jerusalém por ser leigo.'),('AT09-L12-Q02','Terceira fase da restauração pós-exílica','Primeira fase da restauração com Zorobabel','Quarta fase da restauração pós-exílica','Segunda fase da restauração com Esdras'),('AT09-L11-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT09-L12-Q01','Artaxerxes, Hanani, oração, jejum e permissão real para reconstruir Jerusalém.','Moisés, Faraó, as pragas do Egito e a travessia do mar Vermelho.','Dário, Ageu, Zacarias e a reconstrução do segundo templo.','Daniel, os três jovens, a fornalha ardente e a cova dos leões.'),('AT09-L12-Q06','雖居波斯朝廷，仍記念百姓，為耶路撒冷求恢復','身處異邦當完全融入波斯文化，勿記念故土','只需在朝中求庇護，不必親自返國重建','單靠己力重建城牆，無需尋求神帮助'),('AT09-L13-Q01','Porque foram destruídos pelos babilônios durante o cativeiro','Porque foram danificados por um terremoto durante o exílio','Porque os romanos demandaram sua reconstrução após a guerra','Porque foram queimados durante a invasão dos midianitas'),('AT09-L13-Q02','Neemias pediu ao rei, que lhe deu carta e provisões para reedificar.','O rei enviou exército para proteger Neemias durante a reedificação.','Neemias vendeu seus bens para financiar sozinho a reconstrução.','O rei ordenou que todos os povos vizinhos ajudassem no projeto.'),('AT09-L12-Q04','Neemias orou a Deus em Susã pela destruição dos muros e da cidade de Deus.','Neemias construiu o templo em Susã por ordem do rei Artaxerxes.','Em Susã, Neemias leu a Lei ao povo e pregou a Palavra de Deus.','Neemias formou uma comunidade de levitas em Susã para worship.'),('AT09-L13-Q03','NAO SEI','Os levitas foram divididos em familias Kohatitas, Geresonitas e Meraritas para o servico do Tabernaculo','Os doze tribus foram organizadas conforme suas familias para o trabalho na terra prometida','As tarefas foram distribuidas conforme a capacidade e experiencia de cada familia biblica'),('AT09-L13-Q06','Em cinquenta e dois dias','Em oitenta e um dias','Em um ano completo','Em trinta dias'),('AT09-L13-Q04','Oposição externa de Sanbalat e Tobias, e conspiração interna de nobres judaicos','Oposição apenas de tribos estrangeiras que viviam próximas a Judá','Resistência interna dos levitas e resistência externa dos filisteus','Conflitos entre os profetas e oposição externa dos assírios apenas'),('AT09-L13-Q05','Com uma mão edificavam e com a outra empunhavam a espada','Usavam ferramentas especiais que serviam como armas defensivas','Trabalhavam apenas durante a noite quando os inimigos dormiam','Dividiram-se em grupos que alternavam entre construir e vigiar'),('AT09-L14-Q03','Sanbalat, Tobias e Gesém','Ciro, Dario e Artaxerxes','Ageu, Zacarias e Miquéias','Abia, Roboão e Jeroboão'),('AT09-L14-Q01','Sanbalat, Tobias e Gesém se opuseram à reconstrução dos muros de Jerusalém por Neemias','Esdras, Ageu e Zacarias foram inimigos de Neemias na reedificação da cidade de Judá','Dario, Ciro e Artaxerxes impediram Neemias de reedificar os muros de Jerusalém','Os filisteus, amalequitas e moabitas foram os principais adversários de Neemias'),('AT09-L14-Q02','Terceiro retorno de restauração','Primeiro retorno sob Zorobabel','Segundo retorno sob Esdras','Durante a reconstrução do templo'),('AT09-L13-Q07','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT09-L14-Q06','A fidelidade em meio à oposição restaura a identidade do povo de Deus.','A identidade do povo se dissolve quando enfrentam qualquer tipo de oposição.','A restauração depende solely da aceitação dos termos impostos pelos inimigos.','O povo recupera sua identidade abandonando as práticas de fidelidade a Deus.'),('AT09-L14-Q05','NAO SEI','Deus levantou Sanbalat e Tobias para testar a fé de Neemias na reconstrução dos muros','Os adversários de Neemias foram escolhidos por Deus para destruir a obra da reconstrução','Neemias enfrentou inimigos que simbolizavam a provisão divina contra sua liderança'),('AT09-L14-Q04','Sanballat, Tobias e Gésen opuseram-se à reconstrução dos muros de Jerusalém.','O templo foi destruído pelos próprios inimigos de Neemias como forma de intimidação.','A Lei foi usada para accusing Neemias de rebellion contra o imperador persa.','A comunidade recusou-se a participar da reconstrução por falta de recursos.'),('AT09-L15-Q01','Nimrod, que fundou Babel, Erech, Accade e Calné (Gênesis 10:10)','A arca de Noé, construída conforme Deus ordenou a Noé (Gênesis 6)','O êxodo dos israelitas guiados por Moíses fora do Egito (Êxodo 13)','A construção do tabernáculo no deserto sob orientação divina (Êxodo 25)'),('AT09-L15-Q02','Terceiro retorno sob Neemias','Primeiro retorno sob Zorobabel','Segundo retorno sob Esdras','Quarto retorno sob Ageu'),('AT09-L15-Q03','A Torre de Babel, desafio à soberania de Deus','As doze cidades de refúgio autorizadas por Deus','O templo de Jerusalém como centro urbano sagrado','As cidades levíticas designadas na terra prometida'),('AT09-L15-Q04','Neemias organizou Jerusalém com a Lei, o templo, os muros e a comunidade.','A Lei, o templo, os muros e a comunidade foram elementos que nunca interagiram entre si na cidade.','O templo organizava a cidade, mas a Lei, os muros e a comunidade não tinham papel algum.','Os muros foram construídos primeiro, e depois o templo, a Lei e a comunidade foram organizados.'),('AT09-L16-Q01','Esdras','Neemias','Moisés','Samuel'),('AT09-L16-Q03','Os levitas ajudavam o povo a entender a Lei que Esdras lia em voz alta','Os levitas traduziam a Lei em línguas estrangeiras para os países vizinhos','Os líderes escribiam comentários na margem do texto sagrado para estudo','Os levitas recolhiam dízimos enquanto o povo ouvia em silêncio reverente'),('AT09-L15-Q05','Deus levanta reis e governantes conforme sua soberana vontade','Deus delega toda autoridade aos seres humanos sem nenhuma intervenção','Deus governa diretamente cada cidade sem usar mediadores humanos','A organização da cidade é determinada exclusivamente pelo acaso'),('AT09-L16-Q02','No concilio de Jerusalem, conforme Atos 15','No templo de Jerusalem, conforme Atos 2','Em Antioquia da Syria, conforme Atos 13','No monte Sinai, conforme Exodo 19'),('AT09-L16-Q07','NAO SEI','Que as Escrituras devem ser interpretadas apenas pelo信徒 individuais','Que a leitura biblica dispensam aplicacao pratica','Que a explanao das Escrituras e privilegio exclusivo dos sacerdotes'),('AT09-L16-Q06','A Festa das Tendas','A Festa da Páscoa','A Festa dos Pães Asmos','A Festa da Dedicação'),('AT09-L16-Q04','Choraram ao ouvir as palavras da Lei','Sorriram alegres ao ouvir a Lei','Rejeitaram toda a autoridade da Lei','Pediram para retornar ao exílio'),('AT09-L16-Q05','Porque compreenderam a Lei e louvaram a Deus pelas bênçãos recebidas.','Porque queriam que o povo se distraísse dos problemas de Judá.','Porque a celebração era obrigatória para manter o calendário religioso.','Porque precisavam recolher dízimos e ofertas do povo.'),('AT09-L17-Q02','No retorno de Neemias, fase da grande confissao em Neemias 9','No retorno de Zorobabel, fase da reedificacao do templo em Esdras 6','No retorno de Esdras, fase do ensino da Lei em Esdras 7','No retorno de Zorobabel, fase da dedicacao do templo em Esdras 6'),('AT09-L17-Q03','Perdão e favour, porque pecamos contra ti','Protecção e refugio, porque o Senhor é nosso Deus','Guerra e derrota, porque abandonamos a lei','Exaltação e gloria, porque fomos justos'),('AT09-L17-Q01','Josué, Esdras, Neemias, Daniel e Samuel lideraram confissões nacionais de Israel.','Salomão, Gideão, Davi e Elias lideraram confissões nacionais em Israel.','Moisés, Abraão, Noé e Gideão conduziram confissões nacionais do povo.','O rei Herodes, Pilatos, Faraó e Nabucodonosor lideraram confissões nacionais.'),('AT09-L17-Q05','Por meio de Ciro, a quem Deus desperta para restaurar e reconstruir Judá','Por intermedio de rituais secretos e pactos ocultos com forcas invisiveis','Pela forca militar propria do rei sem necessidade de intervencao divina','Por intermedio de Nabucodonosor, que destruiu Judá como prova de dominio'),('AT09-L17-Q04','Em Ne 9-10, Lei, templo, muros e povo se unem na confissão nacional e renovação da aliança','Os muros simbolizavam apenas proteção militar, sem relação com a confissão de pecados','O templo servia apenas para sacrifícios, não participava da renovação da aliança','A confissão nacional baseava-se em tradições orais, não na Lei escrita de Moisés'),('AT09-L18-Q02','Retorno de Esdras','Retorno de Zorobabel','Retorno de Neemias','Fase do cativeiro babilonico'),('AT09-L17-Q06','Confissão nacional revela restauração pela fidelidade de Deus quando o povo se arrepende e volta a Ele','Restauração depende exclusivamente da obediência ritual sem necessidade de confissão de pecados','Identidade do povo é mantida automaticamente pela tradição cultural sem relação com Deus','Fidelidade de Deus depende do merecimento humano para realizar restauração nacional'),('AT09-L18-Q01','Moisés, Josué, Josias, Esdras e Neemias','Abraão, Isaque, Jacó e os patriarcas','Davi, Salomão, Roboão e Jeroboão','Elias, Eliseu, Isaías e Jeremias'),('AT09-L18-Q04','Neemias 8-10: Lei lida, povo confessa, alianca renovada.','Exodo 32: o bezerro de ouro, Aaron funde o idolo.','1 Reis 8: Salomao dedica o templo com oracao.','Js 6: as paredes de Jerico caem ao grito.'),('AT09-L19-Q02','Terceiro retorno, sob Neemias, por volta de 445 a.C.','Primeiro retorno, com Zorobabel, na reconstrução do templo','Segundo retorno, junto com Esdras, por volta de 458 a.C.','Durante o cativeiro babilônico, antes da volta a Judá'),('AT09-L18-Q05','Por meio da provisão do pão, água e do Espírito Santo na renovação da aliança','Pela execução de rituais de sacrifício humano e guerras de conquista','Pela entrega de liderança política de reis pagãos e nações idólatras','Por acordos diplomáticos e comerciais entre nações estrangeiras e Israel'),('AT09-L18-Q06','Deus renova aliança e restaura Seu povo à fidelidade e identidade prometidas','A renovação da aliança garante prosperidade material e sucesso em todas as empreitadas','O povo perde completamente sua identidade nacional ao celebrar nova aliança','A aliança renovada dispensa a necessidade de arrependimento e obedecer mandamentos'),('AT09-L19-Q01','Esdras, Sanabalate, o pacto e a leitura da Lei pelo povo.','Moisés, o maná no deserto e a travessia do mar Vermelho.','Davi, o gigante Golias e a construção do primeiro templo.','Abraão, o sacrifício de Isaque e a aliança com Melquisedeque.'),('AT09-L19-Q03','Autorização do rei Artaxerxes para reconstruir os muros','Profecia de Ageu e Zacarias sobre a reconstrução','Oposição de Faraó durante a construção do templo','Desafio do cativeiro babilônico para os judeus'),('AT09-L19-Q06','Deus restaura Seu povo e renova a aliança mediante arrependimento e fidelidade.','A restauração depende do esforço humano e da observância rigorosa da lei mosaica.','A identidade do povo é restaurada solely pela reconstrução física do templo de jerusalém.','A fidelidade divina exige que o povo mantenha sua identidade cultural sem relação com Deus.'),('AT09-L20-Q01','Ciro, Zorobabel, Esdras e Neemias; decreto de Ciro e reconstrução do templo.','Abraão, Isaque, Jacó e o êxodo do Egito; aliança no Sinai e tabernáculo.','Davi, Salomão e os profetas Elias e Eliseu; construção do primeiro templo.','Moisés, Arão e os anciãos; páscoa no deserto e maná do céu.'),('AT09-L19-Q05','Deus ouviu as orações de Neemias e lhe concedeu favor diante do rei.','Um anjo appearedceu a Neemias e entregou suprimentos diretamente.','Deus fez o rei ordenar que os inimigos financiassem toda a obra.','Neemias encontrou um tesouro oculto nos fundamentos do templo.'),('AT09-L19-Q04','Neemias reformou a comunidade reconstruindo os muros, restaurando o templo e lendo a Lei ao povo.','Neemias focusou apenas na construcao dos muros sem envolver a Lei ou o templo.','Neemias reformou exclusivamente o templo sem mencionar os muros ou a comunidade.','Neemias leu a Lei ao povo mas nao reconstruiu os muros nem restaurou o templo.'),('AT09-L20-Q02','Retorno de Esdras restaurou a identidade espiritual da comunidade (Esdras 7-10)','Primeiro retorno com Zorobabel restaurou a identidade politica de Israel (Esdras 1-6)','Retorno de Neemias restaurou a identidade militar da comunidade (Neemias 1-13)','A identidade foi restaurada no segundo retorno com a reconstrucao do templo (Esdras 3-6)'),('AT09-L20-Q03','A nova aliança em Jeremias 31','O dilúvio universal como julgamento','A torre de Babel e confusão das línguas','A aliança no Sinai com Moisés'),('AT09-L20-Q04','Elementos centrais de identidade na restauracao pos-exilica em Ezra-Nehemias.','A monarquia davidica restaurada foi o principal pilar da identidade da comunidade.','O templo sem a Lei bastava para definir a identidade do povo restaurado.','A adesao aos costumes gentílicos era o fator principal de identidade.'),('AT10-L01-Q01','Ciro, Dario, Esdras, Neemias e a reconstrução do templo','Faraó, José e os sete anos de fartura no Egito','Elias, Acab e o confronto no Monte Carmelo','Pilatos, Barrabás e a sentença de Jesus'),('AT10-L01-Q02','Ciro os libertou do cativeiro e permitiu a reconstrução do templo em Jerusalém.','Foram todos exterminados pelos persas durante o reinado de Dario.','Os persas os forçaram a abandonar completamente sua identidade religiosa.','Viveram em paz total sem nenhuma perseguição ou conflito no império.'),('AT09-L20-Q06','Deus restaura seu povo e renova sua aliança fielmente','A identidade se perde para sempre apos a dispersao','O povo deve restaurar-se por seus proprios esforcos','A restauracao depende apenas da obediencia perfeita'),('AT10-L01-Q04','Daniel mostrou coragem ao ser lançado na cova dos leões por orar ao SENHOR.','Os judeus fugiram do império persa para evitar perseguições religiosas.','Daniel foi executado por desafiar o rei Assuero na corte persa.','Os judeus se rebelaram contra o império persa durante o exílio.'),('AT09-L20-Q05','Deus pastoreia e sustenta Seu povo restaurado','Lideres humanos provedem toda a orientacao necessaria','A comunidade se restaura atraves de seu proprio esforço','Recursos materiais definem a identidade da comunidade'),('AT10-L01-Q05','Vitória contra inimigos, Purim estabelecido, Mardoqueu honrado, Hamã enforcado','Os Judeus foram expulsos do império persa e nunca mais voltaram','Ester perdeu o título de rainha e foi banida do palácio','O templo de Jerusalém foi reconstruído durante o reinado de Assuero'),('AT10-L01-Q03','Reversão do decreto de Hamã contra os judeus','Decreto de Ciro permitindo o regresso a Judá','Edificação do segundo templo em Jerusalém','Êxodo dos judeus para o Egito sob Nabucodonosor'),('AT10-L02-Q02','Assuero foi o rei persa do tempo de Ester, instrumento no livramento dos judeus.','Assuero foi um profeta hebreu que liderou os judeus de volta do cativeiro na Babilônia.','Assuero enviou os judeus ao exílio quando conquistou Judá pela primeira vez.','Assuero construiu o Segundo Templo em Jerusalém durante seu governo na Pérsia.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT10-L01-Q06','Judeus na Pérsia mantiveram identidade e fé, origins da festa de Purim.','Judeus na Pérsia adotaram práticas religiosas persas, alterando suas tradições.','Judeus no império persa foram integralmente assimilados pela cultura gentílica.','Judeus contribuíram financeiramente para a reconstrução do templo em Jerusalém.'),('AT10-L02-Q01','Ester,Mardoqueu,Hamã,banquete real,deposição de Vasti,instituição da festa de Purim e decreto real.','Davi,Salomão,reino dividido,e王dio do bezerro de ouro,cativeiro na Babilônia.','Paulo,Silas,Timóteo,Damasco,Marte,Hebas,concílio de Jerusalém.',' Abraão,Isaque,Jacó,José,Faraó,José como governador,encontro no carriers de Hebrom.'),('AT09-L12-Q05','Deus moveu o coração do rei Artaxerxes para dar-lhe recursos, autoridade e proteção.','Deus enviou um anjo com dinheiro e soldados para reconstruir os muros.','O sumo sacerdote entregou a Neemias toda a autoridade e os materiais.','Neemias usou suas economias e liderança sem intervenção divina.'),('AT09-L15-Q06','A fidelidade a Deus restaura a identidade do povo e fortalece a comunidade','A organização política garantiria prosperidade independentemente da fé','O Templo deveria ser construído antes da muralha para validar a restauração','A identidade do povo dependia apenas da localização geográfica da cidade'),('AT09-L18-Q03','O desafio de escolher a quem servir','A oposição dos povos vizinhos à aliança','A autorização do sumo sacerdote','O sacrifício de animais como renovação'),('AT10-L02-Q05','Assuero permitiu que Hamã editasse um decreto para exterminar os judeus','Assuero promoveu Mardoqueu a primeiro ministro do império medo-persa','Assuero ordenou que Ester se tornasse sua única esposa permanente','Assuero converteu todos os judeus à religião do império persa'),('AT10-L02-Q03','Ester se arriscou ao entrar sem ser chamada','Assuero decidiu executar todos os judeus','Mardoqueu se recusou a adorar Haman','Assuero baniu Vera por desobedecer'),('AT10-L03-Q01','Rainha persa que se recusou a comparecerao banquete do rei Aquerages.','Rainha que conspirou contra Aquerages e foi executada por ordem real.','Profetisa que alertou o rei sobre a fome no reino de Judá.','Serva egípcia que liderou o povo durante o êxodo do Egito.'),('AT10-L02-Q04','A providencia se manifesta quando Deus usa Assuero para livrar os judios','A coragem de Assuero se revela quando desafia Haman publicamente','A prudencia aparece quando Assuero consulta os conselheiros antes de agir','Assuero demonstra virtude ao jejuar antes de tomar decisoes importantes'),('AT10-L02-Q06','Mostra como Deus soberanamente usa reis imperfeitos para seus propósitos','Demonstra que os reis persas seguiam a lei divina e eram instrumentos de justiça','Prova que a providência divina não intervém nos negócios dos poderosos','Revela que Assuero e Haman eram aliados leais na proteção do povo'),('AT10-L03-Q03','Ser deposta por desobedecer ao rei','Ser coroada por sua sabedoria','Converter-se ao judaísmo','Fugir com o rei para outra terra'),('AT10-L03-Q02','Rainha deposta do rei Assuero no livro de Ester','Profetisa que liderou o retorno dos judeus do cativeiro','Esposa de Ciro que ajudou a reconstruir o templo','Rainha-mãe que governou Judá sob domínio medo'),('AT10-L04-Q01','Mordecai, Hamã, Assuero e a festa de Purim','Moisés, Faraó, José e a construção do Templo','Davi, Golias, Saul e a unção como rei','Neemias, Artaxerxes, Esdras e a reconstrução dos muros'),('AT10-L03-Q06','Sua remoção ilustra a posição vulnerável da mulher no palácio','Vasti representa a fiel submissão à vontade divina no livro','Sua obediência ao rei estabelece o modelo de conduta','Vasti foi a heroína silenciosa que salvou os judeus'),('AT10-L04-Q02','Ester se tornou rainha e intercedeu junto ao rei para salvar os judeus de Hamã.','Ester converteu-se ao paganismo e abandonou completamente suas raízes judaicas na corte.','Ester foi exilada de Judá por desobedecer às leis mosaicas ao servir no palácio.','Ester utilizou rituais mágicos para influenciar o rei e dominar o Império Persa.'),('AT10-L03-Q04','Vashti manifestou coragem ao recusar-se a ir diante dos convivas do rei.','Vashti agiu com prudência ao pedir perdão ao rei após desobedecer sua ordem.','Vashti demonstrou providência ao aceitar sua demissão como parte do plano divino.','Vashti ordenou que o rei matasse os sete príncipes que a haviam ameaçado.'),('AT10-L03-Q05','Nenhuma consequência direta; sua remoção abriu espaço para Ester.','Vasti revelou ao rei a conspiração de Hamã contra os judeus antes de Ester.','Vasti causou a perseguição inicial dos judeus ao ordenar decreto contra eles.','Vasti foi aliada de Hamã e juntos planejaram a execução de Mardoqueu.'),('AT10-L04-Q04','Abordou o rei sem ser chamada para salvar seu povo, demonstrando coragem e prudência.','Ordenou a execução imediata de Hamã antes de revelar o plano ao rei.','Usou intrigas palacianas e subornos para derrubar Hamã sem confronto.','Fugiu do palácio e escondeu-se até que o perigo passasse.'),('AT10-L04-Q03','O risco de aproximar-se do rei sem ser chamada, o que poderia custar-lhe a vida','A decisão de aceitar ser chamada de Hadossa em vez de Ester, seu nome verdadeiro','O risco de revelar sua identidade antes de se tornar rainha ao povo','A reversão de ser banida do palácio por desobedecer as leis persas'),('AT10-L04-Q05','Salvação do povo judeu da destruição e estabelecimento da festa do Purim.','Perda do título de rainha e exílio de Ester para a Babilônia.','Conversão de Hamã ao judaísmo e elevação de Mardoqueu a rei.','Destruição do templo de Jerusalém e cativeiro permanente dos judeus.'),('AT10-L05-Q01','Esther, o rei Assuero e Haman, revelação de complô e festa do Purim.','Abraão, Sara e Hagar, a aliança com Deus e o sacrifício de Isaque.','Davi, Golias, o rei Saul e a arca da aliança.','Daniel, os três amigos, Nabucodonosor e a queda de Babilônia.'),('AT10-L05-Q02','Mardoqueu era Judeu na corte persa, conselheiro do rei, e protegeu seu povo.','Mardoqueu foi o sumo sacerdote do templo em Jerusalém durante o cativeiro.','Mardoqueu projetou e construiu a segunda muralha de Jerusalém contra invasores.','Mardoqueu liderou uma rebelião militar contra o Império Persa pelos Judeus.'),('AT10-L04-Q06','Ester demonstra que Deus usa pessoas corajosas para salvar seu povo da destruição.','Ester estabelece o calendário de festas judaicas como lei permanente para todos os séculos.','Ester introduz a prática do jejum como requisito essencial para a salvação.','Ester ensina que a intervenção divina sempre ocorre por meio de guerras e conquistas.'),('AT10-L05-Q03','A reversão do cadafalso: Hamã foi enforcado no que construíra para Mardoqueu','Mardoqueu decidiu construir um jardim para demonstrar sua riqueza ao rei','O risco de Mardoqueu foi casar-se secretamente com a rainha Ester','A decisão de Mardoqueu foi abandonar Judá e integrar-se à cultura persa'),('AT10-L05-Q04','Descobriu a conspiração de Hamã e enfrentou-o com coragem sem se curvar.','Com humildade viveu como mendigo entre os pobres de Susa.','Por profecia warning предупреждение alertou o rei de antemão.','Com sabedoria construiu o primeiro templo em Jerusalém.'),('AT10-L06-Q01','Era o principal ministro do rei Assuero, o maior dos príncipes do império.','Era o sogro do rei Assuero, que governava as terras do império ao seu lado.','Era o comandante supremo do exército, liderando todas as campanhas militares.','Era o sumo sacerdote da capital Susa, responsável pelos rituais do império.'),('AT10-L06-Q02','Porque Mardoqueu não se prostou nem se curvava diante dele','Porque Mardoqueu revelara uma conspiração contra o rei','Porque Mardoqueu era descendente do povo amalequita','Porque Mardoqueu se recusou a participar do banquete real'),('AT10-L06-Q04','Significa lançar sortilégios, sortear dias para determinar a sorte.','Significa orar a Deus para pedir orientação sobre decisões importantes.','Significa fazer um pacto secreto com os inimigos do povo de Deus.','Significa consultar os astros para prever eventos futuros.'),('AT10-L05-Q06','Ester e Mordecai trabalharam juntos para salvar Israel da destruição.','Mordecai tentou usurpar o trono de Assuero para governar Judá.','Mordecai estabeleceu a festa da Páscoa como memória da libertação.','Mordecai convinhou os judeus a abandonarem suas tradições em Susa.'),('AT10-L06-Q03','Haman, irado por Mordecai, conspirou com Assuero para destruir todos os judeus.','O rei Assuero decidiu sozinho exterminar os judeus por ganância imperial.','O profeta Elias convenceu o rei persas a perseguir e matar todos os judeus.','Os inimigos de Israel exigiram que o rei Xerxes deportasse todos os judeus.'),('AT10-L05-Q05','Ele saveu os judeus da destruição e foi honrado pelo rei.','Ele causou a destruição dos judeus por sua desobediência.','Ele foi enforcado no cadafalso preparado para Haman.','Ele recebeu todo o reino de Assuero como herança.'),('AT10-L07-Q02','O decreto de Hamã foi invertido pelo rei, permitindo aos judeus defenderem-se.','Os judeus fugiram do Império Persa após o decreto de Hamã.','O decreto foi aceito pelos judeus sem qualquer resistência.','O rei anulou completamente o decreto, cancelando o dia marcado.'),('AT10-L06-Q05','Afirmou que os judeus não obedeciam às leis do rei, prejudicando o reino.','Ofereceu grandes quantidades de ouro e joias ao rei como suborno.','Convenceu o rei de que os judeus planejavam um golpe contra a coroa.','Mostrou ao rei presságios e sinais divinos contra o povo judeu.'),('AT10-L07-Q01','Haman, Ahasuerus, Ester, Mordecai, decreto de aniquilação, livro de Ester.','Pilatos, Sinédrio, Jesus, Judas, sentença de morte, evangelho de Mateus.','Nabucodonosor, Daniel, Jeremias, queda de Jerusalém, livro de Jeremias.','Moisés, Faraó, libertação do Egito, pragas, livro do Êxodo.'),('AT10-L07-Q04','A providencia divina age no livro de Ester','A coragem de Ester ao propor um banquete ao rei','A prudencia de Mardoqueu ao nao se inclinar diante de Hamã','A fè de Abraao ao ofrecer Isaque em sacrifício'),('AT10-L06-Q06','Extinção do povo judeu por meio de genocidio planejado','Subjugação politica e perda da independencia nacional','Dissolução da identidade por meio da assimilação forçada','Deterioração economica e empobrecimento coletivo'),('AT10-L07-Q06','Cria o conflito central que é反转ado, levando ao estabelecimento do Purim.','Determinou a conversão em massa dos judeus ao cristianismo primitivo.','Estabeleceu a paz permanente entre os judeus e os povos gentílicos.','Causou o exílio definitivo dos judeus da terra de Canaã.'),('AT10-L07-Q05','Ester revelou sua identidade e intercedeu, obtendo um decreto que permitiu aos judeus se defenderem.','Os judeus fugiram da Pérsia e nunca mais retornaram às suas terras de origem.','Hamã foi nomeado governor de Judá após a execução do decreto contra os judeus.','Os judeus aceitaram o decreto sem resistencia e se dispersaram pelo império persa.'),('AT10-L08-Q01','Ester, Mardoqueu, jejum de tres dias, audiencia com o rei, queda de Haman.','Jesus, Moises, jejum de quarenta dias no deserto, tentacao de Satanas.','Elias, Eliseu, jejum do monte Carmelo, duelo com os profetas de Baal.','Daniel, os tres jovens, jejum de tres semanas, visao do Valle de Hacmidar.'),('AT10-L08-Q02','Ester pediu aos judeus que jejuassem 3 dias antes dela ir ao rei Aquerages','Os judeus jejuvam semanalmente no templo de Susa como ritual persistente','O jejum era obrigatorio para todos os povos do Imperio Persa','Ester jejuou sozinha por 40 dias no palacio real em preparacao'),('AT10-L08-Q03','Ester arriscou a vida ao se apresentar ao rei sem ser chamada','O rei revogou o decreto contra os judeus antes do jejum terminar','Mardoqueu decidiu não jejuar para negociar com Haman','Os judeus foram expulsos de Susa durante o jejum de Ester'),('AT10-L08-Q04','Coragem ao arriscar a vida, prudência ao planejar, providência no resultado.','O jejum lhe conferiu poder sobrenatural para dialogar com o rei.','Agiu por impulso emocional, sem estratégia ou preparo algum.','Dependeu exclusivamente da sorte e de coincidências favoráveis.'),('AT10-L09-Q01','Porque a lei persa condenava à morte quem entrasse no pátio do rei sem ser chamado.','Porque o rei Mardoqueu havia ordenado que ninguém se aproximasse do trono.','Porque Ester era estrangeira e não tinha permissão de falar com o rei.','Porque havia uma praga no palácio e todos deveriam manter distância.'),('AT10-L08-Q06','Mostra a dependência do povo em Deus durante a crise e precede a libertação dos judeus.','Prova que o jejum deveria ser observado anualmente como sacrifício代代替其他宗教仪式。','Estabelece o jejum como ritual central替代其他祭祀形式 do livro。','Demonstra que a salvação dependia exclusivamente da vontade divina, sem participação humana.'),('AT10-L08-Q05','Os judeus se reuniram, jejuaram e oraram, resultando na salvação do povo da destruição planejada por Hamã','O jejum trouxe praga e esterilidade sobre toda a terra de Susã, causando fome generalizada','Hamã jejuou junto com os judeus e converteu-se ao judaísmo depois do milagre','O jejum fez Ester perder o favorecimento do rei Assuero e ela foi destronada'),('AT10-L09-Q02','Com óleo de mirra e perfumes durante doze meses','Com jejum e orações durante toda a noite','Com banhos em águas perfumadas do rio','Com roupas preciosas e joias finas'),('AT10-L09-Q03','Estendeu o cetro de ouro para ela','Mandou prendê-la imediatamente','Ignorou completamente a sua presença','Sentou-se em silêncio sem reagir'),('AT10-L09-Q04','Para preparar um momento propício antes de revelar sua súplica','Para celebrar a festa dos pães asmos diante do rei Assuero','Para testar o amor do rei antes de pedir seu perdão','Para distrair Haman enquanto planejava sua fuga'),('AT10-L09-Q07','NAO SEI','...','...','...'),('AT10-L09-Q05','No segundo dia do banquete, quando se apresentou ao rei Assuero.','Quando chegou a Susa e se casou com o rei Assuero.','Ao ser coroada rainha diante de todo o reino.','Quando revelou a Hamã o complô contra o rei.'),('AT10-L09-Q06','Ester revelou o plano durante um banquete, pedindo socorro ao rei.','Ester enviou uma carta ao rei revelando toda a conspiração.','Ester confrontou publicamente Hamã diante do povo.','Ester enviou mensageiros secretos ao imperador.'),('AT10-L10-Q01','Ester, Mardoqueu, Assuero e Hamã nos banquetes de Ester com a inversao do decreto.','Jesus, Pilatos, Barrabas e os fariseus com a ultima ceia e a crucifixao.','Daniel, Nabucodonosor, Beltsazar e o festim de Belsazar com a queda da cidade.','Jose, Farao, Maria e Herodes com a fuga para o Egito e a massacre dos innocentes.'),('AT10-L10-Q02','Originou a festa de Purim, celebrando a salvação dos judeus da extinção planejada por Hamã.','Conduziu ao cativeiro babilônico dos judeus após a destruição do Segundo Templo.','Resultou na instituição do jejum de Gedalias, commemorate a destruição de Jerusalém.','Promoveu a aliança entre os judeus e o Egito, fortalecendo o comércio no Mar Vermelho.'),('AT10-L10-Q03','Reversão - Hamã foi enforcado no patíbulo que preparou para Mardoqueu','Ascensão - Hamã tornou-se segundo governante do reino com anel real','Fuga - Hamã escapou para as montanhas e viveu em exile','Conspiração - Hamã planejou casar-se com a rainha Ester secretamente'),('AT10-L10-Q04','Ester manifestou coragem indo ao rei. Deus pela providência reverteu a sentença contra os judeus.','Hamã demonstrou prudência ao consultar astrólogos antes de planejar a queda dos judeus.','A coragem de Hamã em desafiar o rei resultou na sua vitória sobre Mordecai.','A queda de Hamã foi causeda pela falta de prudência do rei Assuero ao ordenar jejum.'),('AT10-L10-Q05','Hamã foi enforcado; Mardoqueu, promovido; e os judeus obtiveram permissão de se defenderem.','Hamã foi exilado; Mardoqueu perdeu o cargo; e os judeus foram escravizados.','Hamã converteu-se; Ester casou-se com Ciro; e os judeus voltaram ao Egito.','Hamã foi apedrejado; Ester fugiu para Roma; e os judeus foram expulsos da Pérsia.'),('AT10-L10-Q06','Mostra que Deus soberanamente frustra os planos dos inimigos do seu povo','Demonstra que os judeus devem abandonar sua identidade para sobreviver na diáspora','Prova que os impérios pagãos são superiores ao Deus de Israel','Estabelece que a vitória judia veio por meio de intervenção miraculosa direta'),('AT10-L11-Q02','Através da ação de Ester e Mardoqueu contra Hamã, garantindo a sobrevivência judaica','Por meio da expulsão dos judeus da cidade de Susa para proteger o império','Mediante a conversão forçada dos persas ao Judaísmo para unificar o império','Pela fuga em massa dos judeus para o Egito durante o reinado de Assuero'),('AT10-L11-Q01','Mardoqueu e Ester impediram o massacre dos judeus pelo império Persa','Abraão defendeu os judeus quando fugiram do Egito com José','Davi e Golias lutaram juntos para defender os judeus dos filisteus','O dilúvio foi a defesa divina enviada contra os inimigos dos judeus'),('AT10-L11-Q05','Hamã foi enforcado e os judeus se livraram da destruição.','Hamã tornou-se conselheiro e os judeus foram todos exterminados.','Mardoqueu foi exilado e os judeus perderam todas as terras.','Ester foi banida e Hamã ficou com os bens dos judeus.'),('AT10-L11-Q04','Ester demonstrou coragem ao aproximar-se do rei para interceder pelo seu povo.','Jonas manifestou coragem ao fugir de Nínive para Társis, evitando o massacre dos inimigos.','Abraão evidenciou providência ao quase sacrificar Isaque, atendendo ao pedido do rei da Pérsia.','Raabe demonstrou prudência ao esconder os espias na cidade durante a conquista de Jericó.'),('AT10-L11-Q03','O risco de Ester ao se aproximar do rei sem ser chamada','A decisão de Hamã de construir um cadafalso para Mordecai','A reversão de Ciro ao permitir a reconstrução do templo','O risco de Nabucodonosor ao ordenar a construção da estátua'),('AT10-L12-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT10-L11-Q06','A defesa dos judeus demonstra a providência divina na proteção do seu povo.','A defesa dos judeus é irrelevante para o propósito principal do livro.','A defesa prova que os judeus não necessitavam de intervenção divina.','A defesa dos judeus causa destruição aos povos inimigos indiscriminadamente.'),('AT10-L12-Q04','Lendo o Megilá, dando esmolas, enviando porções e banqueteando-se','Jejuando no dia 13 de Adar e acendendo velas ritualísticas','Construindo sinagogas especiais em memória do perigo evitado','Realizando procissões pelas ruas comandações do livro de Ester'),('AT10-L12-Q01','A reversao dos planos de Haman contra os judeus no império persa.','A saida dos israelitas da escravidao no Egito sob a conducao de Moises.','A inauguracao do primeiro templo de Jerusalém construido pelo rei Salomao.','A commemoracao da vitoria do rei Saul contra o gigante Golias.'),('AT10-L12-Q05','Ester e Mardoqueu instituíram a festa dos Sortes, chamada Purim, para celebrar a vitória sobre Haman.','Ester e Mardoqueu criaram a festa da Páscoa judaica para agradecer a libertação do Egito.','Mardoqueu sozinho ordenou a festa enquanto Ester apenas jejuava durante os eventos.','Ester e Mardoqueu fundaram o Shavuot para lembrar a entrega da Lei no Sinai.'),('AT10-L13-Q01','Abraão, José, Moisés e Ester exemplificam a providência divina.','Faraó, Nabucodonosor e Pilatos foram instrumentos da providência divina.','Judas Iscariotes, Caim e Faraó demonstraram a providência divina.','Simão Pedro, Tomé e João foram os principais exemplos de providência.'),('AT10-L12-Q03','Leitura do rolo de Ester, ofertas aos pobres e refeição festiva','Jejum solene de quarenta dias e noites em memória da libertação','Construção de um novo templo em Jerusalém durante as festas','Sacrifício anual de cordeiros e ofertas no altar sagrado'),('AT10-L13-Q02','Deus preservou Israel por meio dos eventos na Persia.','Os profetas deixaram de falar ao povo durante a Persia.','Deus abandonou completamente Israel durante o Imperio Persa.','A Lei moisaica foi totalmente suspensa pelos persas.'),('AT10-L13-Q05','Os Judeus foram salvos da destruição e Hamã foi enforcado no seu próprio cadafalso.','Os Judeus foram levados em cativeiro para o Egito sob a proteção divina.','Mardoqueu foi coroado rei em lugar de Hamã como punição.','Ester perdeu o título de rainha e retornou à sua terra natal.'),('AT10-L14-Q01','Não, o nome de Deus não aparece explicitamente no texto hebraico de Ester.','Sim, o nome de Deus aparece no texto hebraico de Ester.','Sim, o nome de Deus aparece no texto hebraico de Ester, no capítulo oito.','Sim, o texto hebraico de Ester usa o Tetragrama YHWH explicitamente.'),('AT10-L13-Q06','Mostra que Deus opera discretamente para proteger Seu povo.','Revela a intervenção direta de Deus através de anjos mensageiros.','Enfatiza a necessidade de jejum e oração para a salvação do povo.','Demonstra que o exílio dos judeus chegou ao fim pelo poder divino.'),('AT10-L13-Q04','Como sabedoria e cuidado de Deus para com a criação.','Como poderio soberano e irresistível de Deus sobre toda criação.','Como cumprimento fiel das promessas da aliança antiga.','Como proteção especial e miraculosa dos eleitos.'),('AT10-L13-Q03','Reversão','Decisão','Preservação','Interrupção'),('AT10-L14-Q04','Expressam a cooperacao do homem com o proposito divino na historia biblica.','Funcionam como rituais magicos que obrigam Deus a agir conforme a vontade humana.','Servem apenas como ornamento literario, sem importancia teologica real na narrativa.','Representam elementos exclusivamente culturais que a Biblia condena em todas as formas.'),('AT10-L14-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT10-L14-Q05','Porque Deus age por meio de causas secundarias e sua soberania permanece oculta.','Porque Deus so age quando seu nome e pronunciado explicitamente pelos homens.','Porque a ausencia do nome divino e impossivel em qualquer texto biblico.','Porque Deus abandona completamente a historia quando seu nome e omitido.'),('AT10-L14-Q06','É o único livro da Bíblia em que Deus nunca é mencionado diretamente','É o único livro escrito originalmente em aramaico no cânon hebraico','Contém a única profecia messiânica direta de toda a literatura veterotestamentária','É o único livro que não faz parte dos manuscritos encontrados em Qumran'),('AT10-L15-Q02','Exigia coragem para permanecer fiel e responsabilidade de guardar a lei no exilio.','Os judeus viviam isentos de qualquer responsabilidade por serem protegidos pelo imperador.','Courage significava resistir militarmente contra o dominio do Imperio Persa.','A responsabilidade dos judeus era apenas pagar impostos e servir ao rei persa.'),('AT10-L15-Q03','Daniel foi lancado na cova dos leoes','Davi enfrentou o gigante Golias sozinho','Jesus jejuou no deserto por quarenta dias','Moises dividiu o mar Vermelho em dois'),('AT10-L15-Q01','Davi e Golias, Ester, Daniel na cova dos leões, Josué e a Terra Prometida, Neemias.','Abraão quase sacrificar Isaque, Sansão e Dalila, o dilúvio com Noé, a Torre de Babel.','Moisés e as pragas do Egito, Caim e Abel, José vendido pelos irmãos, o episódio do bezerro de ouro.','O chamado de Gideão, a vocação de Amós, a construção da arca, o cativeiro da Babilônia.'),('AT10-L15-Q04','NAO SEI','Josue foi coragem liderando Israel na Terra Prometida','Davi demonstrou prudencia ao enfrentar Golias com uma pedra','Jesus revelou sua providencia multiplicando os pães e peixes'),('AT11-L01-Q01','Prólogo em prosa, diálogos poéticos, discurso de Deus e epílogo em prosa.','Narrativa histórica, profecias messiânicas, salmos de louvor e bênçãos finais.','Lei cerimonial, narrativas de guerra, oráculos proféticos e apocalipse.','Genealogias, contratos antigos, hinos sacros e cartas pastorais.'),('AT10-L15-Q05','Salvos da destruição, os judeus celebram o Purim e Haman foi enforcado.','Haman foi honrado e os judeus passaram a servi-lo como súditos.','O rei издаими um novo decreto para destruir os judeus.','Ester foi banida do palácio por sua atitude corajosa.'),('AT11-L01-Q02','Prólogo e epílogo usam prosa narrativa; diálogos usam poesia reflexiva e filosofia.','Prólogo e epílogo pertencem ao Antigo Testamento e os diálogos ao Novo.','Prólogo e epílogo contêm diálogos entre Deus e Satanás; os diálogos apresentam a teodiceia.','Prólogo e epílogo são escritos em hebraico clássico; diálogos usam aramaico.'),('AT11-L01-Q04','No livro de Jó, entre os discursos dos amigos e o de Deus','Nos Salmos, entre os cânticos de louvor e súplica','Nos Provérbios, entre as sabedorias de Salomão','No Gênesis, entre as narrativas dos patriarcas'),('AT11-L01-Q06','Sofrimento produz perseverança, perseverança produz caráter, e caráter produz esperança','O sofrimento é punição divina que deve ser aceita sem questionamento ou reflexão','A restauração vem automaticamente sem nenhum processo de maturação interior','O sofrimento biblico não possui relação com a esperança ou restauração final'),('AT10-L15-Q06','A coragem e a responsabilidade de Ester e Mordecai preservam o povo.','A providência divina age independentemente das ações humanas.','A astúcia de Haman protege os judeus da destruição.','A coragem militar de Dario é o tema central do livro.'),('AT11-L01-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT11-L01-Q03','Tres ciclos de discursos, cada amigo respondendo a Job apos sua lamentacao inicial.','Quatro ciclos completos onde Job sempre inicia e os tres amigos sempre respondem igualmente.','Dois ciclos simetricos com repostas padrao de cinco versiculos para cada interlocutor.','Um unico ciclo longo de 31 capitulos estruturado em perguntas e respostas alternadas.'),('AT11-L02-Q04','Jó aceita com resignação e bendiz a Deus, mas seus amigos o accusam.','Jó amaldiçoa publicamente o nome de Deus por suas desgraças.','Os amigos de Jó reconhecem sua retidão e o consagram como exemplo perfeito.','Jó nega toda sua retidão anterior e implora perdão por seus pecados.'),('AT11-L02-Q03','Job prova que justo pode sofrer sem culpa','Sofrimento castiga todo pecado cometido','Pessoa reta jamais experimenta dor','Sábio evita todo sofrimento na terra'),('AT11-L02-Q02','Deus declara Job íntegro e retosus amigos questionamsua retidão','Noé e sua família são declarados justos por Deus em Gênesis','Abraão intercede por Sodoma e defende a justiça de Ló','Daniel é chamado justo nos capítulos de Jeremias e Ezequiel'),('AT11-L02-Q01','Defende-se que Jó era homem recto, temente a Deus e íntegro, não merecendo o sofrimento','Defende-se que Jó cometeu pecados ocultos que justificavam todo o seu sofrimento','Defende-se que Deus abandonou Jó permanentemente e ele nunca mais foi restaurado','Defende-se que Jó morreu logo no início das pragas sem conhecer a restauração'),('AT11-L02-Q06','Jó reconhece a onipotência e soberania de Deus, e que o homem é limitado em compreendê-lo.','Jó prova que a justiça humana basta para alcançar a salvação eterna por conta própria.','Jó demonstra que todo sofrimento é castigo divino proporcional aos pecados cometidos.','Jó confirma que Deus abandonou o homem e jamais se revela aos que padecem.'),('AT11-L02-Q05','Que Deus reconhece a retidão de Jó, e que o sofrimento não nega sua integridade.','Que Jó precisava conquistar mais justiça para ser aceito plenamente por Deus.','Que a prosperidade material de Jó era prova definitiva de sua retidão.','Que seus amigos estavam certos ao afirmar que Jó era pecador encoberto.'),('AT11-L03-Q02','Satan, que se apresentou diante do Senhor como acusador de Jó','O anjo Gabriel, que actuou como媒intermediário entre Deus e Jó','O próprio Deus, que acusou Jó de ter se afastado dos seus caminhos','O conselho dos anciãos de Uz, que apresentou queixa contra Jó'),('AT11-L03-Q05','Jó desconhecia a conversa entre Deus e Satanás nos céus.','Jó ouviu a conversa celestial quando foi assaltado por anjos.','Deus revelou a conversa celestial a Jó para explicar seu sofrimento.','A conversa celestial foi comunicada a Jó pelos seus amigos durante o diálogo.'),('AT11-L03-Q03','Que Jó só serve a Deus por interesse das bênçãos recebidas','Que Jó adorava ídolos em segredo em sua casa','Que Jó havia furtado ofertas do altar do santuário','Que Jó jurara falso contra seu próximo injustamente')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT11-L03-Q04','Deus nao permite tentacao acima do que podemos suportar.','Deus permite tentacao alem do suportavel para nos humilhar.','As provacoes nao tem limites, sao testes eternos.','Deus estabelece limites apenas para os nao elegidos.'),('AT11-L03-Q01','Os filhos de Deus se apresentaram perante o Senhor, e Satanás veio também entre eles','Anjos cantam hinos de louvor ao redor do trono de Deus','Os quatro seres viventes e os vinte e quatro anciãos diante do trono','A guerra celestial entre os anjos fieis e as hostes de Satanás'),('AT10-L07-Q03','O decreto contra os judeus não pode ser revogado','O decreto pode ser anulado pelo conselho real','Os judeus devem deixar a cidade de Susa','O rei decide deportar todos os persas'),('AT10-L12-Q06','Celebra a salvação dos judeus de Hamã, reforzando identidade e memória.','Comemora a construção do Segundo Templo em Jerusalém pelos retornados do cativeiro.','Lembra a fuga do Egito e a entrega da Lei no Sinai aos descendentes de Abraão.','Celebra a coroação de um novo imperador romano que concedeu liberdade religiosa aos judeus.'),('AT10-L14-Q03','NAO SEI','Atrasos propositais do heroi que adiayam a resolucao','Intervencoes sobrenaturais diretas e inevitaveis','Mudancas abruptas de personalidade dos antagonistas'),('AT11-L03-Q06','O leitor sabe que Jó é provado por Deus, mas Jó ignora o plano celestial','Jó conhece a vontade divina, mas o leitor precisa descobrir o propósito','Os amigos de Jó sabem a causa do sofrimento, mas o leitor desconfia','Deus revela a Jó seu plano antes dos capítulos de diálogo começarem'),('AT11-L03-Q07','NAO SEI','A cena prova que todo sofrimento humano e punicao direta de Deus por pecados especificos.','A cena estabelece que o sofrimento humano nunca tem finalidade pedagogica ou corretiva.','A cena demonstra que Deus causa todo tipo de sofrimento humano sem excecao.'),('AT11-L04-Q02','Elifaz, Bildad e Zofar, amigos de Jó','Moisés, Arão e Miriã, que também sofreram','Abraão, Isaque e Jacó, patriarcas antigos','Elihú, que condenou o sofrimento de Jó'),('AT11-L04-Q01','Jó defende sua inocência e reconhece que Deus é soberano sobre todo sofrimento','Jó reconhece que todo sofrimento é castigo divino proporcional aos pecados cometidos','Jó afirma que o sofrimento prova que Deus abandonou os justos neste mundo','Jó alega que o sofrimento dos inocentes prova que Deus não é justo nem bom'),('AT11-L04-Q05','Deus não puniu Jó por pecados específicos, mas permitiu teste de Satanás e ensina que sabedoria divina excede compreensão humana.','Jó foi punido por duvidar de Deus, por isso perdeu toda sua família e bens como consequência direta de sua incredulidade.','Os amigos de Jó estavam certos ao afirmar que todo sofrimento é castigo divino por pecados pessoais comprovados.','O restante do livro confirma que Jó deveria ter rejeitado a Deus desde o início para evitar o sofrimento completo.'),('AT11-L04-Q03','Sofrimento nao sempre resulta de pecado; a sabedoria de Deus excede a humana','Sofrimento e sempre punicao divina por pecados especificos','A justica humana e superior aos caminhos de Deus','O homem pode compreender plenamente os planos divinos'),('AT11-L04-Q04','Jó se revolta, pranteia e questiona a justiça de Deus, enquanto seus amigos o condenam.','Jó aceita pacificamente o sofrimento sem questionar, agradecendo a Deus por tudo.','Seus amigos o apoiam incondicionalmente e oram por sua recuperação completa.','Jó nega a existência de Deus e abandona completamente a sua fé em público.'),('AT11-L04-Q06','Revela a soberania de Deus e a confiança necessária NEle','Prova que todo sofrimento é castigo divino pelo pecado','Demonstra que o homem pode compreender todos os propósitos divinos','Explica que Deus sempre protege os justos do sofrimento'),('AT11-L05-Q02','Job e seus três amigos, Elifaz, Bildade e Zofar, que discursam sobre a causa de seus sofrimentos.','Moisés, Arão e Miriã, que lamentam a liderança de Deus sobre o povo de Israel.','Davi, Salomão e Jeremias, que lamentam a destruição do templo e do reino de Judá.','Abraão, Isaque e Jacó, que lamentam a perda de suas esposas e descendência.'),('AT11-L05-Q03','A sabedoria está com Deus e o homem não pode descobri-la','A prova de que o justo é testado pelo diabo','A justiça humana pode compreender os propósitos divinos','O sofrimento prova que o homem offendeu a Deus'),('AT11-L05-Q04','Jó lamenta e questiona Deus; amigos o acusam de pecado','Jó aceita seu sofrimento em silêncio resignado perante Deus','Os amigos oram e jejuam até que Deus restaure Jó','Jó amaldiçoa a Deus e todos o abandonam por ímpio'),('AT11-L05-Q01','Jó amaldiçoa o dia do seu nascimento e questiona a razão do seu sofrimento.','Jó reconhece todos os seus pecados e pede perdão a Deus.','Jó faz um acordo com Satanás para recuperar seus bens.','Jó nega a existência de Deus e abandona a fé.'),('AT11-L05-Q05','Os amigos de Jó e Deus ofrecen correções à lamentação de Jó','O restante do livro confirma a lamentação inicial de Jó como perfeitamente justa','Os anjos celestiais aparecem para explicar as razões do sofrimento de Jó','O livro remove toda a lamentação anterior e substitui por louvores'),('AT11-L05-Q06','Mostra que o homem finito não pode compreender os planos do Deus infinito.','Prova que Deus sempre recompensa a fé dos justos de forma direta e visível.','Demonstra que todo sofrimento humano é castigo divino certo e inevitável.','Revela que a paciência silenciosa e resignada é a única resposta aceitável a Deus.'),('AT11-L06-Q01','Elifaz defende que o sofrimento de Jó é castigo divino por seus pecados','Elifaz propõe que Jó deve fazer sacrifícios rituais para ser curado','Elifaz argumenta que Deus é completamente indiferente ao sofrimento humano','Elifaz sugere que Jó deve abandonar completamente sua fé em Deus'),('AT11-L06-Q03','Deus fala pelo sofrimento para disciplinar e corrigir o homem.','O sofrimento é castigo exclusivo dos ímpios e maus.','A sabedoria vem apenas do estudo da lei sem a adversidade.','Deus permite o sofrimento sem propósito pedagógico algum.'),('AT11-L06-Q02','Elifaz, amigo de Jó, discursou nos capítulos 4, 5, 15 e 22 do livro de Jó.','Elifaz liderou o cântico dos levitas no livro de Salmos, capítulos 42 e 43.','Elifaz era um dos profetas que profetizou contra o rei Acabe em 1 Reis.','Elifaz escreveu os livros de Provérbios e Eclesiastes como conselheiro do rei Salomão.'),('AT11-L06-Q05','Deus condena a teologia de Eliphaz, que alegava que todo sofrimento era castigo divino.','O livro confirma que Eliphaz estava certo e que Job foi devidamente punido por seus pecados.','Deus recompensa Eliphaz por sua paciencia e o torna propheta do povo de Israel.','As palavras de Eliphaz sao incluidas nas Escrituras como ensino autorizado de Deus.'),('AT11-L07-Q01','Bildade defende que a afflição é castigo divino pelo peccado','Bildade propõe que Jó renegue a Deus e viva sem lei moral','Bildade ensina que a afflição é prova de que Deus não existe','Bildade defende que os ímpios sempre prosperam e que Deus os abençoa'),('AT11-L06-Q06','NAO SEI','Elifaz demonstra que a sabedoria humana e limitada diante da bondade infinita de Deus','Elifaz prova que todo sofrimento e causado por pecados ocultos do individuo','Elifaz estabelece que Deus sempre recompensa os justos nesta vida'),('AT11-L06-Q04','Jó clama em desespero e questiona, e Elifaz o condena.','Jó aceitra sua sorte e bendiz a Deus, e Elifaz o consola em paz.','Jó e Elifaz discutem como amigos e fazem as pazes logo.','Jó nega a existencia de Deus, e Elifaz confirma sua fé.'),('AT11-L07-Q03','Castigo divino pelo pecado','Sofrimento e prova de fé e perseverança','Sabedoria vem pela prosperidade e abundancia','Justiça divina favorece os impios neste mundo'),('AT11-L07-Q02','Bildade é amigo de Jó e faz discursos nos capítulos 8, 18 e 25 do livro de Jó.','Bildade é propheta que prediz a volta de Cristo nos Salmos de Davi.','Bildade lidera o povo de Israel na saída do Egypto com Moises.','Bildade pregou em Atenas e confrontou o areopago conforme Atos dos Apostolos.'),('AT11-L07-Q04','Jó contesta Bildade, desafiando suas acusações e affirmando sua inocência.','Bildade aceita as palavras de Jó e reconhece publicamente seu erro.','Jó se humilha perante Bildade e pede perdão pelos seus pecados.','Os amigos de Jó condenam Bildade por suas palavras accusatórias.'),('AT11-L07-Q05','Deus repreende Bildade por falar incorretamente sobre Ele','Bildade teve suas palavras confirmadas pelo discurso de Deus','As correções a Bildade vieram principalmente de Jó','Bildade reconheceu sozinho os seus erros no final'),('AT11-L08-Q01','Defendia que Deus todo-poderoso paga ao homem conforme sua maldade','Defendia que Jó era um homem justo e irrepreensivel','Ensinava que o sofrimento humano e uma pura ilusao','Pregava que a paciencia basta para evitar todo castigo'),('AT11-L08-Q02','Zofar, amigo de Jó, discursa sobre a justiça divina no livro de Jó.','Zofar foi um dos doze apóstolos de Jesus Cristo.','Zofar foi o primeiro rei ungido de Israel.','Zofar aparece no livro de Gênesis como patriarca.'),('AT11-L08-Q04','Job contesta Zofar e questiona a justiça divina','Aceitam as acusações e pedem perdão a Deus','Louvam a sabedoria de Zofar e concordam','Mancam de posição e abandonam suas queixas'),('AT11-L07-Q06','Bildad ensina que Deus é justo e puro, enquanto o homem é impuro e limitado.','Bildad sugere que Deus é injusto e parcial, favorecendo os ímpios sobre os justos.','Bildad declara que o homem é igualmente puro e santo diante de Deus, sem limites.','Bildad argumenta que os justos nunca sofrem e que toda dor é castigo divino merecido.'),('AT11-L08-Q03','Defendia que os ímpios recebem castigo e sua prosperidade é breve','Entendia que o sofrimento prova a fé e purifica a alma','Afirmava que Deus trata igualmente justos e ímpios','Dizia que a sabedoria se alcança apenas pelo sofrimento'),('AT11-L08-Q05','NAO SEI','Zofar corregido por Job ao afirmar que Deus e justo e onipotente','Asaccoes de Zofar sao corrigidas pela resposta do Bem-Aventurado','Os discursos de Elifaz e Bildade complementam asaccoes de Zofar'),('AT11-L09-Q01','Job defende sua inocência, questiona a justiça divina e anseia por um mediador com Deus.','Job reconhece seus pecados e pede perdão a Deus por suas obras passadas.','Job aceita a vontade divina sem questionar e louva a Deus por seus sofrimentos.','Job negocia com Satanás a redução de suas pragas em troca de ouro e prata.'),('AT11-L09-Q02','Seus três amigos: Elifaz, Bildade e Zofar','Os filhos de Deus, liderados por Satanás','Os profetas Abraão, Isaque e Jacó','Os reis de Sodoma e Gomorra'),('AT11-L08-Q06','Zofar e corrigido por Deus, que repreende os tres amigos por nao falarem corretamente sobre Ele.','Zofar apresenta a solucao final quando reconhece a grandeza de Deus e a humildade necessaria.','Zofar confirma a justica divina e prova que os limites humanos confirmam a culpa de Job.','Zofar e o unico amigo cuja visao agrada a Deus e e aceito comooraculo verdadeiro.'),('AT11-L09-Q05','Eliú e Deus corrigem que Jó se justificou indevidamente diante de Deus','Deus confirma que Jó estava certo em questionar os caminhos divinos','Os amigos de Jó recebem razão e são absolvidos de suas palavras','Deus ordena que Jó abandone toda esperança de restauração'),('AT11-L09-Q06','Mostraram a limitação humana diante da soberania de Deus','Provavam que Job estava errado e merecia todo o sofrimento que recebeu','Confirmavam que o homem pode compreender completamente os planos de Deus','Demonstravam que a obediência perfeita remove todos os limites humanos'),('AT11-L09-Q03','A sabedoria é mais preciosa que rubis e joias','Jó culpou apenas Satanás por seu sofrimento','Deus revelou a Jó todo o plano do sofrimento','Jó desistiu completamente da fé em Deus'),('AT11-L10-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT11-L10-Q01','Teologia que afirma que toda alegria e todo sofrimento sao punicao ou recompensa divinas.','Teologia que defende que Deus nao interfere diretamente nos assuntos humanos.','Teologia que sustenta a necessidade de se fazer sacrifícios sangrentos diarios.','Teologia que nega a existencia de Satanás como adversário do povo de Deus.'),('AT11-L10-Q02','Porque seguiam a teologia retributiva de que Deus pune o pecado','Porque Jó havia confessado seus pecados em particular','Porque a Lei de Moisés exigia castigo proporcional','Porque Deus lhes revelou isso em visão'),('AT11-L09-Q04','Rasgam as vestes, choram copiosamente e guardam silêncio por sete dias antes de falar.','Lançam fora as túnicas, deitam-se sobre cinzas e começam a discutir com Job imediatamente.','Prostram-se em terra, cobrem a cabeça com panos de linho e oram por sete semanas inteiras.','Rasgam os cabelos, sentam-se no chão e pedem que Job explique detalhadamente cada pecado.'),('AT11-L10-Q05','Jó sofreu sendo inocente, mostrando que a dor não equivale a castigo divino','Jó foi punido por ter se afastado secretamente dos mandamentos','O sofrimento de Jó confirmou que todo castigo é sempre merecido','A prosperidade final de Jó prova que Deus sempre recompensa nesta vida'),('AT11-L10-Q06','Deus se irou contra os amigos porque não falaram dele o que era reto.','Deus elogiou os amigos por consolar Job com palavras sábias e piedosas.','Deus puniu os amigos por terem mentido sobre a vida de Job.','Deus nada disse sobre os discursos, pois eram irrelevantes para o caso.'),('AT11-L10-Q03','O pecado traz consequências reais, como morte, sofrimento e separação de Deus.','As consequências do pecado são apenas metafóricas e desaparecem com o tempo.','As consequências do pecado são causadas principalmente por fatores externos.','O pecado não tem relação com as consequências, que são puramente espirituais.'),('AT11-L10-Q07','Buscar que o sofredor interceda por quem errou em sua conduta pastoral','Exortar o sofredor a perdoar imediatamente sem nenhuma condicao','Ensinar que todo sofrimento e castigo divino por pecados cometidos','Abandonar completamente a pessoa ate que ela pare de se lamentar'),('AT11-L11-Q01','Defende a justiça de Deus e que o sofrimento pode ser disciplina divina.','Afirma que Deus sempre recompensa os justos com prosperidade material.','Aconselha Jó a amaldiçoar a Deus e abandonar toda a sua fé.','Propõe que Jó deve oferecer sacrifícios para demônios malignos.'),('AT11-L11-Q02','Personagem em Job 32-37, discursa contra Jó e destaca a soberania divina.','Um dos tres amigos de Jó que argumenta que o sofrimento e castigo divino.','Sabio em Eclesiastico que ensina sobre a paciencia e a humildade perante Deus.','Lirista que compoe varios salmos de louvor e agradecimento ao Senhor.'),('AT11-L11-Q03','Sofrimento como disciplina que purifica e corrige o homem','Sofrimento e castigo merelyto sem proposito pedagogico','Sabedoria se alcança pelo acumulo de riquezas materiais','Justica divina e determinada pelo julgamento humano'),('AT11-L11-Q04','Jó e seus amigos permanecem em silêncio diante das palavras de Elihu','Jó responde diretamente a Elihu questionando sua autoridade para julgá lo','Os amigos de Jó condenam publicamente a intervenção de Elihu','Elihu pede perdão a Jó antes do Senhor responder do temporal'),('AT11-L12-Q01','De dentro do turbilhão','De cima do monte Sinai','De dentro de uma nuvem','De uma sarça ardente'),('AT11-L11-Q05','Deus nao censurou Eliú como censurou os três amigos de Jó','Deus censurou diretamente Eliú por suas palavras sobre a justiça de Deus','Eliú foi mais condenado que os três amigos por sua presunção','Deus corrigiu Eliú por duvidar da paciência e obediencia de Jó'),('AT11-L12-Q04','A sabedoria divina supera o conhecimento humano, revelando a soberania de Deus.','A sabedoria humana e igual a divina, differing only em grau de compreensao.','Conhecimento humano substitui a sabedoria divina quando baseado em ciencia.','Deus e os homens compartilham a mesma fonte de sabedoria e entendimento.'),('AT11-L12-Q03','Porque o propósito divino era demonstrar soberania, não oferecer explanations.','Porque Satanas ordenou que Deus mantivesse o assunto em segredo celestial.','Porque Deus decidiu que Jó merecia sofrimento sem chance de compreensão.','Porque a cena celestial era considerada herege para ser revelada aos humanos.'),('AT11-L12-Q02','Perguntas retoricas sobre a criacao, a natureza e a ordem do mundo','Perguntas sobre a origem do mal e da corrupcao na humanidade','Perguntas sobre a historia do povo de Israel e suas alianças','Perguntas sobre os mandamentos e a lei mosaica ao povo'),('AT11-L11-Q06','Elihu mostra que Deus fala pelo sofrimento para corrigir o homem e revelar-lhe os limites.','Elihu declara que Job foi salvo por sua justiça e não pela graça de Deus.','Elihu prova que Deus sempre responde aos justos com prosperidade imediata.','Elihu nega que Deus use o sofrimento como forma de comunicação com os homens.'),('AT11-L12-Q06','Nao, os discursos de Deus nao ensinaram que o sofrimento de Jó foi punicao por pecados.','Sim, Deus confirmou que o sofrimento de Jó foi castigo por pecados ocultos.','Sim, nos discursos Deus revelou que Jó pecou secretamente e sofreu por isso.','Deus respondeu que Jó foi punido por seus pecados na tempestade.'),('AT11-L13-Q02','NAO SEI','Sao metaforas poeticas sem significado real','Demonios mencionados em textos apocrifos','Criaturas extintas conhecidas apenas pela paleontologia'),('AT11-L13-Q04','Pela variedade, beleza, perfeição e poder manifestos em cada criatura.','Somente pela obediência estrita às leis e mandamentos divinos.','Por meio de sinais extraordinários e eventos miraculosos.','Através da adoração consciente e do louvor voluntário.'),('AT11-L12-Q05','Agora te vi, e me arrependo em pó e cinzas','Deus me amaldiçoo e destruiu tudo que eu tinha','Perguntei a Deus por que permitiu meus sofrimentos','Perdi toda a fé e abandonei o Senhor'),('AT11-L12-Q07','Pela revelação da soberania divina e o reconhecimento da própria limitação.','Pela aceitação das acusações justas que os amigos fizeram contra Job.','Pela recuperação dos bens materiais e dos filhos que Job havia perdido.','Pela explicação completa que Deus deu sobre as razões do seu sofrimento.'),('AT11-L13-Q01','Beemote: primeira obra de Deus, come capim como bois, forte; Leviatã: criatura terrível e invencível','Beemote é um demônio tentador; Leviatã é um monstro marinho derrotado por Deus','Beemote é um boi doméstico que serve ao homem; Leviatã é uma serpente mansa e dócil','Beemote é um anjo caído; Leviatã é uma baleia gigante criada para alimento dos justos'),('AT11-L13-Q05','O propósito espiritual da Escritura transcende detalhes biológicos','Porque toda espécie biblica tem correspondencia direta na ciência moderna','A identificação exata determina a validade da mensagem divina','Sem saber a espécie moderna, o texto perde completamente seu sentido'),('AT11-L13-Q06','Beemote e Leviatã demonstram que há criaturas invencíveis ao poder humano, reforçando os limites do homem diante da criação de Deus.','Ambas as criaturas foram domesticadas por Job para provar a sabedoria humana.','Beemote e Leviatã representam anjos caídos que simbolizam a arrogância do homem.','Os monstros representam tribos inimigas que Israel deveria conquistar.'),('AT11-L14-Q01','Job reconhece que o homem não pode compreender a Deus e aceita suas limitações','Job defende que o homem é tão sábio quanto Deus e pode questionar Sua vontade','Job nega as limitações humanas e afirma que todos podem alcançar a sabedoria divina','O livro ensina que o homem pode compreender totalmente os propósitos de Deus se buscar com fervor'),('AT11-L14-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT11-L14-Q02','Paulo e o espinho na carne; Pedro duvidou; o jovem rico','Canaã e a terra prometida aos israelitas','Abel e a oferta aceita por Deus ao Senhor','Sansão e a força recebida do Senhor'),('AT11-L14-Q06','NAO SEI','A fragilidade humana elimina completamente a necessidade de Deus na vida das pessoas.','As limitacoes demonstram que Deus e limitado assim como os seres humanos.','A soberania divina anula qualquer relevancia daslimitacoes humanas na experiencia de Deus.'),('AT11-L14-Q04','Jó reconhece a insignificância humana diante da soberania de Deus.','Jó e seus amigos decidem abandonar suas famílias e partir para terras distantes.','Os interlocutores garantem que Jó foi punido por demônios malignos que entraram em sua casa.','Jó nega completamente a existência de qualquer limite humano e exige justiça divina imediata.'),('AT11-L14-Q03','A sabedoria de Deus excede a sabedoria humana','O sofrimento humano anula o plano divino','A justiça humana supera a justiça divina','A sabedoria humana supera a sabedoria divina'),('AT11-L15-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT11-L15-Q03','Tudo coopera para o bem dos que amam a Deus','Deus causa sofrimento para punir todos igualmente','A sabedoria divina ignora a justiça humana','Sofrimento prova que Deus perdeu o controle'),('AT11-L15-Q01','Deus é soberano sobre toda a criação e o sofrimento','Job rejeita a soberania divina diante de seus sofrimento','Satã obtém controle temporário sobre a vontade divina','O sofrimento humano determina a vontade soberana de Deus'),('AT11-L15-Q02','Paulo, Jó, Davi, Isaías e Jesus ensinaram sobre a soberania divina.','Jonas, Rute, Ester e Ageu destacaram a soberania divina em seus livros.','Abraão, Noé, Elias e Eliseu foram os únicos a falar sobre soberania divina.','Pedro, Tiago, João e Judas discutiram a soberania divina nas epistolas pastorais.'),('AT11-L15-Q04','Job se submete e reconhece a soberania de Deus sobre todas as coisas','Job recusa a soberania divina e exige que Deus explique seu sofrimento','Job accuses Deus de injustiça por permitir o sofrimento dos inocentes','Os amigos de Job affirmam que ele so temia a Deus por interesse material'),('AT11-L16-Q01','Para mostrar que a retidão não garante prosperidade material.','Para provar que Deus protege apenas os ricos e prósperos.','Porque Jó era descendente direto dos patriarcas perfeitos.','Para justificar a destruição dos seus bens e família.'),('AT11-L15-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT11-L16-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT11-L16-Q06','A certeza de que um Redentor vive e ressuscitará os mortos.','A esperança de que seus amigos reconheçampublicamente sua inocência.','A promessa divina de restaurar todo o seu gado em vida.','A confiança em sua própria justiça para ser justificado.'),('AT11-L16-Q04','Jó questiona, Lamenta, mas permanece fiel, buscando a face de Deus.','Jó rejeita completamente a existência de Deus após suas perdas.','Jó aceita todas as calamidades sem nenhum questionamento interior.','Jó blameia diretamente Satanás por todas as suas desgraças.'),('AT11-L16-Q03','Seu caso mostra que o sofrimento nem sempre resulta de pecado específico','Todo sofrimento é castigo divino pelo pecado original da humanidade','Jesus confirmou que o cego nasceu assim por pecado de seus pais','O sofrimento humano não tem relação alguma com o plano divino'),('AT11-L16-Q05','Lamentar é confiar em Deus na dor; abandonar é rejeitá-lo completamente.','Ambos são sinais de fraqueza espiritual e devem ser evitados.','Lamentar é duvidar de Deus; abandonar é ter sabedoria.','A Bíblia condena ambos da mesma forma sem distinção.'),('AT11-L16-Q07','Chorai com os que choram e levai as cargas uns dos outros','Abandonar a pessoa para que aprenda a confiar apenas em Deus','Oferecer apenas ajuda financeira sem presença emocional','Julgar a causa do sofrimento antes de oferecer consolo'),('AT11-L17-Q02','Deus, que restituiu o dobro a Jó no final do livro','Os três amigos de Jó, que intercederam por ele','Eliú, que falou sobre a restauração dos aflitos','A esposa de Jó, que o encorajou a manter a fé'),('AT11-L17-Q03','Sofrimento nao implica castigo, e Deus restaura com bondade.','Sofremos apenas por pecar, e a restauração vem pelo merecimento.','Deus abandona os justos para sempre após o sofrimento.','A sabedoria humana supera os propósitos divinos.'),('AT11-L17-Q01','Deus restaura a vida de Jó com mais bens, filhos e saúde.','Jó se torna imortal e habita eternamente com Deus.','Satanás é derrotado e destruído por Jó no final.','Jó recebe poder sobre todos os demônios da terra.'),('AT11-L17-Q04','Jó demonstrou paciencia e o Senhor o restaurou com o dobro de tudo.','Jó amaldicoou o dia de seu nascimento e rejeitou a restauracao','Os amigos de Job celebravam sua ruina com dancas e cantos de alegria','Jó vendeu todos os bens restaurados em sinal de total gratidao'),('AT11-L17-Q05','Deus corrige os amigos e restaura Jó em dobro.','Deus abandona Jó ao final por sua teimosia.','Os amigos de Jó saem vitoriosos na discussão.','Jó perde mais bens e familia apos a restauração.'),('AT11-L18-Q01','Porque Deus os repreendeu por não falarem a verdade sobre Ele, diferentemente de Jó.','Porque Jó era mais sábio que eles e por isso suas palavras tinham mais valor teológico.','Porque apenas as palavras de Jó foram inspiradas pelo Espírito Santo durante o diálogo.','Porque os amigos de Jó eram inimigos declarados de Deus e queriam induzi-lo ao erro.'),('AT11-L17-Q06','Mostra que Deus é soberano e o homem não compreende seus propósitos.','Prova que Deus sempre recompensa os justos por sua paciência.','Demonstra que o homem é justo e Deus deve lhe dar razão.','Indica que a perseverança humana garante a bênção divina.'),('AT11-L18-Q03','A Biblia nao promete prosperidade material a todos os fieis nesta vida.','Porque Deus recompensa apenas os mais fieis com prosperidade.','O Novo Testamento substituiu a promessa de prosperidade pela de saude.','A prosperidade material so e promessa para os apostolos.'),('AT12-L01-Q01','Cinco livros','Três livros','Sete livros','Quatro livros'),('AT11-L18-Q02','Comparando com as Escrituras e a doutrina apostolica','Pela persuasividade rhetorica e a reacao da audiencia ao discurso','Pelo status social e posicao eclesiastica do orador','Pela popularidade e quantidade de pessoas que aceitaram o discurso'),('AT11-L18-Q04','Reduz toda complexidade teológica do sofrimento a uma causa única','Torna Job um texto exclusivamente sobre a guerra espiritual','Prova que Deus nunca permite que seus filhos sofram','Job é apenas uma parábola e não tem valor histórico'),('AT11-L18-Q06','Narrativa registra fatos, personagem expressa visão pessoal, conclusão apresenta doutrina.','Narrativa e conclusão são a mesma coisa, personagem sempre reflete o ponto de vista do autor.','Personagem sempre transmite verdade absoluta, conclusão teológica é apenas opinião humana.','Todas as partes têm igual peso autoritativo e não precisam ser diferenciadas.'),('AT12-L01-Q02','Salmos 41, 72, 89, 106 e 150','Salmos 1, 23, 100 e 150','Salmos 23, 51, 100, 119 e 150','Salmos 1, 41, 72, 89 e 150')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT11-L18-Q05','Somente Deus julga o coração; o homem vê a aparência.','Porque o sofrimento sempre resulta de pecado visível.','Porque devemos julgar segundo a aparência exterior.','Porque Cristo ordenou que acusássemos os outros.'),('AT12-L01-Q03','A doxologia trinitária baseada em 2 Coríntios 13:14','A bênção do sangue de Cristo','A doxologia angélica de Isaías','O cântico dos serafins'),('AT12-L01-Q05','Alguns estudiosos comparam a divisão dos Salmos em cinco livros com a estrutura do Pentateuco.','Os salmos teriam sido compostos directamente a partir do texto do Pentateuco.','A divisão dos Salmos seria baseada na cronologia dos reinados de Israel.','Os cinco livros dos Salmos foram escritos pelo mesmo autor do Pentateuco.'),('AT12-L01-Q06','Grande doxologia conclusiva convidando ao louvor divino com instrumentos','Registra guerras sagradas de Israel contra os povos inimigos','Ensina normas específicas para os sacerdotes no templo','Profecia sobre o Messias que haveria de vir ao mundo'),('AT11-L13-Q03','Insondáveis juízos e inacessíveis caminhos os seus','Juízos manifestos e caminhos simples de seguir','Poder limitado e sabedoria comparável à humana','Condicionalismos humanos e fraquezas naturais'),('AT12-L01-Q04','Os Salmos estão divididos em cinco livros, marcados por doxologias ao final de cada um.','Os Salmos se dividem em dois testamentos conforme o teor das orações.','A divisão em capítulos indica a autoria de cada salmo individualmente.','Os Salmos são organizados cronologicamente segundo os eventos históricos de Israel.'),('AT12-L02-Q01','Paralelismo sinonímico, antitético e sintético entre versos.','Rima consoante e vogais repetidas em cada linha.','Estrutura em estrofes numeradas com títulos em latim.','Uso exclusivo de metros quantitativos gregos.'),('AT12-L02-Q03','Paralelismo','Ritmo acentual','Linguagem apocalíptica','Narrativa histórica'),('AT12-L02-Q04','Por meio do paralelismo, expressando fé, sofrimento e esperança em versos poéticos.','Através de rimas complexas e metros rigorosos como na poesia grega clássica.','Somente por meio de prosa narrativa intercalada com cânticos coletivos.','Por acrósticos hebreus que representam estados emocionais específicos.'),('AT12-L03-Q01','Estrutura poética em que duas linhas expressam ideia semelhante ou oposta.','Métrica baseada em sílabas tônicas como na poesia clássica grega.','Técnica de substituição de palavras por sinônimos no texto sagrado.','Método de contagem das letras de cada verso inspirado no alfabeto hebraico.'),('AT12-L03-Q02','Repetição do sentido com palavras diferentes','Recurso poético que compara dois elementos com base em características comuns','Uso de imagens e metáforas para descrever situações espirituais','Forma de organização textual baseada na alternância de sujeito e verbo'),('AT12-L02-Q06','Enriquece oração e culto com Salmos e paralelismos.','Deve substituir toda liturgia cristã tradicional.','Serve apenas para estudo acadêmico teológico.','Proíbe o uso de música no culto cristão.'),('AT12-L02-Q02','Salmo 119 (paralelismo acróstico), Salmo 23 (poema pastoral) e Salmo 136 (paralelismo sinonímico)','Salmo 2 (canto de coroação), Salmo 15 (requisitos éticos) e Salmo 24 (entrada triunfal)','Salmo 119 (paralelismo), Salmo 78 (narrativo didático) e Salmo 82 (juízo divino)','Salmo 1 (bem-aventurados), Salmo 100 (louvor) e Salmo 150 (hino final)'),('AT12-L03-Q04','O segundo verso completa ou amplia o primeiro, avançando o sentido','O segundo verso repete literalmente o primeiro em palavras diferentes','O segundo verso sempre contradiz o primeiro para criar contraste','O segundo verso apresenta um caso oposto ao primeiro verso'),('AT12-L03-Q03','Contraste entre ideias opostas nos versículos, muito usado nos Salmos.','Método de estudo bíblico que compara textos de diferentes traduções.','Figura de linguagem que repete palavras-chave para ênfase poética.','Técnica narrativa que inverte a ordem cronológica dos eventos bíblicos.'),('AT12-L04-Q02','Salmo 150, Salmo 148 e Salmo 145 sao salmos de louvor','Salmo 51, Salmo 23 e Salmo 137 sao salmos de louvor','Salmo 22, Salmo 42 e Salmo 88 sao salmos de louvor','Salmo 1, Salmo 37 e Salmo 139 sao salmos de louvor'),('AT12-L04-Q01','Celebram os atributos e obras de Deus, convocando o povo ao louvor','Descrevem aflições e súplicas do justo sofredor diante de Deus','Relatam a história da salvação de Israel com finalidades didáticas','Expressam confiança em Deus em momentos de perigo e perseguição'),('AT12-L03-Q05','Para ampliar, contrastar ou completar o sentido do verso.','Porque os poetas biblicos cometiam erros de composicao.','Para confundir os leitores e testar sua fé.','Devido a corrupcao textual ao longo dos seculos.'),('AT12-L03-Q06','Clareia o sentido, amplia ideias e evidencia o tom emocional do verso','Determina a data exata de composicao de cada Salmo','Substitui a necessidade de consultar comentarios biblicos','Identifica quais Salmos foram escritos por Davi'),('AT12-L04-Q04','Por meio de cânticos, lamentos e ações de graças ao Senhor','Por meio de profecias messiânicas e rituais do templo','Através de mandamentos e leis divinas para o povo','Por narrativas históricas dos reis de Israel'),('AT12-L05-Q01','Expressam dor, súplica e confiança na intervenção divina','Celebram vitórias militares e conquistas do povo de Israel','Ensinam regras litúrgicas para sacrifícios no templo','Narram a criação do mundo e a história da humanidade'),('AT12-L04-Q03','Alegria, gratidão e exaltação a Deus','Tristeza e lamento pelo pecado','Medo e desespero diante dos inimigos','Amor romântico entre os fiéis'),('AT12-L04-Q06','Os salmos de louvor expressam gratidao a Deus, guiam a adoracao e fortalecem a fe do crente.','Os salmos de louvor sao oracoes exclusivamente para momentos de tristeza e pranto profundo.','Devem ser recitados apenas em rituais judaicos tradicionais e sinagogas.','Servem principalmente como regras morais para organizar a sociedade humana.'),('AT12-L05-Q03','Lamento, súplica e clamor a Deus na aflição','Celebração festiva com música e dança','Narrativa histórica e genealogia以色列','Ensinamento moral e preceitos legais'),('AT12-L04-Q05','Considerar contexto histórico, gênero poético e natureza corporativa do louvor','Aplicar sempre interpretação estritamente literal, sem recursos poéticos','Ignorar a estrutura literária e o contexto de worship no templo','Tratar apenas como experiências devocionais individuais, sem aspecto corporativo'),('AT12-L05-Q06','Expressando dor e fe a Deus, buscando restauracao na oracao e no culto','Como encantamentos magicos para obter protecao espiritual imediata','Apenas em rituais liturgicos formais, nunca na oracao pessoal','Substituindo completamente os canticos modernos no culto'),('AT12-L05-Q02','Salmo 22, Salmo 6, Salmo 13, Salmo 38','Salmo 23, Salmo 100, Salmo 46, Salmo 103','Salmo 1, Salmo 15, Salmo 24, Salmo 119','Salmo 78, Salmo 105, Salmo 106, Salmo 136'),('AT12-L05-Q05','Considerar o contexto histórico-cultural original da poesia hebraica.','Interpretar os salmos como orações apenas para momentos de felicidade.','Desconsiderar a estrutura literária do salmo ao interpretar.','Ler os salmos de lamento como promessas absolutas sem contexto.'),('AT12-L06-Q01','Louvar a Deus por livramentos e bondade, com memórias de ações divinas passadas.','Lamentação sobre aflições e pedidos de livramento do sofrimento.','Reis coroados entoam cânticos de vitória contra inimigos.','Reflexão sobre a lei divina e suas instruções ao povo.'),('AT12-L05-Q04','Salmos de lamentação expressam fé ao clamar a Deus e esperar Sua salvação.','Expressam dúvida e rejeição da vontade divina, mostrando descrença em Deus.','Celebram apenas a prosperidade material e o bem-estar terreno do fiel.','Rejeitam a intervenção divina e propõem a salvação por esforço próprio.'),('AT12-L06-Q02','Salmos 30, 100, 103, 107, 118 e 136 sao salmos de acao de gracias','Salmos 1, 23, 37, 91 e 119 sao salmos de acao de gracias','Salmos 14, 22, 51, 88 e 90 sao salmos de acao de gracias','Salmos 2, 110, 120, 133 e 139 sao salmos de acao de gracias'),('AT12-L06-Q03','Gratidão e louvor pelo livramento divino','Lamentação e súplica por livramento','Reclamação e murmuração contra Deus','Amaldiçoamento dos inimigos do justo'),('AT12-L06-Q06','Cantando ou recitando salmos de ação de graças a Deus','Lendo exclusivamente em momentos de grande tribulação','Recitando apenas durante celebrações litúrgicas católicas','Cantando sem referência a Deus como destinatário'),('AT12-L06-Q04','Por hinos, súplicas e lamentos que expressam louvor, fé e esperança em Deus.','Por mandamentos e leis divinas que regulam a conduta do povo de Deus.','Por narrativas históricas detalhadas dos eventos do povo de Israel.','Por profecias sobre eventos futuros e a vinda do messias.'),('AT12-L07-Q02','Salmo 23, Salmo 27, Salmo 46, Salmo 91 e Salmo 121 sao salmos de confianza.','Salmo 119, Salmo 137 e Salmo 150 expressam a confiança absoluta do fiel em Deus.','Salmo 1, Salmo 15 e Salmo 24 sao exemplos classicos de salmos de confiança.','Salmo 90, Salmo 106 e Salmo 126 demonstram a confiança do povo de Israel.'),('AT12-L06-Q05','Considerar o contexto histórico, literário e a intenção do autor sagrado.','Devem ser interpretados exclusivamente como poesia sem relevância doutrinária.','Podem ser aplicados literalmente a qualquer situação sem análise contextual.','Precisam ser rejeitados por pertencerem ao Antigo Testamento apenas.'),('AT12-L07-Q01','Declaracao de confianca em Deus como abrigo e protecao contra perigos','Lamentacoes sobre a opressao dos inimigos sem expectativa de livramento','Pedidos de vinganca contra os que perseguem o fiel servo do Senhor','Celebracao de vitorias militares ja ottenhidas pela forca de Israel'),('AT12-L07-Q04','Por meio de lamentos, declarações de fé e esperança em Deus','Através de orações silenciosas sem palavras','Somente pela música instrumental sem letras','Por meio de rituais de sacrifício animal apenas'),('AT12-L07-Q03','Metáforas de Deus como rocha, refúgio e pastor; paz e segurança','Lamentações e apelos desesperados por livramento divino','Narrativas históricas das vitórias do povo de Israel','Ensinamentos sapienciais sobre a lei e os mandamentos'),('AT12-L08-Q01','Ensinam a temer a Deus e vivem segundo a sua lei','Celebram vitórias militares dos reis de Israel e Judá','Profetizam eventos futuros e revelam mistérios divinos','Narram a história do povo hebreu desde a criação'),('AT12-L08-Q02','Salmo 1, Salmo 37, Salmo 49 e Salmo 112.','Salmo 23, Salmo 91, Salmo 139 e Salmo 145.','Salmo 2, Salmo 22, Salmo 110 e Salmo 118.','Salmo 8, Salmo 19, Salmo 104 e Salmo 148.'),('AT12-L07-Q05','Analisar o contexto histórico, gênero poético e a dinâmica entre lamento e confiança.','Tratar os salmos de confiança como mandamentos divinos que garantam saúde e riqueza material.','Ler cada salmo de forma isolada, sem considerar sua posição no livro dos Salmos.','Aplicar diretamente cada salmo ao leitor moderno, ignorando completamente o autor original.'),('AT12-L07-Q06','Recitando-os na oração e no louvor, expressando confiança em Deus nas aflições.','Usando-os como amuletos de proteção escritos em papel para carregar.','Recitando-os para garantir prosperidade financeira e enriquecimento.','Cantando-os como encantamentos para invocar spirits protetores.'),('AT12-L08-Q04','Salmos de sabedoria ensinam a temer a Jehovah e viver segundo a sua vontade.','Salmos de sabedoria são exclusivamente hinos de louvor sem conteúdo reflexivo.','Os salmos de sabedoria negam a existência do sofrimento e da esperança.','Salmos de sabedoria condenam a lei de Jehovah como caminho de salvação.'),('AT12-L08-Q03','Linguagem de instrução e reflexão sobre a lei de Deus','Lamentos de angústia e pedidos insistentes de livramento','Cânticos jubilosos de vitória e celebração militar','Visões proféticas detalhadas sobre eventos apocalípticos'),('AT12-L09-Q02','Salmos 2, 45, 72, 89 e 110 sao salmos reais','Salmos 23, 51, 139 e 150 sao salmos reais','Salmos 1, 119, 127 e 128 sao salmos reais','Salmos 8, 104, 148 e 150 sao salmos reais'),('AT12-L09-Q03','A linguagem real e messiânica','A linguagem de lamento e tristeza','Os símbolos de sabedoria prática','As metáforas de naturezas agrestes'),('AT12-L08-Q06','Como guia para uma vida reta e piedosa diante de Deus','Como encantamentos para proteção espiritual do crente','Para invocar anjos e spirits protetores na adoração','Como ritual mágico para pedir prosperidade material'),('AT12-L09-Q04','Por meio de lamentos, súplicas e louvores a Deus','Por intermédio de guerras santas e conquistas','Por rituais de sacrifício animal e oferendas','Por representações teatrais e danças rituais'),('AT12-L09-Q05','Considerar o contexto histórico e distinguir o rei terreno do Messias.','Desconsiderar o contexto histórico e interpretar apenas como profecia messiânica direta.','Tratar os salmos reais como textos puramente literários sem dimensão espiritual.','Aplicar exclusivamente interpretação alegórica sem considerar o sentido original.'),('AT12-L10-Q01','Profecia sobre Jesus Cristo, seu sofrimento, morte e glória','Salmo que celebra vitórias militares do povo de Israel','Cântico de louvor ao Templo de Jerusalém','Poesia que descreve a criação do mundo'),('AT12-L10-Q02','Salmos 2, 8, 16, 22, 45, 69, 110 e 118','Salmos 1, 15, 19, 24, 50, 85 e 139','Salmos 3, 9, 13, 17, 21, 25 e 27','Salmos 4, 6, 11, 12, 14, 18 e 20'),('AT12-L09-Q06','Os Salmos são usados para orar, louvar eBuscar consolo em Deus.','Os Salmos devem ser recitados apenas no sábado.','Os Salmos foram escritos exclusivamente pelo rei Davi.','Os Salmos só podem ser usados em rituais específicos do templo.'),('AT12-L10-Q03','Pelo princípio da tipologia profética, com sentido imediato Davi e cumprimento pleno em Cristo.','Pela análise crítico-textual que identifica interpolação posterior dos escribas.','Pela mediação da tradição rabínica que atribui automaticamente a Davi toda autoria.','Pela leitura literal que identifica Davi como único autor e Cristo como seu descendente.'),('AT12-L10-Q05','Realeza, sofrimento, sacerdócio e vitória, previstos nos Salmos messiânicos.','Apenas realeza e vitória, pois os Salmos não tratam de sofrimento messiânico.','Sofrimento e sacerdócio exclusivamente, sem menção a realeza ou vitória.','Todos os salmos são messiânicos, sem exceção, conforme tradição cristã.'),('AT12-L11-Q02','Salmos 6, 31, 37, 50, 101, 129 e 142','Salmos 1, 23, 46, 91, 100, 117 e 150','Salmos 15, 24, 85, 93, 96, 97 e 99','Salmos 18, 19, 33, 34, 103, 104 e 107'),('AT12-L11-Q01','Expressam arrependimento e súplica por perdão dos pecados.','Celebram victorias militares e ações de graças a Deus.','Descrevem a criação do mundo e a glória do Criador.','Enaltecem a lei de Deus e ensinam sobre a sabedoria divina.'),('AT12-L10-Q06','Porque o contexto original preserva o sentido e o canônico revela Cristo','Porque o uso canônico substitui completamente o sentido original do texto','Porque a interpretacao messianica deve ser puramente teologica e nao historica','Porque o Espirito Santo substituiu completamente o sentido original das Escrituras'),('AT12-L11-Q03','Lamento, confissão de pecados e súplica por misericórdia','Súplicas por vitória militar e proteção contra inimigos','Hinos de louvor e celebração das bênçãos divinas','Descrições proféticas da vinda do Messias e reino'),('AT12-L11-Q04','Com confissões de pecados, súplicas por misericórdia e esperança na redenção.','Com hinos de vitória celebrando conquistas militares e triumphos terrenos.','Com mandamentos legais detalhando punições para pecados específicos.','Com narrativas históricas do Antigo Testamento sem conteúdo espiritual.'),('AT12-L11-Q05','Contexto histórico-cultural, gênero literário de lamento e aplicação messiânica.','Aplicar diretamente cada verso ao cristão moderno sem considerar o contexto original.','Ignorar o aspecto poético e tratar todos os salmos como narrativa histórica direta.','Considerar apenas a interpretação messiânica, descartando a aplicação direta ao crente.'),('AT12-L12-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT12-L11-Q06','Mediante confissão de pecados, súplica por perdão e consolo divino','Como hinos de celebração e louvor pela victoria alcançada em batalha','Para recitação exclusiva durante asfestas pascais e natalinas','Unicamente para uso doclero e não paraos fiéis comuns'),('AT12-L12-Q05','Como orações que expressam emoções humanas, confiando no juízo justo de Deus.','Como um chamado literal para destruir os inimigos do Senhor.','Como textos ultrapassados que não se aplicam mais aos cristãos.','Como mandamentos de Deus para os cristãos vingarem-se dos ímpios.'),('AT12-L12-Q01','Salmos que contêm imprecações, pedidos de julgamento e maldições contra os inimigos do salmista.','Salmos de louvor dedicados à adoração no templo durante as festas judaicas.','Salmos que narram a vida de Davi desde o pastoreio até ser ungido rei.','Salmos proféticos que predizem a vinda do Messias e sua redenção final.'),('AT12-L12-Q03','Os pedidos alinham-se com a justica de Deus, que revela sua alianca faithful.','Os pedidos seguem a tradicao legalista da justica humana, nao divina.','A justica de Deus contradiz os termos da alianca estabelecidos por ele.','Os pedidos sao irrelevantes para a alianca, pois tratam apenas de pedidos pessoais.'),('AT12-L12-Q07','Nos salmos de lamento, os aflitos clamam a Deus por justicia e libertacao','Somente nos salmos profeticos, nao nos liricos','Apenas por meio de cantos comunitarios de acao de gracias','Exclusivamente atraves de metaforas naturais, sem mencionar opressores'),('AT12-L12-Q04','Porque a vingança pertence a Deus, e não ao homem.','Porque Deus deseja que os homens demonstrem sua ira.','Porque os salmistas não tinham força para se vingar.','Porque a vingança era reservada aos líderes religiosos.'),('AT12-L12-Q06','Desejar justiça é buscar o direito segundo Deus; odiar é guardar amargura no coração, que Deus condena.','Desejar justiça e odiar são a mesma coisa, pois ambos visam punir o próximo segundo a vontade divina.','Odiar é apenas uma forma natural de buscar justiça quando as leis humanas falham em punir.','Desejar justiça é errado porque a vingança pertence somente ao Diabo, não a Deus.'),('AT12-L13-Q02','Salmos 120 a 134, chamados Salmos dos Degraus, entoados por romeiros subindo a Jerusalém.','Salmos 1 a 50, salmos messiânicos proféticos sobre a vinda do Salvador.','Salmos 91 a 100, salmos de proteção divina contra inimigos e perigos.','Salmos 51 a 75, salmos penitenciais de confissão e arrependimento dos pecados.'),('AT12-L13-Q01','Cânticos de louvor dos fieis que subiam a Jerusalem','Salmos profeticos sobre a destruição de nações inimigas','Salmos penitenciais rezados no Templo de Jerusalem','Hinos guerreiros entoados nas batalhas de Israel'),('AT12-L13-Q05','Reconhecer contexto historico de peregrinacao a Jerusalem, seu uso liturgico e a dimensao espiritualmetaforica.','Tratar todos os salmos de peregrinacao exclusivamente como profecias sobre Cristo sem considerar seu significado original.','Ignorar completamente o contexto do Antigo Testamento e interpretar apenas como aplicacoes cristãs modernas.','Considera los unicamente salmos de lamento, sem reconhecer os elementos de acao de gracias e confianca em Deus.'),('AT12-L13-Q03','Saudade e alegria da casa do Senhor','Lamento e pranto pelo exílio na Babilônia','Ira e julgamento contra os inimigos','Medo e terror diante da santidade de Deus'),('AT12-L13-Q06','Usados para expressar dependência de Deus na jornada da vida cristã.','Servem para recitar apenas durante viagens físicas a lugares sagrados.','Devem ser rezados exclusivamente em latim para manter a tradição apostólica.','São orações apenas para ser usadas por líderes religiosos e sacerdotes.'),('AT12-L14-Q01','Salmos que narram eventos da história de Israel como louvor a Deus','Salmos que ensinam princípios de sabedoria divina para a vida diária','Salmos que profetizam eventos futuros do povo de Deus','Salmos que descrevem a estrutura poética em forma de acróstico'),('AT12-L13-Q04','Expressam devoção, reflexão sobre a vida e confiança em Deus durante a jornada.','Celebram principalmente rituais de sacrifício animal no templo.','Descrevem exclusivamente a história da Arca da Aliança.','Contêm profecias sobre a destruição total de Jerusalém.'),('AT12-L14-Q02','Salmos 78, 105, 106, 114 e 136','Salmos 1, 23, 119 e 150','Salmos 51, 32, 130 e 143','Salmos 2, 110, 72, 45 e 22'),('AT12-L14-Q04','Através da narração das obras de Deus na história de Israel e das alianças com o povo.','Somente por meio de lamentações individuais e súplicas pessoais ao Senhor.','Exclusivamente por hinos de louvor sem referência aos eventos históricos.','Por representações teatrais e rituais performedicos realizados no templo.'),('AT12-L14-Q03','Ações de graças e louvor pelas obras de Deus na história','Queixas e murmuração contra os líderes religiosos de Israel','Profecias sobre eventos messiânicos e o fim dos tempos','Descrições detallhadas de rituais e sacrifícios do templo'),('AT12-L15-Q02','Salmos 3,7,18,23,51,52,54,57,59,60,63,142 sao atribuidos a Davi.','Apenas os Salmos 22,23,24 e 110 foram escritos por Davi conforme a tradicao.','Todos os 150 salmos foram compostos integralmente por Davi como salmista.','Davi escreveu apenas os Salmos 119 e 128 por ser seu profile como salmista.'),('AT12-L15-Q01','Salmos inspirados por experiências pessoais e profunda devoção a Deus','Ele é reconhecido como único autor de todos os 150 salmos do Saltério','Seus salmos foram compostos exclusivamente durante seu exílio na Filisteia','A característica principal é a ausência total de elementos emocionais'),('AT12-L14-Q06','Como modelo de oração e louvor, expressando emoções e necessidades humanas a Deus','Apenas como texto histórico, sem aplicação prática na vida moderna','Somente para leitura individual, nunca em contexto comunitário','Exclusivamente para recitação em rituais específicos da tradição judaica'),('AT12-L14-Q05','Considerar o contexto histórico, a finalidade teológica e o gênero literário.','Aceitar todos os relatos como narração literal e objetiva dos fatos.','Ignorar o contexto canônico e ler de forma isolada e devocional.','Aplicar diretamente os eventos ao leitor moderno sem mediação teológica.'),('AT12-L15-Q03','Lamento, arrependimento e louvor em experiência pessoal','Revelação profética exclusivamente messiânica sobre Cristo','Narração histórica de batalhas militares de Israel','Teologia sistemática doutrinária sobre a lei mosaica'),('AT12-L15-Q06','Os salmos de Davi guiam o louvor, a confissão e a súplica do crente.','Os salmos de Davi devem ser recitados apenas no templo judaico.','Davi compos salmos exclusivamente para rituais de sacrifício.','Os salmos de Davi eram usados apenas pelo rei de Israel.'),('AT12-L16-Q01','Diversos autores, incluindo Davi, Asaf, filhos de Corá e levitas.','Um único autor anônimo que compilou todos os salmos.','Apenas profetas do Antigo Testamento escreveram os salmos.','Autores exclusivamente reis e governantes de Israel.'),('AT12-L16-Q03','Lamento, louvor e ação de graças','Narrativa histórica e genealogia','Dogmática teológica formal','Sátira e crítica social'),('AT12-L15-Q04','Por salmos que expressam louvor, súplica e confiança em Deus','Por profecias messiânicas que anunciam a queda de Israel','Por textos que negam a existência do sofrimento humano','Por hinos que glorificam únicamente a natureza e a criação'),('AT12-L16-Q02','Salmo 23: Davi. Salmo 127: Salomão. Salmo 88: Hemã.','Salmo 1: Salomão. Salmo 23: Davi. Salmo 51: Moisés.','Salmo 119: Davi. Salmo 127: Davi. Salmo 150: Salomão.','Salmo 23: Salomão. Salmo 51: Moisés. Salmo 127: Davi.'),('AT12-L15-Q05','NAO SEI','Considerar David exclusivamente como compositor original de todos os 73 salmos que lhe são atribuidos','Aplicar interpretacao puramente literal a todos os salmos davidicos sem considerar os generos literarios','Ignorar o contexto historico e cultural do reino de Israel ao analisar a obra salmica'),('AT12-L16-Q05','Reconhecer o gênero poético hebraico e seu paralelismo.','Ignorar o contexto histórico para universalizar seu mensaje.','Tratar todos os salmos como profecia messiânica direta.','Desconsiderar os títulos e supertítulo dos salmos.'),('AT12-L16-Q04','Por meio de orações, lamentos, hinos de louvor e súplicas sinceras a Deus.','Por meio de profecias cifradas e rituais secretos praticados à noite.','Através de cantos gregorianos e danças rituais nos templos de Jerusalém.','Por intermediação de anjos e rituais de sacrifícios animais no altar.'),('AT12-L17-Q01','Hinos de louvor e lamentos coletivos do culto de Israel','Obras didáticas sobre a lei para instrução do povo','Narrativas históricas dos patriarcas na tradição profética','Intercessões individuais para bênçãos pessoais'),('AT12-L16-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT12-L17-Q04','NAO SEI','Os salmos expressam fé, adoração, sofrimento e esperança porque são preces aprovadas por Deus que demonstram a comunhão do crente com o Criador.','Os salmos sao composicoes poeticas apenas para uso pessoal, sem aplicacao no culto comunitario da igreja.','Os salmos foram escritos exclusivamente para expressar lamento e sofrimento, sem componentes de adoracao ou esperança.'),('AT12-L17-Q03','Lamento','Sátira','Parábola','Narrativa histórica'),('AT12-L17-Q02','Salmo 150, 100 e 95, usados no culto e louvor a Deus','Salmo 1, 12 e 15, salmos de acusação contra inimigos','Salmo 22, 38 e 69, salmos de lamentação por pragas','Salmo 3, 7 e 27, salmos de guerra e proteção militar'),('AT12-L18-Q03','Salmos 16, 110 e 2','Salmos 23, 91 e 121','Salmos 1, 119 e 127','Salmos 51, 130 e 103'),('AT12-L18-Q01','Porque contêm profecias messiânicas e eram centrais na liturgia judaica','Porque foram escritos diretamente pelos apóstolos de Jesus Cristo','Porque são os únicos livros que tratam da vida de Jesus Cristo','Porque foram compostos depois do Novo Testamento ser escrito'),('AT12-L02-Q05','Considerar o paralelismo, o contexto cultural e a linguagem figurada','Desconsiderar o hebraico e basear-se apenas em traducoes em grego','Tratar termos poeticos como se fossem termos teologicos precisos','Ignorar completamente o genero poetico e aplicar sentido literal')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT12-L08-Q05','Considerar gênero literário, contexto histórico e natureza poética.','Ignorar o contexto histórico e aplicar diretamente ao Messias.','Tratar todos os salmos como promessas literais de Deus.','Dispensar o hebraico por ser desnecessário na interpretação.'),('AT12-L09-Q01','Salmos que celebram e intercedem pelo rei de Israel','Salmos que condenam a monarquia e pedem sua extinção','Salmos sobre rituais de caça e alimentação','Salmos que profetizam exclusivamente o fim do mundo'),('AT12-L17-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT12-L18-Q02','Como profecias cumpridas na pessoa e obra de Jesus Cristo','Usando-os apenas como exemplos de oração pessoal','Rejeitando-os por serem textos do Antigo Testamento','Interpretando-os de forma exclusivamente poética e literária'),('AT12-L17-Q06','Os salmos orientam a vida de oracao, louvor e reflexao diaria do crista','Os salmos sao exclusivamente para leitura individual silenciosa sem participacao comunitaria','Os salmos foram substituidos integralmente pelo Novo Testamento e nao tem uso atual','Os salmos devem ser recitados apenas em latim para manter a tradicao da igreja primitiva'),('AT12-L10-Q04','Citações diretas nos sermões e epístolas, explicando morte, ressurreição e messianato.','Os Salmos são aplicados apenas no livro de Apocalipse como profecias literais.','Os Salmos são rejeitados no Novo Testamento como textos judaicos obsoletos.','Apenas Salmo 22 é aplicado a Jesus, pois menciona crucificação específica.'),('AT12-L19-Q02','Analise o contexto, intenção do autor e uso comum da expressão.','Conte o número de vezes que a figura aparece no texto.','Verifique se há rimas ou sons repetidos no trecho.','Traduza para outro idioma e compare os resultados.'),('AT12-L19-Q01','O paralelismo, a linguagem figurada, a métrica e o gênero literário.','A cronologia dos eventos históricos narrados no salmo.','O número exato de versículos e capítulos do saltério.','As notas musicais usadas na execução original do salmo.'),('AT12-L18-Q05','Por meio de tipologia, vendo em Davi sombras e figuras do Messias Jesus Cristo.','Como genealogia literal sem interpretação espiritual, apenas linhagem biológica de Cristo.','Como contraste moral negativo, mostrando os erros de Davi a serem evitados.','Como eventos independentes que confirmam a inspiração histórica da Bíblia.'),('AT12-L18-Q04','Eram cantados em salmos, hinos e cânticos espirituais, como em Cl 3,16','Foram abolidos e substitudos por oracoes originalmente compostas pelos apostolos','Eram recitados em silencio individual, sem participacao comunitaria no culto','Ficaram restritos aos judeus convertidos, sendo proibidos aos cristons gentios'),('AT12-L18-Q06','O uso apostólico ensina que os Salmos apontam para Cristo e cumprimento no Novo Testamento.','O uso apostólico ensina que os Salmos devem ser interpretados apenas de forma literal.','O uso apostólico ensina que os Salmos perderam sua relevância após a morte de Cristo.','O uso apostólico ensina que os Salmos se aplicam exclusivamente ao contexto do Antigo Testamento.'),('AT12-L19-Q03','Porque permite interpretar corretamente a mensagem divina.','Porque determina qual rei大卫 escreveu cada salmo.','Porque facilita a divisão do salmo em estrofes.','Porque permite saber a data exata de composição.'),('AT12-L19-Q04','NAO SEI','Evitar completamente a leitura desses salmos por serem contrarios a vontade de Deus','Usar esses salmos como oracoes de maldicao contra inimigos reais na vida diaria','Interpretar todos esses salmos exclusivamente como profecias ja cumpridas e desactualizadas'),('AT12-L20-Q01','Expressão poética de louvor, lamento e ação de graças ao Senhor','Oração exclusivamente de lamentação e sofrimento humano','Cânticos compostos apenas pelo rei Davi','Coleção de provérbios e ensinamentos morais'),('AT12-L19-Q05','Porque o contexto completo revela a mensagem divina pretendida por Deus.','Porque os salmos foram escritos para serem citados fora de contexto.','Porque traduções modernas são mais confiáveis que o texto completo.','Porque apenas versículos específicos contêm autoridade espiritual.'),('AT12-L20-Q02','Salmo 143:1-2; Salmo 86:1-4; Salmo 90:1-2','Salmo 23:1; Salmo 100:4-5; Salmo 139:23-24','Salmo 1:1-3; Salmo 15:1-2; Salmo 24:3-4','Salmo 8:1-2; Salmo 19:1-4; Salmo 104:1-5'),('AT12-L19-Q06','Fornecem contexto histórico, devotional e revelação messiânica','Confundem mais do que elucidam a compreensão das Escrituras','Rejeitam completamente a relevância entre si para a fé','Substituem a autoridade dos textos sagrados originais'),('AT13-L08-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L08-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L09-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L08-Q05','O temor do Senhor ensina a buscar a verdadeira riqueza e a confiar na provisão de Deus','O temor do Senhor garante prosperidade material imediata e abundante neste mundo','O temor do Senhor remove toda necessidade e sofrimento do crente','O temor do Senhor permite obter riqueza por qualquer meio disponível'),('AT13-L08-Q04','A insensatez leva à ruína e à destruição','A insensatez traz bênçãos materiais garantidas','A insensatez gera sabedoria e prosperidade','A insensatez resulta em paz e segurança eternal'),('AT13-L09-Q01','Provérbios ensina que o liberal para com o pobre empresta ao Senhor, que lhe tornará o benefício','Provérbios condena a generosidade excessiva como desperdício dos bens recebidos','Provérbios ensina que a esmola deve ser dada apenas aos membros da família','Provérbios afirma que a generosidade não traz nenhuma recompensa espiritual'),('AT13-L09-Q02','O sábio espalha e se lhe ajunta mais; o tolo retém mais do que é justo e vem a ter necessidade.','O tolo que dá esmola ao pobre acumula tesouro nos céus; o sábio guarda para si.','O sábio empresta ao pobre e recebe do Senhor; o insensato cobra juro dos necessitados.','O tolo que rega os pobres será fartado; o sábio que retém o seu pão necessitará.'),('AT13-L09-Q05','O temor do Senhor move o crente a generosidade, reconhecendo que toda bênção vem de Deus.','O temor do Senhor gera generosidade pela obrigação de evitar castigos divinos.','O temor do Senhor ensina que a generosidade é meritória para a salvação.','O temor do Senhor justifica a generosidade humana como fonte primária de todas as bênçãos.'),('AT13-L10-Q02','Morte e vida estão no poder da língua','As palavras apressadas destroem a reputacao','A lingua madura expressa a sabedoria','Palavras precipitadas fortalecem vinculos'),('AT13-L09-Q06','Generosidade aplica-se com fé, não como barganha, reconhecendo a soberania de Deus.','Generosidade é uma fórmula certa que garante prosperidade se praticada fielmente.','Devemos exigir que Deus nos recompense conforme a quantia quedoamos.','O princípio da generosidade só vale para quem já é rico efiel.'),('AT13-L10-Q01','A língua tem poder de dar a vida e de causar a morte, de ser árvore de vida e de causar quebrantamento.','A língua tem poder de atraer riqueza e prosperidade, mas também de causar pobreza e ruína.','A língua tem poder de trazer sabedoria divina, mas também de causar demência e loucura.','A língua tem poder de curar enfermidades do corpo, mas também de causar doenças e pragas.'),('AT13-L09-Q04','O que segue aos frívolos terá pobreza de sobras','O homem liberal terá abundância de bênçãos e honras','O que semeia com parcimônia também com parcimônia colhe','O preguiçoso que esconde o seu trigo empobrece a si mesmo'),('AT13-L10-Q03','Tiago 1:19 - Ser tardio para falar e pronto para ouvir traz sabedoria.','Provérbios 18:13 - Responder antes de ouvir revela maturidade espiritual.','João 10:27 - Ovelhas ouvem a voz do Pastor e o seguem.','Romanos 10:17 - A fé vem pelo ouvir a Palavra de Deus.'),('AT13-L10-Q05','A suavidade dos lábios aumenta o ensinamento','O tolo abre sua boca e derrama sabedoria ao mundo','A boca do ímpio profere palavras que alegram a Deus','O falar do sábio deve ser duro e sem agrado'),('AT13-L10-Q06','Provérbios 12:18 - As palavras de sabedoria são medicina para o corpo e alma, trazendo cura.','A fala em línguas exorcisa demônios e imediatamente restaura a saúde física e emocional.','Salmos 23 ensina que palavras de louvor devem ser gritadas para afastar todo sofrimento.','Mateus 7:7 diz que pedir insistentemente em oração remove qualquer enfermidade instantaneamente.'),('AT13-L10-Q07','Do coração procedem as palavras que a boca profere.','A língua comanda os pensamentos que nascem no coração.','Coração e língua são independentes na teologia cristã.','O coração purifica as palavras antes de serem ditas.'),('AT12-L20-Q04','Através de louvores, lamentações, confissões e confianças ao Senhor.','Por meio de rituais mágicos e encantamentos antigos.','Somente pela recitação mecânica sem reflexão espiritual.','Exclusivamente por intermédio de sacerdotes e sacrifícios.'),('AT12-L20-Q03','Lamento, súplica e louvor a Deus em diversas emoções e situações humanas.','Narração genealogica das doze tribos de Israel e suas origens.','Descricao detalhada de rituais sacrificiais do antigo Testamento.','Ensinamentos doutrinarios sobre a natureza da Trindade divina.'),('AT13-L01-Q01','Temor do Senhor é o princípio da sabedoria','Conhecimento adquirido pela razão humana','Busca por riquezas e prosperidade material','Amor ao próximo desprovido de temor a Deus'),('AT13-L01-Q02','Sabedoria biblica e o temor do Senhor que se aplica a vida; acúmulo e apenas guardar dados.','Sabedoria biblica e o conhecimento academico adquiridos nos seminarios teologicos.','Acumulo de informacoes e a capacidade de interpretar as Escrituras corretamente.','Sabedoria biblica e o dom de Deus para memorizar todos os livros da Biblia.'),('AT12-L20-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L01-Q03','Sabedoria é a base; discernimento a distingue; prudência a aplica na vida.','São termos interchangeáveis que significam exatamente a mesma coisa em Provérbios.','Aparecem apenas no Antigo Testamento, nunca sendo mencionados no Novo.','Discernimento supera sabedoria e prudência em importância espiritual no livro.'),('AT13-L01-Q04','A verdadeira sabedoria vem do temor ao Senhor e da obediência aos Seus mandamentos.','A sabedoria bíblica foca apenas no conhecimento intelectual e nos estudos teológicos formais.','O caráter e a obediência são necessários para receber bênçãos materiais e prosperidade.','A sabedoria bíblica ensina que a obediência serve principalmente para evitar sofrimento.'),('AT13-L02-Q02','Porque inicia a compreensao da verdade divina e habilita o discernimento.','Porque a inteligencia humana sozinha ja bastava para alcancar a sabedoria verdadeira.','Porque o homem ja nascia com todo o conhecimento necessario para temer a Deus.','Porque a obediencia as leis religiosas garantiam automaticamente a sabedoria.'),('AT13-L01-Q05','A sabedoria divina se manifesta na ordem da criação e na lei moral de Deus.','A sabedoria humana deriva apenas da experiência e da razão individual.','A criação demonstra desordem, prova de que Deus não é sábio.','A sabedoria existe independentemente de Deus e de sua criação.'),('AT13-L01-Q06','Ensinar sabedoria, prudência e retidão para a vida diária','Preservar a memória dos patriarcas e suas histórias','Estabelecer leis religiosas para o culto sagrado','Registrar profecias sobre o futuro do povo de Deus'),('AT13-L02-Q01','Reverência e obediência a Deus, início da sabedoria','Ter medo do castigo divino como forma de contrôle','Evitar pecar por receio de ser punido','Realizar rituais de adoração nos templos'),('AT13-L02-Q04','O temor do Senhor conduz à sabedoria, que inclui humildade e afastamento do mal.','O temor do Senhor substitui a necessidade de humildade na vida do fiel.','O afastamento do mal é o inicio que leva ao temor do Senhor.','O temor do Senhor e a humildade garantem prosperidade material ao crente.'),('AT13-L02-Q03','O temor do Senhor é reverência amorosa, não terror nem pavor paralyze','O temor do Senhor é terror absoluto diante da natureza divina','São conceitos biblicamente equivalentes e intercambiáveis','O pavor é a forma mais elevada e madura de temor a Deus'),('AT13-L02-Q05','Proporciona sabedoria para discernir o certo do errado','Proporciona submissão cega e medo paralisante','Garante prosperidade material e sucesso financeiro','Remove toda a dúvida e incerteza das decisões'),('AT13-L02-Q06','Comer do fruto do seu próprio caminho e ser saciado com os seus próprios conselhos','Gozar de prosperidade eterna e paz inabalável sem preocupação','Receber sabedoria sobrenatural e dons proféticos sem pedir','Viver em comunhão constante com os anjos do Senhor'),('AT13-L03-Q02','Introduz os temas do livro: temor do Senhor, sabedoria e instrução.','Resume toda a legislação cerimonial e suas aplicações para o culto em Israel.','Apresenta uma biografia detalhada da vida do rei Davi desde a ungção.','Narra a história da criação do mundo e a queda de Adão no Éden.'),('AT13-L03-Q04','Provérbios de Salomão, Provérbios dos sábios, Ditos de Agur e Ditos de Lemuel','Salmos, Cânticos, Lamentações e Odes de Salomão','Provérbios, Eclesiastes, Sabedoria e Sirácida','Sentenças de Salomão, Reflexões dos anciãos, Preces de Agur e Profecias de Lemuel'),('AT13-L03-Q03','Discursos sao lições longas e paternas; provérbios sao ditos breves e paralelos.','Discursos enfatizam leis e mandamentos; provérbios focam em poesía e metáforas.','Discursos sao apenas poéticos; provérbios sao narrativas históricas.','Discursos foram escritos por Salomão; provérbios coletados por outros reis.'),('AT13-L03-Q01','Prólogo (1.1-7), Instruções (1.8-9.18), Provérbios salomônicos (10.1-29.27), Palavras finais (30.1-31.31)','Lei, Profetas e Escritos','Históricos, Poéticos, Proféticos e Apocalípticos','Pentateuco, Históricos, Poéticos, Proféticos e Apocalípticos'),('AT13-L03-Q05','Copiar e preservar os provérbios de Salomão para futuras gerações','Servir como código de leis civis para o reino de Judá','Registrar genealogias da linhagem da casa real davídica','Substituir os mandamentos da Lei de Moisés'),('AT13-L04-Q02','Provérbios sao sabedoria pratica; promessas absolutas sao garantias incondicionals de Deus.','Provérbios e promessas absolutas sao termos sinonimos na Escritura.','Promessas absolutas vem apenas do Antigo Testamento; provérbios do Novo.','Provérbios sao promessas incondicionais e absolutas de Deus ao povo.'),('AT13-L03-Q06','Concluem o livro mostrando a sabedoria prática encarnada na esposa e mãe virtuosa.','Concluem o livro com uma genealogia messiânica que aponta para o Salvador vindouro.','Finalizam o livro contrapondo a sabedoria divina à falibilidade do poder político dos reis.','Encerra o livro com uma profecia apocalíptica sobre o juízo final dos ímpios.'),('AT13-L04-Q03','Considera que proverbios sao orientações práticas, nao promessas absolutas.','Exige interpretacao literal de cada dito, sem considerar o contexto cultural.','Determina que toda afirmação deve ser interpretada como profecia.','Elimina a necessidade de estudo historico-cultural do texto biblico.'),('AT13-L04-Q01','Porque os provérbios são orientações gerais, não promessas absolutas de Deus.','Porque foram escritos apenas para israelitas da antiguidade, sem relevância hoje.','Porque Deus garante cumprimento literal de cada provérbio sem exceção nenhuma.','Porque os provérbios bíblicos são simples enigmas sem importância teológica real.'),('AT13-L04-Q05','O Espirito Santo, o contexto e a experiencia dao discernimento para aplicar provverbios','Provverbios se aplicam literalmente a todos sem necessidade de discernimento','A aplicacao dos provverbios depende apenas da intuicao emocional','O contexto historico da Escrita e suficiente para aplicar provverbios hoje'),('AT13-L11-Q06','NAO SEI','A mentira e sempre pecado, sem excecoes biblicas conhecidas','A verdade deve ser dita sempre, sem considerar o contexto ou intencao','Os principios biblicos sobre verdade e mentira se aplicam apenas em contextos formais'),('AT13-L04-Q06','Gera-se legalismo, desconsiderando contexto e nuancas','Permite relativismo total das Escrituras sagradas','Cria uma espiritualidade sem fundamento biblico','Anula toda a autoridade dos textos biblicos'),('AT13-L12-Q02','O sábio domina a sua ira, mas o tolo derrama a fúria','O tolo é mais paciente que o sábio, pois ignora as provocações','A ira é virtude para o tolo, e o sábio a teme sem controlá-la','O sábio demonstra sabedoria ao expressar livremente a sua ira'),('AT13-L12-Q03','O temor do Senhor e o principio da sabedoria','A soberba e a vaidade do coração humano','A busca por riqueza e prosperidade material','A rebeliao e a desobediencia as Escrituras'),('AT13-L12-Q01','Melhor o paciente que o valente; melhor dominar o espirito que tomar cidade.','Provérbios Ensina que a ira demonstra forca espiritual e deve ser manifestada abertamente.','Provérbios Diz que o paciente e fraco, e dominar o espirito e coisa de medrosos.','Provérbios Ensina que a ira e desnecessaria, pois Deus resolve todos os problemas sozinho.'),('AT13-L12-Q06','Por serem princípios dependentes do Espírito Santo, requerendo crescimento gradual.','Aplicando-os como mandamentos literais, sem considerar o contexto bíblico.','Transformando-os em regras morais que garantem salvação pela obediência.','Ignorando-os por serem apenas figuras de linguagem poéticas.'),('AT13-L13-Q01','Amigo verdadeiro ama em todo tempo e é fiel na adversidade','A amizade deve ser baseada em beneficios mutuos e trocas','Provérbios condena toda forma de amizade e convivio social','Buscar amigos ricos e poderosos é o caminho da sabedoria'),('AT13-L12-Q05','O temor do Senhor, inicio da sabedoria, ensina a tarda ira e dominio proprio','A paciencia vem da forca de vontade humana e nao depende do conhecimento divino','O jejum e a mortificacao do corpo sao os unicos caminhos para controlar a ira','A temperanca e dom natural do nacido de novo, segundo a vontade propria'),('AT13-L13-Q03','Temor do Senhor, prudencia e estudo da Palavra','Orgulho intelectual, ceticismo e rejeicao da tradicao','Confianca apenas na propria experiencia e na razo humana','Indiferenca espiritual, avidez por prazeres e ambicao mundana'),('AT13-L13-Q02','O sábio busca amigos fieis; o tolo com quem anda se perde','O tolo multiplica amigos leais; o sábio se isola em orgulho','O sábio confia em todo amigo; o tolo suspeita de todos','O tolo abençoa os amigos; o sábio amaldiçoa os companheiros'),('AT13-L12-Q04','O que se irra de animo precipitado causa loucura e o excitavel de espirito exalta a loucura','O que tarda em irar-se alcana sabedoria e o prudente herda a vida eterna','O homem de mau genio sera punido com fogo eterno e o Senhor lhe voltara as costas','A loucura do insensato conduz a riqueza e a mansidao e honrada diante dos homens'),('AT13-L13-Q04','Quem se une aos tolos é punido','Ganharás a aprovação dos tolos e prosperarás','Adquirirás sabedoria sem esforço algum','Terás muitos amigos fieis e duradouros'),('AT13-L14-Q03','NAO SEI','Orgulho e autoafirmacao constante','Impaciencia e julgamento rapido','Rebeldia contra a autoridade estabelecida'),('AT13-L13-Q05','O temor do Senhor ensina a escolher amigos que seguem Seus caminhos e evitam os maus.','O temor do Senhor impede que o crente tenha qualquer tipo de amizade.','O temor do Senhor exige que todos os amigos sejam da mesma família.','O temor do Senhor anula a necessidade de discernimento nas amizades.'),('AT13-L14-Q02','A esposa sábia edifica a casa, a tola a derruba com as próprias mãos','O marido sábio governa a casa, o tolo é dominado pela esposa','O casamento sábio traz prosperidade, o tolo traz escassez de filhos','O tolo busca esposa jovem, o sábio busca esposa rica e poderosa'),('AT13-L14-Q01','Quem achar uma esposa acha o bem e recebe favor do Senhor','A beleza exterior é mais importante que o caráter da esposa','O casamento é uma instituição que Provérbios condena','Provérbios ensina que o divórcio é a solução para todo conflito'),('AT12-L20-Q05','Considerar contexto histórico e distinguir vozes humanas e divinas nos salmos','Usar os salmos como promessas literais para todos os crist�os hoje','Ignorar completamente o contexto e orar apenas com sentimentos pessoais','Tratar todos os salmos como profecia messiânica direta'),('AT13-L05-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L05-Q01','A sabedoria é o temor do Senhor; a insensatez despreza a correção.','A sabedoria se alcança pela educação humanista secular.','A insensatez é preferir a humildade à soberba.','A loucura é amar o dinheiro mais do que a vida.'),('AT13-L05-Q02','O sábio guarda o entendimento; o tolo propala a loucura','O rico é sábio e o pobre é tolo segundo as Escrituras','O forte é sábio e o fraco é tolo nas Escrituras','O velho é sábio e o jovem é tolo conforme a Bíblia'),('AT13-L05-Q04','A insensatez traz vergonha pobreza e destruição ao insensato','A insensatez garante prosperidade e respeito dos sábios','O insensato alcança vida longa e protegida por Deus','A insensatez conduz à sabedoria perfeita e glorificação'),('AT13-L04-Q04','Provérbios são princípios sapienciais, não regras absolutas. Cada situação requer discernimento.','Os provérbios devem ser aplicados literalmente sem considerar o contexto da situação.','Os provérbios foram escritos em épocas diferentes e se contradizem intencionalmente.','Os copistas alteraram os provérbios originais introduzindo erros propositais.'),('AT13-L05-Q06','Buscar a sabedoria com temor de Deus, confiando na soberania divina sobre os resultados.','Garantir que todo esforço em sabedoria trará prosperidade material garantida e imediata.','Ignorar completamente os conselhos práticos da Escritura por serem culturalmente datados.','Tratar toda dificuldade como prova direta de insensatez ou falta de fé do indivíduo.'),('AT13-L05-Q05','O temor do Senhor é o princípio da sabedoria e o ódio ao mal.','O amor ao dinheiro orienta a sabedoria e evita a insensatez.','A experiência humana é o guia principal da sabedoria e prudência.','A educação secular revela o caminho da sabedoria e da virtude.'),('AT13-L06-Q01','Não retires a disciplina da criança, porque, fustigando-a, não morrerá','A disciplina dos filhos deve ser deixada por conta da escola e dos professores','O livro de Provérbios não menciona a disciplina dos filhos como dever paterno','Castigar os filhos é pecado segundo os ensinos de Provérbios'),('AT13-L06-Q02','O sábio aceita a disciplina; o tolo rejeita a repreensão e abandona o filho','O tolo disciplina com rigor excessivo; o sábio usa apenas palavras amorosas','Ambos desprezam a disciplina, differing apenas na forma de educar','O tolo corrige os erros infantis; o sábio espera até a idade adulta'),('AT13-L06-Q03','Temor do Senhor, busca pelo conhecimento, prudencia e humildade','Rejeitar toda orientacao espiritual e seguir apenas a razao humana','Buscar poder e gloria pessoal, ignorando os conselhos divinos','Priorizar a aprovacao dos homens acima da vontade de Deus'),('AT13-L06-Q04','A insensatez na disciplina traz vergonha e conduz a alma à perdição','Promete prosperidade material e bênçãos eternas aos filhos','Garante obediência total e paz permanente no lar','Resulta em sabedoria perfeita e vida longa para os filhos'),('AT13-L06-Q06','Com amor e discernimento, reconhecendo que sao principios de sabedoria, nao formulas','Aplicando-os de forma mecanica e inflexivel, sem considerar as circunstancias','Usando-os apenas como promessas literais, esperando resultados garantidos e imediatos','Ignorando-os por completo, tratando toda disciplina como desnecessaria'),('AT13-L07-Q01','A diligence conduz à prosperidade; a preguiça traz pobreza e ruína.','O trabalho e a preguiça sao irrelevantes para a vida espiritual do crente.','A riqueza depende apenas da sorte e nao do esforço humano segundo Provérbios.','Provérbios ensina que a preguiça e uma virtu-de recompensada por Deus.'),('AT13-L13-Q06','Aplicar com discernimento e amor, mantendo o equilibrio e a flexibilidade','Fazer juramentos solenes para provar a lealdade e o compromisso','Tratar todas as amizades de forma identica, sem considerar contextos','Ignorar qualquer principio biblico para evitar promessas absolutas'),('AT13-L14-Q04','Conduz à sepultura e à destruição','Promete paz e prosperidade ao lar','Garante bênçãos e longos anos de vida','Fortalece o vínculo conjugal com amor'),('AT13-L14-Q05','Casamento no temor de Deus: amor, fidelidade e respeito mútuo segundo Sua vontade.','O temor divino exige obediência total da esposa ao marido, sem questionamentos.','Casamento piedoso exige abstinência total de contato físico antes do matrimônio.','O temor divino substitui o amor romântico por dever religioso no casamento.'),('AT13-L11-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L11-Q01','Lábios mentirosos são abominação ao Senhor, mas os fiéis são o seu prazer.','Deus permite a mentira quando é para proteger alguém.','A verdade é relativa, cada um tem a sua própria verdade.','A mentira e a verdade são igualmente importantes para Deus.'),('AT14-L01-Q03','Porque o livro se atribui ao filho de Davi, rei em Jerusalém, título de Salomão','Porque foi o único rei que viveu durante a construção do Templo de Salomão','Porque os manuscritos de Qumran identificam explicitamente o autor como Salomão','Porque o livro menciona o nome divino Javé exatamente mil vezes como Salomão'),('AT14-L01-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L11-Q02','O sábio ama a verdade e fala retamente; o tolo odeia a correção e se deleita na mentira.','O sábio e o tolo igualmente temem a verdade e buscam viver na mentira.','O tolo é mais prudente e guarda a verdade; o sábio se perde em palavras enganosas.','A Escritura não estabelece diferença entre sábio e tolo quanto à verdade.'),('AT14-L02-Q03','Porque hebel significa vapor, futilidade da vida sob o sol, não só orgulho.','Porque Eclesiastes foi escrito originalmente em grego, não hebraico.','Porque orgulho pessoal é virtude segundo os mestres de Israel.','Porque o termo aramaico indica apenas bens materiais e prosperidade.'),('AT14-L02-Q01','Hevel (הבל)','Kavod (כבוא)','Olam (עולם)','Shamaim (שמים)'),('AT14-L01-Q04','O emploiog usa a 3ª pessoa ao falar do Pregador e apresenta estilo diferente do corpo do livro.','A diferenca entre narrador e Pregador baseia-se apenas no numero de palavras usadas por cada um.','O narrador final e distinguido porque traduziu o texto Hebraico para o Grego.','Outros estudiosos distinguem os dois por causa das diferencas entre os nomes dos livros Biblicos.'),('AT14-L02-Q04','Tg 4:14 - a vida aparece por um pouco e logo se desvanece, como o vapor que não deixa vestígio.','Sl 144:4 - o homem é semelhante à vaidade, e os seus dias são como a sombra que passa.','Gn 2:7 - Deus soprou nas suas narinas o fôlego da vida, e o homem se tornou em alma vivente.','Ec 3:20 - todos vão para um lugar, todos são pó, e ao pó tornam-se novamente.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT14-L02-Q05','Os trabalhos, os prazeres, a sabedoria e a vida sob o sol','Os sacrifícios, as orações e os jejuns diante de Deus','A fé, a esperança e o amor que permanece eternamente','A guerra, a fome e as pragas que assolam as nações'),('AT14-L02-Q06','Vaidade leva o leitor a reconhecer a limitaçao humana e buscar Deus','Vaidade ensina que o prazer material e o unico caminho para satisfaçao','Vaidade mostra que a vida terrena ja possui sentido pleno e completo','Vaidade indica que a sabedoria humana basta para resolver todos os problemas'),('AT14-L01-Q06','Porque envolvem metodologias distintas de análise histórica e literária','Porque a Bíblia é um livro sagrado e não precisa de análise crítica','Porque o autor, personagem e data sempre dizem respeito ao mesmo contexto','Porque o mais importante é confirmar a tradição sem questionar fontes'),('AT14-L03-Q01','Refere-se ao mundo terrestre, à existência humana sem referência ao transcendente.','Refere-se ao inferno, lugar de sofrimento eterno após a morte.','Indica a região onde o sol incide diretamente, os trópicos da Terra.','Significa o momento exato em que Cristo voltará ao mundo.'),('AT14-L03-Q02','Tudo é vaidade','Há tempo para cada coisa','Devemos temer a Deus','A alma volta a Deus'),('AT14-L02-Q02','A palavra hebel, do livro de Eclesiastes, significa vaidade','A palavra ruach refere-se ao vento e ao espirito','A palavra nephesh diz respeito a alma e a vida','A palavra olam representa o eterno e o mundo'),('AT14-L03-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT14-L03-Q04','Todas são vaidade e aflição de espírito, sem lucro verdadeiro debaixo do sol.','Cada uma tem valor próprio e propósito eterno para o homem piedoso.','Riqueza e sabedoria superam trabalho e prazer em importância divina.','Prazer e trabalho são boas obras que agradam a Deus eternamente.'),('AT14-L04-Q01','Vaidade das vaidades, tudo é vaidade, sem proveito duradouro sob o sol','Amor perfecto e eterno entre os esposos no cantico dos canticos','Descanso e paz eterna prometida aos fieis que trabalharam','Prosperidade material garantida aos que seguem a lei do Senhor'),('AT13-L15-Q01','Exalta a sabedoria e alerta contra a luxúria e o adultério','Condena toda forma de relacionamento afetivo entre pessoas','Aprova o adultério como caminho para a sabedoria divina','Permite a promiscuidade sexual dentro do casamento'),('AT13-L17-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L14-Q06','Considerar o contexto historico-cultural e distinguir principios universais de aplicacoes temporais.','Aplicar cada texto sobre casamento literalmente, sem nenhuma adaptacao ao contexto atual.','Ignorar todos os ensinos biblicos sobre casamento e seguir apenas sentimentos pessoais.','Tratar apenas o Antigo Testamento como relevante para questoes de casamento.'),('AT13-L17-Q06','NAO SEI','Aplicando-os como mandamentos inflexiveis de lideranca','Seguindo-os ao pe da letra sem considerar o contexto','Transformando-os em regras fixas e imutaveis'),('AT13-L17-Q05','Líderes que temem a Deus governam com integridade e sabedoria.','O temor do Senhor remove a necessidade de líderes com autoridade.','Líderes que temem a Deus seguem seus próprios instintos e ambições.','O temor do Senhor ensina o líder a governar com orgulho e domínio.'),('AT13-L18-Q03','NAO SEI','O estudo constante das Escrituras','A humildade diante da Palavra de Deus','A oração e o jejum'),('AT13-L18-Q06','A Escritura condena a embriaguez e exorta ao dominio proprio e a edificacao do proximo.','A Biblia probe categoricamente qualquer consumo de vinho ou bebida fermentada.','O Cristiano tem total liberdade para beber sem considerar a conciencia alheia.','O Novo Testamento anula completamente todas as instrucoes do Antigo Testamento sobre bebida.'),('AT13-L18-Q01','O vinho escarnece e a bebida forte alborota; evita ambos','Recomenda o uso moderado de vinho para saúde do coração','Timothy devia beber um pouco de vinho pelo seu estômago','Jesus transformou água em vinho, logo o consumo é aprovado'),('AT13-L18-Q02','O sábio evita o vinho; o tolo se deixa enganar pela bebida','O prudente bebe com moderação; o insensato se abstém totalmente','O vinho torna o tolo sábio e fortalece o coração do sábio','O insensato rejeita qualquer bebida; o sábio abençoa o vinho'),('AT13-L18-Q04','Sorrow, disputes, complaints e problemas','Saudade, alegrias, harmonias e vitórias','Bênçãos, prosperidades, consolos e honras','Paz, sabedoria, contentamento e vida longa'),('AT13-L18-Q05','Não se embriagar, ser sóbrio e vigilante, conforme Efésios 5:18.','Beber vinho com moderação é sabedoria, conforme Provérbios 23:30.','O vinho é maldito e totalmente proibido, conforme Gálatas 5:21.','O temor do Senhor permite a embriaguez para glorificar a Deus.'),('AT13-L19-Q01','O temor do Senhor e o inicio da sabedoria, que os que a seguem terem vida.','Escolhas certas garantem prosperidade material sem depende da fearing a Deus.','As consequências das escolhas humanas sao sempre determinadas apenas pelo destino.','A sabedoria permite evitar todo sofrimento, independente de seguir a Deus.'),('AT13-L19-Q04','Destruição, ruína e morte são consequências da insensatez.','Bênçãos materiais e prosperidade são consequências da insensatez.','Vida longa e paz eterna são consequências da insensatez.','Sabedoria instantânea e alegria eterna são consequências da insensatez.'),('AT13-L19-Q03','O temor do Senhor e o inicio da sabedoria','A sabedoria depende da Inteligencia e do raciocinio humano','Ser sabio e evitar toda conversa e contato com outros','A sabedoria se encontra na riqueza e nos bens materiais'),('AT13-L19-Q02','O sábio teme ao Senhor; o tolo é presunçoso','O tolo busca conhecimento; o sábio já possui toda a sabedoria','O prudente se gloria na astúcia humana; o tolo confia no Senhor','O sábio rejeita toda correção; o tolo aceita a instrução'),('AT13-L20-Q01','Provérbios 31:10-31','Provérbios 1:1-7','Provérbios 15:1-22','Provérbios 20:1-29'),('AT13-L19-Q05','O temor do Senhor é o princípio da sabedoria que guia boas escolhas.','O temor do Senhor anula o livre-arbítrio e determina todas as escolhas humanas.','O temor do Senhor permite ignorar consequências, pois Deus perdoa automaticamente.','O temor do Senhor é medo servil de punishments, sem amor ou relação com Deus.'),('AT13-L19-Q06','Buscar discernimento para manter o equilíbrio entre responsabilidade bíblica e a soberania de Deus','Eliminar completamente qualquer menção a consequências para garantir total liberdade','Tratar todos os princípios bíblicos como contratos automáticos com garantias literais','Ignorar completamente as instruções bíblicas sobre escolhas e suas implicações'),('AT13-L15-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L15-Q06','NAO SEI','A Escritura deve ser aplicada conforme a experiencia pessoal de cada individuo','Os principios sobre sexualidade nao se aplicam mais ao contexto contemporaneo','Devemos obedecer apenas aos principios sexuais que nos parecem faceis de cumprir'),('AT13-L15-Q04','Como boi ao matadouro e cervo à rede','Abraão, Sara e os faraó foram liberados','Bênçãos e filhos numerosos na terra','Proteção divina e longa vida em Canaã'),('AT13-L15-Q05','O temor do Senhor leva a viver a sexualidade dentro do casamento heterossexual, conforme a vontade de Deus.','O temor do Senhor ordena que toda relacao sexual seja praticada apenas entre pessoas do mesmo sexo.','O temor do Senhor permite que a sexualidade seja vivida de qualquer forma consensual entre adultos.','O temor do Senhor exige a pratica de celibato total e a reprovacao de qualquer ato sexual.'),('AT13-L16-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L16-Q01','Práticas justas são preferidas por Deus ao sacrifício sem justiça','A justiça deve ser adiada até o fim dos tempos para ser completa','Deus se agrada mais do sacrifício que da justiça prática','O rico sempre tem razão nos tribunais, segundo Provérbios'),('AT13-L16-Q02','O sábio busca a justiça, o tolo rejeita a correção e despreza o conhecimento','O sábio e o tolo seguem ambos os caminhos da justiça indistintamente','O tolo ensina a justiça e o sábio a rejeita por causa do orgulho','A justiça pertence aos insensatos e a sabedoria aos ímpios'),('AT13-L15-Q02','O prudente evita a mulher adúltera; o tolo se entrega à sedução.','O sábio pratica a polygamia como sinal de sabedoria.','O insensato controla seus desejos; o sábio é escravo da carne.','O sábio alcança maior satisfação sexual no casamento.'),('AT13-L17-Q01','Provérbios ensina que o líder sábio governa com retidão e justiça, buscando conhecimento e temendo a Deus.','Provérbios ensina que o líder deve governar com autoridade absoluta, sem consultar ninguém.','Provérbios ensina que a sabedoria não é necessária para a liderança, bastando a força.','Provérbios ensina que o líder deve ignorar conselhos e seguir apenas sua própria vontade.'),('AT13-L16-Q06','NAO SEI','A justica deve ser aplicada de forma literal, sem flexibilidade, para garantir a ordem social','Os principios de justica sao absolute e imutaveis, nao havendo excecoes possiveis','A aplicacao da justica depende exclusivamente da interpretacao humana, sem base nas Escrituras'),('AT13-L16-Q05','O temor do Senhor move a buscar a retidao e afastar-se da impiedade.','O temor do Senhor anula a necessidade de buscar a justica.','O temor do Senhor exige vinganca contra os impios.','O temor do Senhor substitui completamente a sabedoria humana.'),('AT13-L20-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT13-L20-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT14-L03-Q06','Expande a visão para a eternidade, mostrando que esta vida é passageira','Torna a pessoa mais dedicada ao trabalho secular e ao sucesso terreno','Elimina completamente todos os medos e ansiedades da vida presente','Foca exclusivamente nos deveres religiosos sem importar o mundo'),('AT13-L17-Q02','O sábio odeia a maldade e reina com justiça; o tolo espalha a impiedade e destrói a si mesmo','O sábio acumula poder e richesse para si; o tolo serve apenas aos próprios interesses','O sábio governa com mansidão e o tolo com paciência ambas as virtudes','O sábio busca conselho e o tolo também busca, mas ambos obtêm sabedoria'),('AT14-L03-Q03','Pela queda do homem, a terra foi amaldiçoada, tornando a vida laboriosa e frustrante.','Porque Deus permitiu que o homem provasse o bem e o mal no jardim do Éden.','Pela fraqueza da carne e a limitação da mente humana frente aos prazeres.','Porque Deus afastou Sua face do homem após o pecado original no Éden.'),('AT13-L20-Q03','Virtuosa, teme ao Senhor, trabalhadeira, estimada pelo marido','Ela era rica, hermosa y de gran linaje familiar','Descrita como ociosa, ingrata e desconsiderada com o marido','Famosa por sua beleza fisica e por sua vida de ociosidade'),('AT16-L16-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L16-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L16-Q06','João Batista, mensageiro que preparou o caminho, e Cristo, o Senhor que veio ao templo.','Jesus é o unico mensageiro de Deus, sem mencao a João Batista ou preparo previo.','Malaquias foi reescrito integralmente no Novo Testamento sem aplicacao profetica.','O mensageiro prometido foi Elias, identificado como o proprio Jesus nos evangelhos.'),('AT16-L17-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT15-L04-Q04','NAO SEI','Sao temas distintos sem relacao biblica','Aparecem apenas no Antigo Testamento','Referem-se apenas a eventos escatologicos'),('AT15-L05-Q01','Século VIII a.C., durante os reinados de Uzias, Jotão, Acaz e Ezequias','Século VII a.C., durante os reinados de Manassés, Amom e Josias','Século IX a.C., durante o reinado do rei Roboão em Judá','Século VI a.C., durante o cativeiro babilônico do povo de Judá'),('AT15-L04-Q03','Isaías, Ezequiel, Daniel e o Apocalipse','Gênesis, Êxodo e o livro de Levítico','Rute, Ester e o Cântico dos Cânticos','A carta de Paulo a Tito e Filemom'),('AT15-L05-Q02','Uzalias, Jotão, Acaz e Ezequias','Ezequias, Manassés e Amom','Josias, Jeoaquim e Zedequias','Manassés, Amom e Josias'),('AT15-L05-Q03','Três partes: ProtoIsaías (julgamento), DeuteroIsaías (conforto) e TritoIsaías (restauração).','Duas partes: Lei (1-33) e Profetas (34-66), organizadas cronologicamente pelo exílio.','ProtoIsaías (1-39), DeuteroIsaías (40-66), abrangendo apenas julgamento divino.','Narrativa contínua em ordem alfabética, com 22 seções conforme as letras hebraicas.'),('AT15-L04-Q06','Cristo, pela Nova Aliança, осуществляет juízo e restauração, mirando a consumação final','O Antigo Testamento繋ぐ esses temas sem relação com Cristo','Juízo e restauração pertencem apenas ao Antigo Testamento','A Nova Aliança já trouxe a consumação completa sem necessidade de juízo'),('AT15-L05-Q04','Aparece como o dia do Senhor contra Judá e as nações, convocando arrependimento.','Aparece apenas como juízo futuro, sem relação com os eventos presentes do livro.','Aparece somente na forma de destruição dos inimigos de Israel pelo exército hebreu.','Aparece como bênção incondicional prometida a Judá sem necessidade de arrependimento.'),('AT15-L05-Q06','Profeta, Rei, Sacerdote, Servo Sofredor e Filho do Homem','Sacerdote, Profeta, Messias, Deus e Criador do mundo','Juiz, Legislador, Profeta, Anjo e Mensageiro divino','Rabi, Fariseu, Escriba, Zelote e Sumo Sacerdote'),('AT15-L06-Q01','A santidade de Deus e Sua perfeicao absoluta, Ele e separado de todo mal e impuro Isaías 6:3.','A santidade de Deus representa apenas Sua justica nos julgamentos futuros contra as nacoes.','A santidade de Deus e uma qualidade que pode ser conquistada pelo homem mediante jejum.','A santidade de Deus em Isaías se refere principalmente a separacao geografica de Judá.'),('AT15-L05-Q05','Consolacao em Isa 40:1-2; retorno como novo exodo; nova criacao em Isa 43:19 e 65:17-66:22','Sao temas apenas do livro de Jeremias, onde aparecem pela primeira vez na historia profetica','O retorno se refere a conquista de Roma pelos Macabeus, ndo ao exilio babilonico','A nova criacao aparece em Isa 53 como a ressurreicao do servo sofredor que reassumira o trono de Davi'),('AT15-L05-Q07','Cita Isaías para identificar Jesus como o Messais servico e Salvador profetizado.','Isaías nunca é citado no Novo Testamento a respeito de Jesus de Nazaré.','Isaías descreve um Messias guerreiro politico que estabeleceria um reino terreno.','Jesus usou Isaías apenas para fazer analogias poeticas sem relevancia teologica.'),('AT15-L06-Q03','Os serafins clamando: Santo, santo, santo','Os querubins guardando o trono de Deus','O anjo Gabriel e a visao do templo','Os profetas menores e a arca da alianca'),('AT15-L06-Q02','Isaías 6,no reinado de Uzias,visão profética da santidade divina','Êxodo 3,no deserto Sinai,na sarça ardente da revelação','Jeremias 1,no exílio Babilônia,profetizando restauração','Ezequiel 1,no cativeiro,visão do trono celestial'),('AT15-L06-Q05','O pobre exultará no Santo de Israel','A paz sera multiplicada pela gloria de Deus','O justo vivera pela fe no Deus Altissimo','A luz resplandecera sobre os que temem a Deus'),('AT15-L06-Q04','O Deus Santo se revela em juizo e restauracao de Sião','A santidade de Deus impede qualquer juizo sobre o povo de Israel','Isaías ensina que aliança e santidade sao temas independentes','Deus usa santidade para condenar mas nunca para restaurar'),('AT15-L07-Q01','Isaías 42, 49, 50 e 52-53','Isaías 40, 42, 49 e 60','Isaías 1, 3, 5 e 7','Isaías 6, 8, 10 e 12'),('AT13-L16-Q04','NAO SEI','A destruicao das empresas e a ruina dos negocios','A separacao dos amigos e o isolamento social','A escravidao e a servidao aos inimigos'),('AT16-L04-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L04-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L04-Q01','Denúncia da opressão aos pobres e chamado à justiça no Reino do Norte de Israel','Profeta escriba de Jerusalém que defendeu a observaância estrita dos sacrifícios no Templo','Mensagem de prosperidade e bênçãos materiais para o Reino do Sul de Judá','Pregação sobre a necessidade de construir um novo templo em Samaria para adoração'),('AT16-L04-Q02','A injustiça social e a opressão dos pobres','O pecado de adorar ídolos e a infidelidade a Deus','A crise de fé e o abandono das tradições religiosas','A necessidade de purificação ritual e observância cerimonial'),('AT16-L04-Q06','A justica de Deus e cumprida pela fe em Cristo, nao pelas obras da lei (Rm 3.28).','A justica divina e cumprida mediante a observancia rigorosa de toda a Lei de Moises.','O cumprimento da justica de Deus ocorre exclusivamente pelo bautismo e water sanctification.','A justicia sera cumprida apenas no milenio, quando Cristo reinar na terra.'),('AT16-L05-Q03','NAO SEI','JUSTICA E MISERICORDIA SE COMPLETAM NA LEI MOSAICA','O DIA DO SENHOR E TEMA CENTRAL NAS PROFETAS MENORES','ALIANCAS BIBLICAS DEFINEM A SALVACAO HUMANA'),('AT16-L05-Q01','Juízo divino contra Edom por sua soberba e participação na queda de Jerusalém.','Edom foi destruído por Nabucodonosor por suas alianças políticas com o Egito.','Edom se arrependeu e foi restaurado por Deus como povo escolhido.','O livro aborda a aliança entre Israel e Edom contra as nações pagãs.'),('AT16-L04-Q04','Conversao e arrependimento de todo o coracao','Sacrificios continuos e ofertas diarias','Obediencia apenas a metade da lei','Amar ao proximo e esquecer a Deus'),('AT16-L03-Q06','Cumprimento em Atos 2:16-21, quando Pedro declara que a profecia de Joel se cumpriu no Pentecostes.','O cumprimento ocorre apenas em Romanos, quando Paulo fala sobre os dons do Espírito Santo.','Segundo Lucas, a profecia se cumpriu na crucificação de Jesus, quando o véu se rasgou.','O cumprimento acontece em Apocalipse, quando João recebe a visão do novo Pentecostes.'),('AT16-L05-Q02','ORGULHO E TRAIÇÃO FRATERNA DE EDOM CONTRA ISRAEL','A INFIDELIDADE DE ISRAEL AO PACTO E SUA IDOLATRIA CONTÍNUAS','A CRISE DE FOME E MISÉRIA QUE AFETOU OS POVOS DA REGIÃO','A NECESSIDADE DE ARREPENDIMENTO DOS POVOS VIZINHOS DE JUDÁ'),('AT16-L05-Q04','Obediencia','Sacrificio','Dinheiro','Guerra santa'),('AT16-L06-Q01','Para não pregar a Nínive, pois temia que o povo se arrependesse e Deus o poupasse.','Porque temia a ira do rei de Nínive e queria proteger a sua família.','Porque não acreditava que Deus pudesse falar através dele, um profeta simples.','Porque preferia continuar pescando em Társis e não queria deixar o seu trabalho.'),('AT16-L06-Q02','Nínive','Jericó','Sodoma','Belém'),('AT16-L05-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L05-Q06','NAO HA REFERENCIA DIRETA NO NT','ROMAX 9:13 CUMPRE A DESTRUICAO DE EDOM','O NT IGNORA TOTALMENTE O LIVRO DE OBADIAS','A DESTRUICAO DE JERUSALEM CUMPRIU OBADIAS'),('AT16-L06-Q05','Jonas se irritou porque Deus poubou Nínive, pois desejava que a cidade fosse destruída.','Jonas se irritou porque os ninivitas não creram em sua mensagem profética.','Jonas se irritou porque teve que permanecer quarenta dias dentro do peixe.','Jonas se irritou porque Deus não lhe deu autoridade sobre os líderes de Nínive.'),('AT16-L06-Q04','Arrependimento e jejum geral, incluindo homens e animais.','Rejeitaram a mensagem e crucificaram o profeta Jonas.','Pediram um prazo de quarenta dias para analisar a profecia.','Guerquearam e fortificaram as muralhas contra o juizo divino.'),('AT16-L07-Q01','Miqueias profetizou que o Messias nasceria em Belém, pequena cidade de Judá, antes ignorada.','Miqueias viveu no reino do norte e Belém era sua capital religiosa e política.','O governante de Belém era o rei da Babilônia que escravizava Judá na época.','Belém foi o local onde Miqueias ordenou o batismo da multidão em的名称.'),('AT16-L06-Q03','Deus enviou tempestade ao navio e fez um grande peixe engolir Jonas','Anjo do Senhor acompanhou Jonas durante toda a viagem de fuga','Deus permitiu que Jonas chegasse seguro a Tarsis conforme seu plano','Profecia de Elias advertiu Jonas sobre a fuga e suas consequências'),('AT16-L16-Q01','Pós-exílio. Malaquias anuncia o mensageiro que preparará o caminho do Messias.','Exílio na Babilônia. Malaquias adverte Israel contra a adoração de ídolos pagãos.','O mensageiro prometido é o próprio Messias que virá diretamente ao seu templo.','Malaquias escreveu no século VIII AC, antes dos demais profetas menores.'),('AT16-L16-Q02','A infidelidade do povo, o culto indigno e a dúvida sobre o amor de Deus','A ganância dos comerciantes e a corrupcao nos tribunais','A preguiça e a indiferença religiosa do povo','A apostasia total e o abandono completo da lei'),('AT16-L17-Q01','Profetas pré-exílicos condenavam a injustiça e chamavam à conversão.','Profetas que escreveram durante o cativeiro babilônico sobre a restauração futura.','Profetas que profetizaram após o retorno do exílio babilônico à Terra Prometida.','Profetas que apenas prediziam eventos futuros sem chamar o povo à conversão.'),('AT16-L16-Q04','Obediência e serviço ao Senhor','Sacrifícios e ofertas em abundância','Fé nos deuses dos povos vizinhos','Riqueza e primícias das colheitas'),('AT16-L17-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L17-Q04','Que praticassem a justicia, amassem a misericordia e temessem ao Senhor','Que oferecessem sacrifícios e holocaustos continuamente no altar','Que guardassem todos os mandamentos sem excecao alguma','Que jejuassem e fizessem oracoes prolongadas cada dia'),('AT16-L18-Q03','NAO SEI','Sao elementos da teologia reformada sistematica','Aparecem na literatura apocaliptica deuterocanonica','Sao conceitos interchangeis na teologia joanina'),('AT16-L18-Q02','A infidelidade espiritual e o adultério contra Deus','A ausência dos sacrifícios no templo sagrado','A pobreza extrema do povo hebreu','A rebelião contra César romano'),('AT16-L18-Q01','Esperança e restauração durante o exílio babilônico','Punição eterna e sofrimento contínuo do povo','Vitória militar contra os babilônios','Rejeição completa da aliança e das promessas'),('AT16-L18-Q04','Obediência, amor e temor ao Senhor','Sacrifícios e ofertas no templo','Jejum e abstinência total','Riquezas e dízimos abundantes'),('AT16-L18-Q06','Cristo cumpre as profecias de Ezequiel e Daniel sobre o Messias restaurador.','João Batista é identificado como o profeta Ezequiel redivivo na Terra.','O templo espiritual de Ezequiel é construída pelos apóstolos em Roma.','Daniel previu a queda do império americano, cumprir-se no século XXI.'),('AT15-L06-Q06','A santidade de Deus em Isaías revela Cristo como o Santo que nos justifica','A santidade em Isaías refere-se apenas à separação ceremonial do templo','Isaías ensina que a santidade de Deus foi cancelada pela graça do Novo Testamento','A santidade divina em Isaías só terá relevância na consumação final, sem relação com Cristo'),('AT14-L04-Q03','A impossibilidade de o homem gozar dos frutos do seu trabalho, pois tudo envolve vaidade e passam a outros.','A bênção divina que garante prosperidade e sucesso em todo trabalho realizado pelo homem.','A tentação da preguiça e da ociosidade como maiores obstáculos à realização humana.','A capacidade ilimitada do homem de criar, transformar e dominar todas as coisas.'),('AT14-L04-Q02','Parábola dos talentos','Narrativa da arca de Noé','Milagre da multiplicação dos pães','Revelação do monte Sinai'),('AT16-L02-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L01-Q06','Conhecendo a Deus, compreendemos sua misericórdia e respondemos com fidelidade à aliança.','Conhecer a Deus exige abandonar toda forma de misericordia em nome da obediencia rigorosa.','A fidelidade à aliança e substituta pelo conhecimento teologico academico sem experiencia pratica.','Misericordia e fidelidade sao qualidades humanas que definem o criterio para conhecer a Deus.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT16-L02-Q02','Desvio de Deus e necessidade de arrependimento','Guerra contra nações inimigas invasoras','Fome e escassez de recursos naturais','Perda de direitos e liberdade граждан'),('AT16-L02-Q04','Obedecer à Sua voz','Rejeitar os sacrifícios','Abandonar os mandamentos','Servir a outros deuses'),('AT16-L03-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L02-Q06','Cumprido em Atos 2 no Pentecostes, quando o Espírito foi derramado.','Cumprido na natividade de Cristo, conforme Mateus 1:22-23, na encarnação.','Anunciado na crucificação de Cristo, conforme João 19:28-30, no sacrifício.','Revelado na ressurreição de Cristo, conforme Romanos 1:4, o poder divino.'),('AT16-L03-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT16-L03-Q02','Arrependimento do pecado e restauração nacional','A busca por prosperidade material e riqueza','O abandono completo da aliança com Deus','A necessidade de novos líderes religiosos'),('AT16-L03-Q04','Arrependimento e obediencia','Sacrificio de animais','Dinheiro e ofertas','Jejum e penitencia'),('AT16-L02-Q05','Jeremias 29:11 - prometo planos de paz, prosperidade e esperança futura','Joao 3:16 - Deus amou o mundo ao ponto de dar seu filho unigenito','Salmo 23:1 - o Senhor e meu pastor e nada me faltara','Hebreus 11:1 - a fe e a certeza das coisas que esperamos'),('AT16-L18-Q05','Jeremias 29:11 - Promessa de planos de paz, esperança e futuro, não de mal','Gênesis 1:1 - No princípio criou Deus os céus e a terra','Salmo 23:1 - O Senhor é o meu pastor, e nada me faltará','Mateus 6:33 - Buscai primeiro o Reino de Deus e a sua justiça'),('AT15-L07-Q02','Ser alianca do povo e luz dos gentios, segundo Isaías 42:6','Proclamar a lei no Sinai e guiar Israel pelo deserto','Destruir os impérios mundiais e estabelecer o reino militar de Deus','Anunciar o arrependimento e batizar com água no Jordão'),('AT18-L12-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L12-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L11-Q03','NAO SEI','Juizo da aliança representa a promessa incondicional de Deus ao seu povo escolhido','A providencia divina se manifesta atraves da intervencao miraculosa na historia','O juizo da aliança indica que Deus cumpre sua Palavra sem excecoes'),('AT18-L13-Q03','Esdras','Zorobabel','Neemias','Ciro'),('AT18-L13-Q04','Neemias lidera a reconstrução dos muros de Jerusalém na fase final da restauração pós-exílio.','Neemias escreveu os Salmos durante a restauração de Israel.','Neemias profetizou sobre o Messias durante o cativeiro.','Neemias construiu o Templo de Salomão restaurado.'),('AT18-L13-Q01','Os retornos sob Zorobabel, Esdras e Neemias.','Os retornos sob Ciro, Dario e Artaxerxes ao templo.','O retorno de Israel durante o exílio babilônico.','Os retornos sob os patriarcas Abraão, Isaque e Jacó.'),('AT18-L13-Q05','Templo, Lei e muralhas','Sacrifícios, profecias e cânticos','Reino, sacerdocio e primícias','Exílio, libertação e batalha'),('AT18-L13-Q02','Josué, o sacerdote','Ageu, o profeta','Ciro, rei da Pérsia','Esdras, o escriba'),('AT18-L12-Q06','Cumprindo a profecia de Isaías, Ciro permitiu a volta do povo e a reconstrução do templo.','Ciro extinguiu o cativeiro babilônico e restabeleceu a monarquia davídica imediatamente.','Ciro ordenou a reconstrução do templo sem a participação dos judeus, eliminando a esperança.','O decreto de Ciro proibiu os judeus de retornar, gerando desespero entre o povo.'),('AT18-L14-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L14-Q01','O templo foi reedificado sob liderança de Zorobabel após o exílio babilônico.','O templo foi construído pelo rei Salomão para substituir a tenda do encontro no deserto.','O templo foi reedificado sob liderança de Neemias quando os muros da cidade foram concluídos.','O templo foi destruído novamente durante o exílio e nunca mais foi reconstruído.'),('AT18-L14-Q05','NAO SEI','Com oracoes','Com guerra santa','Com fugida em massa'),('AT18-L14-Q02','Ciro, Dario, Zorobabel, Ageu, Zacarias e Esdras','Salomão, Davi, Nabucodonosor e Alexandre, o Grande','Herodes, Pilatos, Tibério e Nero','Elias, Eliseu, Isaías e Jeremias'),('AT18-L13-Q06','Por apatia e negligencia do povo que deixa de edificar a casa de Deus.','Porque os povos vecinos impediram por completo a reedificacao do templo.','Porque Deus nao completou a restauracao devido a incredulidade do povo.','Porque o templo nao podia ser reedificado depois da destruicao total.'),('AT18-L14-Q04','Restauracao do culto em Jerusalem e fortalecimento da identidade judaica','Instituicao da democracia direta entre os adoradores do Senhor','Formacao de um reino independente sob governo monarquico','Estabelecimento de uma teocracia militar separatista'),('AT16-L06-Q06','Deus tem compaixão e amor pelo ser humano','O vento, o verme e a planta simbolizam a Santíssima Trindade','Devemos cuidar de toda criação de Deus','Deus respeita a liberdade do homem de pecar'),('AT18-L07-Q01','Perderam o culto no Templo e passaram a adorar em sinagogas, mantendo a Lei.','Construíram novos templos em Alexandria e Antioquia para continuar os sacrifícios.','Adotaram completamente a cultura babilônica e abandonaram suas tradições.',' foram libertados imediatamente por Ciro e retornaram todos a Jerusalém.'),('AT18-L07-Q02','Mantiveram synagoga, estudo da Lei e orações doméstica.','Abandonaram práticas religiosas por não terem templo.','Substituíram templo por santuários de ídolos pagãos.','Convieram-se às religiões dos povos entre os quais viviam.'),('AT18-L07-Q03','Manter a fé e a identidade do povo durante o cativeiro na Babilônia','Conquistar o favor do imperador babilônico e obter poder político na região','Eliminar todos os costumes e tradições religiosas do povo de Israel','Substituir completamente a esperança da restauração de Jerusalém'),('AT18-L07-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L07-Q04','NAO SEI','Aparecem como elementos de pureza cultural e resistência nacional contra invasores','Manifestam-se como símbolos de prosperidade e integração Harmônica entre povos','Surgem como marcas de opressão e desafios à identidade do povo de Deus'),('AT18-L06-Q06','Destruição do templo cumprimento profecia e esperança messiânica.','Templo nunca foi destruído, apenas reformado pelos romanos.','Destruição do templo extinguiu toda esperança messiânica.','Quem destruiu o templo foi reconhecido como o Messias.'),('AT18-L08-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L08-Q02','Nabucodonosor, Ciro, Belsazar e o Império Babilônico.','Alexandre Magno, Herodes e o Império Romano.','Faraó do Egito, Dario da Média e os reis de Judá.','Sansão, Gideão e os juízes de Israel.'),('AT18-L07-Q06','O exílio levou à centralização da Lei e da sinagoga como forma de organização comunitária judaica.','O exílio resultedou na dissolução total das práticas religiosas judaicas durante o período babilônico.','O exílio promoveu a fusão completa da fé judaica com as religiões cananeias da região.','O exílio eliminou completamente a necessidade de líderes religiosos entre o povo judaico.'),('AT18-L08-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L08-Q04','Sinagogas, maior enfoque na Lei escrita e fortalecimento da identidade judaica em diáspora.','Conversão em massa dos povos vizinhos à fé mosaica durante o período exilar.','Dissolução completa das tradições religiosas judaicas sob dominação babilônica.','Estabelecimento de um reino messiânico imediato após a queda de Jerusalém.'),('AT17-L08-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT17-L08-Q05','Divisão em Israel e Judá, com cultos rivais e instabilidade política constante.','Formação de um único reino teocrático sob liderança dos sumos sacerdotes.','Aliança permanente entre os dois reinos contra todas as potências estrangeiras.','Fim de toda prática religiosa e desaparecimento completo da fé no Senhor.'),('AT17-L09-Q02','Reino de Israel, com capital em Samaria, tendo Jeroboam como primeiro rei','Reino de Judá, com capital em Hebrom, governado por Saul','Império Assírio que conquistaram Israel em 722 a.C','Reino de Israel durante o cativeiro babilônico no século VI a.C'),('AT17-L08-Q06','A divisão das tribos gerou expectativa de um futuro rei davídico restaurador da unidade.','A divisão das tribos extinguiu a esperança messiânica ao revelar a falha do plano divino.','O rei messiânico surgiu durante a divisão para governar apenas as tribos do norte.','A separação dos reino removeu a linhagem davídica das profecias messiânicas.'),('AT17-L09-Q03','Pela obediência fiel à Lei de Moisés e aos termos da aliança divina.','Através da adoração exclusiva no templo de Jerusalém e suas tradições.','Pela implementação de leis locais e costumes das nações vizinhas.','Por meio de alianças políticas com os reinos circun-adjacentes.'),('AT17-L08-Q03','A divisão ocorreu por desobediência à aliança do Senhor','A divisão foi legítima porque o povo assim a quis','Tribos possuíam direito de separar-se pela Lei','Cada tribo podia adorar conforme sua preferência'),('AT17-L09-Q04','NAO SEI','Sucessos como a fé de Abraão e fracassos como a incredulidade de Tomé','Sucessos como a paciência de Jó e fracassos como o orgulho de Nabucodonosor','Sucessos como a devoção de Maria e fracassos como a negação de Pedro'),('AT17-L09-Q01','Reino das dez tribos, capital Samaria, cativeiro assírio em 722 a.C.','Reino das doze tribos que manteve adoração exclusiva a Javé em Jerusalém.','Reino das duas tribos que foi levado em cativeiro para a Babilônia.','Reino que se manteve fiel aos mandamentos e nunca foi conquistado.'),('AT17-L10-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT17-L09-Q05','Divisão do reino, idolâtria, guerras com Judá e queda de Samaria aos assírios.','Fusão religiosa com Judá e criação de uma nova capital em Samaria.','Aliança duradoura com os assírios e prosperidade econômica.','Estabelecimento de uma monarquia sagrada e paz permanente com Judá.'),('AT17-L10-Q03','Pela obediência à Lei e fidelidade à aliança no Templo.','Por meio da adoração de ídolos e abandono total da Lei mosaica.','Através da aliança militar com as nações pagãs vizinhas.','Pela concentração do poder absoluto nos sacerdotes sem lei.'),('AT17-L10-Q01','Teve Jerusalém como capital e linhagem davídica','Teve Samaria como capital e adoração a bezerros de ouro','Foi conquistado pelos assírios no século VIII a.C.','Reino que durou menos de 200 anos até sua queda'),('AT17-L10-Q02','Egito, Ptolomeu, José, Faraó','Assíria, Nínive, Senaqueribe','Roma, Tibério, Pilatos','Babilônia, Ciro, Nabucodonosor'),('AT17-L10-Q06','Preserva a linhagem davídica e a promessa messiânica do Messias.','Proporciona recursos militares para estabelecer o reino messiânico.','Mantém os santuários pagãos como preparação para a vinda do Messias.','Isola-se das outras tribos para proteger a pureza da promessa.'),('AT17-L11-Q03','A dinastia de Davi','A dinastia de Saul','A dinastia de Jeroboão','A dinastia de Acabe'),('AT17-L11-Q01','Sucessão de reis de uma mesma família ou linhagem','Sistema de governo onde o povo escolhe seus governantes','Grupo de sacerdotes que administravam o templo sagrado','Aliança política entre nações para formar um império'),('AT18-L15-Q03','NAO SEI','Aparecem como ferramentas complementares de Deus para governar a criação','Representam a怒 colère e misericórdia de Deus expressas na lei cerimonial','Surgem como resultantes da tensão entre lei e graça na teologia paulina'),('AT18-L15-Q01','Neemias reedificou os muros de Jerusalém após o cativeiro na Babilónia.','Esdras reedificou os muros de Jerusalém sob ordem do rei Dario.','Jeremias profetizou a reconstrução dos muros durante o exílio babilónico.','Os muros de Samaria foram reedificados como símbolo da restauração.'),('AT18-L14-Q06','A reconstrução do templo simbolizou a fidelidade de Deus à aliança e reacendeu a esperança messiânica.','A reconstrução do templo anulou a necessidade do Messias, tornando-o opcional para a salvação.','O templo reconstruído foi erguido após a vinda de Jesus, confirming a messianidade dele.','A reconstrução foi iniciativa de Esdras, que profetizou sozinho sobre a vinda do Messias.'),('AT18-L15-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L15-Q02','Neemias e o rei Artaxerxes do Imperio Persa','Ciro e Daniel lideraram a reedificacao de Jerusalem','Dario e Ageu supervisionaram a construcao dos muros','Zorobabel e os sumos sacerdotes ergueram os muros'),('AT18-L15-Q04','Renovação da aliança, restauração do culto e reorganização política em Judá','Estabelecimento de um novo reino militar independente em Jerusalém','Conversão em massa dos povos gentílicos circundantes','Construção do Segundo Templo profético sob orientação de Neemias'),('AT18-L16-Q03','NAO SEI','Sao conceitos que se referem exclusivamente ao plano fisico da realidade','O juizo da alianca e a providencia divina sao ideias contraditorias entre si','Ambos pertencem exclusivamente ao ambito da teologia reformada atual'),('AT18-L08-Q06','Profecias sobre o Messias e restauração de Israel motivaram esperança de redenção.','Profetas ensinaram que a restauração dependia da obediência estrita à Lei.','Os profetas foram rejeitados pelo povo, extinguindo a esperança messiânica.','Ezequiel e Daniel profetizaram apenas sobre a destruição final de Judá.'),('AT18-L09-Q01','Daniel foi preso e profetizou na Babilônia durante o exílio.','Daniel construiu o templo em Jerusalém durante o exílio.','Daniel foi morto na Babilônia pelos caldeus.','Daniel regressou a Judá antes da queda da Babilônia.'),('AT16-L19-Q01','Chamada à fidelidade, reconstrução do templo e restauração da comunidade apos o exilio.','Proclamacao de julgamento iminente e destruição total de Judá pelos inimigos.','Ensinamentos sobre a conquista militar de Canaã e guerra santa contra pagãos.','Preceitos detalhados sobre leiscerimoniais, cleançao ritual e santificação do sabado.'),('FB01-L05-Q05','Isaías, Jeremias, Ezequiel, Daniel e Lamentações de Jeremias','Os doze profetas menores do Antigo Testamento','Amós, Oséias, Isaías, Miquéias, Jonas e Abdias','Provérbios, Jó, Eclesiastes, Cânticos e Salmos'),('FB01-L05-Q04','Salmos, Provérbios, Jó, Cânticos, Eclesiastes e Lamentações','Salmos, Provérbios, Jó, Hebreus, Tiago e Filipenses','Salmos, Cânticos, Ageu, Abdias e Jonas','Provérbios, Eclesiastes, Lamentações, Gênesis e Êxodo'),('FB01-L05-Q07','Gospels, Epístolas Paulinas, Epístolas Gerais e Apocalipse.','Pentateuco, Livros Históricos, Poéticos e Proféticos.','Evangelhos, Atos, Epístolas, Profecia e Apocalipse.','Salmos, Provérbios, Eclesiastes, Cânticos e Apocalipse.'),('FB01-L05-Q06','Oseias, Joel, Amós, Obadias, Jonas, Miquéias, Naum, Habacuque, Sofonias, Ageu, Zacarias, Malaquias.','Isaías, Jeremias, Lamentações, Ezequiel, Daniel.','Gênesis, Êxodo, Levítico, Números, Deuteronômio.','Mateus, Marcos, Lucas, João, Atos dos Apóstolos.'),('FB01-L05-Q08','Mateus, Marcos, Lucas e João','Mateus, Marcos, Lucas, João e Atos dos Apóstolos','Mateus, João, Romanos e Coríntios','Mateus, Marcos, Lucas e Gênesis'),('FB01-L04-Q07','Evitar abreviaturas ambiguas como J, Cr ou Pv que confundem livros diferentes','Usar apenas as tres primeiras consoantes de cada livro biblico garante clareza universal','Incluir sempre o numero do capitulo imediatamente apos a abreviatura do livro','Substituir numeros ordinais por CARDINAIS como Primeiro Segundo para todos os livros'),('FB01-L06-Q01','Consultar o índice no início da Bíblia, que lista todos os livros em ordem.','Procurar no índice localizado no final da Bíblia.','Usar os marcadores coloridos nas laterais das páginas.','Buscar por palavras-chave no meio do texto.'),('FB01-L05-Q10','A diferenca esta no tamanho dos livros, nao na importancia ou autoridade.','Os maiores escreviam para reis e os menores apenas para o povo comum.','Os profetas maiores sao mais antigos cronologicamente que os menores.','Os maiores foram escritos em hebraico e os menores apenas em aramaico.'),('FB01-L05-Q09','Paulo: Rom, 1-2 Co, Gl, Ef, Fp, Cl, 1-2 Ts, 1-2 Tm, Tt, Fm (13). Gerais: Hb, Tg, 1-2 Pe, 1-3 Jo, Jud (7).','Paulo: Rom, 1-2 Co, Gl, Ef, Fp, Cl, 1-2 Ts, Tg, 1-2 Pe (9). Gerais: 1-2 Tm, Tt, Fm, Hb, 1-3 Jo, Jud (7).','Paulo: 13 cartas. Gerais: Tg, 1-2 Pe, 1-3 Jo, Jud, Apocalipse (8).','Paulo: 14 cartas. Gerais: Hb, Tg, 1-2 Pe, 1-2 Jo (5).'),('FB01-L06-Q02','A ordem alfabetica ou numerica permite encontrar livros rapidamente pelo titulo.','O formato da capa colorida indica onde cada livro esta organizado na estante.','O tamanho do livro determina sua posicao exata em qualquer biblioteca.','O preco do livro define sua localizacao nos catalogos de consulta.'),('FB01-L06-Q05','São um único livro dividido na Septuaginta','Samuel foi escrito por dois profetas diferentes','A diferença está na ordem cronológica dos eventos','O número indica a região onde foram compostos'),('FB01-L07-Q01','Indica qual dos livros biblicos contem o texto referido.','Indica o numero de capitulos do livro biblico.','Indica a versao biblica utilizada na citacao.','Indica o autor original do texto biblico.'),('FB01-L06-Q04','Consulte uma tabela de abreviações dos livros bíblicos','Leia o prefácio da Bíblia para encontrar as abreviações','Use a função de pesquisa do aplicativo da Bíblia','Consulte um dicionário de grego e hebraico bíblicos'),('FB01-L07-Q02','O capítulo do livro','O número total de versículos do livro','A edição da Bíblia em português','A ordem cronológica dos livros bíblicos'),('FB01-L06-Q03','A organização por testamento e gênero facilita localizar livros rapidamente','A classificação por ordem alfabética facilita encontrar qualquer livro','O número de capítulos determina a posição dos livros na Bíblia','A cor da capa indica onde cada livro está localizado'),('FB01-L07-Q03','O número após os dois-pontos indica o número do versículo.','O número após os dois-pontos indica a página do texto bíblico.','O número após os dois-pontos indica a posição do livro no cânon.','O número após os dois-pontos indica quantos versículos há no capítulo.'),('FB01-L07-Q04','Abrir o livro de Romanos, localizar o capítulo 8 e ler os versículos 1 a 4','Consultar apenas o índice temático no final da Bíblia','Procurar primeiro as referências cruzadas de cada versículo','Localizar o capítulo 8 e contar os versículos a partir do final'),('AT18-L16-Q01','Esdras leu publicamente o livro da lei em Jerusalem, e o povo compreendeu','A lei foi reescrita pelos profetas menores durante o exílio na Babilônia','Os sacrifícios foram suspensos e substituídos por orações no templo reconstruído','O rei Ciro ordenou que a lei mosaica fosse aplicada em todo o império persa'),('AT18-L15-Q06','A reconstrução dos muros de Jerusalém restaurou a esperança messiânica de Israel.','A reedificação dos muros demonstrou que os sacerdotes restauraram a independência.','A reedificação dos muros fortaleceu a defesa militar contra os inimigos pagãos.','A reconstrução dos muros simbolizou a independência política total de Judá.'),('AT17-L10-Q05','Exílio babilônico, destruição do templo, preservação da lei e continuidade davídica.','Fusão completa das doze tribos sob Judá e restauração da monarquia unificada.','Adoção do politeísmo como culto oficial sancionado pelo templo de Jerusalém.','Dissolução imediata do estado e integração completa na Assíria.'),('AT17-L11-Q04','A promessa do trono eterno a Davi preservou a esperança messiânica em Judá.','A promessa dividiu Judá entre aqueles que aceitavam e rejeitavam a linhagem davídica.','A promessa fez Judá se tornar independente das outras tribos israelitas.','A promessa estabeleceu que Judá nunca mais precisaria de reis após o exílio.'),('AT18-L09-Q02','Nabucodonosor, Belsazar e Dario, o medo','Ciro, Dario e Artaxerxes, os Persas','Faraó, Acabe e Jezabel, os idolatras','Assuero, Evil-Merodaque e Sambalate'),('FB01-L06-Q06','A estrategia e memorizar que o Antigo Testamento termina em Malaquias e o Novo comeca em Mateus','A estrategia e usar a regra mnemonica de que todo livro com mais de 3 silabas pertence ao Novo Testamento','A estrategia e memorizar que os livros do Antigo Testamento comecam todos com as letras A a J','A estrategia e contar que o Antigo Testamento tem exatamente 27 livros e o Novo tem 39'),('FB01-L07-Q06','Analisar a unidade literaria e o tema连贯 do trecho completo.','Considerar cada capitulo como unidade independente de sentido.','Ignorar o contexto e interpretar apenas o versiculo inicial.','Usar a soma dos capitulos como referencia aleatoria.'),('AT18-L16-Q02','Esdras, Neemias e Josias restauraram a lei apos o exilio.','Abraão, Isaque e Jacó restauraram a lei revelada a Moises no Sinai.','Jeroboão e Acabe restabeleceram a lei no reino do norte de Israel.','Davi e Salomão foram os principais responsaveis pela restauração da lei.'),('AT17-L09-Q06','Pela promessa de restauração em Oséias e pela falha de seus reis em cumprir a esperança messiânica','Por ter sido destruída pela Assíria, eliminando toda esperança de um rei messiânico no norte','Porque seus reis foram considerados modelos perfeitos do ungido divino para o povo','Pelos profetas do sul como Isaías que viveram no reino do norte e lá ensinaram a Lei'),('AT17-L11-Q02','Pela desobediência a Deus e falta de sucessão legítima estável.','Porque os profetas ungiam novos reis sem consentimento do povo.','Devido às invasões estrangeiras que desestabilizavam o poder real.','Por causa das disputas tribais entre as doze tribos de Israel.'),('FB06-L06-Q01','Na região setentrional da Palestina, ao norte de Samaria','Na região sul de Israel, próxima ao deserto da Judeia','Na Mesopotâmia, entre os rios Tigre e Eufrates','Próxima à cidade de Jericó, na região do Jordão'),('FB06-L06-Q03','Jesus de Nazaré, Pedro, André, Tiago, João e o mar da Galileia','Moisés, o mar Vermelho e os filhos de Israel peregrinando pelo Sinai','Abraão, Sara, o rio Jordão e a cidade de Sodoma na Mesopotâmia','Paulo de Tarso, o templo de Jerusalém e os fariseus em Damasco'),('FB06-L05-Q03','Abraão, Isaac e Jacó, patriarcas do povo escolhido, ligados à terra prometida.','O profeta Jonas e a cidade de Nínive, capital da Assíria.','Os reis magos vindos do oriente, relacionados à terra da Pérsia.','O faraó e as dez pragas do Egito, ligadas à terra do Egito.'),('FB06-L06-Q05','Porque a Galileia era a regiao onde Cristo viveu, pregou e realizou a maioria dos seus milagres.','Porque a Galileia era a capital religiosa do judaísmo e centro de estudo dos rabinos.','Porque os textos originais do Novo Testamento foram todos descobertos em cavernas galileias.','Porque a Galileia era a unica regiao onde os impostos eram pagos diretamente ao templo.'),('FB06-L07-Q01','Samaria era a capital do reino norte de Israel.','Samaria era uma cidade da Judeia, no sul da Palestina.','Samaria ficava na região da Mesopotâmia, entre os rios Tigre e Eufrates.','Samaria era o nome de uma região no Egito, próximo ao rio Nilo.'),('FB06-L06-Q02','Regiao norte de Israel, fertil, junto ao mar de Tiberíades, sob Herodes Antipas.','Regiao meridional da Judia, arida e isolada, controlada diretamente pelo sumo sacerdote.','Territorio ao leste do Jordão, montanhoso e deserto, habitado apenas por israelitas.','Zona costeira da Fenícia, grega e comercial, anexada diretamente ao império romano.'),('FB06-L08-Q01','Regiao no sul da Palestina, na Terra de Israel','Regiao na Mesopotamia, entre os rios Tigre e Eufrates','Provincia costeira do Mediterraneo, na regiao da Fenicia','Provincia romana localizada na Peninsula Italica'),('FB06-L07-Q04','Conectava-se por rotas comerciais e foi dominada por Assíria, Babilônia e Pérsia.','Era uma região insular, isolada das principais rotas comerciais por suas montanhas.','Localizada na costa mediterrânea, servia exclusivamente como porto de comércio marinho.','Aliada permanente do Egito, nunca sofreu dominação por impérios do norte.'),('FB06-L07-Q02','Capital do Reino do Norte, fundada por Omri, na região montanhosa','Capital do Reino do Sul, construída por Davi, local do Primeiro Templo','Cidade litorânea da Fenícia, famosa pelo comércio marítimo fenício','Região desértica da Judéia, controlada pelos sumos sacerdote'),('FB06-L07-Q05','Porque revela a identidade e os conflitos entre judeus e samaritanos.','Porque revela o local onde Jesus nasceu e cresceu na palestina.','Porque samaria era o centro principal do império romano na região.','Porque os samaritanos foram os primeiros a escrever os evangelhos.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB06-L07-Q03','Onri fundou Samaria; Elias, Acab e a mulher samaritana','O pharao egypcio construiu Samaria; Moyses e as pragas do Egypto','Salomão reconstruiu Samaria; Esdras e Neemias tambem estao ligados','Nabucodonosor fundou Samaria; Jonas e Naaman foram samaritanos'),('FB06-L08-Q04','Judeia situava-se em encruzilhada de rotas comerciais e sob domínio de vários impérios, como Egípcios, Assírios, Babilônios, Persas e Romanos.','Judeia era completamente isolada e não mantinha contato com nenhuma civilização vizinha do mundo antigo.','Judeia dominava vastos territórios e impunha sua cultura sobre todos os povos vizinhos da região.','Judeia possuía fronteira apenas com o Egito e não tinha relação comercial com impérios do oriente.'),('FB06-L10-Q01','Na terra de Canaã, entre Israel e Jordânia','No deserto do Saara, próximo ao Egito','Na região da Mesopotâmia, entre Irak e Irã','Nas terras da Arábia Saudita, perto de Meca'),('FB06-L09-Q04','Ficava em rotas comerciais entre Egito e Mesopotâmia e foi dominada por vários impérios.','Era completamente isolada e não mantinha contato com civilizações vizinhas.','Localizava-se na costa mediterrânea, sendo um grande porto comercial.','Pertencia exclusivamente ao império egípcio durante toda a Antiguidade.'),('FB06-L10-Q04','Rotas comerciais conectando Egito, Mesopotâmia e impérios mesopotâmicos','Isolavam a Judeia do comércio internacional por não possuírem portos marítimos','Serviam exclusivamente como fronteira natural entre Israel e os povos vizinhos','Eram controlados apenas pelo Império Romano durante toda a Antiguidade'),('FB06-L09-Q05','Jerusalém era o centro religioso, político e cultural de Israel na época bíblica.','Porque os romanos controlavam todas as rotas bíblicas a partir de Jerusalém.','Porque todos os profetas escreveram suas profecias exclusivamente em Jerusalém.','Porque a arca da aliança permaneceu em Jerusalém após a divisão do reino.'),('FB06-L10-Q02','Fossa tectonica do Jordao concentra significance biblico, politico e geopolitico.','Fronteiras naturais entre Africa e Europa, divisorias dos grandes imperios.','O Mar Morto era o maior lago de agua doce do Oriente Medio biblico.','O Rio Jordao era a principal via de comercio maritimo da regiao.'),('FB06-L11-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB06-L11-Q01','No Sinai, Judá e Neguebe; os montes Sinai, Carmelo e Sião.','No Saara, Gobi e Atacama; os Alpes, Himalaia e Andes.','Na Mesopotâmia; os montes Ararate, Carmelo e Libano.','Na Arábia e Pérsia; os Pirineus, Apeninos e Cáucaso.'),('FB06-L10-Q03','Jesus foi batizado por Joao Batista no rio Jordao','O povo hebreu收到了 as tábuas da Lei no Sinai','Moises abriu um caminho no mar Vermelho','Daniel foi lançado na cova dos leões em Babilonia'),('FB06-L10-Q05','Fornece o contexto geográfico e histórico necessário para interpretar as Escrituras.','Prova arqueologicamente que todos os eventos biblicos aconteceram exatamente como relatados.','Revela codigos numericos escondidos que confirmam a autenticidade dos textos sagrados.','Identifica quais autores biblicos testemunharam pessoalmente os eventos descritos.'),('FB06-L11-Q05','Porque desertos e montanhas saocenario frequente nas Escrituras,e seu conhecimento ilumina o contexto das passagem.','Porque Deus habita apenas em lugares isolados e afastados da civilizacao humana.','Porque desertos simbolizam exclusivamente a presenca do demonio nas Escrituras.','Porque os autores biblicos inventaram esseslugares para dar mais drama as narrativas.'),('FB06-L11-Q04','Serviam como barreiras naturais e rotas comerciais entre povos e impérios do mundo antigo.','Eram regiões completamente isoladas, sem conexão com impérios ou rotas comerciais do mundo antigo.','Apenas impediam a expansão dos impérios, nunca facilitando contato entre civilizações.','Desertos e montanhas só se tornaram importantes depois do período bíblico, na era clássica.'),('FB06-L11-Q03','Moisés','Elias','Davi','Sansão'),('FB06-L12-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB06-L12-Q02','Rios navegáveis, desertos, oásis, rotas marítimas e estabilidade política','Clima polar e glaciares como principais facilitadores de rotas comerciais','Ilhas continentais sem acesso ao mar como únicos pontos comerciais','Florestas equatoriais densas como rotas comerciais preferenciais'),('FB06-L13-Q01','Na parte setentrional da Mesopotâmia, com capital em Nínive','No sul de Canaã, próximo à região de Judá e Jerusalém','Na Península do Sinai, entre o Egito e o Mar Vermelho','Na Ásia Menor, ao norte da região da Capadócia'),('FB06-L12-Q03','Os ismaelitas levaram José ao Egito por rotas comerciais.','Os filisteus foram destruídos por搓uma enquanto comercializavam.','O profeta Jonas fugiu de Nínive seguindo rotas comerciais.','O rei Davi estabeleceu um império comercial com as tribos de Benjamim.'),('FB06-L12-Q05','Porque revelam o contexto histórico e geográfico das Escrituras.','Porque indicam que Deus se comunica apenas por símbolos de comércio.','Porque as rotas comerciais são o tema central de toda a Bíblia.','Porque eliminam a necessidade de estudar o hebraico e grego.'),('FB06-L13-Q02','Império militarista da Mesopotâmia, capital Nínive, conquistas e boa administração.','Civilização pacífica do Egito, baseada em comércio fluvial e adoração ao deus Amon.','Reino insular do Mediterrâneo, governado por reis-sacerdotes e dedicado à navegação.','Império montanhoso da Ásia Menor, conhecido por sua diplomacia e tratados comerciais.'),('FB01-L07-Q05','Cada versículo sustenta um ponto distinto do argumento ou tema abordado.','Os versículos formam uma sequência contínua de raciocínio teológico.','Os versículos devem ser lidos em ordem inversa para compreensão correta.','Os versículos citados são intercambiáveis e indicam o mesmo ponto.'),('FB04-L14-Q05','Morte e ressurreicao constituem a obra central da redenção','Morte e ressurreicao foram eventos apenas espirituais sem impacto físico real','Cristo morreu para confirmar seus ensinos e ressuscitou para continuar seu ministerio','A ressurreicao de Cristo prova que ele era apenas um homem iluminado pelo Espirito'),('FB04-L14-Q04','Cumpre as Escrituras e opera a redenção do gênero humano','Inicia uma religião separada sem conexão com o Antigo Testamento','Anula completamente a lei sem continuidade com a aliança anterior','Representa um evento isolado sem relação com as promessas proféticas'),('FB04-L15-Q02','O derramamento do Espírito Santo','A queda do homem no Jardim do Éden','A divisão do reino entre Israel e Judá','A construção do templo de Salomão'),('FB04-L15-Q03','Promessa do Espirito Santo e Pentecostes em Atos 2','A alianca abraamica fundando a igreja de Cristo','A destruicao do templo de Salomon e inicio da vida comunitaria','O recenseamento de Cesar Augusto como marco fundacional'),('FB04-L15-Q01','O Pentecostes, quando o Espirito Santo foi derramado e a igreja foi fundada.','A Criacao do mundo, quando Deus separou Israel como seu povo.','A Segunda Vinda de Cristo, quando a igreja sera reunida com o Senhor.','O sacrifício de Cristo na cruz, quando o novo pacto foi estabelecido.'),('FB04-L14-Q03','A Nova Alianca, a Alianca com Abraao e a Alianca com Davi','A alianca com Noe relacionada ao arco-iris e a preservacao da natureza','As ordenancas civis do livro de Deuteronomio e as leis santas','Os pactos politicos entre Israel e as nacoes voisinhas'),('FB04-L15-Q05','A Igreja nasceu pela obra redentora de Cristo e pelo Espírito Santo em Pentecostes.','A Igreja surgiu antes da vinda de Cristo, como preparacao para Seu ministerio terreno.','A Igreja comecou quando Jesus nasceu em belem, na manjedoura com os pastore','A Igreja se formou a partir de movimentos politicos judaicos no primeiro seculo.'),('FB04-L16-Q03','Aliança abraâmica: em ti serão abençoadas todas as famílias da terra','Aliança mosaica: toda terra será dada em possessão eterna a Israel','Novo concerto: Cristo trará destruição sobre todas as nações','Aliança davídica: os gentios jamais participarão das promessas divinas'),('FB04-L15-Q04','Cumprimento das promessas messiânicas e inauguration da nova aliança','Retorno político de Israel e restauração da monarquia davídica','Supersessão total da revelação veterotestamentária','Simples organização religiosa sem continuidade histórica'),('FB04-L16-Q01','Deus levar a redenção a todos os povos da terra','Restringir a salvação apenas ao povo de Israel','Conquistar militarmente todas as nações da terra','Limitar a revelação divina a uma única língua'),('FB04-L16-Q02','Confusão de línguas','O dilúvio universal','A vocação de Abraão','A aliança com Noé'),('FB04-L16-Q04','A promessa a Abraão é o elo entre a aliança, a missão e a consumação','A missão entre as nações é uma ideia exclusivamente do Novo Testamento','A missão entre as nações substitui completamente a aliança com Israel','A missão se conecta apenas aos eventos do livro de Apocalipse'),('FB04-L17-Q01','Última etapa da redenção, quando Cristo retorna e completa a salvação','O momento em que Cristo nasceu em Belém e iniciou sua obra terrena','A morte de Cristo na cruz que satisfez a justiça divina','A descida do Espírito Santo no dia de Pentecostes'),('FB04-L17-Q02','A glorificacao do corpo','A queda do homem no paraiso','A crucificacao de Cristo','O pecado original de Adao'),('FB04-L17-Q04','A consumação cumpre as promessas covenantais desde a criação até a nova criação','A consumação anula as etapas anteriores, iniciando uma história completamente desconectada','A consumação repete linearmente as etapas anteriores sem trazer novidade redentora','A consumação é um evento isolado sem relação com o plano salvífico divino'),('FB06-L08-Q02','Região montanhosa da Palestina, centro religioso do Judaísmo, sob domínio romano.','Região fértil da Mesopotâmia, berço das primeiras civilizações mesopotâmicas.','Território insular do Mediterrâneo, grande potência naval e comercial antiga.','Região montanhosa da Índia antiga, importante centro cultural e espiritual budista.'),('FB06-L08-Q05','Porque o contexto geográfico e cultural de Judeia é essencial para interpretar as Escrituras.','Porque Judeia é mencionada em todas as эпистолы do Novo Testamento de forma significativa.','Porque os idiomas falados em Judeia são totalmente diferentes do hebraico bíblico.','Porque os costumes de Judeia nunca influenciaram as práticas religiosas do Antigo Testamento.'),('FB06-L08-Q03','Davi, Herodes e Jesus Cristo','O confronto de Elias contra os profetas de Baal no monte Carmelo','O cativeiro assírio das dez tribos de Israel','A construcao do templo de Salomon em Samaria'),('FB06-L14-Q01','Mesopotâmia, na região da Babilônia, ao longo do rio Eufrates.','Canaan, na região costeira do mar Mediterrâneo, ao sul de Israel.','Egito, ao longo do rio Nilo, no nordeste da África.','Asia Menor, na região da Capadócia e da Galácia.'),('FB06-L13-Q04','Por meio de conquistas militares e controle de rotas comerciais no Oriente Médio.','Por isolamento total e recusa em manter contato com povos estrangeiros.','Por conversão religiosa voluntária dos povos conquistados ao culto assírio.','Por dependência exclusiva da economia egípcia para sobrevivência.'),('FB06-L13-Q03','Jonás em Nínive, invasão de Israel, Senaqueribe','Daniel na Babilônia, Ciro, exílio no Egito','Sansão, Dalila, filisteus, Gideão','Abraão em Ur, Sodoma, Melquisedeque'),('FB06-L09-Q01','Na região montanhosa da Judeia, na Palestina.','No alto da montanha do Sinai, no Egito.','Na costa do mar Mediterrâneo, em Alexandria.','No topo do monte Carmelo, na Fenícia.'),('FB04-L16-Q05','A missão decorre da autoridade universal de Cristo e do Espirito Santo.','A missão mundial foi estabelecida pela autorité dos apóstolos, independente de Cristo.','A tarefa missionária restringe-se ao território de Israel conforme a Torá.','A missão entre as nações iniciou-se antes da criação, por decreto angelical.'),('FB06-L09-Q02','Cidade santa, capital do reino de Judá, situada nos montes de Judá, território disputado.','Cidade litorânea do Mediterrâneo, conhecida pelo porto comercial e pescaria abundante.','Cidade fundada por Nabucodonosor como centro administrativo da Babilônia.','Metrópole localizada na planície de Moabe, próxima ao rio Jordão e ao mar Morto.'),('FB06-L13-Q05','Fornece o contexto histórico e arqueológico para interpretar as Escrituras.','Porque os assírios foram os criadores originais dos manuscritos hebraicos.','Porque a língua assíria é a base direta do hebraico bíblico.','Porque toda a narrativa bíblica foi escrita durante o império assírio.'),('FB09-L13-Q02','Por critérios como origem apostólica, uso litúrgico e aceitação geral das igrejas ao longo dos séculos.','Por decisão unilateral do imperador Constantino no Concílio de Nicéia no ano 325.','Automaticamente revelados a todos os crentes desde o início da fé cristã.','Baseado exclusivamente em milagres realizados pelos autores dos livros sagrados.'),('FB09-L13-Q04','Por decisão dos concílios e sínodos eclesiásticos','Pela ordem cronológica de composição dos textos','Pela popularidade entre os fiéis nas comunidades','Pela autorização direta dos imperadores romanos'),('FB09-L13-Q01','Livros deuterocanônicos debatidos na formação do cânon','Livros apócrifos considerados inspirada pela igreja primitiva','Escritos proféticos adicionais ao Novo Testamento','Epístolas escritas diretamente pelos doze apóstolos'),('FB09-L12-Q04','Livros apostólicos possuem autoridade especial por serem atribuídos aos apóstolos de Cristo.','Organizam-se exclusivamente por ordem cronológica de composição entre os primeiros cristãos.','Diferenciam-se por serem aceitos igualmente por todas as tradições cristãs existentes.','Organizam-se conforme o idioma original da composição hebraica ou aramaica.'),('FB09-L13-Q03','Os criterios eram apostolicidade, ortodoxia, catolicidade e uso liturgico','Baseavam-se principalmente em revelacoes profeticas individuais','Sua inclusao era determinada exclusivamente por decreto imperial','Dependiam unicamente da popularidade entre os fieis comuns'),('FB09-L12-Q05','Tratar todas as epístolas como homogêneas, ignorando diversidade de gêneros e contextos.','Afirmar que os apóstolos escreveram seus livros em latim, pois escreveram em grego.','Negar a existência de variações textuais entre os manuscritos antigos das epístolas.','Considerar que Judas não faz referências a fontes extrabíblicas em sua carta.'),('FB09-L14-Q01','Escritos excluídos do cânon bíblico, tidos como heterodoxos e de origem incerta.','Textos originais dos evangelhos canônicos que foram escondidos pela igreja primitiva.','Evangelhos rejeitados pelo Concílio de Niceia por conterem doutrinas satânicas.','Traduções oficiais em latim dos evangelhos aceitos pela igreja anglicana.'),('FB09-L13-Q05','Não confundir livros apócrifos com canônicos nem supor unanimidade na igreja antiga.','Afirmar que o Concílio de Trento criou o cânon bíblico em 1546.','Dizer que os Padres da Igreja sempre concordaram sobre todos os livros.','Tratar os evangelhos apócrifos como historicamente equivalentes aos canônicos.'),('FB09-L14-Q03','Comunidades gnósticas, Biblioteca de Nag Hammadi, evangelhos de Tomé e Judas','Cânon do Novo Testamento, Concílio de Niceia, pais apostólicos','Manuscritos do Mar Morto, seitas essênias, pergaminhos de Qumran','Tradições rabbinicas, Talmude babilônico, literatura midráshica'),('FB09-L14-Q02','Surgiram nos séculos II e III, muitos atribuídos a apóstolos, rejeitados pela Igreja.','Foram incluídos no Cânon do Novo Testamento no Concílio de Niceia em 325.','Surgiram apenas no século XV durante a Reforma Protestante para defender Lutero.','Foram canonizados pela Igreja Católica Romana no Concílio Vaticano II.'),('FB09-L15-Q02','Concílios e Sínodos reconheceram gradualmente os livros canônicos entre os séculos IV e XVI.','O cânon bíblico foi definido somente no Concílio de Trento em 1546.','Os apóstolos criaram o cânon no primeiro século sem nenhum debate.','Apenas a Igreja Católica reconheceu os livros canônicos ao longo da história.'),('FB09-L14-Q04','Apócrifos não foram incluidos no cânon bíblico','Apócrifos foram incluidos no cânon pelo Concílio de Trento','Apócrifos têm a mesma autoridade que os Evangelhos canônicos','Apócrifos foram rejeitados por todas as tradições cristãs'),('FB09-L14-Q05','Considerá-los todos heréticos ou igualar seu valor aos evangelhos canônicos','São manuscripts originais dos apóstolos que a igreja ocultou por medo','Devem ser rechaza dos completamente por não conterem nenhuma verdade histórica','Foram escritos diretamente pelos apóstolos e suas famílias como autobiografias'),('FB09-L15-Q04','Concilios formalizaram o reconhecimento ja existente das comunidades','Concilios foram os unicos meios de organizacao dos livros biblicos','Outros metodos nunca influenciaram a formacao do canone biblico','O canone foi determinado antes da existencia da igreja cristã'),('FB09-L15-Q05','Confundir concílios ecumênicos com sínodos regionais','Acreditar que o cânon foi decidido num único concílio ecumênico','Supor que Roma definiu sozinha os livros canônicos','Pensar que o cânon bíblico foi fixado no século II'),('FB09-L15-Q01','Assembleias eclesiais que deliberaram sobre a regra dos livros sagrados','Reuniões de escribas que copiaram manuscritos da Bíblia hebraica','Lista de profetas que deveriam pregar nos templos de Israel','Códigos legais que regiam a liturgia das sinagogas antigas'),('FB09-L16-Q01','Teorias não confirmadas historicamente sobre seleção de livros bíblicos.','Histórias sobre como imperadores escolheram os livros por decreto divino.','Narativas sobre a descoberta de manuscritos originais que definiram o cânon.','Lendas sobre a orientação direta do Espírito Santo na escolha dos livros.'),('FB09-L16-Q02','O cânon se formou gradualmente por uso e aceitação eclesial ao longo dos séculos.','Um único concílio no século IV selecionou todos os livros canônicos.','O imperador Constantino decidiu sozinho quais livros seriam canônicos.','Apenas os livros escritos em hebraico foram considerados canônicos.'),('FB11-L02-Q01','Material feito do caule da planta Cipero-do-egito, abundante no Egito.','Tecido produzido a partir de fibras de linho egípcio cultivado no delta do Nilo.','Papel feito da polpa da palmeira-das-canárias, comum na região da Palestina.','Material elaborado com pele de carneiro curtida, utilizado no antigo Egito.'),('FB11-L01-Q06','Porque revelam como o texto foi copiado e conservado ao longo dos séculos.','Porque os materiais antigos são mais inspirados que os modernos.','Porque permitem alterar o texto conforme a necessidade de cada época.','Porque os originais de todos os livros bíblicos ainda existem hoje.'),('FB11-L01-Q03','Pergaminho era feito de couro de animal, mais duravel que o papiro.','O pergaminho era produzido com fibras vegetais aquaticas do Rio Nilo.','O papiro era feito de peles de animal curadas ao sol durante semanas.','Ambos os materiais eram essencialmente iguais na composicao e resistencia.'),('FB11-L01-Q05','Papel e pergaminho determinavam durabilidade, extensão e valor dos manuscritos.','Materiais de escrita não influenciavam custos, apenas a estética dos textos.','O papiro era mais durável que o pergaminho, tornando os rolos mais caros.','O tamanho dos manuscritos dependia apenas da importância do texto, não do material.'),('FB11-L01-Q02','Feito da planta Cyperus papyrus, com tiras prensadas e coladas em rolos.','Elaborado a partir de couro de animal curtido, cortado em finas folhas e joinedas.','Produzido com argila modelada e seca ao sol, depois gravada com estiletes.','Fabricado de pedras finas polidas, escritas com pigmentos minerais coloridos.'),('FB11-L01-Q04','Estiletes de junco e tinta de fuligem com goma.','Papiro preparado com tinta de sangue de cordeiro.','Lápis de chumbo e pergaminho encerado.','Pinceles de seda e tinta de frutas vermelhas.'),('FB11-L02-Q02','Fatias do caule eram embebidas, sobrepostas em camadas cruzadas e prensadas para secar.','O papiro era queimado levemente para criar uma superfície escura própria para escrita.','As folhas eram mergulhadas em tinta por semanas até ficarem completamente saturadas.','O caule era fermentado em agua por meses e depois secas ao sol sem prensagem.'),('FB11-L02-Q03','Egito, especialmente o deserto e o Vale do Nilo','Mesopotamia, pela estabilidade política da região','Canaã, pelo uso de cavernas de calcário seco','Grécia, pelo clima mediterrâneo seco no verão'),('FB11-L03-Q01','Material feito de peles de animais, especialmente ovelhas, cabras e bezerros.','Material feito de papiro, extraído de uma planta aquática encontrada no Egito.','Tecido de linho finamente tecido e utilizado para escrever textos sagrados.','Papel produzido a partir de polpa de madeira de árvores específicas.'),('FB11-L02-Q05','Papiro é frágil, racha nas dobras e não permite reescrita.','Papiro era mais pesado e volumoso que o pergaminho.','Papiro resistia melhor à umidade e ao ataque de insetos.','Papiro não podia ser dobrado, apenas enrolado em rolos.'),('FB11-L03-Q03','O pergaminho era feito de peles de animais, sendo mais resistente que o papiro.','Porque era mais barato e fácil de produzir em grandes quantidades.','Porque o pergaminho podia ser reutilizado após apagar o texto anterior.','Porque permitia escrever com tinta mais colorida e vibrante.'),('FB11-L03-Q04','O alto custo levava à reutilização e scripts econômicos','O baixo custo permitia produção em larga escala','Apenas os sacerdotes podiam produzir manuscritos','O pergaminho era descartado após uso único'),('FB11-L02-Q04','Os papiros preservam textos antigos do Novo Testamento para a crítica textual.','Eram usados exclusivamente para escrever os livros históricos do Antigo Testamento.','Possuem menor importância que os manuscritos em pergaminho para a crítica textual.','Serviam principalmente como material de embalsamamento no Egito antigo.'),('FB11-L04-Q01','Manuscrito em forma de livro feito de pergaminho ou papiro.','Rolo sagrado de pergaminho usado nos templos antigos de Israel.','Colecao de leis mosaicas escrita por Moises no deserto.','Traducao grega do Antigo Testamento feita por setenta rabinos.'),('FB11-L04-Q04','Os cristãos preferiram o código por ser mais prático, durável e fácil de esconder durante perseguições.','O código foi adotado porque era mais barato para produzir em grande escala naquele período.','Os cristãos escolheram o código seguindo uma ordem direta dos apóstolos nas Escrituras.','O código tornou-se popular porque os pagãos já usavam rolos e os cristãos queriam se diferenciar.'),('FB11-L03-Q05','Permitiu durabilidade excepcional, garantindo a sobrevivência dos grandes manuscritos bíblicos.','A superfície reflexiva do pergaminho facilitava a leitura em ambientes com pouca luz.','Permitia aos escribas escreverem mais rápido, aumentando a produção de manuscritos.','O pergaminho era mais barato que o papiro, tornando-o acessível a todas as comunidades.'),('FB11-L04-Q03','Permitia consulta rapida por paginas e reunia livros em um unico volume.','Os rolos tambem permitiam reuniao de livros em um volume pratico e leve.','O papiro era superior ao codice para indexacao e organizacao de textos.','O formato de rolo era mais eficiente para localizar capitulos e verses especificas.'),('FB11-L04-Q05','Reuniu múltiplos escritos num volume único, facilitando a compilação.','Substituiu completamente os rolos por terem sido inventados antes dos pergaminhos.','Permitiu que cada fiel possuísse sua própria cópia individual da Bíblia completa.','Garantiu a inspiração divina dos textos através de sua encadernação sagrada.'),('FB11-L04-Q02','O códex é encadernado como livro, já o rolo é enrolado em formato cilíndrico.','O rolo permite acesso direto a qualquer página, diferente do códex.','O códex surgiu antes do rolo na história dos manuscritos.','O códex usa apenas papiro, enquanto o rolo usa apenas pergaminho.'),('FB11-L05-Q01','Textos bíblicos em hebraico, como o Texto Massorético e os Manuscritos do Mar Morto.','Traduções gregas do Antigo Testamento realizadas na Alexandria por Setenta tradutores.','Manuscritos em aramaico que preservam porções do Texto Massorético hebraico.','Cópias em latim dos textos originais hebraicos feitas por Jerónimo de Estridão.'),('FB11-L05-Q04','Permitem comparar versões e identificar variantes textuais ao longo dos séculos.','Comprovam que o texto bíblico permaneceu absolutamente idêntico desde a escrita original.','Eliminam a necessidade de estudos de crítica textual por confirmarem uma única versão autêntica.','Demonstram que os escribas copiavam os manuscritos sem nenhuma variação ou erro.'),('FB11-L05-Q03','Escrita quadrática hebraica e texto consonântico masorético','Utilizam exclusivamente o alfabeto grego koiné com texto alexandrino','Apresentam únicamente texto em papiro alexandrino sem vocalização','Contêm exclusivamente versões da Vulgata Latina tradicional'),('FB11-L16-Q01','Variante textual é uma diferença entre manuscritos bíblicos','Variante textual é um tipo de tradução bíblica moderna','Variante textual é um erro de impressão nas Escrituras','Variante textual é uma interpretação teológica oficial'),('FB11-L16-Q02','Diferenças acidentais e intencionais','Diferenças geográficas e históricas entre manuscritos','Erros de transcrição e modificações teológicas','Variações litúrgicas e rituais entre cópias'),('FB11-L15-Q05','A mensagem foi preservada; os originais se perderam, mas temos cópias fidedignas.','Preservar a mensagem refere-se aos manuscritos, e os originais são as cópias.','A diferença é que os originais existem nos museus e a mensagem se perdeu.','Sao conceitos iguais, pois se referem ao mesmo texto bíblico.'),('FB11-L16-Q04','Aplicam critérios textuais como dificuldade, extensão e procedência geográfica.','Analisam exclusivamente os manuscritos hebraicos encontrados no Mar Morto.','Rejeitam variantes que possam afetar doutrinas teológicas.','Decidem a leitura original por consenso majoritário dos estudiosos.'),('FB11-L16-Q03','Os copistas buscavam fielmente reproduzir o texto, cometendo pequenos erros','Os originais biblicos foram destruidos, impossibilitando checagem','As variantes surgiram apenas apos a invencao da imprensadem Gutenberg','Os escribas recebiam pagamentos por cada palavra alterada no texto'),('FB11-L16-Q06','As notas indicam variantes textuais e traduções alternativas dos originais.','Apenas listam correções ortográficas e gramaticais da lingua portuguesa.','Reproduzem integralmente todos os manuscritos coptas e aramaicos disponíveis.','Substituem o texto bíblico por comentarios de autores modernos.'),('FB11-L17-Q03','A comparação entre eles permite identificar variações e determinar o texto mais próximo do original.','Cada manuscrito representa uma versão definitiva e autoritativa do texto original.','Os manuscritos permitem determinar exatamente qual padre copiou o texto primeiro.','A quantidade de manuscritos garante que o texto original seja preservado palavra por palavra.'),('FB11-L17-Q01','Significa que Deus preservou a integridade das Escrituras contra corrupções.','Significa que os escribas copiaram os textos sem cometer erros humanos.','Significa que todas as cópias antigas da Bíblia são exatamente iguais.','Significa que Deus reescreveu a Bíblia completamente em cada geração.'),('FB11-L17-Q02','Tradição rabínica, copistas e comunidades cristãs preservaram as Escrituras.','A intervenção divina eliminou todos os erros textuais ao longo dos séculos.','A destruição do Templo de Jerusalém foi o principal fator de preservação textual.','Os imperadores romanos determinaram a preservação através de éditos oficiais.'),('FB11-L16-Q05','Não eliminam. O texto original pode ser reconstituído com confiança.','Sim, as variantes eliminam toda possibilidade de conhecer o texto original.','Apenas as variantes do Novo Testamento eliminam o conhecimento do texto.','O texto bíblico original está completamente perdido e é irrecuperável.'),('FB11-L17-Q04','A mensagem essencial foi preservada apesar das variantes entre manuscritos','Preservação exige que não exista nenhuma diferença entre cópias do texto','Auskência de variantes significa que Deus copiou os manuscritos pessoalmente','As variantes textuais provam que o texto original nunca foi preservado'),('FB11-L17-Q05','Devido a variações nos manuscritos e escolhas de tradução que preservam o sentido.','Porque tradutores modernos querem mudar a mensagem para agradar leitores.','Devido a erros acidentais de copistas que foram mantidos nas versões novas.','Por causa de doutrinas protestantes e católicas conflitantes nas editoras.'),('FB11-L17-Q06','A preservação textual sustenta a confiança dos crentes na integridade da Bíblia.','A preservação textual substitui a necessidade de fé pela certeza científica.','Torna a Escritura um documento meramente humano sem autoridade divina.','Prova que os manuscritos originais nunca conteram erros ou discrepâncias.'),('FB12-L01-Q01','Em hebraico e grego','Em aramaico e hebraico','Em grego e latim','Em hebraico e latim')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB12-L01-Q02','Porque os originais foram escritos em hebraico e grego, línguas que poucos conhecem.','Porque as traduções são inspiradas e superiores aos textos originais.','Porque os manuscritos originais foram completamente perdidos ao longo dos séculos.','Porque a igreja primitiva decidiu proibir o acesso direto aos idiomas originais.'),('FB12-L01-Q04','Diferenças entre línguas exigem escolhas interpretativas.','Porque tradutores são imperfeitos e cometem erros.','Todas as línguas são idênticas e não há ambiguidade.','Somente a tradução direta word-for-word é válida.'),('FB12-L01-Q03','Traduzir palavras segue forma; comunicar sentido segue mensagem.','Traduzir palavras é superior a comunicar o sentido.','Palavras e sentido são exatamente a mesma coisa.','Apenas palavras importam; sentido é irrelevante.'),('FB12-L01-Q05','Palavras mudam de sentido, caem em desuso e a gramática evolui, exigindo atualização.','Somente erros de impressão justificam revisões, não mudanças linguísticas históricas.','Traduções originais permanecem sempre claras, tornando revisões desnecessárias.','Bíblias em grego e hebraico nunca precisam de atualização por seremlanguages mortas.'),('FB12-L01-Q06','Nenhuma tradução reproduz todas as nuances das línguas originais.','Traduções modernas são inspiradas e infalíveis como o original.','O grego e o hebraico possuem menos recursos que o português.','Apenas traduções recentes captam o sentido do texto original.'),('FB12-L02-Q02','Preservar a estrutura e as palavras do texto hebraico e grego.','Facilitar a compreensão com linguagem atualizada e contemporanea.','Adaptar os textos para a cultura e costumes modernos.','Reproduzir o significado das ideias de forma livre e interpretativa.'),('FB12-L02-Q03','Preserva a estrutura gramatical e lexical do texto original hebraico e grego.','Adapta o texto ao vocabulario contemporaneo facilitando a compreensão do leitor.','Facilita a memorização do conteúdo através de linguagem poética e rítmica.','Substitui termos teológicos antigos por conceitos mais acessíveis.'),('FB12-L03-Q01','Prioriza o sentido do texto original sobre a forma literal, buscando o mesmo efeito no leitor moderno.','Mantém rigorosamente a estrutura gramatical e lexical do texto hebraico e grego original.','Traduz palavra por palavra sem considerar o contexto cultural ou histórico da época.','Utiliza apenas manuscritos tardios e versões traduzidas em vez dos originais.'),('FB12-L03-Q02','Tornar o sentido biblico inteligivel ao leitor atual','Demonstrar a veracidade das Escrituras Sagradas','Comparar diferentes traducoes da Palavra de Deus','Estabelecer a data de composicao dos livros biblicos'),('FB12-L02-Q04','Vocabulário arcaico, sintaxe complexa e expressões incompreensíveis.','Maior clareza interpretativa e maior fluência no texto final.','Simplificação excessiva e perda completa do sentido original.','Eliminar todas as dificuldades linguísticas automaticamente.'),('FB12-L02-Q05','As palavras mudam de sentido conforme o idioma; contexto importa na traducao.','Traducao formal exige que cada palavra tenha apenas um significado fixo.','Biblia Hebraica e Grega compartilham a mesma estrutura gramatical do Portugues.','Equivalencia formal significa usar a mesma quantidade de palavras do texto original.'),('FB12-L06-Q03','Acesso ao texto original e significado preciso das palavras hebraicas.','Permite compreender melhor os textos traduzidos para o grego clássico.','Garante que o leitor entenda automaticamente todos os idiomas bíblicos.','Elimina a necessidade de estudar qualquer contexto histórico-cultural.'),('FB12-L06-Q05','Com estudo do hebraico original e recursos lexicais confiáveis','Usando apenas a tradução mais literal disponível','Preferindo sempre a paráfrase em vez do texto original','Consultando apenas uma única tradução em português'),('FB12-L07-Q01','A Septuaginta como tradução do hebraico','A Primazia da Vulgata Latina sobre o grego','A tradução exclusiva do aramaico bíblico','A ausência de manuscritos gregos neotestamentários'),('FB12-L06-Q04','Falta de vogais no texto original e complexidade do sistema verbal hebraico.','O hebraico possui mais de 50 tempos verbais diferentes que complicam a traducao.','Todas as palavras hebraicas possuem apenas um unico significado fixo e claro.','A pontuacao e estrutura gramatical do hebraico sao identicas ao portugues.'),('FB12-L07-Q02','Equivalência formal ou dinâmica, escolha lexical, notas marginais','Tradução literal palavra por palavra sem considerar o contexto','Uso exclusivo de equivalência dinâmica sem preservação textual','Igualdade perfeita e completa de sentido entre todas as línguas'),('FB12-L06-Q02','Equivalencia formal ou dinamica, tratamento de termos teologicos e verbos hebraicos','Transliteracao direta de todos os termos hebraicos sem adaptacao ao idioma alvo','Substituicao completa do texto hebraico pela traducao grega dos Setenta','Revogacao de todos os termos teologicos em favor de sinonimos modernos'),('FB12-L07-Q04','Ambiguidade lexical, diferenças culturais e distância histórica do grego koiné.','Limitação principal é a falta de manuscritos gregos disponíveis para estudo.','Riscos centrados exclusivamente em erros de copistas medievais.','Dificuldades apenas de ordem fonética e de pronúncia do grego moderno.'),('FB12-L07-Q03','Acesso direto aos manuscritos originais e maior precisão teológica','Possibilidade de traduzir sem depender de versões anteriores','Redução do texto para facilitar a leitura devocional','Adaptação cultural dos textos bíblicos ao contexto moderno'),('FB12-L07-Q05','Recorrer a léxicos e gramáticas gregas confiáveis','Usar tradução literal sem exceções sempre','Ignorar o original e confiar apenas em traduções','Substituir o grego pelo latim na interpretação'),('FB12-L08-Q01','A distância entre o mundo cultural bíblico e o contemporâneo, dificultando traduções de costumes e expressões.','A necessidade de preservar a inspiração divina nas traduções para diferentes idiomas e nações.','A análise crítica dos manuscritos originais para determinar qual texto deve ser traduzido fielmente.','A impossibilidade de traduzir palavras gregas e hebraicas sem perder o sentido espiritual do texto.'),('FB12-L08-Q02','Decisões sobre tradução de termos culturalmente específicos e adaptação de referências.','Escolha de manuscritos-fonte para tradução e notas marginais explicativas.','Seleção de parábolas para ilustração de conceitos teológicos complexos.','Uso de dialetos regionais na transcrição de textos originais hebraicos.'),('FB12-L09-Q01','São hapax legomena, palavras com apenas uma ocorrência no texto','Nomes proprios divineos sempre traduzidos pelo tetragrama sagrado','Termos teologicos definidos exclusivamente pelo contexto imediato','Palavras de origem exclusivamente aramaica com correspondentes gregos'),('FB12-L08-Q05','Compreender o contexto histórico-cultural para interpretar corretamente as Escrituras.','Ignorar o contexto cultural e interpretar tudo de forma puramente literal.','Substituir a mensagem bíblica pelos valores culturais contemporâneos.','Usar apenas análises linguísticas sem considerar o ambiente cultural.'),('FB12-L08-Q04','Preconceito, discriminação e risco de sincretismo com práticas idólatras','Unanimidade cultural é alcançável através de diálogo inter-religioso','Diferenças culturais não afetam a comunhão cristã entre os povos','Dominância cultural garante harmonia nas relações interpessoais'),('FB12-L08-Q03','Proximidade com a cultura do Oriente Antigo','A Bíblia apresenta apenas cultura ocidental','Todos os costumes bíblicos são iguais aos atuais','O contexto cultural não influencia a interpretação'),('FB12-L09-Q02','Transliteração, equivalência dinâmica e paráfrase explicativa.','Tradução literal palavra por palavra sem adaptações.','Substituição automática por sinônimos de dicionário.','Remoção completa das palavras sem equivalente do texto.'),('FB12-L09-Q03','Preservam a riqueza semântica do texto sagrado original','Eliminam todas as barreiras culturais entre o leitor e o texto','Traduzem automaticamente todos os conceitos teológicos complexos','Substituem palavras difíceis por equivalentes modernos claros'),('FB12-L10-Q02','NAO SEI','Usam exclusivamente a Vulgata Latina como base textual','Eliminam todos os nomes próprios tradados do hebraico','Substituem termos teológicos por sinônimos populares indiscriminadamente'),('FB12-L09-Q04','Perda de nuanças, distorção cultural e ambiguidade interpretativa','Garantem precisão teológica e clareza doutrinária absoluta','Eliminam ambiguidade e preservam sentido original intacto','Proporcionam equivalência perfeita sem nenhuma perda semântica'),('FB11-L05-Q02','Tradição massorética, em hebraico, sobre pergaminho','Manuscritos gregos da Septuaginta, em papiro, tradição alexandrina','Rollos do Mar Morto, em aramaico, sobre papiro egípcio','Tradição samaritana, em grego koiné, sobre papiro'),('FB11-L06-Q02','Escritores judeus que adicionaram vogais ao texto consonantal hebraico, preservando sua pronúncia.','Tradutores que converteram a Bíblia hebraica para o grego nos séculos III e II a.C.','Sacerdotes que reescreveram os textos em aramaico para o povo entender durante o exílio.','Copistas que removeram livros inteiros do cânon hebraico no concílio de Jamnia.'),('FB11-L06-Q01','Texto hebraico bíblico preservado e padronizado pelos massoretas.','Tradução grega da Bíblia Hebraica realizada no século III a.C.','Manuscritos do Novo Testamento descobertos nas margens do Mar Morto.','Versão latina da Bíblia traduzida por Jerónimo de Estridão.'),('FB11-L14-Q02','Século V, grego, pergaminho, tradição alexandrina','Século III, latim, papiro, tradição ocidental','Século VIII, siríaco, pergaminho, tradição bizantina','Século II, grego, papiro, tradição de Roma'),('FB11-L05-Q05','Variacoes entre tradicoes textuais e possiveis erros scribais','Os manuscritos hebraicos sao todos idênticos e nao apresentam diferencas','Quanto mais recente o manuscrito, mais proximo esta do texto original','Comunidades isoladas geographicamente sempre preservaram o texto original'),('FB11-L13-Q05','Sua incompletude e correções posteriores exigem cuidado crítico.','Deve ser aceito sem questionamento como texto autoritativo.','Contém o texto exato e sem erros dos autores bíblicos.','Foi escrito no século II por testemunhas oculares.'),('FB11-L14-Q01','Manuscrito grego do século V com o Septuaginta e o Novo Testamento, na Biblioteca Britânica.','O manuscrito hebraico mais antigo da Bíblia, descoberto nas grutas de Qumran no século XX.','Tradução grega do Novo Testamento feita por Orígenes no século III, хранится em Alexandria.','Cópia do texto hebraico do Pentateuco feita por escribas assírios após o exílio da Babilônia.'),('FB11-L14-Q04','Preserva uma testemunha da tradição textual alexandrina','É o manuscrito mais antigo do Novo Testamento conhecido','Contém exclusivamente textos originais em hebraico','Demonstra que o texto bizantino é mais confiável'),('FB11-L14-Q03','Contém ambos os Testamentos em grego em escrita uncial do século V','É o mais antigo papiro do Novo Testamento, datando do século II','Representa exclusivamente o texto alexandrino puro, sem nenhuma influência','Manuscrito em latim da tradição itálica dos primeiros séculos'),('FB11-L14-Q05','Fragmentação, época tardia e text-type misto exigem cautela','Por ser muito antigo, é a testemunha mais confiável do NT','Está completo e intacto, sem necessidade de cuidados','Deve ser usado como base exclusiva para toda crítica textual'),('FB11-L15-Q01','Copiar, preservar e transmitir os textos sagrados às gerações futuras.','Interpretar e ensinar as leis sagradas ao povo.','Traduzir os textos originais para os idiomas vernáculos.','Compor e editar novos livros inspirados por Deus.'),('FB11-L15-Q04','Permite comparar variantes e identificar a forma mais próxima do original','Quanto mais manuscritos, mais certeza de que um deles é o texto exato','Todos os manuscritos são cópias perfeitas e eliminam a necessidade de crítica textual','Os manuscritos mais recentes preservam melhor a forma original do texto'),('FB11-L15-Q03','Pela imperfeição inerente à natureza humana na cópia','Porque os escribas introduziam alterações teológicas','Devido às guerras que destruíram manuscritos originais','Por causa das diferenças entre os idiomas originais'),('FB11-L15-Q02','Contar letras, palavras e linhas para verificar a cópia','Rezar antes de iniciar cada sessão de cópia','Destruir o original após completar a cópia','Usar papiro especial para melhor aderência da tinta'),('FB09-L16-Q03','Cânon, Tradição Apostólica, Uso Eclesiástico, Inspiração','Decreto Papal, Inquisicão Romana, Concílio de Trento','Manuscritos de Qumran, Tradicão Essena, Biblioteca de Alexandria','Oráculos Sibilinos, Escritores Clementinos, Heresia Montanista'),('FB09-L16-Q04','Mitos simplificam um processo gradual com critérios apostólicos, litúrgicos e de tradição.','Imperadores organizaram as Escrituras aleatoriamente sem critérios teológicos definidos.','Todas as tradições cristãs concordaram com os mesmos livros desde o primeiro século.','A organização bíblica baseou-se apenas em revelações sobrenaturais diretas aos líderes.'),('FB09-L16-Q05','O cânon não foi definido num único concílio, mas desenvolveu-se ao longo de séculos.','O cânon foi estabelecido pelo Papa na Idade Média através de um decreto infalível.','Todos os manuscritos de Qumran foram rejeitados por serem considerados hereges.','Apenas os livros escritos originalmente em aramaico foram aceitos no cânon.'),('FB10-L01-Q02','Romanos 1.19-20: Deus se manifesta pela criação, tornando-se perceptível ao ser humano.','João 3.16: Deus se revela exclusivamente pelo envio do Filho ao mundo.','Apocalipse 1.1: A revelação especial ocorre mediante sonhos e visões proféticas.','Mateus 5.17: Toda Escritura foi originalmente transmitida pela revelação geral.'),('FB10-L01-Q01','Revelação de Deus ao gênero humano mediante a criação e a consciência.','A comunicação divina exclusivamente pelas Sagradas Escrituras.','O conhecimento de Deus concedido aos profetas por meio de visões.','A revelação sobrenatural acessível aos escolhidos por Deus.'),('FB10-L07-Q04','As Escrituras são a norma suprema de fé e prática','Permite que cada leitor interprete livremente a Bíblia','Subordina as Escrituras à tradição e à razão humana','Limita o uso das Escrituras apenas ao culto público'),('FB10-L08-Q02','2 Timóteo 3:16 - Toda a Escritura é divinamente inspirada','Deuteronômio 18:18 - Deus levantaria um profeta como Moisés','A tradição oral da igreja como norma final de fé','Apocalipse 22:19 - Deus remove da Escritura os que a corrompem'),('FB10-L08-Q01','Doutrina de que as Escrituras sao inteiramente verdadeiras e sem erro','Doutrina que afirma que a Biblia e apenas uma among others inspired by God.','Doutrina de que a Biblia contem erros propositais para testing a fe dos fieis.','Doutrina que ensina que as Escrituras foram inspiradas por Deus, mas podem conter pequenos erros historicos.'),('FB10-L08-Q04','Inerrância garante que as Escrituras são plenamente verdadeiras e autoritativas em toda sua extensão.','Inerrância permite que cada fiel interprete a Bíblia segundo sua consciência individual, sem restrições.','Inerrância limita a autoridade bíblica apenas aos ensinamentos morais, excluindo aspectos históricos.','Inerrância requer que se desconsidere o contexto cultural e histórico de cada passagem bíblica.'),('FB10-L08-Q03','Inerrância afirma que a Bíblia em seus originais não contém erros; infallibilidade garante que ela não falhará em seu propósito salvífico.','Inerrância é menos rigorosa que infallibilidade, aceitando pequenos erros históricos e científicos nos originais.','Inerrância é sinônimo de inspiração verbal, significando que cada palavra da Bíblia foi ditada por Deus.','Inerrância refere-se principalmente à autoridade espiritual, não à precisão factual dos relatos bíblicos.'),('FB10-L08-Q05','Evitar literalismo excessivo e relativização da autoridade divina','Aceitar que a Bíblia contém apenas princípios morais gerais sem valor histórico','Exigir precisão científica em textos de gênero poético e profético','Rejeitar todos os manuscritos antigos como fontes textuais confiáveis'),('FB10-L09-Q02','2 Timóteo 3:16 - toda Escritura é inspirada por Deus','Mateus 16:18 - Pedro como fundamento da Igreja','João 3:16 - amor de Deus no envio do Filho','Gênesis 1:1 - criação ex nihilo do universo'),('FB10-L09-Q04','NAO SEI','Infalibilidade reduz a Escritura a mero documento historico.','Infalibilidade nega a necessidade de interpretacao teologica.','Infalibilidade limita a autoridade divina as Escrituras.'),('FB10-L09-Q03','Infalibilidade: a Bíblia não falha em cumprir seu propósito divino de revelar a vontade salvadora de Deus.','Inerrância é quando Deus ditou palavra por palavra cada texto da Bíblia aos seus escribas sagrados.','Revelação significa que toda informação histórica e científica da Bíblia deve ser absolutamente precisa.','Inspiração é a qualidade que torna todos os textos igualmente aplicáveis a qualquer contexto cristão.'),('FB10-L09-Q01','A Biblia e absolutamente confiavel e nao pode ensinar falsidade sobre Deus e a salvacao.','A infalibilidade significa que a Igreja tem autoridade maxima sobre a interpretacao da Biblia.','A infalibilidade e a mesma coisa que a inspiracao divina das Escrituras.','A infalibilidade garante que a Biblia esta correta em todos os detalhes cientificos.'),('FB10-L10-Q01','A doutrina de que a Bíblia contém tudo necessário para a fé e a vida cristã.','A doutrina de que a Bíblia contém apenas o necessário para a salvação, não para a vida prática.','A doutrina de que a Bíblia é suficiente apenas como base, necessitando de tradições complementares.','A doutrina de que a Bíblia precisa ser interpretada apenas pela razão humana, sem orientação divina.'),('FB10-L09-Q05','Evitar racionalismo que nega o sobrenatural e misticismo que ignora o contexto histórico-literário.','Evitar estudar demais as Escrituras para não perder a fé simples e ingênua.','A infalibilidade se aplica apenas aos ensinamentos morais e não aos fatos históricos.','Basta ler a Bíblia em português sem consultar traduções ou originais hebraicos e gregos.'),('FB10-L10-Q04','A suficiência estabelece que a Bíblia é norma suprema e suficiente para fé e prática cristã.','A suficiência permite que tradições eclesiásticas complementem a Escritura na autoridade espiritual.','A suficiência exige que a ciência moderne verifique e confirme os relatos bíblicos.','A suficiência significa que revelações pessoais têm igual autoridade aos textos sagrados.'),('FB10-L11-Q02','A claridade das Escrituras baseia-se em Salmo 119.105 e 2 Timóteo 3.16-17,ando que Deus iluminou o entendimento dos leitores pela sua Palavra.','A claridade das Escrituras fundamenta-se na tradição apostólica e nos concílios ecumênicos, que interpretam a vontade divina para os fiéis.','A claridade das Escrituras depende exclusivamente da iluminação do Espírito Santo sem qualquer base textual específica na Bíblia.','A claridade das Escrituras apoia-se mainly no livro de Apocalipse e nas profecias apocalípticas sobre o conhecimento dos últimos dias.'),('FB10-L11-Q03','É a capacidade da mensagem bíblica ser compreendida pelo leitor comum, separada da hermenêutica','É a qualidade de não possuir erros ou contradições textuais em todas as traduções','É o dom especial do Espírito Santo que revela o sentido oculto das Escrituras','Refere-se à capacidade de interpretar corretamente cada texto bíblico pela razão humana'),('FB13-L09-Q05','Quando contradiz o sentidoplain do texto','Quando o texto foi escrito em outra epoca','Quando a traducao apresenta palavras desconhecidas','Quando exige conhecimento de linguas antigas'),('FB13-L10-Q01','Compreender o texto conforme o sentido original pretendido pelo autor sagrado.','Ignorar o contexto histórico e cultural do texto sagrado.','Ler a Bíblia exclusivamente de forma simbólica e figurativa.','Aceitar cada palavra sem análise crítica ou questionamento.'),('FB13-L09-Q04','Conhecer o contexto histórico-cultural, extrair princípios atemporais e aplicá-los hoje','Ignorar completamente o texto bíblico e viver apenas segundo a consciência moderna','Alterar o sentido das Escrituras para que se adaptem aos valores culturais atuais','Considerar apenas o significado literal sem buscar princípios ou aplicações práticas'),('FB13-L10-Q03','Cada gênero requer regras hermenêuticas próprias para correta interpretação.','O gênero literario e irrelevante para a interpretação de qualquer texto.','Apenas o contexto histórico determina como entender uma afirmação.','Todas as passagens bíblicas devem ser interpretadas literalmente.'),('FB13-L10-Q04','Quando a interpretação literal contradiz o contexto','Sempre que o texto usa palavras hebraicas','Quando o leitor prefere interpretação espiritual','Quando o texto é do livro de Apocalipse'),('FB13-L10-Q02','Porque a interpretacao literal respeita a intencao do texto, que inclui метафораs е символos.','Porque метафораs е символos sao erros textuais que devem ser corrigidos na interpretacao.','Porque a Escritura nao содержит linguagem figurada, sendo totalmente literal.','Porque символos devem ser sempre reinterpretados de forma puramente espiritual.'),('FB13-L11-Q02','Porque revela verdades espirituais que a linguagem literal não exprime plenamente.','Porque torna o texto mais bonito e agradável ao leitor contemporâneo.','Porque elimina a necessidade de estudar o contexto histórico da passagem.','Porque permite ao leitor interpretar livremente conforme sua opinião pessoal.'),('FB10-L11-Q01','A doutrina de que a Biblia e clara em sua mensagem para ser compreendida.','A doutrina de que apenas teologos especializados entendem as Escrituras.','A crenca de que toda passagem biblica tem igual nivel de dificuldade.','A ideia de que a Biblia nunca requer interpretacao para ser compreendida.'),('FB10-L10-Q05','Acrescentar ou tirar da Palavra, e exigir que ela responda sobre o que não trata.','O texto sagrado deve ser compreendido exclusivamente por teólogos formados academicamente.','A Escritura é suficiente apenas para determinar questões de salvação, não para a vida prática.','Deve-se rejeitar toda reflexão teológica e filosófica para interpretar as Escrituras.'),('FB10-L11-Q04','A clareza das Escrituras permite a todos compreendem a mensagem de salvação.','A interpretação correcta requer erudição oficial e autoridades religiosas reconhecidas.','A clareza das Escrituras significa que não há necessidade de estudo ou iluminação.','A ambiguidade bíblica permite que cada interpretação seja igualmente válida.'),('FB12-L09-Q05','Por meio de análise contextual e recursos lexicais, respeitando a intenção do autor.','Substituindo sempre por termos teológicos modernos para melhor adaptação ao leitor.','Ignorando diferenças culturais e aplicando o sentido literal direto em qualquer contexto.','Traduzindo livremente conforme a compreensão e experiência pessoal do leitor.'),('FB12-L10-Q01','Base textual no Texto Received, traducao formal e sem livros deuterocanonicos','Utilizam o Codice Vaticano e incluem todos os livros deuterocanonicos como canonicos','Seguam a traducao livre de Jeová e eliminam todos os nomes divinos hebraicos','Priorizam equivalencia dinamica com linguagem contemporanea e acessivel ao leitor'),('FB12-L10-Q05','Consultar originais hebraicos e gregos, comparar traduçōes e contexto.','Usar exclusivamente uma única traduçāo sem consultar outras.','Priorizar sempre a traduçāo mais moderna e acessível.','Ignorar notas e comentários de estudiosos e tradutores.'),('FB12-L10-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB12-L11-Q01','Inclusão dos livros deuterocanônicos','Uso exclusivo da Bíblia Hebraica como base','Ausência completa de livros poéticos','Tradução feita únicamente do grego koiné'),('FB12-L10-Q04','Perdas de nuances hebraicas e gregas, escolhas terminológicas com implications doutrinários e diferenças entre equivalência formal e dinâmica','Traduções protestantes em português têm sua可靠性 comprometida por serem baseadas em manuscritos tardios e menos confiáveis','Todas as traduções protestantes em português foram deliberadamente editadas para remover conteúdo teológico essencialmente católico','As limitações incluem erros intencionais de tradução motivados por agendas políticas e econômicas específicas do protestantismo'),('FB12-L11-Q03','Inclusão dos livros deuterocanônicos e notas da tradição católica','Exclusivamente a tradução dos originais em hebraico e aramaico','Ausência de qualquer nota ou comentário explicativo ao leitor','Tradução limitada apenas aos quatro Evangelhos canônicos'),('FB13-L10-Q05','Erros de interpretação literal e perda do sentido simbólico espiritual','Gera maior precisão teológica e fortalece a compreensão bíblica','Aproxima a linguagem poética do entendimento científico atual','Elimina a necessidade de estudar o contexto histórico-cultural'),('FB13-L11-Q01','Linguagem que usa imagens, símbolos ou comparações para transmitir verdades além do sentido literal.','Linguagem usada exclusivamente pelos profetas do Antigo Testamento.','Forma de comunicação divina que substitui completamente a mensagem literal da Bíblia.','Técnica literária que invalida qualquer interpretação histórica dos textos bíblicos.'),('FB13-L11-Q05','NAO SEI','Linguagem figurada deve ser totalmente ignorada na aplicação moderna do texto biblico.','Aplica-se apenas o sentido literal, pois linguagem figurada e inválida para interpretação.','Deve-se considerar apenas o contexto histórico-cultural sem relação com aplicaçao atual.'),('FB13-L12-Q02','O princípio hermenêutico de que passagens claras iluminam as obscuras.','Anulando completamente o significado das passagens difíceis.','Eliminando a necessidade de estudo da Palavra de Deus.','Substituindo a autoridade bíblica por tradições humanas.'),('FB13-L12-Q03','Porque a Escritura não se contradiz, e Cristo é o centro de toda a revelação.','Porque os tradutores cometeram erros em toda a Bíblia.','Porque o Espírito Santo guia cada leitor individualmente sem limites.','Porque apenas os teólogos modernos podem interpretar corretamente.'),('FB13-L12-Q01','Interpretar textos biblicos dificeis à luz do ensino claro da Escritura como um todo.','Buscar fora da Biblia significados espiritualizados para trechos biblicos obscuros.','Usar a razão humana como criterio final para entender a vontade de Deus.','Comparar a Biblia apenas com a tradicao dos pais da igreja primitiva.'),('FB13-L12-Q04','NAO SEI','O risco é construir uma teologia equilibrada e bem fundamentada','O risco é garantir uma interpretaçao mais precisa da Escritura','O risco é fortalecer a autoridade das Escrituras de forma segura'),('FB13-L11-Q03','Qual o sentido literal por tras da figura?','Devemos ignorar o contexto historico e cultural.','A linguagem figurada deve ser interpretada literalmente sempre.','O significado emocional e mais importante que o texto.'),('FB13-L11-Q04','Eisegese ou má interpretação das Escrituras','Exegese fiel ao texto original','Plenitude da revelação divina preserved','Ampliação legítima da mensagem profética'),('FB13-L12-Q05','NAO SEI','A analogia da fé permite interpretar toda a Escritura segundo uma única passagem central','Deve-se usar a analogia da fé para corrigir todas as passagens que parecem contraditórias','A analogia da fé anula a necessidade de considerar o contexto histórico-cultural'),('FB13-L13-Q01','Passagens faceis versus as que precisam de analise mais profunda.','Textos de diferentes traducoes da Biblia que variam entre si.','Passagens que foram alteradas por copistas ao longo dos seculos.','Textos que devem ser interpretados apenas pelos lideres religiosos.'),('FB13-L14-Q01','NAO SEI','Texto descritivo sao aqueles que usam linguagem figurada e metaforas abundantemente','Texto descritivo e narrativo sao termos sinonimos na analise textual','A diferenca esta no numero de paragrafos, sendo o descritivo sempre mais curto'),('FB13-L13-Q02','Porque a Escritura interpreta a Escritura, e textos claros iluminam os obscuros.','Porque textos dificeis sempre contradizem os claros em toda a Escritura.','Porque os textos obscuros sao mais importantes que os claros para a fe.','Porque devem ser interpretados apenas pelos lideres religiosos.'),('FB13-L13-Q03','Para textos claros: qual o sentido plain? Para textos difficeis: qual o contexto historico e cultural?','Para textos claros: ignore o contexto. Para textos difficeis: use qualquer traducao disponivel.','Para textos claros: busque significados ocultos. Para textos difficeis: interprete segundo sua opiniao.','Para textos claros: aplique qualquer significado. Para textos difficeis: rejeite o texto como corrupto.'),('FB13-L13-Q05','Os textos claros iluminam e interpretam os difíceis, nunca o contrário.','Textos difíceis devem ser usados para questionar a autoridade dos claros.','Ambos possuem igual autoridade e devem ser interpretados independentemente.','Textos claros devem ser adaptados conforme o entendimento dos difíceis.'),('FB12-L19-Q04','Explicam criterios de traducao e variantes textuais.','Fornecem oracoes adicionais nao presentes no texto.','Substituem termos hebraicos por palavras em grego.','Apontam exclusivamente erros de copistas medievais.'),('FB12-L19-Q05','Porque o sentido das palavras depende do contexto em que são usadas.','Porque todas as traduções bíblicas transmitem o mesmo significado exato.','Porque o contexto histórico é irrelevante para traduções modernas.','Porque comparando traduções elimina-se completamente a necessidade de contexto.'),('FB12-L19-Q03','Estilo e forma de escrever; interpretacao e significado do texto.','Estilo muda o significado; interpretacao preserva a mensagem original.','Estilo afeta a doutrina; interpretacao e apenas sobre vocabulario.','Estilo se aprende na escola; interpretacao e dom espiritual.'),('FB12-L20-Q01','Fidelidade aos textos originais, metodologia de tradução e legibilidade.','A popularidade da tradução e o número de exemplares vendidos.','A cor da capa, o design e a qualidade do papel utilizado.','O país de origem da editora e a religião dos tradutores.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB12-L19-Q06','Formal para estudo exegetico, funcional para leitura devocional','Substituir uma pela outra conforme a preferencial pessoal','Misturar versiculos de ambas sem criterio theological','Utilizar apenas notas de rodape para escolher qual usar'),('FB12-L20-Q03','Porque alta fidelidade pode reduzir legibilidade e vice-versa, exigindo equilíbrio.','Porque fidelidade é sempre mais importante que legibilidade nos textos sagrados.','Porque legibilidade deve sempre prevalecer sobre fidelidade em traduções.','Porque são conceitos independentes sem relação entre si na tradução.'),('FB13-L01-Q01','Ciência da interpretação das Santas Escrituras.','Arte de traduzir a Bíblia para línguas modernas.','Estudo dos manuscritos originais do Antigo Testamento.','Disciplina que cataloga os livros da Bíblia canônica.'),('FB12-L20-Q02','Estudo acadêmico pede formal; devocional, tradução funcional.','Tradução formal traduz palavra por palavra sem exceção.','Leitura devocional exige análise gramatical detalhada.','O objetivo de leitura não interfere na escolha da tradução.'),('FB12-L20-Q04','Garantir fidelidade ao texto original e evitar vieses teológicos','Facilitar a adaptação do texto para diferentes contextos culturais','Possibilitar maior rapidez na publicação de novas edições','Permitir que cada geração reescreva a Bíblia conforme sua visão'),('FB12-L20-Q05','Para compreender melhor nuances do texto original e evitar interpretações limitadas.','Para identificar erros em todas as traduções e encontrar a versão perfeita.','Para escolher a tradução mais fácil de memorizar sem esforço.','Para determinar qual tradução Deus prefere e abençoa mais.'),('FB13-L01-Q02','Compreender o sentido original das Escrituras e aplicá-lo corretamente.','Traduzir os textos bíblicos para diferentes idiomas e línguas modernas.','Memorizar os versículos das Escrituras para edificação espiritual.','Provar doutrinas e tradições teológicas a partir dos textos.'),('FB13-L01-Q03','Hermenêutica é a teoria da interpretação; exegese é a prática interpretativa.','Hermenêutica estuda os manuscritos antigos; exegese analisa traduções modernas.','Exegese é a arte de pregar; hermenêutica é o estudo da história da Igreja.','São sinônimos perfeitos, não há diferença entre eles no estudo bíblico.'),('FB13-L01-Q06','Do estudo do contexto histórico-cultural, gramatical e literário da Escritura.','Permite interpretar qualquer passagem conforme a convicção pessoal do leitor.','Baseia-se principalmente na intuição espiritual individual e direta.','Consiste em adaptar o significado bíblico aos valores culturais modernos.'),('FB13-L01-Q04','Porque cada palavra depende do seu contexto para revelar o sentido correto.','Porque a Bíblia foi escrita em línguas mortas que exigem tradução literal.','Porque os originalistas da Bíblia são mais sábios que os estudiosos modernos.','Porque Deus inspirou apenas versículos soltos, não passagens inteiras.'),('FB13-L01-Q05','Contexto histórico-cultural, gênero literário, texto original e intenção autoral.','Apenas o significado literal em português atual, desconsiderando o contexto.','A tradição eclesiástica e os comentários modernos substituem toda análise.','A inspiração divina dispensa o estudo do contexto histórico e linguístico.'),('FB13-L02-Q01','A intenção do autor é fundamental para interpretar corretamente o texto bíblico.','O autor não tem relevância na interpretação; basta aplicar o texto ao contexto moderno.','A interpretação bíblica deve basear-se apenas na experiência pessoal do leitor.','O sentido do texto bíblico muda conforme a época, e o leitor decide seu significado.'),('FB13-L03-Q01','É o parágrafo ou seção ao redor da passagem que ajuda a compreender seu sentido.','É o contexto histórico e cultural da época em que o livro foi escrito.','É o significado original das palavras em grego e hebraico.','É o contexto de toda a Bíblia e sua mensagem geral.'),('FB13-L03-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB13-L02-Q02','Porque a Escritura, sendo inspirada pelo Espirito Santo, possui sentido fixo.','Porque foi escrita por multiplos autores com intencoes distintas e contraditorias.','Porque os tradutores introduziram erros propositais no texto sagrado.','Porque a interpretacao depende exclusivamente do contexto cultural moderno.'),('FB13-L02-Q03','Contexto, pré-conceitos e experiências do leitor moldam a compreensão do texto.','O leitor não exerce influência alguma sobre a interpretação do texto.','Apenas o texto em si determina o significado, independentemente do leitor.','A leitura é sempre objetiva e livre de influências pessoais.'),('FB13-L13-Q04','Eisegese, ou seja, ler自己的想法 nos textos biblicos','Redacao propria, criando doutrinas fora das Escrituras','FUNDAMENTALISMO, rejeitando qualquer interpretacao critica','Censura textual, removendo trechos considerados difficeis'),('FB13-L02-Q05','Por meio do método histórico-gramatical em equilíbrio com aplicação responsável','Ignorar o texto e se guiar únicamente pela intuição espiritual do momento','Privilegiar exclusivamente a intenção original sem considerar a atualização','Aplicar apenas análise literária contemporânea sem atenção ao contexto histórico'),('FB13-L03-Q02','Para compreender o contexto e evitar interpretações erradas da Escritura.','Porque os versículos foram escritos fora de ordem cronológica.','Para encontrar mensagens ocultas escondidas entre os versículos.','Porque os tradutores cometem erros que só são corrigidos no contexto.'),('FB12-L12-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB12-L12-Q01','Tradutor português da Bíblia para a língua portuguesa','Apóstolo que pregou o evangelho em Portugal no século I','Autor do livro de Apocalipse na Bíblia sagrada','Bispo da Igreja Católica que canonizou a Bíblia em português'),('FB12-L11-Q02','Inclusão dos livros deuterocânicos e uso de termos específicos como Cúrio','Uso exclusivo do latim eclesiástico em todas as traduções católicas','Substituição completa dos nomes próprios hebraicos por nomes portugueses','Exclusão de todos os livros do Antigo Testamento canonizados após o Concílio de Trento'),('FB12-L11-Q04','Viés teológico, deuterocanônicos e terminologia própria do magistério.','Ausência de manuscritos originais hebraicos e gregos na tradução.','Identidade textual perfeita com traduções protestantes brasileiras.','Exclusão dos livros históricos e poéticos do Antigo Testamento.'),('FB12-L12-Q02','A Almeida Revista e Corrigida foi a principal tradução protestante em português, levando as Escrituras ao povo.','Foi a primeira tradução da Bíblia diretamente do hebraico e aramaico para qualquer língua moderna.','A tradução de Almeida tornou-se a versão oficial adotada exclusivamente pela Igreja Católica Romana.','Traduziu toda a Bíblia do latim para o português no século XII, antes da Reforma Protestante.'),('FB12-L12-Q05','Língua atualizada, correções e notas de tradução em relação ao original.','O texto grego e hebraico foi completamente alterado na edição moderna.','Apenas mudaram o formato da letra e a diagramação do texto.','As diferenças são apenas nos livros deuterocanônicos additions.'),('FB12-L11-Q05','Consultar várias traduções e compreender as diferenças teológicas.','Usar exclusivamente traduções católicas, pois são as mais confiáveis.','Rejeitar todas as traduções católicas por serem inferiores.','Aceitar qualquer tradução sem analisar o texto original.'),('FB12-L12-Q04','Avanços na crítica textual e novas descobertas de manuscritos.','Decisão pessoal de João Ferreira de Almeida de refazer o trabalho.','Proibição da Igreja Católica de utilizar a tradução original.','Diferenças entre traduções espanholas que exigiram ajustes.'),('FB13-L14-Q02','Porque relatar é narrar fatos, não é validar moralmente ações.','Porque Deus aprova automaticamente tudo que a Bíblia registra.','Porque a Bíblia contém apenas ações morais exemplares.','Porque os autores bíblicos validavam todas as ações registradas.'),('FB16-L10-Q03','Substituir substantivos na frase','Indicar ação verbal no tempo','Conectar orações coordenadas','Determinar o gênero dos verbos'),('FB16-L10-Q05','Identifica sujeitos e evita ambiguidade no texto hebraico.','Determina o período histórico da composição do livro.','Facilita a contagem das palavras hebraicas do AT.','Identifica o local geográfico de origem do autor.'),('FB16-L11-Q02','Preposições hebraicas são geralmente prefixos unidos às palavras: ב ל כ מ.','Preposições hebraicas são sempre palavras separadas, nunca prefixadas.','Preposições hebraicas são formadas apenas pela vogal sheva sob as letras.','Preposições hebraicas são identificadas apenas pelo ponto daguesh interno.'),('FB16-L10-Q02','Pronomes hebraicos existem como palavras independentes e como sufixos.','Pronomes hebraicos sao formados exclusivamente por sufixos verbais.','O hebraico biblico nao possui pronomes pessoais independentes.','Pronomes no hebraico sao sempre representados por Numeros cardinais.'),('FB16-L10-Q04','Ele pegou o livro e o deu a ela.','Jesus ama o pecador e o transforma em filho.','Maria foi ao templo e la orou por todos.','Pedro caminhou ate o mar e lá encontrou Jesus.'),('FB16-L11-Q01','NAO SEI','Termos que indicam pessoa, número e gênero nos verbos hebraicos','Conectivos que estabelecem relações de causa e consequência','Advérbios de tempo que modificam a ação verbal hebraica'),('FB16-L12-Q01','É o estado do substantivo hebraico quando ligado diretamente a outro substantivo.','É a forma verbal hebraica usada para exprimir desejos e súplicas.','É o estado do adjetivo hebraico que indica comparação entre dois elementos.','É o modo verbal hebraico que expressa ações futurascertainas.'),('FB16-L11-Q03','Estabelecer relações gramaticais entre termos da frase','Conectar orações coordenadas entre si','Indicar a pessoa do verbo conjugado','Marcar o gênero dos substantivos'),('FB16-L11-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB16-L11-Q05','Porque preposições hebraicas indicam relações gramaticais e teológicas','Porque são palavras invariáveis que nunca afetam o sentido original do texto','Porque determinam exclusivamente a cronologia dos eventos narrados','Porque permitem identificar quais livros pertencem ao Pentateuco'),('FB16-L12-Q02','Pela junção direta de dois substantivos, sem uso de preposição.','Usa-se a preposição min para indicar relação de pertencimento.','',''),('FB16-L12-Q03','NAO SEI','Estrutura sintatica do texto biblico que indica jerarquia entre personagens','Sequencia de narrativas biblicas conectadas por temas comuns e genealogicos','Forma poetica hebraica usada nos livros profeticos e nos Salmos'),('FB16-L12-Q04','O substantivo pode ter sua vogal alterada ou ser abreviado no estado construto.','O substantivo recebe um sufixo especial para indicar o estado construto.','O substantivo no estado construto sempre dobra sua consoante inicial.','O substantivo construto muda apenas de posição na frase.'),('FB16-L13-Q03','Expressar ações, estados e eventos com voz, modo e aspecto.','Indicar principalmente relações temporais de passado e futuro.','Funcionar como substantivos nominais no texto biblico.','Conjugar-se apenas para pessoa, numero e genero.'),('FB16-L13-Q02','Pelos binyanim, padrões de conjugação baseados na raiz triliteral hebraica.','Pela vocalização massorética e os pontos diacríticos sobre as consoantes.','Pela posição das letras no alfabeto hebraico e sua numeração tradicional.','Através do nome sagrado de quatro letras adicionado em cada句子.'),('FB16-L12-Q05','Indica a relacao de posse entre substantivos, essencial para traducao fiel.','Determina se o substantivo Hebraico e masculino ou feminino.','Identifica se o texto Biblico e narrativa ou texto poetico.','Distingue se o nome proprio e de personagem ou lugar.'),('FB16-L13-Q04','Bara Elohim et hashamayim ve''et ha''arets (Gn 1.1)','Shema Yisrael Adonai Eloheinu Adonai Echad (Dt 6.4)','Vayomer Elohim haja or vayehi or (Gn 1.3)','Ani Ehyeh asher Ehyeh (Êx 3.14)'),('FB16-L13-Q05','Porque verbos hebraicos expressam tempo, aspecto e voz na Escritura.','Porque o hebraico bíblico é igual ao aramaico usado na Kabbalah medieval.','Porque os verbos hebraicos contêm códigos numéricos secretos da Torá.','Porque o Antigo Testamento foi composto inteiramente em prosa narrativa.'),('FB16-L14-Q01','Conjunto de três consoantes que originam as conjugações verbais hebraicas.','Vogal prefixada ao verbo que indica o tempo e modo da ação verbal.',' substantivo concreto derivado de um verbo na literatura veterotestamentária.','Partícula separadora entre palavras para indicar pausa no texto massorético.'),('FB13-L02-Q04','Pois quem interpreta mal a Escritura se extravia da verdade.','Para que a leitura se tornemais rapida e proveitosa.','Porque a aplicacao sem compreensao e sinal de maturidade.','Para que o leitor possa compartilhar a Palavra com outros.'),('FB13-L03-Q04','NAO SEI','O contexto histórico-campal e a geografia do texto sagrado','Os nomes dos autores inspirados e suas circunstâncias de vida','A tradução exata de todos os termos hebraicos e gregos'),('FB15-L01-Q02','Estabelecer o texto original das Escrituras.','Provar que a Bíblia contém erros e contradições.','Traduzir a Bíblia para línguas vernáculas.','Determinar a interpretação teológica correta.'),('FB15-L01-Q01','Estudo dos manuscritos bíblicos para determinar o texto original','Tradução da Bíblia para línguas modernas e contemporâneas','Análise das narrativas e temas centrais das Escrituras','Estudo da gramática e do léxico das línguas bíblicas'),('FB15-L01-Q06','Porque busca restaurar o texto original, não substituí-lo por outro.','Porque questiona a inspiração divina e a autoridade das Escrituras.','Porque aplica métodos humanos que substituem a revelação divina.','Porque prova que a Bíblia contém erros intencionais dos autores.'),('FB15-L01-Q04','Evidência externa e interna','Evidência arqueológica e linguística','Evidência textual e doutrinária','Evidência profética e apostólica'),('FB15-L02-Q04','Permitem comparar variantes e identificar o texto mais próximo do original.','Eliminam a necessidade de análise crítica textual moderna.','Garantem que todas as cópias são idênticas ao texto original.','Impedem que novos erros sejam introduzidos nas traduções.'),('FB15-L01-Q05','Recupera o texto original; as outras analisam contexto e forma.','Estuda a autoria e intencao do autor biblical.','As tres se preocupam igualmente com o contexto historico.','Analisa o significado teologico dos textos sagrados.'),('FB15-L01-Q03','Para identificar a leitura mais próxima do texto original entre as variantes.','Porque os escribas copiavam sem erros e precisamos confirmar sua perfeição.','Para provar que a Bíblia tem erros e invalidar sua inspiração.','Porque todos os manuscritos são idênticos e precisamos verificar a uniformidade.'),('FB15-L02-Q01','Manuscritos originais dos livros bíblicos escritos pelos autores inspirados por Deus','Antigas cópias dos livros bíblicos preservadas em arquivos e museus religiosos','Primeiras traduções da Bíblia do hebraico e grego para outros idiomas','Livros considerados apócrifos, excluídos do cânon das Escrituras'),('FB15-L02-Q03','Cópias dos textos bíblicos originais feitas por escribas ao longo dos séculos.','Manuscritos originais escritos pelos próprios apóstolos e profetas.','Edições impressas da Bíblia publicadas após a invenção da prensa.','Textos traduzidos diretamente do hebraico e grego para o português.'),('FB15-L03-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB15-L02-Q02','Porque se perderam ao longo dos séculos por deterioração, perseguições e uso constante.','Porque foram recolhidos por anjos e preservados nos céus para os últimos dias.','Porque os Padres da Igreja primitiva os consideraram demasiado sagrados para existir.','Porque nunca foram realmente escritos, sendo apenas tradição oral dos primeiros séculos.'),('FB15-L02-Q05','Inspiração aplica-se aos originais; variantes são erros em cópias.','Inspiração abrange tanto originais quanto cópias com igual autoridade.','Variantes textuais eliminam completamente a inspiração bíblica.','Ambos os conceitos referem-se exclusivamente às cópias antigas.'),('FB15-L03-Q01','Categorias classificadas conforme a natureza das diferenças entre manuscritos','Métodos de datação dos manuscritos antigos do texto bíblico','Classificação das escolas teológicas que analisam o texto sagrado','Tipos de traduções bíblicas baseados na tradição textual'),('FB15-L03-Q04','Não considera singularidades de cada escriba e tradição textual','Garantem automaticamente a prioridade textual por sua frequência','Elimina a necessidade de examinar o contexto teológico','Substitui a análise da história da transmissão textual'),('FB15-L04-Q01','Escorregões mecânicos na cópia do texto, como troca de letras ou omissão de palavras.','Erros propositais para alterar doutrina ou adaptar o texto a interesses específicos de grupos.','Tentativas conscientes dos escribas de melhorar o estilo literário e a eloquência da escritura.','Falsificações intencionais feitas por copistas para vender manuscritos como originais e lucrar.'),('FB15-L03-Q03','NAO SEI','Variações lexicais, gramaticais, de ordem e de transliteração','Testemunhos textuais,考古学研究 e análises linguísticas','Classificações de manuscritos em categorias A, B, C e D'),('FB15-L04-Q03','Erros involuntários revelam hábitos de cópia que identificam famílias textuais.','Erros intencionais demonstram authorized alterações doutrinais nas cópias.','Copistas eliminavam todos os erros sem critério para uniformizar textos.','Variações ortográficas eram padronizadas para manter fidelidade total.'),('FB15-L04-Q04','A escassez de manuscritos originais e a difficuldade de determinar o que constitue erro involuntário.','O fato de que todos os erros scribais foram comprovadamente intencionais e propositais.','A certeza de que erros involuntários nunca ocorreram em qualquer manuscrito biblico.','A abundancia total de manuscritos autografos disponiveis para comparação direta.'),('FB15-L05-Q01','Modificações deliberadas dos escribas no texto bíblico durante a cópia.','Erros acidentais de transcrição cometidos por escribas desatentos.','Mudanças na estrutura gramatical das línguas hebraica e grega.','Alterações feitas exclusivamente por tradutores modernos da Bíblia.'),('FB15-L04-Q02','Variações textuais accidentais','Testemunhos patrísticos e rabbinicos','Evidências arqueológicas e manuscritos','Cânones deuterocanônicos e apócrifos'),('FB12-L13-Q02','NAO SEI','Uso do texto Received Text de Theodore Beza como base textual grega.','Substituição de termos aramaicos por equivalentes em português arcaico.','Revisão exclusiva do Antigo Testamento em hebraico massorético.'),('FB12-L13-Q03','Fidelidade aos textos originais hebraico e grego','Tradução exclusivaapproved pela Igreja Católica','Versão mais recente entre as bíblicas em português','Integração nativa com dispositivos móveis android'),('FB12-L13-Q01','Revisão fiel da tradução de Almeida com linguagem formal e fidelidade aos originais hebraicos e gregos.','Paráfrase moderna destinada ao grande público, com linguagem contemporânea e simplificada.','Tradução baseada exclusivamente na Vulgata Latina com influências明显的 de textos medievais.','Versão limitada apenas ao Novo Testamento, sem incluir os livros do Antigo Testamento.'),('FB13-L15-Q02','Analisando o contexto historico e literario da promessa biblica','Verificando apenas o livro e capitulo onde a promessa se encontra','Aceitando a promessa diretamente para sua vida sem analise','Perguntando a qualquer lider religioso qual a aplicacao'),('FB13-L15-Q05','Perder o sentido contextual, criar legalismo e ignorar condições.','Garantir que Deus sempre agirá conforme nossa interpretação pessoal.','Eliminar a necessidade de sabedoria e discernimento espiritual.','Permitir que cada um defina livremente seu próprio significado.'),('FB13-L15-Q03','Promessas específicas a Israel não se aplicam automaticamente aos cristãos.','Sim, todas as promessas do AT se aplicam diretamente aos cristãos hoje.','Não, pois o NT anula completamente todas as promessas do AT.','Apenas promessas sobre salvação podem ser aplicadas diretamente.'),('FB13-L16-Q01','Alianca antiga e a Lei de Moises; nova alianca e o sacrificio de Cristo pelos pecadores.','Antiga alianca e promessas de Deus ao povo de Israel; nova alianca e a promessa do reino milenar.','Antiga alianca e o periodo do Antigo Testamento; nova alianca e a era da igreja primitiva.','Antiga alianca e o pacto com Abrao; nova alianca e a Lei dada por Moises aos hebreus.'),('FB13-L16-Q03','Qual a continuidade e descontinuidade entre as alianças e como se cumpriram em Cristo?','Qual a autoridade eclesial necessaria para interpretar cada alianca de forma separada?','Deve-se aplicar os mesmos metodos de interpretacao sem nenhuma distinção entre as alianças?','As alianças sao completamente independentes e nao mantem relacao alguma entre si?'),('FB13-L15-Q04','Estudar o contexto histórico e literário da promessa','Ignorar o contexto e aplicar literalmente ao今天','Adaptar o sentido conforme a necessidade atual','Extrair princípios sem considerar o audience original'),('FB13-L16-Q02','Porque a Nova Aliança cumpre e revela o sentido pleno da Antiga Aliança.','Porque a Antiga Aliança foi completamente abolida e não possui mais validade.','Porque as duas alianças são completamente independentes e não mantêm relação alguma.','Porque o entendimento das alianças substitui a necessidade de conhecer os idiomas originais.'),('FB13-L16-Q04','Confusão entre lei e graça','Perda da autoridade bíblica','Rejeição dos Dez Mandamentos','Abolição do Antigo Testamento'),('FB13-L17-Q01','Messias, o ungido, promessa divina de salvação ao povo','O nome sagrado de Deus Pai revelado aos profetas','A personificação da Lei mosaica dada a Moisés','O anjo exterminador enviado contra os primogênitos'),('FB13-L17-Q04','Tirar Cristo do Antigo Testamento','Romper a unidade das doze tribus de Israel','Duvidar da inspiração dos livros profeticos','Negar a autoridade das Escrituras Santas'),('FB13-L17-Q02','Porque Cristo é o cumprimento das Escrituras','Porque permite interpretar os textos fora do seu contexto original','Porque foi uma prática introduzida pelos primeiros pais da Igreja','Porque os manuscritos hebraicos exigem essa referência cristológica'),('FB13-L18-Q01','É interpretar um versículo отдельно do texto ao redor, alterando seu sentido original.','É copiar versículos para um caderno separado da Bíblia sagrada.','É recitar versículos de memória sem consultar o texto bíblico completo.','É marcar versículos com coloridos sem ler o restante do capítulo.'),('FB13-L16-Q05','Lei moral permanece, ceremonial e civil foram cumpridas em Cristo.','O Antigo Testamento foi totalmente abolido e nao possui mais validade.','Ambas as alianças se aplicam de forma identica e sem distincoes.','A Nova Alianca torna o Antigo Testamento completamente dispensavel.'),('FB13-L18-Q02','Eisegese é ler自己的想法 no texto bíblico, devendo ser evitada para preservar o sentido original.','Eisegese é um método de traducão da Bíblia aprovado pelos pais da Igreja primitiva.','Eisegese é uma forma de oração contemplativa usada nos mosteiros antigos.','Eisegese é o nome de um livro apócrifo excluído do cânon bíblico.'),('FB13-L18-Q03','NAO SEI','Porque as palavras perderam todo significado apos a queda da torre de Babel','Porque os dicionarios modernos se baseiam apenas na tradicao oral e nao escrita','Porque o significado original foi alterado por conspiracao dos tradutores biblicos'),('FB13-L17-Q05','Cristo revela o sentido pleno e a aplicação correta do texto','Cristo não tem nenhuma relevância na interpretação do AT','O AT deve ser lido isoladamente de sua conclusão em Cristo','Aplicam-se ao AT apenas os preceitos da Lei mosaica'),('FB13-L18-Q05','O sentido do texto esta no autor e contexto, nao na experiencia pessoal.','A experiencia pessoal revela o sentido verdadeiro da Escritura.','O sentido do texto depende da leitura individual e subjectiva.','A interpretacao correta da Biblia vem da subjectividade pessoal.'),('FB13-L18-Q06','Leituras prévias causam eisegese, distorcendo o sentido textual.','A interpretação correta depende apenas de conhecimento linguístico.','Doutrinas sempre confirmam o sentido original sem distorções.','Preferências pessoais não afetam a hermenêutica bíblica.'),('FB13-L18-Q04','Impor significados subjetivos que desvirtuam o sentido original da Escritura','Enriquecer a compreensão espiritual através de múltiplas camadas de sentido','Preservar a harmonia doutrinária entre todas as tradições cristãs','Eliminar o risco de interpretações excessivamente literais da Bíblia'),('FB16-L13-Q01','Formas verbais derivadas de raízes de três letras organizadas em sete binyanim.','Formas verbais derivadas de raízes de duas letras organizadas em quatro binyanim.','Palavras invariáveis que expressam estados e qualidades dos seres.','Letras que formam nomes e adjetivos na gramática hebraica.'),('FB16-L14-Q02','As raízes hebraicas derivam do hebraico antigo, sistema trilítero semítico.','Porque os três consolos representam a Trindade divina na revelação bíblica.','O sistema de três consoantes foi inventado pelos escribas durante o cativeiro.','As raízes hebraicas usam três letras para indicar gênero, número e caso gramatical.'),('FB15-L04-Q05','Exigem análise crítica textual para identificar variantes e avaliar sua relevância.','Indicam que as Escrituras originais estão completamente corrompidas.','São irrelevantes pois não afetam traduçoes modernas da Bíblia.','Tornam necessário abandonar todas as traduçoes bíblicas existentes.'),('FB15-L05-Q04','Dificuldade de identificar e confirmar alterações genuínas','Ausência completa de variantes textuais nos manuscritos','Impossibilidade de determinar a autoria dos textos','Necesidade de usar apenas fontes impressas modernas'),('FB14-L01-Q02','Compreender o sentido original do texto biblico em seu contexto historico','Provar que a Biblia e a palavra de Deus sem sombras de duvida','Substituir a interpretacao tradicional por novas teorias teologicas','Aplicar diretamente o sentido literal a qualquer epoca sem considerar o contexto'),('FB13-L18-Q07','Comparar Escrituras, estudar contexto histórico e orar por discernimento','Ignorar a tradição e interpretar segundo sentimento pessoal','Seguir apenas autoridade religiosa sem questionar','Aplicar meanings modernos diretamente ao texto bíblico'),('FB16-L14-Q03','Por derivacao e variacao ao longo da historia da lingua','Por traducao literal de textos sagrados hebraicos','Por coincidencia aleatoria entre diferentes idiomas','Por uso figurativo adotado pela tradicao eclesiastica'),('FB18-L07-Q02','Jesus','O prophets Elias','O apostle Paulo','O anjo Gabriel'),('FB16-L14-Q04','O contexto linguístico e a evolução semântica de cada palavra determinam seu sentido próprio.','Todas as palavras da mesma raiz possuem sempre o mesmo significado em qualquer contexto.','A raiz etimológica é o único fator que determina o significado de uma palavra na frase.','As palavras de mesma raiz perderam qualquer conexão de significado ao longo dos séculos.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB18-L07-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB16-L15-Q01','O hebraico bíblico usa formas aspectuais (qatal, yiqtol) em vez de tempos verbais.','O hebraico bíblico possui três tempos: passado, presente e futuro como o português.','As formas verbais hebraicas indicam apenas o momento da ação, sem nuances aspectuais.','O hebraico bíblico é uma língua sem verbos, usando apenas nominalizações para expressar ações.'),('FB18-L07-Q01','Abre-te, sê aberto','Paz, kesejahteraan','Sê limpo, purifica-te','Fé, crê no Senhor'),('FB18-L07-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB18-L06-Q04','Evangelho de Marcos','Evangelho de Mateus','Evangelho de Lucas','Evangelho de João'),('FB18-L08-Q02','NAO SEI','Durante o Sermao da Montanha','Na crucifixao diante de Pilatos','Ao nascer em Betlehem'),('FB18-L08-Q03','NAO SEI','Salmo 23','Salmo 119','Salmo 91'),('FB18-L07-Q05','Os mandamentos de Jesus revelam a vontade de Deus e guiam a vida de fe','Os mandamentos de Jesus sao apenas simbolicos e nao tem aplicacao pratica','As ordens de Jesus foram anuladas apos a sua crucificacao','Os mandamentos de Jesus tem importancia apenas historica e arqueologica'),('FB18-L06-Q05','Fidelidade ao sentido e autenticidade historica do texto sagrado.','A eliminacao de supostas contradicoes entre os evangelhos sinoticos.','A substituicao dos termos aramaicos por equivalentes em grego.','A adaptacao completa da mensagem ao contexto atual do leitor.'),('FB18-L08-Q01','Meu Deus, meu Deus, por que me desamparaste?','Deus meu, Deus meu, isto está consumado agora','Pai, Pai, logo chegará o Reino dos céus','Senhor, Senhor, agora sou recebido por ti'),('FB18-L08-Q05','NAO SEI','Porque o Salmo 22 nao tem relacao com a crucifixao de Cristo','Porque os evangelistas distorceram o significado original do Salmo 22','Porque o Salmo 22 foi escrito mil anos antes da crucifixao e nao pode ser aplicado'),('FB18-L09-Q01','Pai. Termo aramaico para pai, usado por Jesus em oracao.','Senhor. Titulo de respeito ao Criador do universo.','Mestre. Forma de se dirigir a um professor rabinico.','Salvador. Nome dado ao Messias esperado por Israel.'),('FB18-L08-Q04','Mateus, Marcos e Lucas preservam formas semíticas.','Apenas o Evangelho de João preserva formas semíticas.','Nenhum dos Evangelhos preserva formas semíticas.','Somente o Evangelho de Atos preserva formas semíticas.'),('FB18-L09-Q04','Paulo disse que o Espírito nos faz clamar Aba, Pai, confirmando a adoção como filhos de Deus.','Paulo comparou Aba com a escravidão dos hebreus no Egito durante o cativeiro.','Paulo usou Aba para mostrar que a adoção vinha pelo batismo nas águas do Jordão.','Paulo relacionou Aba à herança dos profetas do Antigo Testamento como孟子.'),('FB18-L10-Q01','Nosso Senhor, vem!','Meu Pai, graças a ti','Bênção do Senhor','Amor verdadeiro de Deus'),('FB18-L09-Q02','Marcos 14:36, Romanos 8:15 e Gálatas 4:6, em orações e reflexões sobre Deus Pai.','Mateus, Lucas e João, nos evangelhos sinóticos,主要用于祈祷和敬拜.','Apocalipse, Hebreus e Tiago, em contextos de sofrimento e perseguição.','Todos os livros do Novo Testamento, porque representa a relação entre Deus e os fiéis.'),('FB18-L09-Q03','Jesus orou Abba, Pai em Getsêmani, revelando intimidade com Deus.','Jesus usou Abba em pregações públicas para ensinar os discípulos.','Jesus nunca empregou Abba; usou apenas Pai nas orações.','Abba significa Senhor e Jesus o usou para bendizer o povo.'),('FB18-L10-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB18-L10-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB18-L10-Q03','1 Coríntios 16:22','Apocalipse 22:20','Filipenses 4:5','1 Tessalonicenses 4:16'),('FB18-L09-Q05','Aba é termo formal adulto em aramaico, não gíria, e representa intimidade teológica profunda.','Porque Jesus inventou o termo Aba especificamente para orações infantis no Getsêmani.','Porque a Igreja primitiva substituiu todas as orações judias por termos gregos mais modernos.','Porque Abraão foi o primeiro personagem bíblico a usar Aba em suas súplicas a Deus.'),('FB18-L10-Q05','Porque Jesus falava aramaico, lingua de sua terra e do cristianismo primitivo.','Porque o aramaico e a lingua oficial de toda a Escritura no Novo Testamento.','Porque foi a lingua predominante em que Paulo redigiu suas epistolas canonicas.','Porque sua forma aramaica determina a pronuncia exata do nome divino hebraico.'),('FB18-L11-Q02','Período Persa, nos livros de Daniel e Esdras','Período Babilônico, no livro de Jeremias','Período Monárquico, nos livros de Samuel','Período Helenístico, no livro de Macabeus'),('FB18-L11-Q01','Sistema de escrita de 22 letras derivado do alfabeto fenício, usado em Daniel e Ezra.','Alfabeto de 26 letras derivado do grego clássico usado nos manuscritos do Mar Morto.','Sistema pictográfico egípcio adaptado para escrever textos sagrados hebraicos.','Escrita cuneiforme assíria empregada nos contratos comerciais da Babilônia.'),('FB18-L11-Q04','Permite acessar textos biblicos em aramaico e compreender a lingua de Jesus.','E o unico sistema de escrita usado em toda a Biblia hebraica original.','Substituiu completamente o alfabeto hebraico em todos os manuscritos biblicos.','Possibilita traduzir diretamente o grego do Novo Testamento para o hebraico.'),('FB18-L11-Q05','Conhecer as diferentes formas do alfabeto ao longo da historia e consultar fontes confiaveis','O alfabeto aramaico e identico ao hebraico em todos os aspectos sem nenhuma variacao','O aramaico deve ser estudado exclusivamente atraves dos manuscritos do Mar Morto','Apenas scholars com formacao em linguistica semitica podem acessar textos aramaicos'),('FB18-L11-Q03','O aramaico é ancestral do hebraico quadrático, ambos línguas semíticas','O hebraico antecede o aramaico e desenvolveu a escrita que originou o квадратный','O aramaico e hebraico surgiram independentemente do alfabeto fenício','Apenas o hebraico pertence à família semítica, o aramaico originou-se isoladamente'),('FB16-L16-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB15-L05-Q03','NAO SEI','Por meio de criterios externos como data e geografia dos manuscritos','Analisando se as variacoes coincidem com tendencias teologicas do copista','Comparando o numero de testemunhas que apoiam cada variacao textual'),('FB16-L17-Q02','O nome pessoal de Deus na Bíblia, o tetragrama hebraico','Os quatro evangelhos canônicos da Sagrada Escritura','As quatro estações do ano na tradição hebraica','O nome de Jesus Cristo em aramaico antigo'),('FB16-L16-Q05','Porque palavras hebraicas têm múltiplos significados e nuanças culturais que afetam a tradução.','Porque o hebraico antigo usa o mesmo alfabeto que as línguas modernas ocidentais.','Porque todos os vocábulos bíblicos possuem apenas um único significado fixo e imutável.','Porque as traduções atuais da Bíblia são inspiradas e automaticamente corretas.'),('FB16-L17-Q01','YHWH, Elohim, El Shaddai, Adonai, Tzevaot e Elyon.','YHWH, Baal, Moloc, Quemos e Dagom.','YHWH, Zeus, Apolo, Ares e Hermes.','Elohim, Osiris, Anubis, Thoth e Hórus.'),('FB16-L17-Q03','YHWH é o nome pessoal de Deus, Elohim é título que enfatiza poder e Adonai significa Senhor como tratamento reverente.','YHWH é título de poder, Elohim é o nome pessoal e Adonai refere-se à Trindade.','Elohim designa Deus Pai, Adonai refere-se ao Filho e YHWH ao Espírito Santo.','Adonai é o nome pessoal, Elohim título de criação e YHWH designa anjos superiores.'),('FB16-L17-Q05','O contexto revela a natureza e o caráter de Deus na Escritura.','O contexto determina se o nome divino deve ser adorado ou não.','Apenas o contexto linguístico define o sentido dos nomes divinos.','Os nomes divinos mudam completamente conforme o idioma usado.'),('FB16-L18-Q02','Pelas raizes verbais e nominais identificadas no texto massoretico','Pela traducao grega do Septuaginta e suas variacoes terminologicas','Pela numeracao alfanumerica atribuida a cada palavra hebraica','Pela distribuicao geografica dos manuscritos encontrados em Qumran'),('FB16-L18-Q01','Estudo do significado e uso de palavras hebraicas nos textos biblicos.','Metodo de decifracao de manuscritos hebraicos encontrados em Qumran.','Sistema de analise estatistica da frequencia de letras nos textos sagrados.','Colecao de melodias liturgicas usadas no culto hebraico biblico.'),('FB16-L18-Q03','Fornecer o repertório vocabular com seus significados e regras de uso','Regular toda a estrutura sintática da língua de forma automática','Determinar exclusivamente os sons e a fonologia da linguagem','Substituir elementos gramaticais obrigatórios no discurso'),('FB16-L18-Q05','Porque revela os significados originais das palavras hebraicas e evita traduções imprecisas','Porque torna o texto mais fácil de memorizar sem estudar gramática','Porque permite interpretar o texto sem conhecer o contexto histórico','Porque substitui completamente a necessidade de consultar manuscritos'),('FB16-L19-Q01','O contexto determina o sentido da palavra, nao a etimologia','A origem da palavra sempre define seu significado exato','Palavras biblicas nunca mudam de sentido ao longo do tempo','Apenas dicionarios antigos podem definir o sentido das palavras'),('FB16-L18-Q04','Dicionario biblico de palavras gregas ou hebraicas','Coleção de regras gramaticais para traducao biblica','Lista de personagens principais da Biblia','Guia de pronuncia dos nomes divinos originals'),('FB16-L19-Q03','O contexto determina o significado da palavra','Porque Deus revelou todos os sentidos ao homem','Porque os manuscritos originais assim prescrevem','Porque o concilio ecumenico ordenou isso'),('FB16-L19-Q05','Porque palavras têm múltiplos sentidos e o contexto determina o significado correto.','Porque são ferramentas opcionais e menos importantes que traduções modernas.','Porque todas as palavras gregas têm apenas um significado fixo em léxicos.','Porque devem substituir completamente o estudo gramatical e contextual.'),('FB16-L20-Q01','NAO SEI','O estudo dos livros historicos do Antigo Testamento','A interpretacao das эпистolas paulinas em grego','A analise dos poeticos sagrados da Tradicao Judaica'),('FB16-L19-Q02','A crença falsa de que o sentido da raiz determina o uso bíblico da palavra.','O estudo das raízes hebraicas e gregas para compreender o sentido original bíblico.','A análise das palavras primitivas para descobrir a mensagem divina nelas contida.','O método de comparar traduções para identificar a raiz original das palavras bíblicas.'),('FB16-L19-Q04','O contexto ativo delimita o campo semântico relevante, eliminando sentidos impróprios.','O contexto altera completamente o sentido original de qualquer palavra.','Apenas fatores históricos definem qual significado está em uso.','O contexto linguístico não tem qualquer influência sobre o sentido das palavras.'),('FB16-L20-Q02','Peshat','Derash','Midrash','Halaká'),('FB16-L20-Q04','NAO SEI','Ler salmos de louvor aloud em grupo','Memorizar versículos da Bíblia de cor','Estudar palavras em grego e hebraico bíblicos'),('FB17-L01-Q01','O alfabeto grego possui vinte e quatro letras.','O alfabeto grego possui vinte e duas letras.','O alfabeto grego possui vinte e seis letras.','O alfabeto grego possui vinte e sete letras.'),('FB14-L01-Q01','Interpretação crítica e metódica das Escrituras Sagradas','Tradução da Bíblia para outros idiomas','Estudo da origem dos manuscritos bíblicos','Prática de orar com a Bíblia aberta'),('FB15-L16-Q01','Uma glosa trinitária añadida ao texto de 1 João.','Um papa da Igreja primitiva que confirmou a doutrina da Trindade.','Um concílio eclesiástico que estabeleceu a natureza de Deus.','Um comentário de João Apóstolo sobre a Santíssima Trindade.'),('FB15-L15-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB15-L15-Q05','Comparar com os Evangelhos Sinóticos e avaliar o propósito teológico de João','Rejeitar todo conteúdo joanino por ser teológico e não histórico','Aplicar metodologia exclusivamente histórica ao Evangelho de João','Ignorar as particularidades literárias e teológicas do quarto Evangelho'),('FB15-L15-Q04','Por notas de rodapé e introduções que explicam a crítica textual','Por uma padronização completa baseada únicamente no Texto de Antioquia','Por meio da eliminação de versículos com variações textuais','Através de marcações em cores indicando o nível de certeza textual'),('FB15-L15-Q02','Porque não está nos manuscritos mais antigos e muitos estudiosos consideram-na uma interpolação posterior.','Porque a cena contradiz a proibição de Jesus sobre julgar os outros nas Escrituras.','Porque os evangelhos sinóticos narram exatamente os mesmos fatos com detalhes idênticos.','Porque todos os manuscritos gregos antigos confirmam sua presença nos primeiros séculos.'),('FB15-L16-Q02','1 João 5:7','João 1:1','Apocalipse 3:14','Hebreus 1:3'),('FB15-L15-Q01','João 7:53-8:11','Mateus 5:27-28','1 Tessalonicenses 4:3-5','Romanos 2:21-22'),('FB15-L16-Q04','NAO SEI','Por variantes textuais copias durante a tradicao dos manuscritos originais','Atraves de glosas marginais que foram incorporadas ao texto canonico','Por intermédio de escribas que alteraram o texto por razoes teologicas'),('FB15-L16-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB15-L17-Q01','Variantes textuais que alteram o sentido e a interpretação do texto bíblico.','Diferenças entre manuscritos que são idênticas em todas as traduções modernas.','Cópias falhas de manuscritos que sempre mantêm o sentido original da passagem.','Erros de ortografia que não afetam a compreensão teológica do texto sagrado.'),('FB15-L16-Q05','Nao, a Trindade nao depende do Comma Johanneum.','Sim, a Trindade foi formulada com base nesse texto.','O Comma Johanneum e a principal prova biblica da Trindade.','Sem o Comma Johanneum, a Trindade nao teria fundamento.'),('FB15-L17-Q05','Variantes textuais afetam traduções e geram notas de rodapé nas bíblias modernas.','Variantes são corrigidas na Almeida, eliminando todas as diferenças textuais.','Manuscritos são idênticos, dispensando notas textuais nas traduções.','Variantes apenas afetam nomenclatura, não o sentido das passagens.'),('FB15-L18-Q01','Não. As variantes são analisadas e não comprometem as doutrinas centrais.','As variantes textuais invalidam completamente a inspiração das Escrituras.','Todas as doutrinas dependem das variantes para serem consideradas válidas.','As variantes são apenas erros sem relevância para o entendimento da fé.'),('FB15-L17-Q02','Evidência translacional','Evidência externa','Evidência interna','Evidência papirológica'),('FB15-L17-Q04','Porque variações em traduções podem refletir escolhas tradutórias e não necessariamente corrupção textual','Porque traduções inspiradas são infalíveis e sempre preservam fielmente o texto original','Porque tradutores antigos nunca cometiam erros e seguiam o texto fonte literalmente','Porque manuscritos em hebraico e grego jamais apresentam variações que afetem traduções'),('FB15-L18-Q02','NAO SEI','Porque todas as doutrinas centrais dependem de variant textuais minoritarias','Porque os manuscritos biblicos sao idênticos em todas as copias antigas','Porque variantes textuais nunca afetam passagens teologicas importantes'),('FB15-L19-Q02','NAO SEI','Notas marginais em manuscritos antigos','Citações diretas com referencia correta','Interlinear e criticas textuais'),('FB15-L18-Q03','A multitude de testemunhos permite identificar variantis e determinar o texto mais fiel ao original.','O excesso de manuscritos impede a análise crítica do texto original.','A abundancia de variantis demonstra que o texto bíblico foi corrompido irremediavelmente.','Apenas manuscritos tardios possuem autoridade para avaliar variantis textuais.'),('FB15-L18-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB15-L18-Q04','Variante de redação altera palavras; variante de sentido muda o significado teológico.','Ambas alteram igualmente o significado doutrinário da passagem bíblica.','Variante de sentido refere-se exclusivamente a erros de copistas.','Variante de redação altera a doutrina; variante de sentido altera palavras.'),('FB18-L12-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB16-L20-Q05','Proporciona base em análise textual e gramática essencial para interpretar o hebraico bíblico.','Porque os originais hebraicos foram traduzidos para português simples no AT.','Elimina a necessidade de aprender hebraico e grego para traduzir o AT.','Facilita a memorização dos versículos sem compreender o contexto histórico.'),('FB16-L20-Q03','Funcao referencial ou informacional','Funcao expressiva ou emotiva','Funcao conativa ou apelativa','Funcao poetica ou estetica'),('NT01-L14-Q01','Grupo religioso judaico que enfatizava a lei oral e a ressurreição dos mortos.','Sacerdotes do templo que controlavam os sacrifícios e as ofertas.','Sekta militar que lutava pela independência de Israel contra Roma.','Profetas que pregavam no deserto sobre a vinda do Messias.'),('NT01-L14-Q05','Porque eram hipocritas e ensinavam tradições que anulavam a Palavra de Deus.','Porque os fariseus eram demasiado devotos e queriam passar por justos diante do povo.','Porque Pilatos e as autoridades romanas pressionavam Jesus a atacar os religiosos.','Porque os fariseus não seguiam nenhuma lei e viviam em completa impiedade.'),('NT01-L14-Q02','Atribuíam-lhes igual valor e autoridade na prática religiosa.','A Tradição oral era considerada superior à Lei escrita.','As tradições interpretativas eram totalmente rejeitadas.','Apenas a Lei Escrita possuía autoridade religiosa.'),('NT01-L14-Q06','Havia fariseus justos como Nicodemus, e Cristo censurava práticas, não toda a classe.','Os Evangelhos condenam sem exceção todo fariseu como hipócrita e idólatra.','Jesus nunca dialogou com fariseus que não fossem hypocritical e ímpios.','Todos os fariseus foram completamente rejeitados pelos discípulos de Cristo.'),('NT01-L14-Q03','Ressurreição dos mortos, existência de anjos e demônios, e tradição oral.','Celebração do sábado, jejum semanal e peregrinações a Jerusalém.','Monoteísmo estrito, circuncisão masculina e proibição de imagens.','Observância da dieta kosher, lei do levirato e casamento com estrangeiros.'),('NT01-L14-Q04','Por obediência aos mandamentos, leis de pureza e separação do mundo.','Por meio de boas obras, caridade e dedicação exclusiva ao trabalho.','Por sacrifícios constantes no templo e adoração a múltiplos deuses.','Pela realização de banhos rituais diários e abstinência total de alimentos.'),('FB15-L19-Q04','Notas textuais carecem de contexto teologico e historico para decisao doctrinal isolada.','Notas textuais fornecem interpretacao autorizada sem necessidade de consulta as mesmas.','Notas textuais substituem completamente a analise dos manuscritos gregos originais.','Notas textuais eliminam a necessidade de compreensao da tradicao textual historica.'),('FB15-L19-Q03','Notas textuais registram variantes para avaliar qual leitura é mais provável ser original.','Notas textuais determinam qual texto deve ser copiado por escribas modernos.','Notas textuais substituem o texto original por traduções modernas da Bíblia.','Notas textuais classificam manuscritos apenas por data de produção.'),('FB17-L21-Q05','Porque permite interpretar corretamente o grego koiné e o contexto cultural original.','Porque elimina a necessidade de conhecimento das línguas originais bíblicas.','Porque facilita a memorização de versículos sem análise gramatical profunda.','Porque substitui completamente o uso de comentários e léxicos especializados.'),('FB17-L21-Q04','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB18-L01-Q02','Período do exílio babilônico e império persa','Período do reino dividido de Israel e Judá','Era dos patriarcas e da saída do Egito','Período hasmoneu e rebelião macabaica'),('FB18-L01-Q03','Aramaico e hebraico compartilham raízes semíticas e se influenciaram mutuamente.','Hebraico originou o aramaico, que é seu dialeto posterior.','Aramaico não pertence às línguas semíticas.','Aramaico e hebraico são línguas indo-europeias.'),('FB18-L01-Q01','Estudo da evolucao da lingua aramaica ao longo das epocas historicas','Analise dos dialetos hebraicos utilizados no periodo do exlio na Babilonia','Processo de traducao dos livros biblicos do hebraico para o aramaico','Levantamento dos termos hebraicos presentes nos textos aramaicos biblicos'),('FB18-L02-Q02','Nos livros de Daniel e Esdras, período do cativeiro babilônico','Apenas no livro de Jeremias, durante o exílio no Egito','Nos livros de Jonas e Ageu, durante o período pré-exílico','Apenas nos livros históricos, período dos juizes'),('FB18-L01-Q04','E essencial para interpretar palavras e oracoes originales de Jesus','O aramaico substituiu completamente o hebraico no Antigo Testamento','Apenas o Novo Testamento contem palavras e expressoes em aramaico','A traducao da Biblia para o portugues elimina a necessidade de conhecer o aramaico'),('FB18-L02-Q01','Linguagem semitica aparentada ao hebraico usada em trechos de Daniel e Ezra.','Dialecto greco-hebraico usado pelos apostolos nos primeiros sermoes.','Traducao aramaica do Torah feita pelos rabinos de Qumran.','Idioma falado exclusivamente pelos sacerdotes do templo de Jerusalém.'),('FB18-L02-Q03','É lingua semítica próxima ao hebraico, usada em Daniel e Ezra.','É a lingua original de todo o Pentateuco e livros históricos.','Pertence à família afro-asiática sem relação com o hebraico.','Substituiu completamente o hebraico após o cativeiro babilônico.'),('FB18-L01-Q05','Considerar variações dialetais,escassez de manuscritos e camadas históricas do aramaico.','O aramaico só aparece na Bíblia em textos pós-exílicos,e não há evidências anteriores.','A pronúncia e o sistema vocálico do aramaico estão completamente recuperados pelos estudiosos.','O estudo do aramaico dispensa o conhecimento de outras línguas semíticas cognatas.'),('FB18-L02-Q04','Permite compreender porções originais em aramaico, como Daniel e Ezra, enriquecendo a interpretação','É a língua original de todo o Pentateuco, tendo o hebraico sido uma tradução posterior dos originais','O aramaico substituiu integralmente o hebraico em todo o AT após o cativeiro babilônico','Eliminar o aramaico do estudo não afeta a compreensão, pois o AT foi inteiramente escrito em hebraico'),('FB18-L03-Q01','Língua semítica das seções persas de Esdras caps 4 a 7','Grego alexandrino usado na composição original de Esdras','Dialeto hebraico posterior exclusivo da liturgia do templo','Códex aramaico que substitui textos hebraicos mais antigos'),('FB18-L03-Q02','No livro de Esdras, capitulos 4 a 7','No livro de Daniel, capitulos 2 a 7','No livro de Neemias, capitulos 8 e 9','No livro de Jeremias, capitulos 1 a 3'),('FB18-L02-Q05','Distinguir porções aramaicas das hebraicas e dominar o aramaico bíblico.','Todo o antigo testamento foi originalmente escrito em aramaico.','O aramaico do antigo testamento é idêntico ao aramaico talmúdico.','Basta conhecer o grego koiné para estudar o aramaico veterotestamentário.'),('FB18-L03-Q03','Ambos são línguas semíticas nordeste, mas o aramaico de Esdras tem gramática e vocabulário distintos do hebraico bíblico.','O aramaico de Esdras é hebraico puro apenas escrito com outro alfabeto, sem diferenças gramaticais.','O aramaico de Esdras pertence a uma família linguística totalmente diferente das línguas semíticas.','O aramaico de Esdras é uma língua semítica do sul, mais próxima do árabe clássico do que do hebraico.'),('FB18-L03-Q04','As porções em aramaico de Esdras preservam documentos do período persa.','O aramaico substituiu totalmente o hebraico em todo o livro de Esdras.','O aramaico de Esdras é uma interpolação tardia que deve ser removida.','Todo o AT foi originalmente composto em aramaico.'),('FB18-L04-Q01','Secções do livro de Daniel escritas em aramaico, lingua semítica do período babilónico.','O nome divino de Deus tetragrama usado em todo o livro de Daniel conforme a tradição hebraica.','A totalidade do livro de Daniel composto inteiramente em lingua aramaica sem secções em hebraico.','A lingua original de Daniel interpretada exclusivamente como dialeto cananeu da região da Judeia.'),('FB18-L04-Q02','Período do cativeiro babilônico, séculos VI a.C., nos capítulos 2 a 7 de Daniel.','Período helenístico, século II a.C., nos capítulos 8 a 12 de Daniel.','Período do exílio egípcio, século V a.C., em todo o livro de Daniel.','Período da monarquia unificada, século X a.C., nos capítulos 1 a 7 de Daniel.'),('FB18-L03-Q05','Observar que apenas Ezra 4:8-6:18 e 7:12-26 sao em aramaico','Todo o livro de Esdras foi originalmente escrito em aramaico','O aramaico de Esdras pertence ao periodo previo ao exilio babilonico','O aramaico de Esdras e essencialmente igual ao hebraico biblico'),('FB18-L12-Q01','Conjunto de palavras essenciais do aramaico bíblico para leitura dos textos de Daniel e Ezra','Lista de termos teológicos avançados usados apenas nos Targumim aramaicos','Vocabulário específico da literatura rabínica talmúdica em aramaico','Conjunto de palavras hebraicas incorporadas aos textos aramaicos da Bíblia')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB18-L12-Q03','NAO SEI','O vocabulario basico hebraico deriva exclusivamente do aramaico','As linguas semiticas compartilham raizes linguisticas comuns','O hebraico moderno abandona completamente o vocabulario biblico'),('NT03-L03-Q05','Jesus Cristo se fez homem, encarnou, assumindo a natureza humana','Jesus abandonou sua divindade para existir apenas como homem','O Verbo se transformou em outro ser celestial menor','Jesus criou um corpo físico para habitar na terra'),('NT03-L03-Q06','A lei por Moisés, graça e verdade por Jesus Cristo','A lei e graça e verdade vieram por meio de Moisés','Jesus recebeu a lei e a transmitiu ao povo','Ambos trouxeram igual medida de graça e verdade'),('NT03-L04-Q01','Jesus Cristo, o Filho unigênito de Deus','Deus Pai, a primeira pessoa da Trindade','O Espírito Santo, terceira pessoa da Trindade','João, o escritor que registrou o evangelho'),('NT03-L04-Q03','Afirma a divindade de Cristo, que é Deus, distinto do Pai','Afirma que Cristo é um deus inferior ao Pai','Afirma que o Verbo é apenas um atributo de Deus','Afirma que o Verbo é um anjo criado por Deus'),('NT03-L03-Q07','Introduz temas centrais — Verbo, luz, vida — que o evangelho desenvolve e aprofunda.','Porque foi acrescentado posteriormente, servindo apenas como introducao poetica ao texto.','Porque descreve detalhadamente todos os milagres que Jesus realizaria em Cafarnaum.','Porque apresenta a biografia completa de Jesus desde o nascimento em belém ate a crucifixao.'),('NT03-L04-Q07','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT03-L04-Q02','Indica a pessoa eterna do Filho coexistindo com o Pai.','Afirma que Deus Criou o universo por meio de Sua palavra falada.','Significa que Cristo Se tornou Deus ao ser crucificado e ressuscitar.','Indica que o Verbo representa um simbolismo poetico de Deus.'),('NT03-L04-Q04','O Verbo era Deus e por ele tudo foi feito.','O Verbo foi apenas um mensageiro de Deus na criação.','O Verbo criou o mundo sozinho, sem participação de Deus.','O Verbo surgiu no momento da criação como criatura.'),('NT03-L04-Q05','Nele estava a vida, e a vida era a luz dos homens','O Verbo criou a vida e a luz como dois elementos distintos','A vida e a luz existiam antes do Verbo no principio','O Verbo apenas refletia a vida e a luz de Deus'),('NT03-L05-Q02','NAO SEI','Apocalipse 12','Êxodo 3','Romanos 8'),('NT03-L04-Q06','O Verbo se fez carne e habitou entre nós, cheio de graça e de verdade.','O Verbo revelou-se através de sonhos e visões proféticas ao longo dos séculos.','O Verbo tornou-se conhecido mediante pregação e ensinamentos rabínicos.','O Verbo manifestou-se como um anjo mensageiro diante dos discípulos.'),('NT03-L05-Q01','Que o Verbo se fez carne e habitou entre nós','Que Jesus apenas aparentava ter corpo humano','Que Deus abandonou Jesus durante sua vida terrena','Que a encarnação ocorreu antes da criação do mundo'),('NT03-L05-Q05','NAO SEI','Respostas de fé como Creio, Amém e Bendito seja Deus.','Respostas de incredulidade como Não acredito e Isso é impossível.','Manifestações de dúvida, medo, louvor e adoração ao Senhor.'),('NT03-L05-Q03','João 1:14: O Verbo se fez carne e habitou entre nós','Gênesis 1:1: No princípio criou Deus os céus e a terra','Romanos 5:8: Cristo morreu por nós sendo ainda pecadores','Apocalipse 3:20: Eu estou à porta e bato'),('NT03-L05-Q04','Revela Jesus como o Filho de Deus encarnado, enviado para redimir a humanidade.','Revela Jesus como um anjo enviado por Deus para ensinar moral aos homens.','Revela Jesus como o proprio Deus Pai manifestado em forma humana na terra.','Revela Jesus como um homem comum ungido pelo Espirito Santo para profetizar.'),('NT03-L06-Q04','Os sinais revelam que Jesus e o Cristo, o Filho de Deus, e que nEle se tem a vida eterna.','Os sinais provam que Jesus era um rabbi itinerante com grande poder de cura.','Os sinais demonstram que Jesus era um profeta similar aos profetas do AT.','Os sinais indicam que Jesus veio para estabelecer um reino politico na Terra.'),('NT03-L06-Q01','Os sete milagres (sinais) que demonstram que Jesus e o Cristo, o Filho de Deus','Os trinta e sete milagres realizados por Jesus em todo o seu ministerio','A agua transformada em leite no casamento em Cana da Galileia','A multiplicacao dos pães e peixes para cinco mil pessoas'),('NT03-L06-Q02','Água em vinho, cura do nobre, paralítico em Betesda, 5 mil, águas, cego, Lázaro.','Cura do surdo-mudo,MULTIPLICAÇÃO DOS PEIXES, cura do leproso, transfiguração, ressurreição da filha de Jairo, tempestade calmada, cego de nascença.','Ressurreição de Lázaro, transfiguração, cura da mulher encurvada, MULTIPLICAÇÃO DOS PEIXES, tempestade calmada, cura do servo do centurião, água em vinho.','MULTIPLICAÇÃO DOS PEIXES, cura da filha da cananeia, tempestade no mar, cura do leproso, transfiguração, ressurreição de Lazaro, água em vinho.'),('NT03-L05-Q06','A encarnação permitiu que Cristo morresse pelos pecados e revelasse Deus aos homens','A encarnação fez com que Cristo ficasse limitado e imperfeito como qualquer ser humano','A encarnação permitiu que Deus ficasse visível apenas para os apostolos','A encarnação foi necessaria apenas para que Cristo conhecesse a vida na terra'),('NT03-L06-Q05','A fé reconhece os sinais como obra de Deus; a incredulidade os atribui a engano.','A fé sempre exige sinais visíveis para crer; a incredulidade aceita tudo sem questionar.','Os sinais causam fé nas pessoas ímpias e incredulidade nos justos.','A incredulidade fortalece a fé enquanto os sinais a enfraquecem.'),('NT03-L07-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT03-L06-Q03','Para indicar que os milagres apontam para a identidade divina de Jesus e seu significado espiritual.','Porque Jesus não realizava milagres, apenas ensinamentos espiritualizados.','Porque os sinais sao menos importantes que as demonstracoes de poder na teologia joanina.','Porque os milagres de Joao eram eventos cosmicos e nao terrenais como nos outros evangelhos.'),('NT03-L07-Q01','Jesus transformou água em vinho nas Bodas de Caná, revelando sua glória aos discípulos.','Jesus transformou água em pão nas Bodas de Caná para alimentar os famintos.','O Evangelho de João condena o consumo de vinho em todas as suas formas.','A transformação da água em vinho simboliza a conversão dos gentios ao paganismo.'),('NT03-L07-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT01-L15-Q01','Partido religioso judaico da época de Jesus, que aceitava apenas a Lei escrita.','Sekta militar judaica que liderou a revolta contra os romanos no século I.','Grupo de escribas que preservava as tradições orais da Lei de Moisés.','Sacerdotes egípcios que se converteram ao judaísmo durante o cativeiro.'),('NT01-L15-Q04','Jesus apoiava-se nos marginalizados; os fariseus, na liderança religiosa.','Jesus era apoiado pela elite religiosa de Jerusalém; os fariseus, pelos camponeses.','Jesus e os fariseus compartilhavam a mesma base social e política em Israel.','Os fariseus eram apoiados pelos romanos, enquanto Jesus era sustentado pelos pobres.'),('NT01-L15-Q03','O gnosticismo, o docetismo e o legalismo','A doutrina da Trindade e a divindade de Cristo','A ressurreição dos mortos e a vida eterna','O amor ao próximo e a fé em Cristo'),('NT01-L15-Q05','Porque rejeitavam a mensagem do Reino de Deus','Porque Jesus nao era o Messias prometido','Porque os apossolos pregavam contra a Lei','Porque queriam ocupar o lugar de Jesus'),('NT01-L15-Q02','Eram responsaveis pelo culto no templo e serviam como auxiliares dos sacerdotes.','Nao possuam qualquer vinculo com o sacerdócio, mantendo-se separados do sistema religioso.','Eram os principais sacerdotes que ofereciam os sacrifícios no altar sagrado.','Participavam apenas das festividades, sem duties regulares no templo.'),('NT01-L14-Q07','Fundamentou o judaísmo rabínico, especialmente a tradição da Torah oral.','Introduziu os princípios da revolta Maccabeia no judaísmo posterior.','Estabeleceu a tradição dos escribas como base da lei rabínica.','Criou a base para o misticismo kabalístico no judaísmo rabínico.'),('NT01-L15-Q06','Perderam influência e praticamente desapareceram','Passaram a liderar o movimento cristão primitivo','Estabeleceram uma nova sede religiosa em Roma','Mantiveram poder político no Sinédrio Judeu'),('NT01-L16-Q02','Período do Segundo Templo, domínio romano e helenístico.','Período do Primeiro Templo, domínio babilônico.','Período asmoneu independente, antes dos romanos.','Período pós-exílico, domínio persa.'),('NT01-L16-Q05','NAO SEI','A pergunta nao especifica qual desenvolvimento biblico esta sendo referido.','Contexto insuficiente para identificar o desenvolvimento especifico mencionado.','Necessario especificar o evento ou contexto biblico em questao.'),('NT01-L16-Q04','Influenciaram o monasticismo cristão e os Manuscritos do Mar Morto.','Fundaram o Rabinismo talmúdico e a sinagoga moderna.','Redigiram a Torá em aramaico e criaram o Talmud.','Estabeleceram o calendário lunissolar usado no judaísmo rabínico.'),('NT01-L17-Q02','Século I d.C., sob o domínio romano na Judeia','Século V a.C., sob o domínio persa na Judeia','Século II a.C., sob o domínio selêucida na Judeia','Século III d.C., sob o domínio romano na Judeia'),('NT01-L16-Q06','Os essênios demonstram o contexto judaico intenso em que o cristianismo surgiu','Os essênios foram os autores dos evangelhos canônicos do Novo Testamento','Os essênios ensinaram que Jesus era apenas um rabbi comum sem importancia','Os essênios foram absorvidos pelo império romano no primeiro século da era comum'),('NT01-L16-Q01','Os essênios foram um sekto judáu ascético do período intertestamentário que viveu em comunidades na Judeia.','Sekto cristão primitivo do período interbíblico que vivia em comunidades monásticas na Judeia.','Movimento filosófico helenístico que se estabeleceu na Judeia durante o período interbíblico.','Sekto saduceu radical do período intertestamentário que rejeitava toda a Lei mosaica.'),('NT01-L17-Q01','Grupo politico-religioso judeu que combateu a dominação romana na Judea.','Secta farisaica que defendia a interpretação mais rigorosa da Lei de Moisés.','Movimento profético que aguardava a vinda do Messias filho de Deus.','Casta de sacerdotes responsaveis pela manutenção do Templo de Jerusalem.'),('NT01-L17-Q03','Movimento revolucionario que promoveu resistencia armada contra Roma em Judeia','Grupo filosofico que fundou academias rabbinicas em Jerusalem durante o primeiro seculo','Faccao sacerdotal que incentivava o dialogo diplomatico com o Imperio Romano','Seita que pregava conformidade total com as leis de ocupacao romana em Judea'),('NT01-L17-Q05','NAO SEI','A pergunta nao especifica qual desenvolvimento.','Necessario contexto sobre o tema em questao.','Forneca mais detalhes sobre o assunto.'),('NT03-L07-Q04','Revelou Jesus como o Messias e fez os discípulos crerem nele.','Demonstrou que Jesus era apenas um profeta privilegiado de Deus.','Mostrou que Jesus priorizava a diversão e os prazeres humanos.','Prova que Jesus seguia a lei de Moises com rigor.'),('NT03-L08-Q01','Jesus falou com Nicodemos sobre o novo nascimento','Jesus conversou com a Samaritana sobre o novo nascimento','Jesus falou com os discípulos sobre o novo nascimento','Jesus dialogou com Pilatos sobre o novo nascimento'),('NT03-L07-Q06','Manifestou a glória de Cristo e fez os discípulos crerem nele','Proclamou o Evangelho aos pecadores arrependidos da Judeia','Satisfez a fome espiritual de todos os povos da região','Indicou que o Messias viria para libertar Israel dos romanos'),('NT03-L06-Q06','Porque João selecionou sinais para provar que Jesus é o Cristo (Jo 20:31).','Porque os sinais substituem a pregação verbal da mensagem cristã primária.','Porque cada evangelista registrou sinais seguindo rigorosa ordem cronológica exata.','Porque os sinais determinam quais profecias do Antigo Testamento foram cumpridas.'),('NT04-L14-Q02','NAO SEI','O evento especifico nao foi mencionado para que eu possa identificar os Evangelhos.','Falta o contexto do acontecimento ou periodo biblico sobre o qual deseja saber.','Sem a identificacao do evento, nao e possivel determinar em quais Evangelhos foi narrado.'),('NT04-L14-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT04-L13-Q05','Este é o meu Filho amado, em quem me agrado; escutai-o','Eu sou a verdade e a vida, e ninguém vem ao Pai senão por mim','Em verdade vos digo que hoje estareis comigo no paraíso','Não vim para condenar o mundo, mas para salvar o mundo'),('NT04-L13-Q06','Moisés representa a Lei e Elias os Profetas, e ambos confirmaram a missão de Jesus na Transfiguração.','Moisés escreveu os Salmos e Elias os livros históricos do Antigo Testamento.','Moisés e Elias foram apenas personagens do Antigo Testamento sem relação direta com Jesus.','Moisés era sacerdote e Elias representava os livros poéticos da Bíblia.'),('NT04-L13-Q07','Na transfiguração, a glória de Jesus revela o caminho do sofrimento até a redenção.','A transfiguração ensina que o sofrimento e a glória são eventos independentes entre si.','Na transfiguração, os discípulos aprendem que a glória dispensa o sofrimento redentor.','A transfiguração mostra apenas a poder profético de Jesus, sem relação com a cruz.'),('NT04-L14-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT04-L14-Q04','Jesus como Messias camino à sua morte redentora em Jerusalem','Jesus ia estabelecer seu reino terreno e politico em Jerusalem','Jesus fugia dos fariseus para evitar sua prisao em Jerusalem','Jesus seguia apenas a tradicao yearly da festa judaica em Jerusalem'),('NT04-L14-Q06','Preparação dos discípulos para a morte e ressurreição de Cristo e expansão do Reino de Deus','Afastamento definitivo dos discípulos que abandonaram Jesus durante sua crucificação','Estabelecimento de um novo templo em jerusalém para substituir o antigo sistema religioso','Transformação dos discípulos em líderes políticos do reino messiânico na terra'),('NT04-L15-Q01','Montado num jumento, conforme a profecia de Zacarias.','Montado num cavalo branco, como um rei guerreiro','Andando a pé, sozinho, em silêncio','Numa carruagem dourada, cercado de soldados'),('NT04-L15-Q02','A entrada de Jesus em Jerusalém montado num jumento (Zc 9:9; Mt 21:1-11)','A construção do segundo templo em Jerusalém após o cativeiro babilônico','O nascimento do Messias na cidade de Belém no tempo do rei Herodes','A abertura do túmulo de Lázaro após quatro dias de morte'),('NT04-L15-Q03','Que Jesus fosse crucificado','Que Jesus fosse libertado','Louvai ao Senhor Deus','Paz em terra aos homens'),('NT04-L15-Q04','Título messiânico indicando que Jesus é o descendente prometido de Davi.','Título profético que indica Jesus como o segundo filho do patriarca Davi.','Epíteto que refere Jesus como o pai terreno do rei Salomão.','Título davídico significando que Jesus fundou a monarquia de Israel.'),('NT04-L16-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT04-L15-Q05','Montado num jumento, em vez de cavalos de guerra','Vestiu armadura reluzente e espada na cintura','Entrou montado num cavalo branco de guerra','Carregava estandartes militares vermelhos'),('NT04-L16-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT04-L16-Q01','Expulsou vendilhões, virou mesas de cambistas e disse: casa de oração.','Jesus abençoou os vendilhões e多有 permitiu vender no templo.','Os discípulos levaram animais para o templo a pedido de Jesus.','Jesus construiu novas mesas para os cambistas no templo.'),('NT04-L15-Q06','Porque seguiam pelo pão, não pelo entendimento dos sinais','Porque Jesus nunca falou abertamente sobre sua missão','Porque os romanos impediam o povo de compreender a Cristo','Porque Jesus pregava apenas aos doze apóstolos'),('NT04-L16-Q04','Jesus é o Messias, o Filho de Deus, que veio purificar a casa de seu Pai.','Jesus demonstrava seu poderio militar contra os romanos no templo.','A purificação mostrava que Jesus era apenas um rabbi itinerante comum.','Jesus purificava o templo para estabelecer seu reino político na Judeia.'),('NT01-L17-Q04','Os zelotes inspiraram movimentos de resistência contra dominação estrangeira.','Os zelotes forneceram termos essenciais à liturgia cristã primitiva como aleluia e amém.','Os zelotes fundaram escolas talmúdicas que moldaram o judaísmo rabínico após a destruição do Templo.','Os zelotes criaram o sistema de pontuação e acentuação da língua hebraica usada até hoje.'),('NT03-L13-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT03-L13-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT03-L13-Q04','Jesus se revelou como o Cristo, o Filho de Deus, o autor da vida e da ressurreição.','Prova que Jesus era apenas um profeta inspirado por Deus para realizar milagres.','Demonstra que Jesus possuía poderes mágicos adquiridos através de estudos secretos.','Evidencia que Jesus veio estabelecer um reino político e militar na terra.'),('NT03-L13-Q06','Demonstrou que Jesus e a ressurreicao e a vida,confirmando sua divindade','Prova que os milagres sao necessarios para a salvacao do ser humano','Revela que Jesus precisava de oracao para realizar Seus milagres','Mostra que a morte fisica e definitiva, sem possibilidade de volta'),('NT03-L13-Q01','Jesus é a ressurreição e a vida; Lazaro foi ressuscitado em Betania.','Lazaro ressuscitou por sua propria fé e oracao a Deus sozinho em Cafarnaum.','Este milagre esta narrado apenas no Evangelho de Marcos capitulo 5.','A ressurreicao de Lazaro prova que Jesus era apenas um profeta comum.'),('NT03-L14-Q01','Eu sou o pão da vida, a luz do mundo, a porta, o bom pastor, a ressurreição e a vida, o caminho, a verdade e a vida, e a videira verdadeira.','Eu sou o pão do céu, a água viva, a luz do mundo, o pão dos anjos, a porta, o pastor e a videira.','Eu sou a verdade, o caminho e a vida, a luz do mundo, o pão da vida, a porta, o bom pastor e a ressurreição.','Eu sou a luz do mundo, a água viva, o pão da vida, a porta, o pastor, a verdade e a ressurreição.'),('NT03-L13-Q03','Eu sou a ressurreição e a vida, disse Jesus. Lázaro, vem para fora!','Eu sou o caminho, a verdade e a vida. Levantai-vos eandai, disse Jesus.','O gesto de soprar sobre os discípulos e a ordem Despertai das trevas.','A água turning to wine e o comando Sai do teu túmulo agora mesmo.'),('NT03-L14-Q02','Jesus é o alimento espiritual que nutre a alma para a vida eterna','Significa que Jesus nasceu em Belém, cidade do pão','Significa que Jesus multiplicationou pães para alimentar multidões','Significa que Jesus era um rabbi que ensinava sobre pães'),('NT03-L14-Q03','Significa que Jesus guia a humanidade para a verdade e a vida.','Significa que Jesus era uma luz visivel que brilhava fisicamente.','Significa que Jesus refletia a luz de Deus como a lua reflete o sol.','Significa que Jesus reinar[a] simbolicamente sobre todos os povos.'),('NT03-L14-Q04','Jesus se apresentou como a porta das ovelhas e o bom pastor que dá a vida.','A porta indica a entrada do templo e o pastor lidera os religiosos na lei.','A porta representa a separação entre o bem e o mal e o pastor guia as nações.','A porta simboliza a portaria celestial e o pastor conduce as almas ao purgatório.'),('NT03-L14-Q06','Jesus é o único caminho para Deus, a verdade perfeita e a fonte da vida eterna.','Jesus é um exemplo de amor que todos devem seguir em seu caminho espiritual.','Jesus ensinou que cada pessoa deve buscar sua própria verdade e propósito na vida.','Jesus foi um filósofo que mostrou a humanidade o caminho da paz e da sabedoria.'),('NT03-L14-Q05','Significa que Jesus é a fonte da vida eterna e quem ressuscita os mortos.','Significa que Jesus foi o primeiro a ressuscitar dos mortos e vive eternamente.','Significa que precisamos morrer e ressuscitar espiritualmente para ter vida.','Significa que a fé em Deus nos dá poder para vencer a morte física.'),('NT03-L14-Q07','Jesus é a fonte de vida espiritual para os crentes que permanecem nele e produzem frutos.','Jesus simboliza a videira como metáfora para a organização da igreja primitiva e sua hierarquia.','A videira verdadeira representa a Lei antiga que Cristo veio cumprir e completar espiritualmente.','Significa que Jesus era um viticultor que usava metáforas agrícolas em seus ensinamentos.'),('NT03-L15-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT03-L15-Q05','NAO SEI','O contexto especifico nao foi mencionado para identificar as respostas de fe ou incredulidade.','Respostas de fe e incredulidade variam conforme o texto biblico cited e seu contexto historico.','Sao necessarios mais detalhes sobre a passagem biblica em questao para uma analise adequada.'),('NT03-L15-Q01','Jesus consola os discípulos, promete o Consolador e ensina o mandamento do amor.','Jesus ordena jejum rigoroso e ofertas específicas para os doze apóstolos.','Narrativa detalhada do nascimento de Jesus em Belém com anjos.','Profecias sobre a destruição total de Roma pelos céus.'),('NT03-L15-Q03','NAO SEI','Farewell speeches são marcados por bênçãos, profecias e testamentos.','Diálogos de despedida contêm sempre lamentações e prantos rituais.','Sinais de despedida incluem abraços, beijos e imposição de mãos.'),('NT03-L16-Q02','NAO SEI','Nao ha referencial biblico para essa questao','O tema esta ausente das Escrituras','A pergunta nao especifica o tema abordado'),('NT03-L15-Q06','Preparar os discipulos para a obra do Espirito Santo apos a partida de Cristo','Demonstrar que Jesus desejava evitar completamente o sofrimento da cruz','Substituir integralmente a Lei de Moises por novos mandamentos de origem humana','Estabelecer uma hierarquia politica permanente entre os doze apostolos'),('NT03-L16-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT03-L16-Q01','Jesus prometeu o Espírito Santo como Consolador que ficaria com os discípulos para sempre.','O Consolador seria um dos apóstolos escolhido para liderar a igreja após a morte de Jesus.','O Consolador viria para substituir os milagres realizados por Jesus durante seu ministério.','Jesus disse que o Consolador viria apenas para os líderes religiosos da época.'),('FB18-L04-Q04','Os capítulos em aramaico preservam revelações proféticas e símbolos apocalípticos do texto bíblico.','O aramaico indica que Daniel foi escrito na época de Herodes, após o cativeiro.','A parte em aramaico de Daniel está apenas no primeiro capítulo, narrando a corte real.','O aramaico em Daniel foi acrescentado posteriormente por tradutores da Igreja Primitiva.'),('FB18-L04-Q03','O aramaico em Daniel e lingua semitica aparentada ao hebraico.','Daniel foi escrito apenas em grego, lingua semitica da epoca.','A grafia aramaica em Daniel e identica a do hebraico biblico.','O aramaico de Daniel e uma forma tardia do hebraico classico.'),('NT02-L15-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT02-L14-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT02-L15-Q04','NAO SEI','As diferenças aparecem apenas na tradução das palavras originais para o português','As diferenças aparecem principalmente nos detalhes geográficos mencionados','As diferenças aparecem exclusivamente na numeração dos capítulos e versículos'),('NT02-L15-Q01','Aqueles que seguem a Jesus Cristo, especialmente os doze escolhidos por Ele','Líderes religiosos judaicos que ensinavam a Lei no Templo de Jerusalém','Membros de um movimento político messiânico contra o domínio romano','Os doze apóstolos exclusivamente, sem outros seguidores de Jesus'),('NT02-L15-Q06','Considerar o contexto histórico-cultural e a linguagem propria de cada autor.','Ignorar completamente o contexto historico e cultural de cada texto biblico.','Priorizar sempre interpretacoes literais sem considerar generos literarios.','Substituir o texto original por commentaries e interpretacoes pessoais modernas.'),('NT02-L15-Q02','Como grupo que segue Jesus, recebe ensinamento e é enviado em missão','Como grupo com autoridade política sobre Judá e Samaria','Como grupo restrito aos doze sem função missionária definida','Como grupo presente apenas nos milagres de cura de enfermos'),('NT02-L14-Q05','Cada evangelista escreveu com propósito específico, explicando as diferenças.','As diferenças devem-se apenas a erros de transcrição dos copistas.','Os quatro evangelistas copiaram literalmente as palavras uns dos outros.','Deusditou cada evangelho de forma idêntica aos quatro escritores.'),('NT02-L16-Q04','NAO SEI','Diferencas de selecao envolvem quais livros foram incluidos ou excluidos do c anon.','Diferencas de ordem referem-se a organizacao dos livros dentro do c anon biblico.','Variacoes de enfase mudam quais temas ou ensinos sao destacados em cada traducao.'),('NT02-L16-Q03','NAO SEI','Os tres evangelhos differ em estilo e vocabulario apenas','Apenas o Evangelho de Joao menciona a Ressurreicao','Mateus, Marcos e Lucas nao compartilham nenhuma narrativa similar'),('NT02-L15-Q05','Cada evangelista escreveu para um público distinto, destacando aspectos variados de Cristo.','Os evangelistas copiaram uns dos outros para uniformizar a mensagem de Jesus Cristo.','As diferenças existem porque os apóstolos não presenciaram os mesmos eventos de Jesus.','O propósito de cada evangelista era apenas cronológico, não teológico nem cultural.'),('NT02-L16-Q01','O sofrimento, morte e ressurreição de Jesus Cristo','A natividade e os primeiros anos de vida de Jesus em Belém','Os milagres e exorcismos realizados por Jesus na Galileia','A genealogia e as origens terrestres de Jesus Cristo'),('NT02-L16-Q05','Cada evangelista adaptou a mensagem ao seu público, gerando ênfases distintas.','Os evangelistas escreveram de forma idêntica, copiando palavra por palavra entre si.','As diferenças surgiram apenas de erros de copistas ao longo dos séculos.','Todos os quatro evangelhos foram escritos simultaneamente pelo mesmo autor.'),('NT02-L17-Q01','Combinar os quatro Evangelhos numa narrativa única e cronológica da vida de Cristo.','Eliminar as contradições entre os Evangelhos alterando o texto sagrado original.','Traduzir os quatro Evangelhos para uma única língua vernacula compreensível.','Escolher qual Evangelho deve ser considerado canônico em detrimento dos outros.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('NT02-L16-Q02','Os sinóticos apresentam narrativas paralelas sobre paixão e ressurreição.','Os evangelhos de Mateus, Marcos e Lucas divergem completamente sobre a ressurreição.','Lucas não menciona a ressurreição de Jesus Cristo em seu evangelho.','Os sinóticos foram escritos antes do evangelho de João sobre a paixão.'),('NT02-L17-Q02','Porque diferentes autores sagrados tiveram propósitos distintos e escolheram aspectos variados dos mesmos relatos','Porque Deus permitiu erros nos textos sagrados para testar a fé dos leitores','Porque os tradutores alteraram arbitrariamente os textos originais sem autorização divina','Porque todas as Escrituras foram escritas pelo mesmo autor sobditação direta e literal'),('NT02-L17-Q06','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT02-L17-Q03','Usando compilações temáticas de ditos e feitos de Jesus','Seguindo rigorosamente a ordem cronológica dos fatos','Baseados exclusivamente em testemunhos orais isolados','Utilizando técnicas modernas de edição textual bíblica'),('NT02-L17-Q04','Pode obscurecer a teologia e propósito distintos de cada evangelista.','Garante uma interpretação literal e exata de todos os relatos apostólicos.','Elimina as diferenças entre os evangelhos facilitando a compreensão bíblica.','Prejudica apenas a memorização dos textos sem afetar a compreensão teológica.'),('NT02-L16-Q06','Considerar contexto historico-cultural e literario','Ignorar as variacoes entre manuscritos biblicos','Priorizar traducoes modernas sobre textos originais','Aplicar interpretacao literal a todo tipo de genero'),('NT03-L01-Q01','João, apóstolo, escreveu para que os leitores cressem que Jesus é o Cristo.','Lucas, médico, escreveu para Teófilo e gentios convertsidos ao cristianismo.','Mateus, publicano, escreveu para judeus convertsidos ao cristianismo.','Marcos, intérprete de Pedro, escreveu para cristãos gentios na Roma antiga.'),('NT03-L01-Q02','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('NT02-L17-Q05','Considerar contexto histórico, propósito teológico e revelação progressiva','Ignorar diferenças entre os relatos e forçar harmonização forçada','Selecionar apenas o relato mais antigo como critério de verdade','Discartar relatos supostamente contraditórios sem análise cuidadosa'),('NT03-L01-Q03','NAO SEI','As palavras comuns sao: graça, paz, amen, aleluia e hallelujah.','Os sinais sao as narrativas de milagres e as profecias cumpridas.','Os diálogos sao as conversas entre Deus e os profetas escolhidos.'),('NT04-L17-Q02','Meu corpo','Um símbolo do Reino de Deus','A presença do Espírito Santo','A Palavra de Deus escrita'),('NT04-L16-Q06','Os discípulos creram, e a purificação evidenciou a autoridade messiânica de Jesus.','Os discípulos abandonaram Jesus após a purificação, e o Evangelho perdeu credibilidade entre os judeus.','A purificação trouxe prosperidade financeira ao templo e expandiu o ministério dos apóstolos.','Os discípulos questionaram a autoridade de Jesus, o que gerou cismas na jovem Igreja primitiva.'),('NT04-L17-Q01','Na festa da Páscoa, conforme o Evangelho de Mateus 26:17-19.','Na festa de Pentecoste, conforme o livro de Atos 2:1.','Durante a festa dos Tabernáculos, conforme João 7:2.','Na festa da Dedicação, segundo o Evangelho de João 10:22.'),('NT04-L16-Q05','Por profecia direta, tipologia ou cumprimento literário das promesas divinas','Por mera coincidência histórica entre eventos separados por séculos','Somente através de reinterpretacão alegórica desconectada do contexto','Pela aplicacão exclusiva de regrasrabínicas de midrax e hagadá'),('NT03-L15-Q04','Revelam Jesus como o caminho, a verdade e a vida, enviado para glorificar o Pai e redimir.','Apresentam Jesus como um rei terreno que estabeleceria um reino político na Judeia.','Mostram Jesus apenas como um mestre sábio com ensinamentos éticos para a humanidade.','Revelam que Jesus veio anular a Lei e os Profetas e fundar uma nova religião.'),('NT03-L16-Q03','Palavras de Jesus em João 14,15 e 16 sobre o Consolador','Promessas de Pentecostes em Atos 2 sobre a chegada do fogo','Diálogos de Paulo em Romanos 8 sobre o Fruits do Espírito','Sinais de Isaías 11 sobre os dons do Espírito Santo'),('NT02-L17-Q07','Leia cada evangelho repetidamente, analisando contexto histórico, autor e propósito.','Comece por Marcos, pois é o mais curto e foi o primeiro a ser escrito.','Foque apenas nos milagres de cada evangelho para identificar diferenças.','Analise todos os quatro evangelhos simultaneamente para melhor compreensão.'),('NT03-L01-Q04','NAO SEI','O autor e destinatarios revelam a identidade e missao de Jesus por meio de milagres e ensinamentos','A identidade e missao de Jesus sao reveladas exclusivamente pelos profetas do Antigo Testamento','Autor e destinatarios demonstram a missao de Jesus atraves de rituais e祭祀'),('AT13-L07-Q03','NAO SEI','Buscar conselho dos homens em vez de Deus','Confiar no próprio entendimento acima de tudo','Responder com ira e palavras precipitadas'),('AT13-L07-Q02','O sábio é diligente no trabalho, mas o insensato se entrega à preguiça','O sábio evita o trabalho manual, e o insensato labuta sem cessar','O sábio confia na sorte, e o insensato planeja seus dias','O sábio governa com justiça, e o insensato obedece cegamente'),('AT13-L06-Q05','Motiva a corrigir com amor, instrução e mansidão, à imagem de Deus.','Orienta a poupar a correção para que os filhos sigam seu próprio caminho.','Ensina que a disciplina deve ser feita com ira e severidade extrema.','Indica que os pais devem delegar a correção exclusivamente à igreja.'),('AT13-L07-Q05','O temor do Senhor leva à diligência no trabalho e a aborrecer a preguiça','O temor do Senhor permite descansar o dia todo sem culpa','O temor do Senhor consiste em trabalhar apenas aos sábados','O temor do Senhor garante prosperidade automática sem esforço'),('AT13-L07-Q04','Pobreza, fome e ruína','Riqueza, poder e vitória','Sabedoria, força e vida','Honra, glória e vitória'),('AT13-L07-Q06','Como princípios gerais da ordem criada, não como garantias automáticas.','São promessas absolutas de prosperidade para quem os obedece fielmente.','Não precisam ser aplicados, pois foram abolidos na nova aliança.','Aplicando-os perfeitamente, garantimos nossa salvação pelas obras.'),('AT13-L08-Q02','A coroa dos sábios é a sua riqueza; a loucura dos tolos é só loucura','A fazenda do rico é a sua fortaleza; a pobreza é a herança do prudente','O sábio nunca empobrece; o tolo sempre acumula tesouros','A riqueza dos insensatos é bênção divina; a pobreza do sábio é provação'),('AT13-L11-Q05','O temor do Senhor leva a odiar a mentira e amar a verdade','O temor do Senhor permite mentir para proteger o próximo','O temor do Senhor torna a mentira indiferente na prática cristã','O temor do Senhor autoriza a mentira piedosa em situações extremas'),('AT13-L11-Q04','NAO SEI','A morte e a destruição seguem a mentira, mas a verdade preserva a vida para sempre','O insensato que mente prospera, mas o que fala a verdade enfrenta aflição','A insensatez produz riqueza em mentira e verdade sem distinção alguma'),('AT13-L17-Q04','A terra geme e os príncipes se multiplicam','Abundância de sabedoria e prosperidade eterna','Unidade perfeita entre o povo e o rei','Paz duradoura e governo estável'),('AT13-L20-Q06','Porque exige transformação do coração, não mera obediência exterior','Porque a Bíblia é um código legal a ser seguido sem questionar','Porque seus mandamentos só se aplicam ao povo de Israel','Porque cada ordenança deve ser lida de forma isolada e literal'),('AT13-L21-Q01','Cristo nos foi feito sabedoria de Deus, segundo 1 Co 1:30','A sabedoria de Deus é revelada somente em Pv 8, não no NT','Jesus ensinou sabedoria apenas por parábolas, segundo Mc 4','Somente o Espírito Santo é a sabedoria divina, e não Cristo'),('AT13-L21-Q02','Ele é a Sabedoria de Deus encarnada, cumprindo toda a Lei e os Profetas','Ele vivia como um fariseu, seguindo apenas as tradições dos anciãos','Jesus seguia a Lei de modo parcial, adaptando-a aos seus propósitos','Ele ensinava uma nova sabedoria, abandonando os preceitos mosaicos'),('AT13-L21-Q03','Jesus retoma o temor a Deus, a prudência e a justiça já presentes em Provérbios.','Jesus rejeitou por completo os ensinos e princípios contidos em Provérbios.','Jesus pregou unicamente o amor, descartando prudência e justiça de Provérbios.','Jesus retomou apenas temas do Apocalipse, sem ligação com a literatura sapiencial.'),('AT13-L21-Q04','No contexto original, é personificação poética, não identificação direta com Cristo','É uma cristofania explícita do Logos pré-encarnado no Antigo Testamento','Identifica o Verbo criado como primeira obra de Deus antes do mundo','Revela a natureza angélica de Cristo no princípio da criação divina'),('AT14-L01-Q01','O rei Salomão','O rei Davi','O patriarca Abraão','O profeta Jeremias'),('AT14-L01-Q02','O Pregador identifica-se como filho de Davi e rei em Jerusalém, sendo Salomão.','O Pregador é identificado como filho de Abraão e rei em Jerusalém, sendo Isaque.','O Pregador era um profeta gentio que profetizou em Jerusalém contra a casa de Davi.','O Pregador era sacerdote em Jerusalém, descendente direto de Arão, não de Davi.'),('AT14-L04-Q06','Mostra que as realizações humanas são vaidade, mas devem ser recebidas como dom de Deus','Ensina que o sucesso profissional garante a salvação eterna','Aprova o acúmulo de riquezas como sinal da bênção divina','Defende que o trabalho justifica o homem diante de Deus'),('AT14-L05-Q01','Vaidade e vaidade, tudo é vaidade debaixo do sol','Bênçãos de Deus e promessa de prosperidade aos justos','Sinais do fim dos tempos e da vinda do Messias glorioso','Promessas da nova aliança e do reino de Deus na terra'),('AT14-L05-Q02','NAO SEI','Jardins, servos, vinhas e cantores em Eclesiastes 2','Parábola do rico insensato em Lucas 12','Advertência de Paulo sobre o amor ao dinheiro'),('AT14-L05-Q04','A piedade com contentamento é grande ganho','O amor às riquezas é a raiz de toda a alegria','A prosperidade material é a maior bênção da aliança','O temor do Senhor traz aflição e pobreza'),('AT14-L05-Q05','Não confundir prosperidade com bênção divina nem prazer com pecado','Associar toda riqueza acumulada automaticamente à vontade soberana de Deus','Considerar qualquer forma de prazer terreno como condenação inevitável','Vincular a pobreza absoluta como requisito único da santidade cristã'),('AT14-L05-Q03','A vaidade: quem ama o dinheiro nunca se farta (Ec 5:10)','A completude: riqueza e prazer suprem toda necessidade humana','A eternidade: o gozo terreno garante vida sem fim','A liberdade total: a riqueza elimina toda limitação humana'),('AT14-L06-Q02','Construções, caminhos, mulheres Sabedoria e Loucura, temor do Senhor e disciplina','Os sacrifícios de animais e as festas litúrgicas no templo','As genealogias dos patriarcas e as bênçãos dos filhos','A circuncisão e as leis alimentares do povo de Israel'),('AT14-L06-Q04','O temor do Senhor é o princípio da sabedoria','O amor do Senhor é o princípio do conhecimento','A aliança divina é o fundamento da prudência','A obediência à lei é o fim de toda a loucura'),('AT14-L06-Q03','A mesma sorte que sobrevém tanto ao sábio como ao louco','A prosperidade eterna concedida ao prudente e sensato','O castigo divino reservado somente ao néscio e rebelde','A perfeita união entre o justo e o ímpio diante de Deus'),('AT14-L06-Q05','Não confundir sabedoria com mero conhecimento intelectual nem loucura com ignorância','Sabedoria é dom exclusivo dos anciãos e loucura é própria da juventude','A loucura é sempre castigada de imediato e a sabedoria sempre prospera na terra','Sabedoria e loucura são equivalentes conforme a cultura de cada povo'),('AT14-L06-Q06','A sabedoria é superior à loucura, mas ambas não evitam a vaidade','A sabedoria garante ao homem justificação diante de Deus','A loucura revela a verdadeira espiritualidade do coração','A sabedoria e a loucura são equivalentes diante de Deus'),('AT14-L07-Q01','Que há um tempo determinado para cada propósito debaixo do céu','Que tudo debaixo do sol é vaidade e aflição de espírito','Que o amor forte como a morte é o tema principal de Cantares','Que Deus julgará todas as obras más e boas no fim dos tempos'),('AT14-L06-Q01','Sabedoria é temer a Deus; loucura é correr atrás de vaidades passageiras','Sabedoria é juntar ouro e prata; loucura é rejeitar as riquezas','Sabedoria é dominar as letras; loucura é confiar cego na tradição','Sabedoria é seguir os rituais; loucura é negar toda a Escritura'),('AT14-L07-Q02','Eclesiastes 3 usa imagens de nascer, morrer, plantar e colher para cada propósito','Gênesis 1 usa os sete dias da criação para definir tempo de trabalho e descanso','Daniel 9 apresenta as 70 semanas como medida profética do tempo final','Apocalipse 20 descreve mil anos como tempo do reino milenial de Cristo'),('AT14-L07-Q03','Para tudo há um tempo, e um tempo para cada propósito debaixo do céu','Tempo de nascer e tempo de morrer, tempo de plantar e tempo de colher','Tempo de chorar e tempo de rir, tempo de prantear e tempo de dançar','Tempo de buscar e tempo de perder, tempo de guardar e tempo de lançar fora'),('AT14-L07-Q05','Evitar fatalismo absoluto, passividade ociosa e visão cíclica pagã.','Ensinar que cada tempo é determinado unicamente pelo signo zodiacal.','Usar o texto para negar a soberania divina sobre os acontecimentos.','Afirmar que Eclesiastes apoia a doutrina das reencarnações sucessivas.'),('AT14-L08-Q01','A perversão da justiça e a opressão que se observam debaixo do sol','A prática de idolatria e a adoração prestada a falsos deuses','A negligência dos deveres conjugais e o abandono do lar','A quebra das leis cerimoniais e dos rituais do santuário'),('AT14-L08-Q03','A finitude e a mortalidade como limite da existência humana','A onipotência divina revelada nas obras','A eternidade incondicional da alma imortal','A justiça perfeita e absoluta de Deus'),('AT14-L08-Q02','O êxodo, o jubileu e os oráculos proféticos contra a opressão','A criação, a queda e a expulsão do paraíso','As genealogias, o batismo e a transfiguração de Jesus','A torre de Babel, o dilúvio universal e a destruição de Sodoma'),('AT14-L08-Q05','Não atribuir a Deus a injustiça nem confundir justiça divina com vingança.','Deus é o autor da injustiça para corrigir os ímpios.','A injustiça só existe entre os que não têm fé verdadeira.','O estudo da injustiça deve limitar-se apenas à esfera social.'),('AT14-L08-Q04','Deus abomina a injustiça; o temor, o amor e a aliança exigem justiça.','Deus aprova a injustiça para cumprir seus propósitos soberanos','O temor e o amor a Deus são indiferentes à prática da injustiça','A aliança com Deus permite injustiça em nome da fé religiosa'),('AT14-L08-Q06','Revela que a justiça de Deus transcende a compreensão humana','Confirma que todo inocente é inevitavelmente abandonado por Deus','Garante que a maldade sempre triunfa sobre a retidão','Limita o poder divino diante da injustiça dos homens'),('AT14-L09-Q02','Sono, sombra, voltar ao pó; Cristo venceu a morte pela ressurreição','Reencarnação da alma em novo corpo conforme obras passadas','Aniquilação completa do ser sem qualquer esperança futura','Imediata glorificação da alma sem passagem pelo túmulo'),('AT14-L09-Q06','A morte lembra a brevidade da vida e motiva a busca pela sabedoria','A morte prova que a sabedoria é tão vaidade quanto a loucura','A morte é a punição final que destrói toda esperança humana','A morte mostra que justo e ímpio têm destino idêntico sem julgamento'),('AT14-L09-Q04','Porque o temor e o amor de Deus, pela aliança, vencem a morte','Porque o medo e o odio do homem confirmam a morte para sempre','Porque a antiga aliança termina no momento da morte fisica','Porque o amor humano sozinho e suficiente para vencer a morte'),('AT14-L09-Q05','Sono da alma, universalismo e reencarnação','Pré-milenismo, amilenismo e pós-milenismo','Calvinismo, arminianismo e molinismo','Cessacionismo, continuísmo e pentecostalismo'),('AT14-L10-Q03','A brevidade e vaidade da vida humana','A força gloriosa somente da mocidade','A sabedoria exclusiva dos anciãos','A alegria perfeita apenas na juventude'),('AT14-L10-Q01','Juventude: vigor para servir a Deus. Velhice: declínio físico e tempo de sabedoria.','Juventude: punição pelos pecados. Velhice: recompensa pela obediência.','Juventude: fase de vaidade absoluta. Velhice: período sem qualquer propósito.','Juventude: tempo de ignorância. Velhice: fase de inutilidade espiritual.'),('AT14-L10-Q05','NAO SEI','Juventude e velhice devem ser vistas como fases independentes, sem relacao espiritual entre si','A juventude e desprezivel diante da experiencia da velhice, segundo Eclesiastes','Somente os jovens devem buscar a Deus, pois os velhos ja alcanca a maturidade'),('AT14-L10-Q04','Lembra-te do teu Criador nos dias da tua mocidade','Lembra-te do teu Criador nos dias da tua velhice','O temor do Senhor se perde na mocidade segundo Eclesiastes','A aliança nova foi firmada apenas com os anciãos de Israel'),('AT14-L10-Q06','Exortam a temer a Deus na mocidade, antes dos dias difíceis da velhice.','Apresentam a velhice como a etapa mais nobre e feliz da existência humana.','Sugerem que a juventude deve ser vivida livre de qualquer temor divino.','Ensinam que a velhice anula completamente as escolhas feitas na mocidade.'),('AT14-L11-Q01','É a conclusão final do livro: o dever do homem diante de Deus.','É apresentado como fuga do mundo e rejeição de toda a sabedoria prática.','Aparece apenas no primeiro capítulo como princípio introdutório.','É descrito como algo opcional, dependendo da riqueza de cada um.'),('AT14-L11-Q02','Porque somos pó e frágeis, e o temor reverente reconhece a soberania divina','Porque Deus é vingativo e pune os homens por seus pecados','Porque o temor de Deus é uma forma de controlar as pessoas pela religião','Porque os homens devem temer a Deus somente após a morte, para evitar o inferno'),('AT14-L11-Q03','O temor do Senhor é o princípio da guarda dos mandamentos','O temor do Senhor é o fim dos mandamentos divinos','A obediência é independente do temor na Bíblia','O temor de Deus dispensa a obediência aos mandamentos'),('AT14-L11-Q06','NAO SEI','Tudo é vaidade e correr atrás do vento','O temor do Senhor é o princípio da sabedoria','Deus fez todas as coisas belas no seu tempo'),('AT14-L12-Q02','Reverência e obediência a Deus, pois é o dever de todo homem (Eclesiastes 12:13)','Um sentimento de medo e terror constante da punição divina','A prática de rituais sacrificiais e oferendas contínuas no templo','A busca pelo conhecimento teológico e estudo das escrituras apenas'),('AT14-L12-Q04','Que eram sábias, agradáveis e retas, escritas com verdade','Vãs e sem nenhum proveito para o homem','Agradáveis, porém enganosas e sem fundamento','Dificeis de compreender e desnecessarias'),('AT14-L12-Q03','Deus há de julgar todas as obras, manifestando o sentido oculto da história.','O juízo divino anula a liberdade humana, revelando o vazio da existência.','Deus apenas julga os pecados públicos, ignorando os pensamentos ocultos.','O juízo final confirma que a vida sempre foi absurda e sem propósito.'),('AT14-L12-Q01','Teme a Deus e guarda os seus mandamentos, porque este é o dever de todo o homem.','O fim do homem é o esquecimento, pois vaidade de vaidades, tudo é vão.','Comam, bebam e alegrem-se, pois amanhã morreremos e findará tudo.','Nada há melhor para o homem que se regozijar nas suas próprias obras.'),('AT14-L12-Q05','Porque o muito estudar é cansativo para a carne','Porque a sabedoria humana é superior à divina','Porque livros e estudos afastam o homem do trabalho','Porque somente os sacerdotes deveriam ter acesso ao conhecimento'),('AT14-L13-Q02','NAO SEI','Ezequiel, Daniel e Jeremias','Moisés, Arão e Josué','Elias, Eliseu e Samuel'),('AT14-L13-Q03','Pelos pronomes, verbos e vocativos que cada um emprega no diálogo','Pela quantidade de vezes que cada um aparece no texto','Pelo número de versículos que cada um fala em sequência','Pela posição em que aparecem no início de cada capítulo'),('AT14-L12-Q06','Selando o livro com a nova criação e a promessa final de Cristo.','Concluindo com a destruição de Roma e a queda do Império Romano.','Apresentando as sete igrejas e suas cartas de exortação e correção.','Mostrando o arrebatamento da igreja antes da grande tribulação.'),('AT14-L13-Q04','Selah, ''porque a sua misericórdia dura para sempre'' e aleluias.','''Amém'', ''glória a Deus'' e ''maranata'' como estribilhos poéticos.','Somente o Selah organiza estruturalmente os poemas hebraicos.','Cânticos dos levitas e hinos davídicos no templo de Jerusalém.'),('AT14-L13-Q06','O paralelismo sinonimo permite comparar termos e ampliar o sentido do texto','A estrutura narrativa cronologica dos eventos facilita a compreensao linear','O genero apocaliptico revela o futuro atraves de visoes e simbolos numericos','A estrutura midrashica interpreta o texto por meio de comentarios rabinicos'),('AT14-L13-Q01','Poemas líricos com diálogos entre os noivos e o coro das filhas de Jerusalém.','Relatos históricos organizados cronologicamente por reinados e conquistas militares.','Cartas e epístolas atribuídas a diversos profetas, apóstolos e líderes religiosos.','Leis e códigos cerimoniais divididos em seções sobre sacrifícios e festas religiosas.'),('AT14-L14-Q03','A mortalidade humana como limite do amor terreno','A omnipotencia divina que transcende o amor humano','A perfeição moral inatingivel pelo ser humano','A imortalidade prometida aos fieis em Cristo'),('AT14-L14-Q04','O temor a Deus desperta o amor, fundamentado na aliança','O amor a Deus elimina completamente o temor','A aliança depende apenas da obediência, sem amor','O desejo por Deus independe da aliança'),('AT14-L14-Q05','Não confundir agape com eros nem desejo com pecado.','O amor bíblico é puramente emocional e romântico.','Todo desejo deve ser suprimido por ser pecaminoso.','O Cântico dos Cânticos é apenas alegoria sem sentido literal.'),('AT14-L14-Q01','Em Cantares, amor e desejo representam a união esponsal Cristo-Igreja.','Em Eclesiastes, amor e desejo são vaidade e aflição de espírito passageiro.','No Cantares, amor e desejo significam apenas fraternidade e amizade entre irmãos.','Em Eclesiastes, amor e desejo representam a bênção eterna do trabalho humano.'),('AT14-L14-Q06','Ilustra a beleza e santidade do amor humano dentro do plano divino de Deus.','Apresenta o amor e desejo como distrações perigosas da vida espiritual.','Ensina que o amor conjugal deve ser evitado em favor da contemplação divina.','Defende que o desejo é a principal causa da queda espiritual do homem.'),('AT14-L15-Q01','Presente divino de amor, alegria e companheirismo entre o casal','Namoro e proibido, so o casamento diante de Deus tem valor','Apenas vaidade e vaidade, sem proposito real na vida','Relacao de dominacao onde a mulher deve submissao total ao homem'),('AT14-L15-Q05','NAO SEI','Confundir costumes culturais com mandamentos biblicos universais','Aplicar leis do Antigo Testamento sem considerar a nova alianca','Interpretar Cantares de Salomao de forma excessivamente literal'),('AT14-L15-Q02','A imagem de Cristo e a Igreja; Isaque e Rebeca; aliança e santidade.','A construção da torre de Babel e a confusão das línguas dos povos.','As pragas enviadas contra o Egito e a libertação do povo de Israel.','A construção da arca por Noé e o dilúvio que cobriu toda a terra.'),('AT14-L15-Q04','Devem ser alicerçados em Deus, no amor sincero e no pacto da aliança','Devem fundamentar-se somente na paixao e na atração fisica do casal','São apenas contratos sociais sem qualquer significado espiritual','Devem ser vividos independentemente de qualquer princípio de temor a Deus'),('AT14-L15-Q03','...','...','...','...'),('AT14-L15-Q06','NAO SEI','Apresenta o namoro como alternativa superior ao casamento','Sustenta que o matrimônio substitui a relação com Deus','Enseja que o divórcio é aceitável por incompatibilidade'),('AT14-L16-Q02','NAO SEI','A coroa de espinhos e o sudário de Cristo como imagem de beleza transformada','As pragas do Egito como argumento contra a admiração mundana','A experiência do cativeiro babilônico como prova da beleza passageira'),('AT14-L16-Q03','Vaidade de vaidades, tudo é vaidade','A brevidade inevitavel da existencia humana','A fugacidade da gloria e das paixoes mundanas','O vazio das conquistas carnais e terrenos'),('AT14-L16-Q01','Em Eclesiastes, vaidade; em Cantares, o amor entre Cristo e a Igreja','A condenação total da beleza física e da admiração como pecado','A celebração exclusiva da natureza criada e da obra divina','Um alerta profético contra a vaidade pessoal e o orgulho humano'),('AT14-L16-Q05','Não confundir beleza exterior com valor espiritual nem vaidade com formosura','Deve-se priorizar sempre a aparência física em detrimento do caráter cristão','Toda admiração humana constitui idolatria segundo os ensinos das Escrituras','A beleza física é sempre um sinal claro da aprovação divina na vida'),('AT14-L17-Q01','Pertença mútua e fiel entre esposo e esposa','União temporária entre homem e mulher','Relação permitida com múltiplos parceiros','Amizade fraternal entre os crentes'),('AT14-L17-Q02','Uma só carne, o mandamento contra o adultério e Cristo e a Igreja','Poligamia permitida, divórcio sem causa e votos renováveis','Concubinato aceito, fidelidade condicional e aliança quebrável','Casamento temporário, amor relativo e adultério tolerável'),('AT14-L17-Q05','Reduzir o adultério ao ato físico, pois Cristo inclui a intenção do coração','Tratá-la como norma apenas cultural do Antigo Testamento, pois é princípio eterno','Aplicar a exclusividade somente à mulher, pois ambos os cônjuges são responsáveis','Justificar a poligamia como compatível, pois o plano original de Deus é monogâmico'),('AT14-L17-Q04','Deus é testemunha da aliança conjugal, que une o casal em exclusividade.','A exclusividade conjugal é apenas acordo humano, sem envolver Deus.','O amor romântico basta; a aliança e o temor a Deus são dispensáveis.','A aliança conjugal pode ser desfeita livremente quando o amor acaba.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT14-L17-Q06','NAO SEI','Reforça a aliança de Deus com seu povo, ilustrando fidelidade','Símbolo da relação entre Cristo e a Igreja, sua noiva','Demonstra a santidade requerida para a vida devocional do crente'),('AT14-L18-Q01','Gozo do amor conjugal, dom de Deus para a comunhão dos esposos','Expressão carnal sem propósito espiritual algum no matrimônio','Dever penoso imposto aos cônjuges como fardo inevitável','Recurso apenas reprodutivo destituído de carinho ou afeto'),('AT14-L18-Q03','A concupiscencia, tendencia desordenada herdada do pecado original','A obrigacao mutua entre os esposos descrita em 1 Corintios 7','O livre arbitrio como faculdade exclusiva para decisoes sexuais','A obrigatoriedade da castidade absoluta dentro do matrimonio'),('AT14-L18-Q04','No casamento, a aliança santifica a sexualidade sob o amor e o temor de Deus.','No casamento, o amor e o temor de Deus substituem a aliança conjugal.','No casamento, a sexualidade é regulada apenas pelo amor, sem aliança.','No casamento, o temor de Deus proíbe o prazer sexual entre os cônjuges.'),('AT14-L19-Q01','Compreende o texto como poesia literal sobre o amor matrimonial entre homem e mulher.','Interpreta o cântico como alegoria do amor de Cristo pela Igreja.','Vê o livro como profecia sobre a relação de Israel com Deus no Antigo Testamento.','Entende a obra como alegoria política entre Salomão e a rainha de Sabá.'),('AT14-L19-Q02','NAO SEI','Como uma tipologia da redenção','Como um pacto de aliança literal','Como uma narrativa histórica secular'),('AT14-L18-Q06','A sexualidade no casamento aponta a união indivisível entre Cristo e a Igreja','Serve unicamente para fins de procriação segundo o mandato criador','Garante prazer exclusivo e realização pessoal aos cônjuges','Visa apenas evitar a tentação e a prática da fornicação'),('AT14-L19-Q04','Perda do sentido literal e do contexto histórico','O texto deixa de ser inspirado por Deus','A poesia perde sua beleza literária original','Apenas a leitura tipológica é válida'),('AT14-L19-Q03','Por representar a aliança de amor entre Cristo e a Igreja','Por profetizar a vinda do Messias com detalhes cronológicos','Por estabelecer as leis cerimoniais do povo de Israel','Por narrar as guerras de conquista da terra prometida'),('AT14-L19-Q05','NAO SEI','Privilegiando apenas o sentido alegorico-espiritual','Ignorando o contexto historico do texto','Aplicando somente a tipologia cristologica'),('AT14-L19-Q06','NAO SEI','Deve ser interpretado literalmente como prosa historica','Deve ser ignorado em favor do conteudo teologico','Serve apenas como ilustracao ornamental sem valor doutrinario'),('AT15-L01-Q03','Através de mensagens divinamente inspiradas, visões, sonhos e ações simbólicas.','Por meio de rituais sacerdotais e sacrifícios no templo','Através de consultas a adivinhos e médiuns pagãos','Por meio de cartas diplomáticas enviadas às nações vizinhas'),('AT15-L01-Q01','Mensageiro escolhido por Deus para transmitir Sua palavra ao povo','Sacerdote que oferecia sacrifícios e intercedia pelo povo','Rei ungido que governava o povo de Israel','Juiz que governava Israel em tempos de crise'),('AT15-L01-Q06','Para confirmar que toda profecia estivesse conforme a Escritura já revelada','Porque os profetas eram considerados falsos até prova em contrário','Para permitir que a igreja escolhesse entre vários profetas verdadeiros','Porque a revelação anterior era falha e precisava ser corrigida'),('AT15-L02-Q01','Convocação divina para proclamar a Palavra de Deus ao povo','Dom inato de antecipar o futuro por meios naturais','Cargo sacerdotal exercido no templo de Jerusalém','Título teológico atribuído aos doutores da Lei'),('AT15-L02-Q02','Isaías 6: templo, ano da morte do rei Uzias, reino de Judá','Jeremias 1: chamado antes de nascer, durante o reinado de Josias','Ezequiel 1: chamado junto ao rio Quebar, durante o exílio na Babilônia','1 Samuel 3: chamado na tenda da congregação em Siló, período dos juízes'),('AT15-L02-Q04','O chamado profético proclama juízo, santidade, aliança e restauração.','O chamado profético prioriza a lei mosaica, sacrifícios e o sacerdócio.','Esses temas surgem apenas nos evangelhos e em Atos dos Apóstolos.','São exclusivos da literatura sapiencial e dos provérbios de Salomão.'),('AT15-L02-Q06','Aponta para Cristo, anuncia a Nova Aliança e revela a consumação','Estabelece apenas a antiga aliança e o sistema sacrificial','Substitui o sacerdócio e elimina a função profética','Limita-se ao juízo presente sem dimensão escatológica'),('AT15-L03-Q02','Deuteronômio, período mosaico, renovação da aliança antes de entrar em Canaã','Jeremias, período do exílio babilônico, profecia da nova aliança com Israel','Oseias, período do reino dividido de Israel, denúncia da quebra da aliança','Isaías, período da crise assíria em Judá, promessas messiânicas e alianças'),('AT15-L03-Q01','Profecia é a mensagem divina ao povo; aliança é o pacto de Deus com Israel.','Profecia é somente prever o futuro distante; aliança é um contrato comercial.','Profecia é mensagem dos anjos celestiais; aliança foi feita só com Moisés.','Profecia é magia divinatória dos pagãos; aliança é promessa só aos gentios.'),('AT15-L03-Q05','Maranata, o Senhor vem!','Aleluia, Cristo ressuscitou!','Paz seja convosco','Graça, misericórdia e paz'),('AT15-L03-Q04','NAO SEI','Aparecem exclusivamente no livro de Apocalipse','São temas exclusivos do Antigo Testamento','Tratam-se apenas do juízo final escatológico'),('AT15-L03-Q06','Cristo cumpre as profecias, medeia a Nova Aliança e consuma o plano divino.','A profecia e a aliança findam no Antigo Testamento, sem vínculo com Cristo.','A Nova Aliança anula toda profecia anterior, que perde valor no Novo Testamento.','A consumação final é independente da aliança e da profecia cumpridas em Cristo.'),('AT15-L04-Q02','Livro de Isaías, período profético, crise assíria e exílio babilônico','Livro de Salmos, período davídico, liturgia do templo de Jerusalém','Livro de Apocalipse, período apostólico, visões escatológicas de João','Livro de Gênesis, período patriarcal, criação e queda da humanidade'),('AT15-L04-Q01','Juízo: castigo divino pelo pecado. Restauração: retorno e nova aliança.','Juízo é a vinda do Messias; restauração é a destruição do templo.','Juízo é prosperidade imediata; restauração é fuga para o Egito.','Juízo é bênção incondicional ao povo; restauração é o fim da lei.'),('AT15-L07-Q05','NAO SEI','Jesus é identificado como o Servo Sofredor que carrega os pecados da humanidade','Os textos apontam para Jesus como o novo Moisés que liberta seu povo','As profecias são aplicadas a Jesus como cumprimento literal das Escrituras'),('AT15-L07-Q03','Levado como cordeiro ao matadouro, sofreu por nossos pecados e será exaltado.','Sofreu o castigo dos inimigos de Israel, morreu em batalha sem redenção.','Foi exaltado primeiramente e depois padeceu pelos próprios pecados do povo.','Sofrimento apenas físico, sem propósito redentor, morreu abandonado por Deus.'),('AT15-L07-Q06','O Servo substitui o pecador, obtendo perdão e justificação para muitos.','A substituição do Servo é independente do perdão, pois a justificação vem pelas obras da lei.','O perdão é alcançado sem substituição, apenas pela confissão direta, sem necessidade de justificação.','A justificação ocorre antes da substituição e do perdão, por mérito próprio do crente.'),('AT15-L07-Q04','Carregando os pecados e enfermidades da humanidade em seu próprio corpo','Sofrendo somente como exemplo moral para imitacao dos cristaos','Sofrendo por seus proprios pecados e injusticas cometidas','Sofrendo para revelar a severidade de Deus contra os homens'),('AT15-L04-Q05','A segunda vinda de Cristo','O cativeiro babilônico','O dilúvio nos dias de Noé','A destruição de Sodoma'),('AT15-L07-Q07','Pelo sacrifício expiatório, o Servo justifica muitos, capacitando-os para as nações.','O sofrimento do Servo é apenas exemplo moral para a obediência dos fiéis seguidores.','O Servo vence as nações pelo poderio militar e impõe domínio político sobre povos.','O Servo sofre unicamente como punição por seus próprios pecados pessoais diante de Deus.'),('AT15-L08-Q01','A promessa do Messias que traria salvação, justiça e restauração a Israel','A vinda de um profeta como Moisés para libertar Israel da Babilônia','O anúncio de uma nova aliança restrita apenas à tribo de Judá','A promessa de um rei terreno que faria Israel potência mundial'),('AT15-L08-Q03','Immanuel, Renovo de Jessé e Servo Sofredor','Uzias, Acaz e Ezequias, reis de Judá','Senaqueribe, Rabsaqué e Tirsa, assírios','Moisés, Elias e Eliseu, outros profetas'),('AT15-L09-Q01','No décimo terceiro ano do reinado de Josias, rei de Judá (626 a.C.)','No primeiro ano do reinado de Ezequias, rei de Israel, por volta de 715 a.C.','Após a destruição do templo e o cativeiro babilônico em 586 a.C.','Durante o reinado de Davi, no apogeu da monarquia unida de Israel'),('AT15-L08-Q05','A vinda de Jesus Cristo, o Messias prometido e Servo Sofredor','Ciro, o rei persa que libertou os judeus do cativeiro babilônico','A reconstrução do templo de Jerusalém sob o governador Zorobabel','O retorno dos exilados judeus à terra prometida de Israel'),('AT15-L08-Q04','Em Isaías, o Messias traz juízo, santidade, aliança e restauração de Israel.','Isaías apresenta o Messias apenas como rei militar sem dimensão espiritual.','Em Isaías, o Messias destrói Israel e anula a aliança definitivamente.','Isaías não relaciona juízo, santidade, aliança e restauração ao Messias.'),('AT15-L09-Q02','Uzias, Jotão, Acaz e Ezequias','Davi, Salomão, Roboão e Jeroboão','Josias, Jeoaquim, Jeconias e Zedequias','Saul, Davi, Salomão e Roboão'),('AT15-L09-Q03','Chamado a anunciar o juízo de Deus e a chorar pela desobediência de Israel.','Foi o único profeta que escreveu cartas às sete igrejas da Ásia Menor.','Por ter liderado Israel na conquista da Terra Prometida com Josué.','Por ter interpretado os sonhos do rei Nabucodonosor na Babilônia.'),('AT15-L09-Q06','NAO SEI','A Nova Aliança é introduzida em Jeremias 31 e consumada em Lucas 22:20','Esperança e restauração aparecem somente no Novo Testamento','O livro não menciona esperança nem Nova Aliança'),('AT15-L09-Q05','Foi rejeitado, perseguido, açoitado e crucificado','Foi aplaudido, coroado rei e governou Israel em paz','Viveu sem oposição e morreu de velhice entre os seus','Exilou-se na Babilônia e nunca mais voltou a Jerusalém'),('AT15-L09-Q04','Denunciou a vã confiança no templo e as alianças com o Egito','Exortou a confiança no templo e a obediência à lei','Anunciou paz eterna ao povo fiel em Jerusalém','Encorajou a confiança no templo como defesa contra as nações'),('AT15-L09-Q07','Escriba de Jeremias que escreveu e leu as profecias, preservando a Palavra','Escriba do rei Josias que copiou a lei para o templo de Jerusalém','Profeta que continuou o ministério de Jeremias após o exílio na Babilônia','Sacerdote que escondeu os rolos proféticos no templo durante a destruição'),('AT15-L10-Q03','Jeremias, Ezequiel, Daniel e Jesus profetizaram a queda de Jerusalém','Isaías, Salomão, Davi e Elias anunciaram a destruição da cidade santa','Moisés, Abraão, Isaque e Jacó previram o exílio babilônico em suas visões','Samuel, Saul, Jônatas e Davi predisseram a ruína do templo de Jerusalém'),('AT15-L10-Q01','Juízo de Deus sobre Judá pela quebra da aliança e idolatria.','A salvação definitiva de Israel por meio do Messias.','A unificação política dos reinos de Israel e Judá.','O início do período intertestamentário de paz.'),('AT15-L11-Q01','Jeremias 31','Jeremias 29','Jeremias 7','Jeremias 25'),('AT15-L11-Q02','com a casa de Israel e a casa de Judá','com a casa de Davi e a casa de Levi','com a casa de Abraão e a casa de Moisés','com a casa de Efraim e a casa de Manassés'),('AT15-L10-Q05','A Nova Jerusalém descerá do céu como morada eterna de Deus com os homens','Jerusalém será reconstruída como capital política mundial restaurada de Davi','O terceiro templo será erguido e os sacrifícios animais restaurados para sempre','Jerusalém nunca caiu, pois a profecia de Jesus não se cumpriu historicamente'),('AT15-L11-Q04','Transformação interior pela qual o homem obedece a Deus espontaneamente','Memorização dos mandamentos para repetição oral constante','Cumprimento externo de rituais e cerimônias religiosas','Imposição da lei por meio de autoridades governamentais'),('AT15-L10-Q06','A queda de Jerusalém cumpre a profecia de Cristo e marca a Nova Aliança.','A queda de Jerusalém não tem conexão com Cristo, foi apenas fato político.','A queda de Jerusalém anula as promessas de Deus à descendência de Abraão.','A queda de Jerusalém realizou o fim literal e imediato do mundo presente.'),('AT15-L11-Q06','Este é o meu sangue da nova aliança, derramado por muitos','Esta é a minha carne oferecida em sacrifício pela redenção de Israel','Este cálice representa a nova aliança selada pela minha ressurreição','Este é o meu corpo partido em memória da antiga aliança'),('AT15-L12-Q01','Destruição de Jerusalém e do Templo pelos babilônios em 586 a.C.','A travessia do Mar Vermelho pelo povo de Israel','A conquista de Canaã sob o comando de Josué','A destruição de Sodoma e Gomorra'),('AT15-L11-Q05','NAO SEI','A terra se encherá do conhecimento do Senhor como as águas cobrem o mar','Serei propício somente aos convertidos mediante as obras da lei','Conhecereis a Deus apenas no dia do juízo final após a ressurreição'),('AT15-L11-Q03','A nova aliança cumpre e substitui a do Sinai, garantindo perdão definitivo','A aliança do Sinai permanece eterna e continua válida para os crentes','São pactos independentes, sem qualquer relação de cumprimento entre si','A nova aliança apenas renova a antiga mantendo idênticas exigências'),('AT15-L11-Q07','A nova aliança em Cristo supera a antiga, fundada em melhores promessas','A antiga aliança permanece plenamente válida e não é superada em nada','A superioridade da aliança apoia-se apenas em Moisés e nos profetas','O livro de Hebreus não discute a superioridade de nenhuma aliança'),('AT15-L13-Q01','Babilônia','Jerusalém','Samaria','Damasco'),('AT15-L12-Q05','Isaías 54:7-8','Jeremias 29:11','Salmos 23:4','Isaías 43:2'),('AT15-L13-Q02','Era sacerdote e se encontrava exilado na Babilônia, junto ao rio Quebar','Era rei de Judá levado cativo para a Babilônia após a queda de Jerusalém','Era profeta que permaneceu em Jerusalém durante o exílio babilônico','Era sumo sacerdote que liderou o retorno do povo do cativeiro'),('AT15-L13-Q03','Estruturam o livro em ciclos de revelação, dramatização e aplicação profética.','São elementos decorativos sem qualquer papel na organização do texto bíblico.','Substituem as narrativas históricas como principal meio de comunicação divina.','Organizam exclusivamente em ordem cronológica os eventos da história de Israel.'),('AT15-L13-Q04','Jeremias e Ezequiel profetizaram a destruição de Jerusalém pela Babilônia','Isaías profetizou que Jerusalém seria destruída pelos assírios','Elias e Eliseu anunciaram o juízo de Deus contra Jerusalém','Amós e Oseias predisseram a queda de Jerusalém para os filisteus'),('AT15-L13-Q05','A glória parte do templo em Ezequiel 10 e retorna pelo oriente em Ezequiel 43.','A glória desce no Sinai em Pentecostes e permanece na arca em Siló.','A glória parte com a queda de Jerusalém e retorna com Esdras em 538 a.C.','A glória se afasta no exílio e volta apenas na segunda vinda de Cristo.'),('AT15-L13-Q06','E vos darei um coração novo e porei um espírito novo dentro de vós','Eis que faço novas todas as coisas e não haverá mais morte nem pranto','Farei uma nova aliança segundo a lei do Sinai gravada em pedra','Criarei novos céus e nova terra onde habitará a justiça'),('AT15-L12-Q06','Ensina o lamento coletivo, a confissão dos pecados e a esperança no Senhor.','Propõe isolamento e silêncio pessoal como caminho para superação do sofrimento.','Recomenda a aceitação passiva sem expressão de dor nem diálogo com Deus.','Sugere a vingança imediata contra os opressores como resposta à aflição.'),('AT15-L14-Q01','A manifestação visível da presença majestosa e poderosa de Deus','A aliança eterna e incondicional firmada com Israel','O poder criador de Deus na formação dos céus e da terra','A sabedoria infinita de Deus revelada aos profetas'),('AT15-L14-Q02','Ezequiel, exílio babilônico, visão junto ao rio Quebar','Isaías, período assírio, visão no templo de Jerusalém','Êxodo, libertação do Egito, coluna de glória no deserto','Apocalipse, exílio em Patmos, visão do trono celestial'),('AT15-L14-Q05','Deus prometeu que sua glória encheria o novo templo','A glória do Senhor abandonou Israel para sempre','Deus revelou sua glória apenas a Moisés no Sinai','A glória divina se manifestou na arca da aliança'),('AT15-L13-Q07','Novo templo, terra repartida entre as tribos e a glória do Senhor retornando','Templo destruído, terra em ruínas e abandono da presença divina','Novo céu e nova terra, sem templo, com Deus habitando com os homens','Templo de Salomão, terra conquistada e a glória divina no Santo dos Santos'),('AT15-L15-Q01','Cada pessoa responde por seus proprios atos diante de Deus, segundo Ezequiel 18.','Que os filhos herdam a culpa dos pecados dos pais ate a quarta geracao','Que somente o rei e o sumo sacerdote respondem pelos pecados da nacao','Que a justica divina se aplica apenas ao povo como coletividade'),('AT15-L15-Q02','Ezequiel 18, no exílio babilônico, contra o provérbio sobre o pecado dos pais.','Jeremias 31, no período pré-exílico, anunciando a nova aliança no coração.','Levítico 16, no período mosaico, instituindo o ritual do Dia da Expiação.','Daniel 9, no exílio babilônico, orando pelo perdão dos pecados nacionais.'),('AT15-L15-Q06','Cada um dará conta de si mesmo a Deus','Todos serao salvos independentemente da fé pessoal','A eleicao divina anula toda responsabilidade humana','As proprias obras justificam o homem diante de Cristo'),('AT15-L15-Q05','O Tribunal de Cristo, onde cada um dará conta de si a Deus','A passagem do Mar Vermelho por Moisés e Israel','A unificação de Israel sob o reino de Davi','A queda das muralhas de Jericó diante de Josué'),('AT15-L16-Q01','Os ossos secos reviveram, formando um grande exército','Uma carruagem divina com rodas cheias de olhos','O novo templo sendo medido pelo anjo','Os quatro seres viventes com quatro rostos diferentes'),('AT15-L16-Q03','A palavra profética trouxe vida aos ossos secos, restaurando-os como exército vivo.','A palavra profética amaldiçoou os ossos, transformando-os em pó e cinzas.','A palavra profética purificou os ossos para serem usados em sacrifícios no templo.','A palavra profética endureceu os ossos como pedras para servirem de memorial.'),('AT15-L16-Q04','O Espírito do Senhor desce sobre o profeta e lhe revela a visão','O sopro apenas refresca o vidente, sem participação na visão','A visão ocorre por esforço humano independente do Espírito','O Espírito só atua depois da visão, apenas para interpretá-la'),('AT15-L16-Q02','A casa de Israel em aparente estado de morte no cativeiro','Os patriarcas hebreus falecidos antes do exílio babilônico','Os soldados mortos durante a queda de Jerusalém em 586 a.C.','Os profetas do antigo Israel que foram rejeitados pelo povo'),('AT15-L16-Q06','Analisando o contexto do exílio babilônico e a promessa de restauração nacional de Israel','Aplicando o texto diretamente à experiência pessoal de novo nascimento espiritual','Interpretando a passagem como profecia exclusivamente sobre a ressurreição de Cristo','Separando o sentido literal do figurado sem considerar o contexto histórico original'),('AT15-L17-Q01','Contemplação da glória divina que revela a santidade de Deus ao profeta','Anúncio profético da destruição iminente do templo de Jerusalém','Visão da nova arquitetura do templo restaurado no fim dos tempos','Profecia sobre a purificação futura do templo pelo Messias prometido'),('AT15-L17-Q03','Ezequiel','Isaías','Jeremias','Daniel'),('AT15-L17-Q02','Ezequiel, exílio babilônico (~573 a.C.), visão do novo templo','Daniel, período selêucida, visão do templo reconstruído','Apocalipse, cativeiro na Pérsia, visão do templo celestial','1 Reis, monarquia unificada, visão do templo salomônico'),('AT15-L17-Q06','Cristo cumpre a tipologia do templo, cuja visão se consuma na Nova Jerusalém','A visão refere-se apenas à reconstrução literal do templo em Israel','O templo descrito é exclusivo do culto levítico, sem qualquer relação com Cristo','A visão do templo é apenas simbólica da igreja local, sem dimensão escatológica'),('AT15-L18-Q01','Primeiro cativeiro da Judá, quando Nabucodonosor tomou Jerusalém','Segundo cativeiro da Judá, ordenado pelo rei Nabonido','Exílio no Egito, quando o faraó deportou os hebreus','Após a conquista da Babilônia por Ciro, o Persa'),('AT15-L17-Q05','Nos últimos dias, o monte da casa do Senhor será estabelecido no cume dos montes','A destruição do templo de Jerusalém por Nabucodonosor em 586 a.C.','A construção do segundo templo sob a liderança de Esdras e Neemias','A purificação do templo pelo rei Ezequias antes da invasão assíria'),('AT15-L18-Q04','Babilônia, Medo-Persia, Grécia e Roma','Egito, Assíria, Babilônia e Pérsia','Assíria, Caldeia, Pérsia e Grécia','Babilônia, Pérsia, Grécia e Cartago'),('AT15-L18-Q02','Hebraico e aramaico','Grego e aramaico','Latim e hebraico','Grego e siríaco'),('AT15-L18-Q06','O livro do Apocalipse','O livro de Cantares de Salomão','O livro de Rute','O livro de Obadias'),('AT15-L19-Q01','Fidelidade à aliança divina durante o desterro, esperando a restauração prometida.','Submissão total aos deuses dos povos conquistadores como forma de purificação.','Negação da profecia como método de preservação da identidade no cativeiro.','Acúmulo de riquezas materiais durante o cativeiro como sinal da bênção divina.'),('AT15-L19-Q02','Livro de Daniel, exílio babilônico (586 a.C.) sob Nabucodonosor','Livro de Rute, período dos juízes em Belém de Judá','Livro de Apocalipse, desterro do apóstolo João na ilha de Patmos','Livro de Êxodo, peregrinação do povo hebreu no deserto do Sinai'),('AT15-L19-Q03','Ezequiel, Daniel e Isaías, com visões de fidelidade no exílio babilônico','Balaão, Sansão e Eli, profetas do período dos Juízes','Visões apocalípticas de João em Patmos sobre o fim dos tempos','Moisés e Arão, libertadores do cativeiro egípcio no deserto'),('AT15-L19-Q05','A restauração de Israel e o retorno à Terra Prometida','A destruição eterna de Jerusalém e do templo','A permanência definitiva no cativeiro babilônico','A fuga do povo para o deserto do Sinai'),('AT15-L20-Q01','Revelam o governo soberano de Deus sobre a história e os reinos mundiais','Anunciam a permanência dos impérios terrenos sob proteção divina eterna','Descrevem somente visões pessoais dos profetas sem significado histórico','Indicam a formação eterna de um império israelita de poder universal'),('AT15-L20-Q03','José e Daniel','Moisés e Arão','Davi e Salomão','Pedro e Paulo'),('AT15-L20-Q02','Livro de Daniel, período do exílio babilônico, impérios babilônico e medo-persa','Livro de Apocalipse, período das perseguições romanas, impérios romano e babilônico','Livro de Ezequiel, período do exílio babilônico, impérios assírio e babilônico','Livro de Gênesis, período patriarcal, impérios egípcio e cananeu'),('AT15-L21-Q01','Daniel 9:24-27','Apocalipse 9:24-27','Ezequiel 9:1-12','Daniel 7:24-27'),('AT15-L21-Q02','A oração de Daniel em Daniel 9, durante o cativeio babilônico','A oração de Neemias durante a reconstrução dos muros de Jerusalém','A oração de Ezequiel junto ao rio Quebar em visão profética','A oração de Habacuque no templo após a invasão dos caldeus'),('AT15-L21-Q04','NAO SEI','Diluvio e arca de Noe','Chamado de Abraao','Exodo do Egito'),('AT15-L20-Q05','O reino eterno de Deus que destruirá todos os impérios terrenos','A libertação do povo hebreu da escravidão no Egito','O retorno dos judeus do cativeiro babilônico','A coroação de Davi como rei de Israel e Judá'),('AT15-L21-Q03','Períodos de sete anos, totalizando quatrocentos e noventa anos','Dias literais de sete dias cada, num total de 490 dias','Meses lunares de cerca de 29 dias, totalizando 490 meses','Gerações humanas de aproximadamente 40 anos cada uma'),('AT15-L21-Q05','As principais visões são preterista, futurista e historicista','Somente a interpretação futurista possui validade teológica','Divide-se exclusivamente em literal, simbólica e profética','A única correta é a leitura dispensacionalista literal'),('AT15-L21-Q07','A divindade de Cristo, a Trindade e a salvação pela graça mediante a fé','A obrigatoriedade da circuncisão e das leis cerimoniais para salvação','O batismo infantil como meio de regeneração e a presença real na ceia','A justificação pelas obras da lei e a necessidade de guardar o sábado'),('AT15-L22-Q02','Vem de percorrer a terra e apresenta-se diante do Senhor','Vem de Jerusalém e é apresentado perante Pilatos','Vem do Egito e é apresentado diante de Faraó','Vem do deserto e é apresentado diante dos anjos'),('AT15-L22-Q01','Vem com as nuvens do céu e se aproxima do Ancião de Dias','Vem cavalgando os quatro ventos sobre as águas','Aparece no meio das chamas com os vinte e quatro anciãos','Desce do trono entre os dez chifres do quarto animal')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT15-L22-Q03','Domínio eterno, glória e reino que não será destruído','Domínio terreno, glória passageira e reino temporário','Domínio apenas sobre Israel e reino limitado','Reino político restaurado com glória humana'),('AT15-L22-Q04','É sempiterno e não será destruído, nem passará a outro povo','Será limitado e temporário como os reinos das bestas','Será entregue aos reis da terra após julgamento','Desterroirá os reinos por meio de poder militar'),('AT15-L22-Q06','O título Messiânico une autoridade divina, sofrimento vicário e volta gloriosa.','O título Messiânico enfatiza apenas o sofrimento sem autoridade divina.','Os Evangelhos negam a volta gloriosa e limitam o Messias ao sofrimento.','Jesus é apresentado só como autoridade política terrena, sem retorno.'),('AT15-L22-Q05','Para cumprir a profecia de Daniel 7:13-14 sobre o Messias','Para negar qualquer descendência política da casa de Davi','Por ser uma tradição familiar recebida de José em Nazaré','Para indicar que possuía somente natureza humana comum'),('AT15-L23-Q01','Ressurreição dos mortos, uns para vida eterna e outros para vergonha eterna','Ressurreição física de Israel como nação restaurada e liberta do cativeiro babilônico','Ressurreição espiritual do crente por meio do novo nascimento na fé presente','Ressurreição corporal de Cristo ao terceiro dia conforme narram os evangelhos'),('AT15-L23-Q05','Ressurreição dos mortos para a vida eterna','Ressurreição somente dos justos para o reino','Restauração do templo e do culto em Jerusalém','Tradução dos santos ao final dos tempos'),('AT15-L23-Q02','Daniel 12:2, no período pós-exílico, durante a perseguição de Antíoco Epifânio','Daniel 12:2, no exílio babilônico, sob o governo de Nabucodonosor','Daniel 6:14, no período intertestamentário, sob o domínio romano','Daniel 9:24, no pré-exílio, durante o reinado de Davi em Israel'),('AT16-L01-Q02','A infidelidade de Israel para com Deus, simbolizando a idolatria do povo','O amor incondicional e a aceitação de Deus pelos gentios','A punição justa de Deus sobre as nações pagãs vizinhas','A aliança eterna e inquebrantável entre Davi e Israel'),('AT16-L01-Q01','O casamento de Oseias com Gomer representa Deus fiel e Israel infiel.','Oseias casou com uma princesa assiria para selar alianca politica.','O casamento de Oseias foi anulado porque Gomer era estrangeira.','Oseias desposou Gomer por visao propria, sem comando divino algum.'),('AT16-L01-Q04','A misericórdia do Senhor se renova a cada manhã e jamais se consome','Cessando totalmente enquanto Israel permanecer infiel','Sendo proporcional à obediência da nação','Manifestando-se exclusivamente no juízo final'),('AT16-L06-Q07','NAO SEI','O livro de Jonas confronta o exclusivismo israelita ao mostrar a misericórdia de Deus alcance os ninivitas','O Evangelho de Mateus revela a falta de compaixão dos fariseus através das denúncias de Jesus','Atos dos Apóstolos demonstra a resistência à graça pela perseguição inicial à igreja primitiva'),('AT16-L01-Q05','NAO SEI','Deus exerce juízo, disciplina a igreja e restaura a criação','O livro mostra apenas destruição final sem esperança','Disciplina substitui o juízo, sem restauração futura'),('AT16-L02-Q01','Joel exorta ao arrependimento diante do Dia do Senhor, juizo e restauração.','Amós denuncia injustiça social e anuncia o Dia do Senhor como juizo.','Miqueias profetiza a destruição de Samaria e a vinda do Messias em Belém.','Oséias usa a metáfora do casamento para condenar a idolatria de Israel.'),('AT16-L07-Q03','NAO SEI','A justiça, a misericórdia e a aliança se manifestam na obediência aos mandamentos divinos','O Dia do Senhor é descrito como dia de luz e restauração para todos os povos','A aliança renovada estabelece justiça perpétua e misericórdia eterna'),('AT16-L07-Q02','A crise de liderança e a promessa do Messias nascido em Belém','A construção do templo e o cativeiro na Babilônia','O conflito com os filisteus e a tomada de Jerusalém','A aliança com a Assíria e a reforma religiosa de Ezequias'),('AT16-L07-Q05','NAO SEI','Eis que faço novas todas as coisas','Nova Jerusalém descerá do céu','Os mortos ressuscitarão'),('AT16-L07-Q06','Em Mateus 2:6, ao citar Miqueias 5:2 sobre o governador nascido em Belém.','Em Lucas 2:4-7, quando José e Maria viajam para Belém para o censo.','Em João 7:42, quando alguns argumentam que o Cristo viria de Belém.','Em Apocalipse 12:5, quando a criança varão é arrebatada para Deus.'),('AT16-L08-Q02','A crueldade, violência e opressão de Nínive contra as nações e o povo de Deus','A apostasia espiritual do reino do norte de Israel com seus bezerros de ouro','O cativeiro babilônico de Judá e a destruição do templo de Salomão','A rebelião de Corá, Datã e Abirão contra a autoridade de Moisés'),('AT16-L08-Q03','NAO SEI','Justiça, misericórdia e aliança se manifestam no chamado ao arrependimento e na fidelidade de Deus.','O Dia do Senhor é descrito como dia de juízo e destruição dos ímpios.','A aliança renovada inclui promessas de justiça e misericórdia ao povo fiel.'),('AT16-L08-Q04','NAO SEI','Fé','Arrependimento','Obediência'),('AT16-L08-Q05','E Deus limpará de seus olhos toda a lágrima','Nem todo o que me diz Senhor, Senhor, entrará no reino dos céus','A ira de Deus se revela do céu contra toda impiedade','Ai dos que chamam ao mal bem e ao bem mal'),('AT16-L07-Q04','Obediência sincera de coração','Rituais externos sem devoção','Acúmulo de riqueza e poder','Isolamento total do mundo'),('AT16-L09-Q01','O justo viverá pela fé; Deus julgará o mal usando os babilônios','Habacuque profetiza a vinda do Messias e condena a idolatria do povo','O livro anuncia a destruição de Jerusalém pelos assírios como juízo final','Habacuque exorta o povo à prosperidade e condena a riqueza dos ímpios'),('AT16-L09-Q02','A prosperidade dos ímpios e o silêncio de Deus diante da injustiça em Judá','A apostasia do povo e a adoração de Baal nos tempos do profeta Elias','O exílio babilônico e a destruição do primeiro templo de Jerusalém','A idolatria do bezerro de ouro no Sinai e a murmuração do povo no deserto'),('AT16-L09-Q05','Pensamentos de paz vos tenho, para vos dar o fim que esperais','Restituir-vos-ei os anos que foram comidos, diz o Senhor','Eis que faço novas todas as coisas, escreve','O meu concerto de paz não será removido de vós'),('AT16-L09-Q03','NAO SEI','Nos profetas, anunciam juízo e esperança','No Pentateuco, fundamentam a Lei mosaica','Nos Evangelhos, revelam o caráter de Cristo'),('AT16-L10-Q01','No contexto do juízo divino pelos babilônios, exortando à fidelidade.','No contexto da profecia de Isaías sobre o Messias Salvador.','Durante a destruição do templo de Jerusalém pelos assírios.','No contexto da entrega da Lei por Moisés no monte Sinai.'),('AT16-L09-Q06','O justo vivera pela fe de Habacuque 2.4 e retomado em Romanos, Galatas e Hebreus','O problema do mal e resolvido em Apocalipse com a queda literal da Babilonia moderna','Habacuque e citado apenas em Atos pelos apostolos como profecia messianica','O cumprimento se da na segunda vinda com o julgamento dos caldeus e assirios'),('AT16-L10-Q03','Fidelidade, lealdade e compromisso relacional com Deus','Crença puramente intelectual e racional','Submissão cega e irracional a dogmas','Sentimento emocional e experiência mística'),('AT16-L10-Q04','NAO SEI','Paulo a cita em Romanos 3:28','Paulo a menciona em Gálatas 5:22','Paulo a explica em Romanos 8:1'),('AT16-L09-Q04','Fé em Jesus Cristo','Obras de justiça propria','Sacrificios e ofertas','Circuncisao e rituais'),('AT16-L10-Q06','NAO SEI','Porque expressa que a justificação é obra exclusiva de Cristo sem obras humanas','Porque estabelece a Escritura como única autoridade sobre a salvação','Porque declara que toda a glória pertence somente a Deus na salvação'),('AT16-L10-Q05','Exorta a correr com paciência, olhando para Jesus autor da fé','Promete prosperidade financeira aos perseverantes','Ensina que a salvação se obtém pelas obras da lei','Anuncia libertação do cativeiro babilônico para Israel'),('AT16-L11-Q03','NAO SEI','Apocalise de Deus com fogo e destruicao do ímpio','Nova aliança escrita no coração dos fiéis','Misericórdia vence o juízo segundo Tiago'),('AT16-L11-Q05','NAO SEI','A terra será cheia do conhecimento do Senhor como as águas cobrem o mar','Eis que faço novas todas as coisas','Novo céu e nova terra habitará a justiça'),('AT16-L11-Q06','é cumprido na segunda vinda de Cristo e no juízo final predito em Apocalipse','é abolido por Jesus ao oferecer salvação universal a todos os povos','foi cumprido apenas na destruição de Jerusalém em 70 d.C.','não possui cumprimento no Novo Testamento, sendo apenas histórico'),('AT16-L12-Q03','NAO SEI','Em Miqueias 6:8, Deus requer apenas justiça e misericórdia sem aliança','O Dia do Senhor aparece somente no livro do Apocalipse','Justiça e misericórdia se contradizem na lei mosaica'),('AT16-L12-Q02','A negligência do povo em reconstruir o templo, priorizando o próprio conforto','A introdução de cultos idolátricos gentílicos praticados dentro do templo','A aliança política com povos pagãos que impediam a reconstrução do altar','O abandono completo da lei mosaica e dos sacrifícios levíticos'),('AT16-L11-Q04','Fé em Deus','Sacrifícios rituais','Obediência à lei','Riquezas materiais'),('AT16-L13-Q01','Pós-exílio, reconstrução do templo. Central: restauração de Israel e vinda do Messias.','Período pré-exílico, reino dividido, condenação da idolatria em Israel e Judá.','Exílio babilônico, Judá cativo, anúncio iminente da destruição de Jerusalém.','Período intertestamentário, dominação selêucida e resistência dos Macabeus.'),('AT16-L12-Q05','Pensamentos de paz e não de mal, para vos dar o fim que esperais','Restituir-vos-ei os anos que comeu a locusta','Não temas, porque eu sou contigo, não te assombres','Deus limpará de seus olhos toda a lágrima'),('AT16-L13-Q03','NAO SEI','Justiça e misericórdia se manifestam no perdão de Deus ao povo','A aliança renovada e o Dia do Senhor marcam a esperança escatológica','Misericórdia prevalece sobre o juízo no Dia do Senhor'),('AT16-L12-Q06','Cristo é o cumprimento do templo, e os crentes formam o novo templo de Deus','A reconstrução do templo será literalmente cumprida no milênio futuro','Os sacrifícios do templo serão reinstituídos antes do fim dos tempos','O templo físico de Jerusalém permanece como único lugar de adoração'),('AT16-L12-Q04','Obediência aos seus mandamentos','Culto a ídolos e deuses pagãos','Rebeldia contra a autoridade divina','Oferecimento de sacrifícios humanos'),('AT16-L13-Q04','obediência','sacrifícios rituais','amor ao próximo','justiça própria'),('AT16-L14-Q01','o Renovo, o Rei no jumento, o Traspassado, o Pastor e a Fonte para o pecado','a Sarça Ardente, o Mar de Bronze, a Coluna de Fogo e o Propiciatorio','a Arvore da Vida, o Fruto Proibido, a Serpente e a Espada de Querubim','a Porta Estreita, a Videira, o Pao da Vida e o Cordeiro de Deus'),('AT16-L14-Q02','Humilde e manso, montado sobre um jumento, filho de jumenta','Poderoso e triunfante, montado sobre um cavalo branco','Glorioso e vitorioso, conduzido em um carro de guerra','Severo e justiceiro, montado em um camelo'),('AT16-L13-Q06','Ap 11 retoma os dois oliveiros de Zc 4 como as duas testemunhas','Cumprido na entrada de Jesus em Jerusalém montado num cavalo de guerra','Retomado apenas no Sermão da Montanha, em Mateus 5 a 7','As visões de Zacarias não possuem cumprimento no Novo Testamento'),('AT16-L14-Q05','Reconhecer Jesus Cristo crucificado como fonte de salvação','Identificar o soldado romano que traspassou o Mestre','Prefigurar a unção do sumo sacerdote no templo','Simbolizar a coroação do rei Davi em Jerusalém'),('AT16-L14-Q03','Simboliza Cristo, o pastor rejeitado pelo povo, cujo sofrimento traz redenção.','Representa os profetas do Antigo Testamento perseguidos pelos reis de Israel.','Significa a rejeição dos estrangeiros e pagãos pelo povo eleito de Deus.','Indica apenas o juízo divino sobre os pastores infiéis, sem dimensão messiânica.'),('AT16-L14-Q06','NAO SEI','Jesus é o Cordeiro de Deus que tira o pecado do mundo','Ele é a Pedra angular rejeitada pelos construtores','Jesus é o Bom Pastor que dá a vida pelas ovelhas'),('AT16-L14-Q07','O Messias crucificado purifica pecados e estabelece reino de paz','O Messias governa Israel somente com poderio militar, sem sofrimento','Zacarias profetiza apenas a purificação do templo, sem menção ao Rei','O sofrimento de Israel é unicamente político, sem esperança messiânica'),('AT16-L15-Q02','Os sacerdotes oferecem sacrifícios defeituosos e profanam a aliança do Senhor','A construção do bezerro de ouro nos templos de Betel e Dã por Jeroboão','O cativeiro assírio das dez tribos do reino do norte de Israel','A rebelião de Corá contra a autoridade de Moisés no deserto'),('AT16-L14-Q04','Judas, arrependido, restituiu as moedas aos sacerdotes e as lançou no templo','Pedro devolveu as moedas após negar Cristo três vezes e se arrepender','Os sacerdotes usaram as moedas para subornar Pilatos e condenar Jesus','Judas comprou com elas o campo do oleiro antes de se enforcar'),('AT16-L15-Q04','Praticar a justiça, amar a misericórdia e andar humildemente com o teu Deus','Oferecer holocaustos e sacrifícios continuamente ao Senhor','Guardar a lei perfeitamente sem jamais pecar diante do Senhor','Ser circuncidado e observar rigorosamente o sábado'),('AT16-L17-Q02','Idolatria e injustiça social','Cativeiro babilônico e o retorno','Ressurreição e vida eterna','Reconstrução do templo em Sião'),('AT16-L15-Q05','Pensamentos de paz e não de mal, para vos dar o fim que esperais','O Senhor teu Deus está no meio de ti, poderoso para te salvar','Restituir-vos-ei os anos que comeu o gafanhoto','Porque eu te amo com amor eterno'),('AT16-L19-Q03','NAO SEI','A justiça se cumpre antes da misericórdia na aliança','O Dia do Senhor anula a aliança e a misericórdia','A misericórdia substitui a justiça no Dia do Senhor'),('AT16-L19-Q02','Apatia espiritual e descaso com a reconstrução do templo','Idolatria generalizada e culto a deuses pagãos nas nações vizinhas','Opressão dos pobres e injustiça social praticada pelos reis de Israel','Apostasia da monarquia e culto falso nos santuários do norte'),('AT16-L17-Q06','Suas profecias se cumprem em Jesus Cristo, conforme Mateus 5:17','Realizam-se na restauração do templo por Esdras e Neemias','São explicados somente nas parábolas ensinadas por Jesus','Cumprem-se de forma exclusiva no dia de Pentecostes'),('AT16-L19-Q05','E haverá um novo céu e uma nova terra','E amaldiçoarei a terra para sempre','Não haverá mais esperança para os homens','E acabarei com toda a criação'),('AT16-L19-Q04','Fé','Sacrifícios','Temor','Ódio'),('AT17-L01-Q02','Os filhos de Samuel não andaram nos seus caminhos e aceitaram subornos.','Os filhos de Samuel profetizaram em Betel durante o reinado de Davi.','Samuel ungiu seus filhos como profetas em Ramá antes de falecer.','Os filhos de Samuel escreveram cartas às tribos pedindo um juiz.'),('AT17-L01-Q04','Samuel advertiu que o rei tomaria os filhos, filhas, campos e servos do povo','Samuel advertiu que o rei traria paz e prosperidade eterna a Israel','Samuel advertiu que o rei seria escolhido apenas entre os levitas','Samuel advertiu que o rei governaria com justiça e igualdade'),('AT17-L01-Q03','Representava rejeitar o senhorio direto de Deus sobre Israel','Pois comprometia a identidade cultural sagrada de Israel','Levava o povo a abandonar as praticas liturgicas do templo','Sinalizava o desejo de autonomia politica plena e absoluta'),('AT17-L02-Q02','Não multiplicar cavalos, esposas, prata e ouro; copiar e ler a lei','Construirá palácios luxuosos, terá guarda real e muitos servos','Escolherá sacerdote e oferecerá holocaustos diários no templo','Fará aliança com egípcios e multiplicará cavalos para a guerra'),('AT17-L02-Q03','Para aprender a temer ao Senhor e guardar todos os seus mandamentos','Para mostrar aos povos vizinhos sua sabedoria e grandeza pessoal','Para acumular prestígio e se colocar acima dos profetas e sacerdotes','Para substituir os juízes e governar Israel segundo o seu critério'),('AT17-L02-Q04','O rei julgava com justiça e defendia o pobre, o órfão, a viúva e o estrangeiro','O rei exercia poder absoluto sem prestar contas a nenhuma lei divina','Somente os profetas tinham autoridade para proteger os vulneráveis, não o rei','O governo real ignorava a justiça social, focando apenas na cobrança de tributos'),('AT17-L03-Q02','Samuel o ungiu, Jônatas seu filho, Davi o sucedeu; morreu em Gilboa','Moisés o guiou, Arão seu irmão, Egito; atravessou o mar Vermelho','Abraão o gerou, Isaque seu filho, Canaã; saiu em êxodo do Egito','Salomão o ungiu, Roboão seu filho, Judá; morreu no templo em Jerusalém'),('AT17-L02-Q05','Três ofícios distintos sob Deus: o rei governava, o sacerdote media, o profeta falava.','Eram o mesmo ofício: o rei também era sacerdote e profeta em Israel.','Os três ofícios eram sempre exercidos pela mesma pessoa escolhida por Deus.','O sacerdote tinha autoridade política sobre o rei e o profeta no Antigo Testamento.'),('AT17-L02-Q06','O fracasso dos reis revelou a necessidade do Messias, o Rei perfeito de Deus.','O fracasso dos reis provou que a monarquia em Israel sempre foi divina.','Os reis falharam, cumprindo assim todas as profecias messiânicas antigas.','O fracasso mostrou que Israel deveria voltar a ser governado por juízes.'),('AT17-L03-Q04','NAO SEI','Davi venceu Golias pela fé no Senhor dos Exércitos','Sansão perdeu sua força ao revelar seu segredo a Dalila','Pedro negou Jesus três vezes antes do galo cantar'),('AT17-L03-Q01','Primeiro rei de Israel, ungido pelo profeta Samuel','Rei pertencente à tribo de Judá, ungido após Davi','Rei famoso por construir o templo de Jerusalém','Rei conhecido por sua sabedoria e grande riqueza'),('AT17-L03-Q03','A cumprir os mandamentos de Deus e permanecer fiel a alianca','A agir por impulso, oferecendo holocaustos sem ser sacerdote','A poupar Agague e tomar despojos, desobedecendo ao Senhor','A consultar espiritos e feiticeiros para conhecer o futuro'),('AT17-L04-Q01','O segundo rei de Israel, homem segundo o coração de Deus','O primeiro rei de Israel, escolhido por sorteio entre as tribos','O último rei de Israel, responsável pela divisão do reino','Líder dos filisteus que venceu Golias a serviço de Israel'),('AT17-L03-Q06','Ao falhar, Saul demonstrou a necessidade de um rei perfeito vindo de Deus','Saul foi o modelo do rei messianico que reinaria em Israel eternamente','Saul aboliu a monarquia em Israel e restabeleceu o governo dos juizes','Saul cumpriu perfeitamente todas as profecias sobre o Messias vindouro'),('AT17-L04-Q04','NAO SEI','A vitoria de Davi sobre Golias e a derrota de Sansao contra Dalila','O sucesso de Josue em Jerico e o fracasso de Acã com o Anátema','A fidelidade de Daniel na cova e a queda de Pedro na negacao'),('AT17-L04-Q02','Golias','Sansão','Moisés','Abraão'),('AT17-L04-Q06','Pela aliança davídica, Deus prometeu descendente eterno no trono.','Conquistou toda a terra de Canaã, garantindo-a ao rei messiânico.','Construiu o templo onde o Messias se sentaria no trono de Davi.','Escreveu profecias nos livros dos reis sobre o Messias vindouro.'),('AT17-L04-Q05','De sua linhagem viria o Messias, conforme a aliança davídica','Davi construiu o templo de Jerusalém durante seu reinado','Após sua morte, o reino se dividiu imediatamente em Israel e Judá','Davi instituiu o sistema sacrificial e o sacerdócio levítico'),('AT17-L04-Q03','Andar em seus preceitos e guardar a aliança com o Senhor','Construir o templo do Senhor em Jerusalém','Subjugar os filisteus e todos os inimigos','Multiplicar cavalos e acumular riquezas'),('AT17-L05-Q04','NAO SEI','A obediência de Abraão ao sacrificar Isaque','A incredulidade de Tomé após a ressurreição','A idolatria do povo de Israel no deserto'),('AT17-L05-Q03','O rei davídico devia governar segundo a Lei do Senhor e guardar a aliança','O rei devia abolir a Lei mosaica e criar nova legislação própria','A aliança davídica substituía por completo a Lei e os profetas','O rei podia ignorar a Lei em assuntos políticos e militares'),('AT17-L05-Q02','Davi, Salomão, Jesus Cristo, o Reino de Israel e o Templo de Jerusalém','Moisés, Arão, o Êxodo e a entrega da Lei no monte Sinai','Abraão, Isaque, Jacó e a promessa da terra de Canaã','Elias, Eliseu, a queda de Samaria e o cativeiro assírio'),('AT17-L05-Q01','A promessa divina a Davi de um descendente e trono permanentes, em 2 Samuel 7.','A entrega da lei no Sinai,mediante Moisés,estabelecendo a Torá para Israel.','A promessa a Abraão de uma terra e descendência numerosa como as estrelas.','A unificação das tribos de Israel sob o reino de Saul em torno de 1020 a.C.'),('AT17-L05-Q06','Garante que um descendente de Davi reinará eternamente no trono de Israel.','Promete que Davi construirá o templo eterno para o Senhor em Sião.','Assegura a Israel domínio militar absoluto sobre todas as nações.','Confirma a aliança incondicional feita com Moisés no Sinai.'),('AT17-L05-Q05','Garantiu a perpetuidade do trono davídico e anunciou a vinda do Messias','Conquistou Canaã e estabeleceu os juízes sobre Israel','Dividiu Israel em reino do norte e do sul após Salomão','Promoveu a adoração aos deuses pagãos e a construção de altares idólatras'),('AT17-L06-Q02','A construção do Templo de Jerusalém','A destruição do Templo de Jerusalém','A travessia do Mar Vermelho','A unção como rei por Samuel'),('AT17-L06-Q05','A divisão do reino em Israel e Judá','A conquista e unificação de todos os reinos vizinhos','O cativeiro imediato do povo na Babilônia','A abolição da monarquia e fim do governo real'),('AT17-L06-Q04','NAO SEI','A queda de Adão e Eva no Éden','A vitória de Davi sobre Golias','A incredulidade do apóstolo Tomé'),('AT17-L06-Q06','Reinando em paz e construindo o templo, tipificou o Messias prometido','Perdeu dez tribos para Jeroboão logo após subir ao trono','Rejeitou a aliança davídica e aboliu o culto no templo','Submeteu Israel ao império assírio como vassalo'),('AT17-L07-Q01','Centro do culto a YHWH, edificado por Salomão e destruído em 586 a.C.','Edificado pelo rei Davi após a conquista da cidade santa','Localizado no Monte das Oliveiras, fora dos muros de Jerusalém','Destruído pelos assírios durante o reinado do rei Ezequias'),('AT17-L07-Q04','NAO SEI','Vitoria de Davi contra Golias','Queda de Sansao por Dalila','Triunfo de Elias no Carmo'),('AT17-L07-Q02','Salomão o construiu, Nabucodonosor o destruiu e Herodes o restaurou','Davi o construiu, Nabucodonosor o destruiu e Esdras o restaurou','Moisés o construiu, Belsazar o destruiu e Herodes o restaurou','Josias o construiu, Senaqueribe o destruiu e Ciro o restaurou'),('AT17-L07-Q03','Como casa de oração, adoração e obediência aos mandamentos divinos','Como centro político, administrativo e sede do governo israelita','Como mercado público e local de transações comerciais entre povos','Como fortaleza militar e refúgio seguro contra invasões inimigas'),('AT17-L07-Q05','Fim do culto sacrificial e início do judaísmo rabínico','Unificação das doze tribos sob o governo de Davi','Estabelecimento do sacerdócio universal cristão','Expansão do império assírio pela região de Canaã'),('AT17-L08-Q01','A separação entre Israel (norte) e Judá (sul) após a morte de Salomão.','A conquista assíria do reino do norte, que culminou na destruição de Samaria','O cativeiro babilônico, quando o templo de Jerusalém foi totalmente destruído','A reunificação das tribos sob o reinado de Ezequias após a queda de Samaria'),('AT17-L07-Q06','O templo é o trono de Javé, de onde o Messias reinará com justiça e glória.','O templo era apenas um local de sacrifícios animais sem conexão messiânica.','O templo de Jerusalém foi destruído definitivamente sem esperança de restauração.','O Messias rejeitou completamente o templo como instituição divina.'),('AT17-L08-Q02','Roboão, Jeroboão, reino de Israel e reino de Judá','Saul, Davi e Samuel, reis do período dos juízes','Nabucodonosor, Zedequias e a queda de Jerusalém','Abraão, Isaque e Jacó, patriarcas de Israel'),('AT17-L12-Q01','Conselheiros divinos que advertiam e repreendiam os reis','Substituir os reis no trono como governantes de Israel','Comandar os exércitos reais nas batalhas militares','Submeter-se obedientemente aos reis sem questionar')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('AT17-L11-Q05','Dinastias de Jeroboão, Baasa, Onri e Jeú','Apenas a dinastia davídica governou o Reino do Norte','Somente a dinastia de Acabe predominou no Reino do Norte','As dinastias de Saul, Davi e Salomão no Reino do Norte'),('AT17-L12-Q03','Samuel repreendeu Saul por desobedecer à ordem de destruir os amalequitas','Samuel havia ungido Saul como rei de Israel em momento anterior','Samuel lutou contra Saul numa guerra civil para defender o trono','Samuel perdoou Saul publicamente após ele poupar o rei Agag'),('AT17-L12-Q02','Porque eram chamados por Deus, não pelo rei, para falar com autoridade divina','Porque não possuíam formação acadêmica para exercer funções administrativas','Porque recebiam pagamento do templo, mantendo independência financeira do rei','Porque só profetizavam durante os períodos de jejum nacional declarado'),('AT17-L12-Q07','NAO SEI','O rei governava sem restricoes como senhor absoluto do povo','O poder real era limitado apenas pelo conselho de anciãos','O monarca acumulava poderes legislativo e judicial sem controle'),('AT17-L12-Q04','Por meio de uma parábola, disse: Tu és aquele homem.','Acusou-o diretamente de adultério com Bate-Seba.','Profetizou a destruição de sua casa por meio de Elias.','Apareceu-lhe em sonho para repreender seu pecado.'),('AT17-L13-Q01','Culto oficial a imagens e deuses estrangeiros imposto pela monarquia','Adoração particular de imagens em lares israelitas','Culto exclusivo dos patriarcas nos santuários familiares','Prática religiosa restrita ao povo de Judá no reino sul'),('AT17-L12-Q06','Eram rejeitados por Deus e perdiam o trono','Eram imediatamente curados de suas doenças','Recebiam grandes bênçãos materiais','Eram coroados como imperadores universais'),('AT17-L13-Q03','Subordinando o poder estatal à soberania de Deus, recusando cultos imperiais','Apoiando incondicionalmente o governo como instrumento direto de Deus','Substituindo a aliança pelo Estado como nova identidade do povo','Permitindo adoração ao governante quando a lei civil autorizar'),('AT17-L13-Q04','NAO SEI','A queda de Adão no Éden','O êxodo do povo de Israel','A multiplicação dos pães por Jesus'),('AT17-L13-Q05','Perseguição aos fiéis e juízo divino sobre a nação idólatra','Bênçãos divinas, prosperidade econômica e paz universal','Unificação religiosa entre todos os povos e harmonia plena','Vitória militar garantida, expansão territorial e glória'),('AT17-L14-Q01','Centralização do culto em Jerusalém, destruição de ídolos e abolição dos altos','Construção de altares pagãos e introdução do culto a deuses estrangeiros','Imposição do politeísmo oficial em todo o território de Israel','Alianças militares com Egito e Assíria para proteger o Templo'),('AT17-L13-Q06','A opressão dos impérios idolátricos intensifica o clamor pelo Messias prometido.','O culto ao Estado torna desnecessária a vinda de um rei messiânico futuro.','Esperanças messiânicas bíblicas surgem apenas em tempos de paz e prosperidade.','A adoração ao governo terreno confirma a legitimidade divina dos reis atuais.'),('AT17-L14-Q04','NAO SEI','Sansão perdeu sua força por desobedecer a Deus','Davi cometeu pecado grave ao ordenar o recenseamento','Salomão desviou-se do Senhor por causa de mulheres estrangeiras'),('AT17-L14-Q05','Divisão da cristandade, ascensão dos Estados nacionais e guerras religiosas.','Unificação total de todos os reinos cristãos sob autoridade papal absoluta.','Fortalecimento universal do poder do Papa sobre todas as nações europeias.','Extinção completa de todas as divergências religiosas em todo o Ocidente.'),('AT17-L15-Q01','Conquista de Samaria pelos assírios em 722 a.C., encerrando o reino do norte','Conquista da Babilônia sobre Jerusalém em 586 a.C.','Divisão do reino após a morte do rei Salomão','Invasão dos filisteus e captura da Arca da Aliança'),('AT17-L15-Q02','Nabucodonosor, Sedequias, Babilônia, destruição de Jerusalém e cativeiro','Davi, Salomão, Israel unido e a construção do Templo de Jerusalém','Saul, Davi, Golias e a unificação das tribos de Israel','Faraó, Moisés, Egito e a libertação do povo hebreu'),('AT17-L15-Q04','NAO SEI','A vitória de Davi sobre Golias e a derrota de Saul diante dos filisteus','O triunfo de Elias no Carmelo e a fuga de Jonas para Társis','A queda de Pedro ao negar Cristo e a fidelidade de Paulo nas viagens missionárias'),('AT17-L15-Q03','NAO SEI','A monarquia deveria ser abolida pela Lei para purificar Israel','O rei deveria consultar apenas os profetas, nao a Lei','A alianca com Davi garantiria a permanencia eterna do trono'),('AT17-L16-Q01','Promete descendência eterna no trono de Davi, cumprida em Cristo','Garante a posse da terra de Canaã à descendência de Abraão','Estabelece a lei mosaica como caminho para a salvação','Limita o reino de Davi apenas a Israel e Judá durante a monarquia'),('AT17-L15-Q06','A ausência do trono davídico gerou a expectativa do Messias prometido por Deus.','A queda da monarquia trouxe paz imediata e eliminou a necessidade de um rei salvador.','O fim da monarquia cumpriu as profecias sobre o término permanente do governo em Israel.','A destruição do templo extinguiu toda esperança religiosa e política do povo judeu.'),('AT17-L16-Q04','Porque as promessas messiânicas se cumpriram plenamente em Cristo, o Rei eterno.','Porque o povo de Israel sempre recusou aceitar qualquer governo monárquico sobre si.','Porque todos os reis de Israel morreram jovens em guerras contra a Assíria.','Porque Deus revogou as promessas davídicas após a idolatria de Jeroboão.'),('AT17-L16-Q05','Confirmou o juízo profético e renovou as promessas messiânicas ao remanescente.','Destruiu as esperanças davídicas e encerrou qualquer expectativa de restauração.','Pela aliança com a Babilônia que garantiria a continuidade do trono de Davi.','Pelo abandono da Torá e assimilação cultural que dissolveu a identidade do povo.'),('AT18-L01-Q02','Provocaram a ira de Deus, motivando o juízo condenatório','Purificaram o povo, preparando-o para a nova aliança','Atestaram a fidelidade divina, selando as promessas','Garantiram a salvação, assegurando a vida eterna'),('AT18-L01-Q05','Porque foi também consequência da infidelidade e idolatria do povo de Deus.','Porque Nabucodonosor buscava vingança pessoal contra o rei Zedequias.','Porque o exército de Judá se aliou secretamente ao Egito contra a Babilônia.','Porque faltou pagamento de tributos ao Império Assírio durante gerações.'),('AT18-L01-Q03','Provocou a ira do Senhor, resultando no juízo e exílio do povo','Estabeleceu uma aliança eterna e incondicional com Israel','Conduziu o povo à prosperidade e à bênção material','Garantiu a entrada imediata na terra prometida'),('AT18-L02-Q02','Império Assírio, Sargão II, Salmaneser V, profetas Amós e Oséias','Império Babilônico, Nabucodonosor, profetas Isaías e Jeremias','Império Egípcio, Faraó, profetas Moisés e Arão','Império Persa, Ciro, profetas Ageu e Zacarias'),('AT18-L02-Q01','Assírios conquistaram Samaria em 722 a.C., exilando as dez tribos do norte','Babilônios destruíram Samaria em 586 a.C., exilando as dez tribos','Persas invadiram o reino do norte e deportaram as tribos para a Pérsia','Egípcios capturaram Samaria e escravizaram todas as tribos do norte'),('AT18-L01-Q04','NAO SEI','...','...','...'),('AT18-L02-Q05','NAO SEI','O povo creu e se batizou, regozijando-se na Palavra.','O povo murmurou contra Deus no deserto.','O povo edificou um bezerro de ouro para adorar.'),('AT18-L02-Q03','NAO SEI','A aliança opera apenas como benção sem qualquer juízo corretivo sobre o povo.','A providência divina se ausenta nos momentos de juízo da aliança.','O juízo da aliança substitui totalmente a providência na condução do povo.'),('AT18-L02-Q06','A queda de Israel intensificou a esperança no Messias davídico restaurador de todas as tribos.','A queda de Israel eliminou de vez toda expectativa messiânica entre os judeus.','O cativeiro assírio provou que o Messias já havia chegado em pessoa a Israel.','A destruição do reino do norte encerrou definitivamente as profecias sobre o Messias.'),('AT18-L03-Q02','Senaqueribe, Salmaneser, Isaías, Naum e Jonas','Nabucodonosor, Belsazar, Daniel e Ezequiel','Ciro, Dario, Esdras e Neemias','Faraó, Moisés, Arão e Josué'),('AT18-L03-Q03','NAO SEI','Através do dilúvio de Noé, Deus julgou a corrupção humana','Na provisão do maná no deserto, Deus sustentou Israel','Pela queda de Jerusalém, Deus puniu a infidelidade da aliança'),('AT18-L03-Q05','NAO SEI','O povo deveria ter obedecido aos mandamentos do Senhor','O povo respondeu com fé e louvor a Deus','O povo deveria ter se arrependido e voltado para o Senhor'),('AT18-L02-Q04','Dispersão das dez tribos e introdução de cultos pagãos em Samaria','Reforma religiosa do rei Josias e centralização do culto em Jerusalém','Construção do primeiro templo em Jerusalém por Salomão','Cativeiro babilônico de Judá e destruição do templo'),('AT18-L03-Q01','As dez tribos foram deportadas e a terra repovoada por estrangeiros.','Judas foi destruído e seus habitantes levados ao cativeiro babilônico em 586 a.C.','Os exilados retornaram sob Zorobabel e o sacerdote Josué para reconstruir o templo.','Ciro da Pérsia conquistou a Assíria e permitiu o retorno dos cativos a Jerusalém.'),('AT18-L03-Q04','A queda de Samaria e a dispersão das dez tribos de Israel','A destruição do primeiro Templo de Jerusalém pelos assírios','A unificação política de Israel e Judá sob o domínio assírio','A conversão em massa dos israelitas ao culto exclusivo de Asur'),('AT18-L04-Q03','NAO SEI','Deus demonstra justiça ao punir a desobediência dos israelitas','A providência divina se manifesta no cuidado diário com o povo','O juízo da aliança revela a santidade imutável de Javé'),('AT18-L04-Q01','Nabucodonosor destruiu Jerusalém e levou Judá para o exílio babilônico','Ciro, rei da Pérsia, conquistou Jerusalém e deportou os judeus','Salmanasar destruiu Samaria e levou as dez tribos para o exílio assírio','Antíoco Epífanes profanou o templo e iniciou o exílio babilônico'),('AT18-L04-Q02','Nabucodonosor, Jeremias e Zedequias','Ciro, Dario e Zorobabel','Salmanasar, Sargão e Senaqueribe','Faraó Neco, Josias e Jeoaquim'),('AT18-L04-Q05','NAO SEI','Deveriam ter confiado em Deus e obedecido à Sua voz sem murmurar','Deveriam ter pedido um novo rei para governá-los sobre Israel','Deveriam ter construído um altar e offerings ao Senhor'),('AT18-L03-Q06','A opressão assíria intensificou a esperança de um Messias libertador prometido por Deus','A Assíria libertou Judá do cativeiro babilônico','Os assírios reconstruíram o Templo destruído em 586 a.C.','O domínio assírio trouxe paz e prosperidade para Israel'),('AT18-L05-Q02','Nabucodonosor, Belsazar, Daniel, Ezequiel, Zedequias e Jeoiaquim','Ciro, Dario, Assuero, Esdras e Neemias','Salomão, Davi, Josafá, Josias e Acaz','Faraó, Moisés, Arão, Josué e Calebe'),('AT18-L05-Q01','Destruição de Jerusalém e do Templo, levando o povo ao cativeio na Babilônia.','O rei Ciro emitiu decreto permitindo o retorno dos judeus exilados a Jerusalém','Daniel foi lançado na cova dos leões por desobedecer ao rei da Babilônia','O profeta Elias subiu ao céu em carro de fogo durante o cativeio babilônico'),('AT18-L05-Q03','NAO SEI','O juízo da aliança se manifesta no dilúvio, quando Deus destrói a humanidade por sua corrupção','A providência divina aparece no Êxodo, guiando Israel pela coluna de nuvem e fogo','O juízo se revela no exílio babilônico como consequência da infidelidade à aliança mosaica'),('AT18-L05-Q05','NAO SEI','Crendo no Senhor e sendo batizados','Com temor e tremor, obedecendo a voz de Deus','Louvando e adorando ao Senhor com alegria'),('AT18-L04-Q04','Exílio babilônico e destruição do Templo de Salomão','Divisão do reino unido entre Roboão e Jeroboão','Fim do cativeiro assírio e retorno das dez tribos','Reforma religiosa promovida pelo rei Josias'),('AT18-L05-Q04','Destruição do Templo, exílio babilônico e fim da monarquia davídica','Estabelecimento do reino dividido entre Israel e Judá após Salomão','Expansão do território israelita sob o reinado de Davi até o Eufrates','Reforma religiosa de Josias com centralização do culto em Jerusalém'),('AT18-L05-Q06','Promoveu a esperança de um Messias redentor e de restauração de Israel.','Eliminou qualquer expectativa messiânica entre os judeus exilados.','Cumpriu imediatamente as promessas do Messias em Israel.','Afastou o povo judeu da fé em Javé para sempre.'),('AT18-L06-Q03','NAO SEI','O juizo da alianca se manifesta nas bênçãos e maldições de Deuteronômio 28','A providencia divina age por meio da eleicao incondicional em Romanos 9','O tema central revela a soberania divina sobre nações e individuos'),('AT18-L06-Q01','O templo foi destruído pelos babilônios, causando o exílio e a restauração.','O templo foi destruído pelos assírios, e o exílio ocorreu sob Nabucodonosor.','O templo foi destruído pelos persas, e nunca houve reconstrução em Jerusalém.','O templo foi destruído pelos romanos em 70 d.C., encerrando o culto judaico.'),('AT18-L06-Q05','NAO SEI','Tiveram fé em Deus e obedeceram','Murmuraram contra Moisés no deserto','Adoraram ídolos e se rebelaram'),('AT18-L06-Q02','Nabucodonosor','Salmaneser','Herodes, o Grande','Ciro da Pérsia'),('AT18-L09-Q03','NAO SEI','O juízo da aliança opera por meio da obediência ou transgressão dos mandamentos pactuais de Deus.','A providência divina sustenta todas as criaturas segundo o propósito soberano do Criador.','Ambos revelam a santidade e a misericórdia de Deus na história da redenção.'),('AT18-L09-Q05','NAO SEI','O povo deveria louvar a Deus com sacrificios','O povo obedeceu e confiou no Senhor','O povo se arrependeu e clamou a Deus'),('AT18-L06-Q04','Fim dos sacrifícios no templo e ascensão do judaísmo rabínico e das sinagogas','Reconstrução imediata do templo de Jerusalém por ordem do imperador','Retorno dos sacrifícios no altar e restauração do sumo sacerdócio','Unificação das tribos de Israel sob governo do sumo sacerdote'),('AT18-L10-Q03','NAO SEI','Deus executa o juízo da aliança por meio da providência que guia Israel à terra prometida','A aliança é quebrada quando o povo busca a providência de outros deuses e juízos','Juízo e providência revelam a soberania divina sobre as nações pagãs na dispensação'),('AT18-L10-Q02','Império Babilônico, Nabucodonosor, Joaquim, Daniel e Jeremias','Império Assírio, Senaqueribe, Manasses e Isaías','Império Persa, Ciro, Dario e Zorobabel','Império Romano, César Augusto, Herodes e João Batista'),('AT18-L10-Q05','NAO SEI','O povo respondeu com jejum, oração e arrependimento sincero diante do Senhor','O povo deveria responder com louvor e gratidão ao Altíssimo','O povo clamou em alta voz, derramando lágrimas e buscando a face de Deus'),('AT18-L11-Q01','Ciro emitiu decreto permitindo o retorno dos judeus a Jerusalém','Nabucodonosor permitiu o retorno dos exilados a Jerusalém','Dario destruiu o templo e deportou os líderes judeus','Assuero comandou a invasão e queda de Jerusalém'),('AT18-L10-Q04','Renovou a esperança de restauração, responsabilidade individual e novo coração','Converteu os babilônios ao culto exclusivo de Yahweh','Concedeu autonomia política aos exilados na Babilônia','Iniciou a reconstrução do templo em Jerusalém durante o exílio'),('AT18-L10-Q06','Profetizou a restauração de Israel, o novo coração e o Messias davídico','Conduziu o primeiro retorno dos exilados da Babilônia','Escreveu o livro de Lamentações pelo cativeiro em Jerusalém','Fundou a escola profética em Jerusalém após o exílio'),('AT18-L11-Q05','NAO SEI','Construindo um bezerro de ouro para adorar','Fugindo para o deserto em desespero','Lapidando o profeta com pedras'),('AT18-L11-Q02','Ciro, Dario, Artaxerxes, Assuero, Daniel, Esdras, Neemias','Nabucodonosor, Belsazar, Daniel, Ezequiel, Jeremias','Senaqueribe, Tiglate-Pileser, Salmanasar, Oseias, Naum','Herodes, Pilatos, Augusto, Tiberio, Paulo'),('AT18-L11-Q04','O retorno do exílio e a reconstrução do Templo em Jerusalém','A destruição do Templo e o início da diáspora judaica','A helenização forçada e a proibição da circuncisão','O cativeiro perpétuo em Babilônia sem qualquer restauração'),('AT18-L12-Q04','Retorno dos exilados judeus e reconstrução do Templo em Jerusalém','Destruição do Templo e deportação dos judeus para a Babilônia','Estabelecimento da monarquia unificada em Israel sob o rei Davi','Divisão do reino de Israel em Judá e Samaria após morte de Salomão'),('AT18-L12-Q02','Império Persa, Ciro, Daniel, Zorobabel, Josué, Ageu e Zacarias','Império Babilônico, Nabucodonosor, Jeremias, Esdras e Neemias','Império Assírio, Senaqueribe, Isaías, Ezequias e Manassés','Império Romano, César Augusto, Herodes, João Batista e Jesus'),('AT18-L16-Q05','NAO SEI','Com fé inabalável e obediência imediata aos mandamentos do Senhor','Com clamor sincero e arrependimento diante de Deus','Com louvor e gratidão pelas grandes obras realizadas'),('AT18-L16-Q06','Renovou a aliança, purificou a adoração e manteve viva a esperança no Messias','A restauração da Lei encerrou definitivamente a esperança messiânica entre os judeus','A Lei restaurada por Esdras anulou todas as promessas proféticas sobre o Messias','A Lei foi restaurada apenas após a destruição do segundo templo pelos romanos'),('AT18-L11-Q06','Permitiu o retorno dos exilados e a continuidade das promessas messiânicas.','Conquistou Israel e encerrou definitivamente todas as profecias messiânicas.','Substituiu a Torá pelo Zend-Avesta entre os judeus da diáspora.','Proibiu qualquer prática religiosa judaica e destruiu o templo.'),('AT18-L16-Q04','Destruição de ídolos, centralização do culto em Jerusalém e renovação da aliança','Conquista da terra prometida e divisão entre as doze tribos de Israel','Construção do primeiro templo e início do reinado davídico-salomônico','Divisão do reino em Israel e Judá após a morte de Salomão'),('AT18-L17-Q02','O exílio babilônico e Esdras, após a destruição do Templo','Salomão e a construção do Primeiro Templo em Jerusalém','Moisés e a entrega da Lei no Monte Sinai','O Império Romano com Pôncio Pilatos na Judeia'),('AT18-L17-Q03','NAO SEI','No dilúvio, Deus julgou a corrupção humana e preservou Noé por meio da arca','No Êxodo, as pragas manifestaram o juízo divino sobre o Egito e a libertação de Israel','Em Daniel, a providência de Deus sustentou os hebreus na furna de fogo ardente'),('AT18-L17-Q05','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('AT18-L17-Q01','Surgiram durante o exilio babilonico para estudo da Torah e oracao','Foram edificadas por Salomao junto ao Templo de Jerusalem','Foram instituidas por Moises durante a peregrinacao no deserto','Jesus as construiu durante seu ministerio na Galileia'),('AT18-L17-Q06','Preservou o estudo das Escrituras e das profecias messiânicas','Substituiu os sacrifícios do templo como meio de salvação','Estabeleceu um novo sacerdócio paralelo ao de Jerusalém','Promoveu a insurreição armada contra o domínio romano'),('AT18-L17-Q04','A centralização do culto no Templo cedeu lugar à oração e ao estudo local','O sacerdócio levítico foi abolido e transferido para as sinagogas locais','Os sacrifícios passaram a ser oferecidos diariamente em todas as sinagogas','A Torá perdeu autoridade e foi substituída pela tradição oral nas sinagogas'),('AT18-L18-Q01','Porque a plenitude das promessas proféticas só se cumpriria com Cristo.','Porque o povo judeu demonstrou grande infidelidade após o retorno.','Porque os governantes persas limitaram severamente a autonomia judaica.','Porque os profetas se enganaram quanto às promessas para a nova era.'),('AT18-L18-Q04','Proferiram profecias messiânicas, o Dia do Senhor e a restauração final de Israel.','Pregaram unicamente leis cerimoniais e rituais sem profecia escatológica','Anunciaram apenas a destruição dos ímpios sem esperança de restauração','Eram mensagens exclusivamente políticas e nacionalistas sem conteúdo espiritual'),('AT18-L18-Q06','NAO SEI','Atraves da traducao dos textos sagrados para o grego','Por meio da dominacao romana e da Pax Romana','Com a reconstrucao do templo por Zorobabel'),('AT18-L18-Q03','NAO SEI','...','...','...'),('FB01-L01-Q02','Significa ''livros'', do grego biblia (plural de biblion)','Significa ''Palavra de Deus'', do hebraico davar','Significa ''Livro único'', do latim liber singularis','Significa ''Escritura sagrada'', do aramaico ktaba'),('AT18-L18-Q05','A opressão estrangeira alimentou a esperança de um Messias libertador em Israel','A dominação estrangeira fez Israel desistir de esperar qualquer libertação','O domínio estrangeiro trouxe prosperidade econômica que eliminou o desejo','A presença estrangeira convenceu Israel de abandonar as esperanças messiânicas'),('FB01-L01-Q05','O Espírito Santo, que inspirou os homens santos de Deus','Jesus Cristo, que ditou cada palavra diretamente','Os apóstolos, que escreveram sob impulso próprio','Moisés, autor do Pentateuco e de toda a Escritura'),('FB01-L01-Q04','Por conterem a Palavra de Deus, divinamente inspirada','Por ter sido escrita somente em hebraico e grego antigo','Por ter sido aprovada pelos grandes concílios da Igreja','Por ser o livro mais antigo já produzido pela humanidade'),('FB01-L01-Q03','Porque reúne 66 livros de diversos autores e épocas, sob a inspiração de Deus.','Porque foi escrita por um único autor em um único período da história.','Porque contém apenas os evangelhos e as cartas de Paulo, sem livros históricos.','Porque foi organizada no século XX por decisão de uma entidade internacional.'),('FB01-L01-Q09','O plano de Deus para a salvação da humanidade por meio de Cristo','A história política e militar do povo de Israel ao longo dos séculos','Uma coletânea de leis e mandamentos entregues a Moisés no Sinai','Os ensinamentos morais de profetas e sábios para a vida piedosa'),('FB01-L01-Q07','...','...','...','...'),('FB01-L02-Q02','39 livros','27 livros','46 livros','66 livros'),('FB01-L02-Q04','66 livros','73 livros','54 livros','27 livros'),('FB01-L02-Q03','O Novo Testamento contém 27 livros.','O Novo Testamento contém 26 livros.','O Novo Testamento contém 28 livros.','O Novo Testamento contém 39 livros.'),('FB01-L02-Q01','Antigo Testamento e Novo Testamento','Pentateuco e Evangelhos','Livros históricos e proféticos','Escritos sapienciais e apocalípticos'),('FB01-L02-Q06','A vida, morte e ressurreição de Jesus, e o início da Igreja.','A criação do mundo, a queda do homem e o dilúvio universal.','A travessia do Mar Vermelho, o êxodo e a lei mosaica.','O sacrifício de Isaque, o cativeiro e a construção do Templo.'),('FB01-L02-Q05','Da criação do mundo ao período intertestamentário','Da vida de Jesus à fundação da igreja cristã','Apenas o período da monarquia unificada em Israel','Do nascimento da igreja aos primeiros concílios eclesiásticos'),('FB01-L02-Q08','O Novo Testamento é o registro escrito da Nova Aliança em Cristo','A Nova Aliança substituiu o Novo Testamento após a morte de Cristo','Novo Testamento e Nova Aliança são expressões idênticas em significado','O Novo Testamento anulou a Nova Aliança ao ser canonizado'),('FB01-L02-Q09','Jesus Cristo cumpre as profecias messiânicas do Antigo Testamento.','Moisés cumpriu as promessas ao libertar Israel no Novo Testamento.','O Novo Testamento substitui o Antigo, anulando todas as suas promessas.','Paulo escreveu as profecias que se cumpriram na era apostólica.'),('FB01-L02-Q07','O Antigo Testamento é o registro da Antiga Aliança entre Deus e Israel','A Antiga Aliança foi estabelecida somente após o exílio na Babilônia','O Antigo Testamento contém apenas as profecias messiânicas de Israel','A Antiga Aliança e o Antigo Testamento são conceitos sem qualquer ligação'),('FB01-L03-Q02','NAO SEI','Mateus, Marcos, Lucas, João, Atos, Romanos, Coríntios, Gálatas, Efésios, Filipenses','Gênesis, Êxodo, Levítico, Números, Deuteronômio, Josué, Juízes, Rute','Apocalipse, Judas, 3 João, 2 João, 1 João, 2 Pedro, 1 Pedro, Tiago'),('FB01-L02-Q10','Porque revela o plano de Deus e profetiza a vinda de Cristo.','Porque substitui o Novo Testamento na salvação do cristão.','Porque contém apenas leis rituais já abolidas por Cristo.','Porque é leitura obrigatória só para o povo judeu convertido.'),('FB01-L03-Q04','Apocalipse','Gênesis','Hebreus','Judas')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB01-L03-Q05','Malaquias','Zacarias','Ageu','Joel'),('FB01-L03-Q07','Gênesis, Êxodo, Levítico, Números, Deuteronômio','Gênesis, Êxodo, Levítico, Deuteronômio, Números','Gênesis, Êxodo, Números, Levítico, Deuteronômio','Gênesis, Êxodo, Levítico, Números, Josué'),('FB01-L03-Q06','Mateus','Apocalipse','Gênesis','Atos'),('FB01-L03-Q03','Gênesis','Apocalipse','Mateus','Êxodo'),('FB01-L03-Q08','Mateus, Marcos, Lucas e João','Mateus, Marcos, Lucas e Atos','Mateus, Marcos, João e Lucas','Mateus, Lucas, Marcos e João'),('FB01-L03-Q09','Jó vem antes e Provérbios depois de Salmos','Isaías vem antes e Jeremias depois de Salmos','Provérbios vem antes e Eclesiastes depois de Salmos','Jó vem antes e Cantares de Salomão depois de Salmos'),('FB01-L03-Q10','João vem antes e Romanos depois de Atos.','Marcos vem antes e Coríntios depois de Atos.','Lucas vem antes e Efésios depois de Atos.','Mateus vem antes e Apocalipse depois de Atos.'),('FB01-L04-Q01','São formas reduzidas dos nomes dos livros bíblicos, usadas para facilitar citações de livros, capítulos e versículos.','São códigos ocultos na Bíblia que revelam mensagens proféticas secretas.','São notas explicativas adicionadas nas margens das Bíblias de estudo.','São versões simplificadas do texto bíblico para crianças e iniciantes.'),('FB01-L03-Q12','Permite localizar passagens rapidamente por meio de referências organizadas.','Porque os livros bíblicos seguem estritamente a ordem cronológica dos fatos.','Porque a posição de cada livro revela sua autoridade canônica inspirada.','Porque a sequência dos livros determina a importância teológica deles.'),('FB01-L04-Q03','Mt., Mc., Lc., Jo.','Mt., Mr., Lc., J.','Mat., Mar., Lu., Jn.','M., Mc., L., Jo.'),('FB01-L03-Q11','1 João, 2 João, 3 João, Judas e Apocalipse','Hebreus, Tiago, 1 Pedro, 2 Pedro e 1 João','Romanos, 1 Coríntios, 2 Coríntios, Gálatas e Efésios','1 Pedro, 2 Pedro, 1 João, 2 João e 3 João'),('FB01-L04-Q02','Gn, Êx, Sl, Is','Ge, Ex, Sa, Is','Gên, Êxo, Salm, Is','Gn, Ex, Sal, Isa'),('FB01-L04-Q06','Lê-se o nome do livro, seguido do capítulo e do versículo','Lê-se apenas os números do capítulo e versículo, sem o nome do livro','Lê-se o versículo, depois o capítulo e por fim o nome do livro','Lê-se o nome do livro em grego ou hebraico, conforme a versão'),('FB01-L05-Q01','Pentateuco, Históricos, Poéticos, Profetas Maiores e Menores','Evangelhos, Atos, Epístolas Paulinas e Apocalipse','Pentateuco, Salmos, Provérbios, Evangelhos e Apocalipse','Torá, Neviim, Ketuvim e Escritos Apostólicos'),('FB01-L05-Q02','Gênesis, Êxodo, Levítico, Números e Deuteronômio','Gênesis, Êxodo, Levítico, Números e Josué','Gênesis, Êxodo, Levítico, Deuteronômio e Josué','Gênesis, Êxodo, Números, Deuteronômio e Josué'),('FB01-L07-Q07','Capítulo divide o livro; versículo é a unidade numerada; passagem é um trecho selecionado.','Capítulo é a unidade numerada; versículo divide o livro; passagem é o trecho completo.','Capítulo, versículo e passagem são sinônimos que indicam a mesma divisão bíblica.','Versículo é a divisão maior do livro; capítulo é a menor parte numerada; passagem é o índice.'),('FB01-L08-Q02','NAO SEI','A fé, a obediência e a perseverança são características comuns aos patriarcas e profetas.','Moisés, Davi e Paulo representam os três pilares da narrativa bíblica.','A aliança, a lei e a redenção definem os personagens principais das Escrituras.'),('FB01-L08-Q01','Suas vidas e feitos revelam o plano de Deus','Apenas os nomes e as cidades onde nasceram','Somente os personagens do Antigo Testamento','Suas histórias separadas do contexto bíblico'),('FB01-L09-Q01','Jerusalém, Belém, Nazaré, Egito e o rio Jordão são essenciais','Roma, Atenas e Corinto são os lugares bíblicos mais essenciais','Apenas o templo de Jerusalém é indispensável ao estudante','Babilônia, Pérsia e Grécia são os únicos lugares a estudar'),('FB01-L08-Q04','Evitar confundir os Herodes, as Marias, os Jaques e os Simões bíblicos.','Não atribuir feitos de um patriarca a outro do mesmo período bíblico.','Jamais mencionar personagens apócrifos em estudos sobre textos canônicos.','Ignorar as diferenças entre reis e profetas ao analisar narrativas bíblicas.'),('FB01-L09-Q03','Dá contexto geográfico e histórico, evitando erros de interpretação','Substitui a leitura devocional da Bíblia','Revela profecias ocultas sobre o fim dos tempos','Garante salvação eterna ao estudioso'),('FB01-L10-Q04','Não confundir judeus com israelitas, fariseus com saduceus, samaritanos.','Confundir patriarcas do AT com apóstolos do NT como se fossem iguais.','Tratar cananeus e filisteus como se fossem o mesmo povo antigo.','Identificar essênios e zelotes como um único grupo sem diferenças.'),('FB01-L11-Q02','Moisés, Davi, Isaías, Paulo e João são os principais autores bíblicos','Pedro, Tiago, Judas e Barnabé são os principais autores bíblicos','Apolo, Priscila e Silas são os principais autores do Novo Testamento','Ezequiel, Daniel e Jeremias escreveram apenas cartas às igrejas'),('FB01-L10-Q05','Auxilia a situar os textos no contexto histórico, geográfico e cultural bíblico.','Limita-se a reconhecer os personagens principais nas histórias do Antigo Testamento.','Serve apenas para decorar a ordem dos reis e impérios nas Escrituras Sagradas.','Dispensa o uso de mapas e comentários para localizar passagens bíblicas antigas.'),('FB01-L11-Q01','Conhecer a vida, o contexto histórico e a mensagem inspirada de cada autor.','Que escreveram de forma independente, sem unidade teológica entre si.','Que somente Moisés e Paulo foram os verdadeiros autores bíblicos sagrados.','Que os autores escreveram apenas conforme opinião pessoal, sem revelação.'),('FB01-L11-Q05','Conhecer o autor e seu contexto facilita a localização e interpretação.','O conhecimento dos autores elimina a necessidade de oração ao ler as Escrituras.','Somente os quatro evangelistas possuem autoridade canônica nas Escrituras.','Identificar o autor impede a aplicação pessoal da Palavra de Deus.'),('FB01-L12-Q01','Saber os 66 livros em ordem, divididos em Antigo e Novo Testamento e seus grupos','Memorizar versículos-chave de cada livro em ordem cronológica de redação','Saber apenas os 39 livros do Antigo Testamento e seus respectivos autores','Conhecer a quantidade de capítulos e versículos de cada livro bíblico'),('FB01-L12-Q03','Facilita localizar livros e entender o contexto histórico de cada passagem bíblica.','Substitui a necessidade de consultar concordâncias e comentários bíblicos.','Garante interpretação correta sem precisar do texto em hebraico e grego.','Permite ler a Bíblia inteira sem abrir nenhum índice ou sumário.'),('FB01-L12-Q05','Auxilia a localizar textos, a entender o contexto e a memorizar as Escrituras.','Permite apenas decorar versículos isolados sem compreensão do todo bíblico.','Serve exclusivamente para fins litúrgicos, sem aplicação no estudo pessoal.','Substitui a necessidade de consultar índices e concordâncias bíblicas.'),('FB01-L12-Q02','Divisões do AT (lei, históricos, poéticos, profetas) e do NT (evangelhos, cartas)','Apenas memorização dos primeiros versículos de cada capítulo bíblico','Estudo teológico profundo de cada livro sem preocupação com a ordem','Tradução e análise linguística dos textos originais em hebraico e grego'),('FB02-L01-Q01','A salvação da humanidade por meio da fé em Jesus Cristo','A prosperidade financeira como principal bênção divina','A obediência à lei mosaica como caminho de justificação','A previsão detalhada de datas e eventos do fim do mundo'),('FB02-L01-Q04','O pecado, que separa o homem de Deus','A pobreza material e econômica','A ignorância e a falta de educação','As doenças e o sofrimento físico'),('FB02-L01-Q02','Deus criou, o homem pecou, Cristo redimiu, e Deus restaurará toda a criação.','A narrativa bíblica começa com a queda e termina na criação de Adão.','Deus criou, julgou, abandonou e condenou a humanidade sem restauração.','Criação, dilúvio, lei e cativeiro resumem os quatro atos da Bíblia.'),('FB02-L01-Q03','Deus é o Criador, Soberano e Redentor que conduz o plano da salvação da humanidade.','Deus é apenas um juiz distante que observa a humanidade sem intervir na história.','Deus delega toda a autoridade aos anjos celestiais, sem agir diretamente no mundo.','Deus é uma força impessoal e distante que surgiu após a criação do universo.'),('FB02-L01-Q05','Jesus Cristo é o centro da Bíblia, o Salvador prometido por Deus.','Moisés é o centro da Bíblia, o grande legislador e libertador.','A Lei e os profetas são o centro único da mensagem bíblica.','Jesus foi apenas um profeta, não o centro das Escrituras Sagradas.'),('FB02-L02-Q01','Deus criou o homem à sua imagem, dando-lhe domínio sobre a terra','Deus destruiu a humanidade com um dilúvio por causa da maldade','Deus confundiu as línguas dos homens na torre de Babel','Deus chamou Abraão para formar uma grande nação'),('FB02-L01-Q08','Novos céus e nova terra','O arrebatamento secreto da igreja','O retorno ao paraíso do Éden','O fim absoluto de toda a criação'),('FB02-L02-Q02','Deus Criador, Adão e Eva, a Queda no Éden e Cristo Redentor.','Noé, Abraão e Moisés são centrais para o propósito humano.','Davi, Salomão e os reis de Israel explicam o propósito humano.','Paulo, Pedro e os apóstolos revelam o plano original de Deus.'),('FB02-L01-Q07','Da criação à consumação: promessas, aliança, Cristo e reino eterno','Realizado plenamente só no milênio, ausente na era atual','Estabelecido de forma completa já no Sinai','Restrito ao povo de Israel, sem extensão à igreja'),('FB02-L02-Q03','Criados à imagem de Deus para cultivar a terra e viver em comunhão com Ele','Criados para servirem exclusivamente à nação de Israel e seus descendentes','Herdaram a terra após a queda por merecimento próprio e esforço humano','Predestinados desde o ventre materno ao chamado individual antes do pecado'),('FB02-L02-Q04','Deus criou o homem à sua imagem para dominar a terra','Deus prometeu ao homem vida eterna sem qualquer condição','O homem foi criado apenas para servir os anjos na terra','Deus abandonou a humanidade após a queda sem esperança'),('FB02-L03-Q01','Adão e Eva desobedeceram a Deus, comendo do fruto proibido no Éden','Adão e Eva foram expulsos do Éden antes de comer o fruto proibido','Caim matou Abel por causa do fruto proibido no jardim do Éden','Noé advertiu o mundo sobre o pecado antes do dilúvio universal'),('FB02-L03-Q02','Adão, Eva e a serpente no Jardim do Éden','Caim, Abel e o primeiro homicídio na história','Moisés, Arão e a sarça ardente no Sinai','Davi, Bate-Seba e o profeta Natã'),('FB02-L03-Q04','Protoevangelho: promessa da semente da mulher que ferirá a serpente','Dilúvio universal como juízo pela maldade humana','Aliança com Abraão e promessa de uma grande nação','Entrega dos Dez Mandamentos no monte Sinai'),('FB02-L03-Q05','A entrada do pecado tornou necessária a obra redentora de Cristo.','O pecado entrou por meio da serpente, eliminando a necessidade de redenção.','A entrada do pecado tornou a redenção impossível para toda a humanidade.','O pecado entrou após o dilúvio, invalidando a aliança com Abraão.'),('FB02-L04-Q02','Noé, seus filhos, a arca, o dilúvio e a Torre de Babel','Abraão, Isaque, Jacó, o êxodo e a Páscoa','Moisés, Arão, os dez mandamentos e o Sinai','Davi, Salomão, o templo e os profetas'),('FB02-L03-Q03','Entrou pela desobediência de Adão e Eva no Éden, contaminando toda a humanidade','Originou-se com a rebelião de Lúcifer e anjos caídos antes da criação do homem','Veio pelo primeiro homicídio, quando Caim matou seu irmão Abel por inveja','Surgiu com a adoração de Israel ao bezerro de ouro no Sinai após o êxodo'),('FB02-L04-Q01','Deus castigou a humanidade com o dilúvio e dispersou as nações em Babel','Deus enviou pragas ao Egito e libertou Israel do cativeiro','Deus destruiu Sodoma e Gomorra por causa da maldade humana','Israel atravessou o Mar Vermelho e peregrinou pelo deserto'),('FB02-L04-Q04','A promessa de nunca mais destruir a terra pelo dilúvio','A promessa de dar a Abraão uma descendência innumerable','A promessa do Messias que viria da linhagem de Davi','A promessa de entregar a terra de Canaã a Israel'),('FB02-L04-Q03','Representam juízo de Deus e transição para a história patriarcal.','O dilúvio marcou o início da criação, e a dispersão, seu encerramento.','São relatos independentes, sem ligação com o plano redentor divino.','A dispersão ocorreu antes do dilúvio, como punição pelo pecado original.'),('FB02-L05-Q01','Deus chamou Abraão, fez aliança e prometeu descendência e terra','Moisés libertou Israel do Egito e recebeu os mandamentos no Sinai','Os juízes como Gideão e Sansão lideraram Israel antes dos reis','O rei Davi unificou as tribos e trouxe a arca para Jerusalém'),('FB02-L05-Q02','Abraão, Isaque, Jacó, suas esposas, a aliança divina e a Terra Prometida','Moisés, Arão, Josué, os profetas e a conquista de Canaã','Samuel, Saul, Davi, Salomão e a monarquia unificada','Os juízes Débora, Gideão e Sansão no período dos líderes'),('FB02-L05-Q03','Situam-se após o dilúvio e antes do êxodo, firmando a aliança divina.','Vivem no período dos juízes de Israel, após a conquista de Canaã.','Inserem-se após o exílio na Babilônia, durante o retorno do povo.','Antecedem o dilúvio universal, junto com Enoque e Matusalém.'),('FB02-L06-Q01','Saída do Egito, aliança no Sinai e formação do povo de Israel no deserto','Conquista da terra de Canaã sob a liderança de Josué e divisão das tribos','Exílio do povo judeu para a Babilônia e destruição do templo de Jerusalém','Reinado de Davi e Salomão, construção do templo e auge do reino de Israel'),('FB02-L06-Q03','Situa-se entre os patriarcas e a conquista de Canaã, formando Israel como nação','Ocorre no período dos juizes, após a conquista de Canaã e antes da monarquia','Situa-se após o cativeiro na Babilônia, marcando o retorno dos exilados','Corresponde ao período da monarquia dividida, após o reinado de Salomão'),('FB02-L06-Q04','A libertação do povo hebreu da escravidão no Egito','A conquista militar de Canaã sob liderança de Moisés','A instituição da monarquia israelita logo após o Êxodo','A revelação do Messias prometido ainda no Sinai'),('FB02-L07-Q01','Os israelitas, liderados por Josué, conquistaram Canaã após a morte de Moisés','Os israelitas foram libertados do cativeiro no Egito por Moisés','Davi derrotou Golias e unificou as doze tribos de Israel','Os israelitas foram exilados para a Babilônia por Nabucodonosor'),('FB02-L07-Q03','Realiza a promessa a Abraão, após o êxodo e a peregrinação no deserto.','Inicia a história com a criação do mundo e a queda da humanidade.','Corresponde ao cativeiro babilônico e ao fim da monarquia israelita.','Precede a aliança abraâmica e a formação do povo de Israel.'),('FB02-L07-Q04','A promessa de Deus de entregar a terra a Israel, cumprindo o juramento a Abraão','A construção do templo de Jerusalém por Salomão na terra conquistada','O recebimento das tábuas da lei no monte Sinai pelos israelitas','A libertação do cativeiro babilônico e o retorno a Jerusalém'),('FB02-L07-Q05','Tipifica o descanso da fé, mostrando Deus cumprir as promessas a Abraão.','Anuncia o fim da lei e a abolição imediata dos sacrifícios.','Representa a destruição definitiva de toda a terra prometida.','Simboliza a perda da aliança e o abandono do povo eleito.'),('FB02-L08-Q01','Israel passou do governo dos juízes para a monarquia, iniciando com Saul','Cativeiro babilônico com a destruição do templo e exílio do povo de Israel','Ministério terreno de Cristo entre os judeus e o início da Igreja cristã','Chamado de Abraão e formação da aliança com os patriarcas de Israel'),('FB02-L08-Q02','Juízes, Samuel, Saul, Davi e a transição para a monarquia em Israel','Moisés, Arão, Josué e o êxodo e a conquista de Canaã','Elias, Eliseu, Acabe e a divisão do reino de Israel','Abraão, Isaque, Jacó e a aliança com os patriarcas'),('FB02-L08-Q05','Demonstram a necessidade de um governante perfeito, cumprida em Cristo.','Garantem a estabilidade política e militar de Israel em todas as épocas.','Estabelecem alianças duradouras com povos vizinhos para garantir a paz.','Promovem a prosperidade econômica por meio de acordos comerciais internacionais.'),('FB02-L08-Q04','A infidelidade de Israel e a promessa do Messias davídico','A libertação do Egito e a travessia do mar vermelho','A entrega da lei mosaica no monte Sinai','O retorno do cativeiro e a reconstrução do templo'),('FB02-L09-Q01','Após a morte de Salomão, o reino se dividiu em Israel (norte) e Judá (sul).','O reino se dividiu em três partes após Davi, formando Israel, Judá e Efraim.','Durante o reinado de Saul, o reino se dividiu entre as tribos do norte e do sul.','O reino se dividiu após a morte de Moisés, formando duas nações no deserto.'),('FB02-L09-Q04','A divisão ocorreu como juízo pela idolatria de Salomão','A divisão foi causada por uma grande seca em todo o reino','O reino se dividiu para combater a invasão dos assírios','A divisão aconteceu para separar os sacerdotes dos levitas'),('FB02-L09-Q03','Após a morte de Salomão, o reino se dividiu em Israel e Judá','Ocorre antes do êxodo, quando Moisés divide as tribos de Israel','Resulta da divisão entre Saul e Davi no início do período real','Marca o início da monarquia unida sob Davi e seu filho Salomão'),('FB02-L09-Q02','Salomão, Roboão, Jeroboão e as dez tribos','Moisés, Arão, Josué e a entrada em Canaã','Saul, Davi, Samuel e a monarquia unida','Elias, Eliseu, Acabe e o culto a Baal'),('FB02-L10-Q01','Cativeiro babilônico dos judeus e posterior retorno a Jerusalém','Cativeiro egípcio dos hebreus e saída do Egito sob Moisés','Conquista da terra prometida e destruição de Jericó','Divisão do reino em Israel e Judá após Salomão'),('FB02-L10-Q04','A promessa divina de restaurar Israel e trazê-lo de volta à terra','A maldição eterna e o abandono definitivo do povo de Israel','A construção do primeiro templo pelo rei Salomão','A aliança original feita com Abraão e seus descendentes'),('FB02-L10-Q03','O exílio e o retorno completam a história de Israel, preparando a vinda do Messias.','O exílio precede o êxodo e simboliza a libertação do Egito pelo poder de Deus.','Exílio e retorno são narrativas do Novo Testamento sobre a igreja primitiva em Roma.','O retorno marca o fim definitivo do pecado e o início do reino terreno de Cristo.'),('FB02-L11-Q03','Cumprimento das promessas de Deus e centro do plano divino da redenção','Marca o início da criação do mundo e o estabelecimento da lei mosaica','Representa o fim definitivo de todas as profecias sem cumprimento futuro','Introduz um terceiro testamento que substitui completamente os anteriores'),('FB02-L11-Q01','O nascimento, vida, morte e ressurreição de Jesus Cristo','A segunda vinda de Cristo em glória para julgar','A criação dos céus e da terra por Deus em seis dias','O êxodo do Egito e o recebimento da Lei no Sinai'),('FB02-L10-Q05','Exílio demonstra o juízo pelo pecado; retorno revela a fidelidade de Deus ao Seu pacto.','O exílio foi apenas um evento político sem qualquer significado teológico para a redenção.','O retorno do exílio é a redenção final e completa, não havendo necessidade de Cristo.','Exílio e retorno são temas exclusivos do Novo Testamento e não aparecem no Antigo.'),('FB02-L11-Q05','O Messias realiza a redenção ao oferecer salvação do pecado por seu sacrifício.','O Messias estabelece um reino político terreno sem relação com perdão de pecados.','O Messias atua apenas como profeta moral, sem função sacrificial.','O Messias redime exclusivamente Israel, sem extensão aos demais povos.'),('FB02-L11-Q02','A promessa a Abraão, a aliança davídica e as profecias messiânicas','A lei mosaica, o tabernáculo e os sacrifícios levíticos','O dilúvio, a torre de Babel e a dispersão dos povos','O cativeiro babilônico, o império persa e a sinagoga'),('FB02-L11-Q04','A salvação do seu povo de seus pecados','A destruição imediata de todos os inimigos','O estabelecimento do reino terreno glorioso','A prosperidade material do povo escolhido'),('FB02-L12-Q01','No Pentecostes o Espírito Santo desceu e a Igreja nasceu com três mil convertidos.','Moisés recebeu a Lei no Sinai e Israel foi formado como povo de Deus.','Jesus nasceu em Belém, visitado por pastores e magos do Oriente.','Paulo foi convertido em Damasco e tornou-se apóstolo dos gentios.'),('FB02-L12-Q03','A igreja nasce após a ascensão de Cristo e expande-se até o fim dos tempos','Nasceu antes da vinda de Cristo e se limitou ao povo judeu','Iniciou-se no Antigo Testamento e permanece restrita a Israel','Surgiu na eternidade passada e finda-se com a primeira criação'),('FB02-L12-Q04','O derramamento do Espírito Santo no Pentecostes','A destruição do templo de Jerusalém pelos babilônios','A aliança com Moisés mediante a lei no Sinai','A conversão do imperador romano Constantino'),('FB02-L12-Q02','Jesus Cristo, Espírito Santo, apóstolos, Pentecostes e missões paulinas','Moisés, Arca da Aliança, reis de Israel e exílio na Babilônia','Apocalipse, Anticristo, Grande Tribulação e Juízo Final','Fariseus, saduceus, essênios, zelotes e o Sinédrio'),('FB02-L13-Q01','Cristo voltará e haverá novos céus e nova terra','Cristo foi crucificado e ressurgiu ao terceiro dia','O Espírito Santo desceu sobre os apóstolos em Pentecostes','Israel foi exilado e cativo na Babilônia por setenta anos'),('FB02-L13-Q04','A reconciliação de todas as coisas pelo sangue da cruz de Cristo','A imposição da lei mosaica como caminho para a justificação','A instauração de um reino político terreno em Jerusalém','A prosperidade material como recompensa da obediência'),('FB02-L13-Q05','A segunda vinda de Cristo consuma a redenção ao criar novos céus e nova terra','A segunda vinda de Cristo anula a aliança feita com Israel','Os novos céus surgem após o juízo, sem relação com a redenção','Cristo retorna apenas para destruir a criação, sem renová-la'),('FB02-L13-Q03','São a consumação da história da redenção, quando Deus renova a criação.','Acontecem antes da vinda de Cristo, ainda no período veterotestamentário.','São eventos já plenamente realizados desde o Pentecostes na igreja.','Ocorrem durante o exílio babilônico como promessa de restauração.'),('FB03-L01-Q01','Primeira parte da Bíblia, dividida em Pentateuco, Históricos, Poéticos e Proféticos','A segunda parte da Bíblia, dividida em Evangelhos, Atos e Epístolas','Conjunto de textos judaicos escritos após o nascimento de Jesus','Coleção de livros apócrifos excluídos do cânon das Escrituras Sagradas'),('FB03-L01-Q02','Pentateuco, Históricos, Poéticos, Profetas Maiores e Menores','Evangelhos, Atos, Epístolas e Apocalipse','Torá, Neviim, Ketuvim e Apócrifos','Pentateuco, Históricos, Sapienciais e Evangelhos'),('FB03-L01-Q03','Na primeira parte das Escrituras Sagradas, antes do Novo Testamento','No centro das Escrituras Sagradas, entre os dois testamentos','Na última parte das Escrituras, após o Novo Testamento','Apenas nos livros deuterocanônicos, fora do cânon bíblico'),('FB03-L02-Q01','Evangelhos, Atos, Epístolas e Apocalipse','Pentateuco, Históricos, Poéticos e Profetas','Torá, Profetas e Escritos','Lei, História, Poesia e Profecia'),('FB03-L02-Q03','Após o Antigo Testamento, com 27 livros','No Pentateuco, junto aos livros de Moisés','No meio do Antigo Testamento, entre os profetas','Nos Salmos e Provérbios, no centro das Escrituras'),('FB03-L02-Q02','Evangelhos, Atos, Epístolas Paulinas, Epístolas Gerais e Apocalipse','Evangelhos, Atos, Epístolas Paulinas, Sabedoria e Apocalipse','Pentateuco, Históricos, Poéticos, Profetas e Apocalipse','Evangelhos, Atos, Epístolas Pastorais, Hebreus e Apocalipse'),('FB03-L02-Q04','Apresentar o cumprimento da salvação em Cristo, a Igreja e a esperança escatológica','Compilar as leis cerimoniais e os mandamentos do Sinai para os cristãos','Registrar os sermões dos profetas e a cronologia dos reis de Israel','Organizar a história dos patriarcas e o período dos juízes de Israel'),('FB03-L02-Q05','Organiza-se por gênero literário: Evangelhos, Atos, Epístolas e Apocalipse','Organiza-se por ordem cronológica dos fatos narrados','Divide-se pelo cânon hebraico: Lei, Profetas e Escritos','Classifica-se por idioma original: hebraico, aramaico e grego'),('FB03-L03-Q02','Gênesis, Êxodo, Levítico, Números e Deuteronômio','Josué, Juízes, Rute, Esdras e Neemias','Isaías, Jeremias, Ezequiel, Daniel e Oséias','Mateus, Marcos, Lucas, João e Atos'),('FB03-L03-Q03','Nos cinco primeiros livros do Antigo Testamento, chamado de Lei ou Torá','No Novo Testamento, entre os Evangelhos e o livro de Atos','Na segunda divisão do Antigo Testamento, após os livros históricos','Na seção dos livros poéticos e sapienciais, no centro do cânon'),('FB03-L04-Q02','Josué, Juízes, Rute, Samuel, Reis, Crônicas, Esdras, Neemias e Ester','Isaías, Jeremias, Ezequiel e Daniel','Salmos, Provérbios, Eclesiastes e Cantares','Mateus, Marcos, Lucas e João'),('FB03-L03-Q04','Fundamentar a revelação bíblica ao narrar origens, aliança e lei de Israel.','Profetizar exclusivamente o Messias e os últimos dias da humanidade.','Registrar apenas a história dos reis e dos profetas de Israel.','Estabelecer a Nova Aliança entre Deus e a humanidade por Cristo.'),('FB03-L04-Q01','Livros que narram a história de Israel, da conquista de Canaã ao período pós-exílio.','Livros que contêm salmos e cânticos de louvor e adoração a Deus.','Livros que registram as profecias dos profetas maiores e menores.','Livros que apresentam provérbios, poemas e reflexões sapienciais.'),('FB03-L04-Q03','No Antigo Testamento, entre o Pentateuco e os livros poéticos.','No Novo Testamento, antes dos Evangelhos.','No Antigo Testamento, após os livros proféticos.','No Novo Testamento, entre as epístolas e Apocalipse.'),('FB03-L05-Q02','Jó, Salmos, Provérbios, Eclesiastes e Cantares de Salomão','Isaías, Jeremias, Ezequiel, Daniel e Oséias','Josué, Juízes, Rute, Esdras e Neemias','Mateus, Marcos, Lucas, João e Apocalipse')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB03-L04-Q05','Narram a história de Israel em ordem cronológica, com fatos e personagens.','Contêm leis, mandamentos e códigos cerimoniais dados por Deus a Moisés.','Expressam emoções, orações e reflexões poéticas sobre a condição humana.','Contêm previsões, denúncias e exortações proféticas sobre juízo e restauração.'),('FB03-L04-Q04','Narrar a história de Israel, revelando a fidelidade de Deus à aliança.','Profetizar eventos futuros do Messias e do juízo final.','Transmitir preceitos práticos de sabedoria para o cotidiano.','Relatar a vida e os ensinamentos de Jesus Cristo na terra.'),('FB03-L05-Q03','No Antigo Testamento','No Novo Testamento','No cânon deuterocanônico','Entre os livros proféticos'),('FB03-L05-Q04','Ensinar a sabedoria divina e expressar a experiência humana diante de Deus.','Registrar a genealogia das tribos de Israel e estabelecer as leis cerimoniais.','Narrar as guerras de conquista e a expansão territorial do povo de Israel.','Profetizar a vinda do Messias e anunciar os juízos escatológicos finais.'),('FB03-L05-Q05','NAO SEI','Jó, Salmos e Provérbios pertencem à seção dos livros proféticos do AT','Livros poéticos seguem narrativa histórica e precedem os profetas maiores','Gênesis e Êxodo são classificados como literatura sapiencial hebraica'),('FB03-L06-Q01','Os livros proféticos mais extensos do Antigo Testamento: Isaías, Jeremias, Ezequiel e Daniel.','Profetas que receberam a lei diretamente de Deus no Monte Sinai.','Os profetas que realizaram os maiores milagres no Antigo Testamento.','Livros poéticos do Antigo Testamento: Salmos, Provérbios e Eclesiastes.'),('FB03-L06-Q02','Isaías, Jeremias, Lamentações, Ezequiel e Daniel','Oséias, Joel, Amós, Obadias e Jonas','Mateus, Marcos, Lucas, João e Atos','Gênesis, Êxodo, Levítico, Números e Deuteronômio'),('FB03-L06-Q05','Pela extensao dos livros, sendo os maiores aqueles com livros mais longos','Pela importancia teologica superior em relacao aos demais','Pela ordem cronologica em que os livros foram escritos','Pelo maior numero de profecias messianicas apresentadas'),('FB03-L07-Q01','Livros proféticos breves do Antigo Testamento, doze, de Oséias a Malaquias.','Os quatro profetas maiores: Isaías, Jeremias, Ezequiel e Daniel.','Livros históricos do Antigo Testamento que narram a história de Israel.','Livros do Novo Testamento que profetizam sobre o fim dos tempos.'),('FB03-L07-Q03','No Antigo Testamento, após os profetas maiores','No Novo Testamento, antes dos Evangelhos','No início do Antigo Testamento, junto a Gênesis','No Novo Testamento, entre as epístolas paulinas'),('FB03-L07-Q05','São doze livros proféticos de menor extensão, em contraste com os profetas maiores.','São os profetas que escreveram exclusivamente antes do exílio babilônico.','Reúnem escritos de menor autoridade e inspiração que os profetas maiores.','São livros apócrifos incluídos apenas nas versões deuterocanônicas.'),('FB03-L08-Q02','Mateus, Marcos, Lucas e João','Mateus, Marcos, Lucas, João e Tomé','Gênesis, Êxodo, Levítico e Números','Apocalipse, Tiago, Pedro e Judas'),('FB03-L08-Q01','Os quatro primeiros livros do Novo Testamento que narram a vida de Jesus.','Os cinco livros poeticos do Antigo Testamento que exaltam a Deus.','As cartas apostolicas dirigidas as igrejas do primeiro seculo.','Os livros profeticos que anunciam a vinda do Messias.'),('FB03-L08-Q03','No Novo Testamento','No Antigo Testamento','No Pentateuco','Nos livros profeticos'),('FB03-L09-Q01','Quinto livro do Novo Testamento, escrito por Lucas','Primeiro livro do Novo Testamento','Último livro do Novo Testamento','Livro poético do Antigo Testamento'),('FB03-L07-Q04','Transmitir a mensagem divina, conclamar ao arrependimento e anunciar o Messias','Registrar a história política de Israel e Judá durante os reinados reais','Estabelecer as leis cerimoniais, os rituais e as festas do tabernáculo','Compor cânticos litúrgicos, hinos e salmos para o culto no templo de Deus'),('FB03-L08-Q04','Os evangelhos narram a vida, morte e ressurreição de Jesus, centro da fé cristã.','Os evangelhos são cartas que corrigem heresias nas igrejas primitivas.','Os evangelhos registram as visões apocalípticas do fim dos tempos.','Os evangelhos contêm a genealogia dos patriarcas e as bênçãos de Jacó.'),('FB03-L09-Q03','No Novo Testamento','No Antigo Testamento','Nos livros deuterocanonicos','Na Lei de Moisés'),('FB03-L09-Q04','Registrar a expansão da Igreja e a obra do Espírito Santo','Profetizar o fim dos tempos e o juízo final','Narrar a criação do mundo e a queda do homem','Listar as genealogias de Jesus Cristo'),('FB03-L08-Q05','Narrativas da vida, morte e ressurreição de Jesus, com ensinos e milagres.','Cartas às igrejas com doutrinas, exortações e orientações pastorais.','Visões apocalípticas sobre o fim dos tempos e o triunfo divino.','Relatos históricos do povo de Israel, suas leis e alianças com Deus.'),('FB03-L09-Q05','Único livro histórico do NT que narra a expansão da igreja após os evangelhos.','Livro apocalíptico que revela os eventos finais e a segunda vinda de Cristo.','Compilação de cartas escritas por Paulo às igrejas e líderes do cristianismo.','Coletânea dos ensinamentos e parábolas de Jesus durante seu ministério terreno.'),('FB03-L10-Q03','No Novo Testamento','No Antigo Testamento','No Pentateuco','Nos livros profeticos'),('FB03-L10-Q01','São as epístolas escritas pelo apóstolo Paulo, parte do Novo Testamento.','São os quatro evangelhos que narram a vida terrena de Jesus Cristo.','São as epístolas universais escritas por diversos autores apostólicos.','São os livros proféticos do Antigo Testamento que anunciam o Messias.'),('FB03-L11-Q01','Epístolas do NT não escritas por Paulo: Tiago, Pedro, João e Judas.','Primeiros cinco livros do Antigo Testamento, atribuídos a Moisés.','Cartas do NT escritas por Paulo às igrejas e a Timóteo e Tito.','Livros do AT que registram a história da salvação desde Gênesis.'),('FB03-L10-Q04','Fundamentam a fé cristã, estruturam a doutrina da salvação e orientam as igrejas.','Narram a vida de Jesus e seus ensinamentos em ordem cronológica.','Revelam visões apocalípticas sobre o fim dos tempos e a nova criação.','Apresentam a lei mosaica e os rituais do antigo pacto com Israel.'),('FB03-L10-Q05','Pela estrutura epistolar, autoria declarada de Paulo e conteúdo doutrinário','Pelas narrativas cronológicas dos feitos de Jesus Cristo e parábolas evangelicas','Pelo uso de visões apocalípticas, símbolos e linguagem altamente figurada','Pela estrutura poética hebraica, paralelismo e ausência de autoria declarada'),('FB03-L11-Q03','No Novo Testamento, após as epístolas paulinas e antes de Apocalipse','No Antigo Testamento, entre os livros sapienciais e proféticos','No Novo Testamento, antes das epístolas paulinas e dos evangelhos','No Novo Testamento, após o livro de Apocalipse, encerrando as Escrituras'),('FB03-L11-Q04','Exortar a igreja universal, combater heresias e ensinar a vivência cristã prática.','Relatar exclusivamente as viagens missionárias dos apóstolos pelo mundo gentio.','Substituir os Evangelhos como principal registro da vida e ensino de Cristo.','Estabelecer normas exclusivas para o culto sacrificial no templo de Jerusalém.'),('FB03-L11-Q05','Não se dirigem a igrejas ou pessoas específicas, diferindo das paulinas','São escritas pelo apóstolo Paulo com destinatários definidos','Fazem parte dos evangelhos e narram feitos de Jesus','Contêm exclusivamente profecias apocalípticas sobre o fim dos tempos'),('FB03-L11-Q02','Tiago, 1 e 2 Pedro, 1, 2 e 3 João, Judas','Romanos, Coríntios, Gálatas, Efésios, Filipenses','Mateus, Marcos, Lucas, João, Atos dos Apóstolos','Apocalipse, Gênesis, Êxodo, Levítico, Números'),('FB03-L12-Q01','Gênero bíblico de visões simbólicas e profecias sobre o fim dos tempos.','Gênero de cartas pastorais dirigidas às igrejas do primeiro século.','Gênero de narrativas históricas sobre a formação do povo de Israel.','Gênero de poemas líricos que expressam louvor e lamentação.'),('FB03-L12-Q03','Nos livros de Daniel e Apocalipse','Nos livros de Isaías e Jeremias','Nos Evangelhos e no livro de Atos','Nos livros de Gênesis e Êxodo'),('FB03-L13-Q01','Não. A divisão em capítulos e versículos foi acrescentada posteriormente.','Sim. Moisés já organizou os textos com capítulos e versículos originais.','Sim. Os escribas hebreus numeraram os versículos desde o século V a.C.','Sim. Paulo numerou os versículos de suas epístolas ao escrevê-las.'),('FB03-L12-Q05','Presença de visões simbólicas, revelação de mistérios e dualismo cósmico.','Narrativa histórica linear com genealogias extensas e cronológicas precisas.','Provérbios e ensinamentos morais curtos para a vida cotidiana prática.','Cartas doutrinárias com exortações pastorais para comunidades cristãs.'),('FB03-L13-Q02','Para facilitar a referência, o estudo e a localização de passagens específicas.','Porque foram divinamente inspirados junto com o restante do texto bíblico.','Para separar os livros históricos dos livros poéticos do Antigo Testamento.','Porque os profetas e apóstolos os registraram nos manuscritos originais.'),('FB03-L13-Q04','É uma porção numerada do texto bíblico usada como unidade de referência.','É um capítulo completo do texto sagrado dividido por temas centrais.','É uma versão da Bíblia traduzida por antigos missionários cristãos.','É um poema poético presente somente nos livros sapienciais bíblicos.'),('FB03-L13-Q05','NAO SEI','Foram inspirados diretamente pelo Espírito Santo aos escribas sagrados','Servem apenas para fins litúrgicos nas igrejas tradicionais','Substituem a necessidade de leitura devocional e meditação pessoal'),('FB03-L14-Q01','A Lei, os Profetas e os Escritos','Os Evangelhos, as Epístolas e o Apocalipse','Livros históricos, poéticos e proféticos','O Pentateuco, os livros sapienciais e os proféticos'),('FB03-L13-Q07','Analisar o contexto imediato, o livro, o autor e a situação histórica.','Basta ler o versículo isolado e aplicá-lo diretamente à vida do leitor.','Interpretar somente com base no contexto imediato, sem considerar o autor.','Considerar apenas a opinião pessoal e o sentimento do leitor sobre o texto.'),('FB03-L14-Q02','A Lei, os Profetas e os Escritos','Evangelhos, Epístolas e Apocalipse','Pentateuco, Históricos e Poéticos','Livros Canônicos e Deuterocanônicos'),('FB03-L15-Q01','O Novo Testamento está escondido no Antigo, e o Antigo se revela no Novo','O Antigo Testamento é superior e mais importante que o Novo','Os dois testamentos se contradizem e não possuem ligação','O Novo Testamento substitui completamente o Antigo, tornando-o irrelevante'),('FB03-L14-Q03','Na Lei, nos Profetas e nos Escritos','Nos Evangelhos, nas Cartas e no Apocalipse','Em Pentateuco, Históricos e Sapienciais','Em Torá, Salmos e Provérbios'),('FB03-L14-Q04','Agrupar os livros em Lei, Profetas e Escritos, evidenciando a unidade da revelação.','Separar os textos por autor humano, sem qualquer implicação teológica ou canônica.','Organizar as Escrituras unicamente para uso litúrgico semanal nas sinagogas locais.','Dividir os livros por ordem cronológica de composição dos seus respectivos autores.'),('FB03-L15-Q03','Na unidade das Escrituras, que testifica de Cristo em ambos os testamentos','Apenas nas citações diretas do Novo Testamento ao Antigo','Na separação absoluta entre Lei e Evangelho','Exclusivamente na tradição oral da Igreja primitiva'),('FB03-L15-Q02','Promessa, cumprimento, tipologia e unidade das Escrituras','Apenas o Pentateuco e os quatro Evangelhos','Somente as profecias apocalípticas e suas visões','Tanak, Septuaginta e Vulgata em conjunto'),('FB03-L15-Q04','O Antigo prepara e anuncia; o Novo cumpre e revela a plenitude divina.','Os dois testamentos são independentes e não mantêm relação teológica.','O Novo Testamento corrige e substitui completamente o Antigo.','Só o Antigo Testamento possui validade; o Novo não tem autoridade.'),('FB04-L01-Q01','A criação é o fundamento do plano redentor de Deus, base da salvação.','É apenas o cenário material, sem qualquer ligação com a obra redentora.','A criação será completamente aniquilada no fim da história da redenção.','Significa somente a formação do mundo natural, sem propósito espiritual.'),('FB04-L01-Q02','Não é bom que o homem esteja só','Deus descansou no sétimo dia','O homem foi formado do pó da terra','Deus soprou o fôlego da vida no homem'),('FB04-L02-Q01','É a entrada do pecado no mundo pela desobediência de Adão','É a destruição de Sodoma e Gomorra','É a morte de Cristo na cruz','É a expulsão dos israelitas do Egito'),('FB04-L01-Q05','Todas as coisas foram criadas por ele e para ele','Todas as coisas foram feitas apenas para destruição','Jesus participou somente na redenção, não na criação','A criação existiu por acaso antes do Verbo eterno'),('FB04-L01-Q03','Protoevangelho, Aliança Edênica e instituição do sábado','A circuncisão e a aliança mosaica','O êxodo do Egito e a páscoa','A torre de Babel e a confusão das línguas'),('FB04-L02-Q04','Conecta a criação à promessa redentora do protoevangelho em Gn 3.15.','Origina-se antes da criação do homem e encerra a narrativa bíblica.','Decorre do dilúvio e precede a torre de Babel como castigo final.','Resulta da aliança abraâmica e prepara o exílio na Babilônia.'),('FB04-L02-Q03','A promessa do Messias, o descendente da mulher que feriria a serpente','A aliança com Noé, selada pelo arco-íris após o dilúvio','A promessa a Abraão de descendência innumerable como as estrelas','A nova aliança predita por Jeremias, escrita no coração dos fiéis'),('FB04-L03-Q01','A promessa de Deus de redimir o homem do pecado, iniciada em Gn 3:15.','A promessa de Deus de dar a Israel a terra de Canaã como herança eterna.','O pacto de Deus com Moisés para entregar a Lei ao povo de Israel.','A promessa de prosperidade material e bênçãos temporais para os justos.'),('FB04-L03-Q02','A inimizade entre a serpente e a semente da mulher','A expulsão do Éden pelos querubins guardiões','O dilúvio universal como juízo da humanidade','A destruição de Sodoma e Gomorra pelo fogo'),('FB04-L02-Q05','Jesus é o segundo Adão, que reverte a queda pela sua morte e ressurreição','Jesus veio como novo Moisés, para reescrever a lei após a queda de Adão','Jesus ensinou que a queda não aconteceu, sendo apenas uma metáfora poética','Jesus é apenas o exemplo moral máximo, sem relação direta com a queda'),('FB04-L03-Q04','Une a queda no Éden à restauração final em Cristo','Substitui a aliança mosaica pela lei cerimonial','Anula a promessa abraâmica em favor da nova aliança','Inicia o cativeiro babilônico como juízo imediato'),('FB04-L02-Q02','pecado original','chamado de Abraão','sonho de José','sarça ardente'),('FB04-L03-Q03','Alianças com Noé, Abraão, Moisés, Davi e a Nova Aliança em Cristo','Apenas a aliança com Abraão e o retorno de Elias','Somente os eventos do êxodo e a destruição de Jerusalém','Exclusivamente as profecias de Isaías sobre a Babilônia'),('FB04-L03-Q05','Realiza-se na pessoa do Cristo prometido e em Sua obra expiatória na cruz.','Cumpre-se pela observância da lei e pelas obras da humanidade justificada.','Efetiva-se somente na descendência carnal de Abraão, independente de Cristo.','Anula-se com o advento de Cristo, sendo substituída por nova ordem legal.'),('FB04-L04-Q04','Renova a bênção criacional após o dilúvio e precede a aliança com Abraão','Estabelece a lei cerimonial dada a Moisés no Sinai após o êxodo','Promete a Davi um trono permanente em Israel selado por sacerdotes','Anula as alianças anteriores e estabelece apenas a nova aliança cristã'),('FB04-L05-Q01','Deus chamou Abraão para originar a nação da promessa e abençoar todos os povos','Deus chamou Abraão para libertar Israel do Egito e abrir o Mar Vermelho','Abraão foi chamado para construir o templo de Jerusalém e oferecer sacrifícios','Deus chamou Abraão para reinar sobre Israel como seu primeiro rei'),('FB04-L05-Q02','Deus chama Abrão a sair de Ur e ir para a terra prometida','Deus ordena a circuncisão de Abraão e toda sua descendência','Abraão é tentado a sacrificar seu filho Isaque sobre o altar','Sara ri ao ouvir a promessa de dar à luz em sua velhice'),('FB04-L05-Q03','A promessa de terra, descendência numerosa e bênção a todas as nações','A promessa de conquista do Egito e libertação do povo hebreu','O recebimento das tábuas da lei no monte Sinai','A construção do templo de Jerusalém por Salomão'),('FB04-L06-Q01','A formação de Israel significa que Deus constituiu um povo para Si, por meio do qual traria o Messias e a salvação a todas as nações','A formação de Israel significou a unificação política das tribos hebreias sob um governo centralizado','A formação de Israel representou o estabelecimento de um império militar para conquistar nações vizinhas','A formação de Israel foi um movimento cultural sem propósito redentor na história da humanidade'),('FB04-L06-Q02','A escravidão no Egito e a libertação divina no êxodo','A deportação do povo para o cativeiro na Babilônia','A divisão do reino entre Israel e Judá após Salomão','O exílio das tribos do norte provocado pela Assíria'),('FB04-L05-Q05','Jesus Cristo é o descendente de Abraão em quem todas as nações são benditas','Abraão instituiu a lei cerimonial que Cristo apenas observou','Jesus aboliu a aliança abraâmica ao estabelecer a nova criação','A aliança abraâmica foi renovada por Moisés antes da vinda de Cristo'),('FB04-L06-Q03','Chamado de Abraão, aliança abraâmica, êxodo do Egito e aliança mosaica','Batismo de Jesus no rio Jordão e início do ministério apostólico','Captividade babilônica e reconstrução do templo por Herodes','Diáspora romana e destruição do segundo templo sob Tito'),('FB04-L06-Q05','Israel foi preparado por Deus como cenário para a obra redentora de Cristo.','A formação de Israel não possui qualquer relação com a pessoa de Cristo.','Israel foi formado apenas para estabelecer uma nação política sem fins redentores.','A formação de Israel substituiu a necessidade da vinda do Messias prometido.'),('FB04-L07-Q02','As dez pragas enviadas por Deus ao Egito','O maná descido do céu no deserto','A destruição de Sodoma e Gomorra','Os Dez Mandamentos entregues no Sinai'),('FB04-L07-Q03','Promessa abraâmica, pragas do Egito, Páscoa e travessia do Mar Vermelho','Cativeiro babilônico, decreto de Ciro e reconstrução do templo','Conquista de Jericó, período dos juízes e reino de Saul','Batismo de Jesus, Sermão da Montanha e crucifixão'),('FB04-L07-Q05','Cristo é o Cordeiro pascal que liberta do pecado, prefigurado na saída do Egito.','Jesus conduziu pessoalmente os hebreus na saída do Egito.','A libertação do Egito não tem relação tipológica com Cristo.','Cristo apenas repetiu os milagres do êxodo sem valor redentor.'),('FB04-L08-Q01','Deus entregou a lei a Moisés em Sinai, revelando a norma santa ao seu povo.','A aliança incondicional da graça, feita antes da fundação do mundo.','O pacto de Deus com Noé, prometendo nunca mais destruir a terra com águas.','A promessa feita a Abraão de uma descendência innumerable e terra.'),('FB04-L08-Q04','Renova a aliança abraâmica e aponta para a nova aliança em Cristo','Substitui a aliança abraâmica, tornando-a sem efeito permanente','Aplica-se apenas a Moisés e Arão, sem alcance nacional','Invalida a promessa davídica do trono eterno de Israel'),('FB04-L08-Q03','A entrega da Lei, a aliança mosaica e o sacerdócio levítico','A promessa de uma descendência tão numerosa quanto as estrelas do céu','O estabelecimento do reino eterno davídico em Israel','A instituição do arco-íris como sinal da aliança com Noé'),('FB04-L09-Q01','Tipos de Cristo, o sacrifício perfeito e eterno Sumo Sacerdote','São rituais vazios sem qualquer relação com a obra da redenção','Leis cerimoniais já totalmente abolidas sem cumprir propósito algum','Meios de salvação obtidos pela observância ritual do próprio crente'),('FB04-L09-Q02','A expiação do pecado mediante o sangue sacrificial','A purificação ritual por meio de ofertas vegetais','O dominio politico dos sacerdotes sobre as tribus','A celebração festiva das colheitas agricolas'),('FB04-L10-Q01','O povo teocrático mediador das promessas divinas até Cristo.','O reino político terreno de Israel, sem dimensão espiritual.','O Israel carnal, sem relevância no plano redentor de Deus.','A nação israelita que perdeu definitivamente a aliança divina.'),('FB04-L09-Q03','A aliança mosaica institui o sacerdócio levítico e os sacrifícios','A aliança davídica estabelece o trono eterno em Jerusalém','A promessa a Noé garante a preservação pelo arco-íris','A conversão de Paulo marca o início da missão aos gentios'),('FB04-L09-Q05','Cristo é o sacrifício perfeito e o sumo sacerdote eterno.','Os sacrifícios levíticos ainda precisam ser oferecidos continuamente.','Jesus foi apenas sacerdote levítico, sem oferecer sacrifício algum.','Cristo substituiu só o sacerdócio, mantendo-se os sacrifícios antigos.'),('FB04-L10-Q04','Realiza as alianças patriarcais e anuncia o reino messiânico futuro.','Sucedeu o cativeiro babilônico e não possui relação com Abraão.','Foi fundado por Moisés após o êxodo e destruído pelos filisteus.','Período isolado da história, sem conexão com o Novo Testamento.'),('FB04-L10-Q02','Idolatria','Unção de Saul como primeiro rei','Reforma religiosa de Josias','Cativeiro babilônico'),('FB04-L11-Q01','A promessa de Deus a Davi de um descendente eterno no trono, cumprida em Cristo.','A aliança mosaica da lei no Sinai, renovada com Davi.','A promessa de terra a Abraão estendida à dinastia de Davi.','O pacto de Davi com os filisteus para combater Saul.'),('FB04-L10-Q03','A divisão do reino após Salomão e o cativeiro assírio','A aliança davídica e a promessa do trono eterno','O cativeiro babilônico e a queda de Jerusalém','A aliança no Sinai e a entrega da lei a Moisés'),('FB04-L10-Q05','Jesus, descendente de Davi, cumpre as promessas messiânicas do Reino de Israel.','Jesus rejeitou toda ligação com o trono de Davi e com o Reino de Israel.','O Reino de Israel foi extinto sem qualquer cumprimento nas promessas divinas.','Jesus restaurou o Reino de Israel como monarquia política independente dos romanos.'),('FB04-L11-Q02','Deus promete a Davi descendência e trono eternos','Davi faz aliança com os filisteus para combater Saul','O pecado com Bate-Seba é a base da aliança divina','A aliança é rompida após a rebelião de Absalão'),('FB04-L12-Q02','O cativeiro babilônico e a promessa de restauração','O exílio no Egito e a libertação pelo Mar Vermelho','A fuga para o Egito e a estadia da Sagrada Família','A prisão de Paulo em Roma e as cartas às igrejas'),('FB04-L12-Q01','Exílio: juízo divino pelo pecado. Esperança profética: promessa de restauração.','Exílio é aliança política entre povos; esperança profética é vitória militar.','Exílio é castigo eterno e definitivo; esperança profética refere-se só a Israel.','Exílio significa negação da aliança mosaica; esperança profética é cumprimento da lei.'),('FB04-L11-Q05','Jesus, descendente de Davi, cumpre a aliança herdando o trono eterno.','A aliança com Davi foi apenas política, sem qualquer ligação com Cristo.','Jesus cumpriu somente a aliança abraâmica, sem relação com a davídica.','A aliança davídica acabou com Salomão, não possuindo vínculo com Jesus.'),('FB04-L13-Q01','Deus se fez homem em Cristo para realizar a salvação dos pecadores.','A encarnação foi apenas uma aparência humana de Cristo para os ensinamentos.','A encarnação significa que Cristo ressuscitou dentre os mortos para a salvação.','A encarnação foi quando Cristo apareceu como anjo no Antigo Testamento.'),('FB04-L12-Q04','Exílio consuma juízo da aliança; profecia anuncia restauração futura em Cristo','Exílio foi castigo sem relação com as alianças divinas anteriores','Esperança profética se limitou ao retorno imediato do cativeiro babilônico','Exílio e profecia são temas isolados, sem conexão com a redenção'),('FB04-L13-Q02','Deus se fez homem para salvar a humanidade do pecado','A encarnação de Cristo marca sua ressurreição dentre os mortos','A encarnação representa a entrega da lei mosaica','A encarnação foi a ascensão de Jesus ao céu'),('FB04-L13-Q04','Em Cristo se cumprem as promessas messiânicas e se inicia a restauração final.','A encarnação de Cristo ocorreu antes da criação do mundo, sendo anterior à queda.','Após a encarnação, a lei mosaica e os profetas perderam totalmente seu valor.','A encarnação foi apenas um evento isolado, sem conexão com a história anterior.'),('FB04-L12-Q03','A promessa da nova aliança e a restauração do exílio','As pragas do Egito e a libertação pela Páscoa','A aliança com Noé e o arco-íris como sinal','A unificação do reino sob Davi e Salomão'),('FB04-L14-Q02','Redenção do pecado e da morte pela morte e ressurreição de Cristo','A morte de Cristo apenas confirma a lei e os profetas sem novo pacto','A ressurreição é exemplo moral de perseverança humana diante do sofrimento','A morte de Cristo resolve a questão política da ocupação de Israel'),('FB04-L13-Q05','A encarnação une divindade e humanidade em Cristo para realizar a salvação','A encarnação foi apenas aparência, pois Cristo não possuía corpo real','Cristo encarnou somente para ensinar moral, sem necessidade de morrer','A encarnação tornou Cristo apenas um homem comum, sem natureza divina'),('FB04-L17-Q03','O retorno de Cristo, a ressurreição dos mortos e o novo céu e nova terra','A primeira vinda de Cristo e o estabelecimento da lei mosaica','A construção do templo de Salomão e a aliança davídica','O dilúvio universal e a aliança estabelecida com Noé'),('FB04-L14-Q01','Sacrifício pelos pecados e vitória sobre a morte, assegurando a redenção do crente.','Apenas exemplo moral de amor e coragem diante do sofrimento terreno.','Simbolo espiritual sem efeito real, apenas inspirando fé pessoal.','Restauração política de Israel e fim do domínio romano sobre os judeus.'),('FB05-L01-Q02','Criação, Queda, Caim e Abel, Dilúvio, Torre de Babel','Dilúvio, Queda, Criação, Caim e Babel, Torre','Criação, Torre de Babel, Queda, Caim, Dilúvio','Criação, Queda, Abraão, Êxodo, Dilúvio'),('FB05-L01-Q01','Período primevo, da Criação ao chamado de Abraão','Era patriarcal, de Abraão à ida para o Egito','Período mosaico, do Êxodo à conquista de Canaã','Era dos juízes, após a morte de Josué')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB05-L01-Q03','Adão, Eva, Caim, Abel, Sete, Noé, Babel, o Dilúvio','Moisés, Josué, Davi, Salomão, Israel, Judá, Babilônia','Jesus, Pedro, Paulo, Roma, Galiléia, Antioquia, Éfeso','Saul, Davi, Jônatas, Absalão, Israel, Judá, Filístia'),('FB05-L02-Q01','Segundo milênio antes de Cristo','Primeiro milênio antes de Cristo','Terceiro milênio antes de Cristo','Quarto milênio antes de Cristo'),('FB05-L01-Q05','As datas da criação e do dilúvio são aproximadas e debatidas','A criação ocorreu exatamente em 4004 a.C. sem discussões','O dilúvio aconteceu em data precisa e unanimemente aceita','Toda a cronologia de Gênesis é absolutamente certa'),('FB05-L02-Q04','Torre de Babel antes e cativeiro no Egito depois','Diluvio universal antes e o Exodo depois','Criacao do homem antes e exilio babilonico depois','Pecado original antes e queda de Jerusaem depois'),('FB05-L02-Q03','Abraão, Isaque e Jacó','Moisés, Arão e Josué','Saul, Davi e Salomão','Ciro, Dario e Artaxerxes'),('FB05-L03-Q01','Idade do Bronze Tardio, c. 1446 a.C.','Idade do Bronze Médio, c. 2100 a.C.','Período dos Juízes, c. 1200 a.C.','Idade do Ferro, c. 1000 a.C.'),('FB05-L02-Q02','Chamado de Abraão, Ismael, Isaque, Jacó, doze filhos e a ida ao Egito','Moisés, Arão, Josué, Davi e Salomão como patriarcas principais','Adão, Noé, Abraão, Moisés e Josué na ordem dos patriarcas','Dilúvio, torre de Babel, Ismael, Esaú e o exílio babilônico'),('FB05-L03-Q02','Chamada de Moisés, pragas, Páscoa, Mar Vermelho, Lei no Sinai','Lei no Sinai, sarça ardente, Mar Vermelho, Páscoa, pragas','Dilúvio, torre de Babel, pragas, Páscoa, Mar Vermelho','Cativeiro na Babilônia, reconstrução do templo, retorno do exílio'),('FB05-L03-Q04','Antes: cativeiro no Egito e pragas. Depois: travessia do Mar Vermelho e Sinai','Antes: o dilúvio de Noé. Depois: construção do templo de Salomão','Antes: queda das muralhas de Jericó. Depois: exílio na Babilônia','Antes: reinado de Davi em Jerusalém. Depois: destruição do primeiro templo'),('FB05-L03-Q03','Moisés, Arão, Faraó, Israelitas, Egito e Midiã','Abraão, Isaque, Jacó, Simeão, Levi e Harã','Davi, Salomão, Roboão, Babilônia e Nabucodonosor','Elias, Eliseu, Acabe, Jezabel, Israel e Samaria'),('FB05-L03-Q05','1446 a.C., data tradicional derivada de 1 Reis 6:1','1290 a.C., data arqueologica sustentada por evidencias do Egito','1250 a.C., cronologia alternativa proposta por estudiosos','1200 a.C., periodo da estela de Merneptah sobre Israel'),('FB05-L04-Q01','Período da conquista de Canaã, na era de Josué','Período dos Patriarcas, antes do êxodo do Egito','Período dos Reis, durante o reino unido de Israel','Período do exílio babilônico, após a queda de Jerusalém'),('FB05-L04-Q04','Antes: morte de Moisés. Depois: divisão da terra e morte de Josué','Antes: o êxodo do Egito. Depois: o cativeiro na Babilônia','Antes: a queda de Jericó. Depois: o reinado de Davi','Antes: a chamada de Abraão. Depois: a construção do templo'),('FB05-L04-Q05','Conquista de Canaã: ~1406 a.C. (precoce) ou ~1250 a.C. (tardia)','Conquista de Canaã: 1200 a.C. sem debate cronológico','Êxodo: data fixa de 1446 a.C. totalmente consensual','Cronologia da conquista é exata e sem divergências'),('FB05-L05-Q01','Entre a conquista de Canaã e a instauração da monarquia em Israel','Durante o exílio babilônico, após a destruição do primeiro templo','No período patriarcal, entre Abraão e a ida ao Egito','Após a divisão do reino entre Israel e Judá sob Roboão'),('FB05-L05-Q04','Antes: morte de Josué e conquista de Canaã. Depois: unção de Saul como rei por Samuel.','Antes: cativeiro na Babilônia. Depois: exílio dos hebreus no Egito.','Antes: reinado de Davi em Jerusalém. Depois: divisão do reino em Israel e Judá.','Antes: construção do Templo por Salomão. Depois: profecias de Isaías e Jeremias.'),('FB05-L06-Q01','Monarquia Unida, aproximadamente 1050-930 a.C.','Período dos Juízes, aproximadamente 1380-1050 a.C.','Período dos Patriarcas, aproximadamente 2000-1700 a.C.','Período do Cativeiro Babilônico, aproximadamente 586-539 a.C.'),('FB05-L06-Q03','Israel com Saul, Davi e Salomão','Israel com Josué, Sansão e Gideão','Judá com Roboão, Asa e Josafá','Babilônia com Nabucodonosor e Belsazar'),('FB05-L05-Q05','Os 450 anos de Atos 13.20 e os 300 anos de Juizes 11.26 sao discutidos','Os 480 anos de 1 Reis 6.1 fixam com precisao o inicio do periodo','Exatos 600 anos separam a conquista do reinado de Saul','Quatorze juizes governaram em ordem cronologica continua e absoluta'),('FB05-L06-Q04','Antes: período dos Juízes. Depois: divisão do reino em Israel e Judá','Antes: cativeiro babilônico. Depois: período dos Juízes','Antes: êxodo do Egito. Depois: exílio na Babilônia','Antes: período patriarcal. Depois: retorno do exílio'),('FB05-L07-Q01','Período do Reino Dividido, de Jeroboão I à queda de Samaria (722 a.C.)','Período dos Juízes, desde a morte de Josué até a escolha de Saul','Período do Cativeiro Babilônico, de 586 a.C. até a queda da Babilônia','Período do Reino Unido, desde a unção de Saul até a morte de Salomão'),('FB05-L07-Q04','Divisão do reino após Salomão e cativeiro assírio','Unificação monárquica e cativeiro babilônico','Reinado de Davi e destruição do primeiro templo','Governo dos juízes e queda de Jerusalém'),('FB05-L07-Q02','Divisão do reino, idolatria em Betel, profetas Elias e Eliseu, queda de Samaria','Reinado de Davi, construção do templo, queda de Jerusalém','Dilúvio, chamado de Abraão, êxodo do Egito','Cativeiro babilônico, edito de Ciro, reconstrução do templo'),('FB05-L08-Q01','Após a divisão do reino unido, por volta de 930 a 586 a.C.','Antes da divisão do reino unido, entre 1050 e 930 a.C.','Durante o cativeiro babilônico, entre 586 e 539 a.C.','No período dos juízes, entre 1400 e 1050 a.C.'),('FB05-L08-Q03','Reino de Judá, dinastia de Davi e tribo de Judá','Reino de Israel, dinastia de Onri e tribo de Efraim','Império Babilônico, dinastia de Nabucodonosor e caldeus','Reino de Samaria, dinastia de Jeroboão e tribo de Manassés'),('FB05-L08-Q04','Reino Unido de Israel; Cativeiro Babilônico','Período dos Juízes; destruição do Templo','Cativeiro no Egito; exílio na Pérsia','Reino do Norte; retorno do cativeiro'),('FB05-L07-Q05','A cronologia dos reis de Israel diverge entre o Texto Massorético e a Septuaginta','O reino do norte existiu por 300 anos exatos segundo as escrituras','Jeroboão I reinou 40 anos conforme o registro bíblico de seu reinado','A queda de Samaria ocorreu em 586 a.C. junto com a queda de Jerusalém'),('FB05-L09-Q01','Do seculo VIII ao seculo V a.C.','Do seculo X ao seculo VII a.C.','Do seculo VI ao seculo III a.C.','Do seculo XII ao seculo X a.C.'),('FB05-L09-Q03','Reinos de Israel e Judá, Impérios Assírio, Babilônico e Persa','Reinos de Israel e Judá, Impérios Romano e Grego','Reinos de Israel e Judá, Impérios Egípcio e Hitita','Reinos de Israel e Judá, Impérios Assírio e Grego'),('FB05-L09-Q04','NAO SEI','O diluvio e a torre de Babel','A construcao do tabernaculo e o sinai','O cativeiro babilonico e a volta do exilio'),('FB05-L10-Q01','Exílio Babilônico','Cativeiro Assírio','Período dos Patriarcas','Época dos Macabeus'),('FB05-L09-Q05','A data do cativeiro babilônico e os 70 anos profetizados por Jeremias','A cronologia dos profetas é totalmente precisa e consensual entre os estudiosos','Os profetas menores atuaram exclusivamente no período pós-exílico em Judá','Daniel e Ezequiel profetizaram em períodos completamente distintos sem debate'),('FB05-L10-Q05','Os 70 anos de cativeiro previstos por Jeremias','Os 40 anos de peregrinação no deserto','As 70 semanas de anos profetizadas por Daniel','Os 430 anos da permanência no Egito'),('FB05-L11-Q01','Pós-exílio babilônico, retorno sob Zorobabel','Período dos Juízes, antes da monarquia em Israel','Monarquia unificada, no tempo do rei Salomão','Êxodo do Egito, sob a liderança de Moisés'),('FB05-L11-Q04','Queda da Babilônia e reconstrução do templo','Invasão assíria e reconstrução do templo','Reforma de Josias e reconstrução do templo','Destruição do Egito e reconstrução do templo'),('FB05-L12-Q01','Entre o Antigo e o Novo Testamento, cerca de 400 anos','Durante o cativeiro babilônico, sob domínio de Nabucodonosor','Antes do Antigo Testamento, na era dos patriarcas hebreus','Após o Novo Testamento, na era apostólica tardia'),('FB05-L11-Q03','Império Persa, Zorobabel, Josué, Esdras, Neemias, Ageu, Zacarias e Malaquias','Império Babilônico, Nabucodonosor, Joaquim, Daniel, Ezequiel e Sedecias','Império Romano, César Augusto, Herodes, Pilatos, Pôncio e Tibério','Reino de Israel, Saul, Davi, Salomão, Roboão, Jeroboão e Acabe'),('FB05-L11-Q05','O milênio de mil anos mencionado em Apocalipse 20','As setenta semanas proféticas declaradas em Daniel','Os 1.260 dias proféticos conforme Apocalipse 11','Os 2.300 dias evenings and mornings de Daniel 8'),('FB05-L12-Q02','Alexandre, ptolomaicos, selêucidas, macabeus e romanos','Criação, queda, dilúvio e torre de Babel','Reino Unido, divisão do reino, cativeiro e retorno','Batismo, crucificação, ressurreição e ascensão de Cristo'),('FB05-L12-Q04','Antes Malaquias encerrou profecias; depois nasceram João Batista e Jesus','Antes a destruição do templo; depois a conversão de Paulo','Antes o exílio babilônico; depois a Reforma Protestante','Antes o dilúvio universal; depois o arrebatamento da igreja'),('FB05-L13-Q01','Primeiro século da era cristã, sob o domínio romano','No quarto século a.C., durante o cativeiro babilônico','No período dos patriarcas, antes do dilúvio','No século XV a.C., na época do êxodo do Egito'),('FB05-L12-Q03','Os Ptolomeus, os Selêucidas, os Macabeus e os Romanos','Os Babilônios, os Persas, os Medos e os Caldeus','Os Egípcios, os Cananeus, os Filisteus e os Assírios','Os Fariseus, os Saduceus, os Essênios e os Zelotes'),('FB05-L12-Q05','aproximadamente 400 anos entre Malaquias e o nascimento de Cristo','exatos 480 anos entre o êxodo do Egito e a construção do templo','cerca de 1000 anos decorridos entre Adão e o dilúvio universal','período fixo de 70 anos conforme a profecia de Jeremias'),('FB05-L13-Q02','Ressurreição de Cristo ao terceiro dia','Construção da Torre de Babel','Dilúvio nos dias de Noé','Chamada de Abraão na Mesopotâmia'),('FB05-L13-Q05','Nascimento entre 6-4 a.C. e crucificacao em 30 ou 33 d.C.','Nascimento em 1 d.C. e crucificacao no ano 70 d.C.','Batismo aos 12 anos e ministerio com duracao de 10 anos','Nascimento em 10 a.C. e morte com aproximadamente 50 anos'),('FB05-L13-Q04','O ministerio de Joao Batista precedeu e Pentecostes seguiu a vida de Jesus','A lei de Moises foi dada antes e a queda de Jerusalem depois da vida de Jesus','O cativeiro babilonico antecedeu e a destruicao do templo seguiu a vida de Jesus','O profeta Elias ministrou antes e o martirio de Paulo encerrou apos Jesus'),('FB05-L13-Q03','Império Romano','Império Babilônico','Império Persa','Império Grego'),('FB05-L14-Q01','Período da igreja primitiva','Período dos patriarcas','Período intertestamentário','Período monárquico de Israel'),('FB05-L14-Q03','O Imperio Romano, as autoridades judaicas e a igreja primitiva com Paulo e Pedro','O Imperio Babilonio, o povo de Israel e o rei Davi em Jerusalem','O Egito, os filisteus e o rei Saul governando as tribus de Israel','O Imperio Persa, a Babilonia conquistada e o rei Ciro reinando'),('FB05-L15-Q01','Período apostólico, por volta de 47-67 d.C.','Período dos patriarcas, cerca de 2000 a.C.','Cativeiro babilônico, século VI a.C.','Período dos juízes, cerca de 1200 a.C.'),('FB05-L15-Q02','Conversão em Damasco, três viagens missionárias, prisão em Jerusalém, viagem a Roma','Nascimento em Tarso, estudo em Jerusalém, primeira viagem, fuga para Tessalônica','Aparição no templo, duas viagens missionárias, concílio de Roma, morte em Jerusalém','Batismo no Jordão, primeira viagem, segunda viagem, terceira viagem, retorno a Tarso'),('FB05-L15-Q03','Império Romano','Império Babilônico','Império Persa','Império Assírio'),('FB05-L15-Q04','A conversão de Paulo e sua prisão em Jerusalém','A morte de Estêvão e a destruição de Jerusalém','O Pentecostes e a conversão de Cornélio','A ascensão de Jesus e o concílio de Jerusalém'),('FB05-L14-Q04','Antes: a ascensão de Cristo. Depois: o cativeiro de Paulo em Roma','Antes: a crucificação de Cristo. Depois: a destruição de Jerusalém','Antes: a conversão de Paulo. Depois: o martírio de Pedro em Roma','Antes: o nascimento de Jesus. Depois: a grande tribulação'),('FB05-L14-Q05','Conversão de Paulo, aproximadamente 33-36 d.C.','Martírio de Estêvão, datado de 30 d.C. exato','Viagem missionária de Paulo a Roma, cerca de 45 d.C.','Fuga de Pedro da prisão, em 40 d.C. certo'),('FB05-L16-Q01','Período apostólico','Período patriarcal','Época dos juízes','Período intertestamentário'),('FB05-L16-Q03','Império Romano','Império Babilônico','Império Persa','Império Assírio'),('FB05-L16-Q04','Pentecostes, conversão de Paulo, destruição de Jerusalém','Dilúvio, torre de Babel, chamado de Abraão','Natividade, batismo de Cristo, transfiguração','Cativeiro egípcio, travessia do mar, entrega da Lei'),('FB05-L16-Q05','A cronologia das cartas paulinas e debatida, situando-se entre 50-100 d.C.','Todas as cartas do NT foram escritas entre 30-33 d.C. por Jesus.','As cartas do NT foram escritas exclusivamente no seculo II d.C.','A cronologia das cartas do NT e universalmente aceita sem debates.'),('FB05-L17-Q01','Criação, Queda, Israel, Cristo, Igreja e Nova Criação.','Criação, Babel, Moisés, Reis, Cativeiro e Apocalipse.','Dilúvio, Patriarcas, Evangelhos, Igreja e Eternidade.','Gênesis, Êxodo, Levítico, Números e Deuteronômio.'),('FB05-L17-Q03','Os juízes governaram Israel até o povo rejeitar a teocracia e exigir um rei.','A monarquia começou logo após o êxodo, com Moisés como primeiro rei.','Os juízes e os reis governaram simultaneamente em diferentes tribos de Israel.','O período dos juízes terminou quando Davi unificou o reino, não com Saul.'),('FB05-L17-Q04','Monarquia unida, divisão dos reinos, exílio e retorno','Divisão dos reinos, monarquia unida, exílio e retorno','Monarquia unida, exílio, divisão dos reinos e retorno','Monarquia unida, divisão dos reinos, retorno e exílio'),('FB05-L17-Q05','Porta-vozes de Deus que exortavam Israel e Judá ao arrependimento e à fidelidade.','Eram sacerdotes que ofereciam sacrifícios diários no templo de Jerusalém.','Eram reis que governavam Israel e Judá durante os períodos de crise política.','Eram escribas responsáveis por copiar e preservar as leis e os textos sagrados.'),('FB05-L17-Q02','Origens (Gn 1-11), patriarcas (Gn 12-50), êxodo (Êxodo) e conquista (Josué)','Patriarcas e origens são narrados depois do êxodo na narrativa bíblica','Origens em Apocalipse, patriarcas em Atos, êxodo e conquista em Romanos','A conquista da terra prometida ocorreu antes do êxodo no Antigo Testamento'),('FB05-L17-Q06','Entre o Antigo e o Novo Testamento, com duração de cerca de 400 anos','Dentro do Antigo Testamento, imediatamente após o livro de Malaquias','No começo do Novo Testamento, antes do nascimento de Jesus Cristo','Após o livro de Apocalipse, ao final de toda a Bíblia Sagrada'),('FB05-L17-Q07','Nascimento, batismo, tentação, ministério, morte e ressurreição','Nascimento, casamento em Caná, exílio na Pérsia, morte e ascensão','Infância em Nazaré, unção, fuga para o Egito, julgamento e fim','Batismo, apostasia, exílio em Roma, crucificação e desaparecimento'),('FB05-L17-Q08','Atos registra a expansão missionária e as cartas consolidam a fé nas igrejas fundadas','Atos trata apenas do ministerio de Pedro e as cartas registram as viagens','Atos e as cartas são escritos sem relação com a expansão da Igreja','As cartas narram as viagens missionárias e Atos aplica a doutrina às igrejas'),('FB05-L17-Q10','Datas como a criação, o êxodo e o nascimento de Cristo são aproximadas.','Todas as datas bíblicas são exatas e confirmadas por registros históricos.','A Bíblia não apresenta nenhuma data específica em nenhum dos seus livros.','Apenas datas do Novo Testamento são incertas; as do Antigo são precisas.'),('FB06-L01-Q01','No Crescente Fértil, entre o Egito e a Mesopotâmia','Na Europa Setentrional, entre o Mar Báltico e os Alpes','No Extremo Oriente, entre a China e o Japão','Na África Subsaariana, ao sul do deserto do Saara'),('FB06-L01-Q04','Rotas como Via Maris e Caminho do Rei conectavam Egito e Mesopotâmia.','Por rotas exclusivamente marítimas, sem contato terrestre com outros povos.','Apenas por guerras e conquistas militares, sem relações comerciais pacíficas.','Não possuía conexões com outras regiões do mundo antigo.'),('FB06-L02-Q01','Entre os rios Tigre e Eufrates, região do atual Iraque','Entre os rios Nilo e Jordão, no território egípcio','Na península do Sinai, junto ao mar Vermelho','Entre os rios Tigre e Nilo, na antiga Pérsia'),('FB06-L01-Q02','Crescente Fértil entre o Nilo e o Eufrates, com impérios e povos semitas','Planaltos da Ásia Central com impérios mongóis e rotas da seda medievais','Península itálica com civilização romana e império bizantino cristão','Mesoamérica com civilizações maias, astecas e olmecas pré-colombianas'),('FB06-L02-Q05','Porque é o contexto histórico-cultural das origens dos patriarcas de Israel.','Porque a Mesopotâmia é citada literalmente em todos os livros bíblicos.','Porque revela que a Bíblia foi originalmente escrita em acádio.','Porque torna desnecessário o estudo do hebraico e do grego bíblicos.'),('FB06-L03-Q01','Localizava-se no nordeste da África, na região do rio Nilo','Localizava-se no sudoeste da Ásia, próximo à Mesopotâmia','Situava-se na região da Anatólia, atual Turquia','Encontrava-se na Europa ocidental, junto ao mar Mediterrâneo norte'),('FB06-L02-Q04','Através de rotas comerciais, migrações e alianças com Egito, Canaã e Pérsia','Mesopotâmia manteve-se totalmente isolada dos povos vizinhos','Apenas por navegação marítima com Grécia e Fenícia','Exclusivamente por rotas terrestres com o Egito Antigo'),('FB06-L02-Q03','Torre de Babel, Abraão originário de Ur dos caldeus, exílio na Babilônia','Êxodo no Egito, Moisés e as pragas contra o faraó','Jesus pregando em Nazaré e na Galileia','José vendido no Egito e o cativeiro no Egito'),('FB06-L03-Q05','Porque muitas passagens foram escritas em contexto egipcio ou descrevem eventos la ocorridos','Porque o hebraico derivaria diretamente da lingua egipcia antiga','Porque o cativeio babilonico substituiu a cultura mosaica original','Porque os fariseus teriam surgido no antigo Egito'),('FB06-L04-Q01','Na região do Levante, entre o rio Jordão e o mar Mediterrâneo','Na região do Egito, entre o rio Nilo e o mar Vermelho','Na Mesopotâmia, entre os rios Tigre e Eufrates','Na Pérsia, a leste do deserto e junto ao mar Cáspio'),('FB06-L03-Q03','José, Moisés, Faraó, Êxodo, pragas do Egito, rio Nilo','Davi, Golias, Saul, Babilônia e exílio na Pérsia','Noé, arca, dilúvio, Ararate e montanhas da Armênia','Jericó, Josué, Canaã, Ai e conquistadores hebreus'),('FB06-L03-Q02','NAO SEI','Rio Nilo e deserto do Sinai','Faraós e sistema de escravidão','Refúgio da Sagrada Família'),('FB06-L04-Q04','Canaã era ponte entre Egito e Mesopotâmia, em rotas comerciais antigas.','Canaã era uma potência naval que dominava todo o Mediterrâneo.','Canaã se localizava ao sul do Egito, na região da Núbia.','Canaã era um império isolado, sem contatos com outras civilizações.'),('FB06-L04-Q05','Conhecer Canaã esclarece o contexto geográfico, histórico e cultural dos textos bíblicos.','Canaã é citada apenas nas profecias escatológicas sobre o fim dos tempos.','O estudo de Canaã comprova a substituição da Igreja pelo povo judeu moderno.','Canaã aparece somente nos Salmos como metáfora de alegria e prosperidade.'),('FB06-L04-Q02','Canaã: região entre o Jordão e o Mediterrâneo, com várias cidades-estado pagãs.','Canaã era um grande império unificado governado por um único rei poderoso.','Canaã ficava na região desértica do norte da África, sem cidades importantes.','Canaã era habitada apenas por hebreus organizados em doze tribos unificadas.'),('FB06-L05-Q01','No Oriente Médio, entre o Egito e a Mesopotâmia, junto ao Mediterrâneo.','Na Ásia central, próxima às montanhas do Himalaia e do Tibete.','No norte da África, próxima ao deserto do Saara e ao Egito antigo.','Na Europa ocidental, junto ao mar Mediterrâneo e à Península Ibérica.'),('FB06-L04-Q03','Terra prometida a Abraão, conquistada por Josué, habitada pelos cananeus','Egito, Moisés, cativeiro e travessia do Mar Vermelho','Babilônia, Daniel, interpretação de sonhos e cativeiro','Egito, José, interpretação dos sonhos do faraó'),('FB06-L05-Q02','Terra que mana leite e mel, promessa divina a Abraão e sua descendência','Região desértica e estéril, sem qualquer valor agrícola ou simbólico','Pátria dos grandes impérios egípcios e mesopotâmicos da antigüidade','Território exclusivamente habitado por povos pagãos sem aliança divina'),('FB06-L05-Q04','Rota comercial entre Egito e Mesopotâmia, sob impérios como Assíria e Babilônia.','Era um grande império que conquistou Egito, Pérsia e Grécia antigas.','Localizava-se no extremo oriente, totalmente isolada das rotas comerciais.','Era região sem contato algum com povos vizinhos, segundo o relato bíblico.'),('FB06-L12-Q01','Via Maris, Caminho do Mar, ligava Egito à Mesopotâmia pela costa mediterrânea','Rota das Especiarias, caminho exclusivo entre Jerusalém e a Pérsia antiga','Via Real Persa, ligava diretamente Susa ao Egito através do deserto do Sinai','Caminho de Damasco a Roma, atravessando o centro do deserto da Arábia'),('FB06-L14-Q04','Conquistou Judá, dominou rotas mesopotâmicas e rivalizou com Egito e Pérsia','Manteve completo isolamento diplomático com todos os povos vizinhos','Funcionou exclusivamente como vassalo do Egito durante todo o império','Bloqueou todas as rotas comerciais impedindo qualquer comércio regional'),('FB06-L14-Q05','Revela o contexto historico do exilio, profecias e costumes da epoca biblica.','Porque os babilonios teriam escrito o Novo Testamento em sua lingua.','Permite identificar erros historicos nos relatos do Antigo Testamento.','Mostra que a Biblia foi traduzida pela primeira vez na Babilonia.'),('FB06-L15-Q01','A leste de Israel, abrangendo a Mesopotâmia e a Pérsia (atual Irã)','Ao sul de Israel, abrangendo o Egito, a Núbia e a Etiópia antiga','Ao norte de Israel, abrangendo a Síria, Assíria e a Ásia Menor','A oeste de Israel, abrangendo Chipre, Creta e as ilhas gregas'),('FB06-L15-Q02','Tolerancia religiosa, organizacao em satrapias e decretos imperiais registrados.','Exilio forcado, destruicao do templo e uso do acadio como lingua oficial.','Deportacao em massa, politica de assimilacao forcada e lingua oficial o aramaico.','Dominio militar expansionista, lingua grega oficial e cultura helenistica imposta.'),('FB06-L15-Q05','Esclarece o contexto histórico de Esdras, Neemias, Ester e Daniel.','Porque revela os erros geográficos dos autores bíblicos.','Porque mostra que os hebreus inventaram as leis persas.','Porque comprova que a Bíblia foi escrita em persa antigo.'),('FB06-L16-Q01','Na Macedônia, Acaia, Ásia Menor e regiões mediterrâneas','Apenas na Judeia e Samaria, durante o período macabeu','Somente no Egito, sob o domínio exclusivo dos Ptolomeus','Exclusivamente na Babilônia, após o exílio judaico'),('FB06-L16-Q02','Geografia montanhosa, polis gregas, expansao mediterranica e helenizacao cultural','Deserto do Sahara, tribos nomades, comercio transahariano e islamizacao','Florestas tropicais, cacicados, agricultura de subsistencia e pajelanca','Estepes asiaticas, hordes mongois, rotas da seda e xamanismo'),('FB06-L17-Q01','Em todo o mundo mediterrâneo, com capital em Roma','Apenas na região da Itália','Somente na Ásia Menor','Exclusivamente no Egito'),('FB06-L17-Q02','NAO SEI','A expansao territorial atraves de conquistas militares garantiu dominio sobre todo o Mediterraneo','A organizacao politica em republica depois imperio centralizou poder no imperador','A cultura romana incorporou elementos gregos e conquistou povos por assimilacao'),('FB06-L17-Q05','Revela o contexto histórico, político e cultural em que a Bíblia foi escrita','Porque os textos bíblicos foram originalmente escritos em latim pelos romanos','Porque Jesus exerceu cargo político de liderança no Império Romano','Porque a Bíblia só pode ser corretamente compreendida por estudiosos da Roma Antiga'),('FB06-L18-Q01','Leste do Mediterrâneo, no Império Romano','Deserto da Arábia e Monte Sinai','Mesopotâmia e Império Persa antigo','Celtas, Germânia e Ibéria antiga'),('FB06-L18-Q04','Utilizavam as vias romanas e rotas marítimas mediterrâneas sob o Império Romano','Seguiam exclusivamente as rotas do Império Persa e Selêucida','Limitavam-se à Judeia e ignoravam as redes romanas e marítimas','Dependiam unicamente das caravanas da Rota da Seda chinesa')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB06-L19-Q01','Na Ásia Menor, província romana da Ásia (atual Turquia)','No Egito, às margens do Rio Nilo','Na Palestina, na região da antiga Israel','Na Grécia, em cidades como Atenas e Corinto'),('FB06-L18-Q03','Barnabé','Moisés','Elias','Sansão'),('FB06-L18-Q02','Pax Romana, vias romanas e língua grega facilitaram as viagens de Paulo','Pauloviajou exclusivamente por caravanas pelo deserto da Arábia','A perseguição romana e o uso do latim impediram as viagens de Paulo','As viagens missionárias de Paulo se limitaram à região da Galileia e Judeia'),('FB06-L19-Q03','Efeso, Esmirna, Pérgamo, Tiatira, Sardes, Filadélfia e Laodiceia','Corinto, Tessalônica, Bereia, Filipos, Colossos, Antioquia e Roma','Jerusalém, Betel, Hebrom, Siquém, Nazaré, Cafarnaum e Jericó','Babilônia, Nínive, Damasco, Sidom, Tiro, Samaria e Gaza'),('FB06-L19-Q02','Eram cidades da Ásia Menor sob domínio romano, com influências gregas e judaicas.','Eram tribos de Israel dispersas pelo deserto após o cativeiro babilônico.','Eram províncias do Império Persa localizadas na Mesopotâmia antiga.','Eram aldeias judaicas na Galileia durante o período intertestamentário.'),('FB06-L18-Q05','Permite compreender o contexto das comunidades receptoras das cartas paulinas.','Porque demonstra que Lucas escreveu Atos dos Apóstolos como narrativa estritamente histórica.','Porque revela que todas as cartas de Paulo foram escritas antes de suas viagens missionárias.','Porque prova que Paulo fundou pessoalmente todas as igrejas mencionadas no Novo Testamento.'),('FB07-L01-Q02','O levirato obrigava o cunhado a desposar a viúva sem filhos','A circuncisão era realizada no trigésimo dia após o parto','Os pais escolhiam as esposas dos filhos sem qualquer consulta','As mulheres recebiam herança igual à dos homens na Bíblia'),('FB07-L01-Q03','NAO SEI','Estrutura patriarcal autoritaria','Papel central da mulher no lar','Familia nuclear sem escravidao'),('FB07-L02-Q01','Pai arranjava, noivo pagava o preço, noivado era vínculo legal antes da festa','A noiva escolhia livremente o marido, sem qualquer participação do pai','Era como no Ocidente moderno, com namoro prolongado antes do sim','Não havia noivado, o casamento era direto sem qualquer rito prévio'),('FB07-L02-Q02','O noivo pagava um dote à família da noiva e havia período de noivado vinculante.','As noivas escolhiam livremente seus maridos sem qualquer aprovação paterna.','O casamento era proibido entre membros pertencentes à mesma tribo.','Não existiam cerimônias públicas de casamento nos tempos bíblicos.'),('FB07-L03-Q02','Circuncisão no oitavo dia','Batismo nos primeiros sete dias','Purificação da mãe aos 90 dias','Apresentação no templo após um ano'),('FB07-L02-Q05','Confundir noivas com esposas, alterando leis sobre adultério e direitos','Confundir sacramentos com alianças, invalidando doutrinas eclesiásticas','Ignorar costumes de poligamia, distorcendo narrativas sobre patriarcas','Desconsiderar rituais de casamento, perdendo simbolismos proféticos'),('FB07-L03-Q04','Mateus 1-2 e Lucas 1-2, as narrativas da infancia de Jesus','Genesis 1-2, a criacao do homem e da mulher','Apocalipse 12, a visao da mulher e do dragao','Joao 1:1-18, o Verbo se fez carne e habitou entre nos'),('FB07-L03-Q01','...','...','...','...'),('FB07-L04-Q01','Era domiciliar: pais ensinavam aos filhos a Lei de Deus e um oficio pratico.','Era em escolas publicas obrigatorias com ensino formal a partir dos sete anos.','Criancas frequentavam universidades chamadas Betsil, estudando grego e filosofia.','Meninos e meninas estudavam juntos em academias militares desde a infancia.'),('FB07-L04-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB07-L04-Q05','Interpretar a vara como punição cruel e não como correção formativa','Achar que Provérbios apoia a violência contra menores','Concluir que a criança desobediente deve ser excluída da família','Entender que a educação cristã é opcional para os pais'),('FB07-L05-Q03','Trabalho antigo era hereditário; hoje há mobilidade e formação acadêmica','No mundo antigo todos escolhiam livremente sua profissão desde jovens','Hoje as profissões são definidas exclusivamente pelo nascimento familiar','O trabalho no mundo antigo era exatamente igual ao contexto atual'),('FB07-L05-Q01','Baseava-se em agricultura, artesanato, comércio e pesca, com mão de obra servil.','Baseava-se em indústrias mecanizadas e corporações de ofício da Europa medieval.','Baseava-se exclusivamente em servidão obrigatória imposta a todos os estrangeiros.','Baseava-se em profissões exclusivamente hereditárias sem qualquer mobilidade social.'),('FB07-L04-Q02','Ensinar a lei de Deus e corrigir com a vara desde a infância','Circuncidar os meninos no oitavo dia como sinal da aliança','Apresentar os primogênitos ao sacerdote para sua redenção','Celebrar a Páscoa em família com cordeiro sem fermento'),('FB07-L05-Q02','O trabalho é digno e obrigatório; o preguiçoso não deve comer','Apenas os levitas podiam exercer qualquer ofício profissional','O trabalho era visto como pura maldição sem propósito algum','As profissões eram herdadas exclusivamente por linhagem paterna'),('FB07-L06-Q01','Cultivo de trigo, cevada, videiras e oliveiras; criação de ovelhas, cabras e bois.','Usavam arados de ferro e sistemas de irrigação em todo o território israelita.','A criação de porcos era a atividade pecuária principal no antigo Israel.','Dependia exclusivamente de poços artesianos e canais de irrigação persas.'),('FB07-L07-Q03','Refeições antigas eram comunitárias e rituais; atuais são individuais e práticas.','No antigo se comia apenas maná; hoje se come pão.','Antigamente não existiam cozinhas; hoje existem.','No mundo antigo se jejuava sempre; hoje nunca.'),('FB07-L07-Q04','A Última Ceia, a multiplicação dos pães e as bodas de Caná','A travessia do Mar Vermelho, o Sinai e a queda de Jericó','A arca de Noé, a torre de Babel e o cativeiro babilônico','O batismo de Jesus, a tentação no deserto e a crucificação'),('FB07-L07-Q05','Legalismo, perda do simbolismo e incompreensao do evangelho','Erros genealogicos e cronologicos nas narrativas patriarcais','Problemas de pronunciacao dos termos hebraicos originais','Confusao entre autoria mosaica e deuteronomica do Pentateuco'),('FB07-L07-Q02','Leis alimentares, jejum ritual, páscoa e partilha do pão','Proibição de consumir carne com leite e restrição total de sal','Culto aos anjos durante as refeições e uso obrigatório de incenso','Recusa absoluta de qualquer bebida alcoólica em todas as refeições'),('FB07-L08-Q03','Na Bíblia, roupas tinham significado simbólico; hoje são mera expressão de moda.','Não há nenhuma diferença; roupas antigas e modernas têm o mesmo significado.','Na antiguidade ninguém usava roupas; as pessoas andavam sempre completamente nuas.','Hoje todas as roupas são fabricadas de lã e linho, exatamente como na Bíblia.'),('FB07-L08-Q01','Túnica interna, manto externo, sandálias e turbante; tecidos de lã e linho.','Todos usavam exclusivamente seda chinesa, sem qualquer distinção social.','As roupas eram idênticas às egípcias, com uso obrigatório de perucas longas.','Os hebreus vestiam apenas peles de animais, como no Éden antes da queda.'),('FB07-L08-Q04','A veste nupcial na parábola do banquete em Mateus 22','A túnica colorida de José indica riqueza material','A veste de linho de Cristo prova sua origem pobre','As vestes de Adão no Éden eram feitas de seda'),('FB07-L08-Q02','Não usar vestes feitas com mistura de linho e lã','Os sacerdotes vestiam apenas túnicas feitas de ouro puro','Rasgar as vestes era proibido mesmo em sinal de luto','Era obrigatório pintar as bordas das roupas com sangue'),('FB07-L09-Q02','cidades de refúgio para homicidas involuntários','oferendas de incenso nos cantos dos muros','círculos de sal ao redor dos alicerces','imagens de querubins esculpidas nas ombreiras'),('FB07-L08-Q05','Aplicar simbolos culturais do vestuario como doutrinas universais','Negar a continuidade entre os escritos profeticos','Rejeitar a interpretacao literal dos textos narrativos','Comprometer a autoridade apostolica nas epistolas'),('FB07-L09-Q01','Casas de pedra e barro, telhados planos; cidades muradas com portões.','Casas de madeira com telhados inclinados; cidades sem muralhas.','Estruturas de concreto com múltiplos andares; cidades sem portões.','Casas totalmente subterrâneas; cidades em planícies sem defesa.'),('FB07-L10-Q01','Acolhimento de viajantes com alimento, água, pousada e lavagem dos pés','Hospedava-se somente parentes próximos mediante pagamento em prata','Recusava-se estrangeiros para preservar a santidade da tribo','A hospitalidade acontecia exclusivamente em locais sagrados com sacrifícios'),('FB07-L09-Q04','Mateus 7:24-27, Josué 2, Atos 10 e Apocalipse 21','Gênesis 1, Êxodo 20, Salmos 23 e Apocalipse 22','Isaías 53, Jeremias 29, Ezequiel 37 e Malaquias 4','Romanos 8, 1 Coríntios 13, Efésios 2 e Tiago 2'),('FB07-L09-Q03','Antigamente casas de barro e cidades muradas; hoje materiais modernos e cidades vastas sem muralhas.','Antigamente casas de concreto armado e cidades sem muralhas; o oposto do real.','Nao ha diferencas relevantes entre casas e cidades antigas e atuais.','Antigamente as cidades eram maiores que as atuais e as casas mais altas.'),('FB07-L11-Q01','Usava-se escambo, pesos de metais preciosos e moedas como siclo e denário','O comércio baseava-se apenas em sistema bancário com juros compostos','Usava-se exclusivamente ouro em barras como única moeda no período bíblico','Não existia moeda alguma, somente troca direta de bens em toda a Bíblia'),('FB07-L10-Q02','Lavar os pés, ungir com óleo, oferecer pão e acolher os forasteiros','Sacrificar cordeiros no altar do templo e queimar incenso sagrado','Circuncidar todos os visitantes e guardar o sábado rigorosamente','Jejuar quarenta dias seguidos e vigiar noites em oração constante'),('FB07-L10-Q04','Gn 18; Gn 19; Hb 13:2; 1Pe 4:9; Rm 12:13','Mc 16:15; At 1:8; Mt 28:19-20','Jo 3:16; Rm 3:23; Ef 2:8-9','Sl 23:1-4; 1Co 15:55; Ap 21:4'),('FB07-L11-Q03','Antigo usava metais preciosos e escambo; atual usa dinheiro fiduciário e digital','Antigo e atual são idênticos, apenas com nomes diferentes para as moedas','No mundo antigo não existia comércio, apenas doações religiosas entre templos','Atualmente as moedas são feitas de ouro puro como no passado bíblico'),('FB07-L11-Q05','NAO SEI','Confundir o talento bíblico com unidade monetária atual','Interpretar o denário romano como sinônimo de salário moderno','Equiparar o siclo do Antigo Testamento ao real brasileiro'),('FB07-L12-Q03','Na Biblia a servidao era regulada e temporaria; hoje e crime contra a humanidade.','A Biblia permitia apenas servidao voluntaria entre os povos antigos','No mundo antigo a escravidao era sempre perpetua para todos os povos','Hoje nao existe escravidao em nenhuma forma no mundo contemporaneo'),('FB07-L12-Q05','Anacronismo ao projetar a escravidão moderna sobre os textos bíblicos','Concluir que a Bíblia aprova definitivamente a escravidão como instituição','Achar que o Novo Testamento aboliu imediatamente toda forma de servidão','Ignorar que as leis mosaicas legitimavam a escravidão sem qualquer limite'),('FB07-L13-Q01','As leis eram dadas por Deus a Moisés e aplicadas por juízes e anciãos','As leis eram criadas anualmente pelos reis em assembleias públicas','Cada tribo julgava seus próprios crimes sem autoridade central','Apenas os profetas tinham poder para julgar todas as questões'),('FB07-L13-Q04','Sermão do Monte, Romanos 7, Gálatas e Hebreus','O livro do Apocalipse e as cartas às sete igrejas','Atos dos Apóstolos e as cartas pastorais','Os Salmos, Provérbios e o Cântico dos Cânticos'),('FB07-L13-Q03','No mundo antigo, leis vinham de Deus ao povo; hoje, de autoridades humanas sem base teocrática.','No mundo antigo não existiam leis escritas; hoje todas procedem diretamente de Deus.','Leis antigas e modernas são idênticas em essência, origem e aplicação prática.','Somente no contexto atual existem julgamentos; no passado antigo não havia.'),('FB07-L14-Q01','Ungido com especiarias, envolvido em linho e sepultado em cavernas ou tumbas','Cremacao era pratica comum, com cinzas guardadas em jarros','Corpo permanecia na casa por sete dias antes do sepultamento','Enterro acontecia sempre em cemiterios publicos ao redor das cidades'),('FB07-L13-Q02','Juízes e oficiais eram estabelecidos nas cidades para julgar com justiça','Sacerdotes ofereciam sacrifícios diários pelo pecado do povo','O povo peregrinava três vezes ao ano ao templo de Jerusalém','Os levitas cantavam salmos durante as assembleias sagradas'),('FB07-L14-Q03','NAO SEI','Antigamente só havia cremação; hoje só sepultamento','Funerais antigos duravam sete dias; hoje duram uma hora','No mundo antigo não havia caixões; hoje não há túmulos'),('FB07-L15-Q01','Incluíam peregrinações a Jerusalém, sacrifícios e memorial de eventos históricos.','Realizavam-se apenas nas sinagogas locais em reuniões semanais privadas.','Consistiam exclusivamente em jejum e oração sem sacrifícios no Templo.','Aconteciam somente na colheita agrícola sem qualquer significado histórico.'),('FB07-L15-Q03','Antigo: sacrifícios no Templo. Hoje: oração na sinagoga e rituais familiares.','Diferem apenas na língua usada nos rituais','Hoje as festas perderam todo significado religioso','No antigo as festas duravam exatamente o dobro do tempo'),('FB07-L14-Q05','Anacronismo nas práticas e costumes fúnebres bíblicas','Erro na aplicação das leis alimentares levíticas','Confusão entre profecias messiânicas e textos apócrifos','Interpretação literal indevida das genealogias patriarcais'),('FB07-L15-Q02','Ofertas, sacrifícios, pão ázimo e descanso nos dias santos','Adoração a ídolos e sacrifícios humanos nos altares pagãos','Batismo nas águas e participação na ceia do Senhor','Trabalho contínuo no sábado e colheita durante as festas'),('FB07-L15-Q04','Páscoa, Pentecostes e Tabernáculos elucidam Êxodo 12, Atos 2 e João 7.','O jejum de Ezequiel esclarece todas as parábolas do Novo Testamento.','A circuncisão e o sábado são as festas centrais para entender Apocalipse.','A Festa de Purim revela a cronologia das epístolas paulinas.'),('FB07-L16-Q04','Levítico 11-15 e Marcos 7, sobre o puro e o impuro','Gênesis 1 e os seis dias da criação','Apocalipse 21 e a nova Jerusalém','Salmos 23 e o Senhor como meu pastor'),('FB07-L16-Q03','Antes era ritual e cerimonial externa; agora é pureza interior do coração','Sempre foi apenas sobre lavar as mãos e manter higiene física corporal','Hoje não há pureza alguma exigida pois Cristo aboliu toda a lei de Deus','A pureza atual exige guardar todos os rituais levíticos como no antigo'),('FB07-L17-Q01','Locais de oração, leitura das Escrituras e ensino da Torá, com reuniões sabáticas.','Sacrifícios de animais eram oferecidos diariamente por sacerdotes levitas.','Eram construídas exclusivamente dentro do Templo de Jerusalém.','Apenas o sumo sacerdote podia entrar e ministrar nas reuniões.'),('FB07-L18-Q01','O templo era centro do culto com sacrifícios, sacerdotes e festas religiosas.','O templo funcionava apenas como mercado de animais sem sacrifícios.','Somente estrangeiros podiam entrar no templo para culto.','O culto era realizado exclusivamente por profetas sem sacerdotes.'),('FB07-L17-Q05','Anacronismo, perda do Sitz im Leben judaico e leituras anti-semitas','Ignorar o contexto do Templo leva a erros sobre o culto levitico','Desconsiderar o helenismo provoca leituras erradas do mundo antigo','Ignorar o contexto romano causa erros sobre o Imperio e a lei civil'),('FB07-L18-Q02','Sacrifícios, ofertas, festas religiosas, leis de pureza e dízimos','Poligamia, leis de herança e casamentos arranjados','Agricultura, pecuária e técnicas de irrigação','Batalhas militares, estratégia de guerra e alianças políticas'),('FB07-L17-Q02','Leitura das Escrituras, ensino, oração, castigos e excomunhão','Sacrifícios de holocausto, incenso, lava dos pés e batismo','Circuncisão, purificação ritual, lava dos pés e páscoa','Ceia do Senhor, batismo, lava dos pés e imposição de mãos'),('FB07-L18-Q04','Hebreus e Apocalipse, que dependem do simbolismo do templo','Os quatro Evangelhos e Atos','Gênesis e os livros históricos','As Epístolas de Paulo em geral'),('FB07-L19-Q02','NAO SEI','A circuncisão era um costume exclusivamente judaico sem paralelo greco-romano','As leis alimentares de Levítico foram adotadas diretamente dos gregos','O sábado era uma prática compartilhada com os templos romanos'),('FB07-L18-Q05','Anacronismo, alegorização indevida e perda do sentido sacrificial e litúrgico.','Confundir o tabernáculo do deserto com o templo de Salomão.','Identificar o Santo dos Santos com o pátio dos gentios.','Interpretar as ofertas levíticas como meras transações comerciais.'),('FB07-L19-Q03','Escravidão, poligamia e oráculos divinos eram aceitos; hoje são abolidos e ilegais.','Os costumes greco-romanos são exatamente iguais aos atuais em todos os aspectos.','Na Grécia e Roma antigas não existiam costumes próprios, apenas seguiam leis modernas.','Atualmente a escravidão e a poligamia são práticas obrigatórias em todo o mundo.'),('FB07-L19-Q05','Anacronismos na compreensão de ekklesia, honra-vergonha e relações patrono-cliente','Ignorar o contexto hebraico ao interpretar passagens do Antigo Testamento','Misturar costumes medievais europeus com práticas do primeiro século','Confundir gêneros literários proféticos com apocalípticos'),('FB07-L19-Q01','Pax Romana e helenização trouxeram língua grega, leis, estradas e sincretismo','Eram baseados exclusivamente nas leis mosaicas e tradições farisaicas','Impunham apenas o politeísmo egípcio, rejeitando qualquer influência grega','Proibiam totalmente o uso do grego e do latim nas províncias orientais'),('FB08-L01-Q03','NAO SEI','Confirmação da historicidade dos reis de Israel e Judá','Descoberta dos Manuscritos do Mar Morto em 1947','Inscrições que mencionam o rei Davi e a Casa de Davi'),('FB08-L01-Q02','Oriente Próximo antigo, do período patriarcal ao período romano','Europa medieval cristã, do século V ao século XV','Mesoamérica pré-colombiana, período maia e asteca','Extremo Oriente, durante as dinastias Han e Tang'),('FB08-L01-Q01','Estudo dos vestígios materiais relacionados ao contexto bíblico','Análise teológica dos textos sagrados do Antigo Testamento','Estudo linguístico das línguas originais da Bíblia','Pesquisa histórica sobre os ensinamentos de Jesus Cristo'),('FB08-L01-Q04','Estuda evidências materiais relacionadas a personagens, locais e eventos bíblicos','Ignora os textos bíblicos, baseando-se apenas em artefatos isolados','Confirma integralmente todos os relatos bíblicos sem questionamento','Limita-se a estudos do Antigo Testamento, excluindo o Novo'),('FB07-L19-Q04','Os relatos de Paulo em Atos e a Ceia em 1 Coríntios 11','Os rituais do tabernáculo em Êxodo e Levítico','As narrativas babilônicas em Daniel e Esdras','Os patriarcas em Gênesis e o cativeiro egípcio'),('FB08-L02-Q03','NAO SEI','A arqueologia confirma toda a narrativa biblica sem excecoes','Os limites da arqueologia nao oferecem nenhuma informacao historica','A Biblia contem todas as datas e locais arqueologicos precisos'),('FB08-L02-Q02','NAO SEI','Período patriarcal, Mesopotâmia, cerca de 2000 a.C.','Período intertestamentário, Palestina, século II a.C.','Período dos reis de Israel, Canaã, século X a.C.'),('FB08-L02-Q01','Estuda somente os vestígios materiais, sem acesso ao espiritual','Comprova literalmente todos os milagres descritos na Bíblia','Substitui o testemunho das Escrituras como fonte histórica','Revela diretamente o plano divino por trás dos eventos bíblicos'),('FB08-L02-Q05','Limita-se ao material e tangível; não comprova milagres nem intenções espirituais','A arqueologia confirma historicamente todos os relatos e milagres bíblicos','É a fonte primária e suficiente para validar toda a narrativa bíblica','Limita-se exclusivamente ao Antigo Testamento, sem aplicação ao Novo'),('FB08-L03-Q02','NAO SEI','Periodo patriarcal, em Canaa','Epoca do cativeiro na Babilonia','Periodo dos reis de Israel'),('FB08-L02-Q04','A arqueologia confirma contextos, não verdades de fé','A arqueologia provou todos os milagres bíblicos','Nada bíblico pode ser investigado pela arqueologia','A Bíblia só é válida se a arqueologia confirmar'),('FB08-L03-Q01','NAO SEI','Técnicas arqueológicas para descobrir manuscritos antigos do Mar Morto','Processo de cavar poços para obtenção de água na Palestina Antiga','Método de esconder tesouros em campos, conforme parábola de Mateus 13:44'),('FB08-L03-Q03','Permitem datar ocupações e identificar contextos culturais antigos','Permitem reconstruir apenas os textos bíblicos originais','Revelam exclusivamente a composição geológica do terreno','Permitem identificar somente artefatos metálicos antigos'),('FB08-L04-Q02','NAO SEI','Periodo dos patriarcas, por volta de 2000 a.C.','Epoca do exilio babilonico, seculo VI a.C.','Contexto do ministerio de Jesus, seculo I d.C.'),('FB08-L04-Q03','NAO SEI','Confirma a historicidade dos relatos bíblicos com precisão','Revela detalhes culturais do período bíblico','Estabelece cronologia dos eventos do Antigo Testamento'),('FB08-L04-Q01','Determinação da idade de achados arqueológicos e manuscritos bíblicos','Identificação do período histórico em que os artefatos foram produzidos','Análise comparativa entre manuscritos de diferentes regiões geográficas','Verificação da autenticidade dos objetos descobertos em escavações'),('FB08-L05-Q01','Registros escritos preservados que comprovam eventos e personagens bíblicos','Mensagens divinas gravadas por anjos em pedras sagradas','Profecias apocalípticas escritas em línguas desconhecidas','Códigos secretos usados para invocar poderes sobrenaturais'),('FB08-L04-Q04','Confirma a historicidade de eventos e personagens bíblicos','Nega totalmente a existência dos patriarcas e profetas','Substitui as narrativas sagradas por achados materiais','Invalida as profecias e os milagres registrados na Bíblia'),('FB08-L05-Q03','Confirmam a existência de reis, povos e eventos citados na Bíblia','Revelam doutrinas teológicas e dogmas ainda não escritos nas Escrituras','Predizem eventos futuros e profecias messiânicas ainda não cumpridas','Estabelecem o cânon definitivo dos livros sagrados do Antigo Testamento'),('FB08-L05-Q05','Fragmentárias, parciais, datáveis com imprecisão e refletem perspectivas específicas','São suficientes e conclusivas para validar todos os relatos bíblicos sem ressalvas','Eliminam qualquer necessidade de análise textual e do contexto histórico bíblico','Provam categoricamente a inexistência dos eventos narrados nas Sagradas Escrituras'),('FB08-L05-Q04','A Estela de Merneptá confirma a presença de Israel na terra de Canaã','A Pedra de Pilatos confirma que Jesus foi governador da Judeia','O Cilindro de Ciro narra a travessia do Mar Vermelho pelos hebreus','A Estela de Merneptá menciona Moisés e a saída do Egito'),('FB08-L05-Q02','Babilônia, palácio real de Belsazar, durante o império neobabilônico em 539 a.C.','Jerusalém, templo de Herodes, durante a Páscoa sob Pôncio Pilatos em 30 d.C.','Egito, palácio do faraó, durante o êxodo dos hebreus no séc. XIII a.C.','Nínive, palácio de Senaqueribe, durante o Império Assírio no séc. VII a.C.'),('FB08-L06-Q02','Antigo Egito, reinado de Merneptá, cerca de 1208 a.C.','Babilônia, reinado de Nabucodonosor II, séc. VI a.C.','Pérsia, reinado de Ciro II, cerca de 539 a.C.','Assíria, reinado de Salmanasar III, séc. IX a.C.'),('FB08-L06-Q03','A mais antiga menção a Israel fora da Bíblia','A data exata do êxodo do povo hebreu','O relato da travessia do Mar Vermelho','A construção dos templos de Salomão'),('FB08-L06-Q04','Contém a mais antiga menção extra-bíblica de Israel como povo em Canaã.','Confirma a saída dos hebreus do Egito durante o grande êxodo bíblico.','Descreve a construção do templo de Salomão na antiga Jerusalém.','Relata o nascimento de Jesus Cristo na cidade de Belém da Judeia.'),('FB08-L07-Q02','Século IX a.C., reinado de Mesa, rei de Moabe','Século VI a.C., durante o cativeiro babilônico','Século X a.C., no tempo do rei Davi em Israel','Século V a.C., período do retorno do exílio'),('FB08-L07-Q01','NAO SEI','Pedra onde foram gravados os Dez Mandamentos','Monumento de pedra erguido por Jacó em Betel','Coluna commemorativa do pacto entre Jacó e Labão'),('FB08-L07-Q05','São parciais, fragmentárias e refletem a visão propagandística do governante.','São fontes completas e objetivas que confirmam fielmente os relatos bíblicos.','Limitam-se a textos religiosos neutros, sem qualquer viés ideológico.','Têm apenas valor literário, sem qualquer relevância histórica para os textos bíblicos.'),('FB08-L07-Q03','Confirma a revolta de Mesa, rei de Moabe, contra Israel, conforme 2 Reis 3','Registra a construção do Templo de Salomão em Jerusalém','Narra a conquista da Terra de Canaã sob liderança de Josué','Descreve o exílio babilônico do povo de Judá'),('FB08-L08-Q02','Século IX a.C., norte de Israel, contexto das guerras de Hazael de Aram-Damasco','Século X a.C., em Jerusalém, durante o reinado de Salomão','Séc. VIII a.C., no sul de Judá, durante a reforma religiosa de Ezequias','Séc. VI a.C., na Babilônia, no período do exílio judaico'),('FB08-L08-Q04','Menciona a Casa de Davi, confirmando historicamente a dinastia davídica','Descreve a construção do Templo de Salomão em Jerusalém','Relata a travessia do Mar Vermelho por Moisés e os hebreus','Narra o confronto entre Davi e o gigante Golias no vale de Elá'),('FB08-L07-Q04','A Estela de Mesa registra a revolta de Moabe contra Israel, em 2 Reis 3','A Estela de Mesa narra a vitória do Egito sobre a Assíria no tempo de Isaías','A Estela de Mesa registra a aliança firmada por Davi com os filisteus em Gate','A Estela de Mesa aparece citada na Parábola do Semeador contada por Jesus'),('FB08-L09-Q02','Jerusalem, reinado de Ezequias de Judá (~701 a.C.), antes da invasão assíria','Babilônia, período do cativeiro, durante o reinado de Nabucodonosor','Egito, época dos faraós, durante a construção das pirâmides','Galileia, período dos Macabeus, durante a revolta contra os selêucidas')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB08-L09-Q04','Túnel construído por Ezequias para levar água da fonte de Giom ao tanque de Siloé (2 Rs 20:20)','Túnel construído por Davi para levar água da fonte de Giom ao templo de Jerusalém (1 Rs 3)','Túnel cavado por Josias para proteger Judá dos babilônios na planície de Meguido (2 Rs 23)','Túnel que ligava o palácio de Salomão ao porto de Cesaréia durante o período dos reis de Israel'),('FB08-L09-Q01','Aqueduto subterrâneo cavado por Ezequias para levar água de Giom ao tanque de Siloé','Passagem secreta usada por Davi para fugir de Absalão em Jerusalém','Túnel onde Ezequias escondeu os tesouros do templo antes da destruição','Conduto construído por Salomão para abastecer o templo de água'),('FB08-L09-Q03','Confirma relato bíblico sobre Ezequias e mostra engenharia do século VIII a.C.','Atribuído ao rei Davi para esconder tesouros do templo de Jerusalém.','Construído pelos romanos no século I para abastecer o templo de Herodes.','Teria sido escavado por Salmaneser V durante o cerco assírio a Samaria.'),('FB08-L10-Q02','Nínive, período neoassírio','Babilônia, período neobabilônico','Persépolis, período aquemênida','Ur, período sumeriano'),('FB08-L10-Q03','Confirma o cerco assírio a Jerusalém em 701 a.C., conforme 2 Rs 18-19','Descreve a vitória completa de Senaqueribe sobre Ezequias e a queda de Jerusalém','Relata a destruição do templo de Salomão pelos assírios em 586 a.C.','Narra a conversão de Senaqueribe ao Deus de Israel após a campanha na Judeia'),('FB08-L11-Q01','Decreto de Ciro que libertou os judeus do cativeiro e autorizou reconstruir o Templo','Tabuleta com as leis do rei Nabucodonosor entregues ao povo judeu na Babilônia','Objeto de cerâmica babilônica que registra a destruição do Templo de Jerusalém','Cilindro com as batalhas e conquistas militares de Ciro contra o Egito antigo'),('FB08-L10-Q01','Prisma assírio de Senaqueribe, confirma relato bíblico sobre cerco a Jerusalém','Tábua de argila babilônica com as leis do Código de Hamurabi sobre justiça','Manuscrito do Mar Morto com profecias completas atribuídas ao profeta Elias','Obelisco egípcio erguido pelo faraó Ramsés para celebrar vitórias militares'),('FB08-L10-Q04','Confirma o cerco de Jerusalém por Senaqueribe ao rei Ezequias, em 2 Rs 18-19','Registra a destruição total de Jerusalém e a deportação de Ezequias','Narra a aliança de Ezequias com Hirão de Tiro para reconstruir o templo','Descreve a vitória de Josafá contra Senaqueribe no vale de Beraca'),('FB08-L11-Q02','Conquista da Babilônia por Ciro, o Grande, no Império Persa (séc. VI a.C.)','Babilônia sob o domínio de Nabucodonosor II, séc. VI a.C.','Império Persa durante o reinado de Dario I, séc. V a.C.','Assíria, período da queda de Nínive, séc. VII a.C.'),('FB08-L12-Q01','Antigos manuscritos judaicos encontrados em cavernas próximas ao Mar Morto.','Textos sagrados escritos por Moisés durante o êxodo no Sinai.','Manuscritos cristãos primitivos escritos pelos apóstolos no século I.','Livros sagrados islâmicos descobertos no deserto da Arábia.'),('FB08-L12-Q02','Período do Segundo Templo, entre os séculos III a.C. e I d.C.','Encontrados no Templo de Herodes durante o século I a.C.','Na Biblioteca de Alexandria no período helenístico','Descobertos no Monte Sinai durante o êxodo de Israel'),('FB08-L12-Q03','Os mais antigos manuscritos biblicos em hebraico ja encontrados','Provas de que Jesus Cristo viveu entre os essenios de Qumran','Confirmam que Moises escreveu todo o Pentateuco em primeira mao','Revelam que os escribas fariseus compuseram os quatro Evangelhos'),('FB08-L12-Q05','Limitam-se ao período 250 a.C.–68 d.C. e refletem variantes de uma só comunidade.','Não apresentam variantes textuais em relação aos textos masoréticos posteriores','Foram escritos diretamente pelos autores originais dos livros bíblicos','Cobrem todo o período desde a composição original dos textos bíblicos'),('FB08-L13-Q02','Antigo Oriente Médio','Novo Testamento','Período interbíblico','Era cristã primitiva'),('FB08-L13-Q03','NAO SEI','O Cântico dos Cânticos de Salomão','A Carta aos Hebreus','O livro de Jonas'),('FB08-L14-Q01','NAO SEI','Manuscritos do Mar Morto','Papiro de Rylands (P52)','Papiros de Chester Beatty'),('FB08-L14-Q02','Palestina','Mesopotâmia','Pérsia','Grécia'),('FB08-L14-Q03','NAO SEI','Inscricao de Pilatos confirmou sua existencia como prefeito da Judeia','Manuscritos do Mar Morto contem fragmentos do Novo Testamento','O Papiro P52 e o fragmento mais antigo conhecido do Evangelho de Joao'),('FB08-L14-Q04','Confirma a historicidade de pessoas, lugares e eventos narrados na Bíblia.','Reescreve toda a cronologia e autoria dos livros do novo testamento.','Nega a existência de Jesus e de todos os apóstolos mencionados nos evangelhos.','Inverte a ordem dos evangelhos e prova que João foi escrito antes de Mateus.'),('FB08-L13-Q04','Confirmam relatos bíblicos sobre reis de Judá e o período do Segundo Templo','Contrariam relatos bíblicos sobre a existência de reis de Israel e Judá','Referem-se exclusivamente a eventos narrados no Novo Testamento','Não possuem qualquer relação com personagens ou locais bíblicos'),('FB08-L15-Q01','Evidências materiais e documentais que confirmam a confiabilidade bíblica','Estudo de artefatos religiosos sem comprovação histórica válida','Análise exclusivamente literária das Sagradas Escrituras','Método de tradução das línguas originais da Bíblia'),('FB08-L15-Q02','Antigo Oriente Próximo, entre cerca de 2000 a.C. e 100 d.C.','Mesoamérica pré-colombiana, período entre 1500 a.C. e 1500 d.C.','Europa medieval cristã, entre os séculos V e XV d.C.','Extremo Oriente antigo, durante as dinastias Shang e Zhou'),('FB08-L15-Q03','NAO SEI','A arqueologia confirma todos os relatos biblicos sem excecao','A Biblia nao possui nenhum respaldo arqueologico','A arqueologia prova que a Biblia e apenas mito literario'),('FB08-L15-Q04','NAO SEI','Arqueologia comprova cada detalhe da Biblia sem excecao','A Biblia nao possui nenhuma confirmacao arqueologica','Arqueologia contradiz totalmente os relatos biblicos'),('FB08-L15-Q05','NAO SEI','A arqueologia deve ser o critério único e final para validar qualquer narrativa bíblica','Relatos bíblicos sem confirmação arqueológica são necessariamente falsos ou lendários','A confiabilidade histórica da Bíblia é totalmente independente de qualquer evidência material externa'),('FB08-L16-Q01','NAO SEI','Evidências que confirmam relatos bíblicos','Provas científicas da historicidade das Escrituras','Descobertas arqueológicas que validam a narrativa bíblica'),('FB08-L16-Q02','NAO SEI','No período dos patriarcas em Ur dos Caldeus','Durante o cativeiro babilônico na Babilônia','No período romano sob Pôncio Pilatos'),('FB08-L16-Q05','Arqueologia é parcial e interpretativa; não pode julgar sozinha a verdade bíblica.','A arqueologia é infalível e critério absoluto para validar a Escritura.','Qualquer erro arqueológico invalida totalmente o relato bíblico correspondente.','A Bíblia deve ser descartada se não coincidir com achados arqueológicos atuais.'),('FB08-L13-Q01','Evidências arqueológicas que confirmam relatos bíblicos','Provas históricas que contradizem as Escrituras Sagradas','Descobertas que negam a existência de Davi e Salomão','Comprovação da inexistência histórica de Jesus Cristo'),('FB09-L01-Q02','Do grego kanon (regra), passou a designar livros bíblicos normativos no século IV.','O cânon bíblico foi oficialmente fixado por Martinho Lutero na Reforma Protestante.','Cânon significa originalmente canto litúrgico, passando depois a indicar livros sagrados.','O cânon foi estabelecido definitivamente no Concílio de Trento em resposta aos protestantes.'),('FB09-L01-Q03','Os 66 livros do Antigo e Novo Testamento da Bíblia Sagrada','Os livros deuterocanônicos como Tobias, Judite e Sabedoria','O Alcorão sagrado e os Hadiths da tradição islâmica','Os Evangelhos apócrifos e textos de Nag Hammadi'),('FB09-L01-Q04','É a lista autoritativa inspirada, distinta de apócrifos e outras coleções.','É uma lista de leituras devocionais recomendadas, mas não obrigatórias.','Refere-se ao índice de livros proibidos pela autoridade eclesiástica.','Indica a ordem cronológica em que os livros bíblicos foram escritos.'),('FB08-L16-Q03','NAO SEI','...','...','...'),('FB09-L02-Q02','Formou-se gradualmente; o Sínodo de Jamnia (c. 90 d.C.) o reconheceu','Definido oficialmente pelo Concílio de Trento em 1546 como resposta à Reforma','Fixado instantaneamente por Moisés no Sinai, incluindo todos os 39 livros atuais','Estabelecido por Jesus durante seu ministério terreno, conforme relato dos Evangelhos'),('FB09-L03-Q01','O conjunto dos escritos sagrados do judaísmo, equivalente ao Antigo Testamento cristão.','A coletânea dos livros do Novo Testamento escritos originalmente em grego koiné.','O conjunto exclusivo dos escritos apócrifos e deuterocanônicos reconhecidos pelo Concílio de Trento.','A totalidade da Bíblia cristã, abrangendo os dois testamentos de origem hebraica e grega.'),('FB09-L03-Q03','Torá, Nevi''im e Ketuvim','Torá, Mishná e Talmude','Evangelhos, Epístolas e Apocalipse','Tanakh, Apócrifos e Pseudepígrafos'),('FB09-L03-Q04','Organiza os livros em Torá, Nevi''im e Ketuvim, totalizando 24 livros','Possui 39 livros divididos em Pentateuco, Históricos, Poéticos e Proféticos','Apresenta 46 livros incluindo os deuterocanônicos no Antigo Testamento','Estrutura-se apenas em duas divisões: Lei e Profetas'),('FB09-L03-Q05','Não reduzir ao ''Velho Testamento'' nem impor teologia cristã posterior','A bíblia hebraica foi escrita originalmente em grego','Possui o mesmo cânon fixo desde o tempo de Moisés','Foi toda compilada no Concílio de Jamnia em 90 d.C.'),('FB09-L04-Q01','As três divisões do cânon do Antigo Testamento hebraico','A divisão dos livros do Novo Testamento em evangelhos, epistolas e apocalipse','A separação entre livros protocanonicos e deuterocanonicos da Biblia','A subdivisão do Pentateuco em cinco partes principais chamadas Torá'),('FB09-L04-Q03','O cânon hebraico dividido em Torá, Profetas e Escritos','O cânon cristão católico com 73 livros deuterocanônicos incluídos','A tradição da Septuaginta grega usada pela Igreja primitiva cristã','O Novo Testamento com seus 27 livros escritos pelos apóstolos'),('FB09-L05-Q01','É a tradução grega do Antigo Testamento, feita em Alexandria no século III a.C.','É a tradução latina da Bíblia feita por São Jerônimo no século IV d.C.','É o texto original hebraico do Antigo Testamento usado nas sinagogas','Representa os sessenta e seis livros do cânon protestante da Bíblia'),('FB09-L04-Q04','Divisão judaica tripartite do cãnon, citada em Lucas 24:44, distinta da cristã.','É a divisão cristã em Antigo e Novo Testamento usada por todas as igrejas cristãs.','Corresponde à divisão em livros históricos, poéticos e proféticos do Novo Testamento.','Inclui os livros deuterocanônicos entre os Escritos, como nas bíblias católicas.'),('FB09-L05-Q02','Tradução grega do AT surgida em Alexandria, usada por judeus e cristãos','Versão latina do AT produzida por Jerônimo a partir do hebraico original','Texto hebraico original preservado pelos escribas massoretas na Palestina','Tradução aramaica do NT feita pelos apóstolos em Jerusalém'),('FB09-L04-Q02','Lei reconhecida no exilio, Profetas gradualmente, Escritos em Jamineia (90 d.C.)','Todos reconhecidos ao mesmo tempo por Moises ao receber as tabuas no Sinai','Formalizados todos integralmente por Esdras no periodo pos-exilico na Judia','Reconhecidos oficialmente por Paulo na conferencia apostolica de Jerusalem'),('FB09-L05-Q04','Inclui deuterocanônicos ausentes no cânon hebraico e usa outra ordem dos livros.','Organiza o AT igual ao texto massorético hebraico e exclui os deuterocanônicos.','É uma versão em latim usada somente pela Igreja Católica após o Concílio de Trento.','Aceita apenas os cinco livros da Torá e rejeita todos os profetas e escritos.'),('FB09-L05-Q05','Que foi tradução única e uniforme feita por 70 sábios em 70 dias','Que é superior ao Texto Massorético em toda a Escritura','Que foi composta após o cânon hebraico já estar fechado','Que surgiu como tradução oficial do Sinédrio para Roma'),('FB09-L06-Q03','Cânon católico, tradição ortodoxa e Septuaginta grega','Cânon protestante exclusivo de Westminster','Textos encontrados apenas em Qumran','Escritos do Novo Testamento exclusivamente'),('FB09-L06-Q02','Reconhecidos pela Igreja Catolica atraves de concilios e da Tradicao','Aceitos exclusivamente por Martinho Lutero na Reforma Protestante','Reconhecidos apenas a partir do Concilio Vaticano II','Rejeitados unanimemente por todos os Pais da Igreja'),('FB09-L06-Q04','Incluídos no cânon católico e ortodoxo, mas considerados apócrifos pelos protestantes','São aceitos por todas as tradições cristãs como livros plenamente inspirados','Fazem parte exclusivamente do cânon judeu, sem reconhecimento cristão','Foram rejeitados unanimemente por todas as igrejas cristãs nos primeiros séculos'),('FB09-L04-Q05','Reduzir a Lei a código, profetas a previsores, Escritos a miscelânea','A Lei foi totalmente abolida por Cristo, perdendo toda relevância cristã','Os Escritos são textos apócrifos excluídos do cânon hebraico original','Os profetas eram principalmente adivinhos gentios adotados por Israel'),('FB09-L07-Q01','Lista de 66 livros bíblicos aceita por igrejas protestantes, sem os deuterocanônicos.','Conjunto de 73 livros bíblicos aceito pela Igreja Católica, com os deuterocanônicos.','Lista dos 27 livros do Novo Testamento, sem incluir nenhum livro do Antigo.','Coleção de livros apócrifos rejeitados por todas as igrejas cristãs históricas.'),('FB09-L08-Q01','Lista dos 73 livros inspirados reconhecidos pela Igreja Católica','Lista dos 66 livros inspirados que fundamentam a fé cristã reformada','Conjunto de escritos apócrifos rejeitados pela tradição cristã antiga','Compilação dos textos litúrgicos aprovados pelo Concílio de Calcedônia'),('FB09-L08-Q02','O cânon católico foi definido oficialmente no Concílio de Trento em 1546.','O cânon católico foi estabelecido por Martinho Lutero na Reforma Protestante.','O cânon católico surgiu pronto no século I durante o Concílio de Jerusalém.','O cânon católico foi definido pelo imperador Constantino no Édito de Milão.'),('FB09-L08-Q04','Inclui os deuterocanônicos, ausentes no cânon protestante','Possui 66 livros, mesmo número do cânon protestante atual','Difere apenas na ordem dos livros, sem conteúdos distintos','Rejeita livros históricos como Macabeus e Tobias por apocrifia'),('FB09-L08-Q03','Concílio de Trento, Vulgata e livros deuterocanônicos','Sola Scriptura, Cânon de Westminster e livros apócrifos','Concílio de Niceia, Targum e cânon massorético','Cânon de Jamnia, Septuaginta e livros protocanônicos'),('FB09-L07-Q03','Os 66 livros do AT e NT, excluindo os deuterocanônicos, pela Sola Scriptura','Os 73 livros incluindo os deuterocanônicos, conforme o Concílio de Trento','Apenas os 39 livros do cânon hebraico, sem o Novo Testamento','Os 81 livros da tradição etíope, incluindo Enoque e Jubileus'),('FB09-L09-Q01','Conjunto de livros sagrados aceitos pela tradição cristã ortodoxa como inspirados','Lista de livros heréticos rejeitados oficialmente pela tradição cristã antiga','Relação de textos apócrifos tidos como falsos pelos reformadores protestantes','Compilação de manuscritos antigos não inspirados reservados apenas para pesquisa'),('FB09-L09-Q03','Cânon ortodoxo inclui deuterocanônicos, 3 Macabeus e Salmo 151','Cânon ortodoxo contém apenas os 66 livros protestantes sem adições','Cânon ortodoxo foi definido pelo Concílio de Trento como autoridade','Cânon ortodoxo exclui Sabedoria e Eclesiástico por serem apócrifos'),('FB09-L08-Q05','A Igreja não adicionou os deuterocanônicos em Trento; já eram canônicos antes','O cânon católico foi definido pela primeira vez apenas no Concílio de Trento','Jerônimo rejeitou por completo os livros deuterocanônicos da Septuaginta','Os deuterocanônicos nunca foram citados ou aludidos por nenhum autor do Novo Testamento'),('FB09-L10-Q02','Através do uso litúrgico, decisões conciliares e aceitação gradual pelas igrejas','Por decreto do imperador Constantino no Concílio de Niceia em 325','Instantaneamente no dia de Pentecostes pelos apóstolos reunidos','Por ordem do Papa no Concílio de Trento em 1546'),('FB09-L10-Q01','O processo de reconhecimento eclesial dos 27 livros como Escritura inspirada.','A inspiração imediata dos hagiógrafos durante a composição dos textos.','A tradução dos originais hebraicos e gregos para a Septuaginta.','A formação do cânon veterotestamentário pelos escribas fariseus.'),('FB09-L09-Q05','O cânon bíblico não foi definido em Niceia, mas pelo uso litúrgico e conciliar ao longo dos séculos.','A Igreja Ortodoxa exclui os livros deuterocanônicos, seguindo o cânon protestante.','A Vulgata de Jerônimo é a versão bíblica oficial e original usada pela Ortodoxia.','O Sínodo de Jerusalém de 1672 reduziu o cânon ortodoxo aos 66 livros protestantes.'),('FB09-L11-Q01','Requisitos usados pela Igreja para validar livros como Escritura Sagrada','Lista dos livros que foram rejeitados pela Igreja no processo de formação','Ordem cronológica em que os textos sagrados foram originalmente escritos','Quantidade de manuscritos antigos encontrados para autenticação textual'),('FB09-L11-Q04','Critérios formais de canonização diferem do reconhecimento informal pela tradição e uso litúrgico','Os critérios canônicos baseiam-se exclusivamente nas decisões do Concílio de Trento','Todas as formas de reconhecimento bíblico são idênticas entre si','Apenas a Igreja Católica Romana possui critérios válidos de reconhecimento'),('FB09-L12-Q01','Escritos atribuídos aos apóstolos, com autoridade apostólica no cânon.','Livros do Antigo Testamento atribuídos aos profetas durante o exílio.','Textos apócrifos rejeitados pelas igrejas por conterem heresias doutrinárias.','Obras escritas por Paulo antes de sua conversão no caminho de Damasco.'),('FB09-L11-Q05','Evitar o mito de que o cânon foi definido no Concílio de Nicéia','O cânon foi estabelecido definitivamente pelos escribas no retorno do exílio','Os critérios de canonicidade foram unificados após a Reforma Protestante','Apenas livros aceitos pelo Sinédrio judeu antes de Cristo são canônicos'),('FB10-L02-Q01','A comunicação sobrenatural de Deus ao homem, registrada na Escritura','A manifestação de Deus através da natureza e da criação','O processo pelo qual o crente compreende as Escrituras','A capacidade humana de conhecer a Deus pela razão'),('FB10-L01-Q05','Panteísmo, naturalismo e suficiência para salvação.','A revelação geral basta para a salvação dos incrédulos.','Deus se revela exclusivamente por meio das Escrituras.','A revelação geral se contradiz à revelação especial.'),('FB10-L02-Q02','Deus se revela em Cristo e nas Escrituras segundo Hebreus 1:1-2.','Deus se revela apenas pela natureza e pela razão humana, segundo Salmo 19:1.','A revelação especial se baseia na tradição oral da igreja, segundo Atos 2:42.','A revelação especial ocorre só por experiências místicas, segundo 1 Reis 19:12.'),('FB10-L02-Q03','É a manifestação específica de Deus por meio das Escrituras e de Cristo','É o conhecimento de Deus obtido pela observação da natureza criada','Se fundamenta exclusivamente na tradição oral transmitida pelos apóstolos','Consiste em experiências místicas individuais de cada crente em particular'),('FB10-L03-Q01','Deus soprou as Escrituras, tornando-as autoritativas, infalíveis e inerrantes.','É a iluminação interior do Espírito que ajuda o crente a entender a Bíblia.','É a revelação geral de Deus por meio da criação e da consciência humana.','É o processo histórico pelo qual a Igreja reconheceu os livros canônicos.'),('FB10-L03-Q02','Base: 2 Tm 3:16 e 2 Pe 1:21, que afirmam a inspiração divina das Escrituras.','Base: Tradição oral dos apóstolos, fonte única de autoridade cristã.','Base: Razão humana e experiência religiosa como critérios de verdade espiritual.','Base: Decisões dos concílios ecumênicos como norma suprema da fé cristã.'),('FB10-L03-Q03','É o sopro divino que levou os autores a escreverem a Palavra de Deus','É a manifestação progressiva do plano de Deus ao longo da história','É a ação do Espírito que capacita o crente a entender as Escrituras','É a ausência de erros nas Escrituras em seus manuscritos originais'),('FB10-L02-Q05','Racionalismo, misticismo e biblicismo literalista','Pelagianismo, semipelagianismo e arminianismo','Arianismo, modalismo e apolinarismo','Anabatismo, donatismo e montanismo'),('FB10-L04-Q01','Significa que cada palavra da Escritura foi inspirada por Deus','Significa que apenas os pensamentos foram inspirados por Deus','Significa que a Biblia e totalmente inerrante em tudo que ensina','Significa que Deus ditou mecanicamente cada palavra aos autores'),('FB10-L04-Q03','Estende-se às próprias palavras da Escritura, não apenas aos pensamentos','Inspira somente os pensamentos, deixando as palavras aos autores','Aplica-se apenas aos temas centrais da revelação bíblica','Limita-se a uma iluminação interior dos crentes piedosos'),('FB10-L03-Q05','Evitar o naturalismo e o ditado mecânico como extremos opostos.','Devemos evitar reconhecer que Deus usou a personalidade dos autores humanos.','A inspiração plena não se aplica às narrativas históricas do Antigo Testamento.','Apenas os textos originais são úteis, pois as traduções perderam a inspiração.'),('FB10-L05-Q01','Toda a Escritura é divinamente inspirada em todas as suas partes e palavras.','Apenas os ensinamentos espirituais da Bíblia foram inspirados por Deus.','Somente os profetas receberam inspiração divina ao escrever as Escrituras.','A inspiração plenária se aplica apenas aos livros do Novo Testamento.'),('FB10-L05-Q04','Garante autoridade absoluta das Escrituras como regra infalível de fé e vida','Apenas os ensinamentos morais da Bíblia são inspirados, o resto é cultural','A inspiração plenária restringe a autoridade das Escrituras ao âmbito espiritual','A inspiração plenária autoriza interpretação pessoal acima do texto bíblico'),('FB10-L05-Q05','Evitar o ditado mecânico e a mera iluminação humana','Aceitar o ditado verbal como única forma válida de inspiração','Defender a inspiração parcial apenas das verdades espirituais','Apoiar a inerrância absoluta em todos os detalhes científicos'),('FB10-L06-Q04','Nao diminui a autoridade divina, pois a Escritura e inspirada por Deus','Autoria humana torna as Escrituras relativas e sujeitas a erro','Interpretacao deve ignorar o contexto humano e focar so no divino','Uso das Escrituras deve ser limitado pelas limitacoes dos autores'),('FB10-L06-Q02','2 Pedro 1:21: homens santos falaram movidos pelo Espírito Santo','João 1:1: No princípio era o Verbo, e o Verbo era Deus','2 Timóteo 3:16: Toda Escritura é inspirada por Deus e proveitosa','Hebreus 1:1: Deus falou pelos profetas nos últimos dias pelo Filho'),('FB10-L07-Q01','A Escritura é a Palavra inspirada de Deus, autoridade suprema da fé e da vida.','A tradição da Igreja possui autoridade superior à das Escrituras Sagradas.','Somente os Evangelhos possuem autoridade divina para a fé e a prática.','A autoridade bíblica depende da aprovação dos líderes religiosos da época.'),('FB10-L06-Q03','Autores humanos escreveram sob inspiração, usando suas faculdades próprias.','Autores humanos apenas copiaram literalmente as palavras de Deus.','Os autores escreveram apenas por esforço humano, sem ação divina.','A Bíblia surgiu exclusivamente por meio de visões místicas dos profetas.'),('FB10-L07-Q02','A Escritura, inspirada por Deus, possui autoridade absoluta sobre a fé','A tradição apostólica é superior à autoridade das Escrituras Sagradas','O magistério papal confere autoridade infalível às Sagradas Escrituras','A experiência mística pessoal fundamenta a autoridade do texto bíblico'),('FB10-L10-Q02','2 Tm 3.16-17: a Escritura inspirada basta para tornar perfeito o homem de Deus.','A tradição oral apostólica possui a mesma autoridade normativa da Escritura.','A infalibilidade papal é o fundamento da suficiência da revelação cristã.','Novas profecias contemporâneas complementam a suficiência das Escrituras.'),('FB10-L07-Q03','É intrínseca à Palavra de Deus, distinta de inspiração, revelação e inerrância.','É atribuída pela Igreja Católica por meio do magistério e da tradição.','Depende da aceitação racional do indivíduo e da evidência empírica.','Resulta unicamente da decisão dos concílios ecumênicos da era cristã.'),('FB10-L12-Q03','NAO SEI','A Escritura toda é inspirada por Deus segundo 2 Timoteo 3:16','Distingue-se como regra unica de fé e pratica do crente','A Palavra de Deus é viva e eficaz segundo Hebreus 4:12'),('FB10-L12-Q04','As Escrituras são a regra infalível de fé e prática, dotada de autoridade suprema.','Tornam a tradição da igreja o critério final de verdade, acima das Escrituras.','As Escrituras servem apenas como guia devoconal, sem autoridade doutrinária.','A necessidade das Escrituras limita sua autoridade à vida espiritual privada.'),('FB10-L14-Q01','É a ação do Espírito Santo que esclarece o entendimento para compreender as Escrituras','É a inspiração verbal que garante a inerrância dos textos bíblicos originais','É o processo pelo qual o crente alcança a perfeição moral através da leitura bíblica','É a capacidade profética de prever eventos futuros contidos nas Escrituras Sagradas'),('FB10-L13-Q04','Confirma a autoridade divina e a coerência de toda a Escritura Sagrada','Implica que a Bíblia contém erros e contradições entre seus textos','Sugere que cada livro bíblico deve ser interpretado de forma isolada','Indica que apenas o Novo Testamento possui autoridade divina plena'),('FB10-L14-Q02','1 Coríntios 2:10-16: o Espírito revela as profundezas de Deus aos crentes','Gênesis 1:2: o Espírito pairava sobre as águas na criação inicial','Atos 2:1-4: o Espírito desceu em línguas de fogo no Pentecostes','Romanos 8:28: Deus coopera todas as coisas para o bem dos crentes'),('FB10-L14-Q04','Confirma a autoridade das Escrituras e capacita o crente à correta interpretação','Dispensa o estudo diligente das Escrituras pelo leitor comum','Concede autoridade exclusiva aos mestres eclesiásticos sobre o texto','Produz novas revelações que se sobrepõem ao cânon escriturístico'),('FB10-L15-Q01','Revelam a origem divina das Escrituras e a limitação humana','Indicam erros de tradução que devem ser corrigidos pelos estudiosos','Provam que as Escrituras contêm falhas humanas em sua composição','Mostram que devemos rejeitar os trechos de difícil compreensão'),('FB10-L14-Q05','Racionalismo e misticismo; a iluminacao opera pela Palavra e com a razao.','A iluminacao concede novas revelacoes extracanonicas ao crente.','A razao humana, sem o Espirito, basta para compreender as Escrituras.','A iluminacao ocorre apenas por emocoes e experiencias mysticas.'),('FB10-L15-Q03','São textos que parecem contraditórios, mas admitem harmonização pela exegese.','Paradoxo teológico cuja tensão lógica é insolúvel e permanente.','Erro textual decorrente de falha na transmissão manuscrita.','Mistério revelado apenas pelo Espírito Santo ao crente.'),('FB10-L15-Q05','Negar que existam dificuldades e duvidar da inspiração das Escrituras','Aceitar todas as contradições como verdadeiras e abandonar o estudo','Interpretar tudo literalmente e rejeitar o contexto histórico','Confiar na tradição da igreja acima do texto bíblico'),('FB11-L03-Q02','Era mais durável e resistente à umidade, permitindo escrita nos dois lados','Era mais barato e de produção mais rápida que o rolo de papiro','Era feito de fibras de junco do Nilo, iguais às do papiro','Desenvolvido pelos egípcios antes mesmo do papiro'),('FB10-L15-Q02','A inspiração divina das Escrituras e a limitação do entendimento humano','A tradição eclesiástica tem autoridade final sobre todas as questões bíblicas','A razão filosófica autônoma supera a revelação divina nas questões de fé','As contradições aparentes provam que a Bíblia contém erros e não é inspirada'),('FB11-L06-Q04','É o texto-base hebraico usado pelas traduções modernas do Antigo Testamento.','É a tradução grega do AT usada como base das versões modernas.','Foi encontrado entre os manuscritos do Mar Morto em cavernas.','É um texto deuterocanônico usado apenas em edições católicas.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB11-L01-Q01','Pedra, papiro, pergaminho e tábuas de argila','Bronze, ouro, prata e pedras preciosas lapidadas','Tecido de linho fino, seda pura e couro curtido','Vidro soprado, alabastro e cristais lapidados'),('FB11-L07-Q02','Gênesis, Êxodo, Levítico, Números e Deuteronômio','Gênesis, Êxodo, Levítico, Números e Josué','Gênesis, Êxodo, Levítico, Deuteronômio e Josué','Êxodo, Levítico, Números, Deuteronômio e Isaías'),('FB11-L06-Q05','O Texto Massorético mostra grande concordância com os Manuscritos do Mar Morto.','O Texto Massorético diverge completamente dos Manuscritos do Mar Morto.','Os Manuscritos do Mar Morto são cópias idênticas do Texto Massorético.','Os Manuscritos do Mar Morto provam a corrupção do Texto Massorético.'),('FB11-L07-Q03','É a Torá sagrada dos samaritanos, escrita em alfabeto próprio e base da identidade religiosa da comunidade.','É um comentário rabínico medieval sobre o Pentateuco massorético, sem uso litúrgico.','Trata-se de uma tradução grega dos cinco livros usada apenas por judeus helenistas.','É o cânone completo do Antigo Testamento reconhecido pela comunidade, incluindo Profetas e Escritos.'),('FB11-L07-Q04','Em cronologias, variantes textuais e na extensão de certos livros','Em nada, pois são idênticos em conteúdo e forma','Apenas na divisão de capítulos e versículos','Somente na ordem dos livros no cânon'),('FB11-L08-Q02','Grego','Hebraico','Latim','Aramaico'),('FB11-L07-Q05','São os mais antigos manuscritos hebraicos, confirmando o texto masorético.','São traduções gregas que auxiliaram na revisão do texto hebraico.','São pergaminhos aramaicos do período do Novo Testamento.','Foram as primeiras edições impressas da Bíblia Hebraica.'),('FB11-L08-Q03','Porque o hebraico já não era sua língua vernácula após a helenização','Porque os manuscritos hebraicos foram perdidos durante a diáspora','Porque o grego era considerado a língua sagrada do povo eleito','Porque o cânone das Escrituras ainda não havia sido oficialmente definido'),('FB11-L06-Q03','Para preservar a pronúncia correta, pois o hebraico já não era língua falada cotidiana.','Para registrar fielmente as tradições interpretativas de cada escola rabínica.','Para substituir o antigo sistema paleo-hebraico pelo alfabeto quadrático aramaico.','Para possibilitar a tradução precisa do texto para o grego da Septuaginta.'),('FB11-L09-Q01','Antigos manuscritos judaicos encontrados em cavernas perto do Mar Morto.','Cartas de Paulo escritas durante suas viagens missionárias pelo Império Romano.','Manuscritos do Talmude copiados pelos escribas no Templo de Jerusalém.','Traduções dos Evangelhos em latim realizadas por Jerônimo.'),('FB11-L09-Q02','NAO SEI','Foram achados junto ao rio Jordao, no periodo dos Juizes','Descobertos nas escavacoes de Jerusale, era do rei Davi','Encontrados no deserto do Sinai, tempo do exodo'),('FB11-L09-Q03','Textos bíblicos, apócrifos e sectários','Apenas textos do Novo Testamento grego','Somente manuscritos em língua latina','Exclusivamente livros deuterocanônicos'),('FB11-L08-Q05','Ajudam a reconstruir o texto hebraico original e elucidar a transmissão textual.','Confirmam a superioridade absoluta do Texto Massorético sobre todas as versões.','Demonstram que a Septuaginta deve ser totalmente descartada dos estudos.','Provam que as diferenças são meros erros introduzidos pelos tradutores gregos.'),('FB11-L09-Q04','É o mais antigo rolo completo de Isaías, confirmando a fidelidade textual.','Revela que Isaías previu a fundação da comunidade essênia de Qumram.','Contém textos apócrifos desconhecidos que ampliam o cânon bíblico.','Prova que Isaías foi escrito por múltiplos autores no século I d.C.'),('FB11-L09-Q06','Revelam múltiplas tradições textuais bíblicas e obras sectárias judaicas.','Confirmam que o texto massorético era único na tradição judaica antiga.','Apresentam somente manuscritos cristãos do primeiro século da era comum.','Revelam tradição textual única e uniforme sem variações significativas.'),('FB11-L10-Q02','Escritos em grego koiné, sobre papiro, séculos II a VIII','Em latim vulgar, em pergaminho, tradição ocidental tardia','Em hebraico, em couro, tradições qumranianas','Em aramaico, em papiro, tradição essênia'),('FB11-L10-Q01','Cópias do NT em papiro, os manuscritos mais antigos preservados.','Cópias do NT em pergaminho, datadas do período medieval.','O texto sagrado original ditado pelos apóstolos em hebraico.','Traduções do NT para o latim feitas por Jerônimo na Vulgata.'),('FB11-L10-Q04','São os testemunhos mais antigos do NT, permitindo reconstruir o texto original.','Foram escritos diretamente pelos apóstolos, sendo portanto autênticos.','Comprovam a inerrância absoluta do texto bíblico em todas as versões.','Substituem os códices majúsculos como única fonte confiável do texto.'),('FB11-L10-Q05','São fragmentários, com datação incerta e cobertos por variantes scribais.','Devem ser tratados como texto original e infalível, sem crítica.','Substituem completamente os manuscritos unciais e cursivos posteriores.','Apresentam sempre o texto mais fiel por serem os mais antigos.'),('FB11-L11-Q04','Revelam variantes textuais e famílias de manuscritos na transmissão do texto.','Garantem a autenticidade dos autógrafos originais preservados intactos.','Comprovam que o cânon bíblico foi definitivamente definido no século IV.','Mostram que a Septuaginta é o único texto bíblico plenamente confiável.'),('FB11-L11-Q02','Manuscritos bíblicos gregos em pergaminho, séc. IV-XV','Manuscritos hebraicos do Antigo Testamento em papiro, séc. II-III','Códices latinos da Vulgata em pergaminho, séc. IV-XV','Textos coptos do Novo Testamento em papiro, séc. III-V'),('FB11-L11-Q01','Unciais são manuscritos em maiúsculas; minúsculos, em letras cursivas.','São manuscritos classificados pelo material: papiro, pergaminho ou papel.','São tipos textuais da Bíblia usados por diferentes igrejas cristãs antigas.','São coleções de manuscritos agrupados por região geográfica de origem.'),('FB11-L12-Q01','Antigo manuscrito grego do século IV, contém o Novo Testamento mais completo.','Manuscrito latino do século II, descoberto em Jerusalém.','Cópia hebraica do Novo Testamento, feita pelos apóstolos.','Texto apócrifo do século V, encontrado no Vaticano.'),('FB11-L12-Q04','Permite comparar variantes textuais e reconstruir o texto original','Definiu o canon oficial dos livros do Novo Testamento','Traduziu o texto biblico para o latim vulgar nos primeiros seculos','Comprovou a historicidade dos eventos narrados nos Evangelhos'),('FB11-L12-Q03','Códice grego do séc. IV em pergaminho, letras unciais, quatro colunas por página.','Códice em latim do séc. V, com iluminuras medievais e comentários de Jerônimo.','Manuscrito hebraico massorético do séc. IX, escrito por escribas judeus.','Tradução em aramaico do séc. II, encontrada nas cavernas de Qumran.'),('FB11-L13-Q01','É um dos mais antigos manuscritos gregos da Bíblia, do século IV, no Vaticano.','Tradução latina da Bíblia feita por São Jerônimo no século IV.','Cópia da Bíblia descoberta por Tischendorf no mosteiro de Santa Catarina.','Conjunto de pergaminhos hebraicos achados nas cavernas de Qumran.'),('FB11-L13-Q02','Século IV, grego, pergaminho, texto alexandrino','Século V, latim, pergaminho, tradição ocidental','Século II, grego, papiro, tradição ocidental','Século IV, hebraico, pergaminho, texto massorético'),('FB11-L13-Q03','Século IV, três colunas, uncial, texto alexandrino, scriptio continua','Século X, minúscula cursiva, texto bizantino, com glosas marginais','Século II, papiro, texto ocidental, duas colunas por página','Século V, uncial bilíngue, texto cesariano, com iluminuras douradas'),('FB11-L12-Q02','Século IV, em grego koiné, escrito em pergaminho.','Século II, em latim eclesiástico, escrito em papiro.','Século VII, em siríaco, escrito em couro animal.','Século I, em hebraico massorético, escrito em papiro.'),('FB11-L13-Q04','É um dos mais antigos manuscritos bíblicos, essencial à crítica textual.','Foi o primeiro manuscrito bíblico traduzido para o latim por Jerônimo.','Contém exclusivamente o Novo Testamento, sem porções do Antigo.','É a base exclusiva do Textus Receptus utilizado nas Bíblias protestantes.'),('FB12-L03-Q03','Clareza de sentido e naturalidade na leitura pública','Preserva a estrutura sintática do hebraico e do grego','Privilegia a tradução literal palavra por palavra','Mantém arcaísmos e termos técnicos do original'),('FB11-L12-Q05','Data do século IV, contém correções de escribas posteriores e está incompleto','Ser cópia exata dos originais, sem variações textuais','Datá do século II, sendo o mais antigo manuscrito grego completo','Não possuir correções, mantendo o texto original intacto'),('FB12-L02-Q01','Prioriza a tradução palavra por palavra, mantendo a sintaxe do original.','Tradução sentido por sentido, buscando a equivalência dinâmica do texto.','Paráfrase interpretativa que explica o significado teológico do texto.','Adaptação cultural que substitui termos hebraicos por equivalentes atuais.'),('FB12-L03-Q04','Distorce o sentido original ao impor a interpretação do tradutor','Torna o texto mais acessível, sem qualquer prejuízo à mensagem','Prejudica apenas o estilo literário, preservando o conteúdo','Dificulta a leitura, mas mantém fielmente a Palavra de Deus'),('FB12-L04-Q01','Reformulação do texto bíblico com outras palavras, mantendo o sentido original','Tradução literal palavra por palavra de um versículo bíblico para outro idioma','Interpretação teológica pessoal aplicada ao contexto amplo das Sagradas Escrituras','Resumo condensado de toda a narrativa bíblica em poucas e simples palavras-chave'),('FB12-L04-Q05','Não distorcer o verdadeiro sentido das Escrituras','Interpretar livremente sem considerar o contexto','Adaptar o texto bíblico às opiniões pessoais','Substituir a revelação bíblica por tradições humanas'),('FB12-L05-Q01','Que se fundamenta em uma edição ou manuscrito grego específico','Que possui notas de rodapé com explicações teológicas','Que inclui os livros apócrifos no cânon bíblico','Que foi traduzida diretamente do latim para o português'),('FB12-L05-Q04','Devido a variantes nos manuscritos gregos e critérios de crítica textual.','Porque Deus revelou textos distintos a cada tradutor inspirado.','As traduções modernas corrigem erros propositais das antigas.','Cada tradutor escolhe o texto conforme sua preferência pessoal.'),('FB12-L05-Q05','Apontam variantes textuais e leituras alternativas entre os manuscritos.','Traduzem palavras originais para o português contemporâneo.','Indicam referências cruzadas com outros textos bíblicos.','Apresentam dados biográficos dos autores sagrados.'),('FB12-L06-Q01','Base no texto massorético hebraico como fonte primária da tradução','Uso da Septuaginta grega como texto-base exclusivo para a tradução','Tradução literal palavra por palavra sem considerar o contexto cultural','Adoção prioritária da Vulgata latina como referência textual principal'),('FB12-L13-Q05','Como referência textual, sempre confrontada com o contexto bíblico','Como versão única, dispensando o uso de outras traduções','Substituindo o estudo dos textos originais em hebraico e grego','Baseando toda interpretação apenas na leitura literal isolada'),('FB12-L05-Q03','Textus Receptus e Nestle-Aland','Vulgata Latina e Septuaginta','Codex Vaticanus e Sinaiticus','Papiros e Códices Alexandrinos'),('FB12-L13-Q04','NAO SEI','Risco de acrescentar ou diminuir palavras das Escrituras','Perigo de interpretação herética da Palavra de Deus','Limitação da compreensão dos mistérios divinos'),('FB12-L14-Q02','NAO SEI','Uso exclusivo do Textus Receptus como base textual única','Tradução realizada diretamente da Vulgata Latina','Revisão apenas ortográfica da edição Almeida de 1943'),('FB12-L14-Q03','Linguagem contemporânea e fidelidade aos manuscritos hebraicos e gregos','Tradução feita diretamente da Vulgata Latina','Versão oficial adotada exclusivamente pela Igreja Católica','Texto sem nenhuma revisão desde sua primeira edição'),('FB12-L14-Q01','Revisão literal da Almeida baseada no Textus Receptus, com linguagem formal eclesiástica','Tradução de equivalência dinâmica que usa linguagem coloquial e acessível','Paráfrase contemporânea priorizando ideias em vez das palavras originais','Versão baseada no Codex Vaticanus e na Septuaginta grega'),('FB12-L14-Q05','NAO SEI','Substituir o estudo dos textos originais hebraico e grego por esta versão','Adotá-la como única tradução, ignorando versões como a NVI ou NTLH','Interpretar versículos isolados, sem considerar o contexto histórico e literário'),('FB12-L14-Q04','NAO SEI','Cuidado para que ninguém se enrede nas questões secundárias da fé','O perigo maior é o amor ao mundo e às concupiscências da carne','As limitações da lei foram abolidas pela graça em Cristo Jesus'),('FB12-L15-Q01','Revisão da Almeida Revista e Corrigida com atualização linguística','Tradução de equivalência dinâmica em linguagem acessível','Paráfrase bíblica em linguagem popular e contemporânea','Tradução interconfessional baseada no texto crítico grego'),('FB12-L15-Q03','Linguagem acessível e fiel aos melhores textos hebraico e grego.','Mantém a linguagem arcaica de 1681, sendo fiel à versão original de João Ferreira de Almeida.','Inclui os livros apócrifos como parte integrante do cânon bíblico protestante.','É baseada exclusivamente na Vulgata Latina, seguindo a tradição católica.'),('FB12-L15-Q02','Adoção do texto crítico grego e modernização do português arcaico','Baseia-se exclusivamente no Textus Receptus mantendo formas do século XVII','Tradução paráfrase livre a partir da Vulgata Latina sem base manuscrita','Revisão apenas ortográfica sem alterações de terminologia teológica'),('FB12-L16-Q01','Equilíbrio entre equivalência formal e dinâmica','Literalidade estrita palavra por palavra do Textus Receptus','Paráfrase livre sem fidelidade aos manuscritos originais','Equivalência dinâmica radical com liberdade interpretativa total'),('FB12-L15-Q04','Substituição do Textus Receptus pelo texto crítico grego mais recente','Inclusão de livros deuterocanônicos inéditos na versão Almeida','Tradução feita exclusivamente por uma única equipe linguística','Distribuição restrita apenas a denominações protestantes históricas'),('FB12-L16-Q02','NAO SEI','Equivalência formal preservando estrutura do hebraico','Uso exclusivo do Textus Receptus grego','Tradução palavra por palavra sem paráfrase'),('FB12-L16-Q03','Linguagem clara e acessível, equilibrando fidelidade e naturalidade','Tradução estritamente literal palavra por palavra dos originais','Baseada exclusivamente na antiga Vulgata Latina de Jerônimo','Destinada unicamente a estudiosos e acadêmicos teológicos'),('FB12-L16-Q05','Comparando com outras traduções e consultando os textos originais','Substituindo todas as outras versões sem necessidade de comparação','Interpretando versículos isolados sem considerar o contexto','Usando como única fonte sem consultar comentários bíblicos'),('FB12-L16-Q04','NAO SEI','Risco de heresias doutrinarias','Perda da inspiracao textual original','Distorcao das profecias escatologicas'),('FB12-L17-Q03','Linguagem contemporânea e acessível que preserva o sentido do texto original.','Tradução palavra por palavra do hebraico e grego seguindo método interlinear.','Preserva arcaísmos e linguagem tradicional para manter a fidelidade histórica.','Inclui notas explicativas detalhadas em cada versículo para estudo aprofundado.'),('FB12-L17-Q02','NAO SEI','Escolha entre Septuaginta e Vulgata como texto-fonte principal','Adoção exclusiva do Textus Receptus para o Novo Testamento','Inclusão dos livros deuterocanônicos no cânon protestante'),('FB12-L17-Q04','NAO SEI','Risco de distorcer o sentido original das Escrituras','Perigo de acrescentar ou diminuir da Palavra de Deus','Possibilidade de interpretacoes teologicas erradas'),('FB12-L17-Q05','Como recurso auxiliar, comparando com o texto original e outras traduções reconhecidas','Substituindo integralmente a leitura das Escrituras Sagradas em qualquer contexto','Aceitando sem critica qualquer interpretacao como inspirada e literal','Ignorando o contexto historico e cultural do periodo biblico'),('FB12-L17-Q01','Alterações que vão além da equivalência linguística, modificando o texto.','Fidelidade absoluta ao texto original sem nenhuma adaptação.','Tradução palavra por palavra mantendo forma e conteúdo.','Reprodução literal da sintaxe e estrutura do idioma original.'),('FB12-L18-Q02','Tradução dos idiomas originais com notas críticas e introdução por livro.','Tradução literal direta da Vulgata Latina sem qualquer anotação.','Paráfrase simplificada do texto bíblico para o público infantil.','Transcrição fonética dos originais hebraicos e gregos sem tradução.'),('FB12-L18-Q05','Consultando suas notas de rodapé e comparando com outras traduções','Substituindo o estudo exegético pela leitura devocional apenas','Ignorando as introduções aos livros bíblicos apresentadas','Usando exclusivamente sem consultar o texto original'),('FB12-L18-Q04','Notas com viés liberal baseadas em método histórico-crítico','Tradução palavra por palavra sem qualquer influência interpretativa','Versão bíblica baseada unicamente na tradução da Vulgata Latina','Texto protestante sem anotações, notas ou comentários explicativos'),('FB12-L19-Q02','O sentido do texto no idioma original','A preferência pessoal do leitor','A popularidade da tradução escolhida','O ano em que a versão foi publicada'),('FB12-L19-Q01','Para esclarecer ambiguidades e captar nuances do texto original','Para encontrar erros e contradições entre as versões bíblicas','Para identificar qual tradução é a única autorizada por Deus','Para confundir o leitor e gerar dúvida sobre a Palavra'),('FB13-L03-Q05','Distorção do sentido original e falsas interpretações heréticas','Clareza absoluta na compreensão do texto bíblico sagrado','Harmonia perfeita entre todas as doutrinas cristãs','Aprofundamento espiritual sem necessidade de estudo'),('FB13-L04-Q03','Para compreender o contexto histórico e a intenção original do texto bíblico','Porque definem a estrutura gramatical e a sintaxe do texto bíblico','Porque indicam a quantidade de capítulos e versículos do livro sagrado','Porque determinam a tradução exata do hebraico e do grego originais'),('FB12-L18-Q01','Tradução direta dos originais hebraico e grego, com vasto aparato crítico','Revisão da Vulgata Latina feita por monges beneditinos sem notas','Tradução exclusivamente da Septuaginta grega sem aparato crítico','Primeira tradução protestante em português feita por missionários'),('FB13-L04-Q01','Analisar a passagem considerando o que a precede e sucede no mesmo livro bíblico.','Interpretar a passagem conforme opiniões e sentimentos pessoais do leitor.','Buscar sentidos ocultos por meio de códigos e numerologias bíblicas.','Aplicar o texto sem qualquer ligação com o restante do livro.'),('FB13-L04-Q05','Descontextualização','Concordismo literal','Tipologia seletiva','Eisegese parcial'),('FB13-L04-Q04','Permite identificar a função da seção pelo contexto literário e posição no todo.','A estrutura geral do livro é irrelevante para localizar a função de uma seção.','Apenas a estrutura interna da seção determina sua função, sem considerar o todo.','A divisão em capítulos e versículos define por si só a função da seção.'),('FB13-L05-Q03','Quem escreveu, a quem, quando, por que e em que contexto cultural e histórico?','Qual a estrutura gramatical, o tempo verbal e a sintaxe do texto original?','Como este texto se aplica a vida devocional do crente no tempo atual?','Quais os tipos, figuras, simbolos e alegorias presentes no texto biblico?'),('FB13-L05-Q04','Anacronismo ao projetar conceitos modernos no texto antigo','Eisegese ao inserir significados ausentes no texto bíblico','Desconsideração do gênero literário presente na passagem','Conflito teológico entre o autor inspirado e o intérprete'),('FB13-L05-Q05','Esclarecendo o sentido original para aplicação fiel no presente','Substituindo o texto por interpretações culturais modernas','Ignorando as diferenças culturais entre as épocas bíblicas','Aplicando literalmente sem considerar o público original'),('FB13-L06-Q03','Costumes, valores, práticas sociais e crenças religiosas da época','Textos paralelos, gramática, sintaxe e estrutura literária','Autoria, data de composição, destinatários e cânon','Tipologia, alegoria, profecia e aplicação teológica'),('FB13-L06-Q05','NAO SEI','Devemos ignorar o contexto cultural e aplicar o texto literalmente em todas as culturas','O contexto cultural anula completamente o significado original do texto biblico','Apenas o Novo Testamento tem relevancia cultural para a aplicacao atual'),('FB13-L06-Q01','É entender os costumes e práticas sociais da época em que a Bíblia foi escrita.','Análise das variantes textuais dos manuscritos bíblicos originais.','Buscar o sentido espiritual e místico do texto independentemente da época.','Estudo exclusivo das palavras originais em hebraico e grego.'),('FB13-L06-Q02','Permite entender os costumes da época e evitar leituras anacronicas.','Porque define qual versão bíblica é mais confiável para estudo.','O contexto cultural já foi plenamente absorvido pela fé cristã.','Serve apenas para confirmar a precisão histórica dos relatos.'),('FB13-L06-Q04','Anacronismo na interpretação dos textos bíblicos','Etnocentrismo cultural ao interpretar as Escrituras','Leitura literal que ignora o contexto da época','Sincretismo ao misturar culturas antigas e modernas'),('FB13-L07-Q01','Leitura do texto à luz do cânon bíblico completo e da história da redenção.','Método que isola o texto do contexto histórico para evitar influências externas.','Interpretação baseada exclusivamente na Septuaginta, ignorando o hebraico e aramaico.','Leitura que prioriza os Evangelhos como única norma interpretativa das Escrituras.'),('FB13-L07-Q03','Posição do livro no cânon, relação do livro com o cânon e lugar da passagem no livro','Autoria, data de composição e destinatários originais do texto bíblico','Gênero literário, estrutura textual e vocabulário empregado na passagem','Contexto histórico, cultural e geográfico do mundo bíblico antigo'),('FB13-L07-Q04','Eisegese e deturpação do sentido canônico da Escritura','Exegese fiel ao contexto histórico e gramatical','Interpretação literal do texto bíblico original','Leitura devocional e piedosa das Sagradas Escrituras'),('FB13-L07-Q02','Porque situa o texto na totalidade das Escrituras e revela seu sentido original.','Porque permite ignorar o contexto histórico e aplicar o texto de forma subjetiva.','Porque o sentido literal é o único válido, dispensando o gênero literário.','Porque o cânon bíblico contém apenas textos históricos, sem valor teológico.'),('FB13-L08-Q01','É o sentido que o autor humano pretendeu comunicar ao escrever o texto bíblico.','Significado que o leitor moderno descobre ao aplicar o texto à sua realidade.','Sentido alegórico e místico que ultrapassa o sentido literal do texto bíblico.','Revelação pessoal dada pelo Espírito Santo diretamente ao intérprete.'),('FB13-L08-Q04','Eisegese','Exegese','Hermenêutica','Tipologia'),('FB13-L08-Q02','Porque o sentido original do texto é o que o autor inspirado pretendia comunicar.','Porque o leitor moderno possui autoridade superior à do autor bíblico.','Porque o texto possui infinitos sentidos independentes de qualquer autor.','Porque o sentido da passagem depende apenas da emoção de quem a lê.'),('FB13-L08-Q05','A intenção do autor define o sentido, guiando a aplicação do texto.','O leitor moderno é quem determina o sentido, ignorando o autor.','O texto aplica-se segundo a cultura atual, sem limitar pelo autor.','A tradição eclesiástica substitui a intenção do autor na aplicação.'),('FB13-L09-Q03','NAO SEI','O principio deve ser aplicado literalmente sem considerar o contexto cultural do texto biblico','A aplicacao do principio depende apenas da interpretacao pessoal do leitor','O principio ensinado perde sua validade fora do contexto original do texto'),('FB13-L08-Q03','O que o autor quis dizer? Para quem escreveu? Com que propósito?','Qual o versículo? Qual o capítulo? Qual o livro?','Quem traduziu? Quando traduziu? Onde publicou?','Quantas palavras tem? Quantos versículos? Quantos capítulos?'),('FB13-L09-Q02','Porque o texto bíblico possui um só sentido, mas diversas aplicações legítimas','Porque a Bíblia contém sentidos contraditórios dados pelo próprio Deus','Porque cada passagem admite infinitas interpretações verdadeiras simultâneas','Porque os autores sagrados tinham intenções múltiplas e mutuamente opostas'),('FB13-L14-Q04','Reduzem a ambiguidade interpretativa e guiam o julgamento moral do leitor','Criam suspense narrativo e expectativa crescente ao longo do texto bíblico','Substituem a interpretação pessoal do leitor pela aceitação literal do texto','Introduzem ambiguidades propositais para testar a fé e a razão do leitor'),('FB13-L09-Q01','Sentido original foca o autor e sua época; aplicação foca o leitor atual.','Não há diferença; o sentido do texto é sempre o mesmo em qualquer época.','A aplicação atual é superior e substitui o sentido original do texto.','O sentido original se altera conforme a cultura de cada geração.'),('FB13-L14-Q03','Confrontando o comportamento com as Escrituras e o exemplo de Cristo.','Imitando todos os comportamentos narrados, pois toda a Bíblia é exemplar.','Baseando-se apenas no sentimento pessoal e na tradição local.','Copiando somente os exemplos do Antigo Testamento por terem prioridade.'),('FB13-L15-Q01','Promessa específica é contextual e particular; princípio geral é universal e atemporal.','Promessa específica é incondicional; princípio geral depende de méritos humanos.','Promessa específica só aparece no Antigo Testamento; princípio geral apenas no Novo.','Promessa específica é individual; princípio geral se aplica só a igrejas locais.'),('FB14-L01-Q04','A exegese aplica os princípios da hermenêutica ao texto bíblico','A exegese e a hermenêutica são disciplinas totalmente independentes e sem relação','A hermenêutica é apenas um sub-ramo da exegese, sem autonomia própria','Exegese trata apenas do Antigo Testamento, e a hermenêutica apenas do Novo'),('FB13-L17-Q03','Como o texto revela e aponta para Cristo, e se cumpre no NT?','Qual o contexto histórico e a datação do texto?','Que ensinamentos morais podemos extrair para a vida?','Quem é o autor humano e a quem o texto foi dirigido?'),('FB13-L14-Q05','Surge o legalismo e anula-se a graça revelada progressivamente nas Escrituras','Surge a justificação pela fé e a segurança eterna dos salvos em Cristo','Promove-se a centralidade da cruz e a suficiência das Escrituras para a vida','Estabelece-se a unidade da Igreja e a disciplina cristã no Novo Testamento'),('FB14-L01-Q05','Para que a pregação transmita fielmente a mensagem revelada nas Escrituras','Para que o pregador demonstre maior conhecimento teológico ao público','Porque a aplicação prática depende apenas da experiência pessoal do pregador','Para substituir a necessidade do estudo devocional e da oração pessoal')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB14-L02-Q01','Exegese extrai o sentido do texto; eisegese insere ideias nele.','Exegese é tradição oral; eisegese é tradição escrita da Igreja.','Exegese se aplica ao Antigo Testamento; eisegese ao Novo Testamento.','Exegese é tradução literal; eisegese é tradução dinâmica do texto.'),('FB14-L02-Q05','Analisar o contexto, estudar as línguas originais e aplicar a analogia da fé','Confiar apenas na iluminação pessoal durante a leitura devocional da Bíblia','Escolher previamente uma tese e buscar versículos que a confirmem','Interpretar cada passagem de modo isolado, sem considerar o livro inteiro'),('FB14-L02-Q04','Projeta no texto conclusões prévias em vez de extrair seu sentido original.','Busca exaustivamente o sentido literal das palavras no idioma original.','Usa apenas o método histórico-crítico rejeitando a inspiração divina.','Compara várias traduções para reconstruir fielmente o texto autógrafo.'),('FB14-L02-Q02','Analisando o texto em seu contexto histórico-gramatical e literário','Interpretando o texto apenas segundo o sentido alegórico e simbólico','Aplicando diretamente o texto à vida do leitor sem análise prévia','Usando exclusivamente traduções modernas para compreender o original'),('FB14-L02-Q03','Lê no texto suas próprias ideias, em vez de extrair o sentido original.','Extrai do texto seu significado por meio do contexto histórico e gramatical.','Compara versões bíblicas para identificar variantes textuais relevantes.','Aplica princípios hermenêuticos tradicionais para atualizar a mensagem.'),('FB14-L03-Q01','Determinar os limites de uma perícope ou unidade literária bíblica.','Traduzir fielmente o texto bíblico de seus idiomas originais.','Separar os livros canônicos dos apócrifos e deuterocanônicos.','Interpretar alegoricamente cada versículo da Escritura Sagrada.'),('FB14-L03-Q02','Pela mudança de cenário, personagem, tempo ou tema, e por marcadores como inclusio.','Pelo número exato de versículos atribuídos a cada autor bíblico da Bíblia.','Através da divisão fixa em capítulos e versículos estabelecida no século XVI.','Pela contagem manual de sílabas poéticas em cada passagem do texto sagrado.'),('FB14-L03-Q05','Desconecta o texto do contexto, atribuindo sentido alheio à intenção do autor.','Modifica o sentido ao trocar a versão da tradução utilizada no texto bíblico.','Acrescenta ou exclui versículos que se mostram repetidos dentro da narrativa.','Reorganiza os livros sagrados, alterando a sequência dentro do cânon bíblico.'),('FB14-L03-Q03','NAO SEI','Destacam a unidade teologica do texto','Marcam a transicao entre aliancas biblicas','Indicam a presenca de generos literarios distintos'),('FB14-L04-Q02','No início da análise, como passo preparatório','Durante a interpretação exegética do texto','Na fase final de aplicação prática','Apenas na etapa de correlação bíblica'),('FB14-L04-Q03','NAO SEI','Estrutura geral, termos-chave e ideias principais do texto','Contexto historico, geografico e cultural da passagem','Conexoes entre paragrafos, contrastes e paralelismos'),('FB14-L04-Q04','A releitura aprofunda a compreensão e revela os argumentos centrais do texto.','A leitura repetida ajuda a memorizar apenas trechos específicos do texto.','Aumenta a velocidade de leitura ao reduzir a necessidade de interpretação.','Facilita apenas a identificação de erros gramaticais presentes na escrita.'),('FB14-L05-Q02','Deve ser a primeira etapa da análise da passagem','Após a aplicação prática do texto à comunidade','Somente na fase final da análise exegética','Durante a etapa de revisão homilética do sermão'),('FB14-L05-Q01','Identificação do gênero literário do texto bíblico para sua correta interpretação.','Análise do gênero gramatical (masculino ou feminino) das palavras bíblicas.','Identificação do sexo do autor humano do texto bíblico na interpretação.','Verificação da coerência textual da tradução bíblica entre os idiomas.'),('FB14-L05-Q03','Vocabulário, estrutura, contexto histórico e convenções literárias do texto.','Apenas o número de capítulos e versículos do livro bíblico.','Somente o nome do autor inspirado do texto sagrado.','Exclusivamente a quantidade de palavras repetidas no texto.'),('FB14-L05-Q04','NAO SEI','O gênero textual determina o vocabulário e a gramática utilizados pelo autor','A identificação do gênero permite conhecer o autor e a data de composição do texto','O gênero textual é definido apenas pela extensão e quantidade de parágrafos do texto'),('FB14-L06-Q02','Deve ser considerada em primeiro lugar, antes de outras análises','Deve ser feita somente após a análise gramatical detalhada','Somente na etapa final, como aplicação prática','Apenas após o estudo de palavras-chave no original'),('FB14-L06-Q04','O contexto revela o propósito do autor e o argumento central do texto.','O contexto bíblico é irrelevante para identificar a mensagem central do texto.','Apenas o versículo isolado, sem contexto, revela a ideia central do autor.','A análise de contexto substitui a necessidade de oração no estudo bíblico.'),('FB14-L06-Q03','Contexto histórico, cultural, literário, gramatical e as passagens paralelas','Somente a tradução do texto na versão Almeida Revista e Corrigida','Apenas as opiniões dos reformadores protestantes do século XVI','Exclusivamente a data de escrita e o autor humano de cada livro'),('FB14-L07-Q02','Logo no início da análise da passagem.','Somente após a aplicação prática.','Apenas no final da interpretação.','Depois da aplicação pessoal ao leitor.'),('FB14-L06-Q05','Evitar eisegese, anacronismo e descontextualização do texto bíblico','Confiar exclusivamente na Almeida Revista e Corrigida para toda análise','Subordinar o contexto bíblico à tradição eclesiástica estabelecida','Aplicar unicamente o método devocional sem rigor exegético'),('FB14-L07-Q03','Repetições, inclusões, paralelismos, conectivos e termos-chave','Contexto histórico, cultural e geográfico do autor bíblico','Significado original das palavras no grego e no hebraico','Aplicações práticas e princípios para a vida cristã atual'),('FB14-L08-Q01','Repetição lexical que evidencia ênfase temática no texto bíblico','Paralelismo sinonímico que expressa ideias equivalentes no versículo','Quiasmo estrutural que organiza ideias em forma invertida e simétrica','Aliteração sonora que produz ritmo por repetição de fonemas'),('FB14-L08-Q02','Na fase de observação','Na fase de aplicação','Na fase de interpretação','Antes da leitura do texto'),('FB14-L08-Q03','NAO SEI','Contexto historico e cultural da epoca','Autoria e destinatarios originais do texto','Relacao com outras passagens paralelas'),('FB14-L04-Q01','Leitura atenta e múltipla do texto bíblico para captar seu sentido','Crítica textual das variantes dos manuscritos gregos','Leitura devocional para edificação espiritual do crente','Interpretação alegórica do sentido espiritual figurado'),('FB14-L08-Q05','NAO SEI','Ignorar o contexto historico-cultural do texto original','Aplicar a palavra repetida sem considerar o genero literario','Confundir repeticao estilistica com duplicidade de conteudo'),('FB14-L08-Q04','NAO SEI','Palavras repetidas indicam que o autor possui vocabulario limitado','Palavras repetidas sao erros gramaticais do autor','Palavras repetidas demonstram que o texto é traduzido'),('FB14-L09-Q01','São elementos gramaticais que conectam orações e estruturam o raciocínio do autor.','Divisões de capítulos e versículos criadas pelos tradutores da Bíblia.','Figuras de linguagem usadas para embelezar poeticamente o texto bíblico.','Códigos numéricos ocultos no texto para revelar profecias futuras.'),('FB14-L09-Q03','NAO SEI','O contexto histórico e cultural do texto bíblico','A autoridade apostólica dos escritos do Novo Testamento','A coerência com a tradição da igreja primitiva'),('FB14-L09-Q04','NAO SEI','Por meio da inspiração divina do autor sagrado','Através da análise literal do texto hebraico','Pela comparação entre traduções antigas'),('FB14-L10-Q02','Como primeiro passo na análise interpretativa da passagem','Após a análise teológica da passagem','Somente no final do estudo da passagem','Apenas quando há dificuldades textuais'),('FB14-L10-Q01','Estudo das palavras, formas e estruturas sintáticas nas línguas originais','Análise do contexto histórico e cultural em que o texto foi escrito','Interpretação alegórica baseada no sentido espiritual das Escrituras','Tradução literal do texto bíblico para idiomas contemporâneos'),('FB14-L10-Q04','NAO SEI','A analise gramatical identifica apenas erros ortograficos do texto, sem relevancia para a ideia central.','A analise gramatical substitui a interpretacao teologica na compreensao do texto biblico.','A analise gramatical serve somente para classificar verbos em textos liturgicos.'),('FB14-L09-Q02','Na interpretação','Na observação','Na aplicação','No contexto histórico'),('FB14-L09-Q05','NAO SEI','Falacia de peticao de principio e generalizacao apressada','Apelo a autoridade sem fundamentacao textual biblica','Equivocacao e falso dilema na exegese'),('FB14-L11-Q01','Estudo do contexto histórico, cultural e social em que o texto bíblico surgiu.','Análise gramatical das palavras e estruturas linguísticas do texto sagrado.','Aplicação prática e devocional do texto para a vida do leitor moderno.','Comparação de manuscritos para estabelecer o texto original mais confiável.'),('FB14-L11-Q02','Deve ser a primeira etapa, antes da gramatical e teológica.','Deve ser feita somente após a análise teológica da passagem.','Apenas ao analisar textos do Antigo Testamento bíblico.','Somente em passagens de natureza profética e apocalíptica.'),('FB14-L11-Q03','Manuscritos, evidências arqueológicas e contexto histórico-cultural','Apenas interpretações teológicas contemporâneas','Somente opiniões pessoais do pesquisador','Exclusivamente tradições orais sem registro escrito'),('FB14-L11-Q04','Contextualiza o texto em seu cenário original, revelando a intenção do autor.','Analisa somente a gramática do texto para descobrir a mensagem central ao leitor.','Identifica os temas teológicos, desconsiderando o contexto histórico-cultural.','Aplica o texto à realidade contemporânea, ignorando o cenário histórico original.'),('FB14-L11-Q05','Anacronismo, falta de contexto histórico-cultural e leituras seletivas','Aceitar a tradição oral sem qualquer verificação documental','Priorizar dogmas confessionais sobre evidências textuais','Aplicar categorias filosóficas modernas a textos antigos'),('FB14-L12-Q01','Estudo do contexto cultural da época para interpretar corretamente o texto bíblico','Análise dos manuscritos originais para reconstruir o texto bíblico','Estudo das figuras de linguagem e estruturas literárias do texto','Aplicação dos princípios bíblicos à cultura contemporânea'),('FB14-L12-Q02','No início, na primeira fase da exegese do texto','Na última fase, após a aplicação prática da passagem','Somente após a análise gramatical e sintática detalhada','Apenas quando surgem termos culturalmente desconhecidos'),('FB14-L12-Q04','NAO SEI','Revela os valores e crenças do autor e do público original','Permite comparar o texto com outras obras do mesmo período','Ajuda a identificar símbolos e metáforas culturais do texto'),('FB14-L10-Q05','NAO SEI','Ignorar a sintaxe e focar apenas no vocabulario isolado','Confundir a voz ativa com a passiva sem marcadores claros','Aplicar categorizacoes modernas sem base nos textos originais'),('FB14-L12-Q03','NAO SEI','Privar os pobres e oprimir os fracos','Construir templos e oferecer sacrificios','Multiplicar os rebanhos e as colheitas'),('FB14-L12-Q05','Etnocentrismo, anacronismo e ausência de contexto histórico-cultural','Fundamentalismo, literalismo e dogmatismo teológico','Subjetivismo, relativismo e individualismo metodológico','Sincretismo, hibridismo e pluralismo cultural'),('FB14-L13-Q01','Análise do texto bíblico em várias traduções para compreensão do sentido original','Exame dos manuscritos gregos e hebraicos para estabelecer o texto correto','Estudo do contexto histórico e cultural em que o texto bíblico foi produzido','Aplicação do significado teológico do texto bíblico à vida prática do leitor'),('FB14-L13-Q04','NAO SEI','Permite identificar variantes textuais e suas implicações teológicas','Ajuda a reconhecer o genero literario do texto biblico','Facilita a memorizacao dos versiculos principais'),('FB14-L13-Q02','Na etapa gramatical, após análise sintática','Na etapa inicial de observação do texto','Antes de qualquer análise do original','Apenas na fase final de aplicação'),('FB14-L13-Q03','Os textos nas línguas originais, o contexto histórico-cultural e as notas de tradução','Apenas a tradução em português mais popular entre os leitores leigos','Somente as versões ecumênicas sem análise crítica textual','Exclusivamente os comentários pastorais e homilias sobre o texto'),('FB14-L14-Q01','Busca do significado original das palavras bíblicas em dicionários especializados.','Tradução do texto bíblico para línguas modernas pelos estudiosos.','Análise da estrutura gramatical e sintática do texto sagrado.','Estudo do contexto histórico e cultural das passagens bíblicas.'),('FB14-L14-Q02','Na observação, ao deparar com termos desconhecidos','Apenas na fase final, antes da aplicação','Antes de iniciar a leitura do texto bíblico','Somente na fase de interpretação'),('FB14-L14-Q04','Esclarecer o sentido das palavras ajuda a compreender a ideia central do texto.','O dicionário substitui a leitura, tornando desnecessária a análise completa do texto.','O dicionário serve apenas para verificar a ortografia correta das palavras escritas.','Consultar dicionários ajuda a decorar trechos específicos para memorização em provas.'),('FB14-L14-Q05','Aceitar apenas a primeira acepcao e desconsiderar o contexto historico-cultural','Ler todas as paginas do dicionario antes de pesquisar o termo','Consultar somente dicionarios nao teologicos para termos biblicos','Memorizar integralmente o dicionario antes de estudar a Biblia'),('FB14-L14-Q03','O significado da palavra nos idiomas originais e seus diversos sentidos biblicos','A genealogia completa dos autores que empregaram o termo nas Escrituras','Somente a datação historica e geografica do vocabulo no periodo biblico','Apenas as variantes textuais nos diferentes manuscritos gregos e hebraicos'),('FB14-L15-Q02','Após a análise pessoal independente da passagem','Antes de qualquer leitura do texto bíblico','Durante a etapa inicial de observação','No começo da interpretação da passagem'),('FB14-L15-Q01','Consultar comentários bíblicos para compreender o significado do texto','Analisar as línguas originais hebraica e grega para traduzir o texto','Aplicar as Escrituras à vida prática dos crentes na atualidade','Investigar o contexto histórico e cultural do mundo bíblico antigo'),('FB14-L15-Q05','NAO SEI','Ler apenas comentários de uma única tradição denominacional','Ignorar o texto bíblico e basear-se só no comentário','Consultar comentários sem considerar o contexto histórico-cultural'),('FB14-L13-Q05','Tratar a tradução como se fosse o texto bíblico original','Não conferir a versão utilizada nas citações acadêmicas','Usar traduções sem verificar a data da revisão textual','Preferir paráfrases em vez de traduções formais'),('FB14-L16-Q01','O tema principal do texto bíblico','O contexto histórico da passagem','O gênero literário do escrito','A estrutura gramatical do versículo'),('FB14-L16-Q02','Observe o contexto: assunto é o tema; afirmação é a tese defendida pelo autor.','O assunto geral e a afirmação principal são exatamente a mesma coisa.','Basta ler o título do livro para identificar ambos os elementos.','A afirmação principal está sempre no último versículo do texto.'),('FB14-L16-Q03','NAO SEI','A repetição de palavras-chave ao longo do texto','O título da obra e sua relação com o conteúdo','A frase de conclusão que sintetiza os argumentos'),('FB14-L16-Q04','Para expressar com fidelidade a mensagem do texto bíblico em sua totalidade.','Para impressionar o ouvinte com vocabulário erudito e sofisticado.','Para substituir a leitura completa e devocional das Escrituras.','Para evitar o estudo aprofundado do contexto histórico e cultural.'),('FB14-L15-Q03','Contexto histórico-cultural, texto original, intenção do autor e análise gramatical.','Somente a opinião pessoal do comentarista moderno sobre o texto bíblico.','Apenas as traduções modernas em português sem análise do original.','Exclusivamente as notas de rodapé e sem considerar o contexto bíblico.'),('FB14-L16-Q05','A ideia central governa o esboço, a aplicação e a exposição, mantendo unidade na pregação do texto','O esboço do texto controla a ideia central, que se adapta à estrutura e divisão das partes','As necessidades dos ouvintes determinam a ideia central antes de qualquer exposição bíblica','O versículo-chave define a aplicação e o esboço, sem depender de uma ideia central fixa'),('FB14-L17-Q01','A identificação da mensagem teológica central do texto bíblico em seu contexto literário e histórico.','A análise gramatical detalhada de cada palavra e verbo do versículo original.','A comparação de manuscritos antigos para reconstruir o texto original fielmente.','A aplicação prática do texto à vida do leitor contemporâneo em sua devoção.'),('FB14-L17-Q02','No final da análise, após a exegese do texto','No início da análise, antes da leitura','Durante o estudo de palavras-chave apenas','Antes de considerar o contexto histórico'),('FB14-L17-Q03','Contexto histórico, literário, gramatical, canônico e a intenção do autor','Apenas a gramática do texto e o significado das palavras originais','Somente o contexto histórico e as evidências arqueológicas','Unicamente a opinião de comentaristas e teólogos contemporâneos'),('FB14-L18-Q02','Após a interpretação, como etapa final da análise','Antes de qualquer leitura inicial do texto bíblico','Apenas no momento da pregação, fora do estudo','Em substituição à exegese do texto original'),('FB14-L18-Q03','NAO SEI','O contexto historico e cultural do texto original','A gramatica e sintaxe do idioma original','A analogia da fe e as referencias cruzadas'),('FB14-L17-Q04','Revelando os temas teologicos que sustentam a argumentacao do autor','Anulando a relevancia do genero literario do texto biblico','Garantindo uma unica interpretacao valida da passagem','Substituindo a necessidade de consulta ao texto original'),('FB14-L18-Q01','Aplicar o sentido original do texto à vida do leitor moderno','Inserir opiniões pessoais no texto bíblico sem base exegética','Interpretar alegoricamente cada passagem das Escrituras Sagradas','Substituir o contexto histórico por ideias contemporâneas'),('FB14-L19-Q02','A exposição deve girar em torno da ideia central, com tudo subordinado a ela.','A exposição deve seguir a ordem dos versículos, sem priorizar nenhum ponto.','A exposição deve apresentar todas as interpretações possíveis sem assumir uma.','A exposição deve iniciar pelas aplicações práticas antes de explicar o texto.'),('FB14-L19-Q03','NAO SEI','Captar atenção, explicar o texto e fazer a aplicação prática','Contextualizar historicamente, dividir em pontos e resumir a mensagem','Apresentar o tema, desenvolver argumentos e fechar com exortação'),('FB14-L18-Q04','Auxilia na compreensão do sentido original, garantindo aplicação fiel ao contexto.','Consiste em aplicar o texto sem considerar o contexto histórico-cultural.','Baseia-se apenas na opinião pessoal do leitor sobre o trecho bíblico.','Ignora a intenção do autor original em favor de aplicações atuais.'),('FB14-L19-Q05','NAO SEI','Identificar o principio teologico central e derivar implicacoes praticas para a vida do leitor','Aplicar o texto diretamente sem considerar o contexto cultural original','Usar o texto como pretexto para transmitir ensinamentos moralistas atuais'),('FB14-L18-Q05','Subjetivismo, descontextualização, alegorização e falta de base exegética','Contextualização histórica, análise do gênero e progressão revelacional','Interpretação literal, estudo lexical e comparação de traduções','Leitura devocional, meditação pessoal e estudo comunitário'),('FB14-L19-Q04','NAO SEI','Através do método devocional, priorizando a experiência pessoal sobre o texto','Usando apenas a interpretação alegórica como base principal de ensino','Aplicando exclusivamente o contexto histórico, sem análise gramatical'),('FB14-L19-Q06','A mensagem não depende do texto; ideias vêm de fora dele','Pregador usa a versão Almeida Revista e Corrigida como base','Sermão contém aplicações práticas para o cotidiano','Exposição segue a estrutura gramatical do texto bíblico'),('FB14-L19-Q01','Expor o sentido original do texto, segundo o contexto e a analogia da fe.','Priorizar revelacoes pessoais e impressoes espirituais acima do texto biblico.','Adaptar a mensagem conforme os sentimentos e as necessidades da congregacao.','Usar o texto apenas como ponto de partida para temas contemporaneos.'),('FB15-L03-Q05','Variantes significativas exigem decisão de tradução e nota de aparato crítico','Variantes textuais não possuem implicação relevante para traduções modernas','Somente variantes do Textus Receptus merecem nota textual nas traduções','Notas textuais devem ocultar variantes para não confundir os leitores'),('FB15-L05-Q05','Exigem rigor crítico e transparência nas notas textuais das traduções modernas.','Facilitam a tradução ao eliminar ambiguidades do texto bíblico.','Permitem ignorar variantes na constituição do texto crítico.','Reduzem a necessidade de aparato crítico nas edições atuais.'),('FB15-L06-Q02','Manuscritos mais antigos são mais confiáveis, pois estão mais próximos do texto original','Manuscritos mais antigos são menos confiáveis por estarem deteriorados','A idade do manuscrito não interfere em sua avaliação textual','Manuscritos mais recentes são sempre mais fiéis ao texto original'),('FB15-L06-Q01','Testemunho dos manuscritos e versões que sustentam uma variante textual.','Análise do vocabulário e do estilo do autor para julgar a leitura.','Probabilidade de o copista ter alterado o texto por erro ou tendência.','Avaliação da coerência teológica e literária do texto examinado.'),('FB15-L06-Q03','Indica maior antiguidade, pois precede as divisões geográficas das igrejas.','Determina a inspiração divina do texto por meio do consenso regional entre igrejas.','Garante a precisão absoluta da tradução para todos os idiomas modernos falados.','Limita a autoridade escriturística apenas às regiões geográficas de origem.'),('FB15-L06-Q04','Considerando a qualidade textual e a relação genealógica dos manuscritos.','Pela inspiração divina e autoridade profética dos autores bíblicos.','Pela inclusão no cânon e a aprovação dos concílios ecumênicos.','Pela tradução para línguas vernáculas e sua aceitação popular.'),('FB15-L07-Q02','Crítica textual','Hermenêutica bíblica','Crítica de fontes','Formação do cânon'),('FB15-L06-Q05','Copistas tendiam mais a acrescentar do que a omitir; expansoes se multiplicaram','Leituras mais longas sempre foram mais fieis as palavras dos apostolos originais','A quantidade de manuscritos garante diretamente a exatidao do texto em todas epocas','Textos expandidos preservam melhor o sentido original das Escrituras Sagradas'),('FB15-L07-Q03','Para eliminar dificuldades, harmonizar paralelos ou esclarecer ambiguidades','Por revelação profética direta concedida aos copistas antigos','Para adequar o texto sagrado às leis do Império Romano','Devido à obrigação monástica de revisar manuscritos anualmente'),('FB15-L07-Q01','Evidência do próprio texto, baseada no estilo do autor e tendências dos copistas.','Evidência obtida da comparação entre manuscritos e versões bíblicas antigas.','Critério usado para determinar quais livros devem fazer parte do cânon bíblico.','Análise das fontes literárias utilizadas pelo autor bíblico na composição.'),('FB15-L08-Q02','Evidência externa','Evidência interna','Evidência arqueológica','Evidência literária'),('FB15-L07-Q05','Copistas simplificam; assim, a leitura mais difícil tende a ser a original.','Copistas hábeis introduziam variantes complexas por zelo devocional.','Leituras difíceis são erros tardios de tradução para o grego.','O texto difícil indica menor domínio linguístico do autor original.'),('FB15-L08-Q03','Manuscritos mais antigos têm prioridade por estarem mais próximos do original.','Os manuscritos mais recentes são preferidos por terem menor número de cópias.','A data do manuscrito é irrelevante; apenas a versão vernácula é considerada.','Manuscritos medievais têm autoridade absoluta sobre os textos mais antigos.'),('FB15-L08-Q04','A idade não garante fidelidade textual; variantes exigem análise interna e comparativa.','Manuscritos mais antigos são sempre os mais confiáveis em qualquer tradição textual.','A datação por si só já define a superioridade do texto, sem análise de variantes.','Somente a idade determina a qualidade textual entre os manuscritos disponíveis.'),('FB15-L09-Q01','O estudo da propagação dos manuscritos e leituras textuais pelas diversas regiões','A divisão dos livros bíblicos conforme o país onde foram originalmente escritos','O processo de tradução da Bíblia para os idiomas locais de cada região','A separação dos textos segundo as rotas comerciais de transporte dos manuscritos'),('FB15-L09-Q02','Evidência geográfica','Evidência textual','Evidência arqueológica','Evidência profética'),('FB15-L08-Q05','Textos mais antigos permitem reconstruções mais fiéis aos originais','Manuscritos recentes são mais confiáveis por terem menor desgaste','A idade dos manuscritos é irrelevante para o trabalho textual','Traduções modernas rejeitam toda evidência de manuscritos antigos'),('FB15-L07-Q04','Auxiliam na identificação do gênero literário e do contexto do texto.','Tornam dispensável a consulta ao texto bíblico em sua língua original.','Impedem qualquer interpretação figurada ou simbólica da passagem.','Eliminam a influência do contexto histórico e cultural do autor.'),('FB15-L09-Q04','Não garante origem apostólica nem a antiguidade do manuscrito','Garante a autenticidade e a inspiração plena do texto bíblico','É o critério mais decisivo para comprovar a canonicidade','Confirma a veracidade histórica e a infalibilidade doutrinária')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB15-L09-Q03','Ajuda a rastrear a propagação geográfica, indicando leituras mais antigas','Determina quais textos são canônicos e devem ser aceitos','Quanto mais restrita a região, mais antiga é a leitura','É usado para identificar a língua original do texto'),('FB15-L10-Q02','Evidência externa','Evidência interna','Evidência histórica','Evidência canônica'),('FB15-L09-Q05','NAO SEI','...','...','...'),('FB15-L08-Q01','Distância cronológica entre os autógrafos e as cópias preservadas.','Tempo de degradação física dos pergaminhos e papiros ao longo dos séculos.','Período histórico em que o cânon bíblico foi oficialmente definido pelos concílios.','Intervalo de tempo exigido para traduzir as Escrituras para idiomas antigos.'),('FB15-L10-Q01','Grupos de manuscritos que compartilham características textuais comuns de transmissão.','Livros reconhecidos como inspirados e incluídos no cânon bíblico.','Classificação dos livros bíblicos por gênero, como narrativo ou profético.','Versões da Bíblia traduzidas em diferentes idiomas ao longo da história.'),('FB15-L10-Q03','Agrupam manuscritos com variantes comuns para identificar a leitura mais antiga','Comprovam que todas as variantes textuais sao igualmente corretas','Sao usadas apenas para fins de traducao biblica moderna','Eliminam a necessidade de consultar os papiros mais antigos'),('FB15-L11-Q01','Texto apoiado pela maioria dos manuscritos gregos do Novo Testamento.','Texto baseado nos manuscritos mais antigos, como os do século II.','Texto publicado por Erasmo em 1516, conhecido como Textus Receptus.','Texto reconstruído por métodos de crítica literária e histórica.'),('FB15-L10-Q05','Guiam decisões tradutórias e fundamentam variantes registradas nas notas textuais','Substituem completamente o texto original nas edições modernas atuais','Eliminam por completo a necessidade de notas de rodapé bíblicas','Garantem a total uniformidade entre todas as versões traduzidas'),('FB15-L11-Q02','evidência externa','evidência interna','evidência de versões antigas','evidência arqueológica'),('FB15-L11-Q03','Preferindo-se a leitura sustentada pelo maior número de manuscritos','Rejeitando-se as variantes apoiadas por manuscritos mais antigos','Aceitando-se somente a leitura do cânon ocidental sem análise','Ignorando-se a idade dos testemunhos em favor da quantidade'),('FB15-L11-Q05','Fundamenta traduções baseadas no Textus Receptus e nas leituras mais longas','Apoia traduções baseadas somente no Códice Vaticano e em leituras breves','Desconsidera por completo o testemunho dos manuscritos na composição das notas','Impõe o uso prioritário da Septuaginta em traduções modernas das Escrituras'),('FB15-L12-Q03','NAO SEI','O texto recebido serve como base fixa para descartar todas as variantes','As leituras diferentes são ignoradas em favor do texto recebido','O texto recebido é substituído pela leitura mais antiga encontrada'),('FB15-L12-Q01','Texto grego do NT editado por Erasmo em 1516, base de traducoes protestantes.','Traducao grega do AT realizada em Alexandria, usada pela Igreja Primitiva.','Versao latina da Biblia feita por Jeronimo no seculo IV para a Igreja Ocidental.','Texto hebraico do AT fixado pelos massoretas, base da Biblia Hebraica Stuttgartensia.'),('FB15-L12-Q02','Evidência textual','Evidência arqueológica','Evidência científica','Evidência profética'),('FB15-L11-Q04','Não considera variantes de manuscritos mais antigos nem evidência interna','É o critério mais confiável pois reflete a tradição eclesial uniforme','Só pode ser aplicado quando não há manuscritos gregos disponíveis','Depende exclusivamente da aprovação do concílio ecumênico de Trento'),('FB15-L13-Q01','Texto reconstruído pelos críticos com base nos manuscritos mais antigos.','O próprio texto original escrito pelos autores bíblicos.','Tradução oficial das Escrituras em línguas modernas pelos críticos.','Comentário teológico explicativo sobre o sentido das Escrituras.'),('FB15-L13-Q03','Analisa variantes manuscritas para determinar a leitura mais provável do original.','Traduz os textos originais para a língua vernácula dos leitores.','Seleciona os livros que devem compor o cânon das Escrituras.','Comprova a historicidade dos eventos narrados nas Sagradas Escrituras.'),('FB15-L13-Q04','NAO SEI','A inspiração verbal e plenária das Sagradas Escrituras','O testemunho unânime dos Pais da Igreja primitiva','A autoridade dogmática definida no Concílio de Trento'),('FB15-L13-Q05','Fundamenta decisões tradutórias e o registro de variantes nos aparelhos críticos','Garante a inspiração verbal de cada palavra do texto traduzido','Elimina a necessidade de consulta a manuscritos antigos','Impede qualquer divergência entre versões modernas'),('FB15-L12-Q05','Aponta variantes textuais que fundamentam notas e escolhas de tradução','Assegura superioridade absoluta do Textus Receptus sobre manuscritos críticos','Impede a divulgação de variantes em edições modernas traduzidas','Substitui critérios filológicos por revelação direta do tradutor'),('FB15-L14-Q03','NAO SEI','Papiros, unciais e minúsculas','Códices, lecionários e versões antigas','Citações patrísticas e inscrições'),('FB15-L14-Q04','NAO SEI','Colocam o texto entre colchetes duplos para indicar passagem duvidosa','Incluem nota de rodape apontando ausencia nos manuscritos mais antigos','Sublinham a passagem com tomate indicando variante textual'),('FB15-L14-Q06','NAO SEI','Contextualizando historicamente o texto sagrado em seu cenário original','Aplicando os princípios escriturísticos à vida contemporânea do ouvinte','Expondo o sentido gramatical e teológico do trecho bíblico selecionado'),('FB15-L14-Q05','NAO SEI','A justificação pela fé e a santificação progressiva do crente.','A divindade de Cristo e a obra expiatória na cruz do Calvário.','A inspiração verbal da Escritura e a suficiência das Escrituras.'),('FB15-L14-Q01','Marcos 16:9-20','Marcos 15:40-47','Marcos 14:62-72','Marcos 13:1-37'),('FB15-L19-Q05','NAO SEI','Todas as variantes devem ser incorporadas ao texto principal sem distinção','Notas textuais devem incluir apenas conjecturas editoriais sem base manuscrita','Traduções modernas devem abandonar completamente o uso de manuscritos antigos'),('FB15-L17-Q03','NAO SEI','Comparando-se as leituras com manuscritos mais antigos','Avaliando o peso da evidência externa dos testemunhos','Aplicando o princípio da lectio difficilior potior'),('FB16-L01-Q01','22 letras','24 letras','26 letras','27 letras'),('FB15-L14-Q02','Os manuscritos mais antigos terminam o evangelho no versículo 8','Contradiz a teologia do restante do evangelho','Foi acrescentado por decisão do Concílio de Trento','Contém relatos que contradizem os demais evangelhos'),('FB16-L01-Q03','Kaf, Mem, Nun, Pe e Tsade','Alef, Bet, Gimel, Dalet e He','Somente Kaf, Mem e Nun','Todas as 22 letras do alfabeto'),('FB16-L02-Q01','Da direita para a esquerda','Da esquerda para a direita','De cima para baixo em colunas','Bidirecional, da direita ou da esquerda'),('FB16-L02-Q02','NAO SEI','A escrita vertical sempre segue de cima para baixo e da esquerda para a direita','Letras são organizadas em colunas paralelas da direita para a esquerda','Palavras são lidas em espiral a partir do centro da página'),('FB16-L02-Q05','NAO SEI','Para ler corretamente o hebraico bíblico antes de analisar sua gramática','Porque a gramática depende apenas do vocabulário prévio','Para memorizar os mandamentos antes da análise sintática'),('FB16-L03-Q02','Pelas 22 letras consoantes que compõem a raiz triliteral das palavras','Pela inclusão de sinais vocálicos no texto consonântico primitivo','Pelos acentos massoréticos fixados junto às consoantes originais','Pela tradução para o grego presente na Septuaginta'),('FB16-L03-Q03','NAO SEI','Representar exclusivamente os sons nasais da fala','Indicar as pausas ritmicas entre as silabas tonicas','Bloquear totalmente a vibracao das cordas vocais'),('FB16-L03-Q04','A consoante "p" aparece na palavra "pão" como exemplo.','A vogal "a" é classificada como consoante na palavra "pata".','Consoantes produzem sons sem qualquer obstrução aérea.','A palavra "aia" contém apenas consoantes em sua formação.'),('FB16-L04-Q02','Para preservar a correta pronúncia e leitura do texto hebraico','Para facilitar a tradução do texto para o idioma grego antigo','Para diferenciar as versões protocanônicas das deuterocanônicas','Para registrar as variações encontradas nos Manuscritos do Mar Morto'),('FB16-L04-Q04','Abaixo das consoantes','Acima das consoantes','Antes das consoantes','Depois das consoantes'),('FB16-L04-Q03','Escribas judeus responsáveis pela preservação do texto massorético','Apóstolos que escreveram os Evangelhos do Novo Testamento','Profetas que anunciaram as mensagens divinas no Antigo Testamento','Líderes religiosos que combateram Jesus durante seu ministério'),('FB16-L05-Q01','A leitura das 22 consoantes com sinais vocálicos massoréticos','A leitura das 24 consoantes do alfabeto grego bíblico','A pronúncia baseada em 27 letras consoantes hebraicas','A leitura das 22 consoantes do alfabeto aramaico targúmico'),('FB16-L04-Q05','O consonantal possui só consoantes; o massorético acrescenta sinais vocálicos','O texto consonantal é em grego e o massorético em hebraico','O consonantal é canônico e o massorético é considerado apócrifo','O consonantal pertence ao Antigo Testamento e o massorético ao Novo'),('FB16-L05-Q03','NAO SEI','Desempenha funcao de verbo principal na oracao','Funciona como conjuncao coordenativa adverbial','Exerce papel de adverbio de intensidade'),('FB16-L03-Q01','As 22 letras do alfabeto hebraico bíblico, originalmente escrito sem vogais.','São os sinais de pontuação vocálicos criados pelos massoretas.','São os acentos musicais usados na leitura sinagogal das escrituras.','São as 27 letras do alfabeto hebraico moderno com inclusão de vogais.'),('FB16-L05-Q04','NAO SEI','O exemplo da arca de Noé mostra pronúncia básica','A pronúncia básica aparece na parábola do semeador','O nome Jeová demonstra pronúncia básica'),('FB16-L05-Q02','...','...','...','...'),('FB16-L06-Q01','NAO SEI','Derivação de raízes triconsonanticas por meio de prefixos e sufixos','Construção de vocabulário através de composicao de radicais','Processo de criacao de novos termos por analogia morfologica'),('FB16-L06-Q03','NAO SEI','Desempenha funcao sintatica de sujeito na oracao','Funciona como elemento de coesao textual entre paragrafos','Tem funcao fonologica de marcacao de acento tonico'),('FB16-L06-Q04','Infeliz, derivado de in- + feliz','O verbo ter conjugado no pretérito','O plural do substantivo cidadão','A sílaba tônica da palavra café'),('FB16-L05-Q05','A pronúncia distingue palavras hebraicas com consoantes idênticas.','A pronúncia correta revela os acentos musicais do texto sagrado.','O estudo da pronúncia facilita a memorização dos Salmos poéticos.','A pronúncia básica evita erros de concordância verbal na tradução.'),('FB16-L07-Q01','Palavras que designam pessoas, objetos ou ideias, com gênero e número','Palavras que indicam ações, estados ou processos no texto bíblico','Partículas que conectam orações e estabelecem relações entre termos','Termos invariáveis que qualificam verbos e adjetivos na narrativa'),('FB16-L06-Q05','Porque revela a estrutura semântica do hebraico e evita traduções imprecisas.','Porque auxilia na contagem dos versículos por capítulo em cada livro bíblico.','Porque dispensa o uso de dicionários e comentários teológicos no estudo.','Porque comprova que o hebraico deriva diretamente do idioma aramaico.'),('FB16-L07-Q04','NAO SEI','Deus criou o ceu e a terra','Jesus e o bom pastor','O Senhor e a minha rocha'),('FB16-L07-Q03','Nomear seres, objetos, sentimentos, ideias e estados','Indicar ações, estados e processos','Modificar ou qualificar um termo','Estabelecer relação entre duas palavras'),('FB16-L06-Q02','Por raízes triconsonantais (shoresh) combinadas com padrões vocálicos e afixos','Apenas pela vocalização massorética tardia sem sistema de raízes','Exclusivamente pela transliteração grega da Septuaginta','Somente pela gematria numérica sem padrões morfológicos'),('FB16-L08-Q01','O prefixo ha (הַ)','O sufixo hê final (הָ-)','A conjunção vav (וְ)','A preposição bet (בְ)'),('FB16-L08-Q02','É formado pelo prefixo ה (he) com vogal, no início da palavra','É formado pelo sufixo ה (he) anexado ao final da palavra','Pela duplicação da letra inicial por meio do dagesh forte','É indicado pela preposição ל (lamed) colocada antes da palavra'),('FB16-L08-Q03','Determinar o substantivo, individualizando-o ou tornando-o conhecido.','Flexionar o verbo em tempo, modo e pessoa na conjugação','Indicar a ação praticada pelo sujeito do predicado verbal','Estabelecer relação de posse entre dois termos da oração'),('FB16-L08-Q04','NAO SEI','um cordeiro pascal','Deus é amor','alguns discípulos'),('FB16-L09-Q01','Dois gêneros (masculino e feminino) e três números (singular, plural e dual).','Três gêneros (masculino, feminino e comum) e apenas dois números.','Gênero distingue animado e inanimado; número tem só singular e plural.','Quatro gêneros e quatro números derivados das raízes verbais.'),('FB16-L09-Q03','NAO SEI','Indicar a classe gramatical do substantivo','Determinar a posicao sintatica do verbo','Classificar o tipo de oracao do periodo'),('FB16-L09-Q04','NAO SEI','O substantivo ''Deus'' é masculino e invariável','Adjetivos concordam em gênero e número com o substantivo','A palavra ''espírito'' pode ser masculina ou feminina'),('FB16-L09-Q05','Garante fidelidade ao original e correta atribuição de sujeitos e ações no texto.','Permite identificar com precisão a data e o autor de cada livro bíblico.','Torna desnecessário consultar o texto hebraico para qualquer tradução bíblica.','Define quais livros pertencem exclusivamente ao cânon do Antigo Testamento.'),('FB16-L09-Q02','Pelas desinências de gênero e número nos vocábulos','Pelo acento tônico e entonação na leitura do texto','Pela ordem sintática das palavras na construção frasal','Pelos artigos definidos e indefinidos junto aos nomes'),('FB16-L14-Q05','Ordena alfabeticamente pelas raízes e detalha significados em cada binyan','Lista verbos em ordem de frequência nos textos bíblicos originais','Agrupa por categorias teológicas e apresenta etimologia comparada','Ordena por campo semântico dos radicais nominais derivados'),('FB16-L15-Q03','NAO SEI','Os tempos verbais indicam a época em que a ação ocorre','Os aspectos verbais expressam a duração da ação verbal','Tempos e aspectos são categorias gramaticais do verbo'),('FB16-L15-Q05','Porque o hebraico exprime aspecto, não tempo, evitando erros de interpretação.','Porque o hebraico usa tempos verbais idênticos aos do português.','Porque os tempos verbais sempre indicam a data exata do fato.','Porque a tradução literal dispensa qualquer análise gramatical.'),('FB16-L08-Q05','Porque distingue nomes definidos de indefinidos, alterando o sentido do texto.','Porque o artigo hebraico é decorativo e não interfere no sentido do texto.','Porque indica exclusivamente palavras de origem estrangeira no texto bíblico.','Porque substitui os pronomes pessoais ausentes na gramática hebraica bíblica.'),('FB16-L15-Q04','O contraste entre o presente ''grapho'' (eu escrevo) e o aoristo ''egrapsa'' (eu escrevi)','A comparacao entre o hebraico qatal e o wayyiqtol no AT','O uso do verbo ''eimi'' apenas no presente do indicativo','A distincao entre genero e numero no substantivo ''theos'''),('FB16-L16-Q03','Fundamenta a compreensão lexical e semântica das Escrituras','Decodifica profecias apocalípticas em linguagem acessível','Substitui o estudo das línguas bíblicas originais','Traduz automaticamente textos sagrados para o vernáculo'),('FB16-L16-Q02','Pelo sistema de raizes triliterais (shoresh) com padroes (binyanim)','Pela vocalizacao massoretica (niqqud) acrescentada posteriormente','Pelos acentos de cantilacao (taamei ha-mikra) que marcam ritmo','Pela divisao tradicional em parashot e capitulos'),('FB16-L17-Q04','Era escrito só com consoantes e o nome era sagrado demais para se pronunciar.','Porque os escribas erraram ao copiar as vogais nas escrituras sagradas.','O nome foi perdido quando os textos foram traduzidos para o grego.','Os fariseus proibiram o estudo da língua hebraica após o exílio.'),('FB17-L01-Q02','NAO SEI','Alfa, Beta, Gama, Delta, Épsilon, Zeta, Eta, Teta, Iota, Capa','Alfa, Ômega, Beta, Gama, Delta, Épsilon, Zeta, Eta, Teta, Iota','Beta, Gama, Delta, Épsilon, Zeta, Eta, Teta, Iota, Capa, Lambda'),('FB17-L01-Q03','Rô (ρ) e Qui (χ), por lembrarem P e X latinos','Alfa (α) e Beta (β), por iniciarem o alfabeto','Iota (ι) e Teta (θ), por terem hastes simples','Sigma (σ) e Xi (ξ), por terem formas angulares'),('FB17-L01-Q05','Permite ler o texto original e localizar termos nos léxicos e comentários.','Permite traduzir profecias apocalípticas sem auxílio externo.','Garante compreensão imediata do sentido espiritual das palavras.','Substitui o uso de léxicos e comentários nas pesquisas bíblicas.'),('FB17-L02-Q01','NAO SEI','Erasmiana, usada em seminarios e estudos academicos do NT','Moderna, baseada no grego contemporaneo falado na Grecia','Reconstruida, baseada em evidencias da Koine antiga'),('FB17-L02-Q03','NAO SEI','Distinguir palavras homófonas no texto bíblico','Indicar a função sintática do verbo na oração','Marcar o tempo verbal em hebraico antigo'),('FB17-L02-Q04','NAO SEI','as vogais longas e breves, o daguex e o shewa','os sinais de pontuação massorética e os acentos','as consoantes guturais e as labiais'),('FB17-L01-Q04','Maiúsculas marcam início de frases e nomes próprios; minúsculas, o resto.','Maiúsculas representam consoantes; minúsculas representam vogais no grego bíblico.','Não há distinção: maiúsculas e minúsculas têm forma idênticano grego antigo.','Maiúsculas indicam ênfase; minúsculas são a forma padrão nas cartas paulinas.'),('FB17-L02-Q02','Cada sílaba grega contém uma vogal ou ditongo','Os acentos gregos são irrelevantes na leitura','As consoantes podem formar sílabas sozinhas','A pronúncia grega não segue padrões definidos'),('FB17-L03-Q01','São marcas diacríticas (acentos e espíritos) que indicam pronúncia no grego.','São sinais de pontuação grega que indicam pausas e separações no texto bíblico.','São apenas marcas tônicas da língua grega sem qualquer valor fonético distinto.','São variantes textuais presentes em manuscritos gregos do Novo Testamento.'),('FB17-L02-Q05','Distingue homófonos gregos, acentos e pronúncia que afetam o sentido do texto','Facilita a memorização dos textos bíblicos na língua portuguesa atual','Permite comparar diretamente o grego do Novo Testamento com o hebraico','Dispensa completamente o uso de léxicos e comentários bíblicos na exegese'),('FB17-L03-Q03','NAO SEI','Indicar exclusivamente a pronúncia das consoantes hebraicas','Marcar apenas o ritmo musical da leitura sinagogal','Separar unicamente os versículos dos capítulos bíblicos'),('FB17-L03-Q02','Os acentos gregos indicam a sílaba tônica da palavra na pronúncia da frase.','Os acentos gregos marcam a duração das vogais longas e breves na frase grega.','Os sinais gregos indicam a obrigatoriedade de pausa entre sujeito e predicado.','Os acentos gregos diferenciam o tempo verbal dos verbos na construção frasal.'),('FB17-L04-Q01','Palavras que designam pessoas, objetos ou ideias, com casos, gêneros e números.','Verbos que indicam ações e estados, flexionados em tempos e modos verbais.','Adjetivos que qualificam substantivos, concordando em caso, gênero e número.','Advérbios que modificam verbos, adjetivos ou outros advérbios.'),('FB17-L04-Q02','é reconhecido pelo artigo definido e pelas desinências de caso','é identificado unicamente pela ordem das palavras na frase','se forma apenas por composição de verbos gregos','é reconhecido exclusivamente pelo acento tônico da palavra'),('FB17-L03-Q05','Acentos gregos distinguem palavras iguais e esclarecem o sentido original.','Acentos indicam a autoria e datação dos livros do Novo Testamento.','Sinais diacríticos revelam a inspiração divina do texto sagrado.','Acentos mostram quais textos são canônicos e quais são apócrifos.'),('FB17-L03-Q04','Contexto, posição, tipo e função gramatical do acento ou sinal','Apenas a função musical e o ritmo de leitura do texto bíblico','Somente a posição isolada do acento dentro da palavra grega','Exclusivamente o contexto histórico e a cultura da época'),('FB17-L04-Q03','Nomear e designar seres, objetos, ideias ou sentimentos','Flexionar-se somente no grau aumentativo sintético','Desempenhar exclusivamente a função de verbo de ligação','Atuar unicamente como pronome demonstrativo'),('FB17-L05-Q01','Nominativo, Genitivo, Dativo, Acusativo e Vocativo','Nominativo, Genitivo, Dativo, Acusativo e Ablativo','Sujeito, Complemento, Indireto, Direto e Predicativo','Nominativo, Possessivo, Dativo, Acusativo e Vocativo'),('FB17-L04-Q04','gênero, número, caso, contexto e uso literal ou figurado','tempo, modo, voz, aspecto e conjugação verbal','sujeito, predicado, objeto direto, indireto e adjunto adverbial','gênero, número, grau do adjetivo, voz passiva e conjugação'),('FB17-L05-Q02','NAO SEI','Indicar o sujeito da oracao','Indicar o objeto direto','Indicar o complemento indireto'),('FB17-L05-Q04','NAO SEI','O verbo concorda em gênero com o substantivo no caso nominativo','A terminação indica o tempo verbal da palavra','As desinências mostram a função sintática do verbo'),('FB17-L05-Q05','NAO SEI','O caso gramatical define a pronúncia da palavra','O caso gramatical indica a classe gramatical do vocábulo','O caso gramatical mostra a origem etimológica do termo'),('FB17-L06-Q02','Concordando em gênero, número e caso com o substantivo','Pela terminação uniforme -ος em qualquer contexto','Por aparecer exclusivamente no final da oração grega','Por ser invariável e totalmente independente do substantivo'),('FB17-L05-Q03','Posse e relação (gen.); objeto indireto e instrumento (dat.); objeto direto (ac.)','Sujeito e predicativo (nom.); vocativo (voc.); adjunto adnominal (gen.)','Posse e origem (gen.); adjunto adverbial e objeto direto (dat.); objeto indireto (ac.)','Sujeito e nome (nom.); posse e relação (gen.); objeto direto e indireto (ac.)'),('FB17-L06-Q03','NAO SEI','Designar objetos litúrgicos usados no tabernáculo','Indicar oferendas e dízimos entregues ao templo','Representar os bens e mercadorias dos hebreus'),('FB17-L07-Q01','Palavras que qualificam substantivos, concordando em caso, número e gênero.','Palavras invariáveis que modificam verbos, adjetivos ou outros advérbios.','Palavras que substituem os substantivos ou determinam seu sentido.','Palavras que exprimem ações, estados ou processos existentes na frase.'),('FB17-L06-Q01','Determinam os substantivos, indicando se são definidos','Conjugam os verbos indicando tempo, modo e aspecto verbal','Ligam palavras entre si expressando relações gramaticais','Qualificam os adjetivos modificando seu sentido na frase'),('FB17-L06-Q05','O artigo distingue definidos de indefinidos, esclarecendo sentido e ênfase.','O artigo grego não tem função no sentido do Novo Testamento.','Artigos servem apenas para identificar verbos no texto bíblico.','O artigo grego deve ser sempre omitido nas traduções bíblicas.'),('FB17-L07-Q03','Substantivar-se, exercendo função de substantivo','Flexionar-se em tempo e modo verbais','Desempenhar função exclusivamente adverbial','Concordar com o verbo em pessoa e número')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB17-L06-Q04','NAO SEI','...','...','...'),('FB17-L07-Q02','Concordam em gênero, número e caso com o substantivo modificado','Conjugam-se em pessoa, número e tempo verbal como verbos','São sempre flexionadas apenas no masculino plural','Aparecem sempre antes do substantivo sem qualquer flexão'),('FB17-L07-Q04','O substantivo modificado, o contexto e o grau do adjetivo','Apenas a posição do adjetivo na oração','Somente a terminação e o gênero do adjetivo','Exclusivamente o número singular ou plural'),('FB17-L08-Q03','de substantivo','de verbo','de preposição','de conjunção'),('FB17-L08-Q04','O antecedente, o contexto imediato e a relação sintática','Apenas a versão em português e a concordância verbal','A raiz hebraica e o número gramatical apenas','O significado literal e a etimologia da palavra'),('FB17-L08-Q01','Palavras que substituem o nome, indicando pessoas ou objetos sem nomeá-los.','Palavras que indicam ações, estados ou processos na narrativa bíblica.','Palavras que qualificam o nome, atribuindo-lhe características ou qualidades.','Palavras invariáveis que ligam termos e estabelecem relações sintáticas.'),('FB17-L08-Q05','Porque permite identificar corretamente a quem ou a que o texto se refere.','Porque os pronomes indicam o número exato de personagens em cada cena.','Porque facilita a memorização dos capítulos do Novo Testamento inteiro.','Porque os pronomes substituem todos os verbos nas orações do texto grego.'),('FB17-L07-Q05','Porque adjetivos qualificam substantivos, afetando sentido e exegese do texto.','Porque adjetivos são apenas recursos estilísticos sem impacto no significado.','Porque substituem os verbos nas construções gregas do Novo Testamento.','Porque indicam apenas a posição gramatical dos termos na frase original.'),('FB17-L09-Q03','Elemento de ligação entre dois termos da oração','Sujeito da oração composta','Predicado verbal do enunciado','Objeto direto do verbo principal'),('FB17-L09-Q04','o caso regido, o contexto imediato e o uso do autor','a posição da preposição na frase e o número de sílabas','a tradução literal e a versão bíblica utilizada pelo leitor','o número de ocorrências e a divisão de capítulos e versículos'),('FB17-L09-Q01','...','...','...','...'),('FB17-L09-Q02','São palavras invariáveis que regem casos: genitivo, dativo ou acusativo','São palavras flexionadas em gênero, número e caso como os substantivos','Formam-se exclusivamente como sufixos presos ao final dos verbos','Aparecem sempre no caso nominativo e nunca regem outro caso'),('FB17-L10-Q02','São palavras invariáveis que ligam termos ou orações, ex.: καί, δέ, ἀλλά.','São verbos que se flexionam em modo, tempo, voz, pessoa e número na oração grega.','São substantivos que concordam em gênero, número e caso com adjetivos e artigos.','São advérbios que modificam verbos, flexionando-se em graus comparativo e superlativo.'),('FB17-L10-Q01','Palavras que conectam orações ou termos no grego do NT, como καί, δέ, ὅτι.','Palavras que indicam relação de lugar ou tempo no grego do NT, como ἐν, εἰς, ἐκ.','Palavras que nomeiam pessoas, objetos ou ideias no grego do NT, como θεός, λόγος.','Palavras que indicam ações ou estados no grego do NT, como λέγω, γράφω, εἰμί.'),('FB17-L10-Q03','Conjunções ligam orações e expressam relações semânticas entre elas.','Conjunções flexionam verbos indicando tempo e modo verbal.','Conjunções substituem o substantivo para evitar repetições no texto.','Conjunções modificam o adjetivo, atribuindo-lhe grau de comparação.'),('FB17-L11-Q01','NAO SEI','Conjugação dos verbos terminados em -ω no presente do indicativo','Sistema de augmento verbal nos verbos compostos gregos','Classificação dos verbos gregos segundo a voz média e passiva'),('FB17-L11-Q04','Tempo, modo, voz, pessoa e número','Somente o tempo e o modo do verbo','A raiz, o tema e a terminação verbal','O caso, o gênero e o número do substantivo'),('FB17-L11-Q02','NAO SEI','Pela posição fixa no início da frase grega','Pela ausência de artigo definido','Pela terminação em -os no nominativo singular'),('FB17-L12-Q01','São as formas verbais que expressam ação, tempo e aspecto no grego koiné.','São as conjugações verbais portuguesas usadas para traduzir o Novo Testamento.','São os tempos históricos em que os autores do Novo Testamento viveram.','São as formas verbais hebraicas preservadas na Septuaginta grega.'),('FB17-L11-Q05','Porque revelam tempo, aspecto e modo que definem o sentido do texto original','Porque o grego substitui o hebraico como lingua sagrada do Antigo Testamento','Porque os verbos gregos nao possuem flexao e sao traduzidos literalmente','Porque a gramatica grega elimina a necessidade de consulta a outros idiomas'),('FB17-L12-Q03','NAO SEI','Indicar a pessoa do discurso no texto sagrado','Marcar a acao liturgica do verbo nas Escrituras','Expressar o tempo liturgico da narrativa biblica'),('FB17-L12-Q05','Porque o grego do NT expressa aspecto da acao, nao apenas tempo cronologico.','Porque os tempos gregos marcam a epoca exata em que os fatos ocorreram.','Porque o grego possui mais tempos verbais que o portugues, exigindo adaptacao.','Porque os autores biblicos escreveram no passado para preservar a tradicao oral.'),('FB17-L12-Q04','Contexto histórico, literário, gramatical e a intenção do autor','Apenas o tempo cronológico e a pessoa do verbo na oração','Somente a tradução oficial e a tradição interpretativa da igreja','Exclusivamente o significado literal e o dicionário bíblico usado'),('FB17-L13-Q01','A relação entre o sujeito e a ação expressa pelo verbo','O tempo em que a ação verbal se desenrola na oração','O modo como o falante encara a ação no discurso','A pessoa e o número gramatical do sujeito da oração'),('FB17-L13-Q02','Na voz ativa o sujeito pratica a ação; na passiva o sujeito sofre a ação.','A voz ativa se forma com o verbo haver; a passiva usa o verbo fazer.','A voz ativa exige objeto direto; a passiva dispensa complementos.','A voz ativa usa verbos no infinitivo; a passiva apenas no particípio.'),('FB17-L13-Q05','NAO SEI','A voz verbal revela apenas o tempo em que o fato ocorre','A voz verbal indica exclusivamente o numero e a pessoa gramatical','A voz verbal determina a concordancia nominal entre sujeito e adjetivo'),('FB17-L14-Q01','Indicativo, subjuntivo, imperativo, optativo, infinitivo e particípio','Pretérito, presente, futuro e aoristo','Voz ativa, passiva e reflexiva','Artigo definido, indefinido e partitivo'),('FB17-L14-Q02','Pelas desinências pessoais e vogais temáticas que distinguem cada modo.','Exclusivamente pelo contexto semântico da frase grega.','Pela presença de artigos definidos junto ao verbo.','Através da declinação do substantivo na frase grega.'),('FB17-L14-Q04','Contexto imediato e remoto, léxico, sintaxe, gramática e intenção do autor','Geografia, arqueologia, cronologia bíblica e contexto histórico-cultural','Tipologia, alegoria, simbolismo e interpretação profética das Escrituras','Trindade, cristologia, pneumatologia e escatologia do texto bíblico'),('FB17-L13-Q03','O sujeito pratica a ação em si mesmo ou em seu próprio benefício','O sujeito recebe a ação sem participar dela de modo algum','O sujeito pratica a ação somente sobre outro agente','A ação se realiza de modo recíproco entre agentes diversos'),('FB17-L14-Q03','NAO SEI','Expressar a acao ou estado do sujeito','Indicar o numero e a pessoa gramatical','Marcar o tempo cronologico do verbo'),('FB17-L15-Q02','NAO SEI','Possui tempo, modo e voz verbal, além de gênero e número nominais.','Funciona apenas como verbo, flexionando-se em pessoa e número.','Concorda em gênero e número, mas não admite voz passiva.'),('FB17-L14-Q05','Porque cada modo grego revela a intenção do autor em cada afirmação','Porque os modos gregos determinam a divisão dos capítulos e versículos','Porque a tradução literal dispensa a análise dos modos verbais','Porque o grego do Novo Testamento emprega somente dois modos verbais'),('FB17-L15-Q03','O particípio concorda em caso, gênero e número com o substantivo antecedente.','O particípio sempre concorda apenas em gênero e número, nunca em caso.','O particípio se relaciona somente pelo gênero, independentemente do número.','O particípio concorda com o verbo principal, e não com o substantivo.'),('FB17-L15-Q01','Forma verbal que une natureza de verbo e adjetivo, expressando ação ou estado.','É um tempo do modo indicativo que denota ação contínua e habitual no passado.','É forma nominal do verbo equivalente ao infinitivo, sem flexão de pessoa.','É classe de preposição que conecta orações subordinadas ao verbo principal.'),('FB17-L15-Q05','O contexto define a função e a temporalidade do particípio na frase.','O particípio sempre deve ser traduzido no tempo presente por convenção gramatical.','Somente o particípio presente exige análise contextual para tradução adequada.','A tradução literal do particípio preserva fielmente o sentido original do texto.'),('FB17-L15-Q04','Expressa relações temporais, causais, concessivas e instrumentais','Expressa apenas relações temporais e finais, nunca concessivas ou instrumentais','Indica exclusivamente relações condicionais e modais no texto bíblico','Serve somente como adjetivo, sem qualquer função adverbial no período'),('FB17-L16-Q03','substantivo (desempenha função de nome)','adjetivo (qualifica um substantivo)','advérbio (modifica verbo ou adjetivo)','pronome (substitui o nome)'),('FB17-L16-Q02','Pelo artigo τό ou pelas terminações -ειν (ativa) e -εσθαι (média/passiva).','Pela desinência pessoal -ω na primeira pessoa do singular.','Pelo uso do particípio com o artigo no caso genitivo.','Pela terminação -ντος no particípio presente ativo.'),('FB17-L13-Q04','Porque o contexto determina sua função semântica entre várias possibilidades','Porque a tradição exige tradução uniforme em todas as versões','Porque significa sempre ação praticada pelo próprio sujeito','Porque equivale unicamente à voz passiva em português'),('FB17-L17-Q02','NAO SEI','Através da ordem fixa Sujeito-Verbo-Objeto em todo o texto grego','Pela tradução literal palavra por palavra do hebraico','Somente pelo uso do alfabeto e acentos gregos'),('FB17-L16-Q04','O artigo, o tempo, a voz e a construção sintática do infinitivo','Somente o artigo e o tempo verbal do infinitivo','O modo, o número e a pessoa do infinitivo','Apenas a voz e a construção do infinitivo'),('FB17-L17-Q04','A ordem das palavras, suas funções e conexões na oração','O contexto histórico e cultural do texto bíblico','A tipologia e o sentido figurado das passagens','As divisões de capítulos e versículos da Bíblia'),('FB17-L17-Q05','NAO SEI','Porque revela a autoria divina de cada livro','Porque determina o canon do Novo Testamento','Porque confirma a inerrancia textual absoluta'),('FB17-L17-Q01','Estudo da estrutura frasal, casos, vozes e orações no grego koiné do NT.','Estudo das raízes hebraicas e consoantes radicais presentes no texto do NT.','Análise do grego moderno usado nas traduções atuais do Novo Testamento.','Conjunto de regras de tradução literal palavra por palavra do grego.'),('FB17-L18-Q01','O Grego Koiné, língua comum helenística usada na redação do Novo Testamento','O Grego Clássico, a língua da filosofia ateniense antiga','O Grego Ático, dialeto literário da Grécia antiga','O Aramaico, idioma semítico falado por Jesus na Palestina'),('FB17-L18-Q02','NAO SEI','Por meio da herança do grego classico e septuaginto','Pelo uso exclusivo de hapax legomena no corpus','Pela traducao literal do hebraico masorético'),('FB17-L18-Q05','Capta o sentido original dos termos gregos, evitando erros na tradução e exegese.','Permite decorar versículos rapidamente para uso em cultos e estudos bíblicos.','Facilita a comparação apenas com o Antigo Testamento, ignorando o contexto grego.','Dispensa o uso de commentaries e estudos teológicos externos ao texto sagrado.'),('FB17-L18-Q03','NAO SEI','designar atributos divinos e titles cristologicos','expressar relacoes semanticas de causalidade teologica','funcionar como marcador discursivo no texto grego'),('FB17-L19-Q02','NAO SEI','Pelo estudo da morfologia nominal e verbal grega','Por meio da analise sintatica do periodo grego','Atraves da fonetica historica do grego classico'),('FB17-L19-Q04','Contexto histórico, gramatical, literário, cultural e o uso do autor.','Apenas o significado literal das palavras, sem considerar o contexto.','A frequência da palavra no grego clássico, sem analisar o texto bíblico.','A primeira acepção do dicionário, como se fosse a única válida para o texto.'),('FB17-L19-Q05','Permite identificar o sentido original dos termos gregos e suas nuances.','Facilita apenas a tradução de textos do Antigo Testamento em hebraico.','Permite decorar versículos sem necessidade de interpretação contextual.','Serve exclusivamente para memorizar palavras gregas sem aplicação prática.'),('FB17-L20-Q02','Transferência ilegítima de totalidade','Falácia do sentido literal único','Transferência indevida de contexto','Falácia da equivalência semântica'),('FB17-L19-Q03','NAO SEI','Função sintática de sujeito na oração principal','Função semântica de adjunto adverbial de lugar','Função morfológica de verbo intransitivo'),('FB17-L20-Q03','O contexto imediato restringe o sentido do termo ao seu uso específico no texto','O sentido é definido pelo uso amplo do termo em toda a Escritura Sagrada','A etimologia da palavra no hebraico e grego é o fator decisivo e exclusivo','A tradição eclesiástica e o magistério determinam o sentido correto do termo'),('FB17-L17-Q03','NAO SEI','Sujeito e predicado sao as unicas funcoes possiveis','Apenas funcao adverbial em sentencas declarativas','Funcao exclusivamente sintatica, sem papel semantico'),('FB17-L20-Q01','Porque o sentido e determinado pelo uso no contexto, e nao pela origem etimologica','Porque a etimologia grega foi fixada pelo Concilio de Trento como norma unica','Porque o grego biblico depende exclusivamente da Septuaginta para definir sentidos','Porque apenas a raiz hebraica determina o verdadeiro sentido das palavras gregas'),('FB17-L20-Q04','Cada palavra possui nuanças e conotações únicas que outros termos não reproduzem.','Porque os tradutores bíblicos atuais desconhecem os idiomas originais.','Porque a Bíblia foi originalmente escrita em três línguas diferentes.','Porque todas as línguas antigas possuem vocabulários muito limitados.'),('FB17-L21-Q03','sujeito','predicativo do sujeito','objeto direto','adjunto adverbial'),('FB17-L20-Q05','Complementam-se mutuamente, integrando significado, estrutura e contexto','Devem substituir-se, pois uma abordagem basta para a interpretação','Trabalham de forma isolada, cada uma com metodologia específica','Apenas a gramática é suficiente para o entendimento correto do texto'),('FB17-L21-Q01','Leitura básica do grego koinê, a língua comum do NT','Leitura avançada do hebraico massorético do AT','Compreensão do latim da Vulgata medieval','Estudo do aramaico targúmico pós-exílio'),('FB17-L21-Q02','NAO SEI','anagnose','gramma','lexis'),('FB18-L05-Q03','O aramaico do NT e lingua semitica irma do hebraico, com raizes comuns','As expressoes aramaicas derivam diretamente do grego koine, nao do hebraico','O aramaico do NT e uma variante tardia do latim eclesiastico medieval','Aramaico no NT foi traduzido do antigo sumerio mesopotamico'),('FB18-L05-Q02','No seculo I, na Palestina, registrado nos Evangelhos e em Atos','No periodo do exilio babilonico, no seculo VI a.C.','No seculo IV, nos escritos dos concilios ecumenicos','No antigo testamento, durante o periodo dos patriarcas'),('FB18-L05-Q01','Palavras e frases em aramaico preservadas no texto grego do Novo Testamento','Tradução do Novo Testamento para o aramaico moderno pelos pais da Igreja','Manuscritos originais do Novo Testamento escritos em língua aramaica','Frases hebraicas preservadas pelos evangelistas no Novo Testamento grego'),('FB18-L05-Q04','NAO SEI','As expressões aramaicas são traduções do grego para o hebraico moderno.','O aramaico substituiu completamente o grego como língua original do Novo Testamento.','As expressões aramaicas foram acrescentadas posteriormente por tradutores medievais.'),('FB18-L04-Q05','Observar o corpus reduzido, hapax legomena e o aramaico imperial específico','Daniel foi escrito somente em hebraico, sem qualquer porção em aramaico','O aramaico de Daniel é idêntico ao siríaco usado na Peshitta posterior','Os manuscritos de Qumran não apresentam variantes no aramaico de Daniel'),('FB18-L06-Q03','NAO SEI','NAO SEI','NAO SEI','NAO SEI'),('FB18-L12-Q04','Permite identificar termos-chave e compreender o sentido original do texto bíblico.','Permite memorizar versículos rapidamente sem necessidade de interpretação.','Substitui a necessidade de consulta a dicionários e comentários bíblicos.','Garante a salvação eterna do leitor estudioso das Escrituras Sagradas.'),('FB18-L12-Q05','Não construir doutrinas apenas na etimologia de uma palavra isolada','Usar somente a Septuaginta para definir termos teológicos','Basear o estudo apenas no significado literal e moderno','Interpretar cada vocábulo isoladamente do seu contexto'),('FB18-L13-Q01','Línguas semíticas irmãs com raízes comuns, vocabulário compartilhado e estruturas similares','O aramaico bíblico é apenas um dialeto regional do hebraico antigo','São línguas semíticas totalmente distintas sem qualquer relação histórica entre si','O hebraico descende do aramaico bíblico como sua língua materna original'),('FB18-L06-Q02','Jesus','Pedro','Paulo','João'),('FB18-L13-Q03','NAO SEI','Hebraico e aramaico sao unicas linguas semiticas com parentesco genealogico','O aramaico descende diretamente do hebraico antigo','Hebraico e aramaico pertencem a ramos opostos do semitico'),('FB18-L13-Q02','Período do exílio babilônico','Época dos patriarcas hebreus','Período dos juízes em Israel','Reino dividido de Israel'),('FB18-L13-Q04','Essencial para compreender o sentido original das Escrituras em seus idiomas','Apenas o hebraico foi utilizado em toda a Biblia sem qualquer excecao','O aramaico e uma lingua moderna sem qualquer relacao com textos antigos','O Novo Testamento foi escrito originalmente em hebraico nao em grego'),('FB18-L06-Q01','Menina, levanta-te','Filha, levanta-te','Jovem, levanta-te','Criança, vem a mim'),('FB18-L14-Q01','Dialeto popular falado na Galileia no século I, língua de Jesus','A língua oficial do Império Persa usada nos decretos reais','O aramaico literário e padronizado dos livros de Esdras e Daniel','A forma primitiva e original do aramaico de Gênesis 31:47'),('FB18-L14-Q02','Aramaico era a língua comum na Palestina do séc. I, no período do Segundo Templo','Aramaico era a língua oficial do Império Romano no tempo de Jesus','Aramaico surgiu somente após a destruição do Templo em 70 d.C.','Aramaico era falado exclusivamente pelos fariseus na Judéia'),('FB18-L15-Q01','NAO SEI','A reconstrução literal das falas de Jesus com base em cognatos gregos','O uso exclusivo do aramaico galileu como chave interpretativa','A correspondência exata entre os ditos de Jesus e os manuscritos do Mar Morto'),('FB18-L15-Q02','Período entre o ministério de Jesus e a redação dos Evangelhos','Período intertestamentário entre Malaquias e Mateus','Era dos patriarcas antes do dilúvio','Cativeiro babilônico no século VI a.C.'),('FB18-L15-Q05','Reconhecer que conhecemos em parte e respeitar o mistério revelado','Buscar revelações pessoais acima da Escritura para ampliar o conhecimento','Confiar apenas na razão humana, ignorando a inspiração divina','Atribuir novos significados sem considerar o contexto original'),('NT01-L01-Q01','Alexandre, o Grande','Dario III, o Medo','Nabucodonosor II','Antíoco Epífanes'),('NT01-L01-Q03','Início da dominação helenística e da helenização cultural da Judeia','Retorno do exílio babilônico e restauração do culto no Templo','Destruição do Segundo Templo e dispersão do povo judeu','Conquista babilônica e início do cativeiro em Judá'),('NT01-L01-Q02','Transição para o período helenístico com a conquista de Alexandre Magno (331 a.C.)','Início do domínio romano na Palestina sob o general Pompeu em 63 a.C.','Início do domínio persa com Ciro conquistando a Babilônia em 539 a.C.','Encerramento do período babilônico com a destruição de Jerusalém em 586 a.C.'),('NT01-L01-Q05','NAO SEI','A Igreja de Roma e o papado medieval','O sinédrio judeu e os fariseus','As sinagogas e a escola de Hillel'),('NT01-L02-Q02','Rei da Macedônia no século IV a.C., fundador do período helenístico','Imperador romano do século I a.C.','Faraó egípcio da dinastia ptolemaica','Rei persa da dinastia Aquemênida no século V a.C.'),('NT01-L02-Q04','Divulgou a cultura e língua gregas, helenizando os povos conquistados','Conquistou Roma e implantou o direito romano no Ocidente','Fundou a Igreja de Antioquia como centro do cristianismo primitivo','Escreveu pessoalmente os livros do Novo Testamento em grego'),('NT01-L02-Q05','NAO SEI','A sinagoga e o Sinédrio foram moldados pelo desenvolvimento do judaísmo pós-exílico','As primeiras comunidades cristãs surgiram após o Pentecostes em Jerusalém','Os mosteiros medievais foram estruturados a partir da regra beneditina'),('NT01-L02-Q03','Alexandre conquistou a Judeia e permitiu aos judeus manterem seus costumes e leis.','Alexandre destruiu o Templo de Jerusalém e deportou os judeus para a Grécia.','Alexandre impôs a religião grega e proibiu a circuncisão dos judeus.','Alexandre foi derrotado pelos judeus e nunca conseguiu entrar na Judeia.'),('NT01-L03-Q02','Após Alexandre Magno, no período helenístico','Durante o cativeiro babilônico','Sob o domínio do Império Romano','No período dos juízes de Israel'),('NT01-L03-Q03','Causou divisão interna e perseguição, levando à revolta dos Macabeus.','Promoveu unificação cultural plena e aceitação total pelos judeus.','Levou diretamente à destruição do Templo de Jerusalém pelos babilônios.','Não provocou mudanças relevantes na sociedade e cultura judaica.'),('NT01-L03-Q04','Divulgou o grego koiné, a filosofia e os costumes gregos pelo mundo antigo','Estabeleceu o latim como língua universal do Mediterrâneo','Preservou a cultura hebraica original sem nenhuma mudança','Afastou os judeus do estudo das Escrituras Sagradas'),('NT01-L03-Q05','NAO SEI','A Igreja de Cristo foi moldada por esse desenvolvimento','O movimento dos essênios surgiu desse desenvolvimento','A reforma protestante foi influenciada por esse desenvolvimento'),('NT01-L03-Q06','Revela o contexto linguístico e cultural grego em que o NT foi escrito.','Permite identificar os autores gregos que escreveram os evangelhos.','Ajuda a provar que Jesus era um filósofo grego.','Mostra que o NT foi traduzido do latim para o hebraico.'),('NT01-L04-Q01','Partilha do império de Alexandre Magno entre os diádocos','Reinado de Antíoco Epifânio IV sobre o Império Selêucida','Revolta dos Macabeus contra o domínio selêucida na Judeia','Conquista romana do território grego e da região da Judeia'),('NT01-L04-Q03','Causou a helenização da Judeia, perseguições religiosas e a Revolta dos Macabeus.','Resultou em liberdade religiosa completa e autonomia política plena dos judeus.','Levou à reconstrução do Templo de Salomão com financiamento dos generais gregos.','Estabeleceu o governo romano direto sobre toda a Judeia por dois séculos seguidos.'),('NT01-L02-Q06','Promoveu a helenização e a difusão do grego koiné, língua do Novo Testamento.','Fundou o Império Romano, que dominou a Palestina no século I.','Traduziu pessoalmente o Antigo Testamento para o grego em Alexandria.','Foi contemporâneo de Jesus e citou seus ensinamentos nas cartas.'),('NT01-L04-Q04','Espalhou o grego koiné, língua do Novo Testamento','Manteve o império unificado sob um único governante','Estabeleceu o latim como língua oficial em todo oriente','Acabou com toda influência cultural grega no mediterrâneo'),('NT01-L04-Q05','NAO SEI','O colégio apostólico e o sinédrio judaico reformado','As sete igrejas do Apocalipse e os conselhos presbiterianos','Os tribunais dos anciãos e a ordem dos levitas'),('NT01-L04-Q06','Mostra a divisao entre selucidas e ptolemaicos que definiu o contexto do NT','Indica que Alexandre Magno manteve o imperio grego unido apos sua morte','Revela que o imperio grego conquistou Roma apos a fragmentacao interna','Explica como os gregos eliminaram completamente o dominio romano na Judea')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('NT01-L05-Q02','Período intertestamental, dinastia ptolomaica no Egito','Período patriarcal, monarquia unificada de Israel','Cativeiro babilônico, império neo-babilônico','Período monárquico tardio, reino do norte de Israel'),('NT01-L05-Q05','NAO SEI','O sacerdócio levítico e o sistema sacrificial do Templo','A Grande Sinagoga e a tradição farisaica posterior','As comunidades essênias e os zelotes'),('NT01-L05-Q04','Hellenizou a cultura judaica e viabilizou a Septuaginta','Instituiu o culto a Serápis entre os judeus alexandrinos','Concedeu plena autonomia política ao povo de Israel','Traduziu o Novo Testamento para o grego koiné'),('NT01-L06-Q04','Hellenizou a Judeia, profanando o templo e perseguindo os judeus','Conquistou a Pérsia e libertou os hebreus do cativeiro','Estabeleceu o primeiro templo em Jerusalém','Traduziu a Septuaginta para o latim'),('NT01-L06-Q02','Reino helenístico sucessor de Alexandre, dominante na Síria (312–63 a.C.)','Império persa aquemênida dominante na Pérsia e Mesopotâmia (550–330 a.C.)','Reino ptolomaico egípcio que controlou Egito e Palestina (305–30 a.C.)','Império romano que conquistou o Oriente após Cartago (146 a.C.–476 d.C.)'),('NT01-L06-Q05','NAO SEI','A Igreja primitiva em Jerusalém foi moldada por esse desenvolvimento','As sinagogas judaicas surgiram como consequência direta desse evento','Os conselhos de anciãos das comunidades cristãs foram formados a partir disso'),('NT01-L07-Q01','Rei selêucida que perseguiu os judeus e profanou o Templo de Jerusalém','Rei selêucida que favoreceu os judeus e concedeu autoridade ao sumo sacerdote','General romano que destruiu o Templo de Jerusalém no ano 70 d.C.','Profeta hebreu que anunciou a vinda do Messias e o novo concerto'),('NT01-L06-Q06','Revela a helenização que moldou a cultura judaica do primeiro século','Confirma a origem selêucida do sinédrio e do sumo sacerdócio','Identifica os selêucidas como povo do pacto descrito em Atos','Estabelece a data precisa da redação do evangelho de Marcos'),('NT01-L07-Q05','O Filho do Homem','O Servo Sofredor','O Cordeiro de Deus','O Príncipe da Paz'),('NT01-L07-Q03','Antíoco Epifânio ergueu a abominação da desolação no templo','Nabucodonosor queimou completamente o templo de Jerusalém','Tito e os romanos destruíram o templo no ano setenta','Manassés introduziu culto pagão dentro do templo santo'),('NT01-L08-Q01','Matatias, sacerdote da família de Asmoneu','Judas Macabeu, filho de Matatias Asmoneu','Antíoco Epifânio, rei selêucida da Síria','Jonatas Macabeu, sumo sacerdote judeu'),('NT01-L07-Q04','NAO SEI','Nao sei','Nao sei','Nao sei'),('NT01-L08-Q02','A ordem selêucida para sacrificar aos ídolos gregos e a submissão de um judeu.','A destruição do templo de Jerusalém pelos exércitos babilônicos de Nabucodonosor.','O decreto do rei Ciro para permitir o retorno dos judeus do cativeiro na Babilônia.','A prisão e execução de Jesus Cristo pelos soldados romanos sob ordens de Pilatos.'),('NT01-L08-Q03','Líder judeu que comandou a revolta macabeia contra os selêucidas no século II a.C.','Apóstolo traidor que entregou Jesus aos sumos sacerdotes por trinta moedas de prata.','Rei de Israel que unificou as tribos e construiu o primeiro Templo de Jerusalém.','Profeta que enfrentou os profetas de Baal no monte Carmelo por volta do século IX a.C.'),('NT01-L08-Q04','Pelo decreto de Ciro, rei da Pérsia','Por meio do rei Herodes, o Grande','Pelos macabeus no segundo século','Pela aliança com o rei Assírio'),('NT01-L08-Q05','Hanukkah','Páscoa Judaica','Festa dos Tabernáculos','Festa de Purim'),('NT01-L09-Q01','Dinastia judaica que governou a Judeia de 140 a 37 a.C., surgida da revolta macabeia.','Dinastia persa que governou a Judeia após o cativeiro babilônico, com Ciro e Dario.','Linhagem dos reis assírios que conquistaram Samaria e deportaram as dez tribos.','Família de sacerdotes egípcios que governaram a Judeia durante o período helenístico.'),('NT01-L09-Q02','Período intertestamentário, reinou sobre a Judeia entre 140 e 37 a.C.','Período dos juízes, governou Israel de 1050 a 931 a.C.','Era dos patriarcas, liderou o povo hebreu no Egito','Cativeiro babilônico, governou Judá na Babilônia'),('NT01-L09-Q03','Restaurou a independência política e a pureza religiosa de Israel','Conduziu Judá ao cativeiro e destruição do Templo em Jerusalém','Construiu o Primeiro Templo e o palácio real sob Salomão','Estabeleceu o domínio romano direto e permanente sobre a Judeia'),('NT01-L09-Q05','NAO SEI','O sacerdócio levítico e o sistema sacrificial do Templo de Jerusalém','A Igreja primitiva e o movimento apostólico após Pentecostes','As sinagogas e a tradição rabínica do judaísmo posterior'),('NT01-L09-Q04','Restaurou o culto puro no Templo de Jerusalém e combateu a helenização','Destruiu o Templo de Salomão e introduziu ídolos pagãos em Israel','Submeteu Judá ao império selêucida e aboliu a Torá','Fundou o cativeiro babilônico e levou o povo para a Assíria'),('NT01-L10-Q01','Conquista da Judeia por Pompeu em 63 a.C.','Conquista da Judeia por Alexandre Magno em 332 a.C.','Conquista da Judeia por Nabucodonosor em 586 a.C.','Destruição de Jerusalém por Tito em 70 d.C.'),('NT01-L10-Q03','Subjugação política, impostos pesados e destruição do Templo em 70 d.C.','Invasão dos assírios e destruição do reino de Israel em 722 a.C.','Conquista babilônica de Jerusalém e início do cativeiro judaico','Domínio persa e autorização para reconstrução do Templo em 516 a.C.'),('NT01-L10-Q05','NAO SEI','A igreja primitiva em Jerusalém','As sinagogas da dispersão judaica','As comunidades monásticas medievais'),('NT01-L10-Q04','Difundiu o latim, o direito romano e a infraestrutura por todo o império','Implantou parlamentos democráticos nas províncias conquistadas','Unificou todo o império sob o uso exclusivo do latim','Impediu a prática de qualquer culto religioso local'),('NT01-L11-Q02','Rei da Judeia, vassalo de Roma, no período neotestamentário','Imperador romano que governava diretamente toda a Judeia','Rei da Pérsia que dominava Israel no Antigo Testamento','Sumo sacerdote judeu durante o exílio babilônico'),('NT01-L11-Q01','Rei idumeu da Judeia que governou de 37 a 4 a.C. e reconstruiu o Templo de Jerusalém.','Rei da Judeia que governou de 4 a.C. a 37 a.C. e perseguiu os primeiros cristãos.','Sumo sacerdote judeu responsável pela reconstrução do Templo de Jerusalém.','Profeta do Antigo Testamento que profetizou a destruição do Templo de Jerusalém.'),('NT01-L11-Q05','NAO SEI','A Igreja de Roma','As sinagogas locais','O Sinédrio'),('NT01-L11-Q03','Reconstruiu o Templo de Jerusalém, mas oprimiu o povo com pesados impostos','Conquistou a Judeia expandindo o território israelita','Restaurou a monarquia davídica unificando as tribos de Israel','Devolveu a independência política de Israel ao povo judeu'),('NT01-L11-Q06','Revela o domínio romano e a perseguição que marcou o nascimento de Jesus.','Herodes foi o governador romano que ordenou a crucifixão de Jesus.','Herodes escreveu várias epístolas que compõem o Novo Testamento.','Herodes liderou a primeira comunidade cristã em Jerusalém após a ascensão.'),('NT01-L11-Q04','Reconstruiu o Templo de Jerusalém, renovando o culto judaico','Destruiu o Templo de Jerusalém no ano setenta d.C.','Escreveu epístolas fundando as primeiras igrejas cristãs','Traduziu as Escrituras hebraicas para o idioma grego'),('NT01-L12-Q02','Desenvolveram-se no pós-exílio babilônico, sob domínios persa e helenístico','Originaram-se no período do Primeiro Templo, sob o reinado de Davi e Salomão','Surgiram na era dos Macabeus, durante o domínio romano na Judeia','Criadas no cativeiro egípcio, antes do êxodo do povo de Israel'),('NT01-L12-Q01','Locais de reunião para oração e estudo da Lei','Templos dedicados ao culto sacrificial','Centros políticos do governo judaico','Locais exclusivos para sacerdotes'),('NT01-L10-Q02','O quarto império, sucedendo Babilônia, Medo-Pérsia e Grécia','Primeiro reino universal surgido após o dilúvio','Segundo domínio político posterior à Babilônia','Sexto poder hegemônico após a monarquia unificada'),('NT01-L12-Q06','Revela o ambiente de ensino e oração onde Jesus e os apóstolos ministraram.','Mostra que as sinagogas eram apenas locais de sacrifícios como o templo.','Indica que o culto cristão surgiu independente de qualquer prática judaica.','Demonstra que as sinagogas foram fundadas pelos apóstolos no século I.'),('NT01-L12-Q05','NAO SEI','As igrejas da Reforma Protestante como Luterana e Presbiteriana','As primeiras comunidades judaico-cristas de Jerusale','Os movimentos missionarios apostolicos do seculo I'),('NT01-L13-Q01','A tradução grega do Antigo Testamento, feita em Alexandria','Um grupo de 70 anciãos que governavam Israel durante o êxodo','Os 70 discípulos enviados por Jesus às cidades da Judeia','O conselho judaico de 70 membros conhecido como Sinédrio'),('NT01-L12-Q03','Fortaleceu a identidade religiosa e a preservação da Torá entre o povo judeu','Provocou o abandono do culto sacrificial no Templo de Jerusalém','Causou a divisão política e a fragmentação das tribos de Israel','Levou à substituição da Torá pelos ensinamentos dos escribas'),('NT01-L13-Q02','Tradução grega do AT, feita em Alexandria, no Egito ptolomaico, séc. III a.C.','Tradução grega do AT, feita em Jerusalém, sob domínio selêucida, séc. II a.C.','Versão aramaica do AT, produzida na Pérsia, no séc. IV a.C.','Tradução grega do NT, feita em Roma, sob o império, séc. I d.C.'),('NT01-L13-Q05','NAO SEI','A igreja primitiva em Jerusalém','As sinagogas da dispersão','Os conselhos apostólicos'),('NT01-L13-Q03','Ampliou o alcance das Escrituras entre os judeus helenizados da Diáspora','Substituiu o hebraico como texto oficial nas sinagogas da Judeia','Causou o rompimento definitivo entre judeus e a comunidade grega','Levou os judeus a abandonarem as práticas do Antigo Testamento'),('NT01-L13-Q04','Base textual do Novo Testamento e da teologia cristã primitiva','Tradução aramaica do Antigo Testamento usada no templo de Jerusalém','Texto original hebraico compilado pelos escribas da seita de Qumran','Versão latina do Antigo Testamento organizada pelo papa Jerônimo'),('NT01-L17-Q06','Conhecer os zelotes ajuda a entender as tensões políticas da Judeia no século I','Os zelotes foram os principais tradutores do Antigo Testamento para o grego','Os zelotes fundaram as primeiras igrejas gentílicas em Antioquia da Síria','Os zelotes defenderam publicamente que Jesus era o Messias esperado pelos romanos'),('NT01-L18-Q02','Período do Segundo Templo, sob domínio romano na Judéia','Antigo Testamento inicial, sob governo dos patriarcas em Canaã','Era dos Juízes, em Israel antes da monarquia unificada','Período exílico na Babilônia, sob império neo-babilônico'),('NT01-L18-Q03','Preservaram e interpretaram a Lei Sagrada tornando se mestres religiosos influentes em Israel','Construíram o Templo de Jerusalém durante o reinado do rei Salomão','Conduziram o êxodo do Egito e receberam os mandamentos no monte Sinai','Fundaram a monarquia israelita e ungiram os primeiros reis de Judá'),('NT01-L19-Q01','O supremo tribunal judaico composto por 71 membros, presidido pelo sumo sacerdote','O templo principal de Jerusalém onde os sacerdotes ofereciam sacrifícios diários','Um tribunal romano encarregado de aplicar as leis imperiais entre os judeus','A principal sinagoga de Jerusalém usada para reuniões e ensinamentos'),('NT01-L18-Q05','NAO SEI','A igreja primitiva em Jerusalém','As sinagogas do período intertestamentário','Os concílios dos primeiros séculos cristãos'),('NT01-L18-Q04','Preservaram e copiaram as Escrituras Sagradas, influenciando a religião','Traduziram as Sagradas Escrituras para o latim, mudando a língua','Influenciaram a política romana por meio de cartas oficiais','Fundaram as sinagogas como centros culturais na Babilônia'),('NT01-L18-Q06','Intérpretes da Lei, aliados dos fariseus, opunham-se a Jesus nos Evangelhos.','Cobradores de impostos a serviço de Roma que atuavam no Templo de Deus.','Soldados romanos designados para guardar e proteger o Templo sagrado.','Sacerdotes principais que ofereciam sacrifícios e lideravam o culto.'),('NT01-L19-Q02','Sumos sacerdotes, escribas e anciãos','Fariseus, saduceus e essênios','Apóstolos, presbíteros e diáconos','Patriarcas, juízes e profetas'),('NT01-L19-Q03','NAO SEI','Apenas sacerdotais no tabernáculo','Militares e políticas em Israel','Proféticas e miraculosas'),('NT01-L19-Q06','Porque cada grupo tinha convicções teológicas e interesses políticos diferentes.','Porque os grupos do conselho eram todos unanimemente favoráveis a Jesus.','Porque as diferenças eram apenas de idioma e região geográfica.','Porque o Novo Testamento apresenta esses grupos como totalmente homogêneos.'),('NT01-L19-Q05','Sinédrio julgou Jesus e processou os apóstolos','Pôncio Pilatos condenou Jesus e os apóstolos','Os fariseus autorizaram a morte dos apóstolos','O sumo sacerdote absolveu Jesus e os apóstolos'),('NT01-L20-Q03','Provocaram revoltas contra Roma, divisões internas e forte esperança de libertação.','Trouxeram prosperidade econômica imediata e paz duradoura para toda a Judeia.','Levaram à conversão em massa dos judeus ao culto imperial romano.','Resultaram no estabelecimento imediato e visível do reino messiânico terreno.'),('NT01-L20-Q02','Segundo Templo, sob dominação romana','Cativeiro babilônico, sob Nabucodonosor','Período dos Juízes, em sistema tribal','Monarquia unificada, sob governo dos reis'),('NT01-L19-Q04','O Sinédrio não tinha poder de morte; precisava da autoridade romana','Jesus perdeu seus poderes divinos ao ser julgado por Pilatos','Os romanos proibiram seus ensinamentos nas sinagogas','Pilatos anulou todos os seus milagres publicamente'),('NT01-L20-Q01','Esperanças judaicas de um Messias ungido, político e apocalíptico.','Profecias messiânicas já cumpridas na primeira vinda de Cristo.','Doutrina do Novo Testamento sobre a parusia e o juízo final.','Esperativa de um sumo sacerdote eterno segundo a ordem de Melquisedeque.'),('NT01-L20-Q05','NAO SEI','A sinagoga e o sinédrio foram moldados pelo exílio babilônico','A igreja primitiva surgiu a partir do Pentecostes','O sacerdócio levítico foi reformado por Josias'),('NT02-L01-Q01','Podem ser vistos em conjunto, pois narram eventos de forma semelhante.','Significa que foram escritos na mesma época e pelos mesmos autores.','Significa que são os únicos evangelhos aceitos pela tradição cristã.','Significa que contêm exclusivamente parábolas e ensinamentos de Jesus.'),('NT02-L01-Q02','Do grego synopsis, que significa visão de conjunto','Do grego logos, que significa razão ou palavra','Do grego theoria, que significa contemplação','Do grego kosmos, que significa ordem do universo'),('NT02-L01-Q03','Porque apresentam notável semelhança de conteúdo, ordem e linguagem','Porque foram compostos por um único autor sob pseudônimo comum','Porque registram apenas os milagres de Jesus em igual sequência','Porque substituem o Antigo Testamento no cânon cristão'),('NT02-L01-Q06','Permite identificar fontes, estruturas e tradições literárias comuns.','Prova que apenas um Evangelho é verdadeiro e os outros falsos.','Elimina as diferenças entre os textos para criar um único relato.','Substitui o estudo teológico pela análise histórica secular.'),('NT01-L20-Q04','Originou o cristianismo ao reconhecer Jesus como o Messias prometido','Limitou-se a influenciar apenas a culinária e os costumes judaicos','Provocou o abandono total das esperanças escatológicas em Israel','Restringiu-se ao Império Romano, sem afetar outras civilizações'),('NT02-L01-Q04','Semelhanças verbais, de ordem e de conteúdo','Apenas semelhanças materiais e teológicas','Somente paralelos cronológicos e geográficos','Semelhanças tipológicas e proféticas'),('NT02-L02-Q01','Cinco grandes discursos, Reino dos Céus e cumprimento das profecias do AT.','Sete declarações ''Eu sou'' que revelam a divindade de Cristo e a vida eterna.','Narrativa curta e dinâmica, focada nas ações e milagres imediatos de Jesus.','Ênfase na oração, compaixão aos marginalizados e alcance universal da salvação.'),('NT02-L02-Q05','Tema central da pregação de Jesus em Mateus, expressa o governo de Deus.','Um conceito político terreno que Jesus buscou estabelecer contra Roma.','Uma metáfora exclusiva para a vida após a morte, sem implicações presentes.','Um título alternativo para a Igreja como instituição religiosa.'),('NT02-L02-Q04','Cinco discursos de Jesus alternam-se com narrativas, estruturando o Evangelho de Mateus','Sete discursos de Jesus dividem o Evangelho em seções iguais sem intercalação narrativa','O Sermão do Monte é o único grande bloco de discurso que estrutura o Evangelho','Os discursos aparecem somente após a narrativa completa da paixão de Cristo'),('NT02-L02-Q02','Pela genealogia davídica, profecias messiânicas e tipologia mosaica','Apenas pelos milagres extraordinários e curas realizadas por Cristo','Somente pelos ensinamentos do Sermão do Monte e parábolas cristãs','Pela narrativa do evangelho de Lucas e genealogia atribuída a José'),('NT02-L02-Q06','NAO SEI','Israel é a Igreja e a missão se restringe a Jerusalém','A Igreja substitui Israel sem continuidade missionológica','A missão às nações é separada de Israel e da Igreja'),('NT02-L03-Q02','NAO SEI','Atraves de metaforas extensas e descricoes detalhadas','Por meio de monologos interiores prolongados','Com a repeticao exaustiva de um unico cenario'),('NT02-L03-Q01','Ação urgente, técnica de intercalação, segredo messiânico e grego popular','Genealogia detalhada, sermão do monte extenso e cinco grandes discursos','Hinos como Magnificat, narrativa desde o nascimento e ênfase nos pobres','Longos discursos, alegorias da luz e teologia alta do Logos'),('NT02-L03-Q04','Revela que o messianismo de Jesus é espiritual e se cumpre na cruz','Esconde a identidade divina de Jesus dos leitores até a ressurreição','Indica que Jesus recusou ser reconhecido como Messias por qualquer pessoa','Mostra que os demônios tinham poder de revelar a identidade de Jesus'),('NT02-L03-Q03','No batismo, transfiguração e nas três profecias da paixão','Pela genealogia davídica e nos relatos da infância em Belém','Apenas nos sete sinais miraculosos registrados por João','Exclusivamente na confissão de Pedro em Cesareia de Filipe'),('NT02-L03-Q05','Por relatos que mostram fraquezas, como a negação de Pedro e a fuga.','Por profecias messiânicas que anunciam as traições dos discípulos.','Através de visões apocalípticas que revelam o julgamento deles.','Pelas epístolas pastorais que repreendem suas condutas morais.'),('NT02-L03-Q06','Porque nela Jesus morreu para redimir a humanidade do pecado','Porque a cruz era o símbolo oficial do Império Romano','Porque era o instrumento que Jesus usou para curar enfermos','Porque foi o presente que os magos ofereceram ao menino Jesus'),('NT02-L04-Q04','Epístola de Paulo aos Filipenses','Epístola de Paulo aos Colossenses','Epístola de Paulo aos Efésios','Primeira Epístola de Paulo aos Tessalonicenses'),('NT02-L04-Q05','Jerusalém é o centro da história da salvação, palco da morte e ressurreição de Cristo','Jerusalém foi apenas o local onde Jesus cresceu, sem importância na crucificação','Jerusalém é citada nos evangelhos só como cidade romana, sem valor profético','Jerusalém serviu somente como cenário das parábolas, sem papel na redenção'),('NT02-L04-Q06','Relata a ascensão de Jesus e a promessa do Espírito Santo','Com a ressurreição de Lázaro e a entrada em Jerusalém','Narrando a conversão de Paulo na estrada de Damasco','Com a última ceia e o lava-pés aos discípulos'),('NT02-L05-Q04','NAO SEI','A parábola do semeador e a do filho pródigo','As bem-aventuranças e o Sermão do Monte','A parábola do bom samaritano e dos talentos'),('NT02-L05-Q02','Os Evangelhos Sinópticos Mateus, Marcos e Lucas','Os Evangelhos Apócrifos de Nag Hammadi','Os Livros Históricos do Antigo Testamento','As Cartas Pastorais e Epístolas Gerais'),('NT02-L05-Q03','Ministério na Galiléia, viagem a Jerusalém e paixão estruturam os sinóticos.','Os relatos seguem: nascimento em Belém, exílio no Egito e retorno a Nazaré.','A estrutura tripartite é formada por parábolas, milagres e discursos escatológicos.','Os evangelhos narram: tentação, transfiguração e ascensão como blocos centrais.'),('NT02-L06-Q02','Diferem em origens, infâncias e relatos de aparições entre os quatro Evangelhos.','Os quatro Evangelhos apresentam narrativas idênticas sobre origens e aparições.','Apenas Mateus e Marcos registram aparições do Cristo ressurreto.','João é o Evangelho com a narrativa da infância mais extensa e detalhada.'),('NT02-L06-Q05','Porque diferentes perspectivas bíblicas se complementam, como nos quatro Evangelhos.','Porque a Bíblia possui erros que se cancelam entre si nas diferenças textuais.','Porque cada autor bíblico escreveu apenas segundo sua própria opinião humana.','Porque somente o Novo Testamento é completamente isento de contradições internas.'),('NT02-L06-Q03','Sob a inspiração do Espírito Santo, conforme seu propósito e audiência.','Por causa da fragilidade humana e da memória limitada dos apóstolos.','Porque recebeu relatos contraditórios e imprecisos das testemunhas.','Por imposição das autoridades religiosas que controlavam as Escrituras.'),('NT02-L07-Q01','A questão da relação literária entre os três evangelhos sinóticos','O problema da autoria e composição do livro do Apocalipse','A questão da historicidade dos milagres narrados nos evangelhos','O problema da datação das epístolas do Novo Testamento'),('NT02-L06-Q06','As diferenças nos Evangelhos complementam a compreensão da pessoa e obra de Jesus','As diferenças nos Evangelhos geram contradições que comprometem a fé cristã','As diferenças nos relatos bíblicos devem ser ignoradas para preservar a verdade','Apenas o Evangelho de João revela a verdadeira pessoa e obra de Jesus'),('NT02-L07-Q03','Hipótese das Duas Fontes (Marcos + Q), Griesbach e Farrer são as principais.','Mateus foi o primeiro evangelho, seguido por Marcos, que dependeu dele e de Lucas.','Os três evangelhos foram escritos sem qualquer dependência literária entre si.','O Evangelho de João serviu como fonte principal para Mateus, Marcos e Lucas.'),('NT02-L07-Q05','NAO SEI','O perdão das ofensas mediante sacrifícios rituais','A instituição da lei mosaica como código civil','A formação de comunidades monásticas no deserto'),('NT02-L07-Q02','NAO SEI','Semelhanca estrutural total sem diferencas','Diferenca absoluta sem pontos em comum','Identidade perfeita entre os elementos'),('NT02-L07-Q04','Hipótese que propõe Marcos como fonte e uma fonte ''Q'' para Mateus e Lucas.','Hipótese que atribui o Pentateuco a quatro fontes: Javista, Eloísta, Deuteronomista e Sacerdotal.','Teoria que defende que Mateus escreveu primeiro e Marcos o utilizou como base.','Hipótese que propõe o Evangelho de João como fonte principal dos sinóticos.'),('NT02-L08-Q01','Que Marcos foi escrito primeiro e serviu de fonte para Mateus e Lucas.','Que Mateus foi escrito primeiro e serviu de fonte para Marcos e Lucas.','Que Lucas foi escrito primeiro e serviu de fonte para Mateus e Marcos.','Que os três evangelhos foram escritos independentemente, sem fontes comuns.'),('NT02-L07-Q06','A inspiração atua por meio das fontes, sem anular a historicidade.','Os Evangelhos foram escritos sem qualquer dependência entre si.','A inspiração divina dispensa a confiabilidade histórica nos Evangelhos.','Fontes e inspiração são incompatíveis, anulando-se nos Evangelhos.'),('NT02-L08-Q02','NAO SEI','As evidencias se baseiam nos manuscritos de Qumran e na Septuaginta','As evidencias vem da tradicao apostolica e dos concilios ecumenicos','As evidencias sao encontradas na concordancia dos textos profeticos e seu cumprimento'),('NT02-L08-Q03','NAO SEI','Confirma a prioridade literaria de Mateus sobre Marcos','Indica que Marcos foi o ultimo evangelho canonico','Mostra que Marcos copiou literalmente de Lucas'),('NT02-L08-Q06','Porque se fundamenta em critérios histórico-críticos externos, não em afirmação doutrinária das Escrituras','Porque o texto bíblico a afirma explicitamente como dogma de fé','Porque foi definida solenemente como dogma no Concílio de Trento','Porque toda a tradição patrística a confirma como artigo de fé'),('NT02-L09-Q01','Fonte Q: hipotética coleção de ditos de Jesus usada por Mateus e Lucas','Fonte de narrativas e milagres comum aos três evangelhos sinóticos','Coleção exclusiva de Lucas com material ausente em Mateus','Documento veterotestamentário usado como base dos Evangelhos'),('NT02-L08-Q05','Farmer, Dungan, Goulder, Goodacre e Farrer defendem alternativas a Marcos','Bultmann, Käsemann e Conzelmann são os principais proponentes de alternativas','Irineu, Tertuliano e Clemente de Alexandria propuseram alternativas a Marcos','Apenas Wrede e Reimarus contestaram a prioridade de Marcos'),('NT02-L09-Q04','NAO SEI','diferencas entre Mateus e Lucas nos relatos da infancia de Jesus','variacoes na ordem dos eventos da paixao nos sinoticos','diferencas de enfase teologica entre Paulo e Tiago sobre a justificação'),('NT02-L09-Q02','Recorrem à fonte de ditos Q como base comum sinótica','Baseiam-se apenas em tradições orais independentes','Usam o Evangelho de Tomé como fonte primária','Negam qualquer fonte compartilhada entre si'),('NT02-L09-Q03','NAO SEI','Todas narram o nascimento virginal de Jesus de forma detalhada','Todas registram a genealogia completa de José até Davi','Todas descrevem a infância de Jesus em Belém com os magos')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('NT02-L09-Q06','NAO SEI','Não acrescentar nem diminuir nada às Escrituras','Respeitar a intenção original de cada autor sagrado','Considerar o contexto histórico e cultural de cada passagem'),('NT02-L10-Q01','Transmitir oralmente os ensinamentos e atos de Jesus antes dos Evangelhos.','Substituir as Escrituras do Antigo Testamento pela tradição oral dos fariseus.','Impedir a composição escrita dos Evangelhos por ordem dos apóstolos.','Registrar oficialmente os dogmas do Concílio de Jerusalém aos gentios.'),('NT02-L10-Q03','Atestaram a verdade do evangelho e a transmitiram fielmente','Interpretaram as profecias messiânicas para os gentios','Escreveram a lei mosaica sob inspiração divina','Estabeleceram os rituais do templo em Jerusalém'),('NT02-L10-Q06','Organizaram tradições conforme propósitos teológicos, sob inspiração divina.','Copiaram literalmente de um único evangelho sem edições próprias.','Inventaram as narrativas sem fundamento em tradições prévias.','Organizaram o material seguindo apenas a ordem cronológica dos fatos.'),('NT02-L11-Q01','Mateus e Lucas','Marcos e João','Mateus e João','Marcos e Lucas'),('NT02-L10-Q04','NAO SEI','...','...','...'),('NT02-L11-Q04','Auxiliar a memorização e evidenciar o cumprimento das promessas a Davi.','Seguir o modelo das genealogias romanas organizadas por ciclos políticos.','Separar a descendência biológica da legal para evitar contestações farisaicas.','Corresponder ao número de livros do Antigo Testamento hebraico.'),('NT02-L11-Q05','Mateus agrupa a genealogia de Jesus em três séries de catorze gerações.','Mateus lista vinte e quatro profetas entre Abraão, Davi e o exílio babilônico.','Mateus registra sete pactos distintos firmados com Abraão, Davi e durante o cativeiro.','Mateus descreve três exílios diferentes do povo de Israel antes do nascimento de Jesus.'),('NT02-L11-Q02','Gn 5, 10 e 11; 1Cr 1-9; Mt 1; Lc 3','Apenas no livro de Gênesis','Somente nos Evangelhos','Em Êxodo, Levítico e Números'),('NT02-L11-Q06','Mostrando Jesus como descendente de Adão e filho de Deus','Limitando a genealogia apenas até Abraão','Iniciando a linhagem em Zorobabel até Adão','Apresentando a descendência de Jesus por Ismael'),('NT02-L12-Q01','Não, os Evangelhos Sinóticos nem sempre seguem a mesma ordem.','Sim, Mateus, Marcos e Lucas narram os fatos na mesma sequência.','Sim, os três Evangelhos seguem uma ordem cronológica idêntica.','Apenas Mateus e Marcos apresentam a mesma ordem dos fatos.'),('NT02-L12-Q02','A história antiga priorizava o significado teológico sobre a cronologia estrita','Porque não possuíam calendários precisos para datar os eventos','Porque a imprensa ainda não existia para padronizar as narrativas','Porque a transmissão oral obrigava inverter a ordem dos fatos'),('NT02-L11-Q07','Levirato; genealogia de Maria versus José; linhagem real versus biológica','José era filho adotivo de ambos por costumes tribais diferentes','Heli e Jacó eram avô e neto com mesmo nome por tradição oral','Apenas a genealogia de Mateus é verdadeira, a de Lucas é apócrifa'),('NT02-L12-Q03','Paixão, morte e ressurreição de Jesus','Nascimento e infância em Nazaré','Fuga para o Egito e retorno','Anos ocultos antes do batismo'),('NT02-L12-Q04','Revelam a estrutura teológica e a lógica organizacional de cada evangelista','Marcam apenas as transições geográficas entre as cenas dos evangelhos','Separam eventos sem revelar a intenção organizacional de cada autor','Indicam que todos os evangelhos seguem a mesma sequência temporal'),('NT02-L12-Q06','Ordena os fatos no tempo, sem substituir a perspectiva teológica de cada autor.','Inutiliza o trabalho dos evangelistas ao impor uma sequencia unica e rigida.','Substitui os textos originais por uma reconstrucao artificial da historia.','Apaga as diferencas entre os sinoticos para manter apenas o relato de Lucas.'),('NT02-L12-Q05','Porque isso constitui acréscimo à revelação, indo além do que o texto sagrado afirma','Porque a cronologia bíblica é meramente simbólica e espiritual','Porque os autores sagrados desconheciam a ordem dos eventos','Porque Deus ocultou a cronologia para testar a fé dos leitores'),('NT02-L13-Q01','Mostrar que Jesus é o Messias prometido e cumprimento das profecias','Apresentar Jesus como líder político contra o império romano','Mostrar Jesus como filósofo que trouxe sabedoria pagã ao mundo','Apresentar Jesus como sacerdote para abolir o templo de Jerusalém'),('NT02-L13-Q02','Apresentar Jesus como o Servo Sofredor, vindo para dar a vida em resgate por muitos','Apresentar Jesus como o grande legislador que restaurou a Lei de Moisés','Apresentar Jesus como um rei político que veio libertar Israel do jugo romano','Apresentar Jesus como o Sacerdote eterno que ofereceu sacrifícios contínuos no templo'),('NT02-L13-Q05','Cada evangelista seleciona o material conforme audiência e ênfase cristológica.','Os quatro evangelistas usaram as mesmas fontes e produziram textos idênticos.','Os evangelistas escolheram o material aleatoriamente, sem propósito teológico.','Somente João escreveu para produzir fé, os demais não tinham esse objetivo.'),('NT02-L13-Q03','Para que tenhas plena certeza das coisas que foste ensinado','Para demonstrar que Jesus é o Messias prometido a Israel','Para corrigir os erros dos evangelhos anteriores','Para registrar as genealogias de José e Maria'),('NT02-L13-Q04','Adaptam temas, linguagem e ênfases ao perfil cultural e religioso do público.','Os Evangelhos possuem ênfases fixas e imutáveis, independentes de quem os lê.','As ênfases dependem exclusivamente da inspiração divina, sem considerar o leitor.','Apenas o Evangelho de João foi escrito para gentios, os demais para judeus.'),('NT02-L13-Q06','NAO SEI','Porque foram revelados em tempos diferentes aos patriarcas','Porque um depende da observancia da lei mosaica','Porque so se aplicam apos a vinda do Espirito Santo'),('NT02-L14-Q04','NAO SEI','Os evangelhos sinoticos divergem na ordem dos eventos da paixao','Joao omite a instituicao da ceia registrada nos sinoticos','Marcos prioriza o ministerio na Galileia sobre a Judeia'),('NT02-L14-Q02','NAO SEI','Os tres usam o termo exclusivamente como realidade futura e escatologica sem distincoes','Somente Lucas trata do reino de deus, Mateus fala apenas em reino dos ceus','Marcos nega a existencia do reino terreno e defende apenas o reino espiritual abstrato'),('NT02-L14-Q03','NAO SEI','Os tres registram o mesmo Sermao da Montanha com palavras identicas','Todos comecam com a genealogia de Jesus desde Abraao','Compartilham exatamente as mesmas palavras nas parabolas'),('NT03-L01-Q05','NAO SEI','A fé do centurião e a incredulidade dos fariseus','A obediência de Noé e a incredulidade dos gigantes','A fé de Tomé e a incredulidade de Pedro'),('NT03-L02-Q02','NAO SEI','Gênesis 1','Apocalipse 22','Salmos 23'),('NT02-L14-Q01','O reino de Deus é o governo soberano de Deus inaugurado em Jesus','O reino de Deus é apenas uma realidade celestial futura e distante','O reino de Deus se limita à restauração política de Israel','O reino de Deus é a estrutura eclesiástica visível na terra'),('NT03-L02-Q04','Revelar Jesus como o Cristo, Filho de Deus, servo sofredor que dá a vida em resgate','Apresentar Jesus apenas como profeta que condena os pecados de Israel','Mostrar Jesus como rei político que restauraria o trono de Davi na terra','Revelar Jesus como mestre da lei que veio abolir os mandamentos'),('NT03-L02-Q06','NAO SEI','O livro revela o amor redentor de Deus à humanidade','O livro demonstra que o Evangelho visa a salvação dos perdidos','O livro confirma que o Evangelho foi escrito para fortalecer a fé'),('NT03-L02-Q05','NAO SEI','Creio, Senhor! Ajuda-me na minha falta de fé','Senhor, creio; mas acrescenta-me fé','Eu creio que tu és o Cristo, o Filho de Deus'),('NT03-L03-Q02','O Logos divino, criação, encarnação, luz, graça e verdade.','Purificação, sacrifícios, leis cerimoniais e sacerdócio levítico.','Visões apocalípticas, selos, trombetas e taças da ira.','Parábolas do reino, sementes, joio e crescimento.'),('NT03-L03-Q03','O Verbo estava com Deus e era Deus, e por ele todas as coisas foram feitas.','O Verbo era uma criatura angelical que serviu como instrumento na criação.','O Verbo se tornou igual a Deus somente depois de sua encarnação em Jesus.','Deus criou o universo sozinho, sem qualquer participacao do Verbo eterno.'),('NT03-L07-Q03','O diálogo com Maria e a ordem de encher as talhas de água','A multiplicação dos pães junto ao mar da Galileia','A tempestade acalmada no lago por ordem a Pedro','A cura do cego de nascença com argila no tanque'),('NT03-L03-Q04','O Verbo é a luz e a vida; João Batista testificou, e os seus o rejeitaram.','O Verbo é o pão da vida; Pedro testificou, e os fariseus o rejeitaram.','Jesus é a porta das ovelhas; Paulo testemunhou, e os gentios o receberam.','Moisés trouxe a luz da lei no Sinai; Elias profetizou, e o povo o aceitou.'),('NT03-L08-Q04','É necessário nascer da água e do Espírito para entrar no Reino de Deus','É necessário nascer do sangue e do fogo para entrar no Reino de Deus','Basta ser batizado nas águas para entrar no Reino de Deus','A água e o Espírito são apenas símbolos sem efeito para o Reino'),('NT03-L08-Q03','Interpretou literalmente a expressão nascer de novo, sem captar o sentido espiritual.','Porque era fariseu e desconhecia as escrituras hebraicas.','Por ser idoso e não conseguir compreender os ensinamentos.','Porque era membro do Sinédrio e se opunha a Jesus.'),('NT03-L08-Q02','Renascimento espiritual operado pelo Espírito Santo pela fé em Cristo','Ressurreição física do corpo que ocorrerá no último dia','Circuncisão do prepúcio como sinal da aliança com Deus','Batismo ritual nas águas que apaga todos os pecados'),('NT03-L08-Q07','Porque importa nascer de novo, do Espírito Santo','Porque as tradições humanas justificam o pecador','Porque o saber intelectual garante a salvação eterna','Porque as obras da lei aperfeiçoam a nova criatura'),('NT03-L09-Q01','No poço de Jacó','No rio Jordão','No templo de Jerusalém','No deserto da Judeia'),('NT03-L09-Q03','A água viva simboliza o Espírito Santo, fonte de vida eterna concedida por Cristo.','Refere-se às águas do rio Jordão, que purificavam os pecados dos pecadores.','Jesus falava sobre uma nascente natural que jorrava no deserto da Judeia.','Era a água que brotou da rocha quando Moisés feriu o deserto com a vara.'),('NT03-L09-Q04','Revelando que tivera cinco maridos e o atual não era seu','Curando a mulher de uma grave enfermidade que a afligia','Ressuscitando o filho único que ela havia perdido','Perdoando seus pecados depois que ela os confessou'),('NT03-L09-Q05','O debate entre Jesus e a mulher samaritana sobre Jerusalém e o monte Gerizim','O debate entre Moisés e Arão sobre o tabernáculo no deserto','O debate entre Elias e os profetas de Baal no monte Carmelo','O debate entre Davi e Saul sobre sacrifícios em Gileade'),('NT03-L09-Q06','Adorar a Deus com o coração sincero, segundo a Palavra, sem formalismo.','Adorar somente no templo de Jerusalém com sacrifícios de animais.','Realizar apenas rituais externos e cerimônias religiosas vazias.','Buscar experiências místicas sem nenhum fundamento bíblico.'),('NT03-L09-Q07','Contou aos samaritanos sobre Jesus, e muitos creram por seu testemunho.','Os samaritanos a seguiram após ela multiplicar os pães','Ela batizou todos os samaritanos nas águas do poço','Curou os enfermos da cidade com poder recebido de Jesus'),('NT03-L10-Q02','NAO SEI','Gênesis capítulo 3','Apocalipse capítulo 22','Salmos capítulo 23'),('NT03-L10-Q01','Jesus é o pão da vida que desceu do céu dando vida eterna','Moisés deu ao povo o verdadeiro pão vindo do céu santo','O pão da vida se resume ao alimento físico do dia a dia','O pão da vida é apenas o pão partido na ceia pascoal'),('NT03-L10-Q05','NAO SEI','Os discipulos creram e adoraram a Jesus como o Messias prometido','Os fariseus se converteram apos ouvirem os ensinos de Cristo','O povo reconheceu Jesus como profeta sem duvidas nem hesitações'),('NT03-L10-Q04','Jesus é o pão da vida, fonte de sustento espiritual e vida eterna.','Jesus é o pão literal que sacia a fome física de todos.','O maná do deserto foi o verdadeiro pão da vida permanente.','Jesus é apenas um profeta que multiplicou pães na multidão.'),('NT03-L11-Q02','NAO SEI','Gênesis 1','Apocalipse 22','Salmos 23'),('NT03-L11-Q05','NAO SEI','Somente fé demonstrada pela multidão','Apenas incredulidade dos fariseus','Resposta neutra dos escribas'),('NT03-L11-Q03','João 8:12 - Eu sou a luz do mundo','Gênesis 1:3 - Haja luz','Mateus 5:14 - Vós sois a luz do mundo','Apocalipse 21:23 - A glória de Deus a iluminou'),('NT03-L11-Q06','Para que vejam as vossas boas obras e glorifiquem o Pai','Para que a luz do mundo julgue os pecadores no fim dos tempos','Para que os homens conheçam apenas a vossa sabedoria e dons','Para que a vossa luz seja escondida dos olhos dos homens'),('NT03-L12-Q02','NAO SEI','Gênesis 3','Apocalipse 22','Salmos 23'),('NT03-L12-Q01','Eu sou o bom pastor que dá a sua vida pelas ovelhas','Jesus é o bom pastor que governa as nações com vara de ferro','Jesus é o bom pastor que entrega as chaves do reino a Pedro','Jesus é o bom pastor que batiza com o Espírito Santo e fogo'),('NT03-L11-Q04','Jesus é a luz divina que revela o caminho de Deus e liberta das trevas do pecado','Jesus é a luz que ensina moral sem identidade divina','Moisés foi a luz do mundo que guiou Israel para fora do Egito','A luz do mundo refere-se apenas à sabedoria humana de Jesus'),('NT03-L12-Q04','Jesus se revela como Pastor que conhece, protege e entrega a vida pelas ovelhas.','Jesus é apenas um governante terreno que lidera Israel com autoridade política.','Jesus guia o povo somente por ensinamentos morais, sem sacrifício pessoal.','Moisés foi o bom pastor que libertou Israel da opressão egípcia no deserto.'),('NT03-L12-Q05','NAO SEI','Crer em Cristo e ser batizado','Endurecer o coração como Faraó','Confiar nas obras da lei'),('NT03-L12-Q06','Dá a vida pelas ovelhas para cumprir o propósito de salvação e vida eterna','Estabelece um reino político terreno em Israel para dominar as nações','Recruta discípulos para formar um exército contra os invasores romanos','Ensina apenas os judeus, excluindo os gentios do seu rebanho'),('NT03-L16-Q04','Revela Jesus como Senhor, pois o Consolador procede do Pai e testifica dele','Revela Jesus apenas como profeta, pois o Consolador age sem ele','Mostra Jesus subordinado ao Espírito, que substitui sua missão','Indica que Jesus é precursor do Consolador, sem autoridade divina'),('NT03-L12-Q03','Eu sou o bom Pastor; o bom Pastor dá a sua vida pelas ovelhas.','Eu sou a porta das ovelhas; quem entra por mim será salvo.','O Senhor é o meu Pastor; com nada me deixará faltar.','Apascenta as minhas ovelhas, e não as deixes perecer.'),('NT03-L17-Q01','João 17','João 13','João 14','João 18'),('NT03-L17-Q02','NAO SEI','A pergunta não especifica qual oração está sendo referida.','Faltam informações para identificar a oração mencionada.','O contexto da oração não foi fornecido na pergunta.'),('NT03-L17-Q03','Pai, glorifica o teu Filho, para que o Filho te glorifique','Pai, glorifica o teu nome acima de toda a criação','Pai, salva-me desta hora que agora sobrevém','Pai, revela a tua glória aos homens por meu meio'),('NT03-L14-Q08','Revelam Sua divindade, missão salvífica e suficiência plena para a humanidade.','Revelam apenas ensinamentos éticos, sem afirmar divindade ou missão salvífica.','Mostram que Jesus era somente um profeta entre vários, sem identidade divina.','Revelam um líder terreno buscando estabelecer um reino político material em Israel.'),('NT03-L17-Q04','Para que os guarde do mal','Para que tenham saúde e prosperidade','Para que o mundo os aceite','Para que evitem todo sofrimento'),('NT03-L16-Q06','O Consolador convence do pecado, guia à verdade e aplica a salvação.','O Consolador substitui Cristo na terra e elimina a necessidade da fé.','O Consolador apenas consola os aflitos, sem relação com a salvação.','O Consolador foi prometido apenas aos apóstolos, sem efeitona Igreja.'),('NT03-L17-Q07','Unidade do Espírito','Unidade apostólica','Unidade cerimonial','Unidade de governo'),('NT03-L17-Q06','Pela unidade dos que creriam nele','Pela destruição dos seus inimigos','Pelo fim imediato do mundo','Pela conversão dos fariseus'),('NT03-L17-Q05','Ser preservado pelo poder de Deus e separado para Ele por meio da Sua palavra.','Significa que uma vez salvo, a pessoa nunca mais pode perder a salvação.','Refere-se a um ritual cerimonial que purifica o corpo e a alma do crente.','Indica que Deus dará aos crentes um nome completamente novo e celestial.'),('NT03-L17-Q08','Revela comunhão eterna, amor mútuo e submissão amorosa do Filho ao Pai','Mostra que Jesus era apenas humano e aprendia a orar','Revela que o Filho foi criado depois do Pai','Indica que o Pai abandonou o Filho na cruz'),('NT03-L18-Q01','Jesus demonstra soberania divina, cumprindo voluntariamente a obra do Pai','Jesus sofre como vitima passiva, submisso a violencia dos homens','A paixao em Joao enfatiza apenas o sofrimento fisico intenso de Cristo','O evangelho narra a paixao de forma identica aos sinoticos Mateus e Marcos'),('NT03-L18-Q02','NAO SEI','Gênesis 1','Apocalipse 22','Salmos 23'),('NT03-L18-Q05','NAO SEI','A fé de Abraão e a incredulidade dos egípcios','A obediência de Noé e a incredulidade de Caim','A fidelidade de Moisés e a rebelião de Esaú'),('NT03-L18-Q04','Na paixão, Jesus revela ser o Cordeiro Paschal enviado para dar vida eterna','A paixão mostra Jesus fracassando como Messias político esperado em Israel','Em João, a paixão revela Jesus apenas como vítima humana sem missão divina','A paixão em João apresenta Jesus como mártir involuntário sem glória divina'),('NT03-L19-Q02','NAO SEI','Gênesis 1','Apocalipse 22','Salmos 23'),('NT03-L18-Q03','Amou-os ate ao fim; chegada a hora; levantado; esta consumado','Sofrimento no Getsemani; Pai perdoa-lhes; sangue e agua','Crucificacao entre dois ladroes; morte; ressurreicao ao terceiro dia','Mansidao e paciencia; silencio perante Pilatos e escribas'),('NT03-L19-Q01','Eu sou a ressurreição e a vida','Eu sou o caminho, a verdade e a vida','Eu sou a videira verdadeira','Eu sou a porta das ovelhas'),('NT03-L19-Q05','NAO SEI','A fé de Abraão e a incredulidade de Faraó','A obediência de Moisés e a rebelião de Corá','A confiança de Davi e a dúvida de Tomé'),('NT03-L19-Q03','Eu sou a ressurreição e a vida','Bem-aventurados os puros de coração','O Senhor é meu pastor, nada me faltará','Amai os vossos inimigos, fazei o bem'),('NT03-L19-Q04','A ressurreição revela Jesus como Senhor e Deus, confirmando sua missão salvífica','Jesus é apenas profeta humano, sem autoridade divina sobre a morte','A ressurreição é somente metáfora espiritual, sem acontecimento real','Jesus foi somente mestre moral, sem missão divina de salvação'),('NT03-L20-Q03','Porque Ele se declarava igual a Deus, o Pai','Porque Ele se recusava a jejuar como os fariseus','Porque Ele ensinava sem ter formação rabínica','Porque Ele criticava a lei de Moisés publicamente'),('NT03-L20-Q02','Jesus disse que o Pai que habitava nele é quem fazia as obras','Jesus realizava as obras unicamente por seu próprio poder divino','As obras de Jesus tinham como único fim impressionar as multidões','Jesus agia de forma totalmente independente, sem consultar o Pai'),('NT03-L20-Q05','Confirma a divindade de Cristo e expressa a fé cristã','Tomé perdeu a posição de apóstolo por causa de sua dúvida','A confissão de Tomé foi feita na Galileia','Jesus repreendeu Tomé por chamá-lo de Deus'),('NT03-L20-Q06','Afirmando ''o Pai é maior do que eu'' e mostrando o Filho em submissão ao Pai','Identificando Pai e Filho como dois títulos diferentes para o mesmo ser','Declarando que o Filho possui autoridade absoluta idêntica à do Pai','Ensinando que Pai e Filho são dois modos de manifestação do mesmo Deus uno'),('NT03-L20-Q04','Ecoam o nome Javé de Êxodo 3:14, afirmando a divindade de Jesus.','Identificam Jesus apenas como um mestre moral sem pretensões divinas.','São títulos honoríficos comuns que os judeus usavam para reconhecer rabinos.','Referem-se somente à autossuficiência humana de Jesus como exemplo moral.'),('NT03-L21-Q02','NAO SEI','Gênesis 1','Apocalipse 22','Salmos 23'),('NT03-L21-Q01','Quem crê em Jesus Cristo tem a vida eterna (Jo 3:16)','A salvação vem pelas obras da lei e não pela fé','Quem crê em Jesus tem a vida eterna só após morrer','A vida eterna é prometida só ao povo judeu eleito'),('NT03-L20-Q07','Porque somente Cristo, sendo Deus, podia oferecer sacrifício infinito pelo pecado.','Porque Cristo demonstrou ser exemplo moral perfeito para a humanidade seguir.','Porque Sua divindade garante que Ele retornará para estabelecer um reino terreno.','Porque sem ela, Ele seria apenas mais um profeta entre muitos de Israel.'),('NT03-L21-Q05','NAO SEI','A fé de Abraão ao oferecer Isaque','A incredulidade de Tomé após a ressurreição','A fé do centurião romano'),('NT03-L21-Q03','Tu tens as palavras da vida eterna','Eu sou a ressurreição e a vida','O justo viverá pela fé','Eu sou o caminho, a verdade e a vida'),('NT03-L21-Q06','Fé e vida eterna são o alvo do Evangelho: crer para ter vida','A fé substitui a lei e a vida eterna é recompensa por obras','O Evangelho tem como propósito principal a prosperidade temporal','A vida eterna é conquistada por esforço próprio mediante a fé'),('NT04-L01-Q01','O censo de César Augusto e Quirino como governador da Síria','A crucificação de Jesus e sua posterior ressurreição','O cativeiro babilônico e a libertação pelo rei Ciro','A perseguição religiosa de Antíoco Epifânio contra os judeus'),('NT03-L21-Q04','Conhecer o único Deus verdadeiro e Jesus Cristo, o enviado, é a vida eterna','A vida eterna se alcança pelas obras meritórias e pela observância da lei','Conhecer Jesus unicamente pelo conhecimento intelectual garante a vida eterna','A identidade messiânica de Jesus se revela somente ao sacerdócio judeu'),('NT04-L01-Q03','NAO SEI','Moisés, Israel, Egito, Êxodo','Davi, Jerusalém, Israel, monarquia','Paulo, Éfeso, Roma, cristianismo primitivo'),('NT04-L01-Q02','NAO SEI','Mateus, Marcos, Lucas e João','Mateus e Lucas','Apenas em João'),('NT04-L01-Q05','NAO SEI','Conforme está escrito: o Messias haveria de sofrer e ressuscitar ao terceiro dia','Para que se cumprisse a profecia de Isaías sobre o servo sofredor','Assim como Moisés levantou a serpente no deserto, importa que o Filho do homem seja levantado'),('NT04-L01-Q04','Jesus é o Messias prometido, descendente de Davi, nascido em Belém para salvar','Jesus era um líder político romano enviado para governar Israel e Judeia','Jesus nasceu como rei terreno em um grande palácio para governar Jerusalém','Jesus era um profeta enviado apenas para condenar e julgar todos os pecadores'),('NT04-L01-Q06','NAO SEI','A perseguição de Herodes obrigou a fuga para o Egito, formando os discípulos','O censo romano uniu José e Maria em Belém para a vinda do Messias','Os magos do Oriente anunciaram o Evangelho aos discípulos desde o nascimento')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('NT04-L02-Q04','NAO SEI','A primeira lista contém sete itens e a segunda contém doze itens','A primeira lista está no Antigo Testamento e a segunda no Novo Testamento','A primeira lista foi escrita por Moisés e a segunda por Paulo'),('NT04-L02-Q03','Pela genealogia que apresenta Jesus como descendente de Adão e filho de Deus.','Por meio da parábola do bom samaritano, Jesus se identifica com toda a humanidade.','Pela genealogia que vai de Abraão a Davi e a Jesus, cumprindo as promessas.','Através da transfiguração no monte, Jesus revela sua glória à humanidade.'),('NT04-L02-Q05','Uma linhagem é de José e outra de Maria','Uma linhagem vem de Salomão e outra de Absalão','São linhagens de reis e profetas diferentes','Uma linhagem é real e a outra sacerdotal'),('NT04-L02-Q02','Por meio da genealogia que abre o seu evangelho','Através das profecias messiânicas de Isaías','Por meio do Sermão da Montanha','Através do batismo de Jesus por João Batista'),('NT04-L03-Q02','NAO SEI','Mateus, Marcos, Lucas e João','Apenas em Mateus e Lucas','Nos quatro Evangelhos canônicos'),('NT04-L03-Q03','NAO SEI','Adao, Eva e o Jardim do Eden no seculo XXX a.C.','Moisés, Faraó e o Egito no periodo do Exodo','Davi, Golias e Israel no tempo dos Juizes'),('NT04-L03-Q01','Anunciação do anjo Gabriel a Zacarias no templo','Anunciação do anjo Gabriel a Maria em Nazaré','Batismo de Jesus nas águas do rio Jordão','Apresentação do menino Jesus no templo'),('NT04-L03-Q05','NAO SEI','Cumprindo a profecia de Isaías sobre o servo sofredor','Retomando a aliança de Abraão e a promessa do descendente','Cumprindo o tipo do cordeiro pascoal sacrificado na Páscoa'),('NT04-L03-Q04','Que Jesus é o Messias prometido, cujo caminho João preparou como precursor','Que João Batista era superior a Jesus em autoridade e poder espiritual','Que Jesus era apenas um discípulo de João Batista e não seu superior','Que João Batista era o Messias esperado e Jesus veio apenas como seu sucessor'),('NT04-L04-Q02','NAO SEI','Mateus, Marcos e Lucas','Mateus, Marcos, Lucas e João','Apenas João'),('NT04-L03-Q06','Encheu-se do Espírito Santo e preparou o caminho do Senhor','Tornou-se sumo sacerdote e ofereceu sacrifícios no templo','Escreveu cartas às sete igrejas da Ásia Menor','Reinou em Judá após a morte do rei Herodes'),('NT04-L04-Q03','NAO SEI','Moisés, Egito e o êxodo do povo hebreu','Davi, Jerusalém e o reino unificado de Israel','Paulo, Roma e a expansão do cristianismo no século I'),('NT04-L04-Q05','NAO SEI','Cumpriu-se a profecia de Isaías acerca do Messias sofredor','Retomou as promessas feitas a Abraão sobre a descendência','Realizou-se a visão de Ezequiel sobre o vale dos ossos secos'),('NT04-L05-Q01','Nascimento em Belém, magos, fuga ao Egito e apresentação no templo','Batismo no rio Jordão, tentação no deserto e primeiro milagre em Caná','Transfiguração no monte, ressurreição de Lázaro e entrada em Jerusalém','Última ceia, crucificação e ressurreição ao terceiro dia'),('NT04-L05-Q03','NAO SEI','Moisés, Egito e o êxodo dos hebreus','Jesus, Nazaré e o império romano','Davi, Jerusalém e o reino de Israel'),('NT04-L05-Q02','NAO SEI','Mateus, Marcos, Lucas e João','Apenas nos Evangelhos Sinóticos','Somente no Evangelho de João'),('NT04-L04-Q04','Jesus é o Messias, Deus encarnado, nascido para salvar seu povo dos pecados','Jesus nasceu como um simples profeta humano, sem qualquer identidade divina','Jesus veio estabelecer um reino político terreno para libertar Israel de Roma','Jesus nasceu apenas como mestre moral, sem missão de salvação dos pecados'),('NT04-L06-Q01','João Batista','O apóstolo Pedro','O profeta Moisés','O apóstolo Tiago'),('NT04-L06-Q02','No rio Jordão','No mar da Galiléia','No rio Nilo','No rio Eufrates'),('NT04-L05-Q04','Revela que Jesus é o Messias, o Filho de Deus e o Salvador universal','Jesus era apenas um menino obediente sem identidade especial','Jesus nasceu para ser um rei político e libertar Israel de Roma','A infância de Jesus é amplamente detalhada nos quatro evangelhos'),('NT04-L06-Q03','Para cumprir toda a justiça','Para lavar os pecados do mundo','Para ser reconhecido pelos fariseus','Para obedecer a João Batista'),('NT04-L05-Q06','NAO SEI','Jesus revelou aos discípulos os mistérios do Reino durante sua infância em Nazaré','Os discípulos foram formados teologicamente na infância de Cristo em Belém','A infância de Jesus em Nazaré resultou na escrita dos quatro Evangelhos'),('NT04-L06-Q04','O Pai fala dos céus, o Filho é batizado, o Espírito desce como pomba','O Pai aparece a Moisés, o Filho ressuscita Lázaro, o Espírito em Pentecostes','Pai ordena a Abraão, o Filho purifica o templo, o Espírito fala a Moisés','Pai cria a luz, o Filho é ungido em Betânia, o Espírito guia Elias'),('NT04-L06-Q05','Este é o meu Filho amado, em quem tenho complacência','Este é o meu Filho amado, em quem me comprazo','Tu és o meu Messias, em quem tenho complacência','Este é o meu servo fiel, em quem tenho complacência'),('NT04-L05-Q05','NAO SEI','Cumpre a profecia de Miqueias sobre o Messias nascido em Belém','Retoma a aliança feita com Abraão acerca de sua descendência','Realiza a promessa do novo coração predita por Ezequiel'),('NT04-L07-Q01','No deserto','No templo de Jerusalém','No monte Sinai','No Jardim do Éden'),('NT04-L06-Q07','Identifica com Cristo, unge com o Espírito e cumpre a justiça divina.','Purifica do pecado original, apaga a culpa e concede a vida eterna.','Garante a salvação, perdoa pecados e impõe as mãos do sacerdote.','Inicia na igreja, ensina os mandamentos e confirma a profecia final.'),('NT04-L07-Q03','Pedras em pão, lançar-se do templo e adorar Satanás pelos reinos.','Riquezas materiais, poder político e fama entre os judeus.','Fome no deserto, prisão pelos soldados e renúncia à missão.','Multiplicar pães, curar enfermos e ressuscitar mortos no templo.'),('NT04-L07-Q02','Quarenta dias e quarenta noites','Doze dias e doze noites jejuando','Sete dias jejuando no deserto','Vinte dias e vinte noites em jejum'),('NT04-L07-Q07','NAO SEI','Jesus é plenamente Deus e plenamente homem em duas naturezas','A obediência de Cristo foi apenas simbólica e não real','Sua humanidade era uma aparência sem verdadeira natureza humana'),('NT04-L08-Q01','Batismo no Jordão, tentação no deserto e chamada dos primeiros discípulos','Transfiguração no monte, última ceia e crucificação','Nascimento em Belém, circuncisão e fuga para o Egito','Ressurreição, ascensão aos céus e derramamento do Espírito'),('NT04-L07-Q06','Jesus é o segundo Adão obediente e o verdadeiro Israel fiel','Jesus vence por meio de um exército terreno contra Roma','Jesus vence somente os judeus, excluindo os gentios da salvação','Jesus vence pela riqueza e poder político como o rei Salomão'),('NT04-L08-Q02','NAO SEI','Mateus, Marcos e Lucas','Somente em João','Todos os quatro Evangelhos'),('NT04-L08-Q03','NAO SEI','Moisés, Egito e o Mar Vermelho durante o Êxodo','Davi, Jerusalém e o reino unificado de Israel','Jesus, Belém e o Império Romano no século I'),('NT04-L08-Q05','NAO SEI','Cumpre a profecia de Isaías sobre o Servo Sofredor','Retoma a aliança abraâmica com a nova criação','Realiza a promessa davídica do reino eterno'),('NT04-L08-Q04','Jesus é o Messias enviado a pregar o evangelho e salvar os pecadores','Jesus é um simples profeta que veio apenas ensinar a lei de Moisés','Jesus veio estabelecer um reino político terreno contra Roma','O ministério de Jesus tinha como objetivo curar enfermos na Galileia'),('NT04-L07-Q05','Ofereciam atalhos ao poder, buscando desviá-lo da cruz e da confiança no Pai','Jesus cedeu às tentações, mas se arrependeu antes de iniciar o ministério','As tentações eram apenas físicas, sem qualquer dimensão espiritual ou messiânica','Satanás convenceu Jesus a abandonar a missão da cruz por um reino terreno'),('NT04-L09-Q02','NAO SEI','Apenas em Mateus','Apenas em Lucas','Em todos os quatro Evangelhos'),('NT04-L08-Q06','Foram chamados a seguir Cristo e enviados para pregar o Evangelho','Foram enviados apenas para reconstruir o templo de Jerusalém','Receberam poder somente para julgar as tribos de Israel','Abandonaram Cristo imediatamente após o primeiro milagre'),('NT04-L09-Q03','NAO SEI','Moisés, Egito e o êxodo do povo hebreu','Davi, Jerusalém e a unificação das tribos','Paulo, Roma e a propagação do cristianismo'),('NT04-L09-Q05','NAO SEI','Cumpre a profecia de Miqueias sobre o nascimento em Belém','Retoma a aliança abraâmica com a promessa de descendência','Realiza a profecia isaiana do servo sofredor'),('NT04-L09-Q04','Jesus é o Messias, enviado para anunciar o Reino de Deus e fazer discípulos.','Revela que Jesus era apenas um mestre humano comum sem autoridade divina.','Mostra que Jesus buscava poder político para reinar sobre Israel.','Indica que Jesus veio abolir a lei e os profetas sem cumprir as Escrituras.'),('NT04-L10-Q02','NAO SEI','Somente em Mateus','Em Mateus, Marcos e Lucas','Em todos os quatro Evangelhos'),('NT04-L10-Q01','Batismo, tentação, sermão da montanha, milagres e chamada dos discípulos','Crucificação no Calvário, ressurreição e ascensão aos céus','A travessia do Mar Vermelho e as pragas do Egito','Conversão de Paulo e o primeiro Concílio de Jerusalém'),('NT04-L10-Q05','NAO SEI','Cumpre a profecia de que o Messias nasceria em Belém','Retoma a aliança feita com Abraão no Sinai','Realiza a promessa do novo céu e nova terra'),('NT04-L10-Q03','NAO SEI','Moisés, Egito e a travessia do Mar Vermelho','Davi, Jerusalém e o reinado de Israel','Paulo, Roma e as viagens missionárias'),('NT04-L10-Q04','Jesus é o Messias prometido que veio pregar o evangelho e curar enfermos','Jesus era apenas um profeta comum sem autoridade divina alguma','O reino de Deus seria estabelecido por meio do poder político e militar','Jesus buscava reconhecimento pessoal e glória mundana para si'),('NT04-L10-Q06','Os discípulos foram instruídos e o Evangelho se propagou','Os discípulos foram presos imediatamente pelas autoridades romanas','O ministério trouxe grande riqueza material aos discípulos','Os discípulos abandonaram definitivamente o ensino das Escrituras'),('NT04-L11-Q02','NAO SEI','Mateus, Marcos, Lucas e João','Apenas em Mateus e João','Somente nos Evangelhos Sinóticos'),('NT04-L11-Q05','NAO SEI','Cumpre a profecia de Isaías sobre o Servo Sofredor','Retoma a aliança feita com Abraão e sua descendência','Realiza a promessa do novo coração feita por Ezequiel'),('NT04-L11-Q04','Revelam que Jesus é o Messias universal, cuja missão é salvar toda a humanidade','Mostram que Jesus era apenas um peregrino sem destino fixo na Terra','Revelam que Jesus buscava poder político em Roma para libertar Israel','Indicam que Jesus fugia das autoridades romanas por medo da prisão'),('NT04-L11-Q03','NAO SEI','Noé, arca e dilúvio','Moisés, Egito e êxodo','Davi, Jerusalém e reino de Israel'),('NT04-L11-Q06','Os discípulos foram capacitados e o Evangelho se espalhou por diversas regiões','Jesus nunca saiu da Judeia e não viajou com seus seguidores','Os discípulos abandonaram a missão e o Evangelho foi esquecido','O Evangelho ficou restrito a Jerusalém sem alcançar outras regiões'),('NT04-L12-Q02','NAO SEI','Somente em Mateus','Nos quatro Evangelhos','Em Mateus, Marcos e Lucas'),('NT04-L12-Q03','NAO SEI','Moisés, Egito e o êxodo dos hebreus','Davi, Jerusalém e o reino unificado','Paulo, Roma e a propagação do evangelho'),('NT04-L12-Q05','NAO SEI','A profecia de Malaquias 3:1 sobre o mensageiro preparando o caminho','A aliança davídica confirmada em 2 Samuel 7','O servo sofredor descrito em Isaías 53'),('NT04-L12-Q04','Revelam que Ele é o Cristo, o Filho de Deus, enviado para salvar os pecadores','Revelam que Jesus era apenas um profeta entre muitos, sem autoridade divina','Revelam que seu objetivo era abolir totalmente a Lei e os profetas','Revelam que Jesus buscava poder político contra o Império Romano'),('NT04-L13-Q02','Moisés e Elias','Pedro e João','Abraão e Isaque','Davi e Salomão'),('NT04-L13-Q01','Pedro, Tiago e João','Pedro, André e Tiago','André, Filipe e Bartolomeu','Tomé, Mateus e Judas'),('NT04-L13-Q03','A sua glória divina','A fraqueza de Moisés e Elias','O início de seu reino terreno','A dor futura na cruz'),('NT04-L13-Q04','Fazer três tendas para Jesus, Moisés e Elias','Andar sobre as águas até Jesus','Negar Jesus três vezes','Cortar a orelha do servo do sumo sacerdote'),('NT04-L17-Q05','Um de vós me trairá','Pedro me negará por três vezes','Um dos fariseus me trairá','Serei vendido por trinta moedas'),('NT04-L17-Q03','Novo testamento no meu sangue','Sangue da pascoa antiga','Promessa do reino terreno','Lembranca do diluvio'),('NT04-L17-Q06','Jesus demonstra serviço e purificação ao lavar os pés dos discípulos como servo.','Pedro lavou os pés de Jesus na ceia como ato de purificação.','Jesus instituiu a ceia como memorial perpétuo da purificação.','Moisés lavou os pés dos hebreus no deserto como sinal da aliança.'),('NT04-L18-Q02','Pedro, Tiago e João','Pedro, André e Filipe','Pedro, Tiago e Tomé','Pedro, João e Judas'),('NT04-L18-Q04','Pai, se possível, passa de mim este cálice; todavia não se faça a minha vontade, mas a tua','Jesus pediu que o cálice da alegria fosse compartilhado com os discípulos no Reino','O cálice representa a ceia pascoal que deveria ser celebrada imediatamente','Significava o pedido para que Judas bebesse do cálice da traição'),('NT04-L18-Q03','A alma triste até a morte, no Getsêmani','A dor física da flagelação no pretório','O abandono dos discípulos no Calvário','A zombaria dos soldados diante da cruz'),('NT04-L18-Q05','Orando: ''Não seja a minha vontade, mas a tua''','Jejuando quarenta dias no deserto','Pregando o Sermão da Montanha','Multiplicando os pães e os peixes'),('NT04-L18-Q06','Por causa da tristeza, seus olhos se tornaram pesados de sono.','Porque foram afetados por um espirito maligno que os fez adormecer.','Por terem comido demais na ceia e estarem com o estomago pesado.','Por ordem de Jesus, que quis estar so no momento da oracao.'),('NT04-L19-Q01','Getsêmani, traição de Judas, prisão, julgamento e negação de Pedro','Batismo no Jordão, tentação no deserto e primeiro milagre em Caná','Transfiguração no monte, cura dos cegos e entrada em Jerusalém','Aparecimento a Maria Madalena, ascensão aos céus e Pentecostes'),('NT04-L19-Q03','NAO SEI','Moisés, Egito e o êxodo dos hebreus','Davi, Jerusalém e o reino de Israel','Paulo, Roma e a expansão do cristianismo'),('NT04-L19-Q05','NAO SEI','Cumpre a profecia de Miqueias sobre o nascimento em Belém','Retoma a aliança abraâmica feita com os patriarcas','Realiza a promessa do Messias davídico libertador'),('NT04-L19-Q06','Foram açoitados, mas regozijaram-se e nunca cessaram de pregar Jesus Cristo','Os discípulos fugiram de Jerusalém e abandonaram a pregação','A prisão encerrou definitivamente a missão dos apóstolos em Israel','Pedro negou Jesus Cristo mais uma vez durante a perseguição'),('NT04-L19-Q02','NAO SEI','Mateus, Marcos e Lucas','Somente em João','Mateus, Marcos, Lucas e João'),('NT04-L20-Q01','Sumos sacerdotes, escribas, anciãos e fariseus','Pílatos, Herodes e os soldados romanos','Os profetas, levitas e somente um sacerdote','Os zelotes, essênios e os escribas'),('NT04-L20-Q03','Os judeus não tinham autoridade para aplicar a pena de morte','Para que Pilatos o proclamasse rei dos judeus','Porque ele havia desrespeitado as leis do sábado','Para receber apenas um julgamento religioso'),('NT04-L20-Q02','Blasfêmia e ameaça de destruir o templo','Idolatria e prática de feitiçaria','Ruptura do sábado e consumo de porco','Negação da Torá e apostasia formal'),('NT04-L20-Q04','Perverter a nação, proibir tributo a César e dizer-se rei','Blasfêmia por dizer-se Filho de Deus e violar o sábado','Furto no templo, falsa profecia e rebeldia contra Moisés','Magia, possessão demoníaca e heresia contra a Torá'),('NT04-L20-Q06','Pilatos o soltou por costume da Páscoa, a pedido do povo.','Barrabás escapou da prisão durante um terremoto.','Herodes o libertou após julgamento em Jerusalém.','Foi solto por intercessão dos fariseus junto a Pilatos.'),('NT04-L20-Q05','Tetrarca da Galileia que julgou Jesus enviado por Pilatos','Rei de toda a Palestina que ordenou a morte do Messias','Sumo sacerdote que interrogou Jesus perante o Sinédrio','Governador romano da Judeia que sentenciou Jesus a morte'),('NT04-L21-Q01','Gólgota','Monte das Oliveiras','Jardim de Getsêmani','Monte Sião'),('NT04-L20-Q07','Julgamento noturno, falsas testemunhas, sem defesa e sentença de morte no mesmo dia','Julgamento público no templo durante o dia, com ampla defesa e absolvição unânime','Realizado com Pilatos e Herodes em acordo, condenando Jesus ao exílio','Decisão tomada após longo debate teológico entre fariseus e saduceus'),('NT04-L20-Q08','Por Pilatos, que declarou: Não acho nele culpa alguma','Por meio de sua ressurreição ao terceiro dia','Através de seus muitos milagres e curas','Pela sua ascensão ao céu junto ao Pai'),('NT04-L21-Q02','Simão de Cirene','José de Arimateia','Judas Iscariotes','Barrabás, o ladrão'),('NT04-L21-Q03','JESUS NAZARENO, REI DOS JUDEUS','JESUS NAZARENO, FILHO DE DEUS','JESUS NAZARENO, PRÍNCIPE DA PAZ','JESUS NAZARENO, PROFETA DA GALILEIA'),('NT04-L21-Q05','Escurecimento do sol, tremor de terra e o véu do templo rasgado','Forte tempestade de fogo e granizo que destruiu a cidade','Um anjo desceu e removeu a pedra do sepulcro','Sangue emanou da rocha e cobriu a tenda da congregação'),('NT04-L19-Q04','Jesus veio proclamar libertação aos cativos','Jesus esteve preso quarenta dias no deserto','Pedro libertou Paulo da prisão em Roma','Jesus fugiu da prisão do Sinédrio por milagre'),('NT04-L21-Q07','Morreu por nossos pecados segundo as Escrituras','Morreu apenas como exemplo moral para a humanidade','Sua morte foi um acidente político sem valor teológico','Morreu para estabelecer um reino terreno imediato em Israel'),('NT04-L21-Q06','Apresentam Jesus como cumprimento das profecias do Antigo Testamento','Mostram apenas o cumprimento das leis ceremoniais do judaismo','Apresentam promessas politicas de restauracao nacional de Israel','Narram somente simbolos sem qualquer base profetica biblica'),('NT04-L22-Q02','NAO SEI','Somente em Mateus','Apenas em João','Em todos os quatro Evangelhos'),('NT04-L22-Q03','NAO SEI','Moisés, Egito e o êxodo do povo hebreu','Davi, Jerusalém e o reinado de Israel','Paulo, Roma e a expansão do cristianismo'),('NT04-L22-Q05','NAO SEI','Conforme Mateus 5:17, Jesus veio para cumprir a Lei e os Profetas','Retoma a promessa feita a Abraão em Gênesis 12:3','Cumpre a profecia messiânica de Isaías 53'),('NT04-L21-Q04','O povo, principais sacerdotes, escribas, anciãos e soldados','Os fariseus, saduceus, essênios e zelotes da seita','Os apóstolos, discípulos, mulheres e centuriões','Os magos, profetas, reis gentios e sumo sacerdote'),('NT04-L22-Q04','Confirma a morte real de Jesus, sua humanidade e o cumprimento das profecias.','Revela que Jesus era apenas um homem comum sem qualquer missão divina.','Mostra que o sepultamento foi o fim absoluto da missão de Jesus na terra.','Indica que Jesus foi sepultado com seus pais na cidade de Belém.'),('NT04-L23-Q01','No primeiro dia da semana','No terceiro dia da semana','No sétimo dia da semana','No quarto dia da semana'),('NT04-L23-Q02','Maria Madalena e as outras mulheres','Os doze apóstolos','José de Arimateia e Nicodemos','Os soldados romanos'),('NT04-L23-Q04','Não creram, parecendo-lhes como um disparate','Aclamaram-no com grande alegria e louvor','Prostraram-se em adoração com profundo temor','Ficaram contritos e jejuaram por três dias'),('NT04-L23-Q03','Anunciaram o nascimento do Salvador, que é Cristo, o Senhor','Anunciaram a ressurreição do Senhor aos seus discípulos','Anunciaram a vinda do profeta Elias antes do Messias','Anunciaram a destruição de Jerusalém e do seu templo'),('NT04-L23-Q05','Jesus foi tocado, comeu peixe assado e mostrou as feridas aos discípulos.','Jesus apareceu somente como espírito luminoso no cenáculo e ascendeu em glória.','Apenas Paulo teve visões espirituais da ressurreição, sem testemunhas corporais.','Moisés e Elias ressuscitaram com Jesus e foram vistos fisicamente no cenáculo.'),('NT04-L23-Q08','Porque sem ela a fé é vã e permanecemos em nossos pecados.','Porque ela é apenas um exemplo de obediência a ser seguido pelos crentes.','Porque garante a prosperidade material dos que creem em Cristo.','Porque prova que Jesus era um grande profeta, mas não o Filho de Deus.')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('NT04-L23-Q07','Pela fé sou justificado, tenho nova vida e espero a ressurreição em Cristo','Pelas obras da lei sou justificado, alcanço nova vida e mereço a ressurreição','Pela tradição dos anciãos recebo justificação, nova vida e esperança futura','Por rituais exteriores sou justificado e tenho nova vida por meu próprio esforço'),('NT04-L24-Q02','NAO SEI','Somente em Mateus e Lucas','Em Mateus, Marcos e João','Somente em João'),('NT04-L24-Q03','NAO SEI','Moisés, Egito e o Êxodo','Davi, Jerusalém e o reino unido','Paulo, Roma e o Império Romano'),('NT04-L24-Q05','NAO SEI','Para que se cumprisse a profecia do profeta Isaías','Conforme está escrito no livro do Apocalipse','Assim como falou o Senhor por meio do profeta Elias'),('NT04-L25-Q01','Quarenta dias após a ressurreição, no Monte das Oliveiras','Cinquenta dias após a ressurreição, no Monte Sião','Três dias após a ressurreição, em Jerusalém','No dia da ressurreição, no Monte Sinai'),('NT04-L24-Q06','Encheram os discípulos do Espírito Santo e os encorajaram a pregar','Causaram medo e obrigaram os discípulos a fugir de Jerusalém','Enfraqueceram a fé dos discípulos e cessaram a pregação do Evangelho','Provocaram dúvidas e fizeram os discípulos abandonarem a missão'),('NT04-L25-Q02','Fazei discípulos de todas as nações, batizando e ensinando','Amai os vossos inimigos e orai pelos que vos perseguem','Vendei os vossos bens e dai esmolas aos pobres','Apascenta as minhas ovelhas'),('NT04-L23-Q06','Confirma Jesus como Filho de Deus e sua vitória sobre a morte e o pecado.','Confirma Jesus como profeta comum, sem natureza divina alguma.','A ressurreição foi uma alucinação coletiva dos discípulos amedrontados.','A ressurreição prova que a morte é o fim absoluto da existência humana.'),('NT04-L25-Q05','Significa que Jesus recebeu autoridade máxima, poder e glória, reinando com Deus.','Significa apenas uma posição literal no céu, sem autoridade espiritual alguma.','Significa que Jesus se tornou inferior aos anjos após sua ascensão aos céus.','Significa que Jesus perdeu sua natureza divina ao ser recebido no céu.'),('NT04-L25-Q04','Este Jesus virá assim como o vistes ir ao céu','Não está aqui, mas ressuscitou como havia dito','Não temais, porque vos trago boa nova de grande alegria','Por que procurais entre os mortos ao que vive'),('NT04-L25-Q03','Era necessário que Cristo ascendesse para enviar o Consolador','A ascensão de Cristo substituiu o envio do Consolador','O Consolador foi enviado antes da ascensão de Cristo','A ascensão tornou desnecessária a vinda do Consolador'),('NT04-L25-Q07','A bendita esperança da segunda vinda de Cristo','A descida do Espírito Consolador sobre os apóstolos','A ressurreição corporal dos santos e dos mártires','A inauguração visível do Reino milenar na terra'),('NT04-L25-Q06','A ascensão o exalta ao trono, onde reina e intercede eternamente por nós.','A ascensão marca o fim de seu ministério terreno, cessando sua mediação.','A ascensão o afastou dos homens, impossibilitando sua intercessão diária.','A ascensão foi apenas um deslocamento físico, sem efeito em seu reinado.'),('AT13-L10-Q04','São condenadas como males que destroem amizades e semeiam contendas','São recomendadas como meios de promover a verdade cristã','São tratadas com neutralidade sem qualquer juízo moral','São aceitas apenas entre anciãos e líderes da igreja'),('AT13-L20-Q05','É o princípio da sabedoria e o dever de todo homem','É apenas um sentimento opcional e passageiro','Foi abolido pela vinda da graça de Cristo','Só se aplica aos profetas do antigo concerto'),('AT13-L20-Q07','NAO SEI','O poema apresenta a sabedoria como dom exclusivo dos sábios de Israel','A sabedoria no poema é apresentada como resultado do esforço humano','O poema mostra que a sabedoria é alcançada apenas através do sofrimento'),('AT13-L08-Q01','Riqueza e pobreza vêm do Senhor; quem dá ao pobre empresta a Deus','Os ricos jamais herdarão o reino dos céus, mesmo sendo justos e tementes','A riqueza é sempre castigo divino e a pobreza é sempre bênção celestial','Somente os pobres podem possuir a verdadeira sabedoria divina'),('AT13-L21-Q06','Cristo é o agente da criação, redenção e sabedoria divina (Cl 1:15-20).','A lei mosaica é o fundamento da criação e da sabedoria divina.','Os anjos foram os intermediários da criação e da redenção humana.','A sabedoria humana é superior à revelação de Cristo para a redenção.'),('AT14-L04-Q05','Que o labor é pura vaidade e que as realizações humanas são o fim último','Que o trabalho é a base da salvação e que o ócio jamais será aceitável','Que somente os ricos devem se dedicar ao trabalho e os pobres devem servir','Que todo esforço humano será recompensado imediatamente ainda nesta vida'),('AT14-L05-Q06','Demonstram sua vaidade e conduzem ao temor de Deus','São bênçãos que asseguram ao crente prosperidade eterna','Representam a plenitude do Reino de Deus na terra','São recompensas pelos méritos alcançados pelo homem'),('AT14-L07-Q06','NAO SEI','Reforça a urgência escatológica da mensagem profética ao leitor contemporâneo','Estabelece contraste entre a eternidade divina e a finitude humana no livro','Demonstra a soberania divina sobre o tempo e a história da redenção'),('AT14-L09-Q01','O fim da vida terrena e o retorno do espirito a Deus','A separacao eterna e definitiva do corpo e da alma','O castigo permanente de Deus contra os impios','A cessacao completa e final de toda a consciencia'),('AT14-L09-Q03','A separação entre corpo e espírito','A fusão da alma com a energia divina','O desaparecimento total da pessoa humana','A transformação da carne em luz eterna'),('AT14-L11-Q04','Porque cada escolha será pesada diante da justiça eterna de Deus.','Porque anula o livre arbítrio e torna as escolhas moralmente vazias.','Porque as escolhas humanas não têm peso diante da predestinação divina.','Porque Deus julga apenas as obras externas sem considerar o coração.'),('AT14-L11-Q05','Confiando na misericórdia de Deus e dependendo de Sua graça','Levando-nos a confiar em nossos méritos e obras próprias','Fazendo-nos desesperar da misericórdia divina por nossos pecados','Ensinando-nos a desprezar a santidade de Deus e seguir nosso coração'),('AT14-L14-Q02','Imagens como noiva e noivo, água e fogo; amor como mandamento supremo.','Imagens de guerra e batalha; amor como sentimento puramente humano e opcional.','Apenas argumentos racionais sobre amor próprio e egoísmo como base.','Imagens de tempestade e destruição; desejo deve ser totalmente suprimido.'),('AT14-L13-Q05','Porque reúne oráculos de profetas de períodos históricos distintos','Porque é um livro exclusivamente poético sem elementos narrativos','Porque foi escrito por um único profeta no século VIII a.C.','Porque possui uma estrutura cronológica linear bem definida'),('AT14-L16-Q06','NAO SEI','Celebra a beleza do amor que reflete a união entre Cristo e a Igreja','Revela a soberania divina sobre toda a criação e a história humana','Apresenta os princípios da sabedoria para a vida piedosa e justa'),('AT14-L16-Q04','Deus não vê a aparência exterior, mas o coração do homem','A beleza exterior é o principal critério de Deus','O temor do Senhor despreza toda forma de beleza','A aliança elimina a capacidade humana de admirar'),('AT14-L17-Q03','Indissolubilidade do vinculo matrimonial','Fidelidade reciproca e mutua dos esposos','Sacramentalidade propria do matrimonio','Abertura a transmissao da vida humana'),('AT14-L18-Q05','Que sexo é só para procriação, que negar o cônjuge é espiritualidade e que pornografia é aceitável no matrimônio','Que poligamia é permitida, que divórcio é obrigatório e que celibato é exigido para todos','Que adultério é perdoável sem arrependimento, que concubinato é válido e que infidelidade é normal','Que namoro é pecado, que noivado é obrigatório e que aliança matrimonial é desnecessária'),('AT15-L01-Q02','A profecia vem de Deus por inspiração divina, não de especulação humana.','A profecia bíblica prevê apenas eventos futuros, como guerras e pestes.','A profecia bíblica surgiu da imaginação criativa dos profetas antigos.','A profecia bíblica é idêntica à previsão astrológica dos babilônios.'),('AT15-L01-Q04','Acusação do pecado, advertência do juízo, consolo ao aflito e esperança de restauração','Bênçãos materiais, prosperidade financeira, cura física e vitórias temporais','Predição de datas, sinais cósmicos, eventos apocalípticos e cronologias finais','Ensino da lei, rituais sacrificiais, orações litúrgicas e cerimônias sagradas'),('AT15-L01-Q05','Para revelar a mensagem de Deus, advertir o povo e conclamar ao arrependimento','Para substituir a Torá e revogar as alianças estabelecidas com Israel','Apenas para prever o futuro distante, sem advertir o povo presente','Como práticas divinatórias idênticas às dos povos pagãos vizinhos'),('AT15-L01-Q07','Profetas fiéis à aliança exortavam obediência a Yahweh; falsos induziam Israel à idolatria.','A aliança era renovada apenas por sacrifícios, sem ligação com a identidade do profeta.','Profetas falsos eram identificados por não possuírem linhagem sacerdotal legítima.','A distinção se baseava no número de seguidores que cada profeta conseguia reunir.'),('AT15-L02-Q03','Moisés, Isaías, Jeremias, Ezequiel e Samuel','Abraão, Isaque, Jacó e José','Pedro, Paulo, João e Tiago','Davi, Salomão, Asa e Josafá'),('AT15-L02-Q05','A vinda do Messias prometido','A destruição do templo de Jerusalém','O exílio babilônico de Judá','A conversão dos gentios ao judaísmo'),('AT15-L03-Q03','Moisés, Davi e Jeremias','Elias, Eliseu e Samuel','Salomão, Rute e Ester','Pedro, Paulo e João'),('AT15-L08-Q02','Livro de Isaías, século VIII a.C., período da ameaça assíria','Livro de Jeremias, século VII a.C., período do exílio babilônico','Livro de Ezequiel, século VI a.C., período pós-exílico','Livro de Daniel, século II a.C., período da perseguição selêucida'),('AT15-L08-Q06','Cristo é o Servo de Isaías que sela a Nova Aliança e consuma a esperança messiânica.','Cumpre-se no retorno de Elias como precursor do dia do Senhor segundo Isaías.','Isaías ensina que a esperança se alcança pela obediência à Lei para herdar a terra.','Isaías prevê a restauração política de Israel sob um novo rei davídico terreno.'),('AT15-L10-Q04','Manifestam o juízo de Deus pela quebra da aliança, apontando restauração','Revelam apenas a derrota política de Judá, sem caráter teológico algum','Sinalizam a renovação da aliança antes da destruição babilônica de Jerusalém','Indicam a santidade de Israel como causa principal da queda de Jerusalém'),('AT15-L12-Q02','Através de lamentos poéticos, prantos coletivos e personificação de Jerusalém.','Por meio de salmos de louvor, hinos de gratidão e cânticos alegres ao Senhor.','Com provérbios, ensinamentos morais e reflexões sobre a obediência a Deus.','Por visões apocalípticas de triunfo, promessas de glória e júbilo celestial.'),('AT15-L14-Q03','A visão do trono, a partida da glória do templo e seu retorno final','A visão de Isaías no templo com serafins clamando santo, santo, santo','O tabernáculo de Moisés coberto pela coluna de nuvem e de fogo no deserto','A visão da Nova Jerusalém descendo do céu adornada com a glória de Deus'),('AT15-L12-Q04','NAO SEI','Pela tradição da igreja','Pelas boas obras','Através dos sacramentos'),('AT15-L14-Q06','A glória que parte do templo e retorna prefigura Cristo e a consumação.','A glória em Ezequiel se refere exclusivamente à reconstrução do segundo templo.','A glória de Ezequiel é apenas uma metáfora política para a restauração de Israel.','Ezequiel ensina que a glória divina abandonou Israel sem esperança de retorno.'),('AT15-L16-Q05','Restaurar Israel à terra dada aos seus pais','Enviar o Messias para julgar todas as nações','Destruir o templo de Jerusalém para sempre','Conceder salvação eterna por meio da lei'),('AT15-L18-Q07','Jesus assume o título Filho do Homem, de Daniel 7:13-14','Jesus se autodenomina Cordeiro Pascal, imagem de Daniel 8','Jesus identifica-se com a estátua de Nabucodonosor, de Daniel 2','Jesus compara-se aos quatro animais selvagens de Daniel 7'),('AT15-L19-Q04','No exílio, Deus demonstra fidelidade: juízo, santidade, aliança e restauração.','No exílio, Deus rejeita Israel e rompe para sempre a sua santa aliança.','O exílio revela que Deus perdeu sua santidade diante das nações pagãs.','No exílio, a fidelidade divina se manifesta apenas como castigo eterno.'),('AT15-L19-Q06','Tipifica Cristo, o Servo fiel, e antecipa a consumação da Nova Aliança','Substitui a obra de Cristo, pois o exílio já realiza plena redenção','Anula a necessidade da Nova Aliança, bastando a fidelidade no cativeiro','Aplica-se apenas à restauração política de Israel, sem dimensão escatológica'),('AT15-L20-Q04','...','...','...','...'),('AT15-L23-Q03','A visão de Daniel 12 sobre a ressurreição dos mortos','A visão das quatro bestas e do Filho do homem','A interpretação da escritura na parede em Beltessazar','Os três jovens na fornalha de fogo ardente'),('AT15-L21-Q06','Para garantir uma interpretação correta e fiel das Escrituras','Para determinar com precisão a data do fim do mundo','Para identificar a autoria humana de cada livro bíblico','Para provar que todas as profecias já se cumpriram na igreja'),('AT15-L23-Q04','Ressuscitam uns para a vida eterna e outros para a vergonha eterna','Todos os que dormem no pó ressuscitam para o mesmo destino eterno','Os justos e ímpios ressuscitam unicamente após o grande juízo final','Somente os justos do povo de Israel ressuscitarão para a vida eterna'),('AT16-L03-Q01','Contexto do Dia do Senhor; promessa do derramamento do Espírito sobre toda carne','Contexto da destruição de Jerusalém; promessa de restauração do Templo','Contexto do exílio babilônico; mensagem de libertação do cativeiro','Contexto da aliança mosaica; promessa do fim dos sacrifícios levíticos'),('AT16-L10-Q02','A fidelidade preserva o justo, mas a arrogância precipita a ruína do opressor','O justo é recompensado pela sua força, e o opressor pela sua prudência','A fidelidade do justo é esquecida, mas a arrogância do opressor é exaltada','O opressor prospera pela sua arrogância, e o justo perece pela sua fé'),('AT16-L08-Q06','Os ninivitas se levantarão no juízo e condenarão esta geração','Nínive será reconstruída nos últimos dias como símbolo da misericórdia divina','A pregação de Jonas provocou a destruição imediata e irreversível de Nínive','O Apocalipse de João revela a restauração gloriosa e eterna de Nínive'),('AT16-L11-Q02','A idolatria e a injustiça social de Judá, sob a ameaça do juízo do Dia do Senhor','A opressão dos gentios e o cativeiro babilônico do povo judeu','O cisma político entre o reino de Judá e o reino de Israel','A perseguição religiosa dos judeus sob o império selêucida'),('AT16-L13-Q05','NAO SEI','Pensamentos de paz e nao de mal, para vos dar o fim que esperais','Restituir-vos-ei os anos que comeu o gafanhoto','Eis que faco uma coisa nova; agora saira a luz'),('AT16-L13-Q02','A impureza e o pecado do povo, e a apatia na reconstrução do Templo','A adoração ao bezerro de ouro por Jeroboão e a divisão do reino','A deportação do povo para a Assíria e a queda de Samaria','A opressão dos filisteus e a captura da Arca da Aliança'),('AT16-L15-Q03','NAO SEI','Justiça e misericórdia são opostos em Miquéias','A aliança aparece somente em Jeremias','O Dia do Senhor é tema exclusivo de Ezequiel'),('AT16-L19-Q06','João Batista cumpre a profecia de Malaquias como precursor do Messias','Zorobabel reconstrói o templo e estabelece o trono davídico eterno','Elias reaparece corporalmente para ungir o novo sumo sacerdote','Ageu profetiza a vinda imediata do reino político de Israel'),('AT17-L01-Q01','A velhice de Samuel e a corrupção de seus filhos Joel e Abias.','A perda da arca da aliança para os filisteus em batalha.','A ameaça dos midianitas que devastavam as colheitas anualmente.','O desejo de Saul de expandir o território israelita além do Jordão.'),('AT16-L15-Q06','Jesus institui novo sacerdócio perfeito segundo a ordem de Melquisedeque','O sacerdócio corrompido é restaurado pelos sumos sacerdotes Anás e Caifás','Os escribas fariseus são consagrados como novos sacerdotes legítimos','Os sacrifícios levíticos são intensificados no templo para purificar os sacerdotes'),('AT17-L01-Q06','Deus agiu soberanamente através de reis falhos para realizar Seus desígnios','Deus condenou Israel e nunca permitiu que tivessem um rei sobre si','A monarquia em Israel foi totalmente santa e irrepreensível diante de Deus','Deus usou somente reis perfeitamente piedosos durante toda a monarquia'),('AT17-L02-Q01','Ser servo obediente da lei e pastor do povo na aliança','Conquistar povos vizinhos e acumular grandes tesouros','Substituir os sacerdotes e oferecer sacrifícios no templo','Governar com autoridade absoluta e livre de qualquer lei'),('AT17-L03-Q05','Deus rejeitou Saul, o reino passou a Davi e sua dinastia acabou','Saul construiu o templo em Jerusalém para honrar a Deus','Saul estabeleceu dinastia eterna com seus descendentes','Saul unificou Israel em paz duradoura sob bênção divina'),('AT17-L06-Q01','Construiu o Templo de Jerusalém e foi célebre por sua sabedoria','Unificou as tribos de Israel após o êxodo do Egito','Conquistou a Terra Prometida derrotando os filisteus','Estabeleceu a monarquia em Israel sendo o primeiro rei'),('AT17-L01-Q05','O rei não devia multiplicar cavalos, esposas, nem ouro, e devia ler a Lei.','Proibia totalmente que Israel tivesse rei, pois Deus seria o único governante.','Permitia que qualquer povo pagão indicasse o rei, desde que fosse forte e rico.','Determinava que o rei fosse sempre o filho mais velho, mesmo que não fosse capaz.'),('AT17-L11-Q06','Reis fiéis foram aprovados; infiéis condenaram suas dinastias à queda.','Apenas vitórias militares determinavam a avaliação dos reis e dinastias.','A riqueza do tesouro real era o critério principal para avaliar a dinastia.','Alianças políticas com nações vizinhas definiam o julgamento das dinastias.'),('AT17-L06-Q03','Andando nos caminhos do Senhor, guardando Seus estatutos e mandamentos','Construindo primeiro o templo antes de obedecer à lei','Confiando apenas na própria sabedoria para governar Israel','Estabelecendo alianças com povos estrangeiros antes da lei'),('AT17-L12-Q05','Denunciaram Acabe diretamente, falando a palavra do Senhor contra seus pecados.','Lutaram fisicamente contra Acabe no templo de Baal em Samaria.','Acusaram Acabe somente de crimes políticos sem mencionar idolatria.','Pediram suborno a Acabe para esconderem seus pecados do povo.'),('AT17-L13-Q02','Nabucodonosor e a estátua de ouro em Daniel 3','Davi e Golias no vale de Elá','Moisés e a sarça ardente no Horebe','Salomão e a construção do primeiro templo'),('AT17-L14-Q03','Restaurando a obediência à Lei e renovando a aliança com Deus','Estabelecendo novos rituais além do que Deus havia prescrito','Impondo tradições humanas acima dos mandamentos divinos','Substituindo a Lei por costumes e práticas das nações pagãs'),('AT17-L15-Q05','Exílio na Babilônia, destruição do Templo de Jerusalém e fim da dinastia davídica','Estabelecimento imediato do culto pagão em Jerusalém e ascensão dos samaritanos','Unificação das doze tribos sob um novo rei davídico no Egito','Conversão em massa ao zoroastrismo e perda completa da identidade judaica'),('AT17-L16-Q02','Reino eterno, justiça, paz, sabedoria divina e governo justo','Conquista militar, domínio político e riqueza material abundante','Sacerdócio levítico contínuo e sacrifícios diários no templo','Reino temporário limitado a Israel com governo de cem anos'),('AT17-L16-Q03','O Messias reinará com justiça, trará paz e dominará sobre toda a terra.','O Messias reinará com poder militar, conquistas e domínio sobre Israel apenas.','A justiça virá pela lei mosaica, a paz pela política e o domínio pela força humana.','Justiça, paz e domínio universal ocorrerão apenas após o arrependimento de Israel.'),('AT17-L16-Q06','Pela genealogia em Mateus 1:1 e pela confissão de Pedro em Mateus 16:16.','Por meio dos milagres registrados no livro de Apocalipse.','Exclusivamente pela profecia do Servo Sofredor em Isaías 53.','Somente no livro de Apocalipse como o Cordeiro de Deus.'),('AT18-L01-Q06','Condenando o pecado em Cristo, Deus cumpriu a justiça sem anular a promessa','Anulando a lei para que a promessa prevalecesse sobre a justiça divina','Poupando os pecadores para que a promessa de bênção se cumprisse','Destruindo a lei para estabelecer unicamente a promessa da graça'),('AT18-L01-Q01','Idolatria, injustiça social, violência e profanação do sábado','Adultério, roubo, falso testemunho e cobiça','Desobediência a Moisés, murmuração, incredulidade e idolatria','Rejeição do Messias, incredulidade e negligência da Torah'),('AT18-L08-Q01','Proclamaram a esperança da restauração ao povo no cativeiro','Reconstruíram o templo de Jerusalém com Esdras','Receberam a lei no monte Sinai novamente','Conduziram o povo na travessia do mar Vermelho'),('AT18-L09-Q04','Soberania de Deus reconhecida por reis e preservação da fé no exílio','Imposição do monoteísmo judeu como religião oficial do império babilônico','Fim imediato do cativeiro e retorno de todos os judeus à Palestina','Conversão em massa dos babilônios ao judaísmo e abolição da idolatria'),('AT18-L09-Q06','Profetizou os 70 anos de exílio e a vinda do Messias Príncipe','Conduziu o exército babilônico na destruição de Jerusalém','Escreveu os Salmos durante o cativeiro na Babilônia','Fundou o segundo templo em meio ao exílio'),('AT18-L12-Q01','Ciro decretou o retorno dos judeus exilados e a reconstrução do Templo em Jerusalém.','Ciro destruiu o Templo de Jerusalém e exilou os judeus para a Pérsia.','Ciro manteve os judeus no cativeiro babilônico e proibiu a reconstrução.','Ciro proibiu o retorno dos exilados e ordenou a destruição dos muros de Jerusalém.'),('AT18-L10-Q01','Ezekiel profetizou a restauração de Israel aos exilados na Babilônia','Ezekiel profetizou a destruição de Israel aos exilados no Egito','Ezekiel profetizou a vinda do Messias aos exilados na Pérsia','Ezekiel profetizou a queda da Babilônia aos judeus na Judeia'),('FB01-L01-Q01','A Palavra de Deus escrita por homens inspirados pelo Espírito Santo','Um livro de histórias e tradições de povos antigos','Um conjunto de ensinamentos morais escritos por sábios','As tradições orais dos primeiros seguidores de Jesus'),('AT18-L18-Q02','Intensificou a expectativa de um descendente de Davi que restaurasse o reino','Eliminou completamente toda esperança de restauração davídica em Israel','Tornou o povo indiferente às promessas proféticas sobre o Messias futuro','Provocou a adoção imediata de cultos pagãos pelos israelitas exilados'),('FB01-L01-Q06','Foram movidos pelo Espírito Santo, que os inspirou a escrever','Os autores copiaram manuscritos antigos sem contribuição pessoal','Cada livro foi escrito por um único anjo celestial','Os textos foram revelados mecanicamente, sem participação da vontade humana'),('FB01-L01-Q10','É a Palavra de Deus inspirada, que revela Sua vontade e guia o crente.','É um livro meramente histórico, sem autoridade espiritual para o crente.','É um manual exclusivo para líderes e pastores, não para os leigos.','Foi escrita apenas por homens, sem qualquer inspiração divina.'),('FB01-L01-Q08','Narrativa, poesia, lei, profecia, apocalipse, sabedoria, epístolas e evangelhos.','Ficção científica, romance policial, poesia moderna, comédia romântica e terror.','Apenas narrativa histórica e cartas paulinas, sem poesia, lei ou profecia alguma.','Fábulas infantis, contos de fadas, crônicas jornalísticas e ensaios filosóficos.'),('FB01-L03-Q01','NAO SEI','Gênesis, Mateus, Marcos, Lucas, João e os demais 34 livros','Os 39 livros do Novo Testamento na ordem tradicional','Apenas o Pentateuco: Gênesis, Êxodo, Levítico, Números e Deuteronômio'),('FB01-L04-Q04','Jo para o Evangelho; 1 Jo, 2 Jo e 3 Jo para as epístolas.','Jn para o Evangelho; 1 Jn, 2 Jn e 3 Jn para as epístolas.','Jó para João; 1 Jó, 2 Jó e 3 Jó para as cartas.','Joo para o livro; 1 Joo, 2 Joo e 3 Joo para as epístolas.'),('FB01-L04-Q05','1 Sm, 1 Rs, 1 Cr, 1 Co e 1 Ts','1 Sa, 1 Re, 1 Cro, 1 Co e 1 Te','1 Sm, 1 Rg, 1 Cro, 1 Cor e 1 Tes','1 Sam, 1 Rei, 1 Cron, 1 Cor e 1 Te'),('FB01-L07-Q08','Nome do livro, seguido do número do capítulo e do versículo.','Inverter a ordem, começando pelo versículo, depois capítulo e livro.','Ler somente o nome do livro, sem citar capítulo nem versículo.','Sempre pronunciar por extenso as palavras capítulo e versículo.'),('FB01-L09-Q04','NAO SEI','Confundir o Mar Vermelho com o mar de Tiberíades','Localizar o Monte Ararate na região da Palestina','Identificar Belém como capital do reino do Norte'),('FB01-L10-Q01','Hebreus, cananeus, egípcios, babilônios, assírios, persas e romanos e seus contextos.','Sumérios, fenícios, hititas, medos, partos e citas nos textos sagrados.','Fariseus, saduceus, essênios e zelotes como principais povos bíblicos.','Germanos, gauleses, bretões e citas no contexto das escrituras.'),('FB01-L09-Q05','Facilita localização, compreensão e memorização das narrativas bíblicas.','Substitui o estudo teológico, dispensando a leitura completa das Escrituras.','Serve apenas para decorar mapas, sem utilidade prática no estudo bíblico.','Permite viajar fisicamente aos locais sagrados e modificar o texto bíblico.'),('FB01-L10-Q02','Aliança, terra prometida, lei e patriarcas','Sacerdotes, sacrifícios, tabernáculo e altar','Reis, impérios, batalhas e conquistadores','Profetas, visões, apocalipse e Juízo Final'),('FB01-L11-Q03','Conhecendo o contexto histórico, o estilo e a ênfase teológica de cada autor.','Substituindo toda interpretação pessoal apenas pelo estudo dos autores.','Seguindo exclusivamente a ordem cronológica dos livros sem considerar o cânon.','Lendo toda a Bíblia como se fosse um único livro escrito por um só autor.'),('FB01-L12-Q04','NAO SEI','Trocar a ordem dos quatro evangelhos sinóticos','Confundir a posição dos profetas menores no cânon','Misturar livros deuterocanônicos com os protocanônicos'),('FB01-L11-Q04','Atribuir todos os Salmos ao rei Davi','Confundir Tiago filho de Zebedeu com Tiago irmão de Jesus','Dizer que Salomão escreveu o livro de Apocalipse','Crer que João Batista escreveu o Evangelho de João')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB02-L01-Q06','As alianças revelam a unidade do plano de Deus ao longo da história da salvação.','As alianças separam Antigo e Novo Testamento como pactos independentes.','As alianças foram revogadas em Cristo, perdendo função unificadora.','As alianças existiram só no Antigo Testamento, sem conexão com o Novo.'),('FB02-L02-Q05','Criação revela o propósito humano que a redenção em Cristo restaura plenamente.','A criação não possui relação com a mensagem redentora da Bíblia.','A redenção elimina o propósito original dado por Deus na criação.','O propósito humano surgiu somente após a queda no Éden.'),('FB02-L05-Q05','Por meio da aliança, da fé demonstrada e da promessa do Messias.','Exclusivamente pela observância da Lei mosaica no Sinai.','Somente através da construção do Templo em Jerusalém.','Pela conquista militar da terra de Canaã sob seu comando.'),('FB02-L07-Q02','Josué, travessia do Jordão, queda de Jericó, Raabe e os cananeus','Moisés, Arão, as pragas do Egito, o Mar Vermelho e a sarça ardente','Davi, Golias, Saul, os filisteus, Natã e o reino dividido de Israel','Sansão, Dalila, os filisteus, o templo de Dagom, Gaza e Sisaque'),('FB02-L09-Q05','A divisão evidencia o pecado humano e aponta para a necessidade do verdadeiro Rei redentor','A divisão estabelece o cumprimento definitivo das promessas abraâmicas na terra','A separação dos reinos encerra definitivamente o plano redentor de Deus','A divisão dos reinos elimina a necessidade do Messias prometido a Israel'),('FB02-L12-Q05','NAO SEI','Através da pregação dos apóstolos aos gentios e judeus','Por meio do derramamento do Espírito Santo em Pentecostes','Pela expansão missionária até os confins da terra conhecida'),('FB02-L08-Q03','Juízes vieram após Josué; a monarquia iniciou-se com Saul, seguida por Davi e Salomão.','Juízes e monarquia sucederam diretamente o período dos patriarcas hebreus','A monarquia em Israel precedeu o período dos juízes','Juízes governaram Israel durante o exílio na Babilônia'),('FB03-L01-Q04','Fundamentar a revelação divina e preparar progressivamente a vinda do Messias','Substituir completamente o Novo Testamento como única revelação válida','Registrar unicamente as tradições orais perdidas do antigo Israel','Apresentar a lei mosaica como o único caminho para a salvação eterna'),('FB03-L01-Q05','Combina gêneros variados como lei, narrativa histórica, poesia e profecia.','Apresenta exclusivamente cartas paulinas e epístolas organizadas por temas','Contém apenas relatos de viagens missionárias em quatro seções distintas','Divide-se em evangelhos sinóticos, cartas e um livro apocalíptico final'),('FB03-L03-Q01','Os cinco primeiros livros da Bíblia: Gênesis, Êxodo, Levítico, Números e Deuteronômio.','Os quatro Evangelhos do Novo Testamento: Mateus, Marcos, Lucas e João.','Os livros poéticos e sapienciais: Jó, Salmos, Provérbios e Eclesiastes.','Os livros proféticos que anunciam a vinda do Messias.'),('FB03-L05-Q01','São Jó, Salmos, Provérbios, Eclesiastes e Cantares, obras de poesia e sabedoria','São os livros históricos: Josué, Juízes, Rute, Esdras e Neemias','São os profetas maiores: Isaías, Jeremias, Ezequiel e Daniel','São os evangelhos e as epístolas do Novo Testamento'),('FB03-L06-Q03','Na seção dos Profetas, no Antigo Testamento','No Novo Testamento, entre os Evangelhos e Atos','No início da Bíblia, antes do livro de Gênesis','Nos livros sapienciais, junto com Provérbios e Eclesiastes'),('FB03-L03-Q05','Primeiros cinco livros: Lei/Torah, de Gênesis a Deuteronômio, autoria mosaica.','Livros poéticos e sapienciais, de Jó a Eclesiastes, autoria davídica.','Livros proféticos maiores e menores, de Isaías a Malaquias, com oráculos.','Quatro evangelhos e Atos, narrando a vida de Cristo e da igreja primitiva.'),('FB03-L12-Q02','Daniel e Apocalipse','Ezequiel e Zacarias','Isaías e Jeremias','Gênesis e Êxodo'),('FB03-L12-Q04','Consolar os perseguidos e revelar a soberania divina e o triunfo final do bem','Ensinar princípios morais práticos para a vida cotidiana através de provérbios','Registrar fielmente os acontecimentos históricos do povo de Israel','Estabelecer leis cerimoniais e rituais de pureza para o culto no templo'),('FB03-L13-Q03','Divisão dos livros bíblicos em partes menores, subdivididas em versículos.','Divisão sagrada inspirada por Deus, presente nos textos originais da Bíblia.','Unidade completa e independente que resume todo o sentido do livro bíblico.','Conjunto de livros bíblicos agrupados por um mesmo autor ou período histórico.'),('FB03-L15-Q05','Pela continuidade e descontinuidade entre os dois testamentos','Pela separação radical entre a Lei de Moisés e a graça cristã','Pelo critério de inspiração verbal e plenária das Escrituras','Pela distinção entre os gêneros literários profético e sapiencial'),('FB04-L01-Q04','NAO SEI','A criação se liga diretamente ao dilúvio de Noé como evento preparatório','A criação precede e fundamenta a aliança com Abraão em Ur','A criação é consequência imediata da queda no Éden como restauração'),('FB04-L04-Q01','Deus prometeu preservar a criação do dilúvio, selando a promessa com o arco-íris.','Promessa de dar a Abraão uma descendência numerosa como as estrelas do céu.','Estabelecimento da lei mosaica no Monte Sinai com entrega dos dez mandamentos.','Promessa de um descendente real que governaria Israel no trono de Davi eternamente.'),('FB04-L04-Q02','O arco-íris como sinal da aliança de Deus com Noé','A aliança foi feita com Abraão e seus descendentes','O dilúvio como punição eterna e definitiva à humanidade','A torre de Babel como símbolo da nova aliança divina'),('FB04-L04-Q05','Noé prefigura Cristo como salvador que preserva seu povo do juízo divino','Noé prefigura Cristo como mediador da lei que condena os pecadores','Noé prefigura Cristo como administrador da circuncisão da nova aliança','Noé prefigura Cristo como guardião do sábado e do repouso eterno'),('FB04-L04-Q03','Promessa de não mais destruir a terra por águas, selada com o arco-íris.','Promessa de dar a Abraão descendência tão numerosa quanto as estrelas do céu.','Aliança firmada no Sinai com entrega dos Dez Mandamentos a Moisés.','Promessa a Davi de que seu trono seria estabelecido para sempre em Israel.'),('FB04-L05-Q04','Conecta a queda ao plano redentor, culminando em Cristo e na salvação dos povos.','Estabeleceu a lei mosaica que seria o centro da adoração em Israel.','Resultou do pacto Noáico como cumprimento direto da aliança pós-dilúvio.','Originou o sacerdócio levítico que mediou a aliança entre Deus e o povo.'),('FB04-L06-Q04','NAO SEI','A formacao de Israel cumpre as promessas feitas a Abraao sobre uma grande nação','Israel surge apos o cativeiro babilonico como restauracao do povo eleito','A nacao israelita e posterior ao periodo dos juizes e precede os reis'),('FB04-L07-Q01','É o livramento de Israel da escravidão egípcia, tipo da redenção em Cristo.','É a conquista da terra de Canaã pelos hebreus sob a liderança de Josué.','Significa a escolha de Israel como povo de Deus desde o patriarca Abraão.','É o retorno dos judeus exilados na Babilônia com Esdras e Neemias.'),('FB04-L08-Q02','A idolatria do bezerro de ouro','A promessa de terra a Abraão','A aliança após o dilúvio com Noé','O pacto davídico de reino eterno'),('FB04-L09-Q04','Prefiguram Cristo, o Cordeiro sacrificial e Sacerdote eterno','São apenas rituais mosaicos sem conexão tipológica cristológica','Substituem a aliança abraâmica sem relação com o Novo Testamento','Servem exclusivamente aos levitas sem alcance à nova criação'),('FB04-L11-Q03','Promessa de descendência, trono e reino eternos, com vinda do Messias.','Promessa de terra a Abraão e sua descendência, com circuncisão como sinal.','Aliança da lei entregue a Moisés no Sinai, com mandamentos e sacrifícios.','Promessa de nunca mais destruir a terra por águas, com o arco-íris como sinal.'),('FB04-L08-Q05','Revela o pecado e aponta para Cristo, mediador da Nova Aliança que cumpre a lei.','A aliança do Sinai é idêntica à Nova Aliança, sem distinção entre ambas.','Moisés, mediador do Sinai, é superior a Cristo em glória e autoridade.','A aliança do Sinai não possui qualquer relação com a pessoa de Cristo.'),('FB04-L11-Q04','Conecta os pactos anteriores e anuncia o Messias e o reino eterno.','Liga-se apenas ao pacto mosaico, ignorando as promessas a Abraão.','Estabelece um reino puramente terreno, sem dimensão escatológica futura.','Anula todas as alianças prévias ao introduzir uma nova dispensação.'),('FB05-L01-Q04','A criação do mundo e o chamado de Abraão','O dilúvio de Noé e a torre de Babel','A queda do homem e o cativeiro do Egito','O êxodo e a entrada na terra prometida'),('FB05-L02-Q05','O período patriarcal é situado entre cerca de 2000 e 1700 a.C.','Os patriarcas viveram aproximadamente entre 1500 e 1200 a.C.','Abraão teria nascido por volta do ano 1200 a.C. segundo dados','A era patriarcal teria terminado por volta do ano 1000 a.C.'),('FB05-L04-Q03','Josué, os israelitas e Canaã','Moisés, o Egito e os amalequitas','Davi, os filisteus e Judá','Sansão, Gaza e a Assíria'),('FB05-L05-Q03','Os juízes, as tribos de Israel e os filisteus','O reino de Davi, Salomão e o império assírio','O cativeiro babilônico, Daniel e Nabucodonosor','O império romano, Herodes e Pôncio Pilatos'),('FB05-L06-Q05','1020-1000, 1000-970 e 970-930 a.C. (Saul, Davi, Salomão)','1400-1200 a.C. (Moisés, Josué e os Juízes)','931-722 a.C. (Roboão, Jeroboão e Acabe)','586-538 a.C. (Zedequias, Ciro e Dario)'),('FB05-L06-Q02','Saul ungido, morte de Saul, Davi rei, Salomão rei, construção do Templo','Abraão chamado, Moisés lidera êxodo, Josué conquista Canaã, juízes governam','Cativeiro babilônico, retorno do exílio, reconstrução do templo, domínio persa','Divisão do reino, reino de Israel, reino de Judá, queda de Samaria'),('FB05-L08-Q02','Roboão, Asa, Josafá, Ezequias, Josias e queda de Jerusalém em 586 a.C.','Jeroboão, Onri, Acabe, Jeroboão II e queda de Samaria em 722 a.C.','Josias, Ezequias, Josafá, Roboão e queda de Jerusalém em 586 a.C.','Saul, Davi, Salomão, Roboão e queda de Jerusalém em 586 a.C.'),('FB05-L08-Q05','Queda de Jerusalém em 586/587 a.C. e divisão do reino em c. 930 a.C.','Início do reino em 1050 a.C.; queda definitiva em 500 a.C.','Reino do Norte de Israel durou de 930 a 722 a.C.','Início em 586 a.C.; destruição do templo em 70 d.C.'),('FB05-L09-Q02','Visao de Isaias, queda de Samaria, exilio babilonico, retorno do cativeiro','Diluvio, Babel, chamamento de Abraao, saida do Egito','Nascimento, batismo, morte e resurreicao de Cristo','Monarquia de Saul, Davi, Salomao, cisma do reino'),('FB05-L10-Q02','...','...','...','...'),('FB05-L11-Q02','Arrebatamento, Tribulação, Segunda Vinda, Milênio, Juízo Final, Eternidade','Segunda Vinda, Arrebatamento, Tribulação, Milênio, Juízo Final, Purgatório','Milênio, Arrebatamento, Tribulação, Segunda Vinda, Juízo Final, Eternidade','Tribulação, Juízo Final, Arrebatamento, Segunda Vinda, Milênio, Nova Criação'),('FB06-L01-Q03','Patriarcas, êxodo, reinos de Israel e Judá, e o cativeiro babilônico','A reforma protestante, o concílio de trento e a grande contrarreforma','As viagens missionárias de Paulo, o concílio de Jerusalém e as epístolas','Os pais da igreja, os primeiros concílios ecumênicos e a patrística'),('FB06-L03-Q04','O Egito tinha relações comerciais e bélicas com Canaã, Mesopotâmia, Cuxe e Pérsia.','O Egito se relacionava apenas com a Pérsia, sem contatos com outras regiões.','O Egito não possuía rotas comerciais e vivia em completo isolamento.','O Egito dominava toda a Europa antiga através de conquistas militares.'),('FB06-L06-Q04','Atravessada pela Via Maris, ligava Egito, Síria e Mesopotâmia','Região isolada e sem acesso a rotas comerciais do mundo antigo','Deserto árido sem ligação com impérios vizinhos','Localizada no extremo sul de Israel, longe do Mediterrâneo'),('FB06-L09-Q03','A conquista de Jerusalém por Davi','A construção da torre de Babel','A travessia do Mar Vermelho por Moisés','A pregação de Jonas em Nínive'),('FB06-L05-Q05','O contexto geográfico esclarece metáforas e expressões culturais das Escrituras.','Conhecer Israel valida cada evento histórico narrado nas Escrituras Sagradas.','A geografia bíblica revela onde estão escondidos os tesouros do templo.','Estudar a terra de Israel é pré-requisito para se tornar um sacerdote levítico.'),('FB06-L14-Q02','Localizava-se na Mesopotâmia entre os rios Tigre e Eufrates, com capital em Babel.','Estava situado no Egito, às margens do rio Nilo, com capital em Mênfis.','Era um povo nômade do deserto, sem cidade fixa nem governo centralizado.','Localizava-se na Pérsia, com capital em Persépolis, e desconhecia a idolatria.'),('FB06-L14-Q03','Nabucodonosor, cativeiro babilônico, Daniel, Belsazar e destruição de Jerusalém','Ciro, Dario, Esdras, Neemias e reconstrução do segundo templo em Jerusalém','Senaqueribe, Salmanasar, assírios e queda do reino do norte de Israel','Faraó, egípcios, Moisés, dez pragas e libertação do povo de Israel'),('FB06-L15-Q04','Ciro conquistou a Babilônia e libertou os judeus do cativeiro','Conquistou Roma e impôs tributos ao senado romano','Formou aliança com a Grécia para invadir o Egito','Submeteu a China e controlou a Rota da Seda'),('FB06-L16-Q03','Alexandre Magno, selêucidas e ptolomeus ligados à visão do bode em Daniel','O império grego foi fundado por Nabucodonosor após a destruição de Jerusalém','Belsazar era o governante grego durante a festa no livro de Daniel','Os filisteus de Gate eram os principais generais de Alexandre Magno'),('FB06-L16-Q05','O Novo Testamento foi escrito em grego koiné, língua do império','O império grego perseguiu diretamente os primeiros cristãos','Porque a Vulgata Latina surgiu no período helenístico','Somente o Antigo Testamento foi escrito em grego'),('FB06-L16-Q04','Dominou rotas do Mediterrâneo ao Oriente, sucedendo os persas e antecedendo Roma.','Manteve-se isolado, sem contatos com Egito ou Pérsia.','Foi vassalo permanente do Império Romano durante toda sua existência.','Limitou-se apenas à Grécia continental, sem expansão marítima.'),('FB06-L17-Q03','Censo de César Augusto, crucificação sob Pilatos e cidadania romana de Paulo','Cativeiro babilônico, decreto de Ciro e reconstrução do templo por Zorobabel','Invasão assíria, exílio das dez tribos e queda de Samaria','Diáspora judaica, retorno com Esdras e reformas de Neemias'),('FB06-L17-Q04','Dominava a Judeia, rivalizava com os Partos e controlava rotas mediterrâneas','Aliava-se aos persas sassânidas para combater o Império Parto em conjunto','Manteve isolamento diplomático completo após conquistar a Grécia Antiga','Possuía relações exclusivamente pacíficas com todos os povos germânicos'),('FB06-L19-Q04','Cidades da Ásia Menor romana, situadas em importantes rotas comerciais','Sinagogas da Palestina, sob o domínio do Império Persa','Cidades egípcias às margens do Nilo, sob o Império Ptolemaico','Comunidades da Gália romana, protegidas pelos povos celtas'),('FB07-L01-Q01','Sistema patriarcal, pai como chefe, herança passada aos filhos varões.','Sistema matriarcal, mãe como chefe supremo da parentela.','Família nuclear isolada, sem laços com parentes extensos.','Igualdade total entre homens e mulheres em todos os assuntos.'),('FB06-L19-Q05','Revela o contexto historico, cultural e espiritual das cartas apostolicas','As sete igrejas correspondem exatamente aos sete sacramentos da Igreja','Permite identificar a localizacao geografica de todas as cartas paulinas','O estudo dessas igrejas revela os mandamentos da lei mosaica em detalhe'),('FB07-L01-Q04','A lei do levirato (Dt 25:5-10) e o resgate em Rute 4','Apocalipse 21 sobre a nova Jerusalém celestial','O Salmo 23 sobre o cuidado do Senhor Pastor','João 3:16 sobre o amor salvífico de Deus'),('FB07-L02-Q03','No noivado antigo era pacto vinculante; hoje é apenas promessa preparatória.','No antigo o casamento era mera formalidade; hoje é pacto sagrado.','Hoje o noivado possui valor legal igual ao do casamento; no antigo não.','No mundo antigo não existia noivado; realizava-se apenas o casamento direto.'),('FB07-L01-Q05','Honra, primogenitura e papéis sao deturpados sem o contexto familiar antigo.','A polygamia era apenas um desvio moral, nunca uma pratica cultural aceita','Familias biblicas tinham estrutura identica a das sociedades ocidentais modernas','O levirato era apenas um formalismo legalista sem enraizamento cultural'),('FB07-L02-Q04','Mt 1.18-25 (José e Maria), Mt 25.1-13 (dez virgens) e Jo 3.29 (amigo do noivo).','A circuncisão de Abraão (Gn 17) e a sarça ardente (Ex 3).','O dilúvio (Gn 6-9) e a torre de Babel (Gn 11).','A travessia do Mar Vermelho (Ex 14) e os dez mandamentos (Ex 20).'),('FB07-L03-Q05','Aplicar profecias do nascimento fora do contexto, gerando erros exegéticos.','Confundir as genealogias de Mateus e Lucas, atribuindo ambas a José.','Negar a divindade de Cristo por rejeitar o nascimento virginal em Belém.','Rejeitar os relatos de infância por ausência de fontes profanas coevas.'),('FB07-L05-Q05','NAO SEI','Pode-se confundir os ofícios de personagens bíblicos com seus papéis espirituais','Ignorar a profissão de Paulo como tendeiro gera erros sobre sustento ministerial','O erro principal é tratar a ociosidade como virtude a partir de Maria e Marta'),('FB07-L06-Q02','Deixar as extremidades do campo para os pobres e estrangeiros','Colher todos os frutos das árvores no primeiro ano de plantio','Juntar diferentes sementes no mesmo campo para aumentar a colheita','Vender os animais primogênitos nos mercados antes da festa'),('FB07-L06-Q04','Parábola do Semeador (Mc 4,1-20) — tipos de solo e semeadura','Sermão do Monte (Mt 5-7) — bem-aventuranças','Apocalipse de João (Ap 1-22) — visões proféticas','Cartas Paulinas (Rm, 1Co, Ef) — doutrina cristã'),('FB07-L06-Q05','NAO SEI','Interpretar a Parábola do Semeador apenas como metáfora moral, ignorando técnicas agrícolas da Palestina','Entender ''apascentar minhas ovelhas'' em João 21 sem considerar a relação pastor-rebanho do Antigo Testamento','Aplicar Gálatas 6:7 sem compreender o princípio agrícola de semeadura e colheita na cultura bíblica'),('FB07-L09-Q05','Reduzir casa e cidade ao sentido literal, perdendo descendência, aliança e povo de Deus.','Confundir a casa patriarcal com o templo, tratando promessas familiares como cultuais.','Interpretar cidades bíblicas como alegorias, sem reconhecer sua função histórica concreta.','Negar o valor teológico das casas e cidades, reduzindo-as a meros elementos geográficos.'),('FB07-L07-Q01','Comiam pão, azeite, frutas e carne; duas refeições ao dia, usando as mãos.','Três refeições diárias obrigatórias: cereal, legumes e carne assada em fogueiras comunitárias.','Usavam garfos e facas de metal em todas as refeições, seguindo rigorosa etiqueta à mesa.','Apenas vegetarianos consumiam frutas e grãos; carne era proibida durante todo o período bíblico.'),('FB07-L10-Q03','No mundo antigo era dever sagrado; hoje é relação comercial e impessoal.','No mundo antigo era ato puramente opcional; hoje tornou-se dever legal universal.','No mundo antigo limitava-se à alimentação; hoje abrange tecnologia digital.','A hospitalidade não existiu no mundo antigo; surgiu apenas na era cristã.'),('FB07-L11-Q02','Cambistas no templo, denário do tributo, pesos justos e proibição de usura','Sacrifícios pagãos no mercado, troca de esposas por moedas, culto a Mamom','Proibição absoluta de qualquer comércio, voto universal de pobreza, ausência de moedas','Troca apenas por cabras e ovelhas, mercado central no Sinai, moedas de barro cru'),('FB07-L11-Q04','Parábola da dracma perdida, dos talentos, do denário de César e da viúva','A sarça ardente, o maná no deserto e a coluna de fogo','O batismo de Jesus, a tentação no deserto e a transfiguração','A criação do mundo, a queda do homem e a torre de Babel'),('FB07-L12-Q02','Servo que recusava a liberdade tinha a orelha perfurada contra a porta','Escravos eram libertados obrigatoriamente a cada três anos de serviço','O dono podia vender seus escravos somente após sete anos','Escravos estrangeiros tinham direito ao jubileu igual aos hebreus'),('FB07-L12-Q01','Escravidão no mundo bíblico envolvia prisioneiros de guerra, dívidas e nascimento.','A escravidão bíblica era idêntica à transatlântica moderna em todos os aspectos.','Todos os escravos eram libertos automaticamente após sete anos sempre.','Escravos no mundo bíblico não possuíam absolutamente nenhum direito legal.'),('FB07-L12-Q04','Filemom, Efésios 6:5-9, Colossenses 3:22-25, 1 Pedro 2:18-25','Apocalipse 13, Daniel 9, Isaías 53','Romanos 8, Gálatas 5, Filipenses 2','Hebreus 1, Hebreus 2, Hebreus 4'),('FB07-L13-Q05','Aplicar leis e juízos fora de contexto gera legalismo ou antinomianismo.','Afirmar que os juízos do AT descrevem castigos físicos literais de Deus nos dias atuais.','Ensinar que apenas Israel pode cumprir as leis bíblicas, excluindo a igreja de toda aplicação.','Concluir que todas as leis do AT são apenas tipológicas, sem qualquer valor normativo.'),('FB07-L15-Q05','Perder a tipologia das festas como sombras do que viria em Cristo','Identificar as festas como rituais sincréticos derivados do paganismo','Afirmar que as festas perderam todo significado após o cativeiro','Aplicar o sábado e festas como requisitos obrigatórios da igreja'),('FB07-L16-Q05','Moralizar textos cerimoniais, confundindo impureza ritual com pecado moral','Tratar as normas de pureza como meras questões culturais sem valor espiritual','Achar que toda impureza ritual indica culpa moral pessoal grave','Ignorar a distinção entre limpo e imundo como categorias teológicas válidas'),('FB07-L17-Q04','Lucas 4:16-21 e Atos 13:14-15, onde Jesus e Paulo ensinam na sinagoga','1 Reis 8:1-11 e 2 Crônicas 5:1-14, dedicação do templo de Salomão','Apocalipse 1:9-11 e 22:1-5, visão da nova Jerusalém celestial','Gênesis 12:1-3 e Êxodo 3:1-10, chamado de Abraão e Moisés'),('FB07-L17-Q03','Antigas: Torá e reunião. Modernas: liturgia fixa, funções sociais amplas.','São idênticas em estrutura e propósito ao longo dos séculos','Antigas tinham sacrifícios diários como o Templo','Modernas não incluem a leitura das Escrituras'),('FB08-L01-Q05','Limita-se ao contexto histórico e cultural; não valida verdades espirituais.','Valida integralmente todos os relatos bíblicos como historicamente exatos.','É a fonte mais confiável e suficiente para interpretar todo o texto sagrado.','Substitui o texto bíblico como autoridade máxima da fé e da doutrina.'),('FB08-L03-Q04','Arqueologia bíblica confirma relatos de pessoas, lugares e eventos','Técnicas modernas de mineração em regiões desérticas antigas','Métodos de construção dos templos pagãos da Babilônia','Escavações para fundação de igrejas cristãs primitivas'),('FB08-L04-Q05','A datação estabelece apenas plausibilidade temporal, não confirma os eventos narrados.','Prova definitivamente a historicidade e veracidade de todos os relatos bíblicos.','A datação arqueológica é totalmente irrelevante para a interpretação bíblica.','Confirma apenas os aspectos miraculosos e teológicos das narrativas bíblicas.'),('FB08-L06-Q01','Primeira menção extra-bíblica de Israel, comprovando sua existência antiga','Tábuas dos Dez Mandamentos gravadas por Moisés no monte Sinai','Monumento erguido por Josué para marcar a travessia do Jordão','Pedra original da Lei encontrada dentro da Arca da Aliança'),('FB08-L06-Q05','Menciona apenas Israel como povo, sem detalhar relatos bíblicos específicos.','Confirma todos os eventos narrados em Josué e Juízes com precisão histórica.','Data o êxodo de Israel do Egito no século XIII a.C. com exatidão.','Comprova a existência dos reinos de Davi e Salomão no século X a.C.'),('FB08-L08-Q03','Menciona a Casa de Davi, evidência extra-bíblica do reinado davídico','Registra a construção do Templo de Salomão em Jerusalém','Descreve a destruição de Sodoma e Gomorra por fogo do céu','Narra a aliança entre Israel e o faraó do Egito na saída do Egito'),('FB08-L08-Q05','Fragmentária e inimiga do séc. IX; atesta só a dinastia, não os relatos bíblicos.','Confirma todos os relatos do reinado de Davi com precisão histórica absoluta.','Prova que Davi governou todo o Israel unido conforme descrito em 1 Samuel.','Inscrição original de Davi, do séc. X a.C., que valida a narrativa bíblica.'),('FB08-L09-Q05','Confirma dados hidráulicos específicos, não valida toda a narrativa bíblica.','Prova toda a historicidade de 2 Reis 20 e 2 Crônicas 32 sem ressalvas.','Confirma exclusivamente os milagres e profecias atribuídos a Isaías.','Invalida todas as teorias críticas sobre a composição deuteronomista.'),('FB08-L11-Q03','Confirma o decreto de Ciro permitindo o retorno dos Judeus a Jerusalém','Confirma que Nabucodonosor ordenou o retorno dos Judeus a Jerusalém','Registra em escrita hebraica antiga as leis dadas por Deus a Ciro','Relata a destruição completa do templo de Jerusalém ordenada por Ciro'),('FB08-L11-Q04','Confirma o édito de Ciro que libertou os judeus do cativeiro babilônico.','Refere-se a Nabucodonosor, que destruiu o templo e levou os judeus cativos.','Relaciona-se com Alexandre Magno, conquistador da Pérsia e da Grécia.','Descreve o édito de Dario, que proibiu os judeus de reconstruírem o templo.'),('FB08-L14-Q05','NAO SEI','A evidencia arqueologica confirma literalmente todos os relatos do Novo Testamento','Descobertas do NT sao a unica fonte confiavel de interpretacao','Manuscritos do NT nao possuem relacao com eventos historicos'),('FB09-L01-Q01','Do grego kanon, significa regra ou norma, padrão para livros inspirados','Significa livro proibido, do latim canon, referindo-se a textos censurados','É um cântico hebraico, referindo-se especificamente aos salmos davídicos','Significa cópia fiel, do aramaico, indicando manuscritos dos escribas'),('FB08-L16-Q04','Por meio de falsificações e interpretações equivocadas de artefatos bíblicos.','Confirmam historicamente todos os relatos do Antigo Testamento.','Provam que todos os personagens bíblicos existiram exatamente como descritos.','São causadas exclusivamente por erros de tradução da Septuaginta.'),('FB09-L01-Q05','Cânon é a lista de livros reconhecidos por apostolicidade, ortodoxia e uso litúrgico','O cânon foi definido definitivamente pelo Concílio de Nicéia em 325 d.C.','A Igreja Católica adicionou os Apócrifos ao cânon de forma arbitrária em Trento','O cânon bíblico é uma lista fechada determinada exclusivamente pelo papado'),('FB09-L02-Q01','Coleção dos livros sagrados reconhecidos como divinamente inspirados','Conjunto dos manuscritos mais antigos descobertos pelos arqueólogos','Lista das traduções oficiais da Bíblia em diferentes línguas','Relação dos livros apócrifos rejeitados pelos concílios ecumênicos'),('FB09-L03-Q02','Formou-se em tres etapas: Lei, Profetas e Escritos, reconhecido no seculo I d.C.','Foi definido no Concilio de Hipona em 393, incluindo livros deuterocanonicos','Esdras e Neemias organizaram todas as escrituras no seculo V a.C. em Jerusalem','Os escribas de Alexandria estabeleceram o canon usando a Septuaginta grega'),('FB09-L05-Q03','Livros deuterocanonicos, tradicao alexandrina, igreja cristã primitiva','Textos massoreticos, comunidade essenia, tradicao babilonica','Apenas livros protocanonicos, tradicao palestina, sinagogas rabinicas','Vulgata latina, tradicao jeronimiana, concilios medievais'),('FB09-L06-Q05','Não dizer que foram acrescentados em Trento; já estavam na Septuaginta cristã.','Apresentar os deuterocanônicos como livros exclusivamente protestantes, surgidos após Lutero.','Afirmar que foram escritos por Paulo em Roma como cartas pastorais às igrejas.','Classificar os deuterocanônicos como parte do Novo Testamento, junto aos Evangelhos.'),('FB09-L06-Q01','Livros canônicos tardios, incluídos na Bíblia Católica e Ortodoxa','Livros rejeitados por todas as tradições cristãs históricas','Escritos exclusivamente pertencentes ao Novo Testamento','Textos apócrifos sem qualquer autoridade religiosa'),('FB09-L07-Q02','Formou-se na Reforma Protestante, com 66 livros, excluindo os deuterocanônicos.','Foi definido pelo Concílio de Trento em 1546, incluindo os livros deuterocanônicos.','Foi reconhecido no dia de Pentecostes, quando os apóstolos escreveram os livros.','Foi estabelecido pelo Rei James I em 1611, com a publicação da versão King James.'),('FB09-L09-Q02','NAO SEI','...','...','...')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB09-L09-Q04','Ortodoxos incluem livros a mais que católicos e protestantes, como 3 Macabeus e Oração de Manassés','Cânon ortodoxo é idêntico ao protestante, diferindo apenas no Novo Testamento','Cânon ortodoxo é o mais restrito, excluindo todos os livros deuterocanônicos','Ortodoxos seguem exatamente o cânon católico romano, sem qualquer diferença'),('FB09-L10-Q05','NAO SEI','...','...','...'),('FB09-L11-Q02','A Igreja reconheceu o cânon com critérios de apostolicidade, ortodoxia e inspiração.','O Concílio de Trento definiu definitivamente o cânon bíblico no século XVI.','Os livros foram escolhidos por votação popular nas igrejas primitivas.','Apenas os livros do Antigo Testamento hebraico foram reconhecidos como inspirados.'),('FB09-L11-Q03','Sinédrio de Javne e os critérios de apostolicidade, inspiração e ortodoxia','Concílio de Niceia e o critério de consubstancialidade cristológica','Sinagoga de Cafarnaum e os critérios de pureza levítica','Concílio de Trento e o critério de unanimidade patrística exclusiva'),('FB09-L12-Q02','O cânon do NT se formou gradualmente, sendo o Concílio de Cartago (397) um marco.','Definido definitivamente pelo Concílio de Niceia em 325, sem processo prévio.','Os próprios apóstolos reuniram e canonizaram seus escritos no primeiro século.','O papa Dâmaso I estabeleceu sozinho o cânon do NT em seu decreto de 382.'),('FB09-L15-Q03','Concílio de Cartago (397) ratificou o cânon das Escrituras cristãs','Concílio de Trento (1546) excluiu os livros deuterocanônicos do cânon','Concílio de Niceia (325) definiu os 66 livros do cânon protestante','Concílio de Jerusalém (50 d.C.) excluiu os livros apócrifos'),('FB10-L01-Q04','Não anula a autoridade das Escrituras, mas a confirma e complementa.','Substitui as Escrituras como fonte primária de autoridade divina.','Torna as Escrituras desnecessárias para o conhecimento salvífico.','Contradiz o ensino das Escrituras sobre o conhecimento de Deus.'),('FB10-L01-Q03','Revelação geral é o conhecimento de Deus na natureza, acessível a todos.','Revelação especial é a Palavra de Deus escrita, dada somente aos profetas.','Inspiração é o processo pelo qual Deus guiou os autores bíblicos na escrita.','Iluminação é a obra do Espírito para entender as Escrituras já escritas.'),('FB10-L06-Q05','Evitar o naturalismo que nega a inspiração e o mecanicismo que anula o autor','Os autores escreveram apenas por opinião humana sem inspiração divina','Os escritores bíblicos foram meros ditadores passivos sem contribuição pessoal','Toda a Escritura foi escrita diretamente por Deus sem participação humana'),('FB10-L06-Q01','Os autores humanos contribuíram com seu estilo próprio sob a inspiração divina','Os autores humanos escreveram independentemente da ação do Espírito Santo','Os autores humanos foram passivos como simples instrumentos sem personalidade','Apenas a vontade humana, sem ação divina, produziu as Escrituras'),('FB10-L10-Q03','Assegura que a Bíblia basta para salvação e piedade, sem necessidade de acréscimos.','Afirma que a Bíblia é totalmente livre de erros em todo o seu conteúdo.','Garante que a Bíblia é perfeitamente clara em todas as suas passagens.','Ensina que a Bíblia é o único caminho de conhecimento sobre Deus.'),('FB10-L12-Q01','São necessárias porque a revelação natural é insuficiente para a salvação.','São necessárias apenas para documentar a história do povo de Israel.','São necessárias porque complementam a obra redentora de Cristo na cruz.','São necessárias somente para orientar normas morais e políticas civis.'),('FB10-L12-Q02','Toda a Escritura é divinamente inspirada e proveitosa para o ensino e correção','A tradição oral da igreja é o fundamento único para a necessidade das escrituras','A iluminação interior do Espírito torna as escrituras externas desnecessárias','Os concílios ecumênicos decidiram a autoridade e necessidade das escrituras'),('FB11-L07-Q01','Versão do Pentateuco usada pelos samaritanos, escrita em alfabeto paleo-hebraico.','Conjunto dos cinco primeiros livros do Novo Testamento, próprio da seita samaritana.','Coletânea de salmos e provérbios preservada pela comunidade samaritana antiga.','Tradução aramaica da Bíblia Hebraica feita pelos samaritanos no século I.'),('FB10-L15-Q04','Exigem estudo, oração e Espírito Santo, sem afetar a autoridade das Escrituras.','Comprovam que a Bíblia possui erros e perde totalmente sua autoridade divina.','Devem ser ignoradas pois a Escritura não apresenta nenhuma dificuldade real.','Indicam que somente o clero pode interpretar corretamente as Escrituras Sagradas.'),('FB11-L08-Q01','Tradução grega do Antigo Testamento, feita por 70 sábios em Alexandria.','Tradução latina da Bíblia completa, feita por Jerônimo no século IV.','Versão siríaca do Novo Testamento, usada nas igrejas da Antiga Pérsia.','Compilação de livros apócrifos organizada por Orígenes em Alexandria.'),('FB11-L09-Q05','Confirmam a fidelidade da transmissão textual em comparação ao Texto Massorético.','Provam que o Novo Testamento contém erros de transmissão textual.','Invalidam o Texto Massorético ao apresentar versões completamente distintas.','Foram escritos diretamente pelos profetas do Antigo Testamento.'),('FB12-L04-Q03','NAO SEI','Para facilitar a memorização de Salmos em grupo de estudo','Para traduzir textos bíblicos do hebraico para o português','Para comparar diferentes versões da Bíblia durante a pregação'),('FB12-L04-Q04','Porque interpretam o texto, comprometendo a fidelidade e a precisão doutrinária.','Porque são versões inspiradas diretamente pelo Espírito Santo, dispensando outras traduções.','Porque foram escritas somente após o século IV, sendo consideradas textos apócrifos.','Porque contêm exatamente os mesmos textos das traduções literais fiéis ao original.'),('FB12-L15-Q05','Como apoio ao estudo, comparando com outras traduções e os idiomas originais.','Substituindo integralmente todas as demais traduções bíblicas no estudo.','Como única fonte de consulta, dispensando os textos originais hebraico e grego.','Apenas para leitura devocional, sem aplicação no estudo exegético.'),('FB12-L18-Q03','Notas explicativas, introduções aos livros e aparato crítico fundamentado nos textos originais.','Tradução baseada na Vulgata Latina, sem aparato crítico ou notas explicativas.','Versão ecumênica protestante fundamentada apenas na Septuaginta grega.','Texto corrido sem divisão de capítulos ou versículos para leitura fluente.'),('FB13-L04-Q02','O propósito do livro fornece o contexto autoral que esclarece a passagem','O propósito do livro é irrelevante; apenas o versículo isolado importa','A passagem isolada define o propósito do livro, nunca o contrário','O propósito do livro elimina a necessidade de considerar o contexto histórico'),('FB13-L05-Q02','Porque revela o sentido original e evita interpretações anacrónicas.','Porque a Bíblia é atemporal e dispensa qualquer análise externa ao texto.','Só é relevante para o Antigo Testamento, pois o Novo não depende de cultura.','O sentido espiritual sempre prevalece sobre qualquer análise histórica do texto.'),('FB14-L01-Q03','Contexto histórico, crítica textual, gramática, gênero e síntese teológica.','Confissão doutrinária, oração pessoal, meditação e leitura devocional.','Interpretação literal, tipológica, alegórica e anagógica dos quatro sentidos.','Tradução literal, memorização de versículos, sermão e estudo de palavras-chave.'),('FB14-L04-Q05','Subjetivismo, eisegese e falta de observacao do contexto original','Comparar diferentes traducoes biblicas para verificar o sentido exato','Consultar comentarios teologicos de autores reconhecidos academicamente','Realizar leitura comparativa com passagens paralelas de todo o texto'),('FB14-L07-Q01','Identificação dos parágrafos e da progressão lógica do texto bíblico.','O estudo do contexto histórico e cultural em que o texto foi escrito.','A comparação entre diferentes traduções e versões bíblicas.','A aplicação prática do texto para a vida do leitor moderno.'),('FB14-L07-Q05','Impor estrutura alheia, ignorar o gênero literário e dividir arbitrariamente','Buscar a estrutura original por repetições, contrastes e progressão de ideias','Comparar a passagem com textos paralelos em outros livros bíblicos','Considerar o contexto histórico e o público original do texto'),('FB14-L10-Q03','Tempos verbais, modos, vozes, sintaxe, preposições e ordem dos termos na oração','Autoria, datação, proveniência dos manuscritos e comparação de variantes textuais','Contexto histórico, cultural, geográfico, político e costumes religiosos da época','Estrutura literária, gêneros textuais, paralelismos poéticos e figuras de linguagem'),('FB14-L15-Q04','NAO SEI','Os comentários substituem a leitura direta do texto bíblico pelo leitor','Os comentários confirmam apenas interpretações já estabelecidas pelo leitor','Os comentários se limitam a dados geográficos sem abordar questões teológicas'),('FB15-L05-Q02','Evidência transcricional','Evidência extrínseca','Evidência arqueológica','Evidência intrínseca'),('FB15-L10-Q04','Não decidem sozinhos: manuscritos são mistos e famílias se sobrepõem.','A família Bizantina é sempre a mais confiável por sua grande quantidade.','A família Ocidental é a única que preserva fielmente o texto original.','Famílias textuais são categorias absolutas, sem exceções ou misturas.'),('FB15-L12-Q04','Base manuscritual restrita, data tardia dos testemunhos e descobertas de papiros mais antigos','Erros gramaticais na transcrição dos escribas alexandrinos do século III','Ausência de aprovação conciliar para uso exegético oficial','Contradições doutrinárias entre os manuscritos do Novo Testamento'),('FB15-L13-Q02','evidência manuscrita','evidência arqueológica','evidência geográfica','evidência científica'),('FB15-L19-Q01','Expor variantes textuais com honestidade, sem dogmatismos ou manipulações.','Esconder variantes que contradigam a tradição eclesiástica estabelecida.','Priorizar sempre o Textus Receptus em decisões textuais complexas.','Apresentar somente variantes que não alterem a doutrina oficial da igreja.'),('FB16-L02-Q03','NAO SEI','Apenas em algarismos arábicos no corpo do texto','Somente em hebraico quadrático sem sinais vocálicos','Exclusivamente em notas de rodapé com caracteres gregos'),('FB16-L02-Q04','Nunca copiar de memória, sempre conferir a fonte original','Decorar primeiro e depois copiar sem conferir','Pular letras que pareçam semelhantes entre si','Copiar apenas o início de cada palavra hebraica'),('FB16-L07-Q02','Pelos sufixos de gênero e número, artigo הַ e pela posição na frase','Por meio de desinências casualísticas como nominativo, genitivo e dativo','Exclusivamente pelo artigo definido הַ sempre presente no início','Pela terminação invariável em -us para o masculino e -um para o feminino'),('FB16-L07-Q05','Porque substantivos hebraicos carregam gênero, número e sentido teológico.','Porque o Antigo Testamento possui mais verbos do que substantivos.','Porque os substantivos gregos determinam a tradução do texto.','Porque não há variação de gênero nos substantivos hebraicos.'),('FB16-L15-Q02','Pelos padrões verbais qatal e yiqtol, prefixos, sufixos e contexto.','Pela flexão de casos nominais e gêneros do latim aplicadas.','Pelo sistema de conjugações em quatro modos verbais fixos.','Pela declinação de substantivos gregos em três gêneros.'),('FB17-L04-Q05','Porque revela sujeito, objeto e conceitos teológicos centrais do texto grego','Porque substitui a necessidade de estudar verbos e sintaxe grega','Porque garante tradução literal palavra por palavra sem ajustes','Porque elimina toda ambiguidade idiomática do texto original'),('FB17-L08-Q02','Pela terminação casual que marca pessoa, número, gênero e caso.','São reconhecidos unicamente pela posição antes do substantivo.','Formam-se pela simples repetição da terminação do verbo.','Não apresentam declinação, mantendo forma invariável.'),('FB17-L09-Q05','Definem relações precisas de sentido entre as palavras no texto grego.','São elementos decorativos sem impacto na compreensão do texto bíblico.','Todas as preposições gregas possuem um único significado fixo e imutável.','Servem apenas para preencher espaços entre as palavras na frase grega.'),('FB17-L10-Q04','O tipo, o contexto, a relação entre as orações e a intenção do autor','Apenas a posição fixa da palavra e sua tradução literal','Somente a frequência de uso na literatura secular da época','A etimologia da conjunção e sua origem histórica isoladamente'),('FB17-L12-Q02','Desinências pessoais, aumento, redobro e alterações no radical verbal','Apenas pela ordem das palavras na oração grega','Exclusivamente pelo significado contextual do verbo','Somente pelo acento prosódico na sílaba tônica'),('FB17-L16-Q01','Forma nominal do verbo que expressa a ação sem referência a pessoa ou número','Forma verbal pessoal que indica o sujeito, número e tempo da ação','Modo verbal usado para expressar ordens, comandos ou exortações','Adjetivo verbal que concorda em gênero, número e caso com o substantivo'),('FB17-L18-Q04','Contexto histórico-cultural, o grego koinê e o uso na Septuaginta.','O hebraico masorético e a tradição rabínica do Talmude.','A Vulgata Latina e os escritos dos Pais Apostólicos.','Apenas o sentido místico e alegórico sem contexto literal.'),('FB18-L13-Q05','Não tratá-las como variantes de uma só língua; respeitar diferenças próprias.','Hebraico e aramaico são essencialmente a mesma língua, portanto intercambiáveis.','O aramaico é simplesmente uma forma tardia e corrompida do hebraico antigo.','Basta uma tradução literal de uma língua para outra para compreendê-las bem.'),('FB18-L14-Q04','Era a língua falada por Jesus, essencial para o sentido original dos Evangelhos.','Era a única língua usada para escrever todo o Antigo Testamento.','Foi abolida completamente após a destruição do Templo em 70 d.C.','Era a língua oficial do Império Romano na época de Jesus.'),('FB18-L14-Q03','Línguas semíticas noroeste cognatas, com influências mútuas e origens comuns.','O aramaico deriva diretamente do hebraico antigo como sua evolução natural.','Jesus falava exclusivamente o hebraico bíblico em seu cotidiano na Galileia.','São línguas semíticas sem parentesco genético, apesar de algumas semelhanças.'),('FB18-L15-Q03','NAO SEI','O aramaico era a lingua nativa de Jesus e nao o hebraico','Jesus escreveu os textos em hebraico no Monte das Oliveiras','Todas as palavras de Jesus foram preservadas em siríaco original'),('FB18-L15-Q04','Reconhecer os limites evita distorções e promove interpretação fiel ao contexto','Permite ignorar o contexto histórico e aplicar livremente qualquer sentido','Garante que toda palavra atribuída a Jesus seja literalmente confirmada','Elimina a necessidade de consultar estudiosos e traduções acadêmicas'),('NT01-L03-Q01','Processo de difusão da cultura grega nos territórios conquistados por Alexandre Magno.','Tradução dos textos sagrados hebraicos para a língua grega em Alexandria.','Revolta dos judeus liderados pelos Macabeus contra Antíoco IV Epifânio.','Domínio cultural e político exercido pelo Império Romano sobre a Judeia.'),('NT01-L02-Q01','Conquistador macedônio que dominou a Pérsia e helenizou o Oriente Médio','General macabeu que liderou a revolta judaica contra os selêucidas','Sumo sacerdote judeu responsável pela tradução da Septuaginta','Imperador persa que libertou os judeus do cativeiro na Babilônia'),('NT01-L04-Q02','Pós-morte de Alexandre Magno (323 a.C.), no período helenístico entre os Diádocos','Durante o apogeu do Império Romano, na divisão entre César e Pompeu','Na era de Péricles, durante as Guerras Médicas na Grécia clássica','Na Queda de Constantinopla em 1453, fim do Império Bizantino'),('NT01-L05-Q01','Dinastia grega que governou o Egito após Alexandre, o Grande','Rei persa que autorizou a reconstrução do templo em Jerusalém','General macedônio que conquistou a Judeia no período selêucida','Sumo sacerdote judeu que governou o templo durante o cativeiro'),('NT01-L06-Q01','Dinastia helenística que governou a Síria e dominou a Judeia','Facção religiosa judaica rival dos fariseus no Sinédrio','Reino do norte formado após a divisão do reino de Israel','Povo hebreu deportado para a Babilônia por Nabucodonosor'),('NT01-L05-Q06','Revela a helenização que moldou a cultura e a língua do Novo Testamento','Esclarece o papel do Império Romano nos tempos do Novo Testamento','Auxilia no entendimento do cativeiro babilônico e seus efeitos','Ajuda a interpretar as profecias messiânicas do Antigo Testamento'),('NT01-L07-Q06','NAO SEI','Fortaleceu a identidade dos seguidores e firmou o martirio como testemunho de fe','Gerou esperanÃ§a apenas para os gentios, sem efeito sobre o judaÃ­smo','Provocou o fim imediato da esperanÃ§a messiÃ¢nica judaica'),('NT01-L07-Q02','NAO SEI','Proibiu o culto no Templo e impôs sacrifícios a Zeus','Exigiu tributo anual a Roma e ordenou o censo de Quirino','Confiscou as terras e obrigou a helenização dos costumes'),('NT01-L08-Q07','NAO SEI','Fortaleceram a expectativa de um Messias politico e militar que libertaria Israel','Geraram o desejo de restauração do trono de Davi com poder temporal','Intensificaram a esperança apocaliptica de um reino celestial imediato'),('NT01-L08-Q06','A revolta macabeia contra Antioquia Epifanes originou a dinastia asmoneia.','Herodes, governador idumeu, fundou a dinastia asmoneia apos a revolta.','A revolta dos zelotes contra Roma, em 70 d.C., originou a dinastia asmoneia.','Antiochus Epifanes fundou a dinastia asmoneia apos a revolta macabeia.'),('NT01-L13-Q06','Identifica o texto-base das citações veterotestamentárias no Novo Testamento','Permite ler o Novo Testamento em sua língua original hebraica','Substitui completamente o estudo do Novo Testamento grego','Serve apenas para corrigir erros textuais do Antigo Testamento'),('NT01-L18-Q01','Os escribas (soferim) eram copistas e intérpretes da Lei no período interbíblico.','Os escribas eram soldados romanos que vigiavam o Templo no período interbíblico.','Os escribas eram profetas que anunciavam a vinda do Messias no período interbíblico.','Os escribas eram sacerdotes do templo que ofereciam sacrifícios no período interbíblico.'),('NT02-L01-Q05','Porque apresenta estrutura, conteúdo e cronologia distintos dos demais evangelhos.','Porque foi escrito originalmente em aramaico, e não em grego.','Porque não contém nenhuma parábola de Jesus em seu texto.','Porque não menciona a ressurreição física de Jesus Cristo.'),('NT02-L02-Q03','Evidenciam o cumprimento das profecias em Cristo, confirmando a inspiração divina.','Servem apenas como registro histórico dos fatos narrados no Antigo Testamento.','Indicam as prescrições cerimoniais e leis rituais do Antigo Testamento.','Revelam os ensinos morais de Jesus para orientar a conduta dos crentes.'),('NT02-L04-Q02','NAO SEI','Declara inspiração divina direta sem investigação humana prévia','Afirma que o texto é obra coletiva sem autor identificável','Promete revelar segredos ocultos apenas para iniciados'),('NT02-L04-Q03','Privilegia os pobres, mulheres, estrangeiros e marginalizados sociais','Privilegia os fariseus, saduceus e a elite religiosa','Dá atenção exclusiva aos Apóstolos e seus ensinamentos','Ignora os marginalizados e foca na lei mosaica'),('NT02-L05-Q06','Analisando as semelhanças sem ignorar o contexto e a teologia própria de cada Evangelho.','Eliminando todas as diferenças para obter um único Evangelho harmonizado e unificado.','Estudando as semelhanças isoladas, totalmente fora do contexto de cada Evangelho.','Priorizando exclusivamente as diferenças e descartando toda semelhança entre eles.'),('NT02-L05-Q01','Batismo no Jordão, tentações, transfiguração, paixão e ressurreição','O nascimento virginal, a fuga para o Egito e a apresentação no templo','A ressurreição de Lázaro, a multiplicação dos pães e a mulher adúltera','A conversão de Paulo, o concílio de Jerusalém e a visão de Patmos'),('NT02-L06-Q01','Mateus enfatiza profecias, Lucas a universalidade, Marcos a ação.','Mateus é o mais curto, Marcos o mais longo, Lucas o mais antigo.','Apenas Lucas contém parábolas e o Sermão do Monte.','Os três evangelhos contêm exatamente o mesmo conteúdo.'),('NT02-L06-Q04','As diferenças refletem os distintos públicos, propósitos e ênfases teológicas de cada autor','As variações textuais existem porque Deus permitiu erros na transmissão bíblica','Os autores bíblicos se contradizem, provando que a Bíblia contém erros doutrinários','As diferenças surgiram porque os escribas alteraram intencionalmente o texto sagrado'),('NT02-L09-Q05','Cada evangelista escreveu a um público específico, com ênfases próprias.','Os evangelistas copiaram literalmente uns dos outros, sem diferenças reais.','As diferenças mostram que os Evangelhos contêm erros e contradições históricas.','Os Evangelhos foram escritos sem intenção teológica, apenas como relatos.'),('NT02-L10-Q02','Pela tradição oral, os apóstolos pregavam e ensinavam as comunidades','Através de documentos oficiais registrados pelos escribas do Sinédrio','Por meio de cartas trocadas entre os fariseus e o imperador romano','Através de registros escritos em pergaminhos pelos soldados romanos'),('NT02-L11-Q03','Mateus vai de Abraão a José; Lucas vai de Jesus até Adão e Deus','Mateus segue a linhagem de Natã; Lucas segue a de Salomão','Lucas começa em Abraão e Mateus termina em Adão','Ambas são idênticas, apenas em ordens diferentes'),('NT02-L10-Q05','Possuía fórmulas fixas, transmissão autorizada e técnicas mnemônicas rigorosas.','Era imediatamente transcrita em pergaminhos por escribas do templo.','Dependia apenas da memória pessoal, sem qualquer supervisão comunitária.','Constituía narrativa livre e criativa, desprovida de padrões fixos.'),('NT03-L02-Q01','Para que creiais que Jesus é o Cristo, o Filho de Deus','Para registrar todos os milagres como prova histórica','Para ensinar as parábolas do Reino aos gentios','Para estabelecer a ordem da igreja primitiva'),('NT03-L01-Q06','NAO SEI','O autor visa a obediência e os destinatários são os descrentes','O autor demonstra poder e os destinatários são os ricos','O autor narra milagres e os destinatários são os romanos'),('NT03-L02-Q03','NAO SEI','Todas as coisas Escrituras são proveitosas para doutrina','No princípio criou Deus os céus e a terra','Apocalipse de Jesus Cristo que Deus lhe deu'),('NT03-L03-Q01','João 1:1-18','João 1:1-5','Mateus 1:1-17','Apocalipse 1:1-8'),('NT03-L08-Q05','Sopra onde quer, ouves a sua voz, mas não sabes donde vem nem para onde vai','Desce como fogo ardente que consome toda impureza do crente','Flui como rio tranquilo de águas vivas que purifica o coração','Cai como semente preciosa em terra fértil e produz fruto'),('NT03-L09-Q02','Judeus e samaritanos; homem e mulher; pureza ritual','Judeus e gentios; circuncisos e incircuncisos; templo e sinagoga','Ricos e pobres; fariseus e publicanos; lei e evangelho','Marido e esposa; adúlteros e justos; acusadores e réus'),('NT03-L10-Q06','Concede a vida eterna a quem crê, realizando o propósito do Evangelho','Institui rituais sacramentalistas como meio único de salvação','Limita a salvação exclusivamente ao povo judeu eleito','Promove a justificação pelas obras da lei mosaica'),('NT03-L10-Q03','João 6: Jesus diz ''Eu sou o pão da vida'', após a multiplicação dos pães','Mateus 14: A multiplicação dos pães por si só explica o pão da vida','Apocalipse 2: Jesus se revela como pão da vida nas cartas às igrejas','Gênesis 14: Melquisedec oferece pão e vinho como pão da vida a Abraão'),('NT03-L11-Q01','Jesus disse: Eu sou a luz do mundo; quem me segue não andará em trevas','Os discípulos são a luz do mundo, conforme Mateus cinco, quatorze','João Batista afirmou ser a luz do mundo, segundo João um, oito','A luz do mundo se apagará com o fim dos tempos, ensina João'),('NT03-L18-Q06','Demonstra Jesus como Cristo glorificado na cruz, gerando fé e vida eterna','Confirma Jesus como rei político terreno frustrado pelo poder romano','Mostra a paixão como tragédia sem esperança de ressurreição ou vida','Estabelece rituais da paixão como base da nova lei cerimonial cristã'),('NT03-L19-Q06','Confirma Jesus como Cristo e Filho de Deus, possibilitando vida ao que crê','Apresenta Jesus como exemplo moral a ser imitado pelos discípulos','Demonstra que a ressurreição foi apenas espiritual, sem corpo físico','Tem por objetivo registrar fatos históricos para aposteridade da Igreja'),('NT04-L02-Q01','Para provar que Jesus é o Messias prometido, descendente de Davi e Abraão','Para registrar a descendência sacerdotal de Jesus da tribo de Levi','Para justificar a viagem da Sagrada Família para o Egito distante','Para demonstrar que José era realmente o pai biológico de Jesus'),('NT03-L20-Q01','No princípio era o Verbo, e o Verbo era Deus','O Verbo era o primeiro e mais poderoso dos anjos criados','Jesus era apenas um homem ungido, separado por Deus','O Verbo se fez carne, mas não era Deus antes da encarnação'),('NT04-L02-Q06','Provam a descendência de Davi e Abraão, cumprindo as profecias messiânicas.','Eram somente documentos do censo romano, sem qualquer valor teológico.','Apenas registravam a nobreza da família de José na sociedade judaica.','Jesus sendo Deus encarnado, dispensava qualquer registro genealógico.'),('NT04-L02-Q07','Revelam que a salvação de Cristo alcança gentios e pecadores','Estabelecem a legitimidade do sacerdócio levítico por herança','Provam que somente mulheres judias podiam gerar o Messias','Indicam que as mulheres eram as principais profetizas de Israel'),('NT04-L04-Q06','Traz a salvação prometida e o início da pregação do Evangelho aos povos','Traz a condenação dos discípulos pelo Sinédrio logo após o parto','Resultou na perda das Escrituras e no fim da lei de Moisés','Causou a fuga imediata de todos para a Galiléia dos gentios'),('NT04-L07-Q04','Dt 6.13, 6.16 e 8.3','Dt 5.6-21; 6.4-9; 11.13-21','Êxodo 20.3-17; 34.6-7; Dt 30.19','Dt 7.1-5; 12.29-32; 18.9-14'),('NT04-L09-Q06','Abandonaram profissão e família, foram discipulados e se tornaram pregadores do Evangelho','Os discípulos receberam grandes riquezas e poder político imediato após o chamado','O chamado não trouxe mudanças significativas na vida dos discípulos nem no Evangelho','Os discípulos fundaram um reino político terreno e se tornaram governantes de Israel'),('NT04-L09-Q01','Chamado dos primeiros discípulos junto ao mar e a escolha dos doze apóstolos','Batismo de Jesus no Jordão e tentação no deserto','Multiplicação dos pães e cura do paralítico','Última ceia, prisão no Getsêmani e negação de Pedro'),('NT04-L12-Q01','Purificação do Templo, debates sobre o sábado, ressurreição e a crucificação','Multiplicação dos pães, cura dos cegos e a ressurreição de Lázaro','Batismo no Jordão, tentação no deserto e a transfiguração no monte','A última ceia, a caminhada sobre as águas e a ascensão aos céus'),('NT04-L14-Q01','Transfiguração no monte, cura de cegos, entrada em Jerusalém e última ceia','Batismo no Jordão, tentação no deserto e chamada dos discípulos','Multiplicação dos pães, caminhada sobre as águas e discurso do pão da vida','Crucificação, ressurreição e aparições após a ressurreição'),('NT04-L17-Q04','A ceia simboliza o sangue de Cristo que selou a Nova Aliança','A ceia substitui a Nova Aliança ao ser repetida semanalmente','A Nova Aliança foi estabelecida por Moisés no Sinai','A ceia é apenas um rito cultural sem relação com alianças'),('NT04-L17-Q07','Porque Cristo a instituiu como memorial de sua morte até que ele venha.','Porque Paulo a introduziu como rito de unidade entre as igrejas.','Porque Moisés a ordenou como prolongamento da Páscoa anual.','Porque o concílio de Jerusalém a tornou obrigatória para os gentios.'),('NT04-L18-Q01','Getsêmani','Monte Sinai','Monte Carmelo','Monte Moriá'),('NT04-L22-Q01','José de Arimateia sepultou Jesus em túmulo novo, envolvendo-o em lençóis','Nicodemos coroou Jesus com espinhos e o sepultou em manjedoura','Lázaro desceu da cruz, foi ungido e sepultado por Simão Pedro','Maria Madalena tirou Jesus da cruz e o colocou em um sepulcro')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('NT04-L24-Q04','Que Jesus é o Cristo ressurreto, confirmado como Senhor e Salvador dos homens','Que Jesus era um líder terreno que falhou em estabelecer o reino político de Israel','Que Jesus era apenas um mestre moral cuja mensagem continua após a sua morte','Que as aparições foram alucinações dos discípulos causadas pelo trauma da crucificação'),('AT13-L21-Q05','O cristão busca a sabedoria em Cristo, em quem estão ocultos todos os tesouros','O cristão busca a sabedoria apenas pela razão humana e filosofia grega','A união com Cristo torna a busca por sabedoria totalmente desnecessária','A sabedoria cristã vem somente da tradição dos mestres da lei e dos anciãos'),('AT14-L04-Q04','Trabalhai de todo o coração, como para o Senhor e não para os homens','O trabalho é consequência do pecado e deve ser evitado pelos fiéis','Somente o descanso no sábado é agradável a Deus, não o trabalho','As realizações humanas são independentes da providência divina'),('AT14-L10-Q02','A águia que renova a mocidade, de Salmo 103:5','A serpente que muda de pele na velhice, de Números 21','O leão que enfraquece nos anos finais, de Juízes 14','A palmeira que floresce somente na velhice, de Salmo 92'),('AT14-L18-Q02','Uma só carne (Gn 2:24), Cântico dos Cânticos e 1 Co 7','O sábado como sinal da união matrimonial em Êxodo 20:8','A circuncisão como pacto de intimidade conjugal em Gn 17','Os sacrifícios de purificação do leito nupcial em Lv 12'),('AT15-L14-Q04','A glória do Senhor sai do templo pelo juízo e volta na restauração','A glória do Senhor nunca deixou o templo, permanecendo ali eternamente','A glória de Deus aparece em Ezequiel apenas para destruir Israel sem restauração','A glória do Senhor é conceito apenas neotestamentário, ausente no AT'),('AT15-L15-Q04','Cada um prestará contas a Deus pessoalmente','A responsabilidade é apenas coletiva para o povo','A aliança isenta o indivíduo de todo julgamento','A santidade elimina toda responsabilidade pessoal'),('AT15-L17-Q04','A glória do SENHOR retorna ao templo, manifestando santidade e restauração.','O templo é destruído pelo Senhor como juízo final e irrevogável sobre Israel','A aliança é anulada permanentemente, sem qualquer perspectiva de restauração futura','A santidade se afasta do templo definitivamente por causa da impureza do povo'),('AT15-L18-Q03','Fiéis perseverantes e juízos apocalípticos estruturam selos, trombetas e taças.','Promessas patriarcais e visões de palácios babilônicos dividem o livro em eras.','Sonhos reais e bestas do mar organizam cartas às sete igrejas gentílicas.','Parábolas messiânicas e sermões proféticos alternam-se ao longo do livro.'),('AT15-L18-Q05','Serviu com integridade sob Nabucodonosor, Belsazar, Dario e Ciro, fiel a Deus.','Recusou-se a governar a Babilonia, entregando o trono a Sadraque.','Negociou alianças politicas com o Egito para enfraquecer a Babilonia.','Abandonou a oração publica apos ser promovido a primeiro ministro.'),('AT16-L15-Q01','Repreensão ao sacerdócio corrupto e apelo à restauração da verdadeira adoração','Malaquias elogia os sacerdotes por sua dedicação e fidelidade sacrificial','O profeta anuncia a destruição do templo e o fim do culto levítico','Malaquias exorta o povo a abandonar a aliança e seguir costumes pagãos'),('AT17-L14-Q06','...','...','...','...'),('FB01-L08-Q03','Conhecê-los oferece contexto seguro para interpretar as Escrituras','Substituem o Espírito Santo na tarefa de interpretar a Bíblia','Tornam desnecessária a consulta a qualquer comentário teológico','Garantem por si sós a interpretação correta de toda a Escritura'),('FB01-L08-Q05','NAO SEI','Conhecendo as personagens é possível situar cada livro no contexto histórico e teológico','As personagens bíblicas funcionam como índices temáticos para localizar passagens','O estudo das personagens ajuda a memorizar versículos por associação narrativa'),('FB01-L09-Q02','Jerusalém, Belém, Galiléia e rio Jordão','Meca, Medina, Cairo e Istambul','Roma, Atenas, Alexandria e Esparta','Londres, Paris, Berlim e Viena'),('FB02-L04-Q05','Revelam juízo sobre o pecado e preparam a redenção universal em Cristo.','São relatos isolados sem conexão com o plano redentor de Deus.','Anulam a promessa divina ao mostrar que Deus desistiu da humanidade.','Aplicam-se apenas a Israel, sem alcance para as demais nações.'),('FB02-L05-Q04','A aliança divina e a promessa de descendência e terra','A construção do templo grandioso em Jerusalém','A travessia milagrosa do Mar Vermelho pelo povo','A entrega dos Dez Mandamentos no monte Sinai'),('FB02-L06-Q02','Moisés, Aarão, Faraó, as pragas, a Páscoa, o Mar Vermelho, o Sinai e Josué','Abraão, Isaque e Jacó, os patriarcas antes da escravidão no Egito','Davi, Salomão, a construção do templo e o reino dividido de Israel','Elias, Eliseu, Isaías e os profetas que advertiram contra a Babilônia'),('FB02-L13-Q02','Cristo, ressurreição dos mortos, juízo final e nova criação celestial.','Adão, Eva, queda no Éden e expulsão do paraíso terrestre.','Moisés, Faraó, pragas do Egito e travessia do Mar Vermelho.','Davi, Golias, Salomão e a construção do primeiro Templo em Jerusalém.'),('FB03-L06-Q04','Proclamar a Palavra de Deus, denunciar pecados e prefigurar Cristo','Registrar a história dos reis de Israel e as guerras com nações vizinhas','Ensinar as leis cerimoniais e os rituais do tabernáculo ao povo','Narrar o início da humanidade e a aliança de Deus com Abraão'),('FB03-L09-Q02','Narrativa da igreja primitiva, autoria de Lucas, segundo volume lucano','Livro de profecias e visões apocalípticas escrito por João','Coletânea de cartas pastorais escritas por Paulo às igrejas','Evangelho sinótico escrito por Marcos para os romanos'),('FB03-L13-Q06','Foram acrescentadas depois e nem sempre coincidem com mudança real de assunto.','Porque cada capítulo contém uma narrativa independente e sem conexão com o anterior.','Porque as divisões foram estabelecidas pelos próprios autores sagrados inspirados.','Porque o cânon bíblico exige que cada capítulo trate de um tema único e distinto.'),('FB03-L14-Q05','Estrutura em Torah, Nevi''im e Ketuvim, com livros históricos como profetas.','Divisão quádrupla: Lei, Históricos, Poéticos e Profetas, com deuteros canônicos.','Ordem baseada apenas em Pentateuco, Salmos e livros sapienciais restantes.','Classificação por gêneros: narrativos, líricos, proféticos e apocalípticos.'),('FB04-L12-Q05','Jesus encarna o exílio de Israel e realiza a esperança profética de restauração.','O exílio foi apenas castigo divino, sem qualquer relação com a esperança em Cristo.','Jesus veio apenas para restaurar a lei mosaica, sem relação com o exílio.','A esperança profética se realizou na libertação política de Israel, não em Jesus.'),('FB04-L13-Q03','O cumprimento das profecias messiânicas e das alianças abraâmica e davídica','A aliança mosaica estabelecida no Sinai e a entrega dos mandamentos','A conquista da terra de Canaã sob a liderança de Josué','O retorno do cativeiro babilônico e a reconstrução do templo'),('FB05-L10-Q03','Nabucodonosor, Zedequeias, Babilônia, Pérsia, Ciro, Zorobabel, Daniel','Moisés, Aarão, Faraó, Egito, Cades, Mar Vermelho, maná','Saul, Davi, Salomão, Israel, Judá, Filisteus, Amalequitas','Herodes, Pilatos, César, Roma, Grécia, Augusto, Tibério'),('FB05-L10-Q04','Destruição de Jerusalém por Nabucodonosor; depois, o édito de Ciro','Queda de Samaria pelos assírios; depois, a vinda do Messias','Reforma religiosa de Josias; depois, o cisma das dez tribos','Período dos juízes; depois, a divisão do reino de Israel'),('FB05-L17-Q09','Arrebatamento, Tribulação, Segunda Vinda, Milênio, Juízo Final, Nova Terra','Segunda Vinda, Arrebatamento, Tribulação, Milênio, Juízo Final, Nova Terra','Arrebatamento, Milênio, Tribulação, Segunda Vinda, Juízo Final, Nova Terra','Tribulação, Arrebatamento, Segunda Vinda, Milênio, Juízo Final, Nova Terra'),('FB07-L05-Q04','A parábola dos operários na vinha e a dos talentos','A criação do mundo e a queda do homem','A fuga do Egito e a travessia do mar Vermelho','O Sermão do Monte e as bem-aventuranças'),('FB07-L06-Q03','Antes: subsistência familiar e oferta a Deus. Hoje: produção industrial voltada ao comércio.','Não há diferenças; as práticas agrícolas e pecuárias permanecem idênticas.','No mundo antigo era proibido criar qualquer tipo de animal doméstico.','Hoje se planta sem sementes; no passado toda lavoura era geneticamente modificada.'),('FB07-L10-Q05','Julgar relatos bíblicos como imorais, sem considerar o código de honra da hospitalidade','Concluir que Abraão era politeísta por receber três visitantes divinos','Entender que Ló foi condenado por oferecer hospitalidade aos anjos','Interpretar que o servo de Abraão buscava esposa por obrigação hospitaleira'),('FB07-L14-Q02','Luto de sete dias, unção com especiarias e sepultamento em cavernas','Circuncisão no oitavo dia e consagração ao Senhor','Celebração da Páscoa anual com cordeiro e pães ázimos','Batismo nas águas e participação na ceia do Senhor'),('FB07-L14-Q04','A ressurreição de Lázaro (João 11) e o sepultamento de Jesus','A construção do tabernáculo no deserto (Êxodo 25-31)','As cartas às sete igrejas no livro de Apocalipse','A parábola do filho pródigo em Lucas 15'),('FB07-L16-Q01','Separava o limpo do imundo, exigindo lavagem ritual e sacrifícios expiatórios.','Baseava-se na contagem de méritos pelas obras humanas e jejum prolongado.','Era obtida unicamente pela profissão verbal de fé no Deus de Israel.','Aplicava-se apenas aos sacerdotes que serviam no Templo de Jerusalém.'),('FB07-L16-Q02','Leis sobre imundícia e purificação de pessoas, alimentos e objetos','Cultos idolátricos pagãos com sacrifícios humanos proibidos','Ritos de magia e feitiçaria praticados por falsos profetas','Celebrações festivas gentílicas com banquetes e danças pagãs'),('FB08-L03-Q05','NAO SEI','A arqueologia bíblica confirma historicamente todos os relatos das Escrituras','Escavações estratigráficas provam a veracidade literal de cada evento bíblico','Datação por radiocarbono é o único critério válido para validar textos sagrados'),('FB08-L08-Q01','Estela aramaica com a primeira menção extra-biblica a Casa de Davi','Mosaico bizantino celebrando a vitoria de Davi contra Golias','Decreto romano confirmando o reinado de Davi sobre Judá','Pergaminho essenio com os salmos atribuidos ao rei Davi'),('FB08-L11-Q05','NAO SEI','O cilindro foi escrito em hebraico antigo e datado do seculo I d.C.','Ciro governou apenas a Babilonia, sem autoridade sobre a Persia','O texto foi considerado falsificacao moderna por estudiosos'),('FB08-L12-Q04','Contêm cópias dos livros do Antigo Testamento, anteriores à era cristã.','Incluem manuscritos do Novo Testamento escritos pelos apóstolos.','Relatam a crucificação de Jesus e a ressurreição.','Foram escritos durante a perseguição romana aos cristãos.'),('FB09-L02-Q03','Torá, Nevi''im e Ketuvim compõem o cânon hebraico do Antigo Testamento','Evangelhos, Atos e Epístolas formam o cânon do Novo Testamento','Os apócrifos foram aceitos unanimemente como canônicos por todas as tradições','O Concílio de Trento ampliou o cânon com textos gnósticos do século II'),('FB09-L07-Q04','O cânon protestante possui 66 livros, a menos do que os cânones católico e ortodoxo.','O cânon protestante inclui os livros deuterocanônicos no Antigo Testamento.','O cânon protestante possui 73 livros, igual ao cânon católico.','O cânon protestante contém apenas o Novo Testamento, rejeitando o Antigo.'),('FB09-L10-Q03','Os 27 livros do Novo Testamento, formados por Evangelhos, Atos, Epístolas e Apocalipse','Os 39 livros do Antigo Testamento, organizados em Lei, Profetas e Escritos','Apenas os livros apócrifos e deuterocanônicos rejeitados pelo cânon cristão','Os quatro Evangelhos e o livro de Atos dos Apóstolos, sem as epístolas paulinas'),('FB09-L10-Q04','Baseou-se em apostolicidade, ortodoxia e aceitação universal pelas igrejas','Inclui os livros deuterocanônicos como Tobias e Judite no cânon principal','Foi definido exclusivamente pelo Concílio de Nicéia em 325 d.C.','Adota os mesmos critérios e livros da tradição etíope ortodoxa'),('FB09-L12-Q03','Pais Apostólicos e critérios de apostolicidade, ortodoxia e catolicidade','Livros deuterocanônicos e tradições farisaicas do judaísmo','Evangelhos gnósticos e comunidades essênias de Qumran','Escritos apócrifos veterotestamentários e tradições rabínicas'),('FB10-L02-Q04','Confirma a Escritura como autoridade divina e exige iluminação do Espírito','Confirma a autoridade da tradição eclesiástica acima da Escritura','Estabelece a razão humana como critério supremo de interpretação','Torna a Escritura acessível apenas por meio da experiência mística'),('FB10-L03-Q04','Confere autoridade suprema à Bíblia, sendo infalível na fé e na prática cristã.','Restringe a autoridade ao clero, exigindo releitura cultural das Escrituras.','Afirma que as Escrituras são humanas, com erros em assuntos científicos e morais.','Permite acréscimos orais à Bíblia, conforme a tradição da igreja primitiva.'),('FB10-L04-Q05','Evitar o racionalismo e o ditado mecânico que anula o elemento humano','Evitar a inerrância absoluta e a unidade do cânon bíblico','Evitar a coautoria divina e a preservação providencial do texto','Evitar a autoridade e a suficiência das Escrituras Sagradas'),('FB10-L05-Q02','2 Tm 3.16: toda Escritura divinamente inspirada e proveitosa','Baseia-se apenas nos quatro evangelhos e nas epístolas paulinas','Gênesis 1.1 fundamenta a inspiração plena das Escrituras Sagradas','Apenas os livros proféticos são inspirados, não os históricos'),('FB10-L13-Q01','A coerência da Escritura, que possui um só Autor e um único plano redentor.','A separação entre Antigo e Novo Testamento como mensagens distintas de Deus.','A uniformidade de estilo literário entre todos os livros bíblicos.','A autoria exclusivamente humana dos livros sagrados em tempos diferentes.'),('FB10-L13-Q02','Inspiração divina (2 Tm 3:16) e Cristo como centro de toda a Escritura','Unidade baseada apenas na decisão dos concílios eclesiásticos','Coerência resultante do estilo literário uniforme dos hagiógrafos','Unidade limitada aos preceitos morais compartilhados entre os testamentos'),('FB10-L13-Q03','Coerência do plano redentor de Deus em ambos os testamentos','Inspiração verbal e plenária do Espírito Santo nos autores bíblicos','Critério de reconhecimento dos livros sagrados pelo cânon eclesiástico','Verdade absoluta e infalibilidade de toda a revelação escrita'),('FB10-L13-Q05','Evitar o mecanicismo da ditadura verbal e o ceticismo que nega a unidade','A Bíblia é apenas uma coleção de textos sem mensagem coerente','Cada livro bíblico deve ser lido isoladamente, sem qualquer conexão','A unidade exige ignorar toda diferença entre os textos sagrados'),('FB11-L08-Q04','Autores do NT citaram a LXX em profecias; Igreja antiga a adotou como AT oficial.','Foi traduzida do hebraico por Tiago, irmão de Jesus, no primeiro século.','Serviu exclusivamente como base para a tradução da Vulgata Latina de Jerônimo.','Foi rejeitada pelos Pais da Igreja por conter graves erros doutrinários e textuais.'),('FB11-L11-Q05','Exigem análise de data, qualidade e relações familiares, jamais evidência isolada','Unciais são sempre superiores aos minúsculos por sua maior antiguidade formal','Quanto mais manuscritos apoiam uma leitura, mais certa ela é, sem análise crítica','Ambos foram copiados diretamente dos autógrafos, garantindo fidelidade absoluta'),('FB12-L03-Q05','NAO SEI','Paráfrase preserva a estrutura formal do original','Equivalência funcional ignora o sentido do texto fonte','Paráfrase e equivalência funcional são sinônimos'),('FB12-L04-Q02','Paráfrase reinterpreta e expande o texto; tradução preserva a forma original.','A paráfrase é uma tradução literal palavra por palavra do original.','A tradução reinterpreta o sentido, enquanto a paráfrase copia o original.','Ambas são idênticas, diferindo apenas na língua de destino.'),('FB12-L05-Q02','Texto Massorético, Septuaginta, Vulgata e Manuscritos do Mar Morto','Textus Receptus, Códice Alexandrino e Códice Sinaítico','Papiro 46, Papiro 75 e Códice de Beza','Codex Claromontanus, Diatessaron e Peshitta'),('FB13-L05-Q01','É considerar a época, cultura e circunstâncias históricas em que o texto foi escrito.','É aplicar o texto bíblico diretamente à realidade do leitor moderno.','É analisar somente a estrutura gramatical e o estilo literário do texto.','É decorar as datas e os principais eventos da cronologia bíblica.'),('FB13-L07-Q05','Interpretar à luz de toda a Escritura, aplicando à revelação cristã.','Aplicar cada passagem isoladamente, sem relação com o todo bíblico.','Priorizar o sentido original histórico sobre a unidade canônica.','Basear a aplicação somente no Novo Testamento, ignorando o Antigo.'),('FB14-L03-Q04','Foram inseridas depois e nem sempre acompanham o sentido do texto.','Foram definidas pelos escribas no período do cativeiro babilônico','Foram organizadas pelos pais da Igreja no primeiro concílio','Foram baseadas nas divisões feitas pelos fariseus na sinagoga'),('FB14-L06-Q01','Exame do contexto histórico, cultural, literário e teológico do texto bíblico','Tradução literal e palavra por palavra do texto bíblico para a língua atual','Interpretação pessoal do leitor baseada em suas emoções e experiências atuais','Análise isolada de palavras gregas e hebraicas sem observar o contexto geral'),('FB14-L07-Q04','NAO SEI','A estrutura revela o genero literario e o proposito do autor','A repeticao de termos chave marca a tese principal','O paralelismo poetico evidencia o argumento central'),('FB14-L17-Q05','Não impor ideias pré-concebidas ao texto, evitando a eisegese.','Usar somente versões modernas, abandonando o estudo dos idiomas originais.','Analisar versículos isolados, sem conexão com o contexto literário imediato.','Subordinar a gramática à confirmação de uma teologia previamente definida.'),('FB16-L01-Q05','NAO SEI','Porque revela o significado original escondido nas Escrituras Hebraicas','Porque permite decifrar os códigos profeticos do Apocalipse','Porque os lexicons biblicos contem revelacoes diretas de Deus'),('FB16-L03-Q05','Porque o texto hebraico original era escrito apenas com consoantes, sem vogais.','Porque o sistema de vogais hebraicas foi criado pelos escribas do Novo Testamento.','Porque o Novo Testamento grego foi traduzido diretamente pelas consoantes hebraicas.','Porque as consoantes revelam automaticamente o significado exato de cada palavra grega.'),('FB16-L10-Q01','NAO SEI','...','...','...'),('FB17-L10-Q05','NAO SEI','Conjuncoes revelam o vocabulario grego usado pelo autor','Conjuncoes indicam a data de composicao do texto','Conjuncoes mostram o genero literario do documento'),('FB17-L11-Q03','NAO SEI','Sujeito da oração principal','Adjunto adnominal','Predicativo do objeto'),('FB18-L05-Q05','Não superinterpretar termos aramaicos nem ignorar o contexto linguístico grego','Substituir o texto grego pelo aramaico para obter a interpretação correta','Considerar que todo o Novo Testamento foi originalmente escrito em aramaico','Estudar apenas expressões aramaicas, desconsiderando o original grego'),('FB18-L14-Q05','Reconhecer a escassez de fontes escritas e evitar anacronismos linguísticos','O Novo Testamento foi originalmente escrito em aramaico por Jesus e os apostolos','Os targuns sao fontes contemporaneas que refletem a fala exata de Jesus','O aramaico moderno da Siria reproduz fielmente o idioma falado por Jesus'),('NT01-L01-Q04','Marcou o início da helenização e difusão do grego koiné entre os judeus.','Restaurou o culto no templo com Esdras e Neemias sob a autoridade persa.','Estabeleceu o cativeiro babilônico e provocou a destruição do templo de Jerusalém.','Iniciou o período dos patriarcas e firmou a aliança com Abraão, Isaque e Jacó.'),('NT01-L01-Q06','Explica a helenização que difundiu o grego koiné em que o NT foi escrito.','Ajuda a compreender as leis persas aplicadas nas primeiras igrejas cristãs.','Explica a influência da religião zoroastriana diretamente nos ensinos de Jesus.','Permite entender a arte persa que decorava as sinagogas no primeiro século.'),('NT01-L10-Q06','A Pax Romana unificou o mundo, facilitando a difusão do evangelho','A conquista romana destruiu totalmente o judaísmo no século I','O império romano foi fundado durante o período do Antigo Testamento','A conquista romana impediu a propagação do cristianismo na Ásia'),('NT02-L04-Q01','Prologo grego classico, narrativa da infancia, viagem a Jerusalem, exito literario','Evangelho mais antigo, escrito por Mateus em hebraico para judeus','Sem narrativas de infancia, escrito por Paulo em romeno, breve e apocaliptico','Escrito por Pedro em aramaico, voltado apenas para a circuncisao judaica'),('NT02-L05-Q05','Porque múltiplas fontes independentes confirmam os mesmos fatos históricos','Porque comprova que todos os evangelhos foram escritos pelo mesmo autor','Porque elimina a necessidade de fé na historicidade dos evangelhos','Porque demonstra que os milagres foram criação coletiva dos apóstolos'),('NT02-L08-Q04','Para adaptar a mensagem às suas comunidades e esclarecer temas teológicos.','Para corrigir erros doutrinários e imprecisões históricas de Marcos.','Porque desconheciam totalmente a existência do Evangelho de Marcos.','Para contradizer diretamente os ensinamentos registrados por Marcos.'),('NT02-L11-Q08','Jesus é o Messias prometido, verdadeiro homem e Filho de Deus.','Jesus é somente um profeta humano, sem qualquer pretensão messiânica.','As genealogias mostram que Jesus não tinha direito ao trono de Davi.','Jesus descendia apenas de Abraão, sem ligação com Adão ou Davi.'),('NT03-L08-Q06','A elevação do Filho do Homem concede vida eterna a quem nele crê','A elevação do Filho do Homem destruiu o templo de Jerusalém','O Filho do Homem foi exaltado apenas para julgar os incrédulos','A elevação do Filho do Homem trouxe paz política a Israel'),('NT04-L04-Q01','Anunciação a Maria, viagem a Belém, nascimento, visita dos pastores e magos.','Batismo no Jordão, tentação no deserto e chamado dos primeiros discípulos.','Última ceia, crucificação no Calvário e ressurreição ao terceiro dia.','Transfiguração no monte, entrada triunfal em Jerusalém e ascensão aos céus.'),('NT04-L06-Q06','Ao batizar-se, os céus se abriram, o Espírito desceu e o Pai o proclamou Filho','Escolheu os doze apóstolos e começou a pregar junto ao rio Jordão','Iniciou o ministério pregando o Sermão da Montanha para as multidões','Realizou seu primeiro milagre transformando água em vinho nas bodas de Caná'),('NT04-L12-Q06','Perseguição e dispersão dos discípulos, mas o evangelho se espalhou ainda mais','O evangelho foi totalmente proibido e desapareceu do mundo','Os discípulos foram todos presos e nunca mais pregaram','Apenas os judeus aceitaram a mensagem cristã'),('NT04-L18-Q07','NAO SEI','...','...','...'),('NT04-L24-Q01','Batismo, Transfiguração e aparições após a ressurreição','Tentação no deserto, última ceia e crucificação','Anunciação a Maria, circuncisão e apresentação no templo','Sermão da montanha, multiplicação dos pães e entrada em Jerusalém'),('AT14-L07-Q04','NAO SEI','Eclesiastes 3:1 — Para tudo há um tempo e um propósito debaixo do céu','Deuteronômio 7:9 — Deus guardará a aliança aos que o amam por mil gerações','Eclesiastes 12:13 — Teme a Deus e guarda os seus mandamentos'),('AT15-L15-Q03','O oraculo de Ezequiel 18: a alma que pecar, essa morrera','A visao de Ezequiel dos ossos secos que revivem no vale','O oraculo de Balaao sobre a estrela que surgir de Jaco','A visao de Daniel sobre as quatro bestas e os reinos mundanos'),('AT15-L20-Q06','Os impérios passam, mas o reino de Cristo, a Pedra de Daniel, permanece para sempre.','Os impérios terrenos são eterno símbolo do poder humano independente de Deus.','Os sonhos de Faraó mostram que o Egito venceu Israel definitivamente.','Daniel revelou que o império romano seria o último e nunca cairia.'),('AT15-L23-Q06','Daniel 12:2 profetiza ressurreição confirmada por Cristo e cumprida na consumação.','Daniel 12:2 refere-se apenas à restauração política de Israel, sem cunho escatológico.','A ressurreição em Daniel é uma metáfora do novo nascimento espiritual do crente.','Daniel 12:2 ensina que todos os mortos ressuscitarão para um único destino eterno.'),('AT16-L01-Q03','Jezreel, Lo-Rúama e Lo-Amí comunicam juízo: dispersão, fim da misericórdia e rejeição.','Os nomes revelam somente a vinda do Messias e a restauração final de Israel.','Jezreel refere-se apenas à cidade histórica, sem qualquer sentido de juízo.','Lo-Rúama e Lo-Amí indicam rejeição, mas Jezreel anuncia somente bênção incondicional.'),('AT16-L08-Q01','Profetiza a destruição de Nínive como juízo divino contra a crueldade assíria.','Anuncia a queda da Babilônia como vingança divina contra a idolatria.','Relata o arrependimento dos ninivitas diante da pregação do profeta Jonas.','Prediz a restauração imediata do reino do norte após o cativeiro assírio.'),('AT16-L12-Q01','Pós-exílio babilônico, povo priorizou suas casas; Deus exorta reconstruir o templo.','Reinado de Salomão, rei edificou primeiro templo com materiais nobres.','Período mosaico, Israel construiu tabernáculo durante peregrinação no deserto.','Tempo dos juízes, povo levantou altar em Siquém para servir a Deus.'),('AT17-L14-Q02','Josias, Ezequias, Esdras e Neemias promoveram reformas religiosas em Judá','Davi, Salomão e Roboão lideraram grandes reformas religiosas no templo','Moisés instituiu reformas religiosas no Egito antes do êxodo','Acabe e Jezabel promoveram reformas religiosas em Israel'),('AT18-L04-Q06','O exílio renovou a aliança davídica, gerando esperança no Messias vindouro','A queda eliminou definitivamente a linhagem messiânica de Davi','O reino do sul nunca foi de fato destruído pelos babilônios','Israel abandonou toda esperança de restauração após o cativeiro'),('FB02-L06-Q05','O êxodo é o modelo de redenção: liberta Israel e aponta para Cristo','O êxodo mostra que Israel se formou apenas pela conquista militar de Canaã','A formação de Israel ocorreu sem o êxodo, somente pela aliança com Davi','O êxodo foi apenas um evento político sem significado para a redenção'),('FB01-L10-Q03','Permite compreender o contexto histórico, cultural e geográfico das Escrituras.','Revela datas exatas do fim dos tempos e da segunda vinda de Cristo','Substitui a ação do Espírito Santo na interpretação das Escrituras','Autoriza tradições humanas acima da Palavra inspirada de Deus'),('FB02-L10-Q02','Babilônia, Ciro, Zorobabel, Esdras, Neemias, reconstrução do templo','Moisés, Êxodo, maná, sarça ardente, Dez Mandamentos','Jesus, discípulos, parábolas, Sermão da Montanha','Davi, Salomão, templo de Jerusalém, reino unido'),('FB04-L07-Q04','Cumprimento da promessa a Abraão, precede a aliança no Sinai e a entrada em Canaã','A libertação do Egito marca o início da criação do mundo e antecede o dilúvio universal','O êxodo ocorreu após a construção do templo de Salomão e antes do cativeiro babilônico','A saída do Egito é um evento isolado, sem ligação com a história dos patriarcas'),('FB04-L17-Q05','A pessoa e obra de Cristo asseguram a consumação final da redenção.','A consumação da redenção resulta apenas da obediência da criatura sem Cristo.','A redenção se consuma pela obra isolada do Espírito sem a mediação de Cristo.','A humanidade de Cristo, sem sua divindade, basta para a consumação da redenção.'),('FB05-L07-Q03','Israel, Jeroboão I, Acabe, Oséias e o império Assírio','Judá, Davi, Ezequias e o império Babilônico','Israel, Saulo, Samuel e o império Egípcio','Edom, Moisés, Arão e o império Persa'),('FB05-L15-Q05','A data do concílio de Jerusalém é debatida entre 48 e 50 d.C.','Conversão de Paulo é unanimemente fixada pelos estudiosos em 70 d.C.','As viagens missionárias paulinas ocorreram todas após 100 d.C.','A cronologia de Atos é idêntica à de Gálatas sem qualquer debate'),('FB06-L01-Q05','Porque esclarece costumes, idiomas e símbolos culturais presentes no texto bíblico','Porque a Bíblia foi originalmente redigida em egípcio hieroglífico e requer tradução','Porque somente assim se demonstra que a Bíblia é um livro puramente mitológico','Porque permite ignorar o contexto histórico e aplicar apenas sentido alegórico')`);
  db.execSync(`INSERT OR REPLACE INTO quiz_alternatives (pergunta_id,correta,distrator1,distrator2,distrator3) VALUES ('FB06-L02-Q02','Planície entre os rios Tigre e Eufrates, berço de civilizações antigas','Planície banhada pelo rio Nilo, conhecida pelas pirâmides e faraós','Região montanhosa próxima ao Mar Mediterrâneo, habitada por cananeus','Península no Mar Egeu, berço da filosofia e da democracia grega'),('FB07-L18-Q03','Antes o templo era físico com sacrifícios; hoje o culto é espiritual e o crente é templo.','No antigo havia vários templos; hoje só existe um, construído por Salomão em Jerusalém.','No mundo antigo o culto era coletivo; hoje deve ser praticado individualmente sem comunhão.','Antigamente não existia templo; somente após Jesus é que se começou a cultuar a Deus.'),('FB08-L10-Q05','É fonte assíria unilateral; omite a perspectiva hebraica e elementos miraculosos','Não apresenta limitações; é registro histórico totalmente neutro e confiável','Confirma integralmente todos os milagres e detalhes do relato bíblico','É a única evidência que menciona os 185.000 soldados assírios mortos'),('FB08-L13-Q05','Descobertas exigem interpretação; não confirmam relatos bíblicos diretamente','Evidências arqueológicas provam literalmente todos os relatos bíblicos sobre Jerusalém','A Bíblia deve ser rejeitada quando não há descoberta arqueológica correspondente','Jerusalém nunca foi objeto de escavações arqueológicas sistemáticas'),('FB09-L02-Q04','Difere no número de livros, na ordem e na inclusão dos livros deuterocanônicos.','Apresenta os mesmos livros do cânon católico, diferindo apenas na ordem.','Foi definido por Marcião como o cânon mais completo do antigo testamento.','Possui 46 livros no protestantismo, iguais aos do cânon alexandrino cristão.'),('FB09-L07-Q05','Os deuterocanonicos ja tinham canonicidade contestada antes da Reforma Protestante.','Martinho Lutero removeu sete livros do canon durante a Dieta de Worms.','Os apocrifos foram inseridos na Biblia Catolica somente apos o Concilio de Trento.','Todos os cristais ate o seculo XVI concordavam com os mesmos 73 livros canonicos.'),('FB10-L04-Q02','2 Tm 3:16 e 2 Pe 1:21: Deus soprou cada palavra, guiando os autores sagrados.','Jo 3:16: o amor de Deus pela humanidade é a base da inspiração bíblica.','A inspiração se fundamenta na experiência mística dos autores, sem ação divina.','Sl 23:1 e Mt 28:19: Deus revelou as Escrituras somente aos apóstolos.'),('FB10-L05-Q03','Consiste em afirmar que toda a Escritura é igualmente inspirada por Deus.','Afirma que apenas as partes teológicas da Bíblia são divinamente inspiradas.','Identifica-se plenamente com o conceito de iluminação espiritual do crente.','Limita-se a reconhecer a inspiração apenas dos textos proféticos da Bíblia.'),('FB10-L14-Q03','Aplica a revelação ao entendimento do crente, sem acrescentar nova verdade','É o processo pelo qual Deus ditou pessoalmente as Escrituras Sagradas','Manifesta-se unicamente no instante da conversão do pecador perdido','Consiste em acrescentar novas doutrinas ao corpo de verdades bíblicas'),('FB11-L10-Q03','Mais antigos MSS do NT; em papiro, sécs. II-IV; formato de código.','Manuscritos em pergaminho do séc. IX, com escrita minúscula cursiva.','Cópias completas da Bíblia escritas em rolos de couro no séc. I.','Edições impressas do NT produzidas por Erasmo no séc. XVI.'),('FB16-L01-Q04','As línguas semíticas estruturam-se em raízes de consoantes que contêm o significado','Porque Moisés recebeu as letras diretamente sem sinais vocálicos de Deus','Para preservar o mistério e impedir a leitura pública das Escrituras','Por cópia adaptada dos hieróglifos egípcios que omitiam vogais'),('FB16-L16-Q01','Conjunto de palavras hebraicas mais frequentes e essenciais no AT','Termos teológicos exclusivos do Novo Testamento em grego','Vocabulário do hebraico moderno usado em Israel atualmente','Palavras aramaicas encontradas em partes do Antigo Testamento'),('NT01-L05-Q03','Promoveu a helenização e a tradução da Septuaginta','Destruiu o Templo de Jerusalém no ano 70 d.C.','Exilou o povo judeu para a Babilônia em 586 a.C.','Estabeleceu o Sinédrio como instituição religiosa'),('NT01-L09-Q06','Contextualiza o cenário político-religioso da Judeia e a formação das seitas.','Apresenta os asmoneus como predecessores diretos da família de Jesus.','Indica que os evangelhos foram escritos durante o período asmoneu.','Mostra que Paulo era um descendente direto da dinastia asmoneia.'),('NT01-L12-Q04','Preservou a língua hebraica e centralizou o estudo da Torá','Instituiu sacrifícios diários fora do Templo de Jerusalém','Substituiu o Shabat pelo culto dominical cristão','Proibiu a leitura das Escrituras aos leigos e mulheres'),('NT01-L16-Q03','Promoveram ascetismo, pureza ritual e preservação dos Manuscritos do Mar Morto.','Dominarem politicamente a Judeia e estabeleceram um reino autônomo em Qumran.','Traduzirem a Bíblia Hebraica para o grego, dando origem à Septuaginta.','Fundarem diretamente o cristianismo como seus primeiros seguidores organizados.'),('NT01-L20-Q06','Revela o pano de fundo judaico que fundamenta a identidade de Jesus.','Permite substituir o Antigo Testamento pela tradição rabínica posterior.','Ajuda a identificar os erros históricos presentes nos Evangelhos.','Serve para negar as profecias messiânicas do Antigo Testamento.'),('NT04-L22-Q06','Selou a morte de Cristo, gerou desespero nos discípulos e firmou a base do Evangelho','Os discípulos proclamaram o Evangelho com alegria logo após o sepultamento de Jesus','O corpo de Jesus foi sepultado publicamente pelos próprios discípulos no templo','Os discípulos compreenderam de imediato que Jesus ressuscitaria ao terceiro dia'),('AT15-L10-Q02','2 Reis 25; período babilônico; destruição por Nabucodonosor em 586 a.C.','1 Reis 22; período assírio; destruição por Senaqueribe em 701 a.C.','Esdras 4; período persa; destruição por Artaxerxes em 458 a.C.','Apocalipse 11; período apostólico; destruição por Nero em 64 d.C.'),('FB05-L04-Q02','Passagem do Jordão, Jericó, Ai, Gibeão, cinco reis, sul e norte','Jericó, Jordão, Ai, Gibeão, cinco reis, sul e norte','Jordão, Jericó, Babel, Persa, Roma, Grécia','Jordão, Jericó, Gibeão, Ai, cinco reis, sul e norte'),('FB05-L16-Q02','NAO SEI','Conversão de Paulo, Concílio de Jerusalém, Viagens missionárias, Martírio de Paulo','Gálatas, 1 Coríntios, Romanos, Apocalipse, escritos joaninos','Mateus, Marcos, Lucas, João, Atos, cartas paulinas'),('FB07-L03-Q03','Antigamente: mortalidade alta e trabalho precoce. Hoje: medicina e educação.','Hoje: alta mortalidade infantil; no passado, crianças viviam com saúde plena.','Em ambos os períodos, parto sempre hospitalar e escolarização obrigatória.','No mundo antigo havia proteção legal total à infância; hoje, crianças trabalham.'),('FB07-L04-Q04','NAO SEI','Provérbios 22:6; Deuteronômio 6:6-7; Efésios 6:4','Salmos 78:4; 2 Timóteo 3:15; Colossenses 3:21','Gênesis 18:19; Deuteronômio 11:19; Provérbios 1:8'),('FB10-L07-Q05','Não subjugar a Escritura à razão, tradição ou experiência humana','Rejeitar toda crítica textual como incompatível com a fé','Aceitar revelações privadas como complemento da Escritura','Negar a unidade teológica entre os testamentos bíblicos'),('FB10-L11-Q05','Evitar os extremos do obscurantismo e do racionalismo sobre a clareza bíblica','A clareza das Escrituras exige o magistério eclesiástico para ser compreendida','A iluminação interior do Espírito torna a Escritura clara independentemente do texto','Somente os eruditos podem compreender a verdadeira clareza das Escrituras'),('FB11-L11-Q03','Unciais usam letras maiúsculas em pergaminho; minúsculos usam letras cursivas minúsculas em papel','São traduções para línguas vernaculares europeias antigas','Diferem apenas pelo número de livros incluídos no cânon bíblico','São versões comentadas com notas extensas de pais da Igreja'),('FB14-L05-Q05','Confundir gênero com conteúdo e ignorar o contexto histórico-cultural do texto.','Classificar o gênero pela quantidade de versículos do texto bíblico.','Basear a identificação do gênero na divisão moderna de capítulos.','Usar exclusivamente a tradução em português para análise do gênero.'),('FB16-L04-Q01','Sinais de vocalização inseridos pelos massoretas no texto hebraico.','Anotações rabínicas sobre o sentido espiritual das escrituras.','Divisões de capítulos e versículos feitas pelos massoretas.','Acentos musicais usados na leitura litúrgica da sinagoga.'),('FB17-L19-Q01','Uso de dicionários gregos para entender o sentido original dos termos do NT.','Tradução literal do grego para o português sem consultar fontes.','Estudo da gramática hebraica aplicada ao Novo Testamento.','Leitura devocional do texto grego sem auxílio de ferramentas.'),('NT01-L06-Q03','Perseguição, profanação do Templo e imposição da cultura grega','Libertação dos judeus do cativeiro babilônico pelos selêucidas','Construção do Templo de Salomão em Jerusalém pelos selêucidas','Governo justo e próspero sobre a Judeia durante vários séculos'),('NT04-L11-Q01','Belém, Egito, Jerusalém aos 12 anos, batismo no Jordão e ministério na Galileia','Ressurreição em Jerusalém, ascensão ao céu e derramamento do Espírito','Construção do templo, saída do Egito e travessia do Mar Vermelho','Conversão de Paulo, destruição do templo e cativeiro na Babilônia'),('AT16-L11-Q01','Sofonias anuncia o Dia do Senhor, juízo contra Judá ímpia e restauração do remanescente.','Isaías profetiza a vinda do Messias servo sofredor e a nova criação de paz.','Jeremias anuncia a nova aliança escrita no coração e a restauração de Israel.','Ezequiel vê a glória de Deus partir do templo e profetiza o vale de ossos secos.'),('FB03-L10-Q02','Romanos','Tiago','Hebreus','Judas'),('FB09-L02-Q05','Evitar Jamnia como decisao formal; canon foi processo gradual, nao decreto unico de concilio','A canonizacao foi decidida no Concilio de Trento como dogma definitivo e imutavel','O texto massoretico foi o unico aceito sem nenhuma discussao entre as seitas judaicas','O canon hebraico e o samaritano sao identicos, diferindo apenas em variantes textuais'),('FB10-L04-Q04','Garante autoridade absoluta, interpretação literal e uso das Escrituras como regra de fé.','Limita a autoridade das Escrituras apenas aos ensinamentos morais e não aos textos históricos.','Permite interpretação alegórica livre, pois somente os autores foram divinamente inspirados.','Restringe a aplicação das Escrituras ao contexto cultural antigo, sem validade atual.'),('FB06-L15-Q03','Ciro, Dario, Assuero, Ester, Mardoqueu, Esdras e Neemias','Nabucodonosor, Belsazar, Zedequias, Joaquim e Daniel','Abraão, Isaque, Jacó, José, Moisés e Arão','Herodes, Pilatos, Caifás, Anás e Barrabás'),('NT04-L21-Q08','O inocente condenado, o pecado julgado, o amor de Deus manifesto na cruz','A cruz revela só a fraqueza humana, sem qualquer juízo ou amor divino','Na cruz Jesus venceu Satanás, mas não houve juízo sobre o pecado','A crucificação mostra apenas que Deus abandonou Jesus, sem amor'),('FB05-L05-Q02','Morte de Josué, ciclos de pecado, juízes libertadores e governo de Sansão','Êxodo do Egito, travessia do mar, leis no Sinai e peregrinação','Unção de Saul, governo de Davi, templo de Salomão e reino dividido','Nascimento de Jesus, batismo, milagres, morte na cruz e ressurreição'),('FB10-L12-Q05','Dizer que Deus nao pode salvar sem as Escrituras e que elas nao sao necessarias','Negar a inspiracao verbal das Escrituras e afirmar que elas contem erros humanos','Afirmar que somente o Novo Testamento tem validade e autoridade para hoje','Ensinar que a tradicao da Igreja tem a mesma autoridade das Escrituras Sagradas'),('FB17-L16-Q05','Identifica função sintática e nuances como propósito, resultado e causa no grego.','Porque substituem todos os verbos finitos nas orações subordinadas do NT.','Garantem a tradução literal palavra por palavra sem ajustes gramaticais.','São usados apenas em citações do Antigo Testamento no Novo Testamento.'),('FB05-L14-Q02','Ascensão, Pentecostes, conversão de Paulo, viagens missionárias e prisão','Batismo de Jesus, tentação, sermão do monte, transfiguração','Criação, queda do homem, dilúvio, torre de Babel','Cativeiro babilônico, retorno do exílio, reconstrução do templo')`);
  db.execSync("COMMIT;");
}